window.HADITH_CACHE["ahmad_1"] = {"501":{"ar":"حَدَّثَنَا حَسَنٌ يَعْنِي الْأَشْيَبَ وَأَبُو النَّضْرِ قَالَا حَدَّثَنَا زُهَيْرٌ عَنْ عُرْوَةَ بْنِ عَبْدِ اللَّهِ بْنِ قُشَيْرٍ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ أَبِيهِ قَالَ أَبُو النَّضْرِ فِي حَدِيثِهِ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا عُرْوَةُ بْنُ عَبْدِ اللَّهِ بْنِ قُشَيْرٍ أَبُو مَهَلٍ الْحَنَفِيُّ قَالَ حَدَّثَنِي مُعَاوِيَةُ بْنُ قُرَّةَ عَنْ أَبِيهِ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي رَهْطٍ مِنْ مُزَيْنَةَ فَبَايَعْنَاهُ وَإِنَّ قَمِيصَهُ لَمُطْلَقٌ قَالَ فَبَايَعْنَاهُ ثُمَّ أَدْخَلْتُ يَدِي فِي جَيْبِ قَمِيصِهِ فَمَسِسْتُ الْخَاتَمَثُمَّ قَالَ عُرْوَةُ فَمَا رَأَيْتُ مُعَاوِيَةَ وَلَا ابْنَهُ قَالَ حَسَنٌ يَعْنِي أَبَا إِيَاسٍ فِي شِتَاءٍ قَطُّ وَلَا حَرٍّ إِلَّا مُطْلِقَيْ إِزَارِهِمَا لَا يَزُرَّانِهِ أَبَدًا","id":"Telah menceritakan kepada kami [Hasan] yaitu Al Asyyab dan [Abu Nadlr] berkata; telah menceritakan kepada kami [Zuhair] dari ['Urwah bin Abdullah bin Qusyair] dari [Mu'awiyah bin Qurrah] dari [Bapaknya]. [Abu Nadlr] berkata; dalam haditsnya, telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami ['Urwah bin Abdullah bin Qusyair, Abu Mahl Al Hanafi] berkata; telah menceritakan kepadaku [Mu'awiyah bin Qurrah] dari [Bapaknya] berkata; saya mendatangi Rasulullah Shallallahu'alaihiwasallam ketika beliau berada di tengah-tengah beberapa orang Muzainah, lalu kami berbaiat kepada beliau sedang kemejanya tidak terkancingkan. (Qurrah Radliyallahu'anhu) berkata; kami berbaiat kepada beliau, lalu saya memasukkan tanganku ke dalam saku baju beliau, saya menyentuh stempel. Lalu 'Urwah berkata; maka saya tidak pernah melihat Mu'awiyah ataupun anaknya, - Hasan berkata yang ia maksud dengan anaknya yaitu Abu Iyash-Mu, baik dalam musim dingin maupun dalam musim panas kecuali pasti keduanya membiarkan sarungnya tidak dikancingi dan mereka tidak mengancinginya selamanya."},"502":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا قُرَّةُ بْنُ خَالِدٍ قَالَ سَمِعْتُ مُعَاوِيَةَ بْنَ قُرَّةَ يُحَدِّثُ عَنْ أَبِيهِ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَأْذَنْتُهُ أَنْ أُدْخِلَ يَدِي فِي جُرُبَّانِهِ وَإِنَّهُ لَيَدْعُو لِي فَمَا مَنَعَهُ أَنْ أَلْمِسَهُ أَنْ دَعَا لِي قَالَ فَوَجَدْتُ عَلَى نُغْضِ كَتِفِهِ مِثْلَ السِّلْعَةِحَدَّثَنَا هُوَ مُعَاوِيَةُ بْنُ قُرَّةَ فَهُوَ مِنْ تَتِمَّةِ حَدِيثِ قُرَّةَ لَا أَنَّهُ صَحَابِيٌّ آخَرُ","id":"Telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami [Qurrah bin Khalid] berkata; saya telah mendengar [Mu'awiyah bin Qurrah] menceritakan dari [Bapaknya] berkata; saya menemui Rasulullah Shallallahu'alaihiwasallam dan saya meminta ijin agar saya memasukkan tanganku pada saku bajunya, lantas beliau memanggilku dan beliau tidak mencegah ketika saya menyentuhnya. (Qurrah Radliyallahu'anhu) berkata; maka saya dapatkan pada bagian atas pundaknya seperti bisul pada tubuh. Telah menceritakan kepada kami Mu'awiyah bin Qurrah dan itu termasuk dari kesempurnaan hadits Qurrah bukan karena ada sahabat yang lainnya."},"503":{"ar":"حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِيَاسٍ عَنْ أَبِيهِأَنَّهُ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَعَا لَهُ وَمَسَحَ رَأْسَهُ","id":"Telah menceritakan kepada kami [Wahb bin Jarir] telah menceritakan kepada kami [Syu'bah] dari [Abu Iyas] dari [Bapaknya] dia mendatangi Nabi Shallallahu'alaihiwasallam lalu beliau mendo'akannya dan mengusap kepalanya."},"504":{"ar":"حَدَّثَنَا وَهْبٌ حَدَّثَنَا شُعْبَةُ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي صِيَامِ ثَلَاثَةِ أَيَّامٍ مِنْ الشَّهْرِ صَوْمُ الدَّهْرِ وَإِفْطَارُهُ","id":"Telah menceritakan kepada kami [Wahb] telah menceritakan kepada kami [Syu'bah] dari [Mu'awiyah bin Qurrah] dari [Bapaknya] dari Nabi Shallallahu'alaihi wasallam bersabda: \"Di dalam puasa tiga hari dalam satu bulan sebagaimana puasa dahr (puasa selamanya) dan berbukanya\"."},"505":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا عَلِيُّ بْنُ زَيْدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ عَنِ الْأَسْوَدِ بْنِ سَرِيعٍ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي قَدْ حَمِدْتُ رَبِّي تَبَارَكَ وَتَعَالَى بِمَحَامِدَ وَمِدَحٍ وَإِيَّاكَ قَالَ هَاتِ مَا حَمِدْتَ بِهِ رَبَّكَ عَزَّ وَجَلَّ قَالَ فَجَعَلْتُ أُنْشِدُهُ فَجَاءَ رَجُلٌ أَدْلَمُ فَاسْتَأْذَنَ قَالَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيِّنْ بَيِّنْ قَالَ فَتَكَلَّمَ سَاعَةً ثُمَّ خَرَجَ قَالَ فَجَعَلْتُ أُنْشِدُهُ قَالَ ثُمَّ جَاءَ فَاسْتَأْذَنَ قَالَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيِّنْ بَيِّنْ فَفَعَلَ ذَاكَ مَرَّتَيْنِ أَوْ ثَلَاثًا قَالَ قُلْتُ يَا رَسُولَ اللَّهِ مَنْ هَذَا الَّذِي اسْتَنْصَتَّنِي لَهُ قَالَ عُمَرُ بْنُ الْخَطَّابِ هَذَا رَجُلٌ لَا يُحِبُّ الْبَاطِلَ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Salamah] telah mengabarkan kepada kami ['Ali bin Zaid] dari [Abdurrahman bin Abu Bakrah] dari [Al Aswad bin Sari'] berkata; saya mendatangi Nabi Shallallahu'alaihiwasallam dan berkata; Wahai Rasulullah, saya memuji Rabku Tabaroka Wa Ta'ala dengan kalimAt kalimat pujian kepadamu. (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Bacakan apa yang kau gunakan dalam memuji Rabb Azzawajalla kamu\". (Al Aswad bin Sari` radliyallahu'anhu) berkata; saya membacakannya, lalu datanglah seorang laki-laki yang hitam tinggi meminta ijin. Lalu Nabi Shallallahu'alaihi wasallam bersabda: \"Jelaskan, jelaskan\". Orang itu berbicara sebentar lalu keluar. Lalu saya membacakannya. Orang tadi datang lagi dan meminta ijin. Nabi Shallallahu'alaihi wasallam bersabda: \"Jelaskan, jelaskan\". (orang itu) melakukan hal itu dua kali atau tiga kali. Lantas kutanyakan, Wahai Rasulullah, siapakah orang yang menjadikan anda memintaku untuk diam!. Beliau bersabda: \"Itu Umar bin Khattab, tidak menyukai hal yang batil."},"506":{"ar":"حَدَّثَنَا رَوْحٌ قَالَ حَدَّثَنَا عَوْفٌ عَنِ الْحَسَنِ عَنْ الْأَسْوَدِ بْنِ سَرِيعٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَلَا أُنْشِدُكَ مَحَامِدَ حَمِدْتُ بِهَا رَبِّي تَبَارَكَ وَتَعَالَى قَالَ أَمَا إِنَّ رَبَّكَ عَزَّ وَجَلَّ يُحِبُّ الْحَمْدَ","id":"Telah menceritakan kepada kami [Rouh] berkata; telah menceritakan kepada kami ['Auf] dari [Al Hasan] dari [Al Aswad bin Sari'] berkata; saya bertanya, Wahai Rasulullah, maukah saya lantunkan kalimAt kalimat pujian yang bisa saya pakai untuk memuji Rabku Tabaroka Wa Ta'ala?. Beliau bersabda: \" Rabmu AzzaWaJalla menyukai pujian'."},"507":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُصْعَبٍ حَدَّثَنَا سَلَّامُ بْنُ مِسْكِينٍ وَالْمُبَارَكُ عَنِ الْحَسَنِ عَنِ الْأَسْوَدِ بْنِ سَرِيعٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِأَسِيرٍ فَقَالَ اللَّهُمَّ إِنِّي أَتُوبُ إِلَيْكَ وَلَا أَتُوبُ إِلَى مُحَمَّدٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَرَفَ الْحَقَّ لِأَهْلِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Mush'ab Radliyallahu'anhu] telah menceritakan kepada kami [Sallam bin Miskin] dan [Al Mubarok] dari [Al Hasan] dari [Al Aswad bin Sari'] Nabi Shallallahu'alaihiwasallam diberi seorang tawanan lalu berkata; Ya Allah, saya bertaubat kepada-Mu dan saya tidak bertaubat kepada Muhammad. Nabi Shallallahu'alaihi wasallam bersabda: \"Dia telah mengetahui kebenaran pada yang berhak\"."},"508":{"ar":"حَدَّثَنَا يُونُسُ حَدَّثَنَا أَبَانُ عَنْ قَتَادَةَ عَنِ الْحَسَنِ عَنِ الْأَسْوَدِ بْنِ سَرِيعٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ سَرِيَّةً يَوْمَ حُنَيْنٍ فَقَاتَلُوا الْمُشْرِكِينَ فَأَفْضَى بِهِمْ الْقَتْلُ إِلَى الذُّرِّيَّةِ فَلَمَّا جَاءُوا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا حَمَلَكُمْ عَلَى قَتْلِ الذُّرِّيَّةِ قَالُوا يَا رَسُولَ اللَّهِ إِنَّمَا كَانُوا أَوْلَادَ الْمُشْرِكِينَ قَالَ أَوَهَلْ خِيَارُكُمْ إِلَّا أَوْلَادُ الْمُشْرِكِينَ وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ مَا مِنْ نَسَمَةٍ تُولَدُ إِلَّا عَلَى الْفِطْرَةِ حَتَّى يُعْرِبَ عَنْهَا لِسَانُهَا","id":"Telah menceritakan kepada kami [Yunus] telah menceritakan kepada kami [Aban] dari [Qatadah] dari [Al Hasan] dari [Al Aswad bin Sari'] Rasulullah Shallallahu'alaihiwasallam mengutus sebuah satuan perang pada Perang Hunain, lalu mereka memerangi orang-orang musyrik dan mereka berlebihan dalam membunuh sampai kepada para wanita dan anak-anak. Tatkala mereka datang, Rasulullah Shallallahu'alaihiwasallam bersabda: \"Apa yang membuat kalian membunuh kaum wanita dan anak-anak?. Mereka menjawab, Wahai Rasulullah, mereka hanyalah anak-anak orang-orang musyrik. (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Bukankah orang-orang pilihan kalian sebenarnya juga anak-anakorang musyrik?. Demi Dzat yang jiwa Muhammad berada di tangan-Nya tidaklah setiap ruh yang dilahirkan kecuali di atas fitrah Islam, sehingga lidahnya yang mengikrarkannya \"."},"509":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ أَخْبَرَنَا يُونُسُ عَنِ الْحَسَنِ عَنِ الْأَسْوَدِ بْنِ سَرِيعٍ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَغَزَوْتُ مَعَهُ فَأَصَبْتُ ظَهْرًا فَقَتَلَ النَّاسُ يَوْمَئِذٍ حَتَّى قَتَلُوا الْوِلْدَانَ وَقَالَ مَرَّةً الذُّرِّيَّةَ فَبَلَغَ ذَلِكَ رَسُول�� اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا بَالُ أَقْوَامٍ جَاوَزَهُمْ الْقَتْلُ الْيَوْمَ حَتَّى قَتَلُوا الذُّرِّيَّةَ فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ إِنَّمَا هُمْ أَوْلَادُ الْمُشْرِكِينَ فَقَالَ أَلَا إِنَّ خِيَارَكُمْ أَبْنَاءُ الْمُشْرِكِينَ ثُمَّ قَالَ أَلَا لَا تَقْتُلُوا ذُرِّيَّةً أَلَا لَا تَقْتُلُوا ذُرِّيَّةً قَالَ كُلُّ نَسَمَةٍ تُولَدُ عَلَى الْفِطْرَةِ حَتَّى يُعْرِبَ عَنْهَا لِسَانُهَا فَأَبَوَاهَا يُهَوِّدَانِهَا وَيُنَصِّرَانِهَا","id":"Telah menceritakan kepada kami [Isma'il] berkata; telah mengabarkan kepada kami [Yunus] dari [Al Hasan] dari [Al Aswad bin Sari'] berkata; saya mendatangi Rasulullah Shallallahu'alaihiwasallam dan saya berperang bersama beliau. Saya mendapatkan harta yang banyak. Orang-orang pada hari itu berperang sampai mereka membunuh anak-anak. Dan pada waktu yang lain anak-anak dan kaum wanita. Lalu hal itu sampai kepada Rasulullah Shallallahu'alaihiwasallam, lalu beliau bersabda: \"Alangkah buruk suatu kaum yang berlebihan dalam membunuh pada hari ini sampai mereka membunuh kaum wanita dan anak-anak\" Lalu ada seorang laki-laki yang berkata; Wahai Rasulullah, mereka hanyalah anak-anak orang-orang musyrik. (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Bukankah orang-orang terbaik kalian pada dasarnya juga anak-anak orang musyrik?\". Lalu bersabda: \"Janganlah kalian membunuh kaum wanita dan anak-anak, Janganlah kalian membunuh kaum wanita dan anak-anak!\" Beliau bersabda: \"Setiap ruh dilahirkan di atas fitrahnya, sehingga lidahnya yang mengikrarkannya, lalu keduanya orang tuanyalah yang akan menjadikannya Yahudi atau menjadikannya Nasrani\"."},"510":{"ar":"حَدَّثَنَا حَسَنُ بْنُ مُوسَى حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ أَنَّ الْأَسْوَدَ بْنَ سَرِيعٍ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي قَدْ حَمِدْتُ رَبِّي تَبَارَكَ وَتَعَالَى بِمَحَامِدَ وَمِدَحٍ وَإِيَّاكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا إِنَّ رَبَّكَ تَبَارَكَ وَتَعَالَى يُحِبُّ الْمَدْحَ هَاتِ مَا امْتَدَحْتَ بِهِ رَبَّكَ قَالَ فَجَعَلْتُ أُنْشِدُهُ فَجَاءَ رَجُلٌ فَاسْتَأْذَنَ أَدْلَمُ أَصْلَعُ أَعْسَرُ أَيْسَرُ قَالَ فَاسْتَنْصَتَنِي لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَوَصَفَ لَنَا أَبُو سَلَمَةَ كَيْفَ اسْتَنْصَتَهُ قَالَ كَمَا صَنَعَ بِالْهِرِّ فَدَخَلَ الرَّجُلُ فَتَكَلَّمَ سَاعَةً ثُمَّ خَرَجَ ثُمَّ أَخَذْتُ أُنْشِدُهُ أَيْضًا ثُمَّ رَجَعَ بَعْدُ فَاسْتَنْصَتَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَوَصَفَهُ أَيْضًا فَقُلْتُ يَا رَسُولَ اللَّهِ مَنْ ذَا الَّذِي اسْتَنْصَتَّنِي لَهُ فَقَالَ هَذَا رَجُلٌ لَا يُحِبُّ الْبَاطِلَ هَذَا عُمَرُ بْنُ الْخَطَّابِحَدَّثَنَا رَوْحٌ حَدَّثَنَا حَمَّادٌ قَالَ أَخْبَرَنَا عَلِيُّ بْنُ زَيْدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ عَنِ الْأَسْوَدِ بْنِ سَرِيعٍ قَالَ أَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Hasan bin Musa] telah menceritakan kepada kami [Hammad bin Salamah] telah mengabarkan kepada kami ['Ali bin Zaid] dari [Abdurrahman bin Abu Bakrah] dari [Al Aswad bin Sari'] berkata; saya mendatangi Nabi Shallallahu'alaihiwasallam lalu saya berkata; Wahai Rasulullah, saya telah memuji Rabku Tabaroka Wa Ta'ala dengan kalimAt kalimat pujian, bagaimana kalau saya demontrasikan kepadamu?. Rasulullah Shallallahu'alaihiwasallam bersabda: \"Rab kamu Tabaroka Wa Ta'ala menyukai pujian. Lakukanlah apa yang kalian gunakan untuk memuji Rabbmu\". (Al Aswad bin Sari` radliyallahu'anhu) berkata; lalu saya membacakannya, dan datanglah seorang laki-laki yang hitam tinggi, botak san orangnya gampang-gampang susah, lalu ia meminta ijin. (Al Aswad bin Sari` radliyallahu'anhu) berkata; lalu Rasulullah Shallallahu'alaihiwasallam memintaku diam karenanya. Abu Salamah mempraktekkan bagaimana beliau memintanya diam. Yaitu sebagaimana yang dilakukan terhadap kucing. Orang itu masuk dan berbicara sebentar lalu keluar, saya hendak memanjatkan pujian lagi namun orang itu ternyata kembali dan Rasulullah Shallallahu'alaihiwasallam memintaku untuk kembali diam. Beliau mengulanginya lagi. Lalu saya bertanya, 'Kenapa anda memintaku untuk diam karenanya?. Beliau bersabda: \"Orang ini tidak menyukai hal yang batil. Ini adalah Umar bin Khattab.\" Telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami [Hammad] berkata; telah mengabarkan kepada kami ['Ali bin Zaid] dari [Abdurrahman bin Abu Bakrah] dari [Al Aswad bin Sari'] berkata; saya telah mendatangi Rasulullah Shallallahu'alaihiwasallam lalu menyebutkan hadits secara sempurna."},"511":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا زِيَادُ بْنُ مِخْرَاقٍ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ أَبِيهِأَنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ إِنِّي لَأَذْبَحُ الشَّاةَ وَأَنَا أَرْحَمُهَا أَوْ قَالَ إِنِّي لَأَرْحَمُ الشَّاةَ أَنْ أَذْبَحَهَا فَقَالَ وَالشَّاةُ إِنْ رَحِمْتَهَا رَحِمَكَ اللَّهُ","id":"Telah menceritakan kepada kami [Isma'il bin Ibrahim] telah menceritakan kepada kami [Ziyad bin Mihraq] dari [Mu'awiyah bin Qurrah] dari [Bapaknya] seseorang bertanya, Wahai Rasulullah, saya hendak menyembelih kambing namun saya sangat menyayanginya. Atau, saya terlalu sayang kepada kambing jika harus menyembelihnya. (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Jika kamu mengasihinya maka Allah akan mengasihimu\"."},"512":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ شُعْبَةَ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ أَبِيهِقَالَ مَسَحَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى رَأْسِي","id":"Telah menceritakan kepada kami [Waki'] dari [Syu'bah] dari [Mu'awiyah bin Qurrah] dari [Bapaknya] berkata; Nabi Shallallahu'alaihiwasallam pernah mengusap kepalaku."},"513":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا شُعْبَةُ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صِيَامُ ثَلَاثَةِ أَيَّامٍ مِنْ كُلِّ شَهْرٍ صِيَامُ الدَّهْرِ وَإِفْطَارُهُ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Syu'bah] dari [Mu'awiyah bin Qurrah] dari [Bapaknya] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Puasa tiga hari dalam setiap bulan sebagaimana puasa dahr (puasa selamanya) dan berbukanya\"."},"514":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا شُعْبَةُ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ أَبِيهِأَنَّ رَجُلًا كَانَ يَأْتِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَهُ ابْنٌ لَهُ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتُحِبُّهُ فَقَالَ يَا رَسُولَ اللَّهِ أَحَبَّكَ اللَّهُ كَمَا أُحِبُّهُ فَفَقَدَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِي مَا فَعَلَ ابْنُ فُلَانٍ قَالُوا يَا رَسُولَ اللَّهِ مَاتَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَبِيهِ أَمَا تُحِبُّ أَنْ لَا تَأْتِيَ بَابًا مِنْ أَبْوَابِ الْجَنَّةِ إِلَّا وَجَدْتَهُ يَنْتَظِرُكَ فَقَالَ الرَّجُلُ يَا رَسُولَ اللَّهِ أَلَهُ خَاصَّةً أَمْ لِكُلِّنَا قَالَ بَلْ لِكُلِّكُمْ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Syu'bah] dari [Mu'awiyah bin Qurrah] dari [Bapaknya] berkata; ada seseorang laki-laki mendatangi Nabi Shallallahu'alaihiwasallam dengan membawa anak laki-lakinya. Nabi Shallallahu'alaihi wasallam bersabda: \"Apakah kamu mencintainya?\". dia menjawab, Wahai Rasulullah, Semoga Allah mencintaimu sebagaimana saya mencintainya. Di kemudian hari Nabi Shallallahu'alaihiwasallam kehilangan orang itu. Lalu beliau bertanya kepadaku (Qurrah Radliyallahu'anhu) 'Bagaimana keadaan anak Fulan?. Mereka menjawab, 'Wahai Rasulullah, dia telah meninggal.' Nabi Shallallahu'alaihi wasallam bersabda kepada bapaknya, 'Tidakkah kau suka jika kau mendatangi salah satu pintu surga, lalu kau dapatkan anakmu telah menunggumu?. Lalu orang itu berkata; Wahai Rasulullah, apakah itu khusus baginya atau untuk semua kita?. Beliau bersabda: \"Untuk kalian semuanya\"."},"515":{"ar":"حَدَّثَنَا يَزِيدُ أَخْبَرَنَا شُعْبَةُ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا فَسَدَ أَهْلُ الشَّامِ فَلَا خَيْرَ فِيكُمْ وَلَا يَزَالُ أُنَاسٌ مِنْ أُمَّتِي مَنْصُورِينَ لَا يُبَالُونَ مَنْ خَذَلَهُمْ حَتَّى تَقُومَ السَّاعَةُ","id":"Telah menceritakan kepada kami [Yazid] telah mengabarkan kepada kami [Syu'bah] dari [Mu'awiyah bin Qurrah] dari [Bapaknya] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jika penduduk Syam telah rusak maka tidak ada kebaikan pada kalian. Dan akan tetap senantiasa dari umatku yang mendapat pertolongan, mereka tidak mempedulikan orang yang merendahkannya sampai Kiamat tiba.\""},"516":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ قَالَ حَدَّثَنِي مُعَاوِيَةُ بْنُ قُرَّةَ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا فَسَدَ أَهْلُ الشَّامِ فَلَا خَيْرَ فِيكُمْ وَلَنْ تَزَالَ طَائِفَةٌ مِنْ أُمَّتِي مَنْصُورِينَ لَا يَضُرُّهُمْ مَنْ خَذَلَهُمْ حَتَّى تَقُومَ السَّاعَةُ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Syu'bah] berkata; telah menceritakan kepadaku [Mu'awiyah bin Qurrah] dari [Bapaknya] dari Nabi Shallallahu'alaihi wasallam bersabda: \"Jika penduduk Syam telah rusak maka tidak ada kebaikan pada kalian. Akan tetap ada di kalangan umatku sekelompok orang yang mendapat pertolongan, orang yang merendahkan mereka tidak bakalan mengganggu mereka sampai Hari Kiamat tiba.\""},"517":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِ قَالَأَتَيْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ شَبَبَةٌ مُتَقَارِبُونَ فَأَقَمْنَا مَعَهُ عِشْرِينَ لَيْلَةً قَالَ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَحِيمًا رَفِيقًا فَظَنَّ أَنَّا قَدْ اشْتَقْنَا أَهْلَنَا فَسَأَلَنَا عَمَّنْ تَرَكْنَا فِي أَهْلِنَا فَأَخْبَرْنَاهُ فَقَالَ ارْجِعُوا إِلَى أَهْلِيكُمْ فَأَقِيمُوا فِيهِمْ وَعَلِّمُوهُمْ وَمُرُوهُمْ إِذَا حَضَرَتْ الصَّلَاةُ فَلْيُؤَذِّنْ لَكُمْ أَحَدُكُمْ ثُمَّ لِيَؤُمَّكُمْ أَكْبَرُكُمْ","id":"Telah menceritakan kepada kami [Isma'il bin Ibrahim] telah menceritakan kepada kami [Ayyub] dari [Abu Qilabah] dari [Malik bin Al Huwarits] berkata; kami menemui Rasulullah Shallallahu'alaihiwasallam saat kami masih muda yang umurnya sebaya, lalu kami tinggal bersama beliau selama dua puluh malam. Rasulullah Shallallahu'alaihiwasallam adalah orang yang sangat penyayang dan baik hati. Beliau menyangka kami telah merindukan keluarga kami, sehingga beliau bertanya kami tentang keluarga yang kami tinggalkan, lalu kami mengabarinya, lalu beliau bersabda: \"Pulanglah kepada keluarga kalian, tinggallah bersama mereka, ajarilah mereka, perintahkan mereka jika telah datang waktu shalat, hendaklah diantara kalian adzan, kemudian yang dewasa menjadi imamnya\"."},"518":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ قَالَجَاءَ أَبُو سُلَيْمَانَ مَالِكُ بْنُ الْحُوَيْرِثِ إِلَى مَسْجِدِنَا فَقَالَ وَاللَّهِ إِنِّي لَأُصَلِّي وَمَا أُرِيدُ الصَّلَاةَ وَلَكِنِّي أُرِيدُ أَنْ أُرِيَكُمْ كَيْفَ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي قَالَ فَقَعَدَ فِي الرَّكْعَةِ الْأُولَى حِينَ رَفَعَ رَأْسَهُ مِنْ السَّجْدَةِ الْأَخِيرَةِ ثُمَّ قَامَ","id":"Telah menceritakan kepada kami [Isma'il] telah menceritakan kepada kami [Ayyub] [Abu Qilabah] berkata; datang [Abu Sulaiman, Malik bin Al Huwarits] ke masjid kami lalu berkata; demi Allah saya hendak Shalat namun bukan shalat yang sebenarnya, saya hanya ingin memperlihatkan kepada kalian bagaimana saya melihat Nabi Shallallahu'alaihiwasallam Shalat. (Abu Qilabah Radliyallahu'anhu) berkata; lalu dia duduk pada rekaat yang pertama ketika mengangkat kepalanya dari sujud akhir lalu berdiri."},"519":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عَدِيٍّ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ نَصْرِ بْنِ عَاصِمٍ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِأَنَّهُ رَأَى نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْفَعُ يَدَيْهِ فِي صَلَاتِهِ إ��ذَا رَفَعَ رَأْسَهُ مِنْ رُكُوعِهِ وَإِذَا سَجَدَ وَإِذَا رَفَعَ رَأْسَهُ مِنْ سُجُودِهِ حَتَّى يُحَاذِيَ بِهَا فُرُوعَ أُذُنَيْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Abu 'Adi] dari [Sa'id] dari [Qatadah] dari [Nashr bin 'Ashim] dari [Malik bin Al Huwarits] dia melihat Nabiyullah Shallallahu'alaihiwasallam mengangkat kedua tangannya dalam shalatnya ketika beliau mengangkat kepalanya dari rukuk, ketika sujud dan jika mengangkat kepalanya dari sujudnya sampai mendekati ujung kedua telinganya."},"520":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُ وَلِصَاحِبٍ لَهُ إِذَا حَضَرَتْ الصَّلَاةُ فَأَذِّنَا وَأَقِيمَا وَقَالَ مَرَّةً فَأَقِيمَا ثُمَّ لِيَؤُمَّكُمَا أَكْبَرُكُمَاقَالَ خَالِدٌ فَقُلْتُ لِأَبِي قِلَابَةَ فَأَيْنَ الْقِرَاءَةُ قَالَ إِنَّهُمَا كَانَا مُتَقَارِبَيْنِ","id":"Telah menceritakan kepada kami [Isma'il] dari [Khalid Al Hadza'] dari [Abu Qilabah] dari [Malik bin Al Huwarits] Nabi Shallallahu'alaihi wasallam bersabda kepada kepada dia dan temannya 'Jika datang waktu shalat, agar ada yang mengumandangkan adzan dan beriqamatlah.' Pada kesempatan lain beliau berkata; 'Beriqamatlah, lalu yang paling dewasa diantara kalian menjadi imam.' Khalid berkata; saya bertanya kepada Abu Qilabah, 'Bagaimana panjang bacaan keduanya? Dia menjawab, keduanya nyaris sama.'"},"521":{"ar":"حَدَّثَنَا أَبُو عُبَيْدَةَ يَعْنِي الْحَدَّادَ قَالَ حَدَّثَنَا أَبَانُ قَالَ الْعَطَّارُ عَنْ بُدَيْلٍ عَنْ أَبِي عَطِيَّةَ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِ قَالَزَارَنَا فِي مَسْجِدِنَا قَالَ فَأُقِيمَتْ الصَّلَاةُ فَقَالُوا أُمَّنَا رَحِمَكَ اللَّهُ فَقَالَ لَا يُصَلِّي رَجُلٌ مِنْكُمْ قَالَ فَلَمَّا قَضَى الصَّلَاةَ قَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا زَارَ رَجُلٌ قَوْمًا فَلَا يَؤُمَّهُمْ يَؤُمُّهُمْ رَجُلٌ مِنْهُمْ","id":"Telah menceritakan kepada kami [Abu 'Ubaidah] yaitu Al Haddad, berkata; telah menceritakan kepada kami [Aban] berkata Al 'Athor dari [Budail] dari [Abu 'Athiyyah] dari [Malik bin Al Huwarits] berkata; Pernah seseorang mengunjungi kami ketika kami berada di masjid, lalu dilaksanakan Shalat. Mereka berkata 'Jadilah imam kepada kami semoga Allah merahmatimu.' Lalu dia berkata; tidak, yang menjadi imam hendaklah salah seorang diantara kalian. Tatkala selesai Shalat dia berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jika salah seorang berkunjung kepada suatu kaum maka janganlah menjadi imam mereka, tapi yang menjadi imam adalah dari mereka (yang dikunjungi) \"."},"522":{"ar":"حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبَانُ بْنُ يَزِيدَ الْعَطَّارُ عَنْ بُدَيْلِ بْنِ مَيْسَرَةَ الْعُقَيْلِيِّ قَالَ حَدَّثَنِي أَبُو عَطِيَّةَ مَوْلًى مِنَّا عَنْ مَالِكِ بْنِ الْحُوَيْرِثِ قَالَكَانَ يَأْتِينَا فِي مُصَلَّانَا فَقِيلَ لَهُ تَقَدَّمْ فَصَلِّ فَقَالَ لِيُصَلِّ بَعْضُكُمْ حَتَّى أُحَدِّثَكُمْ لِمَ لَمْ أُصَلِّ بِكُمْ فَلَمَّا صَلَّى الْقَوْمُ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا زَارَ أَحَدُكُمْ قَوْمًا فَلَا يُصَلِّ بِهِمْ لِيُصَلِّ بِهِمْ رَجُلٌ مِنْهُمْ","id":"Telah menceritakan kepada kami [Yunus bin Muhammad] telah menceritakan kepada kami [Aban bin Zaid, Al 'Athor] dari [Budail bin Maisaroh Al 'Uqaili] berkata; telah menceritakan kepadaku [Abu 'Athiyyah] salah budak dari kami, dari [Malik bin Al Huwarits] berkata; Pernah seseorang datang di tempat Shalat kami, lalu diantara kami ada yang berkata 'Majulah dan Shalatlah.' Lalu dia berkata; Hendaklah yang menjadi imam sebagian diantara kalian sehingga saya ceritakan kenapa saya tidak mau mengimami kalian. Tatkala orang-orang telah melaksanakan Shalat, dia berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jika salah seorang dari kalian sedang mengunjungi satu kaum maka janganlah menjadi imam kepada mereka, tapi hendaklah yang menjadi imam mereka adalah orang dari mereka\"."},"523":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ نَصْرِ بْنِ عَاصِمٍ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِأَنَّهُ رَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْفَعُ يَدَيْهِ إِذَا أَرَادَ أَنْ يَرْكَعَ وَإِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ وَإِذَا رَفَعَ رَأْسَهُ مِنْ السُّجُودِ حَتَّى يُحَاذِيَ بِهِمَا فُرُوعَ أُذُنَيْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Nashr bin 'Ashim] dari [Malik bin Al Huwarits] dia melihat Rasulullah Shallallahu'alaihiwasallam mengangkat kedua tangannya ketika hendak rukuk, ketika mengangkat kepalanya dari rukuk dan ketika mengangkat kepalanya dari sujud sehingga mendekati kedua telinganya."},"524":{"ar":"حَدَّثَنَا هَارُونُ بْنُ مَعْرُوفٍ حَدَّثَنَا ابْنُ وَهْبٍ يَعْنِي عَبْدَ اللَّهِ بْنَ وَهْبٍ الْمِصْرِيَّ قَالَ عَبْد اللَّهِ وَسَمِعْتُهُ أَنَا مِنْ هَارُونَ حَدَّثَنَا عَمْرُو بْنُ الْحَارِثِ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَسْلَمَ أَبِي عِمْرَانَ عَنْ هُبَيْبِ بْنِ مُغْفِلٍ الْغِفَارِيِّأَنَّهُ رَأَى مُحَمَّدًا الْقُرَشِيَّ قَامَ يَجُرُّ إِزَارَهُ فَنَظَرَ إِلَيْهِ هُبَيْبٌ فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ وَطِئَهُ خُيَلَاءَ وَطِئَهُ فِي النَّارِ","id":"Telah menceritakan kepada kami [Harun bin Makruf] telah menceritakan kepada kami [Ibnu Wahb] yaitu Abdullah bin Wahb Al Misri berkata; Abdullah dan saya telah mendengarnya dari [Harun] telah menceritakan kepada kami ['Amr bin Abu Habib] dari [Yazid bin Abu Habib] dari [Aslam Abu 'Imran] dari [Hubaib Mughfil Al Ghifari] dia pernah melihat Muhammad Al Qurasyi berdiri dengan menyeret sarungnya lalu Huhaib melihatnya, lantas berkata; 'Saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Siapa yang menginjak kainnya karena sombong, dia telah menginjak neraka\"."},"525":{"ar":"حَدَّثَنَا يَحْيَى بْنُ إِسْحَاقَ قَالَ أَخْبَرَنَا ابْنُ لَهِيعَةَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ قَالَ أَخْبَرَنِي أَسْلَمُ أَبُو عِمْرَانَ عَنْ هُبَيْبٍ الْغِفَارِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ وَطِئَ عَلَى إِزَارِهِ خُيَلَاءَ وَطِئَ فِي نَارِ جَهَنَّمَ","id":"Telah menceritakan kepada kami [Yahya bin Ishaq] berkata; telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Yazid bin Abu Habib] berkata; telah mengabarkan kepadaku [Aslam Abu 'Imron] dari [Hubaib Mughfil Al Ghifari] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa yang menginjak sarungnya karena sombong, maka dia menginjak Neraka Jahannam\"."},"526":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَسْلَمَ أَنَّهُ سَمِعَ هُبَيْبَ بْنَ مُغْفِلٍ صَاحِبَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَوَرَأَى رَجُلًا يَجُرُّ رِدَاءَهُ خَلْفَهُ وَيَطَؤُهُ فَقَالَ سُبْحَانَ اللَّهِ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ وَطِئَهُ مِنْ الْخُيَلَاءِ وَطِئَهُ فِي النَّارِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata; telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Yazid bin Abu Habib] dari [Aslam] dia telah mendengar [Hubaib bin Mughfil] salah seorang sahabat Nabi Shallallahu'alaihiwasallam, dia melihat seorang laki-laki yang memanjangkan kainnya sampai kebelakangnya dan menginjaknya. Dia berkata; Maha Suci Allah, Saya pernah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa yang menginjak kainnya karena sombong, dia telah menginjaknya di neraka\"."},"527":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا عَاصِمٌ الْأَحْوَلُ حَدَّثَنَا كُرَيْبُ بْنُ الْحَارِثِ بْنِ أَبِي مُوسَى عَنْ أَبِي بُرْدَةَ بْنِ قَيْسٍ أَخِي أَبِي مُوسَى الْأَشْعَرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ اجْعَلْ فَنَاءَ أُمَّتِي فِي سَبِيلِكَ بِالطَّعْنِ وَالطَّاعُونِ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Abdul Wahid bin Ziyad] telah menceritakan kepada kami ['Ashim Al Ahwal] telah menceritakan kepada kami [Kuraib bin Al Harits bin Abu Musa] dari [Abu Burdah bin Qais, saudara Abu Musa Al 'Asyari] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Ya Allah, jadikanlah habisnya umatku berada pada jalan-Mu dengan meninggal dalam perang dan karena penyakit Tha'un\"."},"528":{"ar":"حَدَّثَنَا حَسَنٌ حَدَّثَنَا ابْنُ لَهِيعَةَ قَالَ وَحَدَّثَنَا يَحْيَى بْنُ غَيْلَانَ حَدَّثَنَا رِشْدِينُ حَدَّثَنَا زَبَّانُ بْنُ فَائِدٍ الْحَبْرَانِيُّ عَنْ سَهْلِ بْنِ مُعَاذِ بْنِ أَنَسٍ الْجُهَنِيِّ عَنْ أَبِيهِ مُعَاذِ بْنِ أَنَسٍ الْجُهَنِيِّ صَاحِبِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَرَأَ قُلْ هُوَ اللَّهُ أَحَدٌ حَتَّى يَخْتِمَهَا عَشْرَ مَرَّاتٍ بَنَى اللَّهُ لَهُ قَصْرًا فِي الْجَنَّةِ فَقَالَ عُمَرُ بْنُ الْخَطَّابِ إِذَنْ أَسْتَكْثِرَ يَا رَسُولَ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُ أَكْثَرُ وَأَطْيَبُ","id":"Telah menceritakan kepada kami [Hasan] telah menceritakan kepada kami [Ibnu Lahi'ah] berkata; dan telah menceritakan kepada kami [Yahya bin Ghailan] telah menceritakan kepada kami [Risydin] telah menceritakan kepada kami [Zabban bin Fa'id Al Habrani] dari [Sahl bin Mu'adz bin Anas Al Juhani] dari [Bapaknya, Mu'adz bin Anas Al Juhani] salah seorang sahabat Nabi Shallallahu'alaihiwasallam dari Nabi Shallallahu'alaihi wasallam bersabda: \"Barangsiapa membaca QUL HUWA ALLAHU AHAD, sampai sepuluh kali, Allah membangunkan istana di surga baginya\". Umar bin Khattab berkata 'Kalau begitu saya akan memperbanyak Wahai Rasulullah!.' Rasulullah Shallallahu'alaihiwasallam bersabda: \" Istana Allah mebih banyak dan lebih bagus\""},"529":{"ar":"حَدَّثَنَا حَسَنٌ حَدَّثَنَا ابْنُ لَهِيعَةَ قَالَ حَدَّثَنَا يَحْيَى بْنُ غَيْلَانَ قَالَ حَدَّثَنِي رِشْدِينُ بْنُ سَعْدٍ عَنْ زَبَّانَ عَنْ سَهْلِ بْنِ مُعَاذٍ عَنْ أَبِيهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَرَأَ أَلْفَ آيَةٍ فِي سَبِيلِ اللَّهِ تَبَارَكَ وَتَعَالَى كُتِبَ يَوْمَ الْقِيَامَةِ مَعَ النَّبِيِّينَ وَالصِّدِّيقِينَ وَالشُّهَدَاءِ وَالصَّالِحِينَ وَحَسُنَ أُولَئِكَ رَفِيقًا إِنْ شَاءَ اللَّهُ تَعَالَى","id":"Telah menceritakan kepada kami [Hasan] telah menceritakan kepada kami [Ibnu Lahi'ah] berkata; telah menceritakan kepada kami [Yahya bin Ghoilan] berkata; telah menceritakan kepadaku [Risydin bin Sa'd] dari [Zabban] dari [Sahl bin Mu'adz] dari [Bapaknya] dari Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa membaca seribu ayat di jalan Allah Tabaroka Wa Ta'ala maka pada Hari Kiamat akan ditulis bersama pada Nabi, orang yang dipercaya, para syuhada' dan orang yang shalih, mereka itulah sebaik-baik teman INSYA'ALLAH\""},"530":{"ar":"حَدَّثَنَا حَسَنٌ حَدَّثَنَا ابْنُ لَهِيعَةَ قَالَ وَحَدَّثَنَا يَحْيَى بْنُ غَيْلَانَ قَالَ حَدَّثَنَا رِشْدِينُ عَنْ زَبَّانَ عَنْ سَهْلِ بْنِ مُعَاذٍ عَنْ أَبِيهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الذِّكْرَ فِي سَبِيلِ اللَّهِ تَعَالَى يُضَعَّفُ فَوْقَ النَّفَقَةِ بِسَبْعِ مِائَةِ ضِعْفٍ قَالَ يَحْيَى فِي حَدِيثِهِ بِسَبْعِ مِائَةِ أَلْفِ ضِعْفٍ","id":"Telah menceritakan kepada kami [Hasan] telah menceritakan kepada kami [Ibnu Lahi'ah] berkata; dan telah menceritakan kepada kami [Yahya bin Ghailan] berkata; telah menceritakan kepada kami [Risydin] dari [Zabban] dari [Sahl bin Mu'adz] dari [Bapaknya] dari Rasulullah Shallallahu'alaihiwasallam beliau bersabda: \" Dzikir di jalan Allah Ta'ala akan dilipatgandakan di atas nafkah dengan tujuh ratus kali lipatnya. [Yahya] berkata; dalam haditsnya, \"Tujuh ratus ribu lipat\"."},"531":{"ar":"حَدَّثَنَا حَسَنٌ حَدَّثَنَا ابْنُ لَهِيعَةَ حَدَّثَنَا زَبَّانُ عَنْ سَهْلِ بْنِ مُعَاذٍ عَنْ أَبِيهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ رَجُلًا سَأَلَهُ فَقَالَ أَيُّ الْجِهَادِ أَعْظَمُ أَجْرًا قَالَ أَكْثَرُهُمْ لِلَّهِ تَبَارَكَ وَتَعَالَى ذِكْرًا قَالَ فَأَيُّ الصَّائِمِينَ أَعْظَمُ أَجْرًا قَالَ أَكْثَرُهُمْ لِلَّهِ تَبَارَكَ وَتَعَالَى ذِكْرًا ثُمَّ ذَكَرَ لَنَا الصَّلَاةَ وَالزَّكَاةَ وَالْحَجَّ وَالصَّدَقَةَ كُلُّ ذَلِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَكْثَرُهُمْ لِلَّهِ تَبَارَكَ وَتَعَالَى ذِكْرًا فَقَالَ أَبُو بَكْرٍ رَضِيَ اللَّهُ تَعَالَى عَنْهُ لِعُمَرَ رَضِيَ اللَّهُ تَعَالَى عَنْهُ يَا أَبَا حَفْصٍ ذَهَبَ الذَّاكِرُونَ بِكُلِّ خَيْرٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَجَلْ","id":"Telah menceritakan kepada kami [Hasan] telah menceritakan kepada kami [Ibnu Lahi'ah] telah menceritakan kepada kami [Zabban] dari [Sahl bin Mu'adz] dari [Bapaknya] dari Rasulullah Shallallahu'alaihiwasallam ada seorang yang bertanya kepada beliau, jihad apakah yang paling besar pahalanya? Beliau menjawab, orang yang paling banyak berdzikir kepada Allah Tabaraka Wa Ta'ala. Dia bertanya lagi, 'Puasa apakah yang paling banyak pahalanya? Beliau menjawab, 'Orang yang paling banyak berdzikir kepada Allah Tabaraka Wa Ta'ala.' Lalu beliau menyebutkan Shalat, zakat, haji dan sedekah kepada kami. Kesemuanya Rasulullah Shallallahu'alaihiwasallam bersabda: \"Orang yang paling banyak berdzikir kepada Allah Tabaraka Wa Ta'ala\". Abu Bakar Radliyallahu'anhu berkata kepada Umar Radliyallahu'anhu, 'Wahai Abu Hafs, orang yang berdzikir membawa semua kebaikan?. Rasulullah Shallallahu'alaihiwasallam bersabda: \"Ya\"."},"532":{"ar":"حَدَّثَنَا حَسَنٌ حَدَّثَنَا ابْنُ لَهِيعَةَ حَدَّثَنَا زَبَّانُ عَنْ سَهْلِ بْنِ مُعَاذٍ عَنْ أَبِيهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ حَقٌّ عَلَى مَنْ قَامَ عَلَى مَجْلِسٍ أَنْ يُسَلِّمَ عَلَيْهِمْ وَحَقٌّ عَلَى مَنْ قَامَ مِنْ مَجْلِسٍ أَنْ يُسَلِّمَ فَقَامَ رَجُلٌ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَكَلَّمُ فَلَمْ يُسَلِّمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَسْرَعَ مَا نَسِيَ","id":"Telah menceritakan kepada kami [Hasan] telah menceritakan kepada kami [Ibnu Lahi'ah] telah menceritakan kepada kami [Zabban] dari [Sahl bin Mu'adz] dari [Bapaknya] dari Rasulullah Shallallahu'alaihiwasallam beliau bersabda: \"Kewajiban orang yang mendatangi sebuah majlis untuk mengucapkan salam kepada hadirin. Dan kewajiban orang yang hendak meninggalkan majlis juga harus mengucapkan salam\". Lalu ada seorang yang berdiri yang ketika itu Rasulullah Shallallahu'alaihiwasallam sedang berbicara. Orang itu tidak mengucapkan salam, maka beliau bersabda: \"Alangkah cepatnya dia lupa\"."},"533":{"ar":"حَدَّثَنَا حَسَنٌ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ زَبَّانَ عَنْ سَهْلِ بْنِ مُعَاذٍ عَنْ أَبِيهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ أَعْطَى لِلَّهِ تَعَالَى وَمَنَعَ لِلَّهِ تَعَالَى وَأَحَبَّ لِلَّهِ تَعَالَى وَأَبْغَضَ لِلَّهِ تَعَالَى وَأَنْكَحَ لِلَّهِ تَعَالَى فَقَدْ اسْتَكْمَلَ إِيمَانَهُ","id":"Telah menceritakan kepada kami [Hasan] telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Zabban] dari [Sahl bin Mu'adz] dari [Bapaknya] dari Rasulullah Shallallahu'alaihiwasallam beliau bersabda: \"Barangsiapa memberi karena Allah Ta'ala, tidak memberi karena Allah Ta'ala, marah karena Allah Ta'ala dan menikah karena Allah Ta'ala, imannya telah sempurna\"."},"534":{"ar":"حَدَّثَنَا حَسَنٌ حَدَّثَنَا ابْنُ لَهِيعَةَ قَالَ حَدَّثَنَا زَبَّانُ عَنْ سَهْلِ بْنِ مُعَاذِ بْنِ أَنَسٍ عَنْ أَبِيهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ أَفْضَلُ الْفَضَائِلِ أَنْ تَصِلَ مَنْ قَطَعَكَ وَتُعْطِيَ مَنْ مَنَعَكَ وَتَصْفَحَ عَمَّنْ شَتَمَكَ","id":"Telah menceritakan kepada kami [Hasan] telah menceritakan kepada kami [Ibnu Lahi'ah] berkata; telah menceritakan kepada kami [Zabban] dari [Sahl bin Mu'adz bin Anas] dari [Bapaknya] dari Rasulullah Shallallahu'alaihiwasallam beliau bersabda: \"Keutamaan yang paling utama adalah kamu menyambung orang yang telah memutusmu, kamu memberi orang yang tidak pernah memberimu dan mememaafkan orang yang mencelamu\"."},"535":{"ar":"حَدَّثَنَا حَسَنٌ حَدَّثَنَا ابْنُ لَهِيعَةَ حَدَّثَنَا زَبَّانُ عَنْ سَهْلِ بْنِ مُعَاذٍ عَنْ أَبِيهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ إِذَا سَمِعْتُمْ الْمُنَادِيَ يُثَوِّبُ بِالصَّلَاةِ فَقُولُوا كَمَا يَقُولُ","id":"Telah menceritakan kepada kami [Hasan] telah menceritakan kepada kami [Ibnu Lahi'ah] telah menceritakan kepada kami [Zabban] dari [Sahl bin Mu'adz] dari [Bapaknya] dari Rasulullah Shallallahu'alaihiwasallam beliau bersabda: \"Jika kalian mendengar seorang muadzin mengucapkan bacaan tatswib maka ucapkanlah sebagaimana yang dia ucapkan\". "},"536":{"ar":"حَدَّثَنَا حَسَنٌ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ زَبَّانَ عَنْ سَهْلِ بْنِ مُعَاذٍ عَنْ أَبِيهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَقُولُ الضَّاحِكُ فِي الصَّلَاةِ وَالْمُلْتَفِتُ وَالْمُفَقِّعُ أَصَابِعَهُ بِمَنْزِلَةٍ وَاحِدَةٍ","id":"Telah menceritakan kepada kami [Hasan] telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Zabban] dari [Sahl bin Mu'adz] dari [Bapaknya] dari Rasulullah Shallallahu'alaihiwasallam beliau bersabda: \"Orang yang tertawa, menoleh, dan meraba-raba dengan jari-jarinya ketika shalat, kesemuanya adalah sama\". "},"537":{"ar":"حَدَّثَنَا حَسَنٌ حَدَّثَنَا ابْنُ لَهِيعَةَ حَدَّثَنَا زَبَّانُ حَدَّثَنَا سَهْلٌ عَنْ أَبِيهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ أَمَرَ أَصْحَابَهُ بِالْغَزْوِ وَأَنَّ رَجُلًا تَخَلَّفَ وَقَالَ لِأَهْلِهِ أَتَخَلَّفُ حَتَّى أُصَلِّيَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ ثُمَّ أُسَلِّمَ عَلَيْهِ وَأُوَدِّعَهُ فَيَدْعُوَ لِي بِدَعْوَةٍ تَكُونُ شَافِعَةً يَوْمَ الْقِيَامَةِ فَلَمَّا صَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقْبَلَ الرَّجُلُ مُسَلِّمًا عَلَيْهِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَدْرِي بِكَمْ سَبَقَكَ أَصْحَابُكَ قَالَ نَعَمْ سَبَقُونِي بِغَدْوَتِهِمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي نَفْسِي بِيَدِهِ لَقَدْ سَبَقُوكَ بِأَبْعَدِ مَا بَيْنَ الْمَشْرِقَيْنِ وَالْمَغْرِبَيْنِ فِي الْفَضِيلَةِ","id":"Telah menceritakan kepada kami [Hasan] telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Zabban] telah menceritakan kepada kami [Sahl] dari [Bapaknya] dari Rasulullah Shallallahu'alaihiwasallam beliau menyuruh kepada para sahabatnya untuk berperang. Namun ada seseorang yang berbalik kebelakang dan berkata kepada keluarganya, saya akan berangkat di belakang hingga saya dapat Shalat dhuhur bersama Rasulullah Shallallahu'alaihiwasallam. Lalu saya mengucapkan salam kepada beliau, dan saya menitipkan pesan agar beliau mendo'akan dengan do'a yang akan menjadi syafaat pada hari kiamat. Tatkala Nabi Shallallahu'alaihiwasallam Shalat, maka orang itu menemui Rasulullah Shallallahu'alaihiwasallam dan mengucapkan salam kepada beliau. Lalu (Rasulullah Shallallahu'alaihiwasallam) bersabda kepadanya, \"Apakah kau tahu berapa banyakkah sahabatmu mendahuluimu pahalamu\". Dia menjawab, \"Ya, mereka mendahuluiku dengan keberangkatan mereka menuju peperangan\" Rasulullah Shallallahu'alaihiwasallam bersabda: \"Demi Dzat yang jiwaku berada di tangan-Nya, mereka telah mendahuluimu dengan keutamakan yang jaraknya lebih jauh daripada jarak antara timur dan barat\"."},"538":{"ar":"حَدَّثَنَا مُعَاوِيَةُ بْنُ عَمْرٍو وَأَبُو سَعِيدٍ قَالَا حَدَّثَنَا زَائِدَةُ قَالَ حَدَّثَنَا السَّائِبُ بْنُ حُبَيْشٍ الكَلَاعِيُّ عَنْ أَبِي الشَّمَّاخِ الْأَزْدِيِّ عَنِ ابْنِ عَمٍّ لَهُ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَتَى مُعَاوِيَةَ فَدَخَلَ عَلَيْهِ فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ وَلِيَ أَمْرًا مِنْ أَمْرِ النَّاسِ ثُمَّ أَغْلَقَ بَابَهُ دُونَ الْمِسْكِينِ وَالْمَظْلُومِ أَوْ ذِي الْحَاجَةِ أَغْلَقَ اللَّهُ تَبَارَكَ وَتَعَالَى دُونَهُ أَبْوَابَ رَحْمَتِهِ عِنْدَ حَاجَتِهِ وَفَقْرِهِ أَفْقَرُ مَا يَكُونُ إِلَيْهَا","id":"Telah menceritakan kepada kami [Mu'awiyah bin 'Amr] dan [Abu Sa'id] berkata; telah menceritakan kepada kami [Za'idah] berkata; telah menceritakan kepada kami [As Sa'ib bin Hubaisy Al Kala'i] dari [Abu Asy-Syammah Al Azdi] dari [anak pamannya] salah seorang sahabat Nabi Shallallahu'alaihiwasallam, dia menemui Mu'awiyah lalu berkata; saya telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa mewenangi suatu urusan dari kalangan manusia lalu dia menutup pintunya untuk orang miskin, orang yang teraniaya atau orang yang butuh kepadanya, niscaya Allah Tabaraka Wa Ta'ala menutup pintu rahmAt Nya ketika dia membutuhkannya ketika kefakirannya menjadi sangat memerlukan rahmAt Nya."},"539":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ إِسْحَاقَ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ قَالَ أَخْبَرَنَا يُونُسُ عَنِ ابْنِ شِهَابٍ قَالَ حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ أَنَّ رَجُلًا مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَهُ أَنَّهُسَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا كَانَ أَحَدُكُمْ فِي صَلَاتِهِ فَلَا يَرْفَعْ بَصَرَهُ إِلَى السَّمَاءِ أَنْ يُلْتَمَعَ بَصَرُهُ","id":"Telah menceritakan kepada kami ['Ali bin Ishaq] berkata; telah mengabarkan kepada kami [Abdullah] berkata; telah mengabarkan kepada kami [Yunus] dari [Ibnu Syihab] berkata; telah menceritakan kepadaku ['Ubaidullah bin 'Utbah bin Mas'ud] bahwa [salah seorang sahabat] Rasulullah Shallallahu'alaihiwasallam menceritakannya dia telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jika salah seorang dalam Shalat, maka janganlah menengadahkan penglihatannya ke langit, karena dikhawatirkan penglihatannya akan disambar \"."},"540":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سَيَّارٍ وَيَحْيَى بْنِ سَعِيدٍ الْقَاضِي أَنَّهُمَا سَمِعَا عُبَادَةَ بْنَ الْوَلِيدِ بْنِ عُبَادَةَ يُحَدِّثُ عَنْ أَبِيهِ أَمَّا سَيَّارٌ فَقَالَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَمَّا يَحْيَى فَقَالَ عَنْ أَبِيهِ عَنْ جَدِّهِقَالَ بَايَعْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى السَّمْعِ وَالطَّاعَةِ فِي عُسْرِنَا وَيُسْرِنَا وَمَنْشَطِنَا وَمَكْرَهِنَا وَالْأَثَرَةِ عَلَيْنَا وَأَنْ لَا نُنَازِعَ الْأَمْرَ أَهْلَهُ وَنَقُومَ بِالْحَقِّ حَيْثُ كَانَ وَلَا نَخَافَ فِي اللَّهِ لَوْمَةَ لَائِمٍقَالَ و قَالَ شُعْبَةُ سَيَّارٌ لَمْ يَذْكُرْ هَذَا الْحَرْفَ وَحَيْثُ مَا كَانَ ذَكَرَهُ يَحْيَى قَالَ شُعْبَةُ إِنْ كُنْتُ ذَكَرْتُ فِيهِ شَيْئًا فَهُوَ عَنْ سَيَّارٍ أَوْ عَنْ يَحْيَى","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Sayyar] dan [Yahya bin Sa'id Al Qodli] keduanya telah mendengar ['Ubadah bin Al Walid] menceritakan dari [Bapaknya]. Adapun [Sayyar] berkata; dari Nabi Shallallahu'alaihiwasallam. [Yahya] berkata; dari [Bapaknya] dari [kakeknya] berkata; kami berbaiat kepada Rasulullah Shallallahu'alaihiwasallam untuk mendengar, taat pada saat susah maupun mudah, saat kami giat maupun malas dan kami harus berbuat itsar (mengutamakan orang lain daripada dirinya). Kami tidak menentang urusan yang dilakukan yang berwenang, dan melaksanakan Al haq di mana saja. Tidak takut karena Allah terhadap orang yang mencela. (Muhammad bin Ja'far Radliyallahu'anhu) berkata; Syu'bah berkata; Sayyar tidak memyebutkan teks yang disebutkan Yahya. Syu'bah berkata; jika saya menyebutkan sesuatu di dalamnya maka itu dari Sayyar atau dari Yahya."},"541":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ عِيسَى قَالَ حَدَّثَنِي يَحْيَى بْنُ سُلَيْمٍ عَنْ عَبْدِ اللَّهِ بْنِ عُثْمَانَ بْنِ خُثَيْمٍ عَنْ سَعِيدِ بْنِ أَبِي رَاشِدٍقَالَ لَقِيتُ التَّنُوخِيَّ رَسُولَ هِرَقْلَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِحِمْصَ وَكَانَ جَارًا لِي شَيْخًا كَبِيرًا قَدْ بَلَغَ الْفَنَدَ أَوْ قَرُبَ فَقُلْتُ أَلَا تُخْبِرُنِي عَنْ رِسَالَةِ هِرَقْلَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرِسَالَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى هِرَقْلَ فَقَالَ بَلَى قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَبُوكَ فَبَعَثَ دِحْيَةَ الْكَلْبِيَّ إِلَى هِرَقْلَ فَلَمَّا أَنْ جَاءَهُ كِتَابُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعَا قِسِّيسِي الرُّومِ وَبَطَارِقَتَهَا ثُمَّ أَغْلَقَ عَلَيْهِ وَعَلَيْهِمْ بَابًا فَقَالَ قَدْ نَزَلَ هَذَا الرَّجُلُ حَيْثُ رَأَيْتُمْ وَقَدْ أَرْسَلَ إِلَيَّ يَدْعُونِي إِلَى ثَلَاثِ خِصَالٍ يَدْعُونِي إِلَى أَنْ أَتَّبِعَهُ عَلَى دِينِهِ أَوْ عَلَى أَنْ نُعْطِيَهُ مَالَنَا عَلَى أَرْضِنَا وَالْأَرْضُ أَرْضُنَا أَوْ نُلْقِيَ إِلَيْهِ الْحَرْبَ وَاللَّهِ لَقَدْ عَرَفْتُمْ فِيمَا تَقْرَءُونَ مِنْ الْكُتُبِ لَيَأْخُذَنَّ مَا تَحْتَ قَدَمَيَّ فَهَلُمَّ نَتَّبِعْهُ عَلَى دِينِهِ أَوْ نُعْطِيهِ مَالَنَا عَلَى أَرْضِنَا فَنَخَرُوا نَخْرَةَ رَجُلٍ وَاحِدٍ حَتَّى خَرَجُوا مِنْ بَرَانِسِهِمْ وَقَالُوا تَدْعُونَا إِلَى أَنْ نَدَعَ النَّصْرَانِيَّةَ أَوْ نَكُونَ عَبِيدًا لِأَعْرَابِيٍّ جَاءَ مِنْ الْحِجَازِ فَلَمَّا ظَنَّ أَنَّهُمْ إِنْ خَرَجُوا مِنْ عِنْدِهِ أَفْسَدُوا عَلَيْهِ الرُّومَ رَفَأَهُمْ وَلَمْ يَكَدْ وَقَالَ إِنَّمَا قُلْتُ ذَلِكَ لَكُمْ لِأَعْلَمَ صَلَابَتَكُمْ عَلَى أَمْرِكُمْ ثُمَّ دَعَا رَجُلًا مِنْ عَرَبِ تُجِيبَ كَانَ عَلَى نَصَارَى الْعَرَبِ فَقَالَ ادْعُ لِي رَجُلًا حَافِظًا لِلْحَدِيثِ عَرَبِيَّ اللِّسَانِ أَبْعَثْهُ إِلَى هَذَا الرَّجُلِ بِجَوَابِ كِتَابِهِ فَجَاءَ بِي فَدَفَعَ إِلَيَّ هِرَقْلُ كِتَابًا فَقَالَ اذْهَبْ بِكِتَابِي إِلَى هَذَا الرَّجُلِ فَمَا ضَيَّعْتُ مِنْ حَدِيثِهِ فَاحْفَظْ لِي مِنْهُ ثَلَاثَ خِصَالٍ انْظُرْ هَلْ يَذْكُرُ صَحِيفَتَهُ الَّتِي كَتَبَ إِلَيَّ بِشَيْءٍ وَانْظُرْ إِذَا قَرَأَ كِتَابِي فَهَلْ يَذْكُرُ اللَّيْلَ وَانْظُرْ فِي ظَهْرِهِ هَلْ بِهِ شَيْءٌ يَرِيبُكَ فَانْطَلَقْتُ بِكِتَابِهِ حَتَّى جِئْتُ تَبُوكَ فَإِذَا هُوَ جَالِسٌ بَيْنَ ظَهْرَانَيْ أَصْحَابِهِ مُحْتَبِيًا عَلَى الْمَاءِ فَقُلْتُ أَيْنَ صَاحِبُكُمْ قِيلَ هَا هُوَ ذَا فَأَقْبَلْتُ أَمْشِي حَتَّى جَلَسْتُ بَيْنَ يَدَيْهِ فَنَاوَلْتُهُ كِتَابِي فَوَضَعَهُ فِي حَجْرِهِ ثُمَّ قَالَ مِمَّنْ أَنْتَ فَقُلْتُ أَنَا أَحَدُ تَنُوخَ قَالَ هَلْ لَكَ فِي الْإِسْلَامِ الْحَنِيفِيَّةِ مِلَّةِ أَبِيكَ إِبْرَاهِيمَ قُلْتُ إِنِّي رَسُولُ قَوْمٍ وَعَلَى دِينِ قَوْمٍ لَا أَرْجِعُ عَنْهُ حَتَّى أَرْجِعَ إِلَيْهِمْ فَضَحِكَ وَقَالَ{ إِنَّكَ لَا تَهْدِي مَنْ أَحْبَبْتَ وَلَكِنَّ اللَّهَ يَهْدِي مَنْ يَشَاءُ وَهُوَ أَعْلَمُ بِالْمُهْتَدِينَ }يَا أَخَا تَنُوخَ إِنِّي كَتَبْتُ بِكِتَابٍ إِلَى كِسْرَى فَمَزَّقَهُ وَاللَّهُ مُمَزِّقُهُ وَمُمَزِّقٌ مُلْكَهُ وَكَتَبْتُ إِلَى النَّجَاشِيِّ بِصَحِيفَةٍ فَخَرَقَهَا وَاللَّهُ مُخْرِقُهُ وَمُخْرِقٌ مُلْكَهُ وَكَتَبْتُ إِلَى صَاحِبِكَ بِصَحِيفَةٍ فَأَمْسَكَهَا فَلَنْ يَزَالَ النَّاسُ يَجِدُونَ مِنْهُ بَأْسًا مَا دَامَ فِي الْعَيْشِ خَيْرٌ قُلْتُ هَذِهِ إِحْدَى الثَّلَاثَةِ الَّتِي أَوْصَانِي بِهَا صَاحِبِي وَأَخَذْتُ سَهْمًا مِنْ جَعْبَتِي فَكَتَبْتُهَا فِي جِلْدِ سَيْفِي ثُمَّ إِنَّهُ نَاوَلَ الصَّحِيفَةَ رَجُلًا عَنْ يَسَارِهِ قُلْتُ مَنْ صَاحِبُ كِتَابِكُمْ الَّذِي يُقْرَأُ لَكُمْ قَالُوا مُعَاوِيَةُ فَإِذَا فِي كِتَابِ صَاحِبِي تَدْعُونِي إِلَى جَنَّةٍ عَرْضُهَا السَّمَوَاتُ وَالْأَرْضُ أُعِدَّتْ لِلْمُتَّقِينَ فَأَيْنَ النَّارُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُبْحَانَ اللَّهِ أَيْنَ اللَّيْلُ إِذَا جَاءَ النَّهَارُ قَالَ فَأَخَذْتُ سَهْمًا مِنْ جَعْبَتِي فَكَتَبْتُهُ فِي جِلْدِ سَيْفِي فَلَمَّا أَنْ فَرَغَ مِنْ قِرَاءَةِ كِتَابِي قَالَ إِنَّ لَكَ حَقًّا وَإِنَّكَ رَسُولٌ فَلَوْ وُجِدَتْ عِنْدَنَا جَائِزَةٌ جَوَّزْنَاكَ بِهَا إِنَّا سَفْرٌ مُرْمِلُونَ قَالَ فَنَادَاهُ رَجُلٌ مِنْ طَائِفَةِ النَّاسِ قَالَ أَنَا أُجَوِّزُهُ فَفَتَحَ رَحْلَهُ فَإِذَا هُوَ يَأْتِي بِحُلَّةٍ صَفُورِيَّةٍ فَوَضَعَهَا فِي حَجْرِي قُلْتُ مَنْ صَاحِبُ الْجَائِزَةِ قِيلَ لِي عُثْمَانُ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّكُمْ يُنْزِلُ هَذَا الرَّجُلَ فَقَالَ فَتًى مِنْ الْأَنْصَارِ أَنَا فَقَامَ الْأَنْصَارِيُّ وَقُمْتُ مَعَهُ حَتَّى إِذَا خَرَجْتُ مِنْ طَائِفَةِ الْمَجْلِسِ نَادَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ تَعَالَ يَا أَخَا تَنُوخَ فَأَقْبَلْتُ أَهْوِي إِلَيْهِ حَتَّى كُنْتُ قَائِمًا فِي مَجْلِسِي الَّذِي كُنْتُ بَيْنَ يَدَيْهِ فَحَلَّ حَبْوَتَهُ عَنْ ظَهْرِهِ وَقَالَ هَاهُنَا امْضِ لِمَا أُمِرْتَ لَهُ فَجُلْتُ فِي ظَهْرِهِ فَإِذَا أَنَا بِخَاتَمٍ فِي مَوْضِعِ غُضُونِ الْكَتِفِ مِثْلِ الْحَجْمَةِ الضَّخْمَةِ","id":"Telah menceritakan kepada kami [Ishaq bin 'Isa] berkata; telah menceritakan kepadaku [Yahya bin Sulaim] dari [Abdullah bin 'Utsman bin Khutsaim] dari [Sa'id bin Abu Rosyid] berkata; Saya pernah bertemu dengan [At Tanuhi] utusan Hirqol kepada Rasulullah Shallallahu'alaihiwasallam di Hims. Saya memiliki seorang tetangga tua yang sudah hampir meninggal, saya bertanya, maukah kamu beritahukan surat Hirqol kepada Nabi Shallallahu'alaihiwasallam dan surat Rasulullah Shallallahu'alaihiwasallam kepadanya? Maka dia menjawab, ya. Rasulullah Shallallahu'alaihiwasallam sampai di Tabuk, lalu beliau mengutus Dihyah Al Kalbi kepada Hirqol. Tatkala datang surat Rasulullah Shallallahu'alaihiwasallam kepadanya, dia memanggil para tokoh petinggi Romawi dan para panglimanya, ditutuplah pintu di antara mereka. Lalu dia (raja Hirqol) berkata; orang ini telah sampai sebagaimana kau lihat, dia telah mengutus kepadaku dan mengajakku kepada tiga hal. Dia mengajakku untuk mengikuti agamanya atau kita harus menyerahkan kepadanya apa yang telah dipanen dari tanah kita atau kita memeranginya. Demi Alloh. Sunguh kalian tahu, apa yang kalian dapatkan pada kitab-kitab yang ada, sungguh dia akan mengambil apa yang ada di bawah kakiku, marilah kita mengikuti pada agamanya atau kita memberikan harta kita saja. Lalu mereka berkata dengan perkataan yang penuh kemarahan dengan satu suara sehingga mereka melepaskan pakaian kebesaran mereka. Mereka berkata; anda mengajak kami untuk meninggalkan Agama Nasrani atau kami menjadi budak bagi Arab yang datang dari Hijaz. Dia menyangka jika dia meninggalkan mereka maka Romawi akan hancur, maka dia sangat sayang kepada mereka dan dia tidak mau. Dan berkata; saya mengatakan hal itu kepada kalian, agar saya mengetahui kekukuhan pada urusan kalian, lalu dia mengundang seorang laki-laki dari Arab Tujib, dia adalah orang Arab Nasrani. Lalu dia (raja Hirqol) berkata; panggilkan kepadaku seorang yang hafal hadits dan bisa berbahasa Arab, yang akan saya utus untuk menjawab surat tersebut, lalu saya di bawa pada Hirqol yang menyerahkan kepadaku suatu surat. Lalu dia (Hirqol) berkata; pergilah dengan membawa suratku ini kepada orang ini, maka saya (At Tanuhi) tidak menyia-nyiakannya, dia menyuruhku menghafal tiga hal. Lihatlah apakah dia menyebutkan lembarannya yang dia tulis kepadaku dan lihatlah tatkala dia membaca tulisanku, apakah dia menyebutkan malam. Lihatlah pada punggungnya apakah ada sesuatu yang meragukanmu. Lalu saya berangkat membawa suratnya sampai saya di Tabuk. Beliau (Rasulullah Shallallahu'alaihiwasallam) sedang berada ditengah-tengah sahabatnya, yang sedang menjulurkan kakinya pada air. Lalu saya bertanya, di manakah sahabat kalian? Ada yang menjawab, dia ada di sini. Lalu saya menemuinya dengan berjalan sehingga saya duduk di depannya lalu saya serahkan tulisanku lalu beliau meletakkannya di pangkuannya. Lalu bersabda: \"Dari mana kamu?\" Saya menjawab, saya adalah satu Tanukh. (Rasulullah Shallallahu'alaihiwasallam) bertanya, apakah termasuk orang Islam yang lurus yaitu agama bapak kalian Ibrahim. Saya menjawab, saya adalah utusan suatu kaum, yang beragama dengan suatu agama yang tidak akan saya tinggalkan sehingga saya kembali kepada mereka. Lalu (Nabi Shallallahu'alaihiwasallam) tertawa dan bersabda: \"kamu tidak akan dapat memberi petunjuk kepada orang yang kamu kasihi, tetapi Allah memberi petunjuk kepada orang yang dikehendaki-Nya, dan Allah lebih mengetahui orang-orang yang mau menerima petunjuk.\" Wahai saudara Tanukh, saya telah menulis suratku kepada Kisra, lalu dia meRabeknya dan Alloh akan meRabeknya dan meRabek kerajaannya. Saya mengirim suratku kepada Najasyi dengan sebuah lembaran, lalu dia membakarnya dan Alloh akan membakarnya dan membakar kerajaannya. Saya telah mengirim kepada temanmu sedang lembaran, lalu dia memegangnya dan orang-orang akan tetap mendapatkan darinya kejelekan walau dalam hidupnya baik. Saya berkata; ini adalah satu dari tiga hal yang dia pesankan kepadaku, lalu saya mengambil satu anak panah dari tempatnya lalu saya tulis dalam kulit pedangku lalu beliau telah menyerahkan lembaran pada seseorang dari sebelah kirinya. Saya bertanya, siapakah orang yang akan membawa surat kalian yang akan membacakan dan kalian? Mereka menjawab, Mu'awiyah. Ternyata dalam surat sahabatku dia mengajakku kepada surga yang luasnya seluas langit dan bumi yang disediakan bagi orang-orang yang bertakwa, maka di manakah neraka? Rasulullah Shallallahu'alaihiwasallam bersabda: \"Maha Suci Alloh, di mana malam jika telah datang waktu siang\". (utusan itu) berkata; lalu saya mengambil anak panah dari tempatnya lalu saya menuliskan pada pedangku setelah beliau selesai membaca suratku, beliau bersabda: \" kamu mendapatkan hak, kamu adalah utusan, jika ada pada kami sesuatu yang akan kami berikan kepadamu. kami sedang kehabisan bekal\" (utusan itu) berkata; lalu ada seorang laki-laki yang berada pada tengah-tengah mereka memanggilnya. Dia berkata; saya yang akan memberinya hadiah, lalu dia membuka barangnya, ternyata dia membawa perhiasan yang berwarna kuning, lalu dia meletakkannya di pangkuanku, lalu saya bertanya siapakah yang telah memberi hadiah, ada yang mengatakan dia adalah 'Utsman. Kemudian Rasulullah Shallallahu'alaihiwasallam bersabda: \"Siapa yang akan memberikan penginapan kepada orang ini?\" Lalu ada seorang pemuda dari Anshor yang berkata; saya. Lalu pemuda itu berdiri dan saya berdiri bersamanya sampai ketika saya telah keluar dari kelompok majlis. Rasulullah Shallallahu'alaihiwasallam memanggilku dan berkata; kemari wahai saudara Tanukh, lalu saya menemui panggilanya sehingga saya berdiri dari tempat dudukku yang tadi saya berada di situ. Lalu beliau membuka cara duduk ihtiba'nya (duduk dengan mengumpulkan kedua lututnya ditaruh di depan dada). Lalu beliau bersabda: \"Kesinilah, lakukan apa yang kau diperintahkan, lalu saya melihat ke belakang punggungnya, ternyata saya melihat stempel di pundak yang paling atas seperti bekas bekam yang besar\"."},"542":{"ar":"حَدَّثَنَا مُعَاوِيَةُ بْنُ هِشَامٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي عَلِيٍّ الصَّيْقَلِ عَنْ قُثَمِ بْنِ تَمَّامٍ أَوْ تَمَّامِ بْنِ قُثَمٍ عَنْ أَبِيهِقَالَ أَتَيْنَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا بَالُكُمْ تَأْتُونِي قُلْحًا لَا تَسَوَّكُونَ لَوْلَا أَنْ أَشُقَّ عَلَى أُمَّتِي لَفَرَضْتُ عَلَيْهِمْ السِّوَاكَ كَمَا فَرَضْتُ عَلَيْهِمْ الْوُضُوءَ","id":"Telah menceritakan kepada kami [Mu'awiyah bin Hisyam] berkata; telah menceritakan kepada kami [Sufyan] dari [Abu 'Ali Ash-Shaiqal] dari Qutsam bin Tammam atau [Tammam bin Qutsam] dari [Bapaknya] berkata; kami mendatangi Nabi Shallallahu'alaihiwasallam lalu beliau bertanya, \"Bagaimana kalian ini, kalian mendatangiku dalam keadaan kuning gigi kalian, kalian tidak bersiwak, kalausaja tidak memberatkan umatku, maka saya wajibkan kepada mereka bersiwak sebagaimana saya wajibkan wudlu.\""},"543":{"ar":"حَدَّثَنَا مُعَاوِيَةُ بْنُ هِشَامٍ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ عُثْمَانَ قَالَ أَبِي و حَدَّثَنَا قَبِيصَةُ عَنْ سُفْيَانَ عَنِ ابْنِ خُثَيْمٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ بَهْمَانَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ حَسَّانَ عَنْ أَبِيهِقَالَ لَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَوَّارَاتِ الْقُبُورِ","id":"Telah menceritakan kepada kami [Mu'awiyah bin Hisyam] telah menceritakan kepada kami [Sufyan] dari [Abdullah bin 'Utsman] berkata; bapakku dan telah menceritakan kepada kami [Qabishah] dari [Sufyan] dari [Ibnu Khutsaim] dari [Abdurrahman bin Bahman] dari [Abdurrahman bin Hassan] dari [Bapaknya] berkata; Rasulullah Shallallahu'alaihiwasallam melaknat para wanita yang terlalu sering berziarah kubur."},"544":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ قَالَ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ حَدَّثَنَا مُحَمَّدُ بْنُ عَلِيٍّ أَبُو جَعْفَرٍ عَنْ رَافِعِ بْنِ بِشْرٍ هُوَ أَبُو بِشْرٍ السُّلَمِيِّ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُوشِكُ أَنْ تَخْرُجَ نَارٌ مِنْ حُبْسِ سَيَلٍ تَسِيرُ سَيْرَ بَطِيئَةِ الْإِبِلِ تَسِيرُ النَّهَارَ وَتُقِيمُ اللَّيْلَ تَغْدُو وَتَرُوحُ يُقَالُ غَدَتْ النَّارُ أَيُّهَا النَّاسُ فَاغْدُوا قَالَتْ النَّارُ أَيُّهَا النَّاسُ فَأَقِيلُوا رَاحَتْ النَّارُ أَيُّهَا النَّاسُ فَرُوحُوا مَنْ أَدْرَكَتْهُ أَكَلَتْهُ","id":"Telah menceritakan kepada kami ['Utsman bin 'Umar] berkata; telah menceritakan kepada kami [Abdul Hamid bin Ja'far] telah menceritakan kepada kami [Muhammad bin 'Ali Abi Ja'far] dari [Rofi' bin Bisr] yaitu Abu Bisr As Sulami dari [Bapaknya] Rasulullah Shallallahu'alaihiwasallam bersabda: \"Dimungkinkan api keluar dari Hubs Sayal, yang akan berjalan sebagaimana lambatnya unta, dia akan berjalan pada siang hari dan beristirahat pada malam hari. Api itu akan keluar pada pagi dan sore hari. Akan ada yang berkata 'Ada api wahai manusia, maka pergilah di pagi hari.' Namun api malahan berkata 'Wahai manusia beristirahat sianglah kalian karena api sedang beristirahat, Wahai manusia, keluarlah, siapa yang dijumpai api itu, maka akan dimakannya.\""},"545":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنِ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُقْبَةُ بْنُ سُوَيْدٍ الْأَنْصَارِيُّ أَنَّهُ سَمِعَ أَبَاهُ وَكَانَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ قَفَلْنَا مَعَ نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ غَزْوَةِ خَيْبَرَ فَلَمَّا بَدَا لَهُ أُحُدٌ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُ أَكْبَرُ جَبَلٌ يُحِبُّنَا وَنُحِبُّهُ","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata; telah mengabarkan kepada kami [Syua'ib] dari [Az Zuhri] berkata; telah mengabarkan kepadaku ['Uqbah bin Suwaid Al Anshori] telah mendengar [Bapaknya] salah satu sahabat Nabi Shallallahu'alaihiwasallam berkata; kami serombongan bersama Nabiyullah Shallallahu'alaihiwasallam dari perang Khaibar. Tatkala kelihatan gunung Uhud, Nabi Shallallahu'alaihiwasallam bersabda: \"Allah Maha Besar, itu adalah gunung yang mencintai kami dan kami mencintainya.\""},"546":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ أَبِي جَعْفَرٍ الْخَطْمِيِّ قَالَ حَدَّثَنَا عُمَارَةُ بْنُ خُزَيْمَةَ وَالْحَارِثُ بْنُ فُضَيْلٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي قُرَادٍقَالَ خَرَجْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَاجًّا فَرَأَيْتُهُ خَرَجَ مِنْ الْخَلَاءِ فَاتَّبَعْتُهُ بِالْإِدَاوَةِ أَوْ الْقَدَحِ فَجَلَسْتُ لَهُ بِالطَّرِيقِ وَكَانَ إِذَا أَتَى حَاجَتَهُ أَبْعَدَ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Abu Ja'far Al Khatmi] berkata; telah menceritakan kepada kami ['Umarah bin Khuzaimah] dan [Al Harits bin Fudlail] dari [Abdurrahman bin Abu Qurad] berkata; saya keluar bersama Nabi Shallallahu'alaihiwasallam dalam rangka berhaji, saya melihat beliau keluar dari kamar kecil, saya mengikuti beliau dengan membawa bejana dari kulit atau tempat air lalu saya duduk di jalan menunggunya, adalah kebiasaan beliau jika menunaikan hajatnya menjauh."},"547":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنِي أَبُو جَعْفَرٍ عُمَيْرُ بْنُ يَزِيدَ قَالَ حَدَّثَنِي الْحَارِثُ بْنُ فُضَيْلٍ وَعُمَارَةُ بْنُ خُزَيْمَةَ بْنِ ثَابِتٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي قُرَادٍقَالَ خَرَجْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَاجًّا قَالَ فَنَزَلَ مَنْزِلًا وَخَرَجَ مِنْ الْخَلَاءِ فَاتَّبَعْتُهُ بِالْإِدَاوَةِ أَوْ الْقَدَحِ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَرَادَ حَاجَةً أَبْعَدَ فَجَلَسْتُ لَهُ بِالطَّرِيقِ حَتَّى انْصَرَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ لَهُ يَا رَسُولَ اللَّهِ الْوَضُوءَ فَأَقْبَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَيَّ فَصَبَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى يَدِهِ فَغَسَلَهَا ثُمَّ أَدْخَلَ يَدَهُ فَكَفَّهَا فَصَبَّ عَلَى يَدِهِ وَاحِدَةً ثُمَّ مَسَحَ عَلَى رَأْسِهِ ثُمَّ قَبَضَ الْمَاءَ قَبْضًا بِيَدِهِ فَضَرَبَ بِهِ عَلَى ظَهْرِ قَدَمِهِ فَمَسَحَ بِيَدِهِ عَلَى قَدَمِهِ ثُمَّ جَاءَ فَصَلَّى لَنَا الظُّهْرَ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Yahya bin Sa'id] berkata; telah menceritakan kepadaku [Abu Ja'far 'Umair bin Yazid] berkata; telah menceritakan kepadaku [Al Harits bin Fudlail] dan ['Umarah bin Khuzaimah bin Tsabit] dari [Abdurrahman bin Abu Qurad] berkata; saya keluar bersama Rasulullah Shallallahu'alaihiwasallam dalam rangka berhaji. (Abdurrahman bin Abu Qurad Rsdliyallahu'anhu) berkata; beliau mampir pada suatu tempat, beliau keluar dari kamar kecil lalu saya mengikuti beliau dengan membawa bejana dari kulit atau tempat air. Kebiasaan Rasulullah Shallallahu'alaihiwasallam jika menunaikan hajatnya beliau menjauh. Saya duduk di jalan menunggu sampai Rasulullah Shallallahu'alaihiwasallam selesai, lalu saya berkata kepada beliau 'Wahai Rasulullah, ini air.' Rasulullah Shallallahu'alaihiwasallam menerimanya, Rasulullah Shallallahu'alaihiwasallam memercikan pada tangan beliau, mencucinya lalu beliau memasukkan tangannya, menahannya dan memercikkan pada tangannya sekali, lalu mengusap kepalanya, lalu mengambil air satu genggam dengan tangannya, lalu menaruh pada punggung kakinya dan mengusapnya dengan tangannya, lalu datang dan shalat zhuhur bersama kami."},"548":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا أَبَانُ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ زَيْدٍ عَنْ أَبِي سَلَّامٍ عَنْ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَخٍ بَخٍ خَمْسٌ مَا أَثْقَلَهُنَّ فِي الْمِيزَانِ لَا إِلَهَ إِلَّا اللَّهُ وَاللَّهُ أَكْبَرُ وَسُبْحَانَ اللَّهِ وَالْحَمْدُ لِلَّهِ وَالْوَلَدُ الصَّالِحُ يُتَوَفَّى فَيَحْتَسِبُهُ وَالِدَاهُ وَقَالَ بَخٍ بَخٍ لِخَمْسٍ مَنْ لَقِيَ اللَّهَ مُسْتَيْقِنًا بِهِنَّ دَخَلَ الْجَنَّةَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ وَبِالْجَنَّةِ وَالنَّارِ وَالْبَعْثِ بَعْدَ الْمَوْتِ وَالْحِسَابِ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Aban] telah menceritakan kepada kami [Yahya bin Abu Katsir] dari [Zaid] dari [Abu Sallam] dari [budak Rasulullah Shallallahu'alaihiwasallam] Rasulullah Shallallahu'alaihiwasallam bersabda: \"Amboi. Amboi. Ada lima hal yang sangat berat dalam timbangan.Yaitu ucapan 'Tidak ada ilah selain Allah', 'Allah Maha Besar', 'Maha Suci Allah', 'Pujian bagi Allah' dan anak shalih yang wafat lalu kedua orang tuanya mengihlaskan dan mengharap-harap pahala dari Allah.\" (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Amboi, amboi, ada lima perkara, barangsiapa yang bertemu Allah dalam keadaan yakin terhadap kelima itu maka dia masuk surga. Beriman kepada Allah, Hari Akhir, Surga, Neraka, Hari Kebangkitan setelah kematian dan Hari Pembalasan\""},"549":{"ar":"حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا لَيْثٌ عَنْ عُقَيْلٍ عَنِ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنْ مُعَاوِيَةَ بْنِ الْحَكَمِ السُّلَمِيِّأَنَّهُ قَالَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرَأَيْتَ أَشْيَاءَ كُنَّا نَفْعَلُهَا فِي الْجَاهِلِيَّةِ كُنَّا نَتَطَيَّرُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَلِكَ شَيْءٌ تَجِدُهُ فِي نَفْسِكَ فَلَا يَصُدَّنَّكَ قَالَ يَا رَسُولَ اللَّهِ كُنَّا نَأْتِي الْكُهَّانَ قَالَ فَلَا تَأْتِ الْكُهَّانَ","id":"Telah menceritakan kepada kami [Hajjaj] telah menceritakan kepada kami [Laits] dari ['Uqail] dari [Ibnu Syihab] dari [Abu Salamah bin Abdurrahman bin 'Auf] dari [Mu'awiyah bin Al Hakam As Sulami] berkata kepada Rasulullah Shallallahu'alaihiwasallam 'Bagaimana menurut anda mengenai kebiasaan yang kami lakukan pada masa Jahiliyyah, kami bertathayur (Berfirasat sial karena melihat hewan sehingga menghalangi pelakunya untuk berbuat)? Rasulullah Shallallahu'alaihiwasallam bersabda: \"Itu hanya sesuatu yang kalian dapatkan pada diri kamu, maka janganlah kau menjadi terhalang karenanya!.\" (Mu'awiyah bin Al Hakam As Sulami Radliyallahu'anhu) berkata; 'Wahai Rasulullah kami suka mendatangi dukun.' Beliau bersabda: \"Jangan kalian mendatangi dukun.\""},"550":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ قَالَدَخَلَ مُعَاوِيَةُ عَلَى خَالِهِ أَبِي هَاشِمِ بْنِ عُتْبَةَ يَعُودُهُ قَالَ فَبَكَى قَالَ فَقَالَ لَهُ مُعَاوِيَةُ مَا يُبْكِيكَ يَا خَالُ أَوَجَعًا يُشْئِزُكَ أَمْ حِرْصًا عَلَى الدُّنْيَا قَالَ فَقَالَ فَكُلًّا لَا وَلَكِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَهِدَ إِلَيْنَا فَقَالَ يَا أَبَا هَاشِمٍ إِنَّهَا عَلَّهَا تُدْرِكُ أَمْوَالًا لَا يُؤْتَاهَا أَقْوَامٌ وَإِنَّمَا يَكْفِيكَ مِنْ جَمْعِ الْمَالِ خَادِمٌ وَمَرْكَبٌ فِي سَبِيلِ اللَّهِ تَبَارَكَ وَتَعَالَى وَإِنِّي أُرَانِي قَدْ جَمَعْتُحَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا سُفْيَانُ عَنِ الْأَعْمَشِ وَمَنْصُورٍ عَنْ أَبِي وَائِلٍ قَالَ دَخَلَ مُعَاوِيَةُ عَلَى أَبِي هَاشِمِ بْنِ عُتْبَةَ وَهُوَ مَرِيضٌ يَبْكِي فَذَكَرَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami [Al 'A'masy] dari [Syaqiq] berkata; Mu'awiyah menemui pamannya [Abu Hasyim bin 'Utbah] dalam rangka menjenguknya, lalu dia menangis. (Syaqiq Radliyallahu'anhu) berkata; Mu'awiyah berkata kepadanya 'Apa yang menyebabkan kamu menangis wahai paman, apakah ada penyakit yang mengganggumu atau karena rasa tamak terhadap dunia? '. lalu dia berkata 'Kedua-duanya tidak, tapi Rasulullah Shallallahu'alaihiwasallam telah berwasiat kepada kami, Beliau bersabda: \"Wahai Abu Hasyim, semoga kamu mendapatkan harta, yang kaum tidak akan memberikannya. cukup bagimu dalam mengumpulkan harta berupa seorang pelayan dan kendaraan di jalan Allah Tabaroka Wa Ta'ala.\" Saya melihat diri saya telah mengumpulkannya. Telah menceritakan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Sufyan] dari [Al 'A'masy] dan [Manshur] dari [Abu Wa'il] berkata; Mu'awiyah menemui [Abu Hasyim bin 'Utbah] karena sakit dan menangis, lalu menyebutkan secara makna."},"551":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا مَعْمَرٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ زَيْدِ بْنِ سَلَّامٍ عَنْ جَدِّهِ قَالَكَتَبَ مُعَاوِيَةُ إِلَى عَبْدِ الرَّحْمَنِ بْنِ شِبْلٍ أَنْ عَلِّمْ النَّاسَ مَا سَمِعْتَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَمَعَهُمْ فَقَالَ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ تَعَلَّمُوا الْقُرْآنَ فَإِذَا عَلِمْتُمُوهُ فَلَا تَغْلُوا فِيهِ وَلَا تَجْفُوا عَنْهُ وَلَا تَأْكُلُوا بِهِ وَلَا تَسْتَكْثِرُوا بِهِ","id":"Telah menceritakan kepada kami [Abdurrazzaq] berkata; telah mengabarkan kepada kami [Ma'mar] dari [Yahya bin Abu Katsir] dari [Zaid bin Sallam] dari [kakeknya] berkata; Mu'awiyah menulis kepada [Abdurrahman bin Syibl]: 'Ajarkanlah kepada orang-orang apa yang telah kau dengar dari Rasulullah Shallallahu'alaihiwasallam', lalu dia mengumpulkan mereka dan berkata; saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Pelajarilah Al quran, jika kalian telah mengetahuinya, janganlah berlebihan terhadapnya, jangan berpaling daripadanya dan jangan kalian jadikan untuk mencari makan dan jangan kau jadikan media memperkaya diri\""},"552":{"ar":"ثُمَّ قَالَ إِنَّ التُّجَّارَ هُمْ الْفُجَّارُ قَالُوا يَا رَسُولَ اللَّهِ أَلَيْسَ قَدْ أَحَلَّ اللَّهُ الْبَيْعَ وَحَرَّمَ الرِّبَا قَالَ بَلَى وَلَكِنَّهُمْ يَحْلِفُونَ وَيَأْثَمُونَ","id":"Masih melalui jalur periwayatan yang sama seperti hadits sebelumnya dari [Abdurrahman bin Syibil]; Kemudian (Rasulullah Shallallahu'alaihiwasallam) bersabda: \" Para pedagang itu orang-orang yang berbuat dosa.\" Mereka berkata; Wahai Rasulullah, bukankah Allah telah menghalalkan jual beli dan mengharamkan riba? Beliau bersabda: \"Ya, tapi mereka mempunyai kebiasaan bersumpah dan berbuat dosa.\""},"553":{"ar":"ثُمَّ قَالَ إِنَّ الْفُسَّاقَ هُمْ أَهْلُ النَّارِ قَالُوا يَا رَسُولَ اللَّهِ وَمَنْ الْفُسَّاقُ قَالَ النِّسَاءُ قَالُوا يَا رَسُولَ اللَّهِ أَلَسْنَ أُمَّهَاتِنَا وَبَنَاتِنَا وَأَخَوَاتِنَا قَالَ بَلَى وَلَكِنَّهُنَّ إِذَا أُعْطِينَ لَمْ يَشْكُرْنَ وَإِذَا ابْتُلِينَ لَمْ يَصْبِرْنَ","id":"Masih melalui jalur periwayatan yang sama seperti hadits sebelumnya dari [Abdurrahman bin Syibil]; Kemudian bersabda: \" Orang fasiq itu para penghuni neraka.\" Mereka bertanya, Wahai Rosulullah, siapakah orang yang fasiq itu? Beliau bersabda: \"Para wanita\" mereka bertanya, Wahai Rasulullah, bukankah mereka itu adalah ibu-ibu kita, saudara-saudara perempuan kita, dan istri-istri kita? (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Ya, sebab mereka jika diberi tidak bersyukur (berterima kasih) dan jika diuji tidak bersabar.\""},"554":{"ar":"ثُمَّ قَالَ يُسَلِّمُ الرَّاكِبُ عَلَى الرَّاجِلِ وَالرَّاجِلُ عَلَى الْجَالِسِ وَالْأَقَلُّ عَلَى الْأَكْثَرِ فَمَنْ أَجَابَ السَّلَامَ كَانَ لَهُ وَمَنْ لَمْ يُجِبْ فَلَا شَيْءَ لَهُ","id":"Masih melalui jalur periwayatan yang sama seperti hadits sebelumnya dari [Abdurrahman bin Syibil]; Kemudian bersabda: \"Orang yang berkendaraan mengucapkan salam kepada yang berjalan, dan orang yang berjalan kepada orang yang duduk, orang yang sedikit kepada orang yang lebih banyak. Barangsiapa yang menjawab salam maka dia mendapatkan (pahala) dan yang tidak menjawabnya maka dia tidak mendapatkan apa-apa.\""},"555":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ حَدَّثَنَا عَبْدُ الْحَمِيدِ وَمُحَمَّدُ بْنُ بَكْرٍ قَالَ أَخْبَرَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ حَدَّثَنِي أَبِي عَنْ تَمِيمِ بْنِ مَحْمُودٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ شِبْلٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ ثَلَاثٍ عَنْ نَقْرَةِ الْغُرَابِ وَعَنْ افْتِرَاشِ السَّبُعِ وَأَنْ يُوَطِّنَ الرَّجُلُ الْمُقَامَ قَالَ عُثْمَانُ فِي الْمَسْجِدِ كَمَا يُوَطِّنُ الْبَعِيرُ","id":"Telah menceritakan kepada kami ['Utsman bin 'Umar] telah menceritakan kepada kami [Abdul Hamid] dan [Muhammad bin Bakr] berkata; telah mengabarkan kepada kami [Abdul Hamid bin Ja'far] telah menceritakan kepadaku [bapakku] dari [Tamim bin Mahmud] dari [Abdurrahman bin Syibl] Rasulullah Shallallahu'alaihiwasallam melarang tiga hal: mematuk (ketika bersujud) seperti burung gagak, membentangkan tangan seperti binatang buas (dalam bersujud) dan mengambil tempat duduk. Utsman berkata; maksudnya dalam masjidnya seperti unta yang mengambil tempat duduknya. "},"556":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا يَحْيَى عَنْ زَيْدِ بْنِ سَلَّامٍ عَنْ جَدِّهِ عَنْ أَبِي رَاشِدٍ الْحُبْرَانِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ شِبْلٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اقْرَءُوا الْقُرْآنَ وَلَا تَغْلُوا فِيهِ وَلَا تَجْفُوا عَنْهُ وَلَا تَأْكُلُوا بِهِ وَلَا تَسْتَكْثِرُوا بِهِ","id":"Telah menceritakan kepada kami [Abdushshamad] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Yahya] dari [Zaid bin Sallam] dari [kakeknya] dari [Abu Rasyid Al Hubrani] dari [Abdurrahman bin Syibl] Nabi Shallallahu'alaihiwasallam bersabda: \"Bacalah Al quran, janganlah berlebihan di dalamnya, jangan berpaling daripadanya dan jangan kalian jadikan untuk mencari makan dan jangan kalian jadikan untuk memperkaya diri\""},"557":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا أَبَانُ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ زَيْدٍ عَنْ أَبِي سَلَّامٍ عَنْ أَبِي رَاشِدٍ الْحُبْرَانِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ شِبْلٍ الْأَنْصَارِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ التُّجَّارَ هُمْ الْفُجَّارُ قَالَ رَجُلٌ يَا نَبِيَّ اللَّهِ أَلَمْ يُحِلَّ اللَّهُ الْبَيْعَ قَالَ إِنَّهُمْ يَقُولُونَ فَيَكْذِبُونَ وَيَحْلِفُونَ وَيَأْثَمُونَ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Aban] telah menceritakan kepada kami [Yahya bin Abu Katsir] dari [Zaid] dari [Abu Sallam] dari [Abu Rosiyd Al Hubrani] dari [Abdurrahman bin Syibl Al Anshari] Rasulullah Shallallahu'alaihiwasallam bersabda: \" Para pedagang itu orang-orang yang berbuat dosa.\" Ada seorang bertanya, Wahai Nabiyullah, bukankah Allah telah menghalalkan juAl beli?. Beliau bersabda: \" Mereka suka berkata dusta, bersumpah dan berbuat dosa.\""},"558":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا أَبَانُ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ زَيْدٍ عَنْ أَبِي سَلَّامٍ عَنْ أَبِي رَاشِدٍ الْحُبْرَانِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ شِبْلٍ الْأَنْصَارِيِّأَنَّ مُعَاوِيَةَ قَالَ لَهُ إِذَا أَتَيْتَ فُسْطَاطِي فَقُمْ فَأَخْبِرْ مَا سَمِعْتَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اقْرَءُوا الْقُرْآنَ وَلَا تَغْلُوا فِيهِ وَلَا تَجْفُوا عَنْهُ وَلَا تَأْكُلُوا بِهِ وَلَا تَسْتَكْثِرُوا بِهِحَدَّثَنَا عَفَّانُ حَدَّثَنَا مُوسَى بْنُ خَلَفٍ أَبُو خَلَفٍ وَكَانَ يُعَدُّ مِنْ الْبُدَلَاءِ وَذَكَرَ حَدِيثًا آخَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Aban] telah menceritakan kepada kami [Yahya bin Abu Katsir] dari [Zaid] dari [Abu Sallam] dari [Abu Rasyid Al Hubrani] dari [Abdurrahman bin Syibl Al Anshari] Mu'awiyah berkata kepadanya, jika kamu mendatangi tendaku maka kabarkanlah apa yang kau dengar dari Rasulullah Shallallahu'alaihiwasallam?. Dia berkata; saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Bacalah Al quran, janganlah berlebihan, jangan berpaling, jangan kalian jadikan untuk mencari makan dan jangan kalian jadikan alat untuk memperkaya diri\" Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Musa bin Khalaf], Abu Khalaf, dia dianggap dari Al Budala' lalu dia menyebutkan hadis yang lainnya yang semisalnya."},"559":{"ar":"حَدَّثَنَا سَكَنُ بْنُ نَافِعٍ حَدَّثَنَا صَالِحُ بْنُ أَبِي الْأَخْضَرِ عَنِ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ عَامِرِ بْنِ رَبِيعَةَ أَنَّ أَبَاهُأَخْبَرَهُ أَنَّهُ رَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّ فِي السُّبْحَةِ بِاللَّيْلِ فِي السَّفَرِ عَلَى ظَهْرِ رَاحِلَتِهِ حَيْثُ تَوَجَّهَتْ بِهِ","id":"Telah menceritakan kepada kami [Sakan bin Nafi'] telah menceritakan kepada kami [Shalih bin Abu Al Ahdlor] dari [Az Zuhri] berkata; telah mengabarkan kepadaku [Abdullah bin 'Amir bin Rabi'ah] [Bapaknya] mengabarinya dia telah melihat Rasulullah Shallallahu'alaihiwasallam shalat sunah pada suatu malam dalam perjalanan di atas kendaraannya kearah manasaja kendaraan itu menghadap."},"560":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا ابْنُ عَوْنٍ عَنْ نَافِعٍ عَنِ ابْنِ عُمَرَ عَنْ عَامِرِ بْنِ رَبِيعَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا رَأَيْتَ جَنَازَةً فَقُمْ حَتَّى تُجَاوِزَكَ أَوْ قَالَ قِفْ حَتَّى تُجَاوِزَكَقَالَ وَكَانَ ابْنُ عُمَرَ إِذَا رَأَى جَنَازَةً قَامَ حَتَّى تُجَاوِزَهُ وَكَانَ إِذَا خَرَجَ مَعَ جَنَازَةٍ وَلَّى ظَهْرَهُ الْمَقَابِرَ","id":"Telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Ibnu 'Aun] dari [Nafi'] dari [Ibnu 'Umar] dari ['Amir bin Rabi'ah] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Jika kalian melihat jenazah maka berdirilah sehingga jenazah itu melewatimu.\" Atau bersabda: \"Berhentilah sampai jenazah tersebut lewat.\" (Nafi' Radliyallahu'anhu) berkata; Ibnu 'Umar jika melihat jenazah, dia berdiri sampai melewatinya, dan jika selesai menyertai jenazah, dia memalingkan punggungnya dari kuburan."},"561":{"ar":"حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ أَخْبَرَنِي نَافِعٌ عَنِ ابْنِ عُمَرَ عَنْ عَامِرِ بْنِ رَبِيعَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا رَأَى أَحَدُكُمْ الْجَنَازَةَ وَلَمْ يَكُنْ مَاشِيًا مَعَهَا فَلْيَقُمْ حَتَّى تُجَاوِزَهُ أَوْ تُوضَعَ","id":"Telah menceritakan kepada kami [Yahya] dari ['Ubaidullah] berkata; telah mengabarkan kepadaku [Nafi'] dari [Ibnu 'Umar] dari ['Amir bin Rabi'ah] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Jika salah seorang dari kalian melihat jenazah, dan tidak berjalan bersamanya, maka berdirilah sampai jenazah itu melewatinya atau sampai diletakkan.\""},"562":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ وَابْنُ بَكْرٍ قَالَا حَدَّثَنَا ابْنُ جُرَيْجٍ قَالَ سَمِعْتُ نَافِعًا يَقُولُ كَانَ عَبْدُ اللَّهِ بْنُ عُمَرَ يَأْثُرُ عَنْ عَامِرِ بْنِ رَبِيعَةَ أَنَّهُكَانَ يَقُولُ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَأَى أَحَدُكُمْ الْجِنَازَةَ فَلْيَقُمْ حِينَ يَرَاهَا حَتَّى تُخَلِّفَهُ إِذَا كَانَ غَيْرَ مُتَّبِعِهَا","id":"Telah menceritakan kepada kami [Abdurrazzaq] dan [Ibnu Bakr] berkata; telah menceritakan kepada kami [Ibnu Juraij] berkata; saya telah mendengar [Nafi'] berkata; [Abdullah bin 'Umar] mendapatkan kabar dari ['Amir bin Rabi'ah] dia berkata; Nabi Shallallahu'alaihiwasallam bersabda: \"Jika salah seorang dari kalian melihat jenazah, berdirilah ketika melihatnya sampai jenazah itu meninggalkannya, jika ia tidak ikut mengiringinya.\""},"563":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ وَعَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ عَاصِمِ بْنِ عُبَيْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عَامِرِ بْنِ رَبِيعَةَ عَنْ أَبِيهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا لَا أَعُدُّ وَمَا لَا أُحْصِي يَسْتَاكُ وَهُوَ صَائِمٌ وَقَالَ عَبْدُ الرَّحْمَنِ مَا لَا أُحْصِي يَتَسَوَّكُ وَهُوَ صَائِمٌ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sufyan] dan [Abdurrahman] dari [Sufyan] dari ['Ashim bin 'Ubaidullah] dari [Abdullah bin 'Amir bin Rabi'ah] dari [Bapaknya] berkata; saya melihat Rasulullah Shallallahu'alaihiwasallam hingga jumlah yang saya tidak bisa menghitungnya, yaitu beliau bersiwak sedang beliau dalam keadaan puasa. Sedang 'Abdurrahman berkata dengan redaksi 'Saya tidak bisa menghitungya, yaitu beliau selalu menjaga bersiwak dalam keadaan berpuasa."},"564":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ وَحَجَّاجٌ قَالَ سَمِعْتُ شُعْبَةَ عَنْ عَاصِمِ بْنِ عُبَيْدِ اللَّهِ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عَامِرٍ يُحَدِّثُ عَنْ أَبِيهِأَنَّ رَجُلًا تَزَوَّجَ امْرَأَةً عَلَى نَعْلَيْنِ قَالَ فَأَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ ذَاكَ لَهُ فَقَالَ أَرَضِيتِ مِنْ نَفْسِكِ وَمَالِكِ بِنَعْلَيْنِ قَالَتْ نَعَمْ قَالَ شُعْبَةُ فَقُلْتُ لَهُ كَأَنَّهُ أَجَازَ ذَلِكَ قَالَ كَأَنَّهُ أَجَازَهُ قَالَ شُعْبَةُ ثُمَّ لَقِيتُهُ فَقَالَ أَرَضِيتِ مِنْ نَفْسِكِ وَمَالِكِ بِنَعْلَيْنِ فَقَالَتْ رَأَيْتُ ذَاكَ فَقَالَ وَأَنَا أَرَى ذَاكَ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dan [Hajjaj] berkata; saya telah mendengar [Syu'bah] dari ['Ashim bin 'Ubaidullah] berkata; saya mendengar [Abdullah bin 'Amir] menceritakan dari [Bapaknya] ada seorang laki-laki menikahi seorang wanita dengan (maskawin) dua sandal, maka wanita itu berkata; 'Ya.' Syu'bah berkata; saya berkata kepada ('Ashim bin 'Ubaidullah Radliyallahu'anhu) sepertinya (Rasulullah Shallallahu'alaihiwasallam) membolehkannya. ('Ashim bin 'Ubaidullah Radliyallahu'anhu) berkata; sepertinya (Rasulullah Shallallahu'alaihiwasallam) membolehkannya. Syu'bah berkata; kemudian saya menemuinya. ('Amir Radliyallahu'anhu) berkata; apakah kamu rela dengan dirimu dan hartamu dengan maskawin dua sandal?, wanita itu menjawab. 'Saya pikir nggak masalah.' Maka ('Amir radliallahu 'anhu) berkata; 'Saya pikir juga nggak masalah.'"},"565":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي عَاصِمُ بْنُ عُبَيْدِ اللَّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّهَا سَتَكُونُ مِنْ بَعْدِي أُمَرَاءُ يُصَلُّونَ الصَّلَاةَ لِوَقْتِهَا وَيُؤَخِّرُونَهَا عَنْ وَقْتِهَا فَصَلُّوهَا مَعَهُمْ فَإِنْ صَلَّوْهَا لِوَقْتِهَا وَصَلَّيْتُمُوهَا مَعَهُمْ فَلَكُمْ وَلَهُمْ وَإِنْ أَخَّرُوهَا عَنْ وَقْتِهَا فَصَلَّيْتُمُوهَا مَعَهُمْ فَلَكُمْ وَعَلَيْهِمْ مَنْ فَارَقَ الْجَمَاعَةَ مَاتَ مِيتَةً جَاهِلِيَّةً وَمَنْ نَكَثَ الْعَهْدَ وَمَاتَ نَاكِثًا لِلْعَهْدِ جَاءَ يَوْمَ الْقِيَامَةِ لَا حُجَّةَ لَهُقُلْتُ لَهُ مَنْ أَخْبَرَكَ هَذَا الْخَبَرَ قَالَ أَخْبَرَنِيهِ عَبْدُ اللَّهِ بْنُ عَامِرِ بْنِ رَبِيعَةَ عَنْ أَبِيهِ عَامِرِ بْنِ رَبِيعَةَ يُخْبِرُ عَامِرُ بْنُ رَبِيعَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abdurrazzaq] berkata; telah mengabarkan kepada kami [Ibnu Juraij] berkata; telah mengabarkan kepadaku ['Ashim bin 'Ubaidullah] Nabi Shallallahu'alaihiwasallam bersabda: \"Akan datang setelahku para pemimpin, mereka melaksanakan shalat pada waktunya dan mengakhirkan dari waktunya. Shalatlah bersama mereka, jika mereka shalat pada waktunya. Kamu akan beruntung, dan mereka juga beruntung. Jika mereka mengakhirkan dari waktunya lantas kalian sholat bersama mereka, kamu memperoleh pahala dan mereka berdosa. Barangsiapa yang memisahkan diri dari jamaah, maka mati seperti matinya Jahiliyyah. Siapa yang merusak perjanjian dan dalam keadaan tersebut, datang pada Hari Kiamat, tidak ada alasan baginya.\" Saya (Abdurrazzaq RH) bertanya kepada (Ibnu Juraij RH), siapa yang menghabarimu? Dia menjawab, yang menghabariku adalah [Abdullah bin 'Amir bin Rabi'ah] dari Bapaknya, ['Amir bin Rabi'ah]. 'Amir bin Rabi'ah menghabarinya dari Nabi Shallallahu'alaihiwasallam."},"566":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ عَنْ عَامِرِ بْنِ رَبِيعَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَأَى أَحَدُكُمْ الْجِنَازَةَ فَلْيَقُمْ حَتَّى تُخَلِّفَهُ أَوْ تُوضَعَحَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنِ ابْنِ عُمَرَ عَنْ عَامِرِ بْنِ رَبِيعَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Abdurrazzaq] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salim] dari [Ibnu 'Umar] dari ['Amir bin Rabi'ah] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jika salah seorang dari kalian melihat jenazah, maka berdirilah sampai kamu telah berada di belakang jenazah itu atau sampai jenazah itu diletakkan.\" Telah menceritakan kepada kami [Abdurrazzaq] telah menceritakan kepada kami [Ma'mar] dari [Ayyub] dari [Nafi'] dari [Ibnu 'Umar] dari ['Amir bin Rabi'ah] dari Nabi Shallallahu'alaihiwasallam sama dengan hadis di atas."},"567":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ أَخْبَرَنَا أَيُّوبُ عَنْ نَافِعٍ عَنِ ابْنِ عُمَرَ عَنْ عَامِرِ بْنِ رَبِيعَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَأَيْتَ جَنَازَةً فَإِنْ لَمْ تَكُ مَاشِيًا مَعَهَا فَقُمْ لَهَا حَتَّى تُخَلِّفَكَ أَوْ تُوضَعَقَالَ فَكَانَ ابْنُ عُمَرَ رُبَّمَا تَقَدَّمَ الْجِنَازَةَ فَقَعَدَ حَتَّى إِذَا رَآهَا قَدْ أَشْرَفَتْ قَامَ حَتَّى تُوضَعَ وَرُبَّمَا سَتَرَتْهُ","id":"Telah menceritakan kepada kami [Isma'il] telah mengabarkan kepada kami [Ayyub] dari [Nafi'] dari [Ibnu 'Umar] dari ['Amir bin Rabi'ah] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jika kamu melihat jenazah, sedang kamu tidak mengiringi jenazah tersebut, maka berdirilah karenanya sampai jenazah tersebut menjauh atau diletakkan.\" (Nafi' Radliyallahu'anhu) berkata; Kebiasaan Ibnu 'Umar jika ada jenazah yang dibawa, dia duduk. Namun begitu dia melihatnya dan jenazah telah dekat, maka dia berdiri sampai jenazah itu diletakkan atau tidak kelihatan lagi."},"568":{"ar":"حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَامِرِ بْنِ رَبِيعَةَ عَنْ أَبِيهِأَنَّهُ رَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي عَلَى رَاحِلَتِهِ حَيْثُ تَوَجَّهَتْ بِهِ","id":"Telah menceritakan kepada kami [Abdul Al A'la] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abdullah 'Amir bin Rabi'ah] dari [Bapaknya] dia melihat Rasulullah Shallallahu'alaihiwasallam shalat di atas kendaraanya kearah manasaja kendaraan itu menghadap."},"569":{"ar":"حَدَّثَنَا هَاشِمٌ حَدَّثَنَا اللَّيْثُ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ عَنْ مَوْلًى لِعَبْدِ اللَّهِ بْنِ عَامِرِ بْنِ رَبِيعَةَ الْعَدَوِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَامِرٍ أَنَّهُ قَالَأَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْتِنَا وَأَنَا صَبِيٌّ قَالَ فَذَهَبْتُ أَخْرُجُ لِأَلْعَبَ فَقَالَتْ أُمِّي يَا عَبْدَ اللَّهِ تَعَالَ أُعْطِكَ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَا أَرَدْتِ أَنْ تُعْطِيَهُ قَالَتْ أُعْطِيهِ تَمْرًا قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا إِنَّكِ لَوْ لَمْ تَفْعَلِي كُتِبَتْ عَلَيْكِ كَذْبَةٌ","id":"Telah menceritakan kepada kami [Hasyim] telah menceritakan kepada kami [Laits] dari [Muhammad bin 'Ajlan] dari [budak Abdullah bin 'Amir bin Rabi'ah Al 'Adawi] dari [Abdullah bin 'Amir] dia berkata; Rasulullah Shallallahu'alaihiwasallam mendatangi kami di rumah kami, waktu itu saya masih kecil. (Abdullah bin 'Amir RA) berkata; saya berangkat dan pergi untuk bermain. Lalu ibuku berkata; Wahai Abdullah, kesinilah saya akan memberikan sesuatu. Lalu Rasulullah Shallallahu'alaihiwasallam bersabda kepadanya, apakah yang hendak kau berikan kepadanya? Dia menjawab, saya akan memberikan kurma. (Abdullah bin 'Amir RA) berkata; lalu Rasulullah Shallallahu'alaihiwasallam bersabda kepadanya, jika kau tidak melakukannya maka itu akan dicatat sebagai kedustaan."},"570":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ قَالَ سَمِعْتُ أَبَا شُعْبَةَ يُحَدِّثُ عَنْ سُوَيْدِ بْنِ مُقَرِّنٍأَنَّ رَجُلًا لَطَمَ جَارِيَةً لِآلِ سُوَيْدِ بْنِ مُقَرِّنٍ فَقَالَ لَهُ سُوَيْدٌ أَمَا عَلِمْتَ أَنَّ الصُّورَةَ مُحَرَّمَةٌ لَقَدْ رَأَيْتُنِي سَابِعَ سَبْعَةٍ مَعَ إِخْوَتِي وَمَا لَنَا إِلَّا خَادِمٌ وَاحِدٌ فَلَطَمَهُ أَحَدُنَا فَأَمَرَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نُعْتِقَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Muhammad bin Al Munkadir] berkata; saya telah mendengar [Abu Syu'bah] menceritakan dari [Suwaid bin Muqarrin] ada seseorang yang menampar seorang wanita keluarga Suwaid bin Muqarrin, lalu Suwaid berkata kepadanya, tidakkah kau mengetahui gambar itu adalah diharamkan? Saya pernah menjadi orang yang ketujuh bersama dengan saudara-saudaraku, dan kami hanya memiliki satu pelayan. Salah seorang dari kami menamparnya lalu Nabi Shallallahu'alaihiwasallam menyuruh kami agar memerdekakannya."},"571":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي حَمْزَةَ قَالَ سَمِعْتُ رَجُلًا مِنْ بَنِي مَازِنٍ يُحَدِّثُ عَنْ سُوَيْدِ بْنِ مُقَرِّنٍ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَبِيذٍ فِي جَرٍّ فَسَأَلْتُهُ عَنْهُ فَنَهَانِي عَنْهُ فَأَخَذْتُ الْجَرَّةَ فَكَسَرْتُهَا","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Abu Hamzah] berkata; saya telah mendengar [seorang laki-laki] dari Bani Mazin menceritakan dari [Suwaid bin Muqarrin] berkata; saya memberi Rasulullah Shallallahu'alaihiwasallam minuman anggur yang berada pada teko dari tanah, lalu saya bertanya tentangnya dan beliau melarangnya. Maka saya ambil teko tersebut dan saya pecahkan."},"572":{"ar":"حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا سُفْيَانُ عَنْ سَلَمَةَ عَنْ مُعَاوِيَةَ بْنِ سُوَيْدٍقَالَ لَطَمْتُ مَوْلًى لَنَا ثُمَّ جِئْتُ وَأَبِي فِي الظُّهْرِ فَصَلَّيْتُ مَعَهُ فَلَمَّا سَلَّمَ أَخَذَ بِيَدِي فَقَالَ اتَّئِدْ مِنْهُ فَعَفَا ثُمَّ أَنْشَأَ يُحَدِّثُ قَالَ كُنَّا وَلَدَ مُقَرِّنٍ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَبْعَةً لَيْسَ لَنَا إِلَّا خَادِمٌ وَاحِدَةٌ فَلَطَمَهَا أَحَدُنَا فَبَلَغَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَعْتِقُوهَا فَقَالُوا لَيْسَ لَنَا خَادِمٌ غَيْرُهَا قَالَ فَلْيَسْتَخْدِمُوهَا فَإِذَا اسْتَغْنَوْا فَلْيُخَلُّوا سَبِيلَهَا","id":"Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [Sufyan] dari [Salamah] dari [Mu'awiyah bin Suwaid] berkata; saya menampar budak milik kami, lalu saya dan [bapakku] datang waktu zhuhur, lalu saya shalat bersama (bapakku). Tatkala selesai salam (bapakku) menggandeng tanganku lalu berkata; \"Tinggalkanlah dia\" lalu dia memaafkan kemudian menceritakan, kami adalah anak Muqarrin pada masa Rasulullah Shallallahu'alaihiwasallam, kami bertujuh, kami hanya memiliki satu pelayan. Lalu salah seorang dari kami menamparnya. Berita ini sampai kepada Nabi Shallallahu'alaihiwasallam. Beliau memberi saran, \"Merdekakan.\" Mereka menjawab 'Kami tidak mempunyai lagi kecuali hanya itu.' Beliau bersabda: \"Ya, tidak masalah.' Tapi jika sudah tidak dibutuhkan, biarkanlah dia.\""},"573":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ ابْنِ أَبِي حَدْرَدٍ الْأَسْلَمِيِّأَنَّهُ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتَفْتِيهِ فِي مَهْرِ امْرَأَةٍ فَقَالَ كَمْ أَمْهَرْتَهَا قَالَ مِائَتَيْ دِرْهَمٍ فَقَالَ لَوْ كُنْتُمْ تَغْرِفُونَ مِنْ بَطَحَانَ مَا زِدْتُمْحَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا سُفْيَانُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ التَّيْمِيِّ قَالَ حَدَّثَنَا أَبُو حَدْرَدٍ الْأَسْلَمِيُّ أَنَّ رَجُلًا جَاءَ فَذَكَرَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Yahya bin Sa'id] dari [Muhammad bin Ibrahim At-Taimi] dari [Ibnu Abu Hadrah Al Aslami] dia mendatangi Nabi Shallallahu'alaihiwasallam untuk meminta fatwa tentang mahar wanita. Lalu beliau bersabda: \"Berapa kamu memberinya mahar?\" dia menjawab, dua ratus dirham. Maka (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Seandainya kalian mengambilnya dari Bathhan maka kalian tidak akan menambahinya\" Telah menceritakan kepada kami [Abdurrazzaq] telah menceritakan kepada kami [Sufyan] dari [Yahya bin Sa'id] dari [Muhammad bin Ibrahim At-Taimi] berkata; telah menceritakan kepada kami [Abu Hadrah Al Aslami] ada seorang laki-laki datang, lalu menyebut sama dengan di atas."},"574":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ عَطَاءِ بْنِ السَّائِبِ قَالَأَتَيْتُ أُمَّ كُلْثُومٍ ابْنَةَ عَلِيٍّ بِشَيْءٍ مِنْ الصَّدَقَةِ فَرَدَّتْهَا وَقَالَتْ حَدَّثَنِي مَوْلًى لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقَالُ لَهُ مِهْرَانُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّا آلُ مُحَمَّدٍ لَا تَحِلُّ لَنَا الصَّدَقَةُ وَمَوْلَى الْقَوْمِ مِنْهُمْ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sufyan] dari ['Atha' bin As Sa'ib] berkata; saya menemui [Ummu Kultsum] salah seorang anak 'Ali dengan membawa barang hasil sedekah, lalu dia menolaknya dan berkata; salah seorang budak Nabi Shallallahu'alaihiwasallam menceritakan kepadaku yang bernama [Mihran], Rasulullah Shallallahu'alaihiwasallam bersabda: \" Keluarga Muhammad tidak halal sedekah bagi mereka, dan budak suatu kaum adalah bagian dari mereka.\""},"575":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ رَجُلٍ مِنْ أَسْلَمَأَنَّهُ لُدِغَ فَذَكَرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ أَنَّكَ قُلْتَ حِينَ أَمْسَيْتَ أَعُوذُ بِكَلِمَاتِ اللَّهِ التَّامَّاتِ مِنْ شَرِّ مَا خَلَقَ لَمْ يَضُرَّكَقَالَ سُهَيْلٌ فَكَانَ أَبِي إِذَا لُدِغَ أَحَدٌ مِنَّا يَقُولُ قَالَهَا فَإِنْ قَالُوا نَعَمْ قَالَ كَأَنَّهُ يَرَى أَنَّهَا لَا تَضُرُّهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] berkata; telah menceritakan kepada kami [Syu'bah] dari [Suhail bin Abu Shalih] dari [Bapaknya] dari [salah seorang dari Aslam] dia tersengat, hal itu disampaikan kepada Nabi Shallallahu'alaihiwasallam. Nabi Shallallahu'alaihiwasallam bersabda: \"Jika kamu pada sore harinya membaca, 'Saya berlindung dengan kalimat-kalimat Allah yang sempurna dari kejahatan apa yang telah Dia ciptakan' maka hal itu tidak akan membahayakanmu.\" Suhail berkata; \"Bapakku, jika melihat salah seorang tersengat, maka bertanya, apakah dia telah membacanya?, jika mereka berkata; 'ya' maka dia berpandangan seolah-olah tidak akan membahayakannya.'"},"576":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ يَحْيَى بْنِ سَعِيدٍ وَعَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ بْنِ مُحَمَّدِ بْنِ أَبِي بَكْرٍ الصِّدِّيقِ عَنِ الْقَاسِمِ عَنْ صَالِحِ بْنِ خَوَّاتٍ عَنْ سَهْلِ بْنِ أَبِي حَثْمَةَ أَمَّا عَبْدُ الرَّحْمَنِ فَرَفَعَهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَمَّا يَحْيَى فَذَكَرَ عَنْ سَهْلٍقَالَ يَقُومُ الْإِمَامُ وَصَفٌّ خَلْفَهُ وَصَفٌّ بَيْنَ يَدَيْهِ فَيُصَلِّي بِالَّذِي خَلْفَهُ رَكْعَةً وَسَجْدَتَيْنِ ثُمَّ يَقُومُ قَائِمًا حَتَّى يُصَلُّوا رَكْعَةً أُخْرَى ثُمَّ يَتَقَدَّمُونَ إِلَى مَكَانِ أَصْحَابِهِمْ ثُمَّ يَجِيءُ أُولَئِكَ فَيَقُومُونَ مَقَامَ هَؤُلَاءِ فَيُصَلِّي بِهِمْ رَكْعَةً وَسَجْدَتَيْنِ ثُمَّ يَقْعُدُ حَتَّى يَقْضُوا رَكْعَةً أُخْرَى ثُمَّ يُسَلِّمُ عَلَيْهِمْحَدَّثَنَا رَوْحٌ حَدَّثَنَا شُعْبَةُ وَمَالِكُ بْنُ أَنَسٍ عَنْ يَحْيَى بْنِ سَعِيدٍ الْأَنْصَارِيِّ عَنِ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ صَالِحِ بْنِ خَوَّاتٍ عَنْ سَهْلِ بْنِ أَبِي حَثْمَةَ فَذَكَرَ مَعْنَاهُ إِلَّا أَنَّهُ قَالَ يُصَلِّي بِالَّذِينَ خَلْفَهُ رَكْعَةً وَسَجْدَتَيْنِ ثُمَّ يَقْعُدُ مَكَانَهُ حَتَّى يَقْضُوا رَكْعَةً وَسَجْدَتَيْنِ ثُمَّ يَتَحَوَّلُوا إِلَى مَقَامِ أَصْحَابِهِمْ ثُمَّ يَتَحَوَّلَ أَصْحَابُهُمْ إِلَى مَكَانِ هَؤُلَاءِ فَذَكَرَ مَعْنَاهُ حَدَّثَنَا رَوْحٌ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ صَالِحِ بْنِ خَوَّاتٍ عَنْ سَهْلِ بْنِ أَبِي حَثْمَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَ هَذَا","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] berkata; telah menceritakan kepada kami [Syu'bah] dari [Yahya bin Sa'id] dan [Abdurrahman bin Al Qasim bin Muhammad bin Abu Bakr Ash-Shidiq] dari [Al Qasim] dari [Shalih bin Khawwat] dari [Sahl bin Abu Hatsmah]. [Abdurrahman] memarfukkannya kepada Nabi Shallallahu'alaihiwasallam. [Yahya], menyebutkan dari [Sahl], berkata; imam berdiri dan barisan berada di belakangnya, dan satu barisan di depannya, lalu shalat dengan barisan belakangnya satu rakaat dan dua sujud. Kemudian berdiri, sehingga mereka shalat pada rakaat yang lain. Lalu mereka maju ke tempat para sahabat mereka, lalu mereka datang dan menempati tempat barisan yang tadi, lalu beliau shalat bersama mereka dengan satu rukuk dan dua kali sujud, lalu beliau duduk sampai (para sahabat) menyelesaikan rakaat yang lain, lalu beliau mengucapkan salam kepada mereka. Telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami [Syu'bah] dan [Malik bin Anas] dari [Yahya bin Sa'id Al Anshari] dari [Al Qasim bin Muhammad] dari [Shalih bin Khawwat] dari [Sahl bin Abu Hatsmah], lalu menyebutkan secara makna kecuali ada perkataan, shalat bersama yang di belakangnya satu kali rukuk dan dua kali sujud lalu beliau duduk pada tempatnya sehingga mereka menyelesaikan satu kali rukuk dan dua sujudnya lalu mereka berpindah ke tempat para sahabatnya, lalu para sahabatnya berpindah ke tempat mereka, lalu menyebutkan secara makna. Telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami [Syu'bah] dari [Abdurrahman bin Al Qasim] dari [Bapaknya] dari [Shalih bin Khawwat] dari [Sahl bin Abu Hatsmah] dari Nabi Shallallahu'alaihiwasallam seperti di atas."},"577":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي خُبَيْبُ بْنُ عَبْدِ الرَّحْمَنِ الْأَنْصَارِيُّ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ مَسْعُودِ بْنِ نِيَارٍ قَالَجَاءَ سَهْلُ بْنُ أَبِي حَثْمَةَ إِلَى مَجْلِسِنَا فَحَدَّثَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا خَرَصْتُمْ فَجُدُّوا وَدَعُوا دَعُوا الثُّلُثَ فَإِنْ لَمْ تَجُدُّوا وَتَدَعُوا فَدَعُوا الرُّبُعَ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Syu'bah] berkata; telah mengabarkan kepadaku [Khubaib bin Abdurrahman Al Anshori] berkata; saya telah mendengar [Abdurrahman bin Mas'ud bin dinar] berkata; datang [Sahl bin Abu Hatsmah] kepada majlis kami lalu menceritakan Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jika kalian menaksir maka petiklah, dan tinggalkanlah sepertiganya jika kalian tidak memetiknya dan tidak meninggalkannya maka tinggalkanlah seperempatnya.\""},"578":{"ar":"حَدَّثَنَا سُفْيَانُ قَالَ ذَكَرَهُ عَبْدُ الْمَلِكِ بْنُ نَوْفَلِ بْنِ مُسَاحِقَ قَالَ سُفْيَانُ وَجَدُّهُ بَدْرِيٌّ عَنْ رَجُلٍ مِنْ مُزَيْنَةَ يُقَالُ لَهُ ابْنُ عِصَامٍ عَنْ أَبِيهِ وَكَانَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا بَعَثَ السَّرِيَّةَ يَقُولُ إِذَا رَأَيْتُمْ مَسْجِدًا أَوْ سَمِعْتُمْ مُنَادِيًا فَلَا تَقْتُلُوا أَحَدًا قَالَ ابْنُ عِصَامٍ عَنْ أَبِيهِ بَعَثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَرِيَّةٍ","id":"Telah menceritakan kepada kami [Sufyan] berkata; [Abdul Malik bin Nufail bin Musahiq] menyebutkan, Sufyan berkata; dan kakeknya adalah ahli Badar dari seorang laki-laki dari Muzainah yang bernama [Ibnu Isham] dari [Bapaknya] dia adalah salah seorang sahabat Nabi Shallallahu'alaihiwasallam berkata; Nabi Shallallahu'alaihiwasallam jika mengirim satuan perang bersabda: \"Jika kalian melihat masjid atau mendengar panggilan maka janganlah kalian membunuh seorang pun.\" [Ibnu Isham] berkata; dari [Bapaknya] Rasulullah Shallallahu'alaihiwasallam mengutus kami pada suatu kesatuan perang."},"579":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ عَبْدِ رَبِّهِ حَدَّثَنَا بَقِيَّةُ بْنُ الْوَلِيدِ قَالَ حَدَّثَنِي الزُّبَيْدِيُّ عَنِ الزُّهْرِيِّ عَنِ السَّائِبِ بْنِ يَزِيدَأَنَّهُ لَمْ يَكُنْ يُقَصُّ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا أَبِي بَكْرٍ وَكَانَ أَوَّلَ مَنْ قَصَّ تَمِيمٌ الدَّارِيُّ اسْتَأْذَنَ عُمَرَ بْنَ الْخَطَّابِ أَنْ يَقُصَّ عَلَى النَّاسِ قَائِمًا فَأَذِنَ لَهُ عُمَرُ","id":"Telah menceritakan kepada kami [Yazid bin Abdu Rabnya] telah menceritakan kepada kami [Baqiyyah bin Al Walid] berkata; telah menceritakan kepadaku [Az Zubaidi] dari [Az Zuhri] dari [As Sa'ib bin Yazid] dia tidak mengisahkan pada masa Rasulullah Shallallahu'alaihiwasallam ataupun Abu Bakar, yang pertama kami menceritakan adalah Tamim Ad-Dari meminta ijin kepada 'Umar bin Khattab, agar dia menceritakan kepada manusia dengan keadaan berdiri lalu 'Umar mengijinkannya."},"580":{"ar":"حَدَّثَنَا هَارُونُ بْنُ مَعْرُوفٍ قَالَ عَبْد اللَّهِ وَسَمِعْتُهُ أَنَا مِنْ هَارُونَ قَالَ أَخْبَرَنَا ابْنُ وَهْبٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَسْوَدَ الْقُرَشِيُّ أَنَّ يَزِيدَ بْنَ خُصَيْفَةَ حَدَّثَهُ عَنِ السَّائِبِ بْنِ يَزِيدَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَزَالُ أُمَّتِي عَلَى الْفِطْرَةِ مَا صَلَّوْا الْمَغْرِبَ قَبْلَ طُلُوعِ النُّجُومِ","id":"Telah menceritakan kepada kami telah menceritakan kepada kami [Harun bin Ma'ruf] Abdullah berkata; dan saya mendengarnya dari [Harun] berkata; telah mengabarkan kepada kami [Ibnu Wahb] berkata; telah menceritakan kepada kami [Abdullah bin Aswad Al Qurasyi] dari [Yazid bin Khushaifah] menceritakannya dari [As Sa'ib bin Yazid] Rasulullah Shallallahu'alaihiwasallam bersabda: \"Umatku akan tetap dalam fitrahnya selama masih melaksanakan shalat maghrib sebelum bintang terlihat.\""},"581":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَاعِيلَ عَنْ مُحَمَّدٍ يَعْنِي ابْنَ يُوسُفَ عَنِ السَّائِبِ بْنِ يَزِيدَ قَالَحُجَّ بِي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ وَأَنَا ابْنُ سَبْعِ سِنِينَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Hatim bin Isma'il] dari [Muhammad] yaitu Ibnu Yusuf dari [As Sa'ib bin Yazid] berkata; saya melakukan haji bersama Rasulullah Shallallahu'alaihiwasallam pada Haji Wada', waktu itu saya berumur tujuh tahun."},"582":{"ar":"حَدَّثَنَا مَكِّيُّ بْنُ إِبْرَاهِيمَ حَدَّثَنَا الْجُعَيْدُ عَنْ يَزِيدَ بْنِ خُصَيْفَةَ عَنِ السَّائِبِ بْنِ يَزِيدَ قَالَكُنَّا نُؤْتَى بِالشَّارِبِ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفِي إِمْرَةِ أَبِي بَكْرٍ وَصَدْرًا مِنْ إِمْرَةِ عُمَرَ فَنَقُومُ إِلَيْهِ فَنَضْرِبُهُ بِأَيْدِينَا وَنِعَالِنَا وَأَرْدِيَتِنَا حَتَّى كَانَ صَدْرًا مِنْ إِمْرَةِ عُمَرَ فَجَلَدَ فِيهَا أَرْبَعِينَ حَتَّى إِذَا عَتَوْا فِيهَا وَفَسَقُوا جَلَدَ ثَمَانِينَ","id":"Telah menceritakan kepada kami [Maki bin Ibrahim] telah menceritakan kepada kami [Al Jua'id] dari [Yazid bin Khushaifah] dari [As Sa'ib bin Yazid] berkata; didatangkan orang yang meminum (arak) pada masa Rasulullah Shallallahu'alaihiwasallam, pada masa pemerintahan Abu Bakar dan diawAl awal pemerintahan 'Umar, kami menemuinya dan kami pukuli dengan tangan, sandal dan pakaian kami, sampai pada awAl awal masa pemerintahan 'Umar, peminum khamar dicambuk empat puluh kali. Tatkala peminum khamar semakin menjadi-jadi dan terjadi banyak kefasikan maka mereka dicambuk sebanyak delapan puluh kali."},"583":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنِ السَّائِبِ بْنِ يَزِيدَ قَالَخَرَجْتُ مَعَ الصِّبْيَانِ إِلَى ثَنِيَّةِ الْوَدَاعِ نَتَلَقَّى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ غَزْوَةِ تَبُوكَ وَقَالَ سُفْيَانُ مَرَّةً أَذْكُرُ مَقْدِمَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا قَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ تَبُوكَ","id":"Telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [As Sa'ib bin Yazid] berkata; saya berangkat bersama anak-anak menuju Tsaniyatul Wada', untuk menemui Rasulullah Shallallahu'alaihiwasallam dari Perang Tabuk. [Sufyan] berkata; saya sebutkan kedatangan Nabi Shallallahu'alaihiwasallam, Nabi Shallallahu'alaihiwasallam datang dari Tabuk."},"584":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ حَدَّثَنَا يَزِيدُ بْنُ خُصَيْفَةَ عَنِ السَّائِبِ بْنِ يَزِيدَ إِنْ شَاءَ اللَّهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ظَاهَرَ بَيْنَ دِرْعَيْنِ يَوْمَ أُحُدٍ وَحَدَّثَنَا بِهِ مَرَّةً أُخْرَى فَلَمْ يَسْتَثْنِ فِيهِ","id":"Telah menceritakan kepada kami [Sufyan bin 'Uyainah] telah menceritakan kepada kami [Yazid bin Khushaifah] dari [As Sa'ib bin Yazid] jika Allah menghendaki Nabi Shallallahu'alaihiwasallam memakai dua baju besi pada Perang Uhud. Dan Saib bin Yazid telah menceritakan kepada kami pada lain kesempatan dengan tidak mengucapkan kalimat INSYA ALLAH."},"585":{"ar":"حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا ابْنُ مُبَارَكٍ عَنْ يُونُسَ عَنِ الزُّهْرِيِّ عَنِ السَّائِبِ بْنِ يَزِيدَأَنَّ شُرَيْحًا الْحَضْرَمِيَّ قَالَ ذُكِرَ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ذَاكَ رَجُلٌ لَا يَتَوَسَّدُ الْقُرْآنَ","id":"Telah menceritakan kepada kami [Yahya bin Adam] berkata; telah menceritakan kepada kami [Ibnu Mubarok] dari [Yunus] dari [Az Zuhri] dari [As Sa'ib bin Yazid] Syuraih Al Hadlrami, (As Sa'ib bin Yazid Radliyallahu'anhuma) berkata; pernah namanya disebutkan di hadapan Nabi Shallallahu'alaihiwasallam lalu beliau bersabda: \"Itu adalah orang yang sangat serius mencermati alquran dan rajin mengamalkannya.\""},"586":{"ar":"حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا ابْنُ مُبَارَكٍ عَنْ يُونُسَ عَنِ الزُّهْرِيِّ عَنِ السَّائِبِ بْنِ يَزِيدَأَنَّ شُرَيْحًا الْحَضْرَمِيَّ ذُكِرَ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ذَاكَ رَجُلٌ لَا يَتَوَسَّدُ الْقُرْآنَحَدَّثَنَا عَلِيُّ بْنُ إِسْحَاقَ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ قَالَ أَخْبَرَنَا يُونُسُ بْنُ يَزِيدَ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي السَّائِبُ بْنُ يَزِيدَ فَذَكَرَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Yahya bin Adam] telah menceritakan kepada kami [Ibnu Mubarak] dari [Yunus] dari [Az Zuhri] dari [As Sa'ib bin Yazid] Syuraih Al Hadlromi, pernah namanya disebutkan di hadapan Nabi Shallallahu'alaihiwasallam lalu beliau bersabda: \"Itu adalah orang serius mencermati alquran dan serius mengamalkannya.\" Telah menceritakan kepada kami ['Ali bin Ishaq] berkata; telah mengabarkan kepada kami [Abdullah] berkata; telah mengabarkan kepada kami [Yunus bin Yazid] dari [Az Zuhri] berkata; telah mengabarkan kepadaku [As Sa'ib bin Yazid] lalu menyebutkan sama dengan yang di atas."},"587":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ حَدَّثَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي السَّائِبُ بْنُ يَزِيدَ ابْنُ أُخْتِ نَمِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا عَدْوَى وَلَا صَفَرَ وَلَا هَامَةَ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah menceritakan kepada kami [Syu'aib] dari [Az Zuhri] berkata; telah menceritakan kepadaku [As Sa'ib bin Yazid, anak saudara perempuan Namir] Nabi Shallallahu'alaihiwasallam bersabda: \"Tidak ada 'adwa (keyakinan bahwa penyakit itu menular dengan sendirinya bukan karena taqdir dari Allah AzzaWaJalla), tidak ada shafar (keyakinan pada saat Jahiliyah bahwa terjadinya kematian semata-mata karena cacing perut), dan tidak ada haamah (keyakinan Jahiliyah bahwa tulang mayat itu akan berubah menjadi burung).\""},"588":{"ar":"حَدَّثَنَا يُونُسُ حَدَّثَنَا لَيْثٌ عَنْ يَزِيدَ يَعْنِي ابْنَ الْهَادِ عَنْ إِسْمَاعِيلَ بْنِ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ قَالَ بَلَغَنِيأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ إِنْسَانٍ يَكُونُ فِي مَجْلِسٍ فَيَقُولُ حِينَ يُرِيدُ أَنْ يَقُومَ سُبْحَانَكَ اللَّهُمَّ وَبِحَمْدِكَ لَا إِلَهَ إِلَّا أَنْتَ أَسْتَغْفِرُكَ وَأَتُوبُ إِلَيْكَ إِلَّا غُفِرَ لَهُ مَا كَانَ فِي ذَلِكَ الْمَجْلِسِفَحَدَّثْتُ هَذَا الْحَدِيثَ يَزِيدَ بْنَ خُصَيْفَةَ قَالَ هَكَذَا حَدَّثَنِي السَّائِبُ بْنُ يَزِيدَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Yunus] telah menceritakan kepada kami [Laits] dari [Yazid] yaitu Ibnu Al Had, dari [Isma'il bin Abdullah bin Ja'far] berkata; sampai kepadaku Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidaklah seorang yang berada pada sebuah majlis lalu membaca ketika hendak berdiri, 'Maha Suci Engkau ya Allah, dan pujianmu, tidak ada ilah kecuali engkau. Saya memohon ampun kepada-Mu dan bertaubat kepada-Mu' kecuali akan diampuni, apa yang telah dilakukan dalam majlis tersebut. Saya sampaikan hadits ini pada [Yazid bin Khushaifah]. Dia berkata; beginilah [As Sa'ib bin Yazid] telah menceritakan kepada kami dari Rasulullah Shallallahu'alaihiwasallam."},"589":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ خُبَيْبِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ حَفْصِ بْنِ عَاصِمٍ عَنْ أَبِي سَعِيدِ بْنِ الْمُعَلَّى قَالَكُنْتُ أُصَلِّي فَمَرَّ بِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَعَانِي فَلَمْ آتِهِ حَتَّى صَلَّيْتُ ثُمَّ أَتَيْتُهُ فَقَالَ مَا مَنَعَكَ أَنْ تَأْتِيَنِي فَقَالَ إِنِّي كُنْتُ أُصَلِّي قَالَ أَلَمْ يَقُلْ اللَّهُ تَبَارَكَ وَتَعَالَى{ يَا أَيُّهَا الَّذِينَ آمَنُوا اسْتَجِيبُوا لِلَّهِ وَلِلرَّسُولِ إِذَا دَعَاكُمْ لِمَا يُحْيِيكُمْ }ثُمَّ قَالَ أَلَا أُعَلِّمُكُمْ أَعْظَمَ سُورَةٍ فِي الْقُرْآنِ قَبْلَ أَنْ أَخْرُجَ مِنْ الْمَسْجِدِ قَالَ فَذَهَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيَخْرُجَ فَذَكَّرْتُهُ فَقَالَ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ هِيَ السَّبْعُ الْمَثَانِي وَالْقُرْآنُ الْعَظِيمُ الَّذِي أُوتِيتُهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Khubaib bin Abdurrahman] dari [Hafs bin 'Ashim] dari [Abu Sa'id bin Al Mu'alla] berkata; ketika saya sedang shalat lalu Rasulullah Shallallahu'alaihiwasallam melewatiku, lalu beliau memanggilku namun saya tidak mendatanginya sehingga shalat saya selesai. Beliau bertanya, apa yang mengahalangimu untuk datang kepadaku? (Abu Sa'id bin Al Mu'alla Radliyallahu'anhuma) berkata; saya sedang shalat. Beliau bersabda: \"Bukankah Allah Tabaraka Wa Ta'ala telah berfirman, \"Hai orang-orang yang beriman, penuhilah seruan Allah dan seruan Rasul apabila Rasul menyeru kamu kepada suatu yang memberi kehidupan kepada kamu\" Lalu beliau bersabda: \"Maukah saya ajarkan surat yang paling agung dalam alqur'an sebelum saya meninggalkan masjid ini?. (Abu Sa'id bin Al Mu'alla Radliyallahu'anhuma) berkata; Rasulullah Shallallahu'alaihiwasallam pergi lalu saya mengingatkan beliau, lalu beliau bersabda: \"Segala puji bagi Allah rabb semesta alam\" itu adalah termasuk Assabu' Al Matsani (tujuh ayat yang terulang-ulang) dan Al quran yang agung yang diberikan kepadaku?."},"590":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا حَجَّاجٌ يَعْنِي الصَّوَّافَ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عِكْرِمَةَ عَنِ الْحَجَّاجِ بْنِ عَمْرٍو الْأَنْصَارِيِّ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ وَإِسْمَاعِيلُ قَالَ أَخْبَرَنِي الْحَجَّاجُ بْنُ أَبِي عُثْمَانَ قَالَ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ أَنَّ عِكْرِمَةَ مَوْلَى ابْنِ عَبَّاسٍ حَدَّثَهُ قَالَ حَدَّثَنِي الْحَجَّاجُ بْنُ عَمْرٍو الْأَنْصَارِيُّ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ كُسِرَ أَوْ عَرَجَ فَقَدْ حَلَّ وَعَلَيْهِ حَجَّةٌ أُخْرَىقَالَ فَذَكَرْتُ ذَلِكَ لِابْنِ عَبَّاسٍ وَأَبِي هُرَيْرَةَ فَقَالَا صَدَقَ قَالَ إِسْمَاعِيلُ فَحَدَّثْتُ بِذَاكَ ابْنَ عَبَّاسٍ وَأَبَا هُرَيْرَةَ فَقَالَا صَدَقَ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Hajjaj] yaitu Ash-Shawaf, dari [Yahya bin Abu Katsir] dari [Ikrimah] dari [Al Hajjaj bin 'Amr Al Anshari] berkata; saya telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda. [Isma'il] berkata; telah menceritakan kepadaku [Al Hajjaj bin Abu 'Utsman] berkata; telah menceritakan kepada kami [Yahya bin Abu Katsir] ['Ikrimah] budak Ibnu 'Abbas menceritakannya berkata; telah menceritakan kepadaku [Al Hajjaj bin 'Amr Al Anshari] berkata; saya telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa terluka pada kakinya maka dia telah masuk pada tahallul, dan dia wajib haji yang lainnya.\" (Al Hajjaj bin 'Amr Al Anshari Radliyallahu'anhu) berkata; saya sebutkan hal itu kepada [Ibnu 'Abbas] dan [Abu Hurairah], lalu keduanya berkata; benar. [Isma'il] berkata; lalu saya menceritakan hal itu kepada [Ibnu 'Abbas] dan [Abu Hurairah] lalu keduanya berkata; benar."},"591":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي الْفَيْضِ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ مُرَّةَ يُحَدِّثُ عَنْ أَبِي سَعِيدٍ الزُّرَقِيِّأَنَّ رَجُلًا مِنْ أَشْجَعَ سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْعَزْلِ فَقَالَ إِنَّ امْرَأَتِي تُرْضِعُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مَا يُقَدَّرُ فِي الرَّحِمِ فَسَيَكُونُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Abu Al Faidl] berkata; saya telah mendengar [Abdullah bin Murrah] menceritakan dari [Abu Sa'id Az Zuraqi] ada seorang laki-laki dan Asyja' bertanya kepada Nabi Shallallahu'alaihiwasallam tentang 'azl. Berkata; istriku sedang menyusui. Nabi Shallallahu'alaihiwasallam bersabda: \" Apa yang telah ditentukan di dalam rahim niscaya akan terjadi.\""},"592":{"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا هِشَامٌ وَابْنُ نُمَيْرٍ قَالَ حَدَّثَنَا هِشَامٌ قَالَ أَخْبَرَنِي أَبِي عَنْ حَجَّاجِ بْنِ حَجَّاجٍ عَنْ أَبِيهِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ مَا يُذْهِبُ عَنِّي مَذَمَّةَ الرَّضَاعِ قَالَ غُرَّةٌ عَبْدٌ أَوْ أَمَةٌ","id":"Telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Hisyam] dan [Ibnu Numair] berkata; telah menceritakan kepada kami [Hisyam] berkata; telah mengabarkan kepadaku [bapakku] dari [Hajjaj bin Hajjaj] dari [Bapaknya] berkata; saya berkata; Wahai Rasulullah, apakah yang bisa menghilangkan dariku hubungan persusuan? Beliau menjawab, budak laki-laki atau budak perempuan."},"593":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ وَإِسْحَاقَ عَنْ سُفْيَانَ قَالَ سُفْيَانُ عَنْ عَبْدِ الْكَرِيمِ الْجَزَرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي عَمْرَةَ عَنْ عَمِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَجْمَعُوا اسْمِي وَكُنْيَتِي","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abdurrahman] dari [Sufyan] dan [Ishaq] dari [Sufyan] Sufyan berkata; dari [Abdul Karim Al Jazari] dari [Abdurrahman bin Abu 'Amrah] dari [pamannya] Rasulullah Shallallahu'alaihiwasallam bersabda: \"Janganlah kalian mengumpulkan antara namaku dan kuniyahku (nama yang disandarkan pada nama anaknya).\""},"594":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ عَبْدِ اللَّهِ يَعْنِي ابْنَ أَبِي بَكْرٍ وَسَالِمٍ أَبِي النَّضْرِ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ عَبْدِ اللَّهِ بْنِ حُذَافَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَهُ أَنْ يُنَادِيَ فِي أَيَّامِ التَّشْرِيقِ أَنَّهَا أَيَّامُ أَكْلٍ وَشُرْبٍ","id":"Telah menceritakan kepada kami [Abdurrahman] dari [Sufyan] dari [Abdullah] yaitu Ibnu Abu Karim dan [Salim Abu Nadlr] dari [Sulaiman bin Yasar] dari [Abdullah bin Hudzafah] Nabi Shallallahu'alaihiwasallam menyuruhnya agar mengumumkan pada Hari Tasyriq bahwa hari-hari tersebut adalah hari untuk makan dan minum."},"595":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ حُمَيْدٍ الْأَعْرَجِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ عَنْ عَبْدِ اللَّهِ بْنِ رَوَاحَةَأَنَّهُ قَدِمَ مِنْ سَفَرٍ لَيْلًا فَتَعَجَّلَ إِلَى امْرَأَتِهِ فَإِذَا فِي بَيْتِهِ مِصْبَاحٌ وَإِذَا مَعَ امْرَأَتِهِ شَيْءٌ فَأَخَذَ السَّيْفَ فَقَالَتْ امْرَأَتُهُ إِلَيْكَ إِلَيْكَ عَنِّي فُلَانَةُ تُمَشِّطُنِي فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَهُ فَنَهَى أَنْ يَطْرُقَ الرَّجُلُ أَهْلَهُ لَيْلًا","id":"Telah menceritakan kepada kami [Abdurrahman] telah menceritakan kepada kami [Sufyan] dari [Humaid Al A'raj] dari [Muhammad bin Ibrahim] dari [Abu Salamah] dari [Abdullah bin Rawahah] dia baru datang dari perjalanan pada malam hari, lalu dia tergesa-gesa menuju istrinya, yang ternyata di rumahnya ada lampu. Istrinya di sana sedang bersama bayang-bayang yang mencurigakan. Kontan Abdullah bin Rawahah mengambil pedang. Maka istrinya berkata; 'Maaf, menjauhlah dariku, menjauhlah dariku, ini adalah seorang wanita yang sedang menyisiri rambutku.' Lalu dia (Abdullah bin Rawahah Radliyallahu'anhu) menemui Nabi Shallallahu'alaihiwasallam dan menceritakannya. Lalu Nabi Shallallahu'alaihiwasallammelarang seseorang mendatangi keluarganya secara mendadak pada malam hari."},"596":{"ar":"حَدَّثَنَا يَعْمَرُ بْنُ بِشْرٍ حَدَّثَنَا عَبْدُ اللَّهِ قَالَ أَخْبَرَنَا يُونُسُ عَنِ الزُّهْرِيِّ قَالَ سَمِعْتُ سِنَانَ بْنَ أَبِي سِنَانٍ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُ قَائِمًا فِي قَصَصِهِإِنَّ أَخًا لَكُمْ كَانَ لَا يَقُولُ الرَّفَثَ يَعْنِي ابْنَ رَوَاحَةَ قَالَ وَفِينَا رَسُولُ اللَّهِ يَتْلُو كِتَابَهُإِذَا انْشَقَّ مَعْرُوفٌ مِنْ اللَّيْلِ سَاطِعُيَبِيتُ يُجَافِي جَنْبَهُ عَنْ فِرَاشِهِإِذَا اسْتَثْقَلَتْ بِالْكَافِرِينَ الْمَضَاجِعُأَرَانَا الْهُدَى بَعْدَ الْعَمَى فَقُلُوبُنَابِهِ مُوقِنَاتٌ أَنَّ مَا قَالَ وَاقِعُ","id":"Telah menceritakan kepada kami [Ya'mar bin Bisyr] telah menceritakan kepada kami [Abdullah] berkata; telah mengabarkan kepada kami [Yunus] dari [Az Zuhri] berkata; saya telah mendengar [Sinan bin Abu Sinan] berkata; saya telah mendengar [Abu Hurairah] menceritakan kisahnya sambil berdiri 'Sudara kalian (Ibnu rawahah maksudnya) tidak mengucapkan rafats (perkataan jelek). Bahkan dia berkata 'Di antara kita ada Rasulullah Shallallahu'alaihiwasallam yang membaca kitabnya, saat malam merekah terang. Ia bermalam dengan menjauhkan punggungnya dari tempat tidurnya, saat tempat tidur terasa berat bagi orang-orang kafir. (Rasulullah Shallallahu'alaihiwasallam) memperlihatkan petunjuk kepada kita. Yang karenanya hati kita menjadi yakin, setelah nyata apa yang diucapkannya musti terjadi."},"597":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ أَخْبَرَنَا بَكْرُ بْنُ مُضَرَ عَنِ ابْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ سَعِيدِ بْنِ الصَّلْتِ عَنْ سُهَيْلِ ابْنِ الْبَيْضَاءِ قَالَبَيْنَمَا نَحْنُ فِي سَفَرٍ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا رَدِيفُهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا سُهَيْلُ ابْنَ الْبَيْضَاءِ وَرَفَعَ صَوْتَهُ مَرَّتَيْنِ أَوْ ثَلَاثًا كُلُّ ذَلِكَ يُجِي��ُهُ سُهَيْلٌ فَسَمِعَ النَّاسُ صَوْتَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَظَنُّوا أَنَّهُ يُرِيدُهُمْ فَحُبِسَ مَنْ كَانَ بَيْنَ يَدَيْهِ وَلَحِقَهُ مَنْ كَانَ خَلْفَهُ حَتَّى إِذَا اجْتَمَعُوا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُ مَنْ شَهِدَ أَنْ لَا إِلَهَ إِلَّا اللَّهُ حَرَّمَهُ اللَّهُ عَلَى النَّارِ وَأَوْجَبَ لَهُ الْجَنَّةَحَدَّثَنَا هَارُونُ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ حَيْوَةُ حَدَّثَنِي ابْنُ الْهَادِ عَنْ مُحَمَّدٍ يَعْنِي ابْنَ إِبْرَاهِيمَ عَنْ سَعِيدِ بْنِ الصَّلْتِ عَنْ سُهَيْلِ ابْنِ الْبَيْضَاءِ مِنْ بَنِي عَبْدِ الدَّارِ قَالَ بَيْنَمَا نَحْنُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَذَكَرَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata; telah mengabarkan kepada kami [Bakr bin Mudlar] dari [Ibnu Al Had] dari [Muhammad bin Ibrahim] dari [Sa'id bin As Shalt] dari [Suhail bin Al Baidla] berkata; tatkala kami sedang dalam perjalanan bersama Rasulullah Shallallahu'alaihiwasallam, saya membonceng beliau. Rasulullah Shallallahu'alaihiwasallam bersabda: \"Wahai Suhail bin Al Baidla!\" beliau mengangkat suaranya dua atau tiga kali, semuanya Suhail menjawabnya. Orang-orang mendengar suara Rasulullah Shallallahu'alaihiwasallam dan mereka menyangka menginginkan mereka, lalu orang yang berada di hadapan beliau berhenti dan orang yang berada di belakang beliau mengejarnya. Setelah mereka terkumpul, Rasulullah Shallallahu'alaihiwasallam bersabda: \" Barangsiapa yang bersaksi bahwa tidak ada sesembahan yang hak selain Allah, niscaya Allah mengharamkan neraka atasnya dan wajib baginya surga.\" Telah menceritakan kepada kami [Harun] telah menceritakan kepada kami [Ibnu Wahb], [Haiwah] berkata; telah menceritakan kepadaku [Ibnu Al Had] dari [Muhammad] yaitu Ibnu Ibrahim dari [Sa'id bin As Shalt] dari [Suhail bin Al Baidla] dari Bani Abdul Dar berkata; tatkala kami bersama Rasulullah Shallallahu'alaihiwasallam dalam sebuah perjalanan, lalu menyebutkan secara makna."},"598":{"ar":"حَدَّثَنَا الْحَكَمُ بْنُ نَافِعٍ قَالَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَيَّاشٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ قَالَتَزَوَّجَ عَقِيلُ بْنُ أَبِي طَالِبٍ فَخَرَجَ عَلَيْنَا فَقُلْنَا بِالرَّفَاءِ وَالْبَنِينَ فَقَالَ مَهْ لَا تَقُولُوا ذَلِكَ فَإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ نَهَانَا عَنْ ذَلِكَ وَقَالَ قُولُوا بَارَكَ اللَّهُ لَكَ وَبَارَكَ عَلَيْكَ وَبَارَكَ لَكَ فِيهَا","id":"Telah menceritakan kepada kami [Al Hakam bin Nafi'] berkata; telah menceritakan kepada kami [Isma'il bin 'Ayyasy] dari [Salim bin Abdullah] dari [Abdullah bin Muhammad bin 'Aqil] berkata; ['Aqil bin Abu Thalib] menikah, lalu dia keluar menemui kami. Kami berkata; BIR ROFA`'I WA AL BANIN (semoga kamu mendapat berbarakah, menyatu dan banyak anak). Lalu dia berkata; jangan! Jangan kalian mengatakan hal itu. Nabi Shallallahu'alaihiwasallam telah melarang kami dengan hal itu, namun beliau bersabda: \"Katakanlah 'Semoga Allah memberi barakah kepada kalian berdua baik saat suka maupun duka, dan memberi barakah kepadamu di alam pernikahan'.\""},"599":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا يُونُسُ عَنْ الْحَسَنِأَنَّ عَقِيلَ بْنَ أَبِي طَالِبٍ تَزَوَّجَ امْرَأَةً مِنْ بَنِي جُشَمٍ فَدَخَلَ عَلَيْهِ الْقَوْمُ فَقَالُوا بِالرَّفَاءِ وَالْبَنِينَ فَقَالَ لَا تَقُولُوا ذَاكُمْ قَالُوا فَمَا نَقُولُ يَا أَبَا يَزِيدَ قَالَ قُولُوا بَارَكَ اللَّهُ لَكُمْ وَبَارَكَ عَلَيْكُمْ إِنَّا كَذَلِكَ كُنَّا نُؤْمَرُ","id":"Telah menceritakan kepada kami [Isma'il bin Ibrahim] telah menceritakan kepada kami [Yunus] dari [Al Hasan] ['Aqil bin Abu Thalib] menikahi seorang wanita dari Jusyam, lalu kaumnya menemuinya dan berkata; BIR ROFA'I WA AL BANIN (Semoga kamu mendapat barakah, menyatu dan mendapat banyak anak). Lalu beliau berkata 'Jangan kalian mengatakan hal itu!. Mereka berkata; bagaimana kami harus mengatakannya, Wahai Abu Yazid? Dia berkata; \"Katakanlah 'Semoga Allah memberi barakah kepada kalian baik saat suka maupun duka' demikianlah kami diperintah.\""},"600":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا مَعْمَرٌ عَنْ يَحْيَى بْنِ عَبْدِ اللَّهِ بْنِ بَحِيرٍ قَالَ أَخْبَرَنِي مَنْ سَمِعَ فَرْوَةَ بْنَ مُسَيْكٍ الْمُرَادِيَّ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ أَرْضًا عِنْدَنَا يُقَالُ لَهَا أَرْضُ أَبْيَنَ هِيَ أَرْضُ رُفْقَتِنَا وَمِيرَتِنَا وَإِنَّهَا وَبِئَةٌ أَوْ قَالَ إِنَّ بِهَا وَبَاءً شَدِيدًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعْهَا عَنْكَ فَإِنَّ مِنْ الْقَرَفِ التَّلَفَ","id":"Telah menceritakan kepada kami [Abdurrazzaq] berkata; telah mengabarkan kepada kami [Ma'mar] dari [Yahya bin Abdullah bin Bahir] berkata; telah mengabarkan kepadaku [seseorang] yang telah mendengar [Farwah bin Musaik Al Muradi], berkata; saya bertanya Wahai Rasulullah, tanah yang di tempat kami yang bernama 'Abyan' itu adalah tempat kesayangan kami dan harta pusaka yang kami dapatkan dari negeri lain, namun sekarang terjangkiti wabah, atau berkata di dalamnya ada wabah yang sangat dahsyat. Lalu Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tinggalkan saja, karena mendekati lokasi yang terkena penyakit sama artinya dengan kehancuran.\""},"601":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ رَجُلٍ مِنْ الْأَنْصَارِأَنَّهُ جَاءَ بِأَمَةٍ سَوْدَاءَ وَقَالَ يَا رَسُولَ اللَّهِ إِنَّ عَلَيَّ رَقَبَةً مُؤْمِنَةً فَإِنْ كُنْتَ تَرَى هَذِهِ مُؤْمِنَةً أَعْتَقْتُهَا فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَشْهَدِينَ أَنْ لَا إِلَهَ إِلَّا اللَّهُ قَالَتْ نَعَمْ قَالَ أَتَشْهَدِينَ أَنِّي رَسُولُ اللَّهِ قَالَتْ نَعَمْ قَالَ أَتُؤْمِنِينَ بِالْبَعْثِ بَعْدَ الْمَوْتِ قَالَتْ نَعَمْ قَالَ أَعْتِقْهَا","id":"Telah menceritakan kepada kami [Abdurrazzaq] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [seseorang dari Anshar], dia datang dengan membawa seorang budak perempuan yang hitam dan berkata; Wahai Rasulullah, saya memiliki seorang budak mukmin, jika menurut anda ini adalah orang yang beriman maka saya akan membebaskannya. Rasulullah Shallallahu'alaihiwasallam bertanya kepada budak tersebut, apakah kau bersaksi bahwa tidak ada tuhan selain Allah?. Dia menjawab, 'Ya.' (Rasulullah Shallallahu'alaihiwasallam) bertanya, apakah kau bersaksi bahwa saya adalah Rasulullah?. Dia menjawab 'Ya.' Beliau bertanya, apakah kau percaya dengan kebangkitan setelah mati?. Dia menjawab, 'ya.' (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Bebaskanlah dia.\""},"602":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا يَحْيَى أَنَّ مُحَمَّدَ بْنَ إِبْرَاهِيمَ التَّيْمِيَّ أَخْبَرَهُ أَنَّ عِيسَى بْنَ طَلْحَةَ بْنِ عُبَيْدِ اللَّهِ أَخْبَرَهُ أَنَّ عُمَيْرَ بْنَ سَلَمَةَ الضَّمْرِيَّ أَخْبَرَهُ عَنْ رَجُلٍ مِنْ بَهْزٍأَنَّهُ خَرَجَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُرِيدُ مَكَّةَ حَتَّى إِذَا كَانُوا فِي بَعْضِ وَادِي الرَّوْحَاءِ وَجَدَ النَّاسُ حِمَارَ وَحْشٍ عَقِيرًا فَذَكَرُوا لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَقِرُّوهُ حَتَّى يَأْتِيَ صَاحِبُهُ فَأَتَى الْبَهْزِيُّ وَكَانَ صَاحِبَهُ فَقَالَ يَا رَسُولَ اللَّهِ شَأْنَكُمْ بِهَذَا الْحِمَارِ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبَا بَكْرٍ فَقَسَمَهُ فِي الرِّفَاقِ وَهُمْ مُحْرِمُونَ قَالَ ثُمَّ مَرَرْنَا حَتَّى إِذَا كُنَّا بِالْأُثَايَةِ إِذَا نَحْنُ بِظَبْيٍ حَاقِفٍ فِي ظِلٍّ فِيهِ سَهْمٌ فَأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا أَنْ يَقِفَ عِنْدَهُ حَتَّى يُجِيزَ النَّاسُ عَنْهُ","id":"Telah menceritakan kepada kami [Yazid bin Harun] berkata; telah mengabarkan kepada kami, [Yahya] bahwa [Muhammad bin Ibrahim At-Taimi] mengabarinya ['Isa bin Thalhah bin 'Ubaidullah] menghabarinya dari ['Umair bin Salamah Adl-Dlamri] menghabarinya, dari [seorang laki-laki dari Bahz] dia keluar bersama Rasulullah Shallallahu'alaihiwasallam menuju Makah. Sampai ketika mereka telah sampai pada sebagian bukit Rauha', orang-orang mendapatkan keledai Wahsy dalam keadaan terlepas. Mereka sampaikan kasus itu kepada Nabi Shallallahu'alaihiwasallam, lalu beliau bersabda: \"Lepaskanlah kalian sampai datang pemiliknya.\" lalu Al Bahzi datang dan dia adalah sahabatnya, lalu bertanya Wahai Rasulullah, bagaimana menurut anda keledai ini?. Rasulullah Shallallahu'alaihiwasallam menyuruh Abu Bakar lalu membaginya kepada orang-orang, sedang mereka dalam keadaan ihram. (Al Bahzi) berkata; lalu kami melewati sampai di Utsayah, kami melewati rusa yang tertidur, di bawah mulutnya ada anak panah. Nabi Shallallahu'alaihiwasallam memerintahkan seorang laki-laki mendatanginya sehingga orang-orang melewatinya."},"603":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِأَنَّ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ تَعَالَى عَنْهُ قَالَ مَا أَرَى الدِّيَةَ إِلَّا لِلْعَصَبَةِ لِأَنَّهُمْ يَعْقِلُونَ عَنْهُ فَهَلْ سَمِعَ أَحَدٌ مِنْكُمْ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ذَلِكَ شَيْئًا فَقَالَ الضَّحَّاكُ بْنُ سُفْيَانَ الْكِلَابِيُّ وَكَانَ اسْتَعْمَلَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْأَعْرَابِ كَتَبَ إِلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أُوَرِّثَ امْرَأَةَ أَشْيَمَ الضَّبَابِيِّ مِنْ دِيَةِ زَوْجِهَا فَأَخَذَ بِذَلِكَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ تَعَالَى عَنْهُ","id":"Telah menceritakan kepada kami [Abdurrazzaq] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Sa'id bin Musayyab] 'Umar bin Al Khottob RA berkata; Saya tidak melihat diat kecuali bagi ashobah (kerabat dari pihak ayah) karena mereka mendapatkan sisa harta secara syar'i. Apakah ada seseorang yang telah mendengar dari Rasulullah Shallallahu'alaihiwasallam dalam masalah itu?. Lalu [Al Dlahak bin Sufyan Al Kilabi] berkata; dia adalah salah satu pegawai Rasulullah Shallallahu'alaihiwasallam untuk memimpin orang-orang Arab pedesaan. Rasulullah Shallallahu'alaihiwasallam menulis surat kepadaku agar aku memberi warisan istri Asyyam Adl-Dlababi dari diyat suaminya. Lalu 'Umar bin Al Khattab mengambil hal itu sebagai ketetapan."},"604":{"ar":"حَدَّثَنَا سُفْيَانُ قَالَ سَمِعْتُهُ مِنَ الزُّهْرِيِّ عَنْ سَعِيدٍأَنَّ عُمَرَ قَالَ الدِّيَةُ لِلْعَاقِلَةِ وَلَا تَرِثُ الْمَرْأَةُ مِنْ دِيَةِ زَوْجِهَا حَتَّى أَخْبَرَهُ الضَّحَّاكُ بْنُ سُفْيَانَ الْكِلَابِيُّ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَبَ إِلَيَّ أَنْ أُوَرِّثَ امْرَأَةَ أَشْيَمَ الضَّبَابِيِّ مِنْ دِيَةِ زَوْجِهَا فَرَجَعَ عُمَرُ عَنْ قَوْلِهِ","id":"Telah menceritakan kepada kami [Sufyan] berkata; saya telah mendengarnya dari [Az Zuhri] dari [Sa'id] 'Umar berkata; diyat itu untuk wanita yang berakal, dan seorang istri tidak mewarisi diyat suaminya sampai [Al Dlahak bin Sufyan Al Kalbi] mengabarinya bahwa Rasulullah Shallallahu'alaihiwasallam menulis surat kepadaku agar aku memberi warisan istri Asyyam Adl-Dlababi dari diyat suaminya, lalu 'Umar menarik kembali perkataannya."},"605":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ الْمَلِكِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَلِيِّ بْنِ جُدْعَانَ عَنِ الْحَسَنِ عَنِ الضَّحَّاكِ بْنِ سُفْيَانَ الْكِلَابِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُ يَا ضَحَّاكُ مَا طَعَامُكَ قَالَ يَا رَسُولَ اللَّهِ اللَّحْمُ وَاللَّبَنُ قَالَ ثُمَّ يَصِيرُ إِلَى مَاذَا قَالَ إِلَى مَا قَدْ عَلِمْتَ قَالَ فَإِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى ضَرَبَ مَا يَخْرُجُ مِنْ ابْنِ آدَمَ مَثَلًا لِلدُّنْيَا","id":"Telah menceritakan kepada kami hamad bin [Abdul Malik] telah menceritakan kepada kami [Hammad bin Zaid] dari ['Ali bin Jud'an] dari [Al Hasan] dari [Adl-Dlahak bin Sufyan Al Kilabi] Rasulullah Shallallahu'alaihiwasallam bersabda kepadanya, \"Wahai Dlahak, apakah makananmu?.\" Dia menjawab, Wahai Rasulullah, daging dan susu!. Beliau bertanya, lantas yang kau makan itu menjadi apa?. Dia menjawab 'Sebagaimana yang anda ketahui.' Beliau bersabda: \" Allah Tabaroka Wa Ta'ala membuat contoh apa yang telah keluar dari anak Adam sebagai pemisalan di dunia.\""},"606":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنْ سَالِمٍ عَنِ ابْنِ عُمَرَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اقْتُلُوا الْحَيَّاتِ وَاقْتُلُوا ذَا الطُّفْيَتَيْنِ وَالْأَبْتَرَ فَإِنَّهُمَا يُسْقِطَانِ الْحَبَلَ وَيَطْمِسَانِ الْبَصَرَ قَالَ ابْنُ عُمَرَ فَرَآنِي أَبُو لُبَابَةَ أَوْ زَيْدُ بْنُ الْخَطَّابِ وَأَنَا أُطَارِدُ حَيَّةً لِأَقْتُلَهَا فَنَهَانِي فَقُلْتُ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أَمَرَ بِقَتْلِهِنَّ فَقَالَ إِنَّهُ قَدْ نَهَى بَعْدَ ذَلِكَ عَنْ قَتْلِ ذَوَاتِ الْبُيُوتِقَالَ الزُّهْرِيُّ وَهِيَ الْعَوَامِرُ","id":"Telah menceritakan kepada kami [Abdurrazzaq] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salim] dari [Ibnu 'Umar] berkata; saya telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Bunuhlah ular-ular dan bunuhlah dzitthufyatain (ular yang pada pungungnya ada dua garis putih) dan Al abtar (ular yang ekornya pendek), karena keduanya akan menggugurkan kandungan dan mengaburkan penglihatan.\" Ibnu 'Umar berkata; [Abu Lubabah] atau [Zaid bin Al Khattab] melihatku ketika saya sedang mengejar ular untuk saya bunuh, lalu dia melarangku. Lalu saya berkata 'Rasulullah Shallallahu'alaihiwasallam telah menyuruh untuk membunuhnya.' (Abu Lubabah bin Abdul Mundzir Radliyallahu'anhu) berkata; 'Rasulullah Shallallahu'alaihiwasallam sungguh telah menyuruh membunuhnya.' Maka dia menjawab 'Setelah itu beliau melarang membunuh ular yang berada di rumah.' [Az Zuhri] berkata; itu adalah ular yang hanya tinggal di rumah dan biasanya dari jin."},"607":{"ar":"حَدَّثَنَا يَزِيدُ قَالَ أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْحَاقَ عَنْ نَافِعٍ عَنِ ابْنِ عُمَرَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمِنْبَرِ يَقُولُ اقْتُلُوا الْحَيَّةَ وَاقْتُلُوا ذَا الطُّفْيَتَيْنِ وَالْأَبْتَرَ فَإِنَّهُمَا يَلْتَمِعَانِ الْبَصَرَ وَيَسْتَسْقِطَانِ الْحَبَلَ قَالَ فَكُنْتُ لَا أَرَى حَيَّةً إِلَّا قَتَلْتُهَا قَالَ لِي أَبُو لُبَابَةَ بْنُ عَبْدِ الْمُنْذِرِ أَلَا تَفْتَحُ بَيْنِي وَبَيْنَكَ خَوْخَةٌ فَقُلْتُ بَلَى قَالَ فَقُمْتُ أَنَا وَهُوَ فَفَتَحْنَاهَا فَخَرَجَتْ حَيَّةٌ فَعَدَوْتُ عَلَيْهَا لِأَقْتُلَهَا فَقَالَ لِي مَهْلًا فَقُلْتُ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أَمَرَ بِقَتْلِهِنَّ قَالَ إِنَّهُ قَدْ نَهَى عَنْ قَتْلِ ذَوَاتِ الْبُيُوتِ","id":"Telah menceritakan kepada kami [Yazid] berkata; telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Nafi'] dari [Ibnu 'Umar] berkata; saya telah mendengar Rasulullah Shallallahu'alaihiwasallam di atas mimbar bersabda: \"Bunuhlah ular dan bunuhlah dzitthufyatain (ular yang pada pungungnya ada dua garis putih) dan Al abtar (ular yang ekornya pendek), karena keduanya bisa mengaburkan penglihatan dan menggugurkan kandungan.\" (Ibnu 'Umar Radliyallahu'anhuma) berkata; maka saya tidak melihat satu pun ular kecuali saya bunuh. [Abu Lubabah bin Abdul Mundzir] berkata kepadaku, maukah kau bukakan pintu kecil?. Saya menjawab, Ya. (Ibnu 'Umar Radliyallahu'anhuma) berkata; saya dan dia membukanya lalu keluarlah seekor ular, lalu saya menuju ke tempatnya untuk membunuhnya, lalu dia berkata; 'Berhentilah.' Lalu saya berkata; Rasulullah Shallallahu'alaihiwasallam telah menyuruh untuk membunuhnya. (Abu Lubabah bin Abdul Mundzir Radliyallahu'anhuma) berkata; (Rasulullah Shallallahu'alaihiwasallam) melarang membunuh ular yang menghuni rumah-rumah."},"608":{"ar":"حَدَّثَنَا رَوْحٌ قَالَ حَدَّثَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي ابْنُ شِهَابٍ أَنَّ الْحُسَيْنَ بْنَ السَّائِبِ بْنِ أَبِي لُبَابَةَ أَخْبَرَأَنَّ أَبَا لُبَابَةَ بْنَ عَبْدِ الْمُنْذِرِ لَمَّا تَابَ اللَّهُ عَلَيْهِ قَالَ يَا رَسُولَ اللَّهِ إِنَّ مِنْ تَوْبَتِي أَنْ أَهْجُرَ دَارَ قَوْمِي وَأُسَاكِنَكَ وَإِنِّي أَنْخَلِعُ مِنْ مَالِي صَدَقَةً لِلَّهِ وَلِرَسُولِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُجْزِئُ عَنْكَ الثُّلُثُ","id":"Telah menceritakan kepada kami [Rauh] berkata; telah menceritakan kepada kami [Ibnu Juraij] berkata; telah mengabarkan kepadaku [Ibnu Syihab] [Al Husain bin As Sa'ib bin Abu Lubabah] mengabarkan [Abu Lubabah bin Abdul Mundzir] ketika Allah menerima taubatnya. Dia berkata; \"Wahai Rasulullah, sebagai konsekuensi taubatku, saya akan menghindari rumah kaumku dan saya akan tinggal bersama anda, saya akan melepaskan hartaku sebagai sedekah kepada Allah dan rasul-Nya.\" Rasulullah Shallallahu'alaihiwasallam bersabda: \"Cukuplah bagimu sepertiganya.\""},"609":{"ar":"حَدَّثَنَا مُحَمَّدٌ حَدَّثَنَا شُعْبَةُ قَالَ عَنْ عَبْدِ رَبٍّ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّهُ كَانَ يَأْمُرُ بِقَتْلِ الْحَيَّاتِ كُلِّهِنَّ فَاسْتَأْذَنَهُ أَبُو لُبَابَةَ أَنْ يَدْخُلَ مِنْ خَوْخَةٍ لَهُمْ إِلَى الْمَسْجِدِ فَرَآهُمْ يَقْتُلُونَ ح��يَّةً فَقَالَ لَهُمْ أَبُو لُبَابَةَ أَمَا بَلَغَكُمْ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ قَتْلِ أُولَاتِ الْبُيُوتِ وَالدُّورِ وَأَمَرَ بِقَتْلِ ذِي الطُّفْيَتَيْنِ وَالْأَبْتَرِ","id":"Telah menceritakan kepada kami [Muhammad] telah menceritakan kepada kami [Syu'bah] berkata; dari ['Abdu Rab] dari [Nafi'] dari [Abdullah bin 'Umar] dia menyuruh untuk membunuh ular semuanya. Lalu [Abu Lubabah] meminta ijin untuk masuk lewat pintu kecil disela-sela rumah mereka yang tembus ke masjid, lalu dia melihat mereka sedang membunuh seekor ular. Abu Lubabah serta merta berkata kepada mereka 'Belumkah sampai kepada kalian bahwa Rasulullah Shallallahu'alaihiwasallam melarang membunuh ular yang menghuni rumah dan menyuruh membunuh dzitthufyatain (ular yang pada pungungnya ada dua garis putihnya) dan Al abtar (ular yang ekornya pendek)?."},"610":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنِ ابْنِ عُمَرَأَنَّهُ فَتَحَ بَابًا فَخَرَجَتْ مِنْهُ حَيَّةٌ فَأَمَرَ بِقَتْلِهَا فَقَالَ لَهُ أَبُو لُبَابَةَ لَا تَفْعَلْ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ نَهَى عَنْ قَتْلِ الْحَيَّاتِ الَّتِي تَكُونُ فِي الْبُيُوتِ","id":"Telah menceritakan kepada kami [Muhammad bin 'Ubaid] berkata; telah menceritakan kepada kami ['Ubaidullah] dari [Nafi'] dari [Ibnu 'Umar] dia membuka pintu lalu keluar seekor ular, lalu dia menyuruh untuk membunuhnya. [Abu Lubabah] berkata kepadanya 'Janganlah kau melakukannya, Rasulullah Shallallahu'alaihiwasallam sungguh telah melarang membunuh ular yang menghuni rumah-rumah.'"},"611":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ قَالَ أَخْبَرَنَا عَلِيُّ بْنُ زَيْدٍ عَنِ الْحَسَنِ أَنَّ الضَّحَّاكَ بْنَ قَيْسٍكَتَبَ إِلَى قَيْسِ بْنِ الْهَيْثَمِ حِينَ مَاتَ يَزِيدُ بْنُ مُعَاوِيَةَ سَلَامٌ عَلَيْكَ أَمَّا بَعْدُ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ بَيْنَ يَدَيْ السَّاعَةِ فِتَنًا كَقِطَعِ اللَّيْلِ الْمُظْلِمِ فِتَنًا كَقِطَعِ الدُّخَانِ يَمُوتُ فِيهَا قَلْبُ الرَّجُلِ كَمَا يَمُوتُ بَدَنُهُ يُصْبِحُ الرَّجُلُ مُؤْمِنًا وَيُمْسِي كَافِرًا وَيُمْسِي مُؤْمِنًا وَيُصْبِحُ كَافِرًا يَبِيعُ أَقْوَامٌ خَلَاقَهُمْ وَدِينَهُمْ بِعَرَضٍ مِنْ الدُّنْيَا وَإِنَّ يَزِيدَ بْنَ مُعَاوِيَةَ قَدْ مَاتَ وَأَنْتُمْ إِخْوَانُنَا وَأَشِقَّاؤُنَا فَلَا تَسْبِقُونَا حَتَّى نَخْتَارَ لِأَنْفُسِنَا","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Salamah] berkata; telah mengabarkan kepada kami ['Ali bin Zaid] dari [Al Hasan] [Dlahak bin Qais] menulis kepada Qais bin Al Hutsaim ketika meninggalnya Yazid bin Mu'awiyah, \"Semoga keselamatan atas anda, saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda Sebelum terjadinya hari kiamat akan terjadi beberapa fitnah seperti gelapnya malam, fitnah seperti asap. Ketika itu hati seseorang menjadi mati seperti halnya badan jika mati. Pagi hari seseorang masih dalam keadaan mukmin namun sore harinya sudah kafir, atau pada sorenya dia masih mukmin namun pagi harinya sudah kafir. Manusia menjual akhlak dan agamanya dengan sedikit kenikmatan dunia'. Yazid bin Mu'awiyah telah meninggal dan kamu adalah saudara kami dan saudara kandung kami, janganlah kamu mendahului kami sampai kami memilih untuk diri kami sendiri.\""},"612":{"ar":"حَدَّثَنَا يَزِيدُ قَالَ أَخْبَرَنَا يَحْيَى بْنُ سَعِيدٍ أَنَّ مُحَمَّدَ بْنَ يَحْيَى بْنِ حَبَّانَ أَخْبَرَهُ أَنَّ عَمَّهُ أَبَا صِرْمَةَ كَانَ يُحَدِّثُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ اللَّهُمَّ إِنِّي أَسْأَلُكَ غِنَايَ وَغِنَى مَوْلَايَ","id":"Telah menceritakan kepada kami [Yazid] berkata; telah mengabarkan kepada kami [Yahya bin Sa'id] dari [Muhammad bin Yahya bin Habban] menghabarinya pamannya, [Abu Shirmah] menceritakan Rasulullah Shallallahu'alaihiwasallam bersabda: \"Ya Allah, saya meminta kepada-Mu kekayaan jiwaku dan kecukupan para waliku.\""},"613":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ لُؤْلُؤَةَ عَنْ أَبِي صِرْمَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ ضَارَّ أَضَرَّ اللَّهُ بِهِ وَمَنْ شَاقَّ شَقَّ اللَّهُ عَلَيْهِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits] dari [Yahya bin Sa'id] dari [Muhammad bin Yahya bin Habban] dari [lu'lu'ah] dari [Abu Shirmah] dari Rasulullah Shallallahu'alaihiwasallam beliau bersabda: \"Barangsiapa mendatangkan mara-bahaya, Allah mendatangkan mara bahaya baginya, dan barangsiapa menimpakan kesulitan kepada manusia, Allah mendatangkan kesulitan baginya.\""},"614":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا لَيْثٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ لُؤْلُؤَةَ عَنْ أَبِي صِرْمَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ اللَّهُمَّ إِنِّي أَسْأَلُكَ غِنَايَ وَغِنَى مَوْلَايَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata; telah menceritakan kepada kami [Laits] dari [Yahya bin Sa'id] dari [Muhammad bin Yahya bin Habban] dari [lu'lu'ah] dari [Abu Shirmah] dari Rasulullah Shallallahu'alaihiwasallam beliau bersabda: \"Ya Allah, saya meminta kepada-Mu kekayaan (kekayaan jiwa bukan harta) dan kecukupan para waliku.\""},"615":{"ar":"حَدَّثَنَا يَزِيدُ قَالَ أَخْبَرَنَا ابْنُ أَبِي ذِئْبٍ عَنْ سَعِيدِ بْنِ خَالِدٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عُثْمَانَ قَالَذَكَرَ طَبِيبٌ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَوَاءً وَذَكَرَ الضُّفْدَعَ يُجْعَلُ فِيهِ فَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ قَتْلِ الضُّفْدَعِ","id":"Telah menceritakan kepada kami [Yazid] berkata; telah mengabarkan kepada kami [Ibnu Abu Dzi'b] dari [Sa'id bin Khalid] dari [Sa'id bin Musayyab] dari [Abdurrahman bin 'Utsman] berkata; ada seorang tabib di sisi Rasulullah Shallallahu'alaihiwasallam menyebutkan suatu obat, yaitu berupa katak. Lalu Rasulullah Shallallahu'alaihiwasallam melarang membunuh katak."},"616":{"ar":"حَدَّثَنَا يَزِيدُ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَاقَ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ مَعْمَرِ بْنِ عَبْدِ اللَّهِ بْنِ نَضْلَةَ الْقُرَشِيِّ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَحْتَكِرُ إِلَّا الْأَخَاطُ","id":"Telah menceritakan kepada kami [Yazid] berkata; telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Muhammad bin Ibrahim At-Taimi] dari [Sa'id bin Musayyab] dari [Ma'mar bin Abdullah bin Nadllah Al Qurasyi] berkata; saya telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidak boleh ditimbun kecuali minyak.\""},"617":{"ar":"حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَاقَ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ مَعْمَرِ بْنِ عَبْدِ اللَّهِ الْعَدَوِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَحْتَكِرُ إِلَّا الْأَخَاطُ","id":"Telah menceritakan kepada kami ['Abdah bin Sulaiman] berkata; telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Muhammad bin Ibrahim] dari [Sa'id bin Musayyab] dari [Ma'mar bin Abdullah Al 'Adawi] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidak boleh ditimbun kecuali minyak.\""},"618":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ مَعْمَرٍ رَجُلٍ مِنْ قُرَيْشٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَحْتَكِرُ إِلَّا الْأَخَاطُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Muhammad bin Ishaq] dari [Muhammad bin Ibrahim At-Taimi] dari [Sa'id bin Musayyab] dari [Ma'mar] seorang laki-laki dari Quraish, berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidak boleh ditimbun kecuali minyak.\""},"619":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْأُمَوِيُّ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ مَعْمَرٍ الْعَدَوِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَحْتَكِرُ إِلَّا الْأَخَاطُوَكَانَ سَعِيدُ بْنُ الْمُسَيَّبِ يَحْتَكِرُ الزَّيْتَ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id Al Umawi] berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sa'id bin Musayyab] dari [Ma'mar Al 'Adawi] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidak boleh ditimbun kecuali minyak\". Dan Sa'id bin Musayyab menimbun minyak."},"620":{"ar":"حَدَّثَنَا يَزِيدُ قَالَ أَخْبَرَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عَبَّادِ بْنِ تَمِيمٍ أَخْبَرَهُ عَنْ عُوَيْمِرِ بْنِ أَشْقَرَأَنَّهُ ذَبَحَ قَبْلَ أَنْ يَغْدُوَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَكَرَ ذَلِكَ لَهُ فَأَمَرَهُ أَنْ يُعِيدَ أُضْحِيَّتَهُ","id":"Telah menceritakan kepada kami [Yazid] berkata; telah mengabarkan kepada kami [Yahya bin Sa'id] dari ['Abbad bin Tamim] mengabarinya dari ['Uwaimir bin Asyqor] dia telah menyembelih sebelum Rasulullah Shallallahu'alaihiwasallam berangkat shalat. Tatkala Rasulullah Shallallahu'alaihiwasallam telah menunaikan shalat hari raya, hal itu dilaporkan kepada beliau, dan beliau menyuruh agar mengulangi penyembelihannya."},"621":{"ar":"حَدَّثَنَا يَزِيدُ قَالَ أَخْبَرَنَا الْمُسْتَلِمُ بْنُ سَعِيدٍ حَدَّثَنَا خُبَيْبُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُرِيدُ غَزْوًا أَنَا وَرَجُلٌ مِنْ قَوْمِي وَلَمْ نُسْلِمْ فَقُلْنَا إِنَّا نَسْتَحْيِي أَنْ يَشْهَدَ قَوْمُنَا مَشْهَدًا لَا نَشْهَدُهُ مَعَهُمْ قَالَ أَوَ أَسْلَمْتُمَا قُلْنَا لَا قَالَ فَإِنَّا لَا نَسْتَعِينُ بِالْمُشْرِكِينَ عَلَى الْمُشْرِكِينَ قَالَ فَأَسْلَمْنَا وَشَهِدْنَا مَعَهُ فَقَتَلْتُ رَجُلًا وَضَرَبَنِي ضَرْبَةً وَتَزَوَّجْتُ بِابْنَتِهِ بَعْدَ ذَلِكَ فَكَانَتْ تَقُولُ لَا عَدِمْتَ رَجُلًا وَشَّحَكَ هَذَا الْوِشَاحَ فَأَقُولُ لَا عَدِمْتِ رَجُلًا عَجَّلَ أَبَاكِ النَّارَ","id":"Telah menceritakan kepada kami [Yazid] berkata; telah menceritakan kepada kami [Al Mustalim bin Sa'id] telah menceritakan kepada kami [Khubaib bin Abdurrahman] dari [Bapaknya] dari [kakeknya] berkata; saya menemui Rasulullah Shallallahu'alaihiwasallam ketika beliau hendak berperang, saya bersama dengan salah seorang dari kaumku. Ketika itu kami belum masuk Islam. Kami berkata; kami malu kalau kaum kami mengikuti sebuah peristiwa sebaliknya kami tidak mengikutinya bersama mereka. Beliau bertanya, apakah kalian telah masuk Islam?. kami menjawab, belum. Beliau bersabda: \"Kami tidak akan meminta tolong kepada orang musyrik untuk memerangi orang musyrik\". Kami pun masuk Islam dan kami ikut bersama beliau. Lalu saya membunuh seorang laki-laki dan dia memukulku satu pukulan, lalu saya menikahi anak perempuanya setelah itu. Wanita itu menolak seraya mengatakan 'Tidak, kamu telah menghilangkan (membunuh) seseorang yang memberimu pedang.' Saya menjawab 'Tidak, engkau telah menghilangkan (menolak kesempatan diperistri) seseorang yang mempercepat ayahmu ke neraka."},"622":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ أُسَامَةَ بْنِ زَيْدٍ عَنِ الزُّهْرِيِّ عَنِ ابْنِ كَعْبِ بْنِ مَالِكٍأَنَّ جَارِيَةً لِكَعْبٍ كَانَتْ تَرْعَى غَنَمًا لَهُ بِسَلْعٍ فَعَدَا الذِّئْبُ عَلَى شَاةٍ مِنْ شَائِهَا فَأَدْرَكَتْهَا الرَّاعِيَةُ فَذَكَّتْهَا بِمَرْوَةٍ فَسَأَلَ كَعْبُ بْنُ مَالِكٍ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَهُ بِأَكْلِهَا","id":"Telah menceritakan kepada kami [Waki'] dari [Usamah bin Zaid] dari [Az Zuhri] dari [Ibnu Ka'ab bin Malik], pembantu perempuan milik Ka'b mengembala kambing miliknya. Ada seekor serigala menyerang salah satu kambingnya, wanita itu mendapatkan kambingnya (yang belum tewas) dan menyembelihnya dengan memakai batu tajam. Lalu [Ka'ab bin Malik] bertanya kepada Nabi Shallallahu'alaihiwasallam, dan beliau menyuruh untuk memakannya."},"623":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا زَمْعَةُ عَنِ الزُّهْرِيِّ عَنِ ابْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِهِ وَهُوَ مُلَازِمٌ رَجُلًا فِي أُوقِيَّتَيْنِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلرَّجُلِ هَكَذَا أَيْ ضَعْ عَنْهُ الشَّطْرَ قَالَ الرَّجُلُ نَعَمْ يَا رَسُولَ اللَّهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلرَّجُلِ أَدِّ إِلَيْهِ مَا بَقِيَ مِنْ حَقِّهِ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Zam'ah] dari [Az Zuhri] dari [Ibnu Ka'ab bin Malik] dari [Bapaknya], Nabi Shallallahu'alaihiwasallam pernah melewatinya ketika dia sedang menagih hutang seorang laki-laki sebesar dua uqiyah (empat puluh dirham perak). Nabi Shallallahu'alaihiwasallam bersabda kepada laki-laki itu 'Lakukanlah begini' maksudnya lunasilah separoh hutangnya. Laki-laki itu berkata; ya Wahai Rasulullah. Lalu Nabi Shallallahu'alaihiwasallam bersabda kepada laki-laki itu, 'Besok penuhilah separoh haknya lagi.'"},"624":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا حَجَّاجٌ عَنْ نَافِعٍ عَنِ ابْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِيهِأَنَّ جَارِيَةً لَهُمْ سَوْدَاءَ ذَكَّتْ شَاةً لَهُمْ بِمَرْوَةٍ فَسَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَأَمَرَهُ بِأَكْلِهَا","id":"Telah menceritakan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami [Hajjaj] dari [Nafi'] dari [Ibnu Ka'ab bin Malik] dari [Bapaknya] budak wanitanya yang berwarna hitam menyembelih seekor kambing mereka dengan batu tajam. Dia bertanya kepada Nabi Shallallahu'alaihiwasallam tentang hal itu, dan beliau menyuruh untuk memakannya."},"625":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ سَعْدٍ عَنْ عَبْدِ اللَّهِ أَوْ عَبْدِ الرَّحْمَنِ بْنِ كَعْبِ بْنِ مَالِكٍ قَالَ عَبْدُ الرَّحْمَنِ هُوَ شَكَّ يَعْنِي سُفْيَانَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثَلُ الْمُؤْمِنِ كَمَثَلِ الْخَامَةِ مِنْ الزَّرْعِ تُقِيمُهَا الرِّيَاحُ تَعْدِلُهَا مَرَّةً وَتَصْرَعُهَا أُخْرَى حَتَّى يَأْتِيَهُ أَجَلُهُ وَمَثَلُ الْكَافِرِ مَثَلُ الْأَرْزَةِ الْمُجْذِيَةِ عَلَى أَصْلِهَا لَا يُقِلُّهَا شَيْءٌ حَتَّى يَكُونَ انْجِعَافُهَا يَخْتَلِعُهَا أَوْ انْجِعَافُهَا مَرَّةً وَاحِدَةً شَكَّ عَبْدُ الرَّحْمَنِ","id":"Telah menceritakan kepada kami [Abdurrahman] dari [Sufyan] dari [Sa'd] dari [Abdullah] atau [Abdurrahman bin Ka'ab bin Malik] Abdurrahman berkata; Sufyan ragu dari [Bapaknya] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Permisalan seorang mukmin seperti dahan yang masih basah dalam pohon, terkadang angin menjadikannya berdiri, lurus dan terkadang bengkok sampai tiba ajalnya. Sebaliknya permisalan orang kafir seperti tanaman padi yang senantiasa berdiri tegak pada akarnya, tidak ada yang bisa menggoyahkannya sesuatupun, hingga sekali ia jatuh, ia langsung roboh. Atau roboh secara langsung --Abdurrahman ragu kepastian redaksinya--."},"626":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي ابْنُ شِهَابٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍأَنَّ كَعْبَ بْنَ مَالِكٍ لَمَّا تَابَ اللَّهُ عَلَيْهِ أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ اللَّهَ لَمْ يُنْجِنِي إِلَّا بِالصِّدْقِ وَإِنَّ مِنْ تَوْبَتِي إِلَى اللَّهِ أَنْ لَا أَكْذِبَ أَبَدًا وَإِنِّي أَنْخَلِعُ مِنْ مَالِي صَدَقَةً لِلَّهِ تَعَالَى وَرَسُولِهِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمْسِكْ عَلَيْكَ بَعْضَ مَالِكَ فَإِنَّهُ خَيْرٌ لَكَ قَالَ فَإِنِّي أُمْسِكُ سَهْمِي مِنْ خَيْبَرَ","id":"Telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami [Ibnu Juraij] berkata; telah mengabarkan kepadaku [Ibnu Syihab] dari [Abdurrahman bin Abdullah bin Ka'ab bin Malik], [Ka'ab bin Malik] ketika Allah menerima taubatnya, dia menemui Rasulullah Shallallahu'alaihiwasallam lalu berkata; Allah tidak menyelamatkanku kecuali dengan kejujuran, dan termasuk dari taubatku kepada Allah, saya tidak akan berdusta selamanya, saya akan melepaskan hartaku sebagai sedekah kepada Allah Ta'ala dan Rasulullah-Nya. Lalu Rasulullah Shallallahu'alaihiwasallam bersabda kepadanya: tahanlah sebagian hartamu, itu lebih baik bagimu. (Ka'ab bin Malik Radliyallahu'anhu) berkata; lalu saya menahan sahamku dari Khaibar."},"627":{"ar":"حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا لَيْثٌ قَالَ حَدَّثَنِي عُقَيْلٌ عَنِ ابْنِ شِهَابٍ عَنِ ابْنِ كَعْبِ بْنِ مَالِكٍ أَحَدُ الثَّلَاثَةِ الَّذِينَ تِيبَ عَلَيْهِمْ أَنَّ كَعْبَ بْنَ مَالِكٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَدِمَ مِنْ سَفَرٍ بَدَأَ بِالْمَسْجِدِ فَسَبَّحَ فِيهِ رَكْعَتَيْنِ ثُمَّ سَلَّمَ فَجَلَسَ فِي مُصَلَّاهُ فَيَأْتِيهِ النَّاسُ فَيُسَلِّمُونَ عَلَيْهِ","id":"Telah menceritakan kepada kami [Hajjaj] telah menceritakan kepada kami [Laits] berkata; telah menceritakan kepadaku ['Uqail] dari [Ibnu Syihab] dari [Ibnu Ka'ab bin Malik] salah seorang yang diterima taubatnya. [Ka'ab bin Malik] berkata; Rasulullah Shallallahu'alaihiwasallam jika baru datang dari suatu perjalanan, beliau terlebih dahulu mendatangi masjid, shalat dua rekaat, mengucapkan salam dan duduk di tempat shalatnya, lalu datanglah orang-orang dan mengucapkan salam kepada beliau."},"628":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدِمَ مِنْ غَزْوَةِ تَبُوكَ ضُحًى فَصَلَّى فِي الْمَسْجِدِ رَكْعَتَيْنِ وَكَانَ إِذَا جَاءَ مِنْ سَفَرٍ فَعَلَ ذَلِكَ","id":"Telah menceritakan kepada kami [Abdurrazzaq] berkata; telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abdurrahman bin Ka'ab bin Malik] dari [Bapaknya] Nabi Shallallahu'alaihiwasallam datang dari Perang Tabuk pada waktu dhuha lalu beliau shalat di masjid dua rekaat, dan beliau jika datang dari perjalanan melakukan seperti itu (Shalat dua rakaat di masjid sebelum ke rumah)."},"629":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ وَابْنُ بَكْرٍ قَالَا أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ حَدَّثَنِي ابْنُ شِهَابٍ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ حَدَّثَهُ عَنْ أَبِيهِ عَبْدِ اللَّهِ بْنِ كَعْبٍ وَعَنْ عَمِّهِ عُبَيْدِ اللَّهِ بْنِ كَعْبٍ عَنْ كَعْبِ بْنِ مَالِكٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَقْدَمُ مِنْ سَفَرٍ إِلَّا نَهَارًا فِي الضُّحَى فَإِذَا قَدِمَ بَدَأَ بِالْمَسْجِدِ فَصَلَّى فِيهِ رَكْعَتَيْنِ ثُمَّ جَلَسَ فِيهِ وَقَالَ ابْنُ بَكْرٍ فِي حَدِيثِهِ عَنْ أَبِيهِ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ عَمِّهِ","id":"Telah menceritakan kepada kami [Abdurrazzaq] dan [Ibnu Bakr] berkata; telah mengabarkan kepada kami [Ibnu Juraij] berkata; telah menceritakan kepadaku [Ibnu Syihab] [Abdurrahman bin Abdullah bin Ka'ab bin Malik] menceritakannya dari [Bapaknya, Abdullah bin Ka'ab bin Malik] dan dari pamannya ['Ubaidullah bin Ka'ab] dari [Ka'ab bin Malik] berkata; Nabi Shallallahu'alaihiwasallam tidak datang dari perjalanan kecuali pada siang hari, pada waktu dhuha. Jika beliau datang maka menuju masjid lalu shalat dua rekaat dan setelahnya duduk. Ibnu Bakr berkata dalam hadisnya dari Bapaknya, Abdullah bin Ka'ab bin Malik dari pamannya."},"630":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ كَعْبِ بْنِ مَالِكٍ قَالَقَالَتْ أُمُّ مُبَشِّرٍ لِكَعْبِ بْنِ مَالِكٍ وَهُوَ شَاكٍ اقْرَأْ عَلَى ابْنِي السَّلَامَ تَعْنِي مُبَشِّرًا فَقَالَ يَغْفِرُ اللَّهُ لَكِ يَا أُمَّ مُبَشِّرٍ أَوَلَمْ تَسْمَعِي مَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا نَسَمَةُ الْمُسْلِمِ طَيْرٌ تَعْلُقُ فِي شَجَرِ الْجَنَّةِ حَتَّى يُرْجِعَهَا اللَّهُ عَزَّ وَجَلَّ إِلَى جَسَدِهِ يَوْمَ الْقِيَامَةِ قَالَتْ صَدَقْتَ فَأَسْتَغْفِرُ اللَّهَ","id":"Telah menceritakan kepada kami [Abdurrazzaq] berkata; telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abdurrahman bin Ka'ab bin Malik] berkata; [Umu Mubasyir] berkata kepada [Ka'ab bin Malik] sedang dia dalam keadaan sakit, bacakan kepada anakku salam yaitu Mubasyir. Lalu (Ka'ab bin Malik Radliyallhu'anhu) berkata; semoga Allah mengampunimu Wahai Umu Mubasyir, tidakkah kau mendengar apa yang telah disabdakan Rasulullah Shallallahu'alaihiwasallam: \"Roh seorang muslim itu akan terbang lalu bertengger di pohon surga sampai Allah Azzawajalla mengembalikan ke jasadnya pada Hari Kiamat. Dia berkata; kamu benar, saya memohon ampun kepada Allah."},"631":{"ar":"حَدَّثَنَا سَعْدُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنِ ابْنِ شِهَابٍ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ كَعْبٍ أَنَّهُ بَلَغَهُ أَنَّ كَعْبَ بْنَ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَسَمَةُ الْمُؤْمِنِ إِذَا مَاتَ طَائِرٌ يَعْلُقُ بِشَجَرِ الْجَنَّةِ حَتَّى يُرْجِعَهُ اللَّهُ تَبَارَكَ وَتَعَالَى إِلَى جَسَدِهِ يَوْمَ يَبْعَثُهُ اللَّهُ","id":"Telah menceritakan kepada kami [Sa'd bin Ibrahim] telah menceritakan kepada kami [bapakku] dari [Shalih] dari [Ibnu Syihab] berkata; telah menceritakan kepadaku [Abdurrahman bin Abdullah bin Ka'ab bin Malik] sampai berita kepadanya (dari [seseorang]), [Ka'ab bin Malik] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Ruh seorang mukmin jika meninggal, akan terbang dan bergantung di pohon surga sampai Allah Tabaroka Wa Ta'ala mengembalikan kepada jasadnya pada Hari Allah membangkitkannya.\""},"632":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ يَحْيَى بْنِ سَعِيدٍ قَالَ سَمِعْتُ بُشَيْرَ بْنَ يَسَارٍ قَالَ سَمِعْتُ سُوَيْدَ بْنَ النُّعْمَانِ رَجُلًا مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ أَصْحَابِ الشَّجَرَةِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَلَمْ يَكُنْ عِنْدَهُمْ طَعَامٌ قَالَ فَأَتَوْا بِسَوِيقٍ فَلَاكُوا مِنْهُ وَشَرِبُوا مِنْهُ ثُمَّ أَتَوْا بِمَاءٍ فَمَضْمَضُوا ثُمَّ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Yahya bin Sa'id] berkata; saya mendengar [Busyair bin Yasar] berkata; saya mendengar [Suwaid bin An-Nu'man] seseorang yang termasuk dari sahabat Rasulullah Shallallahu'alaihiwasallam, sahabat yang ikut dalam peristiwa Bai'at dibawah pohon' berkata; Rasulullah Shallallahu'alaihiwasallam berada dalam sebuah perjalanan, namun mereka tidak memiliki makanan. Selanjutnya mereka membawa sawiq (makanan yang terbuat dari tepung gandum), mereka kunyah dan minum darinya, lalu mereka membawa air yang mereka jadikan untuk berkumur-kumur, lalu Rasulullah Shallallahu'alaihiwasallam bangun dan shalat."},"633":{"ar":"حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا يَحْيَى عَنْ بُشَيْرِ بْنِ يَسَارٍ عَنْ سُوَيْدِ بْنِ النُّعْمَانِ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ خَيْبَرَ حَتَّى إِذَا كُنَّا بِالصَّهْبَاءِ وَصَلَّى الْعَصْرَ دَعَا بِالْأَطْعِمَةِ فَمَا أُتِيَ إِلَّا بِسَوِيقٍ فَأَكَلُوا وَشَرِبُوا مِنْهُ ثُمَّ قَامَ إِلَى الْمَغْرِبِ فَمَضْمَضَ وَمَضْمَضْنَا مَعَهُ وَمَا مَسَّ مَاءً","id":"Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [Yahya] dari [Busyair bin Yassar] dari [Suwaid bin An-Nu'man] berkata; kami keluar bersama Rasulullah Shallallahu'alaihiwasallam pada tahun terjadinya Khaibar sampai kami di daerah Shahba' dan shalat ashar, beliau meminta makanan, beliau tidak diberi saji-sajian apa-apa kecuali hanya sawiq (makanan yang terbuat dari tepung gandum), lalu mereka menyantap dan meminumnya, lalu berdiri untuk shalat maghrib. Kami berkumur-kumur bersama beliau dan tidak menyentuh air."},"634":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ أَبَا مَالِكٍ الْأَشْجَعِيَّ يُحَدِّثُ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ قَالَ أَخْبَرَنِي مَنْرَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي ثَوْبٍ وَاحِدٍ قَدْ خَالَفَ بَيْنَ طَرَفَيْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] berkata; saya mendengar [Abu Malik Al Asyja'i] menceritakan dari [Abu Salamah bin Abdurrahman] berkata; telah mengabarkan kepadaku [seseorang yang melihat Nabi Shallallahu'alaihiwasallam] shalat dalam satu kain dengan menyelendangkan kedua ujungnya."},"635":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا عَوْفٌ قَالَ حَدَّثَنِي عَلْقَمَةُ الْمُزَنِيُّ قَالَ حَدَّثَنِي رَجُلٌ قَالَكُنْتُ فِي مَجْلِسٍ فِيهِ عُمَرُ بْنُ الْخَطَّابِ بِالْمَدِينَةِ فَقَالَ لِرَجُلٍ مِنْ الْقَوْمِ يَا فُلَانُ كَيْفَ سَمِعْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْعَتُ الْإِسْلَامَ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ الْإِسْلَامَ بَدَأَ جَذَعًا ثُمَّ ثَنِيًّا ثُمَّ رَبَاعِيًا ثُمَّ سَدِيسِيًّا ثُمَّ بَازِلًاقَالَ فَقَالَ عُمَرُ بْنُ الْخَطَّابِ فَمَا بَعْدَ الْبُزُولِ إِلَّا النُّقْصَانُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami ['Auf] berkata; telah menceritakan kepadaku [Al Qamah Al Muzani] berkata; telah menceritakan kepadaku [seseorang], berkata; saya berada pada sebuah majlis yang di dalamnya ada 'Umar bin Khattab di Madinah, dia berkata kepada seorang dari suatu kaum, Wahai Fulan, bagaimana kamu mendengar Rasulullah Shallallahu'alaihiwasallam menggambarkan Islam? Dia menjawab, saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \" Islam datang seperti unta yang berumur enam bulan sampai satu tahun, kemudian seperti unta yang berumur tiga tahun, lalu tujuh tahun, lalu delapan tahun, lalu sembilan tahun.\" Orang itu berkata; 'Umar bin Khattab berkata; bukankah setelah menjadi buzul (unta yang berumur sembilan tahun) akan mengalami kekurangan?."},"636":{"ar":"حَدَّثَنَا سُفْيَانُ قَالَ سَمِعْتُ عَمْرًا سَمِعَ ابْنَ عُمَرَ قَالَكُنَّا نُخَابِرُ وَلَا نَرَى بِذَلِكَ بَأْسًا حَتَّى زَعَمَ رَافِعُ بْنُ خَدِيجٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْهُ فَتَرَكْنَاهُ","id":"Telah menceritakan kepada kami [Sufyan] berkata; saya telah mendengar ['Amr] telah mendengar [Ibnu 'Umar] berkata; kami pernah melakukan mukhabarah dan kami melihatnya tidak ada masalah sehingga [Rafi' bin Khadij] yakin bahwa Rasulullah Shallallahu'alaihiwasallam melarangnya, lalu kami meninggalkannya. "},"637":{"ar":"حَدَّثَنَا الضَّحَّاكُ بْنُ مَخْلَدٍ عَنْ عَبْدِ الْوَاحِدِ بْنِ نَافِعٍ الْكَلَاعِيِّ مِنْ أَهْلِ الْبَصْرَةِ قَالَمَرَرْتُ بِمَسْجِدٍ بِالْمَدِينَةِ فَأُقِيمَتْ الصَّلَاةُ فَإِذَا شَيْخٌ فَلَامَ الْمُؤَذِّنَ وَقَالَ أَمَا عَلِمْتَ أَنَّ أَبِي أَخْبَرَنِي أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَأْمُرُ بِتَأْخِيرِ هَذِهِ الصَّلَاةِقَالَ قُلْتُ مَنْ هَذَا الشَّيْخُ قَالُوا هَذَا عَبْدُ اللَّهِ بْنُ رَافِعِ بْنِ خَدِيجٍ","id":"Telah menceritakan kepada kami [Adl-Dlahak bin Makhlad] dari [Abdul Wahid bin Nafi' Al Kala'i] dari Basrah berkata; saya melewati suatu masjid di Madinah. Shalat selanjutnya ditegakkan, maka ada [orang tua] yang mencela muadzin dan berkata; tidakkah kau tahu [bapakku] telah mengabarkan kepadaku bahwa Rasulullah Shallallahu'alaihiwasallam memerintahkan agar mengakhirkan shalat ini?. (Abdul Wahid bin Nafi' Al Kala'i Radliyallahu'anhu) berkata; saya bertanya, siapakah orang tua itu? Mereka menjawab, dia adalah Abdullah bin Rafi' bin Khadij."},"638":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عَامِرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ سَعِيدِ بْنِ مَسْرُوقٍ عَنْ عَبَايَةَ بْنِ رِفَاعَةَ بْنِ رَافِعِ بْنِ خَدِيجٍ عَنْ جَدِّهِ رَافِعِ بْنِ خَدِيجٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّا لَاقُو الْعَدُوِّ غَدًا وَلَيْسَ مَعَنَا مُدًى قَالَ مَا أَنْهَرَ الدَّمَ وَذُكِرَ عَلَيْهِ اسْمُ اللَّهِ فَكُلْ لَيْسَ السِّنَّ وَالظُّفُرَ وَسَأُحَدِّثُكَ أَمَّا السِّنُّ فَعَظْمٌ وَأَمَّا الظُّفُرُ فَمُدَى الْحَبَشَةِ قَالَ وَأَصَابَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهْبًا فَنَدَّ مِنْهَا بَعِيرٌ فَسَعَوْا لَهُ فَلَمْ يَسْتَطِيعُوا فَرَمَاهُ رَجُلٌ بِسَهْمٍ فَحَبَسَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لِهَذِهِ الْإِبِلِ أَوْ قَالَ لِهَذِهِ النَّعَمِ أَوَابِدَ كَأَوَابِدِ الْوَحْشِ فَمَا غَلَبَكُمْ فَاصْنَعُوا بِهِ هَكَذَا","id":"Telah menceritakan kepada kami [Sa'id bin 'Amir] berkata; telah menceritakan kepada kami [Syu'bah] dari [Sa'id bin Masruq] dari ['Abayah bin Rifa'ah bin Rafi' bin Khadij] dari [kakeknya Rafi' bin Khadij] berkata; \"Wahai Rasulullah, kita bertemu dengan musuh pada esok hari dan kita tidak memiliki pisau (untuk menyembelih) \" Rasulullah bersabda: \"Darah yang mengalir dan disebut nama Allah, makanlah selain bagian gigi dan kuku, saya beritahukan kepada kalian, gigi termasuk dari tulang. Sedang kuku termasuk pisau orang Habasyah\". (Rafi' Radliyallahu'anhu) berkata; Rasulullah pernah mendapatkan rampasan perang, yang salah satunya adalah unta yang kabur, mereka berusaha menangkapnya tapi tidak ada yang berhasil, lalu ada seorang laki-laki yang melemparnya dengan panah dan berhasil menangkapnya. Rasulullah Shallallahu'alaihiwasallam bersabda: \" dalam unta ini atau hewan ternak ini terdapat suatu rampasan yang buas, jika kalian mendapatkannya lakukan seperti ini.\""},"639":{"ar":"حَدَّثَنَا يَعْقُوبُ قَالَ حَدَّثَنَا أَبِي عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ عَمْرِو بْنِ عَطَاءٍ أَنَّ رَجُلًا مِنْ بَنِي حَارِثَةَ حَدَّثَهُ أ��نَّ رَافِعَ بْنَ خَدِيجٍ حَدَّثَهُمْأَنَّهُمْ خَرَجُوا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ قَالَ فَلَمَّا نَزَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْغَدَاءِ قَالَ عَلَّقَ كُلُّ رَجُلٍ بِخِطَامِ نَاقَتِهِ ثُمَّ أَرْسَلَهَا تَهُزُّ فِي الشَّجَرِ قَالَ ثُمَّ جَلَسْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَرِحَالُنَا عَلَى أَبَاعِرِنَا قَالَ فَرَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأْسَهُ فَرَأَى أَكْسِيَةً لَنَا فِيهَا خُيُوطٌ مِنْ عِهْنٍ أَحْمَرَ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا أَرَى هَذِهِ الْحُمْرَةَ قَدْ عَلَتْكُمْ قَالَ فَقُمْنَا سِرَاعًا لِقَوْلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى نَفَرَ بَعْضُ إِبِلِنَا فَأَخَذْنَا الْأَكْسِيَةَ فَنَزَعْنَاهَا مِنْهَا","id":"Telah menceritakan kepada kami [Ya'qub] berkata; telah menceritakan kepada kami [bapakku] dari [Muhammad bin Ishaq] berkata; telah menceritakan kepadaku [Muhammad bin 'Amr bin 'Atho'] [ada seorang laki-laki] dari Bani Haritsah menceritakannya, [Rafi' bin Khadij] menceritakannya, mereka bepergian bersama Rasulullah dalam sebuah perjalanan. Tatkala Rasululllah berhenti berhenti untuk makan siang, para sahabat menggantungkan tali kekang unta mereka pada sebuah pohon dan membiarkannya bergerak-gerak, kemudian kami duduk bersama Rasulullah. (Rafi' bin Khadij Radliyallahu'anhu) berkata; perbekalan kami diatas unta, lalu Rasulullah mengangkat kepalanya dan melihat kain-kain kami yang terdapat pintalan dari bahan yang berwarna merah. Rasulullah bersabda: \"Kenapa saya banyak melihat warna merah diantara kalian?\" (Rafi' bin Khadij Radliyallahu'anhu) berkata; kami bergegas berdiri karena sabda Rasulullah Shallallahu'alaihiwasallam tersebut, yang menyebabkan sebagian unta kami kabur. Kami mengambil pakaian itu dan kami lepaskan unta-unta itu dengan terikat pakaian."},"640":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ حَنْظَلَةَ الزُّرَقِيِّ عَنْ رَافِعِ بْنِ خَدِيجٍأَنَّ النَّاسَ كَانُوا يُكْرُونَ الْمَزَارِعَ فِي زَمَانِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْمَاذِيَانَاتِ وَمَا سَقَى الرَّبِيعُ وَشَيْئًا مِنْ التِّبْنِ فَكَرِهَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كِرَاءَ الْمَزَارِعِ بِهَذَا وَنَهَى عَنْهَاو قَالَ رَافِعٌ لَا بَأْسَ بِكِرَائِهَا بِالدَّرَاهِمِ وَالدَّنَانِيرِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata; telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Rabi'ah bin Abu Abdurrahman] dari [Handlalah Az Zuroqi] dari [Rafi' bin Khadij] orang-orang menyewakan ladang pada masa Rasulullah Shallallahu'alaihiwasallam dengan pembayaran sesayuran yang tumbuh di anak-anak sungai, segala yang tumbuh akibat siraman kanal dan batu bata. Kemudian hari Rasulullah Shallallahu'alaihiwasallam membenci mukhabarah tanah dan melarangnya. Rafi' berkata; tidak apa menyewanya dengan dirham dan dinar."},"641":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا أَبُو الْأَحْوَصِ قَالَ حَدَّثَنَا سَعِيدُ بْنُ مَسْرُوقٍ عَنْ عَبَايَةَ بْنِ رِفَاعَةَ عَنْ جَدِّهِ رَافِعِ بْنِ خَدِيجٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ الْحُمَّى فَوْرُ جَهَنَّمَ فَابْرُدُوهَا بِالْمَاءِ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Abu Al Ahwash] berkata; telah menceritakan kepada kami [Sa'id bin Masruq] dari ['Abayah bin Rifa'ah] dari kakeknya, [Rafi' bin Khadij] berkata; saya mendengar Rasulullah bersabda: \" penyakit demam adalah bagian dari hembusan api neraka Jahanam, maka dinginkanlah dengan air\"."},"642":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا أَبَانُ قَالَ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ إِبْرَاهِيمَ بْنِ قَارِظٍ عَنْ السَّائِبِ بْنِ يَزِيدَ عَنْ رَافِعِ بْنِ خَدِيجٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَسْبُ الْحَجَّامِ خَبِيثٌ وَمَهْرُ الْبَغِيِّ خَبِيثٌ وَثَمَنُ الْكَلْبِ خَبِيثٌ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Aban] berkata; telah menceritakan kepada kami [Yahya bin Abu Katsir] dari [Ibrahim bin Qarizh] dari [As-Sa'ib bin Yazid] dari [Rafi' bin Khadij] Rasulullah Shallallahu'alaihiwasallambersabda: \"Upah orang yang membekam adalah keji, penghasilan pezina adalah keji dan keuntungan dari juAl beli anjing juga keji\""},"643":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ سَعِيدِ بْنِ مَسْرُوقٍ عَنْ عَبَايَةَ بْنِ رِفَاعَةَ بْنِ رَافِعٍ عَنْ رَافِعِ بْنِ خَدِيجٍ جَدِّهِأَنَّهُ قَالَ يَا رَسُولَ اللَّهِ إِنَّا لَاقُو الْعَدُوِّ غَدًا وَلَيْسَ مَعَنَا مُدًى قَالَ مَا أَنْهَرَ الدَّمَ وَذُكِرَ اسْمُ اللَّهِ عَلَيْهِ فَكُلْ لَيْسَ السِّنَّ وَالظُّفُرَ وَسَأُحَدِّثُكَ أَمَّا السِّنُّ فَعَظْمٌ وَأَمَّا الظُّفُرُ فَمُدَى الْحَبَشَةِ","id":"Telah menceritakan kepada kami ['Affan] berkata; telah menceritakan kepada kami [Syu'bah] dari [Sa'id bin Masruq] dari ['Abayah bin Rifa'ah bin Rafi'] dari [Rafi' bin Khadij] yaitu kakeknya bahwa dia berkata; Wahai Rasulullah, kita besok akan bertemu musuh dan kita tidak mempunyai bekal walau satu mud. Beliau bersabda: \"Makanlah yang telah disembelih dan disebut nama Allah selain tulang dan kukunya. Saya beritahukan sesuatu, yang dimaksudkan dengan 'assin' adalah tulang dan 'adldlufru' adalah pisau Habasyah.\""},"644":{"ar":"وَأَصَابَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهْبًا فَنَدَّ بَعِيرٌ مِنْهَا فَسَعَوْا فَلَمْ يَسْتَطِيعُوهُ فَرَمَاهُ رَجُلٌ مِنْ الْقَوْمِ بِسَهْمٍ فَحَبَسَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لِهَذِهِ الْإِبِلِ أَوْ النَّعَمِ أَوَابِدَ كَأَوَابِدِ الْوَحْشِ فَإِذَا غَلَبَكُمْ شَيْءٌ مِنْهَا فَاصْنَعُوا بِهِ هَكَذَا","id":"Masih melalui jalur periwayatan yang sama seperti hadits sebelumnya, dari [Rafi' bin Khudaij]; Rasulullah Shallallahu'alaihiwasallam mendapatkan rampasan namun untanya lari, mereka mengejarnya namun mereka tidak mampu. Ada seseorang yang melemparnya dengan anak panah dan mengenainya. Rasulullah Shallallahu'alaihiwasallam bersabda: \" unta ini\", atau \"hewan ternak ini mempunyai sifat-sifat liar sebagaimana binatang buas. Jika kalian menjumpai hal seperti itu maka perlakukankanlah demikian\"."},"645":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ قَالَسَرَقَ غُلَامٌ لِنُعْمَانَ الْأَنْصَارِيِّ نَخْلًا صِغَارًا فَرُفِعَ إِلَى مَرْوَانَ فَأَرَادَ أَنْ يَقْطَعَهُ فَقَالَ رَافِعُ بْنُ خَدِيجٍ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُقْطَعُ فِي الثَّمَرِ وَلَا فِي الْكَثَرِقَالَ قُلْتُ لِيَحْيَى مَا الْكَثَرُ قَالَ الْجُمَّارُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Yahya bin Sa'id] dari [Muhammad bin Yahya bin Habban] berkata; budak laki-laki milik Nu'man Al Anshari mencuri sebuah pohon kurma kecil. Kasus itu dilaporkan kepada Marwan, dia hendak memotong (tangan) nya. [Rafi' bin Khadij] mengajukan protes dengan berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidak ada potong tangan dalam pencurian buah dan juga tidak pula pada mayang kurma\". (Rafi' bin Khadij radliyallahu'anhu) berkata; saya bertanya kepada Yahya, apakah Al katsar? Dia menjawab, yaitu bagian atas pada pohon kurma."},"646":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ بُشَيْرِ بْنِ يَسَارٍ عَنْ أَبِي بُرْدَةَ بْنِ نِيَارٍأَنَّهُ ذَبَحَ قَبْلَ أَنْ يَذْبَحَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَهُ أَنْ يُعِيدَ قَالَ إِنِّي لَا أَجِدُ إِلَّا جَذَعَةً فَأَمَرَهُ أَنْ يَذْبَحَ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Yahya bin Sa'id] dari [Busyair bin Yasar] dari [Abu Burdah bin Niyar] dia menyembelih sebelum Nabi Shallallahu'alaihiwasallam menyembelih, maka beliau menyuruhnya mengulanginya. Dia berkata; \"Saya tidak mendapatkannya lagi selain jadza'ah (unta yang berumur antara enam bulan sampai satu tahun) \" lalu (Rasulullah Shallallahu'alaihiwasallam) menyuruhnya agar menyembelihnya."},"647":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْوَلِيدُ بْنُ عَبْدِ اللَّهِ بْنِ جُمَيْعٍ عَنِ الْجَهْمِ بْنِ أَبِي الْجَهْمِ عَنِ ابْنِ نِيَارٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَذْهَبُ الدُّنْيَا حَتَّى تَكُونَ لِلُكَعِ ابْنِ لُكَعٍ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Al Walid bin Abdullah bin Jumai'] dari [Al Jahm bin Abu Al Jahm] dari [Ibnu Niyar] berkata; saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Dunia tidak akan lenyap kecuali setelah muncul orang yang tercela, bodoh, lagi tak berilmu\""},"648":{"ar":"حَدَّثَنَا هَاشِمٌ وَحَجَّاجٌ قَالَا حَدَّثَنَا لَيْثٌ يَعْنِي ابْنَ سَعْدٍ قَالَ حَدَّثَنَا يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جَابِرِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي بُرْدَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يُجْلَدُ فَوْقَ عَشْرِ جَلَدَاتٍ إِلَّا فِي حَدٍّ مِنْ حُدُودِ اللَّهِ تَعَالَى","id":"Telah menceritakan kepada kami [Hasyim] dan [Hajjaj] berkata; telah menceritakan kepada kami [Laits] yaitu Ibnu Sa'd berkata; telah menceritakan kepada kami [Yazid bin Abu Habib] dari [Bukair bin Abdullah bin Al Assyaj] dari [Sulaiman bin Yasar] dari [Abdurrahman bin Jabir bin Abdullah] dari [Abu Burdah] Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidak diperkenankan seseorang dicambuk lebih dari sepuluh kali kecuali pada hukuman syara' dari Allah Ta'ala\"."},"649":{"ar":"حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا شَرِيكٌ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ جُمَيْعِ بْنِ عُمَيْرٍ وَلَمْ يَشُكَّ عَنْ خَالِهِ أَبِي بُرْدَةَ بْنِ نِيَارٍ قَالَانْطَلَقْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى نَقِيعِ الْمُصَلَّى فَأَدْخَلَ يَدَهُ فِي طَعَامٍ ثُمَّ أَخْرَجَهَا فَإِذَا هُوَ مَغْشُوشٌ أَوْ مُخْتَلِفٌ فَقَالَ لَيْسَ مِنَّا مَنْ غَشَّنَا","id":"Telah menceritakan kepada kami [Hajjaj] telah menceritakan kepada kami [Syarik] dari [Abdullah bin 'Isa] dari [Jumai' bin 'Umair] dan tidak ragu dari [pamannya, Abu Burdah bin Niyar] berkata; saya berangkat bersama Nabi Shallallahu'alaihiwasallam ke suatu pasar, lalu beliau memasukkan tangannya ke dalam makanan dan mengeluarkannya. Ternyata makanan tersebut yang baik hanya di bagian luar atau permukaan (tidak sesuai antara sifat makanan yang tampak diatas dengan yang dibawah) lalu beliau berkomentar, \"Bukan termasuk dari golongan kita orang yang menipu.\""},"650":{"ar":"حَدَّثَنَا يَحْيَى بْنُ إِسْحَاقَ قَالَ أَخْبَرَنَا ابْنُ لَهِيعَةَ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ قَالَ قَالَ سُلَيْمَانُ لِعَبْدِ الرَّحْمَنِ بْنِ جَابِرٍ حَدِّثْ فَحَدَّثَ عَنْ أَبِي بُرْدَةَ بْنِ نِيَارٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا جَلْدَ فَوْقَ عَشْرِ جَلَدَاتٍ إِلَّا فِي حَدٍّ مِنْ حُدُودِ اللَّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Yahya bin Ishaq] berkata; telah mengabarkan kepada kami [Ibnu Lahi'ah] dari [Bukair bin Abdullah] berkata; [Sulaiman] berkata kepada [Abdurrahman bin Jabir] ceritakan! Lalu dia menceritakan dari [Abu Burdah bin Niyar] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidak ada hukuman cambuk lebih dari sepuluh kali kecuali pada hukuman syara' dari Allah Azzawajalla\"."},"651":{"ar":"حَدَّثَنَا أَبُو سَلَمَةَ الْخُزَاعِيُّ حَدَّثَنَا لَيْثٌ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جَابِرٍ عَنْ أَبِي بُرْدَةَ بْنِ نِيَارٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يُجْلَدُ فَوْقَ عَشْرِ جَلَدَاتٍ إِلَّا فِي حَدٍّ مِنْ حُدُودِ اللَّهِ عَزّ�� وَجَلَّوَكَانَ لَيْثٌ حَدَّثَنَاهُ بِبَغْدَادَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ بُكَيْرٍ عَنْ سُلَيْمَانَ فَلَمَّا كُنَّا بِمِصْرَ أَخْبَرَنَا بُكَيْرُ بْنُ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ","id":"Telah menceritakan kepada kami [Abu Salamah Al Khuza'i] telah menceritakan kepada kami [Laits] dari [Bukair bin Abdullah bin Al Asyaj] dari [Sulaiman bin Yasar] dari [Abdurrahman bin Jabir] dari [Abu Burdah bin Niyar] berkata; saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidak boleh seseorang dicambuk lebih dari sepuluh kali kecuali pada hukuman syara' dari Allah Azzawajalla\". [Laits] menceritakannya di Baghdad, dari [Yazid bin Habib] dari [Bukair] dari [Sulaiman] tatkala kami di Mesir, telah mengabarkan kepada kami Bukair bin Abdullah bin Al Asyaj"},"652":{"ar":"حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ قَالَ حَدَّثَنَا شَرِيكٌ عَنْ وَائِلٍ عَنْ جُمَيْعِ بْنِ عُمَيْرٍ عَنْ خَالِهِ قَالَسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَفْضَلِ الْكَسْبِ فَقَالَ بَيْعٌ مَبْرُورٌ وَعَمَلُ الرَّجُلِ بِيَدِهِ","id":"Telah menceritakan kepada kami [Aswad bin 'Amir] berkata; telah menceritakan kepada kami [Syarik] dari [Wa'il] dari [Jumai' bin 'Umair] dari [pamannya] Nabi Shallallahu'alaihiwasallam ditanya tentang penghasilan yang paling utama. Beliau bersabda: \"Sebaik-baik penghasilan adalah juAl beli yang sah, tidak terdapat unsur penipuan dan usaha seseorang dengan tangannya.\""},"653":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا الْوَلِيدُ يَعْنِي ابْنَ عَبْدِ اللَّهِ بْنِ جُمَيْعٍ قَالَ حَدَّثَنِي أَبُو بَكْرِ بْنُ أَبِي الْجَهْمِ قَالَأَقْبَلْتُ أَنَا وَزَيْدُ بْنُ حَسَنٍ بَيْنَنَا ابْنُ رُمَّانَةَ مَوْلَى عَبْدِ الْعَزِيزِ بْنِ مَرْوَانَ قَدْ نَصَبْنَا لَهُ أَيْدِيَنَا فَهُوَ مُتَّكِئٌ عَلَيْهَا دَاخِلَ الْمَسْجِدِ مَسْجِدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَهَى ابْنَ نِيَارٍ رَجُلٌ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَرْسَلَ إِلَى أَبِي بَكْرٍ ائْتِنِي فَأَتَاهُ فَقَالَ رَأَيْتُ ابْنَ رُمَّانَةَ بَيْنَكُمَا يَتَوَكَّأُ عَلَيْكَ وَعَلَى زَيْدِ بْنِ حَسَنٍ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَنْ تَذْهَبَ الدُّنْيَا حَتَّى تَكُونَ عِنْدَ لُكَعِ ابْنِ لُكَعٍ","id":"Telah menceritakan kepada kami [Abu Nua'im] telah menceritakan kepada kami [Al Walid] yaitu Ibnu Abdullah bin Jumai', berkata; telah menceritakan kepadaku [Abu Bakar bin Abu Al Jahm] berkata; saya menemui Ibnu Rumanah mantan budak Abdul Aziz bin Marwan sedang Zaid bin Hasan ada diantara kami, kami menegakkan tangan kami, selanjutnya (Ibnu Rumanah) sedang bersandar pada tangan kami dalam masjid, yaitu masjid Rasulullah Shallallahu'alaihiwasallam. Lantas ada seseorang dari kalangan sahabat yang bernama [Ibnu Niyar] melarang, lalu dia mengutus seseorang kepada Abu Bakar dengan mengatakan 'Datangilah aku.' Abu Bakar pun mendatangi Ibnu Niyar, lalu Ibnu Niyar berkata 'Saya melihat Ibnu Rumanah ada di antara kalian berdua, bersandar padamu dan pada Zaid bin Hasan, padahal saya telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Dunia tidak akan sirna kecuali setelah berada pada orang yang tercela, bodoh lagi tak berilmu\"."},"654":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ الْبُرْسَانِيُّ قَالَ أَخْبَرَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ قَالَ أَخْبَرَنَا أَبِي عَنْ زِيَادِ بْنِ مِينَاءَ عَنْ أَبِي سَعْدِ بْنِ أَبِي فَضَالَةَ الْأَنْصَارِيِّ وَكَانَ مِنْ الصَّحَابَةِ أَنَّهُ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا جَمَعَ اللَّهُ عَزَّ وَجَلَّ الْأَوَّلِينَ وَالْآخِرِينَ لِيَوْمٍ لَا رَيْبَ فِيهِ نَادَى مُنَادٍ مَنْ كَانَ أَشْرَكَ فِي عَمَلٍ عَمِلَهُ لِلَّهِ تَبَارَكَ وَتَعَالَى أَحَدًا فَلْيَطْلُبْ ثَوَابَهُ مِنْ عِنْدِ غَيْرِ اللَّهِ عَزَّ وَجَلَّ فَإِنَّ اللَّهَ عَزَّ وَجَلَّ أَغْنَى الشُّرَكَاءِ عَنْ الشِّرْكِ","id":"Telah menceritakan kepada kami [Muhammad bin Bakr Al Bursani] berkata; telah mengabarkan kepada kami [Abdul Hamid bin Ja'far] berkata; telah mengabarkan kepada kami [bapakku] dari [Ziyad bin Mina'] dari [Abu Saad bin Abu Fadlalah Al Anshari, salah seorang sahabat] dia berkata; saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jika Allah menghimpun manusia dari generasi pertama dan generasi terakhir pada hari yang tidak diragukan lagi, ada seorang penyeru yang menyerukan, 'Barangsiapa menyekutukan Allah dengan seseorang dalam suatu amalan yang seharusnya dia kerjakan untuk Allah Tabaraka Wa Ta'ala, mintalah balasannya kepada selain Allah Azzawajalla. Sebab Allah adalah Dzat yang paling tidak membutuhkan tandingan.\""},"655":{"ar":"حَدَّثَنِي أَبِي عَنْ يَعْقُوبَ بْنِ إِبْرَاهِيمَ الزُّهْرِيِّ قَالَ سَمِعْتُ أَبِي يُحَدِّثُ عَنْ يَزِيدَ يَعْنِي ابْنَ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ بْنِ الْحَارِثِ عَنْ سُهَيْلِ ابْنِ بَيْضَاءَ أَنَّهُ قَالَنَادَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ وَأَنَا رَدِيفُهُ يَا سُهَيْلُ ابْنَ بَيْضَاءَ رَافِعًا بِهَا صَوْتَهُ مِرَارًا حَتَّى سَمِعَ مَنْ خَلْفَنَا وَأَمَامَنَا فَاجْتَمَعُوا وَعَلِمُوا أَنَّهُ يُرِيدُ أَنْ يَتَكَلَّمَ بِشَيْءٍ إِنَّهُ مَنْ قَالَ لَا إِلَهَ إِلَّا اللَّهُ أَوْجَبَ اللَّهُ عَزَّ وَجَلَّ لَهُ بِهَا الْجَنَّةَ وَأَعْتَقَهُ بِهَا مِنْ النَّارِحَدَّثَنَا هَارُونُ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ حَيْوَةُ حَدَّثَنِي يَزِيدُ بْنُ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ سَعِيدِ بْنِ الصَّلْتِ عَنْ سُهَيْلِ ابْنِ الْبَيْضَاءِ مِنْ بَنِي عَبْدِ الدَّارِ قَالَ بَيْنَمَا نَحْنُ فِي سَفَرٍ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ مَعْنَاهُ","id":"Telah menceritakan kepada kami bapakku dari [Ya'qub bin Ibrahim Az Zuhri] berkata; saya telah mendengar [bapakku] menceritakan dari [Yazid] yaitu Ibnu Al Had, dari [Muhammad bin Ibrahim bin Al Harits] dari [Suhail bin Baidla'] dia berkata; suatu malam Rasulullah Shallallahu'alaihiwasallam memanggil sedang saya membonceng beliau, Wahai Suhail bin Baidla'!, beliau mengangkat suaranya beberapa kali, sampai orang yang berada di belakang dan depan kami mendengarnya. Mereka berkumpul dan mereka mengetahui bahwa beliau hendak mengatakan, 'Barangsiapa bersaksi bahwa tidak ada tuhan kecuali Allah, Allah Azzawajalla mewajibkan surga baginya dan menyelamatkannya dari neraka. Telah menceritakan kepada kami [Harun] telah menceritakan kepada kami [Ibnu Wahb] [Haiwah] berkata; telah menceritakan kepadaku [Yazid bin Al Had] dari [Muhammad bin Ibrahim] dari [Sa'id Al Shalt] dari [Suhail bin Baidla'] dari Bani Abdu Dar, berkata; tatkala kami dalam sebuah perjalanan bersama Rasulullah Shallallahu'alaihiwasallam, lalu menyebutkan secara makna."},"656":{"ar":"حَدَّثَنَا يَعْقُوبُ قَالَ حَدَّثَنِي أَبِي عَنْ ابْنِ إِسْحَاقَ قَالَ حَدَّثَنِي صَالِحُ بْنُ إِبْرَاهِيمَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنْ مَحْمُودِ بْنِ لَبِيدٍ أَخِي بَنِي عَبْدِ الْأَشْهَلِ عَنْ سَلَمَةَ بْنِ سَلَامَةَ بْنِ وَقْشٍ وَكَانَ مِنْ أَصْحَابِ بَدْرٍ قَالَكَانَ لَنَا جَارٌ مِنْ يَهُودَ فِي بَنِي عَبْدِ الْأَشْهَلِ قَالَ فَخَرَجَ عَلَيْنَا يَوْمًا مِنْ بَيْتِهِ قَبْلَ مَبْعَثِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَسِيرٍ فَوَقَفَ عَلَى مَجْلِسِ عَبْدِ الْأَشْهَلِ قَالَ سَلَمَةُ وَأَنَا يَوْمَئِذٍ أَحْدَثُ مَنْ فِيهِ سِنًّا عَلَيَّ بُرْدَةٌ مُضْطَجِعًا فِيهَا بِفِنَاءِ أَهْلِي فَذَكَرَ الْبَعْثَ وَالْقِيَامَةَ وَالْحِسَابَ وَالْمِيزَانَ وَالْجَنَّةَ وَالنَّارَ فَقَالَ ذَلِكَ لِقَوْمٍ أَهْلِ شِرْكٍ أَصْحَابِ أَوْثَانٍ لَا يَرَوْنَ أَنَّ ��َعْثًا كَائِنٌ بَعْدَ الْمَوْتِ فَقَالُوا لَهُ وَيْحَكَ يَا فُلَانُ تَرَى هَذَا كَائِنًا إِنَّ النَّاسَ يُبْعَثُونَ بَعْدَ مَوْتِهِمْ إِلَى دَارٍ فِيهَا جَنَّةٌ وَنَارٌ يُجْزَوْنَ فِيهَا بِأَعْمَالِهِمْ قَالَ نَعَمْ وَالَّذِي يُحْلَفُ بِهِ لَوَدَّ أَنَّ لَهُ بِحَظِّهِ مِنْ تِلْكَ النَّارِ أَعْظَمَ تَنُّورٍ فِي الدُّنْيَا يُحَمُّونَهُ ثُمَّ يُدْخِلُونَهُ إِيَّاهُ فَيُطْبَقُ بِهِ عَلَيْهِ وَأَنْ يَنْجُوَ مِنْ تِلْكَ النَّارِ غَدًا قَالُوا لَهُ وَيْحَكَ وَمَا آيَةُ ذَلِكَ قَالَ نَبِيٌّ يُبْعَثُ مِنْ نَحْوِ هَذِهِ الْبِلَادِ وَأَشَارَ بِيَدِهِ نَحْوَ مَكَّةَ وَالْيَمَنِ قَالُوا وَمَتَى تَرَاهُ قَالَ فَنَظَرَ إِلَيَّ وَأَنَا مِنْ أَحْدَثِهِمْ سِنًّا فَقَالَ إِنْ يَسْتَنْفِدْ هَذَا الْغُلَامُ عُمُرَهُ يُدْرِكْهُ قَالَ سَلَمَةُ فَوَاللَّهِ مَا ذَهَبَ اللَّيْلُ وَالنَّهَارُ حَتَّى بَعَثَ اللَّهُ تَعَالَى رَسُولَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ حَيٌّ بَيْنَ أَظْهُرِنَا فَآمَنَّا بِهِ وَكَفَرَ بِهِ بَغْيًا وَحَسَدًا فَقُلْنَا وَيْلَكَ يَا فُلَانُ أَلَسْتَ بِالَّذِي قُلْتَ لَنَا فِيهِ مَا قُلْتَ قَالَ بَلَى وَلَيْسَ بِهِ","id":"Telah menceritakan kepada kami [Ya'qub] berkata; telah menceritakan kepadaku [bapakku] dari [Ibnu Ishaq] berkata; telah menceritakan kepadaku [Shalih bin Ibrahim bin Abdurrahman bin 'Auf] dari [Mahmud bin Labid, dari bani Abdul Ashal] dari [Salamah bin Salamah bin Waqsy] salah seorang yang mengikuti Perang Badar, dia berkata; Kami mempunyai seorang tetangga Yahudi dari Bani Abdul Asyhal. (Salamah bin Salamah bin Waqsy Radliyallahu'anhu) berkata; pada suatu saat dia keluar dari rumahnya menjelang diutusnya Nabi Shallallahu'alaihiwasallam, dia ikut dalam sebuah majlis Bani Abdul Asyhal. Pada hari itu saya dalam majlis yang termuda umurnya, saya memakai selendang dengan bersandar di halaman rumahku, (orang yahudi tersebut) menjelaskan tentang Hari Kebangkitan, Hari Kiamat, Hari Perhitungan, Timbangan, surga dan neraka, lalu berkata 'Siksaan itu adalah untuk kaum musyrikin, yang menyembah berhala yang berpendapat bahwa tidak ada hari kebangkitan setelah kematian. Mereka berkata kepadanya, \"Celakalah kamu wahai fulan, kamu menganggap manusia akan dibangkitkan setelah kematian, untuk menuju suatu tempat yang bernama surga dan neraka, mereka diberi balasan sesuai dengan amalan yang telah mereka kerjakan? Maka (orang Yahudi tersebut) berkata; \"Benar, demi Zat yang dengan-Nya dijadikan bersumpah, sungguh seseorang menginginkan jika bagiannya dari neraka, menjadi tungku terbesar di dunia, lantas orang-orang memanggangnya dan memasukkannya dalam neraka itu, dan orang itu ditutup di neraka itu. Mereka berkata kepadanya, \"Huss kamu, apa tanda-tanda dari semua itu\"? Maka dia berkata; \"Seorang nabi yang diutus dari negeri ini\", maka dia menunjuk dengan telunjuknya ke arah Makah dan Yaman. Mereka bertanya, kapan kamu melihatnya? (Salamah Radliyallahu'anhu) berkata; orang Yahudi itu melihat kepadanya, saya adalah yang paling muda umurnya, \"Jika anak ini telah mencapai dewasa, maka dia akan mengetahuinya\". Salamah berkata; \"Demi Allah, tidaklah berganti siang dan malam kecuali Allah Ta'ala mengutus seorang rasul-Nya Shallallahu'alaihiwasallam dan beliau hidup di antara kita dan kami beriman kepadanya, adapun (Yahudi tersebut) mengafiri (Rasulullah Shallallahu'alaihiwasallam) dengan penuh kebencian dan hasad. Kami berkata; \"Celakalah engkau wahai fulan, bukankah engkau yang telah menerangkan kepada kami urusan ini\"? (orang Yahudi tersebut) berkata; \"Benar, tetapi yang dimaksud bukanlah dia\"."},"657":{"ar":"حَدَّثَنَا ابْنُ نُمَيْرٍ قَالَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ يَعْنِي ابْنَ مُهَاجِرٍ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ عَمْرِو بْنِ حُرَيْثٍ قَالَ حَدَّثَنِي أَخِي سَعِيدُ بْنُ حُرَيْثٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ بَاعَ عَقَارًا كَانَ قَمِنًا أَنْ لَا يُبَارَكَ لَهُ إِلَّا أَنْ يَجْعَلَهُ فِي مِثْلِهِ أَوْ غَيْرِهِ","id":"Telah menceritakan kepada kami [Ibnu Numair] berkata; telah menceritakan kepada kami [Isma'il bin Ibrahim] yaitu Ibnu Muhajir, dari [Abdul Malik bin 'Umair] dari ['Amr bin Huraits] berkata; telah menceritakan kepadaku [saudaraku, Sa'id bin Huraits] berkata; saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa menjual tanah maka dia tidak pantas untuk mendapat berkah kecuali dia menjadikannya semisal atau dengan lainnya\"."},"658":{"ar":"حَدَّثَنَا يَحْيَى بْنُ إِسْحَاقَ مِنْ كِتَابِهِ قَالَ أَخْبَرَنَا ابْنُ لَهِيعَةَ عَنْ عَبْدِ اللَّهِ بْنِ هُبَيْرَةَ عَنْ حَسَّانَ بْنِ كُرَيْبٍأَنَّ غُلَامًا مِنْهُمْ تُوُفِّيَ فَوَجَدَ عَلَيْهِ أَبَوَاهُ أَشَدَّ الْوَجْدِ فَقَالَ حَوْشَبٌ صَاحِبُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا أُخْبِرُكُمْ بِمَا سَمِعْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي مِثْلِ ابْنِكَ إِنَّ رَجُلًا مِنْ أَصْحَابِهِ كَانَ لَهُ ابْنٌ قَدْ أَدَبَّ أَوْ دَبَّ وَكَانَ يَأْتِي مَعَ أَبِيهِ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ إِنَّ ابْنَهُ تُوُفِّيَ فَوَجَدَ عَلَيْهِ أَبُوهُ قَرِيبًا مِنْ سِتَّةِ أَيَّامٍ لَا يَأْتِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا أَرَى فُلَانًا قَالُوا يَا رَسُولَ اللَّهِ إِنَّ ابْنَهُ تُوُفِّيَ فَوَجَدَ عَلَيْهِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا فُلَانُ أَتُحِبُّ لَوْ أَنَّ ابْنَكَ عِنْدَكَ الْآنَ كَأَنْشَطِ الصِّبْيَانِ نَشَاطًا أَتُحِبُّ أَنَّ ابْنَكَ عِنْدَكَ أَحَرُّ الْغِلْمَانِ جَرَاءَةً أَتُحِبُّ أَنَّ ابْنَكَ عِنْدَكَ كَهْلًا كَأَفْضَلِ الْكُهُولِ أَوْ يُقَالُ لَكَ ادْخُلْ الْجَنَّةَ ثَوَابَ مَا أُخِذَ مِنْكَ","id":"Telah menceritakan kepada kami [Yahya bin Ishaq] dari tulisannya, berkata; telah mengabarkan kepada kami [Ibnu Lahi'ah] dari [Abdullah bin Hubairah] dari [Hassan bin Kuraib] ada seorang pemuda dari mereka yang meninggal, kedua orang tuanya pun sangat sedih. [Hausyab], seorang sahabat Nabi Shallallahu'alaihiwasallam berkata; \"Maukah kuberitahukan kepada kalian sesuatu yang saya dengar dari Rasulullah Shallallahu'alaihiwasallam tentang kasus seperti yang menimpa anakmu?.\" ada seorang laki-laki dari sahabatnya mempunyai seorang anak yang baru bisa merangkak, dia datang bersama bapaknya kepada Nabi Shallallahu'alaihiwasallam. Kemudian hari anaknya meninggal, hingga bapaknya bersedih atas meninggalnya anaknya sampai sekitar enam hari dia tidak menemui Nabi Shallallahu'alaihiwasallam. Nabi Shallallahu'alaihiwasallam bersabda: \"Mengapa saya tidak melihat si Fulan?\" Mereka menjawab, \"Wahai Rasulullah, sungguh anaknya meninggal, dan dia sangat bersedih karenanya\". Rasulullah Shallallahu'alaihiwasallam bersabda kepadanya, \"Wahai fulan, tidaklah engkau senang jikalau anakmu sekarang sedang bermain bebas sebagaimana anak kecil lainnya, apakah engkau tidak senang jikalau anakmu menjadi anak yang bebas dan berani, dan apakah engkau tidak senang bahwa anakmu menjadi orang dewasa dan utama, atau dikatakan kepada kamu \"Masuklah surga sebagai balasan atas sesuatu yang diambil darimu?? "},"659":{"ar":"حَدَّثَنَا يَعْقُوبُ قَالَ قَالَ أَبِي كَمَا حَدَّثَنِي ابْنُ إِسْحَاقَ عَنْ يَعْقُوبَ بْنِ عُتْبَةَ عَنْ مُسْلِمِ بْنِ عَبْدِ اللَّهِ بْنِ جُنْدُبٍ الْجُهَنِيِّ عَنْ جُنْدُبِ بْنِ مَكِيثٍ الْجُهَنِيِّ قَالَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَالِبَ بْنَ عَبْدِ اللَّهِ الْكَلْبِيَّ كَلْبَ لَيْثٍ إِلَى بَنِي مُلَوَّحٍ بِالْكَدِيدِ وَأَمَرَهُ أَنْ يُغِيرَ عَلَيْهِمْ فَخَرَجَ فَكُنْتُ فِي سَرِيَّتِهِ فَمَضَيْنَا حَتَّى إِذَا كُنَّا بِقُدَيْدٍ لَقِينَا بِهِ الْحَارِثَ بْنَ مَالِكٍ وَهُوَ ابْنُ الْبَرْصَاءِ اللَّيْثِيُّ فَأَخَذْنَاهُ فَقَالَ إِنَّمَا جِئْتُ لِأُسْلِمَ فَقَالَ غَالِبُ بْنُ عَبْدِ اللَّهِ إِنْ كُنْتَ إِنَّمَا جِئْتَ مُسْلِمًا فَلَنْ يَضُرَّكَ رِبَاطُ يَوْمٍ وَلَيْلَةٍ وَإِنْ كُنْتَ عَلَى غَيْرِ ذَلِكَ اسْتَوْثَقْنَا مِنْكَ قَالَ فَأَوْثَقَهُ رِبَاطًا ثُمَّ خَلَّفَ عَلَيْهِ رَجُلًا أَسْوَدَ كَانَ مَعَنَا فَقَالَ امْكُثْ مَعَهُ حَتَّى نَمُرَّ عَلَيْكَ فَإِنْ نَازَعَكَ فَاجْتَزَّ رَأْسَهُ قَالَ ثُمَّ مَضَيْنَا حَتَّى أَتَيْنَا بَطْنَ الْكَدِيدِ فَنَزَلْنَا عُشَيْشِيَةً بَعْدَ الْعَصْرِ فَبَعَثَنِي أَصْحَابِي فِي رَبِيئَةٍ فَعَمَدْتُ إِلَى تَلٍّ يُطْلِعُنِي عَلَى الْحَاضِرِ فَانْبَطَحْتُ عَلَيْهِ وَذَلِكَ الْمَغْرِبَ فَخَرَجَ رَجُلٌ مِنْهُمْ فَنَظَرَ فَرَآنِي مُنْبَطِحًا عَلَى التَّلِّ فَقَالَ لِامْرَأَتِهِ وَاللَّهِ إِنِّي لَأَرَى عَلَى هَذَا التَّلِّ سَوَادًا مَا رَأَيْتُهُ أَوَّلَ النَّهَارِ فَانْظُرِي لَا تَكُونُ الْكِلَابُ اجْتَرَّتْ بَعْضَ أَوْعِيَتِكِ قَالَ فَنَظَرَتْ فَقَالَتْ لَا وَاللَّهِ مَا أَفْقِدُ شَيْئًا قَالَ فَنَاوِلِينِي قَوْسِي وَسَهْمَيْنِ مِنْ كِنَانَتِي قَالَ فَنَاوَلَتْهُ فَرَمَانِي بِسَهْمٍ فَوَضَعَهُ فِي جَنْبِي قَالَ فَنَزَعْتُهُ فَوَضَعْتُهُ وَلَمْ أَتَحَرَّكْ ثُمَّ رَمَانِي بِآخَرَ فَوَضَعَهُ فِي رَأْسِ مَنْكِبِي فَنَزَعْتُهُ فَوَضَعْتُهُ وَلَمْ أَتَحَرَّكْ فَقَالَ لِامْرَأَتِهِ وَاللَّهِ لَقَدْ خَالَطَهُ سَهْمَايَ وَلَوْ كَانَ دَابَّةً لَتَحَرَّكَ فَإِذَا أَصْبَحْتِ فَابْتَغِي سَهْمَيَّ فَخُذِيهِمَا لَا تَمْضُغُهُمَا عَلَيَّ الْكِلَابُ قَالَ وَأَمْهَلْنَاهُمْ حَتَّى رَاحَتْ رَائِحَتُهُمْ حَتَّى إِذَا احْتَلَبُوا وَعَطَنُوا أَوْ سَكَنُوا وَذَهَبَتْ عَتَمَةٌ مِنْ اللَّيْلِ شَنَنَّا عَلَيْهِمْ الْغَارَةَ فَقَتَلْنَا مَنْ قَتَلْنَا مِنْهُمْ وَاسْتَقْنَا النَّعَمَ فَتَوَجَّهْنَا قَافِلِينَ وَخَرَجَ صَرِيخُ الْقَوْمِ إِلَى قَوْمِهِمْ مُغَوِّثًا وَخَرَجْنَا سِرَاعًا حَتَّى نَمُرَّ بِالْحَارِثِ ابْنِ الْبَرْصَاءِ وَصَاحِبِهِ فَانْطَلَقْنَا بِهِ مَعَنَا وَأَتَانَا صَرِيخُ النَّاسِ فَجَاءَنَا مَا لَا قِبَلَ لَنَا بِهِ حَتَّى إِذَا لَمْ يَكُنْ بَيْنَنَا وَبَيْنَهُمْ إِلَّا بَطْنُ الْوَادِي أَقْبَلَ سَيْلٌ حَالَ بَيْنَنَا وَبَيْنَهُمْ بَعَثَهُ اللَّهُ تَعَالَى مِنْ حَيْثُ شَا��َ مَا رَأَيْنَا قَبْلَ ذَلِكَ مَطَرًا وَلَا حَالًا فَجَاءَ بِمَا لَا يَقْدِرُ أَحَدٌ أَنْ يَقُومَ عَلَيْهِ فَلَقَدْ رَأَيْنَاهُمْ وُقُوفًا يَنْظُرُونَ إِلَيْنَا مَا يَقْدِرُ أَحَدٌ مِنْهُمْ أَنْ يَتَقَدَّمَ وَنَحْنُ نُحَوِّزُهَا سِرَاعًا حَتَّى أَسْنَدْنَاهَا فِي الْمَشْلَلِ ثُمَّ حَدَرْنَاهَا عَنَّا فَأَعْجَزْنَا الْقَوْمَ بِمَا فِي أَيْدِينَا","id":"Telah menceritakan kepada kami [Ya'qub] berkata; [bapakku] berkata; sebagaimana telah menceritakan kepadaku [Ibnu Ishaq] dari [Ya'qub bin 'Utbah] dari [Muslim bin Abdullah bin Jundub Al Juhani] dari [Jundub bin Makits Al Juhani] berkata; Rasulullah Shallallahu'alaihiwasallam mengutus Ghalib bin Abdullah Al Kalbi yang dijuluki 'kalb laits' ke Bani Mulawwah di Kadid dan memerintahkan untuk menyerang mereka secara tiba-tiba. Dia pun berangkat, dan saya termasuk dalam pasukannya. Kami berangkat hingga setelah sampai di sampai di Qadid, kami bertemu Al Harits Bin Malik, dia anak Al Barsha' Al Laitsi, kami menawannya. Dia berkata 'Saya datang untuk masuk Islam.' Ghalib bin Abdullah berkata; \"Jika engkau datang sebagai seorang muslim, tidaklah mengapa bagimu untuk berjaga siang dan malam, tapi kalau engkau belum masuk Islam, maka kami meminta janji kesetiaan darimu\".(Jundub bin Makits Al Juhani) berkata; Alharits bin Malik memberi janji kesetiaan dengan ribath (berjaga di perbatasan), Ghalib bin Abdullah alkalbi mempercayakan seorang laki-laki hitam untuk berada di belakangnya. Ghalib bin Abdullah berpesan, \"Tetaplah bersamanya, sampai kami melewatimu nanti, kalau dia khianat, maka potonglah kepalanya\". (Jundub bin Makits Al Juhani) berkata; kami berangkat sehingga kami sampai di tengah daerah Kadid, kami singgah sebentar selepas ashar. Lantas sahabatku mengutusku sebagai pasukan pengintai, hingga aku naik daerah yang tinggi sehingga aku bisa mengintai siapa saja yang datang. Aku-pun menelungkupkan wajahku yang saat itu adalah waktu maghrib. Tiba-tiba keluarlah laki-laki di antara mereka sambil melihat, ternyata dia melihatku tertelungkup di atas dataran tinggi. Dia berkata kepada istrinya, \"Demi Allah, saya melihat sesuatu yang berwarna hitam di atas dataran itu, yang tidak saya lihat pada waktu siang tadi. Lihatlah, jangan sampai ada anjing-anjing yang memangsa sebagian gembalaanmu\". (Jundub bin Makits Al Juhani) berkata; (istri laki-laki tadi) lantas memeriksa dan mengecek gembalaannya dan berkata 'Tidak, demi Allah, saya tidak kehilangan apa-apa.' (Laki-laki itu) berkata; berikan panahku dan dua anak panahnya dari tempatnya. (Jundub bin Makits Al Juhani) berkata; (wanita itu) menyerahkannya, lalu dia memanahku dan mengenai pinggangku.Saya mencabutnya dan saya letakkan dengan tidak sedikitpun bergerak. Dia melemparkan panahnya untuk keduakalinya ke arah pundakku, segera saya mencabutnya dengan tanpa gerak. Laki-laki tadi berkata kepada istrinya, \"Demi Allah, telah saya lemparkan dua panah ke arah benda tersebut, jika itu adalah hewan melata, pastilah bergerak. Besok pagi, telusurilah di mana letak dua panahku serta ambillah keduanya supaya tidak diambil anjing\". (Jundub bin Makits Al Juhani) berkata; ketika gembalaan sudah mulai balik kandang dari tempat minumnya, mereka telah memerah susunya, mengandangkan hewannya ke tempat semula, dan telah datang kegelapan malam, kami dengan perlahan-lahan menyerang mereka dan berhasil membunuh beberapa orang mereka. Kami mendapatkan hewan ternak, lalu kami pulang. Tiba-tiba kami mendengar suara yang berteriak minta tolong, dengan segera kami bergegas pergi ngacir, sampai kami melewati Al Harits bin Barsha' dan temannya, kami bersama-bersama pergi. Orang yang meminta tolong tadi mendatangi kami, tiba-tiba datanglah sekelompok yang bukan dari pihak kami. Hingga saat jarak antara kita dengan mereka (musuh) hanyalah dipisah pertengahan bukit yang menghadap saluran mata air, Allah Ta'ala dengan kehendak-Nya menurunkan air hujan yang sebelumnya tidak pernah aku melihat hujan dan lumpur hitam sederas itu. Derasnya hujan dan lumpur menyebabkan suatu hal yang tak seorang pun bisa melawannya. Kita melihat mereka (musuh) dalam keadaan berdiri memandang kami, tapi tidak ada seorangpun dari mereka yang mampu untuk maju. Kami dengan segera mengumpulkan unta-unta rampasan, kami pinggirkan di daerah air terjun, lantas kami gelincirkan dari kami, sehingga gagallah mereka merampas barang yang telah kami ambil."},"660":{"ar":"حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ قَالَ حَدَّثَنَا أَبُو نَعَامَةَ الْعَدَوِيُّ عَنْ مُسْلِمِ بْنِ بُدَيْلٍ عَنْ إِيَاسِ بْنِ زُهَيْرٍ عَنْ سُوَيْدِ بْنِ هُبَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَيْرُ مَالِ الْمَرْءِ لَهُ مُهْرَةٌ مَأْمُورَةٌ أَوْ سِكَّةٌ مَأْبُورَةٌ وَقَالَ رَوْحٌ فِي بَيْتِهِوَقِيلَ لَهُ إِنَّكَ قُلْتَ لَنَا سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Rauh bin 'Ubadah] berkata; telah menceritakan kepada kami [Abu Na'amah Al 'Adawi] dari [Muslim bin Budail] dari [Iyas bin Zuhair] dari [Suwaid bin Hubairah] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Sebaik-baik harta seseorang adalah anak kuda yang penurut atau pohon yang diserbukkan\". Rauh berkata di rumahnya, ada yang berkata; kamu telah berkata kepada kami, saya mendengar Rasulullah Shallallahu'alaihiwasallam, dia berkata; saya mendengar Nabi Shallallahu'alaihiwasallam."},"661":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ هِشَامِ بْنِ حَكِيمِ بْنِ حِزَامٍ قَالَمَرَّ بِقَوْمٍ يُعَذَّبُونَ فِي الْجِزْيَةِ بِفِلَسْطِينَ قَالَ فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ عَزَّ وَجَلَّ يُعَذِّبُ يَوْمَ الْقِيَامَةِ الَّذِينَ يُعَذِّبُونَ النَّاسَ فِي الدُّنْيَا","id":"Telah menceritakan kepada kami [Abu Mu'awiyah] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari [Hisyam bin Hakim bin Hizam] berkata; dia melewati suatu kaum yang sedang disiksa karena masalah jizyah di Palestina. Dia berkata; saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \" Pada Hari Kiamat Allah Azzawajalla menyiksa orang-orang yang menyiksa manusia di dunia\"."},"662":{"ar":"حَدَّثَنَا أَبُو النَّضْرِ حَدَّثَنَا أَبُو مُعَاوِيَةَ يَعْنِي شَيْبَانَ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ يَحْيَى بْنِ إِسْحَاقَ عَنْ مُجَاشِعِ بْنِ مَسْعُودٍأَنَّهُ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِابْنِ أَخٍ لَهُ يُبَايِعُهُ عَلَى الْهِجْرَةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا بَلْ يُبَايِعُ عَلَى الْإِسْلَامِ فَإِنَّهُ لَا هِجْرَةَ بَعْدَ الْفَتْحِ وَيَكُونُ مِنْ التَّابِعِينَ بِإِحْسَانٍ","id":"Telah menceritakan kepada kami [Abu Nadlr] telah menceritakan kepada kami [Abu Mu'awiyah] yaitu Syaiban, dari [Yahya bin Abu Katsir] dari [Yahya bin Ishaq] dari [Mujasyi' bin Mas'ud] dia datang kepada Nabi Shallallahu'alaihiwasallam bersama keponakannya untuk berbaiat atas hijrah. Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidak, tapi berbai'at atas Islam, karena tidak ada hijrah setelah Fathul Makkah\", di kemudian hari dia termasuk tabi'in yang baik."},"663":{"ar":"حَدَّثَنَا بَكْرُ بْنُ عِيسَى قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عَاصِمٍ الْأَحْوَلِ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ عَنْ مُجَاشِعِ بْنِ مَسْعُودٍ قَالَانْطَلَقْتُ بِأَخِي مَعْبَدٍ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ الْفَتْحِ فَقُلْتُ يَا رَسُولَ اللَّهِ بَايِعْهُ عَلَى الْهِجْرَةِ فَقَالَ مَضَتْ الْهِجْرَةُ لِأَهْلِهَا قَالَ فَقُلْتُ فَمَاذَا قَالَ عَلَى الْإِسْلَامِ وَالْجِهَادِ","id":"Telah menceritakan kepada kami [Bakr bin 'Isa] berkata; telah menceritakan kepada kami [Abu 'Awanah] dari ['Ashim Al Ahwal] dari [Abu 'Utsman An-Nahdi] dari [Mujasyi 'bin Mas'ud] berkata; saya pergi bersama saudaraku, Ma'bad kepada Rasulullah Shallallahu'alaihiwasallam setelah Fathu Makah. Saya berkata; Wahai Rasulullah, baiatlah dia untuk hijrah. Beliau bersabda: \"Hijrah telah berlalu\". (Mujasyi' bin Mas'ud Radliyallahu'anhu) berkata; lalu untuk apa? Beliau bersabda: \"Untuk Islam dan berjihad\"."},"664":{"ar":"حَدَّثَنَا حَسَنُ بْنُ مُوسَى قَالَ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ يَحْيَى بْنِ إِسْحَاقَ أَنَّهُ أَخْبَرَهُ عَنْ مُجَاشِعِ بْنِ مَسْعُودٍ الْبَهْزِيِّأَنَّهُ أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِابْنِ أَخِيهِ لِيُبَايِعَهُ عَلَى الْهِجْرَةِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا بَلْ يُبَايِعُ عَلَى الْإِسْلَامِ فَإِنَّهُ لَا هِجْرَةَ بَعْدَ الْفَتْحِ قَالَ وَيَكُونُ مِنْ التَّابِعِينَ بِإِحْسَانٍ","id":"Telah menceritakan kepada kami [Hasan bin Musa] berkata; telah menceritakan kepada kami [Syaiban] dari [Yahya bin Abu Katsir] dari [Yahya bin Ishaq] dia mengabari dari [Mujasyi' bin Mas'ud Al Bahzi] dia datang kepada Rasulullah Shallallahu'alaihiwasallam dengan anak pamannya agar beliau membaiatnya untuk hijrah. Rasulullah Shallallahu'alaihiwasallam bersabda kepadanya, \"Tidak, tapi baiat atas Islam, tidak ada hijrah setelah Fathu Makah.\" Kemudian hari dia menjadi tabiin yang baik."},"665":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ قَالَ حَدَّثَنَا خَالِدٌ الْحَذَّاءُ عَنْ أَبِي عُثْمَانَ عَنْ مُجَاشِعِ بْنِ مَسْعُودٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ هَذَا مُجَالِدُ بْنُ مَسْعُودٍ يُبَايِعُكَ عَلَى الْهِجْرَةِ قَالَ لَا هِجْرَةَ بَعْدَ فَتْحِ مَكَّةَ وَلَكِنْ أُبَايِعُهُ عَلَى الْإِسْلَامِ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Yazid bin Zurai'] berkata; telah menceritakan kepada kami [Khalid Al Khadza'] dari [Abu 'Utsman] dari [Mujasyi 'bin Mas'ud] berkata; saya berkata; Wahai Rasulullah, ini adalah Mujalid 'bin Mas'ud berbaiat kepada anda untuk berhijrah. Beliau bersabda: \"Tidak ada hijrah setelah Fathu Makah tapi saya membaiatnya untuk Islam\"."},"666":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ الْمَلِكِ بْنِ وَاقِدٍ قَالَ حَدَّثَنَا زُهَيْرٌ قَالَ حَدَّثَنَا عَاصِمٌ الْأَحْوَلُ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ عَنْ مُجَاشِعٍ قَالَقَدِمْتُ بِأَخِي مَعْبَدٍ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ الْفَتْحِ فَقُلْتُ يَا رَسُولَ اللَّهِ جِئْتُكَ بِأَخِي لِتُبَايِعَهُ عَلَى الْهِجْرَةِ فَقَالَ ذَهَبَ أَهْلُ الْهِجْرَةِ بِمَا فِيهَا فَقُلْتُ عَلَى أَيِّ شَيْءٍ تُبَايِعُهُ قَالَ عَلَى الْإِسْلَامِ وَالْإِيمَانِ وَالْجِهَادِقَالَ فَلَقِيتُ مَعْبَدًا بَعْدُ وَكَانَ هُوَ أَكْبَرُهُمَا فَسَأَلْتُهُ فَقَالَ صَدَقَ مُجَاشِعٌ","id":"Telah menceritakan kepada kami [Ahmad bin Abdul Malik bin Waqid] berkata; telah menceritakan kepada kami [Zuhair] berkata; telah menceritakan kepada kami ['Ashim Al Ahwal] dari [Abu 'Utsman An-Nahdi] dari [Mujasyi] berkata; saya bersama saudaraku Ma'bad, menemui Nabi Shallallahu'alaihiwasallam setelah Fathu Makah, lalu saya berkata; Wahai Rasulullah, saya membawa saudaraku agar anda membaiatnya untuk hijrah. Beliau bersabda: \"Orang yang berhijrah telah selesai dengan hijrahnya?\". Lalu saya berkata; terus untuk apa baiat anda kepadanya?. Beliau bersabda: \"Untuk Islam, iman dan jihad\". (Mujasyi Radliyallahu'anhu) berkata; saya bertemu [Ma'bad] setelah waktu yang lama, dia adalah orang yang paling dewasa di antara mereka, saya bertanya kepadanya, maka dia menjawab, Mujasyi' benar."},"667":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرِو بْنِ عَلْقَمَةَ اللَّيْثِيُّ عَنْ أَبِيهِ عَنْ جَدِّهِ عَلْقَمَةَ عَنْ بِلَالِ بْنِ الْحَارِثِ الْمُزَنِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الرَّجُلَ لَيَتَكَلَّمُ بِالْكَلِمَةِ مِنْ رِضْوَانِ اللَّهِ عَزَّ وَجَلَّ مَا يَظُنُّ أَنْ تَبْلُغَ مَا بَلَغَتْ يَكْتُبُ اللَّهُ عَزَّ وَجَلَّ لَهُ بِهَا رِضْوَانَهُ إِلَى يَوْمِ الْقِيَامَةِ وَإِنَّ الرَّجُلَ لَيَتَكَلَّمُ بِالْكَلِمَةِ مِنْ سَخَطِ اللَّهِ عَزَّ وَجَلَّ مَا يَظُنُّ أَنْ تَبْلُغَ مَا بَلَغَتْ يَكْتُبُ اللَّهُ عَزَّ وَجَلَّ بِهَا عَلَيْهِ سَخَطَهُ إِلَى يَوْمِ الْقِيَامَةِقَالَ فَكَانَ عَلْقَمَةُ يَقُولُ كَمْ مِنْ كَلَامٍ قَدْ مَنَعَنِيهِ حَدِيثُ بِلَالِ بْنِ الْحَارِثِ","id":"Telah menceritakan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami [Muhammad bin 'Amr bin 'Alqamah Al Laitsi] dari [Bapaknya] dari [kakeknya] dari [Bilal bin Al Harits Al Muzni] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \" ada seorang laki-laki yang hanya mengucapkan sepatah kata yang diridlai Allah Azzawajalla, dia tidak menduga (perkataan tersebut) pengaruhnya sampai sedemikian rupa hingga Allah Azzawajalla mencatatnya dalam keridlaan-Nya sampai Hari Kiamat. Sebaliknya ada seseorang yang mengucapkan sepatah kata yang dibenci Allah Azzawajalla, dia tidak menduga akibatnya sedemikian rupa hingga Allah menetapkan kemurkaan-Nya karena ucapan itu sampai Hari Kiamat\" (Bilal bin Al Harits Al Muzni Radliallahu'anhu) berkata; 'Alqamah berkata; berapa banyak perkataan yang saya tahan karena hadis Bilal bin Al Harits tersebut."},"668":{"ar":"حَدَّثَنَا سُرَيْجُ بْنُ النُّعْمَانِ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ يَعْنِي ابْنَ مُحَمَّدٍ قَالَ أَخْبَرَنِي ابْنُ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ الْحَارِثِ بْنِ بِلَالٍ عَنْ أَبِيهِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ فَسْخُ الْحَجِّ لَنَا خَاصَّةً أَمْ لِلنَّاسِ عَامَّةً قَالَ بَلْ لَنَا خَاصَّةً","id":"Telah menceritakan kepada kami [Suraij bin An-Nu'man] berkata; telah menceritakan kepada kami [Abdul Aziz] yaitu Ibnu Muhammad, berkata; telah mengabarkan kepadaku [Ibnu Rabi'ah bin Abu Abdurrahman] dari [Al Harits bin Bilal] dari [Bapaknya] berkata; Saya berkata; \"Wahai Rasulullah, apakah perkara membatalkan haji dengan sengaja adalah sesuatu yang khusus buat kita atau untuk ummat secara umum?\" (Rasulullah Shallallahu'alaihiwasallam) menjawab, \"Itu hanya untuk kita secara khusus\""},"669":{"ar":"حَدَّثَنِي قُرَيْشُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ الدَّرَاوَرْدِيُّ قَالَ أَخْبَرَنِي رَبِيعَةُ بْنُ أَبِي عَبْدِ الرَّحْمَنِ قَالَ سَمِعْتُ الْحَارِثَ بْنَ بِلَالِ بْنِ الْحَارِثِ يُحَدِّثُ عَنْ أَبِيهِ قَالَيَا رَسُولَ اللَّهِ أَرَأَيْتَ مُتْعَةَ الْحَجِّ لَنَا خَاصَّةً أَمْ لِلنَّاسِ عَامَّةً فَقَالَ لَا بَلْ لَنَا خَاصَّةً","id":"Telah menceritakan kepadaku [Quraisy bin Ibrahim] berkata; telah menceritakan kepada kami [Abdul Aziz bin Ad-Darawardi] berkata; telah menceritakan kepadaku [Rabi'ah bin Abu Abdurrahman] berkata; saya telah mendengar [Al Harits bin Bilal bin Al Harits] menceritakan dari [Bapaknya] berkata; Wahai Rasulullah, bagaimana pendapat anda tentang Haji tamattu`, apakah khusus bagi kami atau untuk semua manusia?. Beliau bersabda: \"Itu hanya bagi kita\"."},"670":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ سَلَّامِ بْنِ شُرَحْبِيلَ عَنْ حَبَّةَ وَسَوَاءَ ابْنَيْ خَالِدٍ قَالَادَخَلْنَا عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُصْلِحُ شَيْئًا فَأَعَنَّاهُ فَقَالَ لَا تَأْيَسَا مِنْ الرِّزْقِ مَا تَهَزَّزَتْ رُءُوسُكُمَا فَإِنَّ الْإِنْسَانَ تَلِدُهُ أُمُّهُ أَحْمَرَ لَيْسَ عَلَيْهِ قِشْرَةٌ ثُمَّ يَرْزُقُهُ اللَّهُ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Abu Mu'awiyah] berkata; telah menceritakan kepada kami [Al A'masy] dari [Sallam bin Syurahbil] dari [Habbah] dan [Sawa'], dua anak Khalid berkata; Kami berdua menemui Nabi Shallallahu'alaihiwasallam, beliau sedang memperbaiki sesuatu, kami berkeluh kesah kepadanya, beliau bersabda: \"Janganlah kalian berputus asa dari rizqi Allah selama kepala kalian masih bergerak. manusia itu dilahirkan oleh ibunya dalam keadaan merah, tidak memiliki suatu apapun, lalu Allah Azzawajalla memberinya rizqi\""},"671":{"ar":"حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ سَلَّامٍ أَبِي شُرَحْبِيلَ قَالَ سَمِعْتُ حَبَّةَ وَسَوَاءَ ابْنَيْ خَالِدٍ يَقُولَانِأَتَيْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَعْمَلُ عَمَلًا أَوْ يَبْنِي بِنَاءً فَأَعَنَّاهُ عَلَيْهِ فَلَمَّا فَرَغَ دَعَا لَنَا وَقَالَ لَا تَأْيَسَا مِنْ الْخَيْرِ مَا تَهَزَّزَتْ رُءُوسُكُمَا إِنَّ الْإِنْسَانَ تَلِدُهُ أُمُّهُ أَحْمَرَ لَيْسَ عَلَيْهِ قِشْرَةٌ ثُمَّ يُعْطِيهِ اللَّهُ وَيَرْزُقُهُ","id":"Telah menceritakan kepada kami [Waki'] berkata; telah menceritakan kepada kami [Al A'masy] dari [Sallam Abu Syurahbil] berkata; saya telah mendengar [Habbah] dan [Sawa',] dua anak Khalid berkata; Kami berdua menemui Nabi Shallallahu'alaihiwasallam, beliau sedang memperbaiki sesuatu atau sedang membangun suatu bangunan, kami berkeluh kesah kepadanya. Tatkala beliau selesai, beliau memanggil kami dan beliau bersabda: \"Janganlah kalian berputus asa dari kebaikan, selama kepala kalian masih bisa bergerak. Manusia itu dilahirkan oleh ibunya dalam keadaan merah, tidak memiliki suatu apapun, lalu Allah Azzawajalla memberinya rizqi\""},"672":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا خَالِدٌ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ قَالَجَلَسْتُ إِلَى رَهْطٍ أَنَا رَابِعُهُمْ بِإِيلِيَاءَ فَقَالَ أَحَدُهُمْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَيَدْخُلَنَّ الْجَنَّةَ بِشَفَاعَةِ رَجُلٍ مِنْ أُمَّتِي أَكْثَرُ مِنْ بَنِي تَمِيمٍ قُلْنَا سِوَاكَ يَا رَسُولَ اللَّهِ قَالَ سِوَايَ قُلْتُ أَنْتَ سَمِعْتَهُ قَالَ نَعَمْ فَلَمَّا قَامَ قُلْتُ مَنْ هَذَا قَالُوا ابْنُ أَبِي الْجَدْعَاءِ","id":"Telah menceritakan kepada kami [Isma'il bin Ibrahim] berkata; telah menceritakan kepada kami [Khalid] dari [Abdullah bin Syaqiq] berkata; saya duduk bergabung dengan sekelompok orang, saya adalah orang yang keempat di Iliya', salah dari mereka berkata; saya mendengar Rasulullah bersabda: 'Akan masuk surga lantaran syafa'at seorang laki-laki dari umatku, yang jumlahnya lebih banyak dari Bani tamim\". Kami berkata; itu bukan anda Wahai Rasulullah? (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Ya, selainku\". Saya (Abdullah bin Syaqiq Radliyallahu'anhu) bertanya, apakah kamu mendengarnya langsung? Dia menjawab, Ya. Ketika dia berdiri, saya bertanya, \"Siapakah dia?\" mereka berkata; \"Itu adalah [Ibnu Abu Al Jad'a] '\"."},"673":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا وُهَيْبٌ قَالَ حَدَّثَنَا خَالِدٌ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي الْجَدْعَاءِ أَنَّهُسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَيَدْخُلَنَّ الْجَنَّةَ بِشَفَاعَةِ رَجُلٍ مِنْ أُمَّتِي أَكْثَرُ مِنْ بَنِي تَمِيمٍ فَقَالُوا يَا رَسُولَ اللَّهِ سِوَاكَ قَالَ سِوَايَ سِوَايَقُلْتُ أَنْتَ سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَنَا سَمِعْتُهُ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Wuhaib] berkata; telah menceritakan kepada kami [Khalid] dari [Abdullah bin Syaqiq] dari [Abdullah bin Abu Al Jad'a'] telah mendengar Nabi Shallallahu'alaihiwasallam bersabda: \"Sungguh akan masuk surga karena syafa'at seorang dari umatku jumlah yang lebih banyak daripada Bani tamim\". Mereka bertanya, Wahai Rasulullah, orang itu bukan anda? Beliau bersabda: \"Bukan saya, bukan saya\". (Khalid Radliyallahu'anhu) bertanya, apakah kamu mendengarnya dari Rasulullah Shallallahu'alaihiwasallam?. dia menjawab, ya saya mendengarnya langsung dari beliau."},"674":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ أَخْبَرَنَا أَيُّوبُ عَنْ حُمَيْدِ بْنِ هِلَالٍ قَالَ قَالَ عُبَادَةُ بْنُ قُرْطٍإِنَّكُمْ لَتَأْتُونَ أُمُورًا هِيَ أَدَقُّ فِي أَعْيُنِكُمْ مِنْ الشَّعَرِ كُنَّا نَعُدُّهَا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُوبِقَاتِقَالَ فَذُكِرَ ذَلِكَ لِمُحَمَّدِ بْنِ سِيرِينَ فَقَالَ صَدَقَ وَأَرَى جَرَّ الْإِزَارِ مِنْهَا","id":"Telah menceritakan kepada kami [Isma'il] berkata; telah mengabarkan kepada kami [Ayyub] dari [Humaid bin Hilal] berkata; ['Ubadah bin Qurth] berkata; kalian akan menemui suatu urusan-urusan yang menurut pandangan kalian lebih sepele daripada halusnya rambut, padahal kami menganggapnya pada masa Rasulullah Shallallahu'alaihiwasallam termasuk hal yang membinasakan. ('Ubadah bin Qurth Radliyallahu'anhu) berkata; hal tersebut disampaikan kepada Muhammad bin Sirin, lalu dia berkata; \"Hal itu benar adanya, dan saya anggap memanjangkan sarung diatas mata kaki (diantara urusan yang dianggap sepele tersebut).\""},"675":{"ar":"حَدَّثَنَا مُصْعَبُ بْنُ الْمِقْدَامِ وَمُحَمَّدُ بْنُ سَابِقٍ قَالَا حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي الْجُوَيْرِيَةِ أَنَّ مَعْنَ بْنَ يَزِيدَ حَدَّثَهُ قَالَبَايَعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا وَأَبِي وَجَدِّي وَخَطَبَ عَلَيَّ فَأَنْكَحَنِي وَخَاصَمْتُ إِلَيْهِ فَكَانَ أَبِي يَزِيدُ خَرَجَ بِدَنَانِيرَ يَتَصَدَّقُ بِهَا فَوَضَعَهَا عِنْدَ رَجُلٍ فِي الْمَسْجِدِ فَأَخَذْتُهَا فَأَتَيْتُهُ بِهَا فَقَالَ وَاللَّهِ مَا إِيَّاكَ أَرَدْتُ بِهَا فَخَاصَمْتُهُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَكَ مَا نَوَيْتَ يَا يَزِيدُ وَلَكَ يَا مَعْنُ مَا أَخَذْتَ","id":"Telah menceritakan kepada kami [Mush'ab bin Al Miqdam] dan [Muhammad bin Sabiq] berkata; telah menceritakan kepada kami [Isra'il] dari [Abu Al Juwairiyah] [Ma'n bin Yazid] menceritakannya, berkata; saya berbaiat kepada Rasulullah Shallallahu'alaihiwasallam bersama bapakku dan kakekku. (Rasulullah Shallallahu'alaihiwasallam) melamarkan untukku dan menikahkanku. Suatu ketika saya melapor kepada beliau, bapakku, Yazid keluar dari rumah dengan membawa beberapa dinar untuk bersedekah dengannya, dia meletakkannya di samping seorang laki-laki di masjid. Saya datang dan mengambil dinar tersebut, dan membawanya kembali kepadanya. Dia berkata; Demi Allah, saya tidak bermaksud untuk bersedekah kepadamu. Saya laporkan hal tersebut kepada Rasulullah Shallallahu'alaihiwasallam, beliau bersabda: \"Kamu mendapatkan pahala seperti yang kamu niatkan Wahai Yazid, dan kamu Ya Ma'n, kamu mendapatkan apa yang telah kau ambil\"."},"676":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَمَّادٍ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عَاصِمِ بْنِ كُلَيْبٍ قَالَ حَدَّثَنِي سُهَيْلُ بْنُ ذِرَاعٍ أَنَّهُ سَمِعَ مَعْنَ بْنَ يَزِيدَ أَوْ أَبَا مَعْنٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اجْتَمِعُوا فِي مَسَاجِدِكُمْ فَإِذَا اجْتَمَعَ قَوْمٌ فَلْيُؤْذِنُونِي قَالَ فَاجْتَمَعْنَا أَوَّلَ النَّاسِ فَأَتَيْنَاهُ فَجَاءَ يَمْشِي مَعَنَا حَتَّى جَلَسَ إِلَيْنَا فَتَكَلَّمَ مُتَكَلِّمٌ مِنَّا فَقَالَ الْحَمْدُ لِلَّهِ الَّذِي لَيْسَ لِلْحَمْدِ دُونَهُ مُقْتَصَرٌ وَلَيْسَ وَرَاءَهُ مَنْفَذٌ وَنَحْوًا مِنْ هَذَا فَغَضِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَ فَتَلَاوَمْنَا وَلَامَ بَعْضُنَا بَعْضًا فَقُلْنَا خَصَّنَا اللَّهُ بِهِ أَنْ أَتَانَا أَوَّلَ النَّاسِ وَأَنْ فَعَلَ وَفَعَلَ قَالَ فَأَتَيْنَاهُ فَوَجَدْنَاهُ فِي مَسْجِدِ بَنِي فُلَانٍ فَكَلَّمْنَاهُ فَأَقْبَلَ يَمْشِي مَعَنَا حَتَّى جَلَسَ فِي مَجْلِسِهِ الَّذِي كَانَ فِيهِ أَوْ قَرِيبًا مِنْهُ ثُمَّ قَالَ إِنَّ الْحَمْدَ لِلَّهِ مَا شَاءَ اللَّهُ جَعَلَ بَيْنَ يَدَيْهِ وَمَا شَاءَ جَعَلَ خَلْفَهُ وَإِنَّ مِنْ الْبَيَانِ سِحْرًا ثُمَّ أَقْبَلَ عَلَيْنَا فَأَمَرَنَا وَكَلَّمَنَا وَعَلَّمَنَا","id":"Telah menceritakan kepada kami [Yahya bin Hammad] berkata; telah menceritakan kepada kami [Abu 'Awanah] dari ['Ashim bin Kulaib] berkata; telah menceritakan kepadaku [Suhail bin Dzira'] dia mendengar [Ma'n bin Yazid] atau Abu Ma'n berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Berkumpullah kalian di masjid kalian, jika telah berkumpul suatu kaum maka mintalah izin kepadaku\". (Ma'an bin Yazid Radliyallahu'anhu) berkata; maka kita-lah orang pertama kali berkumpul lalu kami mendatangi beliau. Beliau datang dengan berjalan bersama kami, lalu duduk. Ada seseorang dari kami berkata; \"Segala puji bagi Allah, tidak ada bagi pujian selainnya\", --Ia mengucapkannya dengan di singkat-- dan setelahnya tidak ada jalan dan yang semisalnya. Rasulullah marah, beliau berdiri. Lalu kami saling mencela, dan saling menyalahkan satu kepada yang lainnya. lalu kami berkata; \"Allah mengkhususkan kita untuk datang pertama kali dan terjadilah ini semua\" (Ma'an bin Yazid radliyallahu'anhu) berkata; lalu kami mendatangi (Rasulullah Shallallahu'alaihiwasallam) dan kami mendapatinya di masjid Bani Fulan, lalu kami mengajak beliau berbicara, beliau berjalan bersama kami sehingga sampai di tempat yang beliau duduk sebelumnya atau dekat dengan itu, lalu beliau bersabda: \"Pujian itu bagi Allah, terserah kehendak-Nya, dijadikan-Nya di hadapan-Nya atau di belakang-Nya, dan di antara lafadz yang indah terdapat apa yang disebut sihir\", lalu beliau berdiri, menemui kami dan memerintahkan kepada kami serta berbicara dan mengajari kami."},"677":{"ar":"حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ قَالَ حَدَّثَنَا عَاصِمُ بْنُ كُلَيْبٍ قَالَ حَدَّثَنِي أَبُو الْجُوَيْرِيَةِ قَالَأَصَبْتُ جَرَّةً حَمْرَاءَ فِيهَا دَنَانِيرُ فِي إِمَارَةِ مُعَاوِيَةَ فِي أَرْضِ الرُّومِ قَالَ وَعَلَيْنَا رَجُلٌ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ بَنِي سُلَيْمٍ يُقَالُ لَهُ مَعْنُ بْنُ يَزِيدَ قَالَ فَأَتَيْتُ بِهَا يَقْسِمُهَا بَيْنَ ال��مُسْلِمِينَ فَأَعْطَانِي مِثْلَ مَا أَعْطَى رَجُلًا مِنْهُمْ ثُمَّ قَالَ لَوْلَا أَنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَأَيْتُهُ يَفْعَلُهُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا نَفْلَ إِلَّا بَعْدَ الْخُمُسِ إِذًا لَأَعْطَيْتُكَ قَالَ ثُمَّ أَخَذَ فَعَرَضَ عَلَيَّ مِنْ نَصِيبِهِ فَأَبَيْتُ عَلَيْهِ قُلْتُ مَا أَنَا بِأَحَقَّ بِهِ مِنْكَ","id":"Telah menceritakan kepada kami ['Affan] berkata; telah menceritakan kepada kami [Abu 'Awanah] berkata; telah menceritakan kepada kami ['Ashim bin Kulaib] berkata telah menceritakan kepadaku [Abu Al Juwairiyah] berkata; Saya mendapat sebuah bejana mewah, berisi dinar yang banyak pada pemerintahan Mu'awiyah di tanah Rum. Kami dipimpin seorang sahabat dari Bani Sulaim yang bernama [Ma'an bin Yazid]. Saya mendatanginya dengan membawa bejana tersebut untuk dibagi kepada kaum muslimin, dia memberiku sebagaimana dia memberi kepada yang lainnya, lalu berkata; kalaulah saja saya tidak mendengar Rasulullah Shallallahu'alaihiwasallam -dan aku melihat beliau melakukan demikian-, saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: 'Tidak ada rampasan perang kecuali setelah pembagian seperlima', niscaya saya akan memberimu\". (Abu Al Juwairiyah Radliyallahu'anhu) berkata; lalu dia menunjukkan bagiannya kepadaku, namun saya menolaknya dan saya katakan, saya tidaklah lebih berhak darimu."},"678":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَبْدِ الْمَلِكِ وَسُرَيْجُ بْنُ النُّعْمَانِ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي الْجُوَيْرِيَةِ قَالَ حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ قَالَ حَدَّثَنَا أَبُو الْجُوَيْرِيَةِ عَنْ مَعْنِ بْنِ يَزِيدَ قَالَبَايَعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا وَأَبِي وَجَدِّي وَخَاصَمْتُ إِلَيْهِ فَأَفْلَجَنِي وَخَطَبَ عَلَيَّ فَأَنْكَحَنِي","id":"Telah menceritakan kepada kami [Hisyam bin Abdul Malik] dan [Suraij bin An-Nu'man] berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Al Juwairiyah] berkata; Telah menceritakan kepada kami ['Affan] berkata; telah menceritakan kepada kami [Abu 'Awanah] berkata; telah menceritakan kepada kami [Abu Al Juwairiyah] dari [Ma'n bin Yazid] berkata; saya berbaiat kepada Rasulullah Shallallahu'alahiwasallam bersama dengan bapakku dan kakekku, saya membantah beliau, hanya beliau mengalahkanku, bahkan melamarkan untukku dan menikahkanku."},"679":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا سُفْيَانُ عَنْ جَابِرٍ عَنْ الشَّعْبِيِّ عَنْ عَبْدِ اللَّهِ بْنِ ثَابِتٍ قَالَجَاءَ عُمَرُ بْنُ الْخَطَّابِ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي مَرَرْتُ بِأَخٍ لِي مِنْ بَنِي قُرَيْظَةَ فَكَتَبَ لِي جَوَامِعَ مِنْ التَّوْرَاةِ أَلَا أَعْرِضُهَا عَلَيْكَ قَالَ فَتَغَيَّرَ وَجْهُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَبْدُ اللَّهِ فَقُلْتُ لَهُ أَلَا تَرَى مَا بِوَجْهِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ عُمَرُ رَضِينَا بِاللَّهِ رَبًّا وَبِالْإِسْلَامِ دِينًا وَبِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَسُولًا قَالَ فَسُرِّيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ لَوْ أَصْبَحَ فِيكُمْ مُوسَى ثُمَّ اتَّبَعْتُمُوهُ وَتَرَكْتُمُونِي لَضَلَلْتُمْ إِنَّكُمْ حَظِّي مِنْ الْأُمَمِ وَأَنَا حَظُّكُمْ مِنْ النَّبِيِّينَ","id":"Telah menceritakan kepada kami [Abdurrazzaq] berkata; telah memberitakan kepada kami [Sufyan] dari [Jabir] dari [Asy-Sya'bi] dari [Abdullah bin Tsabit] berkata; 'Umar bin Khathab datang kepada Nabi Shallallahu'alaihiwasallam lalu berkata; \"Wahai Rasulullah, saya pernah bertemu dengan saudaraku dari Bani Quraidzah, lalu dia mencatatkan untukku ringkasan kitab Taurat, maukah saya tunjukkan kepada anda? (Abdullah bin Tsabit Radliyallahu'anhu) berkata; kontan wajah Rasulullah Shallallahu'alahiwasallam berubah. Saya bertanya kepada ('Umar Radliyallahu'anhu) tidakkah kau melihat gerangan yang terjadi pada wajah Rasulullah Shallallahu'alahiwasallam? Umar bergegas berkata; \" Kami ridla Allah sebagai Rabb kami, Islam sebagai agama dan Muhammad Shallallahu'alaihiwasallam sebagai seorang Rasul\". Serta merta hilanglah kesedihan dari Nabi Shallallahu'alaihiwasallam lalu bersabda: \"Sungguh Demi Dzat yang jiwaku berada di tangan-Nya, kalaulah di antara kalian terdapat Musa, lalu kalian mengikutinya dan meninggalkanku, sungguh kalian sesat. Sungguh kalian adalah umat yang diperuntukkan bagiku, dan aku adalah nabi yang diperuntukkan bagi kalian'."},"680":{"ar":"حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَاقَ عَنْ رَجُلٍ مِنْ جُهَيْنَةَ قَالَسَمِعَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَقُولُ يَا حَرَامُ فَقَالَ يَا حَلَالُ","id":"Telah menceritakan kepada kami [Yahya bin 'Adam] berkata; telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari [seorang laki-laki dari Juhainah] berkata; Nabi Shallallahu'alaihiwasallam mendengarnya berkata; 'Wahai Haram', beliau bersabda: 'Wahai Halal.'"},"681":{"ar":"حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا عِصَامُ بْنُ قُدَامَةَ الْبَجَلِيُّ قَالَ حَدَّثَنِي مَالِكُ بْنُ نُمَيْرٍ الْخُزَاعِيُّ عَنْ أَبِيهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ قَاعِدٌ فِي الصَّلَاةِ قَدْ وَضَعَ ذِرَاعَهُ الْيُمْنَى عَلَى فَخِذِهِ الْيُمْنَى رَافِعًا بِأُصْبُعِهِ السَّبَّابَةِ قَدْ حَنَاهَا شَيْئًا وَهُوَ يَدْعُو","id":"Telah menceritakan kepada kami [Yahya bin 'Adam] berkata; telah menceritakan kepada kami [Isham bin Qudamah Al Bajali] berkata; telah menceritakan kepadaku [Malik bin Numair Al Khuza'i] dari [bapaknya] berkata; saya melihat Rasulullah Shallallahu'alahiwasallam shalat dalam keadaan duduk dan meletakkan lengan kanan tangan beliau diatas paha kanan dengan mengangkat jari tengahnya dan memiringkannya, beliau dalam keadaan berdoa."},"682":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا عِصَامُ بْنُ قُدَامَةَ عَنْ مَالِكِ بْنِ نُمَيْرٍ الْخُزَاعِيِّ عَنْ أَبِيهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاضِعًا يَدَهُ الْيُمْنَى عَلَى فَخِذِهِ الْيُمْنَى فِي الصَّلَاةِ يُشِيرُ بِأُصْبُعِهِ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Isham bin Qudamah] dari [Malik bin Numair Al Khuza'i] dari [bapaknya] berkata; saya melihat Rasulullah Shallallahu'alahiwasallam meletakkan tangan kanannya diatas paha kanan dalam shalat dengan memberi isyarat dengan jarinya."},"683":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ أَبَا إِسْرَائِيلَ قَالَ سَمِعْتُ جَعْدَةَ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَأَى رَجُلًا سَمِينًا فَجَعَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُومِئُ إِلَى بَطْنِهِ بِيَدِهِ وَيَقُولُ لَوْ كَانَ هَذَا فِي غَيْرِ هَذَا الْمَكَانِ لَكَانَ خَيْرًا لَكَ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] berkata; telah menceritakan kepada kami [Syu'bah] berkata; saya telah mendengar [Abu Isra'il] berkata; saya telah mendengar [Ja'dah] berkata; saya telah mendengar Nabi Shallallahu'alaihiwasallam, beliau melihat seorang laki-laki yang gemuk, lalu Nabi Shallallahu'alaihiwasallam menunjuk ke arah perutnya dengan tangannya bersabda: \"Duhh, kalau kegemukannya tidak di perut, niscaya lebih bagus bagimu\""},"684":{"ar":"قَالَوَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِرَجُلٍ فَقَالُوا هَذَا أَرَادَ أَنْ يَقْتُلَكَ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ تُرَعْ لَمْ تُرَعْ وَلَوْ أَرَدْتَ ذَلِكَ لَمْ يُسَلِّطْكَ اللَّهُ عَلَيَّ","id":"[Ja'dah Radliyallahu'anhu] berkata; diserahkan kepada Nabi Shallallahu'alaihiwasallam seorang laki-laki, lalu mereka berkata; 'Orang ini hendak membunuh anda.' Nabi Shallallahu'alaihiwasallam bersabda kepadanya, \"Tidakkah kau takut, tidakkah kau takut, kalau kau menghendaki hal itu, niscaya Allah tidak akan memberimu jalan untuk menguasaiku\"."},"685":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا أَبُو إِسْرَائِيلَ فِي بَيْتِ قَتَادَةَ قَالَ سَمِعْتُ جَعْدَةَ وَهُوَ مَوْلَى أَبِي إِسْرَائِيلَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَجُلٌ يَقُصُّ عَلَيْهِ رُؤْيَا وَذَكَرَ سِمَنَهُ وَعِظَمَهُ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ كَانَ هَذَا فِي غَيْرِ هَذَا كَانَ خَيْرًا لَكَ","id":"Telah menceritakan kepada kami [Abdusshamad] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Abu Isra'il] di rumah Qatadah, berkata; saya mendengar [Ja'dah] yaitu budak bani Isra'il, berkata; saya pernah melihat Rasulullah Shallallahu'alahiwasallam dan seorang laki-laki yang menceritakan mimpinya, dia menyebutkan kegemukan dan kebesaran badannya. Lalu Rasulullah Shallallahu'alahiwasallam bersabda kepadanya, \"Duhh, kalau saja kegemukannya tidak di perut, itu lebih baik bagimu.\""},"686":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَاصِمٍ الْأَحْوَلِ عَنْ الشَّعْبِيِّ عَنْ مُحَمَّدِ بْنِ صَفْوَانَأَنَّهُ صَادَ أَرْنَبَيْنِ فَلَمْ يَجِدْ حَدِيدَةً يَذْبَحُهُمَا بِهَا فَذَبَحَهُمَا بِمَرْوَةٍ فَأَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَهُ بِأَكْلِهِمَاحَدَّثَنَا يَزِيدُ قَالَ أَخْبَرَنَا دَاوُدُ يَعْنِي ابْنَ أَبِي هِنْدٍ عَنْ عَامِرٍ عَنْ مُحَمَّدِ بْنِ صَفْوَانَ أَنَّهُ مَرَّ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَرْنَبَيْنِ مُعَلِّقُهُمَا فَذَكَرَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Ja'far] telah menceritakan kepada kami [Syu'bah] dari ['Ashim Al Ahwal] dari [Asy-Sya'bi] dari [Muhammad bin Shafwan], dia pernah berburu dua ekor kelinci, lalu tidak mendapatkan besi untuk menyembelihnya, dia pun menyembelihnya dengan sebuah batu putih yang tajam, ia datang menemui Rasulullah Shallallahu'alahiwasallam, beliau memerintahkanya untuk memakan buruannya. Telah menceritakan kepada kami [Yazid] berkata; telah mengabarkan kepada kami [Daud] yaitu Ibnu Abu Hind, dari ['Amir] dari [Muhammad bin Shafwan] sesungguhnya dia melewati Rasulullah Shallallahu'alahiwasallam dengan membawa dua buah kelinci yang tergantung\", lalu menyebutkan secara makna."},"687":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ يُوسُفَ عَنْ شَرِيكٍ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ أَبِي رَوْحٍ الْكَلَاعِيِّ قَالَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةً فَقَرَأَ فِيهَا سُورَةَ الرُّومِ فَلَبَسَ عَلَيْهِ بَعْضُهَا قَالَ إِنَّمَا لَبَسَ عَلَيْنَا الشَّيْطَانُ الْقِرَاءَةَ مِنْ أَجْلِ أَقْوَامٍ يَأْتُونَ الصَّلَاةَ بِغَيْرِ وُضُوءٍ فَإِذَا أَتَيْتُمْ الصَّلَاةَ فَأَحْسِنُوا الْوُضُوءَحَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ قَالَ سَمِعْتُ شَبِيبًا أَبَا رَوْحٍ يُحَدِّثُ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ صَلَّى الصُّبْحَ فَقَرَأَ فِيهَا الرُّومَ فَأَوْهَمَ فَذَكَرَهُ","id":"Telah menceritakan kepada kami [Ishaq bin Yunus] dari [Syarik] dari [Abdul Malik bin 'Umair] dari [Abu Rauh Al Kalla'i] berkata; Rasulullah Shallallahu'alahiwasallam shalat bersama kami, membaca surat Ar Rum. Beliau mengalami kebingungan pada sebagian surat yang dibaca, dan bersabda: \"Yang membuat kita bingung pada waktu membaca surat dalam shalat adalah setan, disebabkan kaum yang mendirikan shalat tanpa berwudlu. Jika kalian mendatangi shalat, perbaguslah wudlu \" Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Abdul Malik bin 'Umair] berkata; saya telah mendengar [Syabib, Abu Rauh] menceritakan dari [salah seorang sahabat Nabi Shallallahu'alaihiwasallam], dari Nabi Shallallahu'alaihiwasallam, beliau shalat subuh, membaca surat Ar Rum, lalu beliau mengalami kebingungan, lalu dia menyebutkan secara lengkap."},"688":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا أَبُو سَعِيدٍ مَوْلَى بَنِي هَاشِمٍ حَدَّثَنَا زَائِدَةُ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عُمَيْرٍ قَال�� سَمِعْتُ شَبِيبًا أَبَا رَوْحٍ مِنْ ذِي الْكَلَاعِ عَنْ رَجُلٍأَنَّهُ صَلَّى مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصُّبْحَ فَقَرَأَ بِالرُّومِ فَتَرَدَّدَ فِي آيَةٍ فَلَمَّا انْصَرَفَ قَالَ إِنَّهُ يَلْبِسُ عَلَيْنَا الْقُرْآنَ أَنَّ أَقْوَامًا مِنْكُمْ يُصَلُّونَ مَعَنَا لَا يُحْسِنُونَ الْوُضُوءَ فَمَنْ شَهِدَ الصَّلَاةَ مَعَنَا فَلْيُحْسِنْ الْوُضُوءَ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Abu Sa'id] budak Bani Hasyim telah menceritakan kepada kami [Za'idah] telah menceritakan kepada kami [Abdul Malik bin 'Umair] berkata; saya mendengar [Syabib, Abu Rauh, dari Dzil Kala'i] dari seseorang, ia shalat subuh bersama Nabi Shallallahu'alaihiwasallam, lalu beliau membaca surat Ar Rum, beliau mengalami keragu-raguan pada beberapa ayat. Tatkala selesai, beliau bersabda: \"(Setan) itu mengganggu pada bacaan Al Quran, sungguh ada satu kaum dari kalian yang shalat bersama kami namun tidak melakukan wudlu dengan baik. Barangsiapa yang mengikuti shalat bersama kami, tolong perbaguslah wudlunya\"."},"689":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا أَبُو مَالِكٍ الْأَشْجَعِيُّ عَنْ أَبِيهِ أَنَّهُسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَقُولُ لِقَوْمٍ مَنْ وَحَّدَ اللَّهَ تَعَالَى وَكَفَرَ بِمَا يُعْبَدُ مِنْ دُونِهِ حَرُمَ مَالُهُ وَدَمُهُ وَحِسَابُهُ عَلَى اللَّهِ عَزَّ وَجَلَّقَالَ أَبِي حَدَّثَنَا بِهِ يَزِيدُ بِوَاسِطٍ وَبَغْدَادَ قَالَ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Yazid bin Harun] berkata; telah mengabarkan kepada kami [Abu Malik Al Asyja'i] dari [Bapaknya] sesungguhnya dia mendengar Nabi Shallallahu'alaihiwasallam bersabda kepada suatu kaum: 'Barangsiapa memurnikan ibadah hanya kepada Allah dan mengufuri apa yang disembah selain-Nya, haram harta dan darahnya, dan perhitungannya menjadi urusan Allah Azzawajalla. Bapaknya berkata; telah menceritakan kepada kami dengan hadits itu, Yazid di Wasith dan Bahgdad. Dia berkata; mendengar Nabi Shallallahu'alaihiwasallam."},"690":{"ar":"قَالَ أَبِي حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ بِبَغْدَادَ أَنْبَأَنَا أَبُو مَالِكٍ الْأَشْجَعِيُّ سَعْدُ بْنُ طَارِقٍ عَنْ أَبِيهِأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ بِحَسْبِ أَصْحَابِي الْقَتْلُ","id":"bapakku berkata; telah menceritakan kepada kami [Yazid bin Harun] di Baghdad, telah memberitakan kepada kami [Abu Malik Al Asyja'i, Sa'd bin Thariq] dari [bapaknya] sesungguhnya dia mendengar Nabi Shallallahu'alaihiwasallam bersabda: \"Perkara yang menyibukkan para sahabatku adalah perang\""},"691":{"ar":"قَالَ أَبِي حَدَّثَنَا يَزِيدُ قَالَ أَخْبَرَنَا أَبُو مَالِكٍ الْأَشْجَعِيُّ قَالَ حَدَّثَنِي أَبِيأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا أَتَاهُ الْإِنْسَانُ يَقُولُ كَيْفَ يَا رَسُولَ اللَّهِ أَقُولُ حِينَ أَسْأَلُ رَبِّي قَالَ قُلْ اللَّهُمَّ اغْفِرْ لِي وَارْحَمْنِي وَاهْدِنِي وَارْزُقْنِي وَقَبَضَ أَصَابِعَهُ الْأَرْبَعَ إِلَّا الْإِبْهَامَ فَإِنَّ هَؤُلَاءِ يَجْمَعْنَ لَكَ دُنْيَاكَ وَآخِرَتَكَ","id":"bapakku berkata; telah menceritakan kepada kami [Yazid] telah mengabarkan kepada kami [Abu Malik Al Asyja'i] berkata; telah menceritakan kepadaku [bapakku] sesungguhnya dia mendengar Rasulullah Shallallahu'alahiwasallam bersabda ketika datang padanya seseorang, \"Bagaimana Rasulullah, apa yang harus saya katakan ketika berdoa meminta kepada Rabbku?\". Beliau bersabda: \"Ya Allah, ampunilah aku, kasihanilah aku, tunjukilah aku dan berilah aku rizqi\" dengan menggenggam keempat jarinya kecuali jempolnya. Keempat hal itu telah menghimpun perkara dunia dan akheratmu."},"692":{"ar":"قَالَوَسَمِعْتُهُ يَقُولُ لِلْقَوْمِ مَنْ وَحَّدَ اللَّهَ وَكَفَرَ بِمَا يُعْبَدُ مِنْ دُونِهِ حَرُمَ مَالُهُ وَدَمُهُ وَحِسَابُهُ عَلَى اللَّهِ عَزَّ وَجَلَّ","id":"[Thariq Radliyallahu'anhu] berkata; saya telah mendengar (Rasulullah Shallallahu'alahiwasallam) bersabda kepada suatun kaum, \"Barangsiapa yang mengesakan Allah dan mengingkari apa yang disembah selain Dia, harta dan darahnya haram. Adapun hisabnya adalah kewajiban Allah Azzawajalla\"."},"693":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا أَبُو مَالِكٍ قَالَقُلْتُ لِأَبِي يَا أَبَتِ إِنَّكَ قَدْ صَلَّيْتَ خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبِي بَكْرٍ وَعُمَرَ وَعُثْمَانَ وَعَلِيٍّ هَاهُنَا بِالْكُوفَةِ قَرِيبًا مِنْ خَمْسِ سِنِينَ أَكَانُوا يَقْنُتُونَ قَالَ أَيْ بُنَيَّ مُحْدَثٌ","id":"Telah menceritakan kepada kami [Yazid bin Harun] berkata; telah mengabarkan kepada kami [Abu Malik] berkata; Saya berkata kepada [bapakku], Wahai bapakku, engkau pernah shalat di belakang Rasulullah Shallallahu'alahiwasallam, Abu Bakar, 'Umar, 'Utsman dan 'Ali waktu di Kufah selama hampir lima tahun, lalu apakah mereka melakukan Qunut? Dia berkata; 'Wahai anakku, itu adalah perkara yang baru."},"694":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ حَدَّثَنَا خَلَفٌ يَعْنِي ابْنَ خَلِيفَةَ عَنْ أَبِي مَالِكٍ الْأَشْجَعِيِّ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ رَآنِي فِي الْمَنَامِ فَقَدْ رَآنِي","id":"Telah menceritakan kepada kami [Husain bin Muhammad] telah menceritakan kepada kami [Khalaf] yaitu Ibnu Khalifah, dari [Abu Malik Al Asja'i] dari [Bapaknya] berkata; Rasulullah Shallallahu'alahiwasallam bersabda: \"Barangsiapa melihatku dalam mimpi, sungguh dia telah melihatku\"."},"695":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا عَبْدُ الْوَاحِدِ يَعْنِي ابْنَ زِيَادٍ حَدَّثَنَا أَبُو مَالِكٍ الْأَشْجَعِيُّ قَالَ حَدَّثَنِي أَبِي طَارِقُ بْنُ أَشْيَمَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعَلِّمُ مَنْ أَسْلَمَ يَقُولُ اللَّهُمَّ اغْفِرْ لِي وَارْحَمْنِي وَارْزُقْنِي وَهُوَ يَقُولُ هَؤُلَاءِ يَجْمَعْنَ لَكَ خَيْرَ الدُّنْيَا وَالْآخِرَةِ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Abdul Wahid] yaitu Ibnu Ziyad, telah menceritakan kepada kami [Abu Malik Al Asyja'i] dari [Abu Thariq bin Asyyam] berkata saya mendengar Rasulullah Shallallahu'alahiwasallam mengajar orang-orang yang masuk Islam untuk mengatakan, \"Ya Allah, ampunilah aku, kasihanilah aku dan berilah aku rizqi\" dan beliau berkata; semua hal itu telah menghimpun kebaikan dunia dan akheratmu."},"696":{"ar":"حَدَّثَنَا بَكْرُ بْنُ عِيسَى أَبُو بِشْرٍ الْبَصْرِيُّ الرَّاسِبِيُّ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ قَالَ حَدَّثَنَا أَبُو مَالِكٍ الْأَشْجَعِيُّ قَالَ سَمِعْتُ أَبِي وَسَأَلْتُهُ فَقَالَكَانَ خِضَابُنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَرْسَ وَالزَّعْفَرَانَ","id":"Telah menceritakan kepada kami [Bakr bin 'Isa, Abu Bisyr Al Bashri Ar Rasibi] berkata; telah menceritakan kepada kami [Abu 'Awanah] berkata; telah menceritakan kepada kami [Abu Malik Al Asyja'i] berkata; saya mendengar [bapakku] dan saya menanyakannya, maka dia berkata; semir rambut kami bersama Rasulullah Shallallahu'alahiwasallam adalah waras (sejenis tanaman berwarna kuning yang mempunyai bau wangi) dan Za'faran."},"697":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ عَمْرِو بْنِ حَسَّانَ يَعْنِي الْمُسْلِيَّ قَالَ حَدَّثَنَا الْمُغِيرَةُ بْنُ عَبْدِ اللَّهِ الْيَشْكُرِيُّ عَنْ أَبِيهِ قَالَدَخَلْتُ مَسْجِدَ الْكُوفَةِ أَوَّلَ مَا بُنِيَ مَسْجِدُهَا وَهُوَ فِي أَصْحَابِ التَّمْرِ يَوْمَئِذٍ وَجُدُرُهُ مِنْ سِهْلَةٍ فَإِذَا رَجُلٌ يُحَدِّثُ النَّاسَ قَالَ بَلَغَنِي حَجَّةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَجَّةُ الْوَدَاعِ فَاسْتَتْبَعْتُ رَاحِلَةً مِنْ إِبِلِي ثُمَّ خَرَجْتُ حَتَّى جَلَسْتُ لَهُ فِي طَرِيقِ عَرَفَةَ أَوْ وَقَفْتُ لَهُ فِي طَرِيقِ عَرَفَةَ قَالَ فَإِذَا رَكْبٌ عَرَفْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهِمْ بِالصِّفَةِ فَقَالَ رَجُلٌ أَمَامَهُ خَلِّ لِي عَنْ طَرِيقِ الرِّكَابِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيْحَهُ فَأَرَبٌ مَا لَهُ فَدَنَوْتُ مِنْهُ حَتَّى اخْتَلَفَتْ رَأْسُ النَّاقَتَيْنِ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ دُلَّنِي عَلَى عَمَلٍ يُدْخِلُنِي الْجَنَّةَ وَيُنْجِينِي مِنْ النَّارِ قَالَ بَخٍ بَخٍ لَئِنْ كُنْتَ قَصَّرْتَ فِي الْخُطْبَةِ لَقَدْ أَبْلَغْتَ فِي الْمَسْأَلَةِ افْقَهْ إِذًا تَعْبُدُ اللَّهَ عَزَّ وَجَلَّ لَا تُشْرِكُ بِهِ شَيْئًا وَتُقِيمُ الصَّلَاةَ وَتُؤَدِّي الزَّكَاةَ وَتَحُجُّ الْبَيْتَ وَتَصُومُ رَمَضَانَ خَلِّ طَرِيقَ الرِّكَابِحَدَّثَنَا وَكِيعٌ عَنْ يُونُسَ قَالَ سَمِعْتُ هَذَا الْحَدِيثَ مِنْ الْمُغِيرَةِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ نَحْوَهُ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ أَبِي إِسْحَاقَ عَنِ الْمُغِيرَةِ عَنْ أَبِيهِ قَالَ انْتَهَيْتُ إِلَى رَجُلٍ يُحَدِّثُ قَوْمًا فَجَلَسْتُ فَقَالَ وُصِفَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا بِمِنًى غَادِيًا إِلَى عَرَفَاتٍ فَذَكَرَ الْحَدِيثَ فَقُلْتُ يَا رَسُولَ اللَّهِ خَبِّرْنِي بِعَمَلٍ يُقَرِّبُنِي مِنْ الْجَنَّةِ وَيُبَاعِدُنِي مِنْ النَّارِ قَالَ تُقِيمُ الصَّلَاةَ وَتُؤْتِي الزَّكَاةَ وَتَحُجُّ الْبَيْتَ وَتَصُومُ رَمَضَانَ وَتُحِبُّ لِلنَّاسِ مَا تُحِبُّ أَنْ يُؤْتَى إِلَيْكَ وَتَكْرَهُ لَهُمْ مَا تَكْرَهُ أَنْ يُؤْتَى إِلَيْكَ خَلِّ عَنْ وُجُوهِ الرِّكَابِ","id":"Telah menceritakan kepada kami [Waki'] dari ['Amr bin Hassan] yaitu Al Musli, berkata; telah menceritakan kepada kami [Al Mughirah bin Abdullah Al Yaskuri] dari [bapaknya] berkata; saya masuk masjid Kufah ketika pertama kali dibangun, ketika itu berada di kebun-kebun pemilik kurma, dindingnya dari tanah liat. Tiba-tiba ada seorang laki-laki yang berbicara kepada orang-orang. Ia berkata; telah sampai kabar kepadaku rencana haji Rasulullah Shallallahu'alahiwasallam tepatnya haji wada'. Saya pun ingin mengikutinya dengan untaku, saya keluar sampai saya bisa duduk menunggu di sebuah jalan Arafah, atau saya menunggunya di jalan Arafah. (laki-laki itu) berkata; ternyata ada serombongan orang yang saya tahu persis bahwa Rasulullah Shallallahu'alahiwasallam bersamanya. Lalu ada seorang laki-laki di depan beliau yang berkata 'Kosongkanlah jalan untukku dari para penunggang.' Nabi Shallallahu'alaihiwasallam bersabda: \"Celakalah dia, apa hak dia?\" lalu saya mendekati beliau sehingga kepala dua unta kami bertemu. Saya berkata; \"Wahai Rasulullah, tunjukkan kepadaku suatu amal yang dapat memasukkanku ke surga dan menyelamatkanku dari api neraka?\" (Rasulullah Shallallahu'alahiwasallam) bersabda: \"Yah, yah, kamu telah meringkas isi khutbah, kamu menanyakan hal yang sangat mengena, kalau begitu, pahamilah. Kamu beribadah kepada Allah Azzawajalla dan kamu tidak menyekutukan-nya dengan suatu apapun, kamu mendirikan shalat, menunaikan zakat, berhaji ke Baitullah, serta puasa Ramadlan, berikanlah jalan untukku\". Telah menceritakan kepada kami [Waki'] dari [Yunus] berkata; saya mendengar hadis ini dari [Al Mughirah bin Abdullah] dari [bapaknya] sama yang di atas. Telah menceritakan kepada kami [Abdurrazzaq] berkata; telah menceritakan kepada kami [Ma'mar] dari [Abu Ishaq] dari [Al Mughirah bin Abdullah] dari [bapaknya] berkata; sampai selesai periwayatan hadis kepada [seorang laki-laki] yang bercerita tentang suatu kaum, lalu saya duduk, dia berkata; disebutkan sifat Rasulullah Shallallahu'alahiwasallam, dan saya berada di Mina untuk menuju ke Arafah, lalu menyebutkan hadits seperti diatas. Saya berkata; \"Wahai Rasulullah, kabarkanlah kepadaku suatu amalan yang mendekatkan diriku kepada surga dan menjauhkan diriku dari neraka\", beliau bersabda: \"Kamu mendirikan shalat, menunaikan zakat, berhaji ke Baitullah, puasa Ramadlan, serta kamu menyukai manusia memperoleh suatu hal yang menyenangkan sebagaimana jika diberikan kepadamu, dan kamu susah seandainya manusia mendapat suatu hal menyusahkan sebagaimana jika ditimpakan kepadamu, minggirlah dari jalan ini\"."},"698":{"ar":"حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ مُرَّةَ الطَّيِّبِ قَالَ حَدَّثَنِي رَجُلٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غُرْفَتِي هَذِهِ حَسِبْتُ قَالَخَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَو��مَ النَّحْرِ عَلَى نَاقَةٍ لَهُ حَمْرَاءَ مُخَضْرَمَةٍ فَقَالَ هَذَا يَوْمُ النَّحْرِ وَهَذَا يَوْمُ الْحَجِّ الْأَكْبَرِ","id":"Telah menceritakan kepada kami [Waki'] berkata; telah menceritakan kepada kami [Syu'bah] dari ['Amr bin Murrah] dari [Murrah Ath-Tayib] berkata; telah menceritakan kepadaku, [salah seorang sahabat] Nabi Shallallahu'alaihiwasallam di kamarku menurutku, dia berkata; Rasulullah Shallallahu'alahiwasallam berpidato kepada kami, pada Hari Nahr di atas untanya yang berwarna merah yang dipotong ujung telinganya, beliau bersabda: \"Sekarang ini adalah Hari Nahr (penyembelihan) dan ini adalah Hari Haji terbesar\""},"699":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا مَعْمَرٌ عَنْ أَبِي إِسْحَاقَ عَنْ أَبِي الْأَحْوَصِ الْجُشَمِيِّ عَنْ أَبِيهِ قَالَ رَآنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيَّ أَطْمَارٌ فَقَالَ هَلْ لَكَ مَالٌ قُلْتُ نَعَمْ قَالَ مِنْ أَيِّ الْمَالِ قُلْتُ مِنْ كُلِّ الْمَالِ قَدْ آتَانِي اللَّهُ عَزَّ وَجَلَّ مِنْ الشَّاءِ وَالْإِبِلِ قَالَ فَلْتُرَ نِعَمُ اللَّهِ وَكَرَامَتُهُ عَلَيْكَ فَذَكَرَ نَحْوَ حَدِيثِ شُعْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ قَالَ سَمِعْتُ أَبَا الْأَحْوَصِ يُحَدِّثُ عَنْ أَبِيهِ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا قَشِفُ الْهَيْئَةِ فَقَالَ هَلْ لَكَ مَالٌ قَالَ قُلْتُ نَعَمْ قَالَ مِنْ أَيِّ الْمَالِ قَالَ قُلْتُ مِنْ كُلِّ الْمَالِ مِنْ الْإِبِلِ وَالرَّقِيقِ وَالْخَيْلِ وَالْغَنَمِ فَقَالَ إِذَا آتَاكَ اللَّهُ مَالًا فَلْيُرَ عَلَيْكَ ثُمَّ قَالَ هَلْ تُنْتِجُ إِبِلُ قَوْمِكَ صِحَاحًا آذَانُهَا فَتَعْمَدُ إِلَى مُوسَى فَتَقْطَعُ آذَانَهَا فَتَقُولُ هَذِهِ بُحُرٌ وَتَشُقُّهَا أَوْ تَشُقُّ جُلُودَهَا وَتَقُولُ هَذِهِ صُرُمٌ وَتُحَرِّمُهَا عَلَيْكَ وَعَلَى أَهْلِكَ قَالَ نَعَمْ قَالَ فَإِنَّ مَا آتَاكَ اللَّهُ عَزَّ وَجَلَّ لَكَ وَسَاعِدُ اللَّهِ أَشَدُّ وَمُوسَى اللَّهِ أَحَدُّ وَرُبَّمَا قَالَ سَاعِدُ اللَّهِ أَشَدُّ مِنْ سَاعِدِكَ وَمُوسَى اللَّهِ أَحَدُّ مِنْ مُوسَاكَ قَالَ فَقُلْتُ يَا رَسُولَ اللَّهِ أَرَأَيْتَ رَجُلًا نَزَلْتُ بِهِ فَلَمْ يُكْرِمْنِي وَلَمْ يَقْرِنِي ثُمَّ نَزَلَ بِي أَجْزِيهِ بِمَا صَنَعَ أَمْ أَقْرِيهِ قَالَ اقْرِهِ","id":"Telah menceritakan kepada kami [Abdurrazzaq] berkata; telah mengabarkan kepada kami [Ma'mar] dari [Abu Ishaq] dari [Abu Al Ahwash Al Jusami] dari [bapaknya] berkata; Rasulullah Shallallahu'alahiwasallam melihatku ketika saya memakai kain yang lusuh, lalu beliau bersabda kepadaku, \"Apakah engkau mempunyai harta?\" saya menjawab, \"Ya\". Beliau bertanya, dari mana harta itu semua?. Saya menjawab, \"Harta itu dari segala macam, sebagaimana Allah Azzawajalla telah memberiku dari kambing dan unta\", beliau bersabda: \"Perlihatkanlah, bahwa Allah telah memberimu nikmAt Nya dan dermawan-Nya kepadamu. Lalu ia menyebutkan seperti hadits Syu'bah. Telah menceritakan kepada kami [Muhammad bin Jafar] berkata; telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] berkata saya telah mendengar [Abu Al Ahwas] menceritakan dari [Bapaknya] berkata; Saya mendatangi Rasulullah Shallallahu'alahiwasallam dalam keadaan yang amburadul, lalu beliau bertanya, \"Apakah engkau mempunyai harta?\" lalu saya jawab, Ya. Beliau bertanya, dari mana saja hartamu? Saya menjawab, \"Dari banyak jalan, dari unta, gandum, kuda dan kambing\". Beliau bersabda: \"Jika Allah memberimu harta, maka perlihatkanlah\", beliau bersabda: \"Apakah unta pada kaummu melahirkan dalam keadaan sehat telinganya, lalu kamu mengambil pemotong lalu kamu potong telinganya, lalu kalian berkilah ini adalah suatu penyakit, lalu kamu membelahnya atau membelah kulitnya, dan kau katakan ini adalah adalah unta yang terpotong telinganya dan kamu haramkan atas diri kalian dan atas keluarga kalian?. Mereka menjawab, ya. (Rasulullah Shallallahu'alahiwasallam) bersabda: \"Sesungguhnya apa yang Allah Azzawajalla berikan kepadamu, itu adalah bagian untukmu, dan lengan Allah itu lebih keras, gunting Allah lebih tajam daripada guntingmu\" (Bapaknya Abu Al Ahwas Radliyallahu'anhu) berkata; Wahai Rasulullah, bagaimana pendapat anda tentang seseorang yang saya menginap dirumahnya namun dia tidak memuliakanku, dan tidak menyambutku?. Lalu dia mampir ke tempatku apakah saya membalas sebagaimana yang dia perbuat terhadapku atau saya sambut dia dengan baik?. Beliau bersabda: \"Sambutlah dengan baik.\""},"700":{"ar":"حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا أَبِي وَإِسْرَائِيلُ عَنْ أَبِي إِسْحَاقَ عَنْ أَبِي الْأَحْوَصِ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ لَكَ مِنْ مَالٍ قَالَ قُلْتُ نَعَمْ مِنْ كُلِّ الْمَالِ قَدْ آتَانِي اللَّهُ عَزَّ وَجَلَّ مِنْ الْإِبِلِ وَمِنْ الْخَيْلِ وَالرَّقِيقِ قَالَ فَإِذَا آتَاكَ اللَّهُ عَزَّ وَجَلَّ خَيْرًا فَلْيُرَ عَلَيْكَ","id":"Telah menceritakan kepada kami [Waki'] berkata; telah menceritakan kepada kami [bapakku] dan [Isra'il] dari [Abu Ishaq] dari [Abu Al Ahwash] dari [Bapaknya] berkata; Rasulullah Shallallahu'alahiwasallam bersabda: \"Apakah kamu memiliki harta?\" Dia menjawab, Ya. Dari harta yang Allah Azzawajalla memberikannya kepadaku, dari unta, dari kuda dan dari budak. Beliau bersabda: \"Jika Allah Azzawajalla memberikan kebaikan maka perlihatkanlah\"."},"701":{"ar":"حَدَّثَنَا عُبَيْدَةُ بْنُ حُمَيْدٍ أَبُو عَبْدِ الرَّحْمَنِ التَّيْمِيُّ قَالَ حَدَّثَنَا أَبُو الزَّعْرَاءِ عَنْ أَبِي الْأَحْوَصِ عَنْ أَبِيهِ مَالِكِ بْنِ نَضْلَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْأَيْدِي ثَلَاثَةٌ فَيَدُ اللَّهِ الْعُلْيَا وَيَدُ الْمُعْطِي الَّتِي تَلِيهَا وَيَدُ السَّائِلِ السُّفْلَى فَأَعْطِ الْفَضْلَ وَلَا تَعْجَزْ عَنْ نَفْسِكَ","id":"Telah menceritakan kepada kami ['Ubaidah bin Humaid, Abu Abdurrahman At Taimi] berkata; telah menceritakan kepada kami [Abu Za'ra] dari [Abu Al Ahwash] dari [Bapaknya, Malik bin Nadlah] berkata; Rasulullah Shallallahu'alahiwasallam bersabda: \"Tangan itu ada tiga: Tangan Allah paling tinggi, tangan orang yang memberi dan ini berada di tengah, lalu tangan orang yang meminta yang paling bawah, maka berikanlah kelebihan dan janganlah merasa dirimu lemah\"."},"702":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا شُعْبَةُ قَالَ أَبُو إِسْحَاقَ أَنْبَأَنَا قَالَ سَمِعْتُ أَبَا الْأَحْوَصِ يُحَدِّثُ عَنْ أَبِيهِ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا قَشِيفُ الْهَيْئَةِ فَقَالَ هَلْ لَكَ مَالٌ قَالَ قُلْتُ نَعَمْ قَالَ فَمَا مَالُكَ فَقَالَ مِنْ كُلِّ الْمَالِ مِنْ الْخَيْلِ وَالْإِبِلِ وَالرَّقِيقِ وَالْغَنَمِ قَالَ فَإِذَا آتَاكَ اللَّهُ عَزَّ وَجَلَّ مَالًا فَلْيُرَ عَلَيْكَ فَقَالَ هَلْ تُنْتِجُ إِبِلُ قَوْمِكَ صِحَاحًا آذَانُهَا فَتَعْمَدُ إِلَى الْمُوسَى فَتَقْطَعُهَا أَوْ تَقْطَعُهَا وَتَقُولُ هَذِهِ بُحُرٌ وَتَشُقُّ جُلُودَهَا وَتَقُولُ هَذِهِ صُرُمٌ فَتُحَرِّمُهَا عَلَيْكَ وَعَلَى أَهْلِكَ قَالَ قُلْتُ نَعَمْ قَالَ كُلُّ مَا آتَاكَ اللَّهُ عَزَّ وَجَلَّ لَكَ حِلٌّ وَسَاعِدُ اللَّهِ أَشَدُّ وَمُوسَى اللَّهِ أَحَدُّ وَرُبَّمَا قَالَهَا وَرُبَّمَا لَمْ يَقُلْهَا وَرُبَّمَا قَالَ سَاعِدُ اللَّهِ أَشَدُّ مِنْ سَاعِدِكَ وَمُوسَى اللَّهِ أَحَدُّ مِنْ مُوسَاكَ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ رَجُلٌ نَزَلْتُ بِهِ فَلَمْ يَقْرِنِي وَلَمْ يُكْرِمْنِي ثُمَّ نَزَلَ بِي أَقْرِيهِ أَوْ أَجْزِيهِ بِمَا صَنَعَ قَالَ بَلْ اقْرِهِ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Syu'bah] [Abu Ishaq] berkata; telah memberitakan kepada kami, berkata; saya telah mendengar [Abu Al Ahwash] menceritakan dari [Bapaknya] berkata; saya menemui Nabi Shallallahu'alaihiwasallam dan saya keadaan sangat acak-acakan. Lalu beliau bertanya, \"Apakah engkau mempunyai harta?\" lalu saya menjawab, \"Ya\". Beliau bertanya, apa hartamu itu? Saya menjawab, \"Harta itu dari segala macam, dari kuda, dari unta, dari budak dan dari kambing \", beliau bersabda: \"Jika Allah Azzawajalla memberimu harta, tolong perlihatkanlah\". Lalu beliau bersabda: \"Apakah unta pada kaummu melahirkan dalam keadaan sehat telinganya, lalu kamu mengambil pemotong dan kamu potong telinganya, lalu kalian berkilah ini adalah suatu penyakit, lalu kamu membelahnya atau membelah kulitnya, dan kau katakan ini adalah adalah unta yang terpotong telinganya dan kamu haramkan atas dirimu dan atas keluargamu?. Saya menjawab, ya. (Rasulullah Shallallahu'alahiwasallam) bersabda: \"Sesungguhnya apa yang Allah Azzawajalla berikan kepadamu adalah halal bagimu, dan lengan Allah itu lebih keras, gunting Allah lebih tajam\" Terkadang menyebutnya dan terkadang tidak. Terkadang menyebutkan lengan Allah lebih keras daripada lenganmu, dan pemotong Allah lebih tajam daripada pemotongmu. (Bapaknya Abu Al Ahwas Radliyallahu'anhu) berkata; saya berkata; Wahai Rasulullah, bagaimana pendapat anda tentang seseorang yang saya menginap di rumahnya namun dia tidak memuliakanku, dan tidak menyambutku. Lalu dia mampir ke tempatku apakah saya membalas sebagaimana yang dia perbuat terhadapku atau saya sambut dia dengan baik?. Beliau bersabda: Sambutlah dengan baik\"."},"703":{"ar":"حَدَّثَنَا بَهْزُ بْنُ أَسَدٍ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ قَالَ أَخْبَرَنَا عَبْدُ الْمَلِكِ بْنُ عُمَيْرٍ عَنْ أَبِي الْأَحْوَصِأَنَّ أَبَاهُ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ أَشْعَثُ سَيِّئُ الْهَيْئَةِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا لَكَ مَالٌ قَالَ مِنْ كُلِّ الْمَالِ قَدْ آتَانِي اللَّهُ عَزَّ وَجَلَّ قَالَ فَإِنَّ اللَّهَ عَزَّ وَجَلَّ إِذَا أَنْعَمَ عَلَى عَبْدٍ نِعْمَةً أَحَبَّ أَنْ تُرَى عَلَيْهِ","id":"Telah menceritakan kepada kami [Bahz bin 'Asad] berkata; telah menceritakan kepada kami [Hammad bin Salamah] berkata; telah mengabarkan kepada kami [Abdul Malik bin 'Umair] dari [Abu Al Ahwash] dari Bapaknya menemui Nabi Shallallahu'alaihiwasallam dan dia dalam kedaan berdebu dan sangat jelek keadaannya. Lalu Rasulullah Shallallahu'alahiwasallam bersabda kepadanya, tidak adakah harta padamu? Dia menjawab, dari setiap harta sungguh Allah Azzawajalla telah memberikan kepadaku. Beliau bersabda: \"Allah Azzawajalla jika memberi nikmat kepada hamba-Nya suka jika diperlihatkannya\"."},"704":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا ابْنُ أَبِي خَالِدٍ يَعْنِي إِسْمَاعِيلَ عَنْ أَبِيهِ قَالَدَخَلْتُ عَلَى رَجُلٍ وَهُوَ يَتَمَجَّعُ لَبَنًا بِتَمْرٍ فَقَالَ ادْنُ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمَّاهُمَا الْأَطْيَبَيْنِ","id":"Telah menceritakan kepada kami [Waki'] dari [Ibnu Abu Khalid] yaitu Isma'il, dari [Bapaknya] berkata; Saya menemui [seorang laki-laki yang sedang makan kurma] dengan susu, maka (Ismail Radliyallahu'anhu) berkata; \"Mendekatlah, sesungguhnya Rasulullah Shallallahu'alahiwasallam menamakan kedua barang tersebut (kurma dan susu) dengan dua yang paling baik\""},"705":{"ar":"حَدَّثَنَا حَسَنُ بْنُ مُوسَى قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ زَاذَانَ أَبِي عُمَرَ قَالَ حَدَّثَنِي مَنْ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَيَقُولُ مَنْ لُقِّنَ عِنْدَ الْمَوْتِ لَا إِلَهَ إِلَّا اللَّهُ دَخَلَ الْجَنَّةَ","id":"Telah menceritakan kepada kami [Hasan bin Musa] berkata; telah menceritakan kepada kami [Hammad bin Salamah bin Sa'ib] dari [Atho' bin Sa'ib] dari [Zadan Abu 'Umar] berkata; telah menceritakan kepadaku [seseorang yang mendengar Nabi] Shallallahu'alaihiwasallam bersabda: \"Barangsiapa yang di ditalqin pada waktu menjelang mati dengan LAA ILAAHA ILLAHLAAH, dia masuk surga\""},"706":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ عَطَاءٍ يَعْنِي ابْنَ السَّائِبِ عَنْ رَجُلٍ مِنْ بَكْرِ بْنِ وَائِلٍ عَنْ خَالِهِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَعْشِرُ قَوْمِي قَالَ إِنَّمَا الْعُشُورُ عَلَى الْيَهُودِ وَالنَّصَارَى وَلَيْسَ عَلَى أَهْلِ الْإِسْلَامِ عُشُورٌ","id":"Telah menceritakan kepada kami [Abdurrahman] dari [Sufyan] dari ['Atho'] yaitu Ibnu As-Sa'ib dari [seseorang dari Bakr bin Wa'il] dari [pamannya] berkata; saya berkata; Wahai Rasulullah, apakah saya mengambil sepersepuluh harta kaumku?. Beliau bersabda: \"Sesungguhnya sepersepuluh itu hanya pada orang Yahudi dan Nasrani. Tidak ada pada pemeluk Islam diambil sepersepuluh\"."},"707":{"ar":"قَالَ حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ عَطَاءٍ عَنْ حَرْبِ بْنِ عُبَيْدِ ال��َّهِ الثَّقَفِيِّ عَنْ خَالِهِ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ لَهُ أَشْيَاءَ فَسَأَلَهُ فَقَالَ أَعْشِرُهَا فَقَالَ إِنَّمَا الْعُشُورُ عَلَى الْيَهُودِ وَالنَّصَارَى وَلَيْسَ عَلَى أَهْلِ الْإِسْلَامِ عُشُورٌ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari ['Atho'] dari [Harab 'Ubaidullah Ats-Staqafi] dari [pamannya] berkata; saya menemui Nabi Shallallahu'alaihiwasallam lalu disebutkan pada beliau sesuatu, pamanku bertanya kepada beliau dengan berkata; 'Apakah saya mengambil sepersepuluhnya?. Beliau bersabda: \"Sesungguhnya sepersepuluh itu hanya pada orang Yahudi dan Nasrani. Tidak ada pada pemeluk Islam diambil sepersepuluh hartanya\"."},"708":{"ar":"حَدَّثَنَا جَرِيرٌ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ حَرْبِ بْنِ هِلَالٍ الثَّقَفِيِّ عَنْ أَبِي أُمِّهِ رَجُلٌ مِنْ بَنِي تَغْلِبَ أَنَّهُسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَيْسَ عَلَى الْمُسْلِمِينَ عُشُورٌ إِنَّمَا الْعُشُورُ عَلَى الْيَهُودِ وَالنَّصَارَى","id":"Telah menceritakan kepada kami [Jarir] dari ['Atho' bin As-Sa'ib] dari [Harb bin Hilal Ats-Atsaqafi] dari [Bapak dari ibunya], yaitu seorang laki-laki dari Bani Taghlib, sesungguhnya telah mendengar Nabi Shallallahu'alaihiwasallam bersabda: \"Tidak ada atas kaum muslimin sepersepuluh Sesungguhnya sepersepuluh itu hanya pada orang Yahudi dan Nasrani\"."},"709":{"ar":"حَدَّثَنَا مُعَاوِيَةُ بْنُ عَمْرٍو قَالَ حَدَّثَنَا زَائِدَةُ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ بَعْضِ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِرَجُلٍ كَيْفَ تَقُولُ فِي الصَّلَاةِ قَالَ أَتَشَهَّدُ ثُمَّ أَقُولُ اللَّهُمَّ إِنِّي أَسْأَلُكَ الْجَنَّةَ وَأَعُوذُ بِكَ مِنْ النَّارِ أَمَا إِنِّي لَا أُحْسِنُ دَنْدَنَتَكَ وَلَا دَنْدَنَةَ مُعَاذٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَوْلَهَا نُدَنْدِنُ","id":"Telah menceritakan kepada kami [Mu'awiyah bin 'Amr] berkata; telah menceritakan kepada kami [Za'idah] dari [Al 'Amsy] dari [Abu Shalih] dari [sebagian sahabat] Nabi Shallallahu'alaihiwasallam berkata; Nabi Shallallahu'alaihiwasallam bertanya kepada seorang laki-laki, \"Apa yang kau ucapkan dalam Shalat\", maka dia menjawab, \"Saya bersyahadat lalu saya mengucapkan, 'Ya Allah, sesungguhnya saya meminta kepada-Mu surga dan berlindung diri kepada-Mu dari api neraka', saya tidak begitu tahu tentang yang ucapkan anda secara komat kamit apa yang dibaca Mu'adz\". Nabi Shallallahu'alaihiwasallam bersabda: \"Kurang lebih sebagaimana yang kau baca\"."},"710":{"ar":"حَدَّثَنَا بَهْزٌ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي عَبْدُ الْمَلِكِ بْنُ مَيْسَرَةَ قَالَ سَمِعْتُ كُرْدُوسًا قَالَ أَخْبَرَنِي رَجُلٌ مِنْ أَصْحَابِ بَدْرٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَأَنْ أَقْعُدَ فِي مِثْلِ هَذَا الْمَجْلِسِ أَحَبُّ إِلَيَّ مِنْ أَنْ أُعْتِقَ أَرْبَعَ رِقَابٍ","id":"Telah menceritakan kepada kami [Bahz] telah menceritakan kepada kami [Syu'bah] berkata; telah menceritakan kepadaku [Abdul Malik bin Maisarah] berkata; saya mendengar [Kurdus] berkata; telah mengabarkan kepadaku [salah seorang ahli Badar], dari Rasulullah Shallallahu'alahiwasallam bersabda: \"Duduk dalam suatu majlis semacam ini lebih saya senangi dari pada membebaskan empat orang budak.\""},"711":{"ar":"حَدَّثَنَا هَاشِمٌ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الْمَلِكِ بْنِ مَيْسَرَةَ قَالَ سَمِعْتُ كُرْدُوسَ بْنَ قَيْسٍ وَكَانَ قَاصَّ الْعَامَّةِ بِالْكُوفَةِ قَالَ أَخْبَرَنِي رَجُلٌ مِنْ أَصْحَابِ بَدْرٍ أَنَّهُسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَأَنْ أَقْعُدَ فِي مِثْلِ هَذَا الْمَجْلِسِ أَحَبُّ إِلَيَّ مِنْ أَنْ أُعْتِقَ أَرْبَعَ رِقَابٍقَالَ شُعْبَةُ فَقُلْتُ أَيَّ مَجْلِسٍ تَعْنِي قَالَ كَانَ قَاصًّا","id":"Telah menceritakan kepada kami [Hasyim] telah menceritakan kepada kami [Syu'bah] dari [Abdul Malik bin Maisarah] berkata; saya telah mendengar [Kurdus bin Qais] dia adalah orang yang bercerita secara umum di Kufah, berkata; telah mengabarkan kepadaku [salah seorang Ahli Badar], ia mendengar Nabi Shallallahu'alaihiwasallam bersabda: \"Duduk dalam suatu majlis semacam ini lebih saya senangi dari pada membebaskan empat orang budak\" Syu'bah berkata; sasya bertanya, majlis apakah yang kau maksud?, dia menjawab, yaitu majlis tentang kisah atau nasehat."},"712":{"ar":"حَدَّثَنَا أَبُو الْجَوَّابِ حَدَّثَنَا عَمَّارُ بْنُ رُزَيْقٍ عَنْ عَطَاءِ بْنِ السَّائِبِ قَالَ حَدَّثَنِي نَفَرٌ مِنْ أَهْلِ الْبَصْرَةِ مِنْهُمْ الْحَسَنُ عَنْ مَعْقِلِ بْنِ سِنَانٍ الْأَشْجَعِيِّ أَنَّهُ قَالَمَرَّ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا أَحْتَجِمُ فِي ثَمَانِ عَشْرَةَ لَيْلَةً خَلَتْ مِنْ شَهْرِ رَمَضَانَ فَقَالَ أَفْطَرَ الْحَاجِمُ وَالْمَحْجُومُ","id":"Telah menceritakan kepada kami [Abu Al Jawwab] telah menceritakan kepada kami ['Ammar bin Ruzaiq] dari [Atha' bin Saib] berkata; telah menceritakan kepadaku beberapa orang dari penduduk Bashrah di antaranya [Al Hasan] dari [Ma'qil bin Sinan Al Asyja'i] sesungguhnya dia berkata; Rasulullah Shallallahu'alahiwasallam melewatiku ketika saya sedang berbekam pada malam ke delapan belas dari bulan Ramadlan, beliau bersabda: \" Orang yang membekam dan dibekam berarti telah batal puasanya\"."},"713":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَاصِمٍ قَالَ خَالِدٌ الْحَذَّاءُ أَخْبَرَنِي عَنْ أَبِي قِلَابَةَ عَنْ عَمْرِو بْنِ سَلِمَةَ قَالَكَانَ تَأْتِينَا الرُّكْبَانُ مِنْ قِبَلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَسْتَقْرِئُهُمْ فَيُحَدِّثُونَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِيَؤُمَّكُمْ أَكْثَرُكُمْ قُرْآنًا","id":"Telah menceritakan kepada kami ['Ali bin 'Ashim] [khalid Al Hadza'] berkata; telah mengabarkan kepadaku, dari [Abu Qilabah] dari ['Amr bin Salimah] berkata; datang kepada kami [para penunggang kuda] selepas bertemu Rasulullah Shallallahu'alahiwasallam, kami meminta mereka untuk melantunkan bacaan alquran untuk kami, lalu mereka menceritakan kepada kami bahwa Rasulullah Shallallahu'alahiwasallam bersabda: 'Hendaklah yang menjadi imam di antara kalian adalah yang paling banyak hafalan Qur'annya\""},"714":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ عِيسَى قَالَ أَخْبَرَنِي مَالِكٌ عَنْ سُمَيٍّ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ عَنْ بَعْضِ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ النَّاسَ بِالْفِطْرِ عَامَ الْفَتْحِ وَقَالَ تَقَوَّوْا لِعَدُوِّكُمْ وَصَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو بَكْرٍ قَالَ الَّذِي حَدَّثَنِي لَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْعَرْجِ يَصُبُّ عَلَى رَأْسِهِ الْمَاءَ مِنْ الْعَطَشِ أَوْ مِنْ الْحَرِّ ثُمَّ قِيلَ يَا رَسُولَ اللَّهِ إِنَّ طَائِفَةً مِنْ النَّاسِ قَدْ صَامُوا حِينَ صُمْتَ فَلَمَّا كَانَ بِالْكَدِيدِ دَعَا بِقَدَحٍ فَشَرِبَ فَأَفْطَرَ النَّاسُ","id":"Telah menceritakan kepada kami [Ishaq bin 'Isa] berkata; telah mengabarkan kepadaku [Malik] dari [Suma] dari [Abu Bakr bin Abdurrahman bin Al Harits bin Hisyam] dari [sebagian sahabat Nabi Shallallahu'alaihiwasallam], Rasulullah Shallallahu'alahiwasallam memerintahkan kepada manusia pada Fathul Makkah untuk berbuka puasa, beliau bersabda: \"Perlihatkanlah kekuatan kalian di hadapan musuh kalian\". Sedangkan Rasulullah Shallallahu'alahiwasallam berpuasa pada hari itu. Abu Bakar berkata; telah berkata orang yang menceritakan kepadaku, sungguh saya melihat Rasulullah Shallallahu'alahiwasallam berhenti dan menuangkan air di atas kepalanya, karena rasa haus atau panas. Lalu ada yang bertanya, Wahai Rasulullah, sesungguhnya sebagian kelompok sahabat berpuasa ketika anda berpuasa, ketika sampai di Kadid, beliau meminta bejana air minum lalu meminumnya, maka para sahabAt pun membatalkan puasanya."},"715":{"ar":"قَالَ حَدَّثَنَا أَبُو أَحْمَدَ مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الزُّبَيْرِيُّ حَدَّثَنَا سَعْدٌ يَعْنِي ابْنَ أَوْسٍ الْعَبْسِيَّ عَنْ بِلَالٍ الْعَبْسِيِّ قَالَ أَخْبَرَنَا عِمْرَانُ بْنُ حُصَيْنٍ الضَّبِّيُّأَنَّهُ أَتَى الْبَصْرَةَ وَبِهَا عَبْدُ اللَّهِ بْنُ عَبَّاسٍ أَمِيرًا فَإِذَا هُوَ بِرَجُلٍ قَائِمٍ فِي ظِلِّ الْقَصْرِ يَقُولُ صَدَقَ اللَّهُ وَرَسُولُهُ صَدَقَ اللَّهُ وَرَسُولُهُ لَا يَزِيدُ عَلَى ذَلِكَ فَدَنَوْتُ مِنْهُ شَيْئًا فَقُلْتُ لَهُ لَقَدْ أَكْثَرْتَ مِنْ قَوْلِكَ صَدَقَ اللَّهُ وَرَسُولُهُ فَقَالَ أَمَا وَاللَّهِ لَئِنْ شِئْتَ لَأَخْبَرْتُكَ فَقُلْتُ أَجَلْ فَقَالَ اجْلِسْ إِذًا فَقَالَ إِنِّي أَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ بِالْمَدِينَةِ فِي زَمَانِ كَذَا وَكَذَا وَقَدْ كَانَ شَيْخَانِ لِلْحَيِّ قَدْ انْطَلَقَ ابْنٌ لَهُمَا فَلَحِقَ بِهِ فَقَالَا إِنَّكَ قَادِمٌ الْمَدِينَةَ وَإِنَّ ابْنًا لَنَا قَدْ لَحِقَ بِهَذَا الرَّجُلِ فَأْتِهِ فَاطْلُبْهُ مِنْهُ فَإِنْ أَبَى إِلَّا الِافْتِدَاءَ فَافْتَدِهِ فَأَتَيْتُ الْمَدِينَةَ فَدَخَلْتُ عَلَى نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا نَبِيَّ اللَّهِ إِنَّ شَيْخَيْنِ لِلْحَيِّ أَمَرَانِي أَنْ أَطْلُبَ ابْنًا لَهُمَا عِنْدَكَ فَقَالَ تَعْرِفُهُ فَقَالَ أَعْرِفُ نَسَبَهُ فَدَعَا الْغُلَامَ فَجَاءَ فَقَالَ هُوَ ذَا فَأْتِ بِهِ أَبَوَيْهِ فَقُلْتُ الْفِدَاءَ يَا نَبِيَّ اللَّهِ قَالَ إِنَّهُ لَا يَصْلُحُ لَنَا آلُ مُحَمَّدٍ أَنْ نَأْكُلَ ثَمَنَ أَحَدٍ مِنْ وَلَدِ إِسْمَاعِيلَ ثُمَّ ضَرَبَ عَلَى كَتِفِي ثُمَّ قَالَ لَا أَخْشَى عَلَى قُرَيْشٍ إِلَّا أَنْفُسَهَا قُلْتُ وَمَا لَهُمْ يَا نَبِيَّ اللَّهِ قَالَ إِنْ طَالَ بِكَ الْعُمُرُ رَأَيْتَهُمْ هَاهُنَا حَتَّى تَرَى النَّاسَ بَيْنَهُمَا كَالْغَنَمِ بَيْنَ حَوْضَيْنِ مَرَّةً إِلَى هَذَا وَمَرَّةً إِلَى هَذَافَأَنَا أَرَى نَاسًا يَسْتَأْذِنُونَ عَلَى ابْنِ عَبَّاسٍ رَأَيْتُهُمْ الْعَامَ يَسْتَأْذِنُونَ عَلَى مُعَاوِيَةَ فَذَكَرْتُ مَا قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Ahmad, Muhammad bin Abdullah Az Zubairi] telah menceritakan kepada kami [Sa'd] yaitu Ibnu Aus Al 'Abasi dari [Bilal Al 'Abasi] berkata; telah mengabarkan kepada kami ['Imran bin Husain Adzabby], dia datang ke Bashrah, pada waktu itu Abdullah bin Abbas menjabat sebagai Amir di wilayah itu. Tiba-tiba ada [seorang laki-laki] yang berdiri disamping istana dan berkata; \"BenAr lah Allah dan Rasul-Nya, BenAr lah Allah dan Rasul-Nya\", tidak menambah apapun kalimat tersebut, lalu saya mendekatinya dan berkata padanya, \"Engkau banyak menyebut lafadz, 'Benarlah Allah dan Rasul-Nya' mengapa? dia menjawab, Demi Allah kalau kamu mau, saya akan beritahukan kepadamu. Saya menjawab, Ya. dia berkata; duduklah. Dia berkata; saya pernah mendatangi Rasulullah Shallallahu'alahiwasallam di Madinah pada suatu waktu ini dan itu, ada dua orang tua dari suatu desa, anak mereka berdua telah pergi dan anak tersebut menemui Rasulullah shallallahu'alaihi wasallam. Kedua orang tua tersebut lantas berkata kepada saya 'Sesungguhnya kamu telah sampai di Madinah ini, sedang anak kami telah menyusul orang ini (Maksudnya nabi Shallallahu 'alaihi wa Salam Muhammad), maka bawalah kemari dan mintalah dia. Jika dia menolak kecuali harus dengan tebusan maka tebuslah. Lalu saya pergi ke Madinah untuk menemui Nabiyullah ShallallahuAlaihiWasallam. Saya sampaikan, 'Wahai Nabiyullah, ada dua orang tua yang dari desa, keduanya menyuruhku untuk meminta anak mereka berdua yang bersama anda. Beliau bertanya, 'Kamu mengenalnya?. Orang itu berkata; 'Saya mengenal nasabnya', dia lantas memanggil anak yang dimaksud, dan anak itu pun datang. Beliau bersabda: \"Ini orangnya, bawalah kepada kedua orang tunya\". Lalu saya bertanya, 'Apakah dengan tebusan Wahai Nabiyullah?\" Beliau bersabda: \"Sesungguhnya tidak selayaknya bagi keluarga Muhammad memakan hasil penjualan orang dari keturunan Isma'il\", lalu beliau memukul pundakku, dan bersabda: \"Saya tidak khawatir terhadap Quraisy kecuali diri mereka\" Saya bertanya, kenapa demikian Wahai Nabiyullah?. Beliau menjawab, jika umurmu panjang maka kamu akan melihatnya di sini, sehingga kamu melihat manusia antara keduanya seperti antara dua telaga, sekali pergi ke sini dan sekali pergi ke sana. Lalu saya melihat orang-orang meminta ijin kepada Ibnu 'Abbas. Di kemudian hari saya melihat mereka meminta ijin kepada Ibnu Abbas lalu saya sebutkan apa yang telah disabdakan Nabi Shallallahu'alaihiwasallam."},"716":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ إِسْحَاقَ حَدَّثَنَا عَبْدُ اللَّهِ يَعْنِي ابْنَ مُبَارَكٍ قَالَ أَخْبَرَنَا سَعِيدُ بْنُ يَزِيدَ وَهُوَ أَبُو شُجَاعٍ قَالَ سَمِعْتُ الْحَارِثَ بْنَ يَزِيدَ الْحَضْرَمِيَّ يُحَدِّثُ عَنْ عَلِيِّ بْنِ رَبَاحٍ عَنْ نَاشِرَةَ بْنِ سُمَيٍّ الْيَزَنِيِّ قَالَسَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ تَعَالَى عَنْهُ يَقُولُ فِي يَوْمِ الْجَابِيَةِ وَهُوَ يَخْطُبُ النَّاسَ إِنَّ اللَّهَ عَزَّ وَجَلَّ جَعَلَنِي خَازِنًا لِهَذَا الْمَالِ وَقَاسِمَهُ لَهُ ثُمَّ قَالَ بَلْ اللَّهُ يَقْسِمُهُ وَأَنَا بَادِئٌ بِأَهْلِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ أَشْرَفِهِمْ فَفَرَضَ لِأَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَشْرَةَ آلَافٍ إِلَّا جُوَيْرِيَةَ وَصَفِيَّةَ ومَيْمُونَةَ فَقَالَتْ عَائِشَةُ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَعْدِلُ بَيْنَنَا فَعَدَلَ بَيْنَهُنَّ عُمَرُ ثُمَّ قَالَ إِنِّي بَادِئٌ بِأَصْحَابِي الْمُهَاجِرِينَ الْأَوَّلِينَ فَإِنَّا أُخْرِجْنَا مِنْ دِيَارِنَا ظُلْمًا وَعُدْوَانًا ثُمَّ أَشْرَفِهِمْ فَفَرَضَ لِأَصْحَابِ بَدْرٍ مِنْهُمْ خَمْسَةَ آلَافٍ وَلِمَنْ كَانَ شَهِدَ بَدْرًا مِنْ الْأَنْصَارِ أَرْبَعَةَ آلَافٍ وَلِمَنْ شَهِدَ أُحُدًا ثَلَاثَةَ آلَافٍ قَالَ وَمَنْ أَسْرَعَ فِي الْهِجْرَةِ أَسْرَعَ بِهِ الْعَطَاءُ وَمَنْ أَبْطَأَ فِي الْهِجْرَةِ أَبْطَأَ بِهِ الْعَطَاءُ فَلَا يَلُومَنَّ رَجُلٌ إِلَّا مُنَاخَ رَاحِلَتِهِ وَإِنِّي أَعْتَذِرُ إِلَيْكُمْ مِنْ خَالِدِ بْنِ الْوَلِيدِ إِنِّي أَمَرْتُهُ أَنْ يَحْبِسَ هَذَا الْمَالَ عَلَى ضَعَفَةِ الْمُهَاجِرِينَ فَأَعْطَى ذَا الْبَأْسِ وَذَا الشَّرَفِ وَذَا اللَّسَانَةِ فَنَزَعْتُهُ وَأَمَّرْتُ أَبَا عُبَيْدَةَ بْنَ الْجَرَّاحِ فَقَالَ أَبُو عَمْرِو بْنُ حَفْصِ بْنِ الْمُغِيرَةِ وَاللَّهِ مَا أَعْذَرْتَ يَا عُمَرُ بْنَ الْخَطَّابِ لَقَدْ نَزَعْتَ عَامِلًا اسْتَعْمَلَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَغَمَدْتَ سَيْفًا سَلَّهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَوَضَعْتَ لِوَاءً نَصَبَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَقَدْ قَطَعْتَ الرَّحِمَ وَحَسَدْتَ ابْنَ الْعَمِّ فَقَالَ عُمَرُ بْنُ الْخَطَّابِ إِنَّكَ قَرِيبُ الْقَرَابَةِ حَدِيثُ السِّنِّ مُغْضَبٌ مِنْ ابْنِ عَمِّكَ","id":"Telah menceritakan kepada kami ['Ali bin Ishaq] telah menceritakan kepada kami [Abdullah] yaitu Ibnu Mubarak, berkata; telah mengabarkan kepada kami [Sa'id bin Yazid] yaitu Abu Syuja', berkata; saya telah mendengar [Al Harits bin Yazid Al Hadlrami] menceritakan dari ['Ali bin Rabah] dari [Nasyirah bin Sumay Al Yazani] berkata; saya telah mendengar 'Umar bin Khattab Radliyallahu'anhu pada Peristiwa Hudaibiyah, berkhotbah di hadapan manusia, ' Allah Azzawajalla telah menjadikanku penjaga harta ini dan yang berhak untuk membagikannya. Lalu berkata; sungguh Allah-lah yang membaginya, saya memulai pembagian ini untuk keluarga Nabi Shallallahu'alaihiwasallam, selanjutnya yang terdekat dengan mereka. Dia pun lantas membagi untuk para istri Nabi Shallallahu'alaihiwasallam sebesar sepuluh ribu kecuali Juwairiyah, Shafiyyah dan Maimunah. Kata 'Aisyah, Rasulullah Shallallahu'alahiwasallam berbuat adil terhadap kami, 'Umar pun membaginya dengan adil. Lalu dia berkata; saya akan membaginya kepada para sahabatku dari kalangan Muhajirin generasi pertama, karena kami telah diusir dari rumah-rumah karena didhalimi dan dimusuhi. Diikuti orang yang terdekat dengan mereka. Mula-mula dia membagi kepada pengikut Perang Badar, mereka mendapatkan lima ribu. Dan Kaum Anshar yang mengikuti Perang Badar, mendapatkan empat ribu. Orang yang ikut pada perang uhud mendapatkan tiga ribu. ('Umar Radliyallahu'anhu) berkata; Siapa yang dahulu bersegera dalam berhijrah, dia mendapatkan pemberian lebih cepat dari yang berhijrah setelahnya. Maka janganlah ada yang mencela kecuali karena sesuatu dalam pelana kudanya, saya memohon ampun atas apa yang saya lakukan terhadap Khalid bin Walid, karena saya memerintahkannya untuk menahan semua harta ini untuk kalangan yang lemah dari kaum Muhajirin, tapi dia malah memberikan harta ini kepada orang yang mempunyai kekuatan, kemuliaan dan yang fasih bicara, sehingga saya memecatnya lalu saya angkat Abu 'Ubaidah bin Al Jarrah sebagai pimpinan. Lalu ['Amr bin Hafsh bin Al Mughirah] berkata; \"Demi Allah, wahai 'Umar bin Al Khattab, engkau tidak bisa beralasan, karena kamu telah memecat pekerja yang telah diangkat oleh Rasulullah Shallallahu'alahiwasallam, kamu telah menyarungkan kembali pedang yang telah Rasulullah Shallallahu'alahiwasallam menghunuskannya, kamu telah mencabut bendera yang telah ditancapkan Rasulullah Shallallahu'alahiwasallam, kamu telah memutus silaturahmi dan kamu dengki kepada anak pamanku. 'Umar bin Khattab berkata; \"Sesunguhnya kamu orang yang dekat persaudarannya, masih muda umurnya, kamu marah atas apa yang telah menimpa sepupumu\""},"717":{"ar":"حَدَّثَنَا أَبُو أَحْمَدَ الزُّبَيْرِيُّ حَدَّثَنَا أَبُو النُّعْمَانِ عَبْدُ الرَّحْمَنِ بْنِ النُّعْمَانِ الْأَنْصَارِيُّ عَنْ أَبِيهِ عَنْ جَدِّهِ وَكَانَ قَدْ أَدْرَكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اكْتَحِلُوا بِالْإِثْمِدِ الْمُرَوَّحِ فَإِنَّهُ يَجْلُو الْبَصَرَ وَيُنْبِتُ الشَّعْرَ","id":"Telah menceritakan kepada kami [Abu Ahmad Az Zubari] telah menceritakan kepada kami [Abu Nu'man Abdurrahman bin Nu'man Al Anshori] dari [Bapaknya] dari [kakeknya] dia mendapati masa Nabi Shallallahu'alaihiwasallam berkata; Rasulullah Shallallahu'alahiwasallam bersabda: \"Pakailah celak kalian semua dengan memakai Itsmid (bahan celak yang terbaik) yang bercampur dengan wangi-wangian, sesungguhnya hal tersebut dapat membuat penglihatan menjadi terang dan menumbuhkan rambut\"."},"718":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا حَرْبُ بْنُ شَدَّادٍ حَدَّثَنَا يَحْيَى يَعْنِي ابْنَ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي نَحَّازُ بْنُ جُدَيٍّ الْحَنَفِيُّ عَنْ سِنَانِ بْنِ سَلَمَةَ أَنَّ أَبَاهُ حَدَّثَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِالْقُدُورِ فَأُكْفِئَتْ يَوْمَ خَيْبَرَ وَكَانَ فِيهَا لُحُومُ حُمُرِ النَّاسِ","id":"Telah menceritakan kepada kami [Abdushamad] dari [Harb bin Syadad] telah menceritakan kepada kami [Yahya bin Abu Katsir] berkata; telah menceritakan kepadaku [Nahhaz bin Juda Al Hanafi] dari [Sinan bin Salamah] sesungguhnya [bapaknya] menceritakan, Rasulullah Shallallahu'alahiwasallam meminta kuali lalu ditumpahkan pada Peristiwa Khaibar yang isinya terdapat daging keledai."},"719":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا هِشَامٌ وَهَمَّامٌ عَنْ قَتَادَةَ عَنِ الْحَسَنِ عَنْ جَوْنِ بْنِ قَتَادَةَ عَنْ سَلَمَةَ بْنِ الْمُحَبِّقِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِبَيْتٍ بِفِنَائِهِ قِرْبَةٌ مُعَلَّقَةٌ فَاسْتَسْقَى فَقِيلَ إِنَّهَا مَيْتَةٌ قَالَ ذَكَاةُ الْأَدِيمِ دِبَاغُهُ","id":"Telah menceritakan kepada kami [Abdushamad] telah menceritakan kepada kami [Hisyam] dan [Hammam] dari [Qatadah] dari [Al Hasan] dari [Jaun bin Qatadah] dari [Salamah bin Al Mujabbiq], Rasulullah Shallallahu'alahiwasallam melewati suatu rumah yang dalam terasnya terdapat ada gerimba dari kulit yang tergantung, beliau meminta air, lalu ada yang menjawab, itu adalah bangkai. Beliau bersabda: \"Penyembelihan secara syar'i pada kulit yang disamak adalah dengan menyamaknya\"."},"720":{"ar":"حَدَّثَنَا عَمْرُو بْنُ الْهَيْثَمِ أَبُو قَطَنٍ قَالَ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنِ الْحَسَنِ عَنْ جَوْنِ بْنِ قَتَادَةَ عَنْ سَلَمَةَ بْنِ الْمُحَبِّقِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دِبَاغُهَا طُهُورُهَا أَوْ ذَكَاتُهَا","id":"Telah menceritakan kepada kami ['Amr bin Al Haitsam, Abu Qathan] berkata; telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Al Hasan] dari [Jaun bin Qatadah] dari [Salamah bin Al Muhabbiq] dari Rasulullah Shallallahu'alahiwasallam, penyamakannya adalah penyuciannya atau penyembilahan secara syar'inya."},"721":{"ar":"حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا الْفَضْلُ بْنُ دَلْهَمٍ عَنْ الْحَسَنِ عَنْ قَبِيصَةَ بْنِ حُرَيْثٍ عَنْ سَلَمَةَ بْنِ الْمُحَبِّقِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُذُوا عَنِّي خُذُوا عَنِّي قَدْ جَعَلَ اللَّهُ لَهُنَّ سَبِيلًا الْبِكْرُ بِالْبِكْرِ جَلْدُ مِائَةٍ وَنَفْيُ سَنَةٍ وَالثَّيِّبُ بِالثَّيِّبِ جَلْدُ مِائَةٍ وَالرَّجْمُ","id":"Telah menceritakan kepada kami [Waki'] berkata; telah menceritakan kepada kami [Al Fadl bin Dalham] dari [Al Hasan] dari [Qabishah bin Huraits] dari [Salamah bin Muhabbiq] berkata; Rasulullah bersabda: \"Ambillah (contoh) dariku, ambillah dariku. Sungguh Allah telah menjadikan urusan kaum perempuan, bahwa laki-laki (perjaka) dan perempuan (gadis) di cambuk seratus kali dan diasingkan selama setahun. Orang yang sudah menikah laki-laki dengan orang yang sudah menikah perempuan, hukumannya dicambuk seratus kali dan dirajam (dilempar dengan batu) sampai meninggal\"."},"722":{"ar":"حَدَّثَنَا أَبُو النَّضْرِ حَدَّثَنَا الْمُبَارَكُ عَنْ الْحَسَنِ عَنْ سَلَمَةَ بْنِ الْمُحَبِّقِ قَالَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الرَّجُلِ يُوَاقِعُ جَارِيَةَ امْرَأَتِهِ قَالَ إِنْ أَكْرَهَهَا فَهِيَ حُرَّةٌ وَلَهَا عَلَيْهِ مِثْلُهَا وَإِنْ طَاوَعَتْهُ فَهِيَ أَمَتُهُ وَلَهَا عَلَيْهِ مِثْلُهَا","id":"Telah menceritakan kepada kami [Abu Nadlr] telah menceritakan kepada kami [Al Mubarak] dari [Al Hasan] dari [Salamah bin Al Muhabbiq] berkata; Rasulullah Shallallahu'alahiwasallam ditanya tentang seorang laki-laki yang menggauli budak perempuan istrinya. Jika dia (laki-laki itu) memaksanya maka budak itu menjadi merdeka dan berhak mendapatkan sesuatu yang sama (harta) dengan istrinya (dari hartanya laki-laki), adapun jika budak itu menyerahkan dirinya secara sukarela maka dia tetap budak, dan mendapatkan (harta) yang sama dari (laki-laki itu) dalam jumlah yang sama."},"723":{"ar":"حَدَّثَنَا أَبُو النَّضْرِ قَالَ حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ حَبِيبِ بْنِ عَبْدِ اللَّهِ الْأَزْدِيِّ ثُمَّ النُّمَيْرِيِّ قَالَ حَدَّثَنِي حَبِيبُ بْنُ عَبْدِ اللَّهِ يَعْنِي أَبَاهُ قَالَ سَمِعْتُ سِنَانَ بْنَ سَلَمَةَ بْنِ الْمُحَبِّقِ الْهُذَلِيَّ يُحَدِّثُ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَتْ لَهُ حَمُولَةٌ تَأْوِي إِلَى شِبَعٍ فَلْيَصُمْ رَمَضَانَ حَيْثُ أَدْرَكَهُ","id":"Telah menceritakan kepada kami [Abu Nadlr] berkata; telah menceritakan kepada kami [Abdusshomad bin Habib bin Abdullah Al Azdi, An-Numairi] berkata; telah menceritakan kepadaku [Habib bin Abdullah] yaitu Bapaknya berkata; saya mendengar [Sinan bin Salamah bin Al Muhabbiq Al Hudzali] menceritakan dari [Bapaknya] berkata; Rasulullah Shallallahu'alahiwasallam bersabda: \"Barangsiapa memiliki tukang angkut (porter) yang membawa ke satu kelompok perjalanan maka berpuasalah Ramadlan, kalau dia menjumpai Ramadhan itu\"."},"724":{"ar":"حَدَّثَنَا أَبُو دَاوُدَ الطَّيَالِسِيُّ قَالَ حَدَّثَنَا حَرْبُ بْنُ شَدَّادٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنِ النَّحَّازِ الْحَنَفِيِّ أَنَّ سِنَانَ بْنَ سَلَمَةَ أَخْبَرَهُ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِلُحُومِ حُمُرِ النَّاسِ يَوْمَ خَيْبَرَ وَهِيَ فِي الْقُدُورِ فَأُكْفِئَتْ","id":"Telah menceritakan kepada kami [Abu Daud Ath-Thayalisi] berkata; telah menceritakan kepada kami [Harb bin Syaddad] dari [Yahya bin Abu Katsir] dari [An-Nahaz Al Hanafi] sesungguhnya [Sinan bin Salamah] mengabarinya dari [Bapaknya], Rasulullah Shallallahu'alahiwasallam memerintahkan daging keledai pada perang Khaibar yang terletak di kuali-kuali, agar kesemuanya ditumpahkan."},"725":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عَدِيٍّ عَنْ سُلَيْمَانَ يَعْنِي التَّيْمِيَّ عَنْ أَبِي عُثْمَانَ يَعْنِي النَّهْدِيَّ عَنْ قَبِيصَةَ بْنِ مُخَارِقٍ قَالَلَمَّا نَزَلَتْ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَأَنْذِرْ عَشِيرَتَكَ الْأَقْرَبِينَ }انْطَلَقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى رَضْمَةٍ مِنْ جَبَلٍ فَعَلَا أَعْلَاهَا ثُمَّ نَادَى أَوْ قَالَ قَالَ يَا آلَ عَبْدِ مَنَافَاهُ إِنِّي نَذِيرٌ إِنَّ مَثَلِي وَمَثَلَكُمْ كَمَثَلِ رَجُلٍ رَأَى الْعَدُوَّ فَانْطَلَقَ يَرْبَأُ أَهْلَهُ يُنَادِي أَوْ قَالَ يَهْتِفُ يَا صَبَاحَاهْقَالَ أَبِي قَالَ ابْنُ أَبِي عَدِيٍّ فِي هَذَا الْحَدِيثِ عَنْ قَبِيصَةَ بْنِ مُخَارِقٍ أَوْ وَهْبِ بْنِ عَمْرٍو وَهُوَ خَطَأٌ إِنَّمَا هُوَ زُهَيْرُ بْنُ عَمْرٍو فَلَمَّا أَخْطَأَ تَرَكْتُ وَهْبَ بْنَ عَمْرٍو","id":"Telah menceritakan kepada kami [Muhammad bin Abu 'Adi] sesungguhnya [Sulaiman] yaitu At Taimi, dari [Abu 'Utsman] yaitu An-Nahdi, dari [Qabishah bin Muhariq] berkata; ketika turun ayat kepada Rasulullah Shallallahu'alahiwasallam, berilah peringatan keluargamu dan kerabatmu, beliau mendaki bebatuan pada suatu gunung lalu berdiri pada bagian atasnya dan berseru atau berkata; \"Wahai segenap keluarga Abdul Manaf, saya adalah pemberi peringatan. Permisalanku dengan permisalan kalian sebagaimana seorang laki-laki yang melihat musuh lalu bersegera memperingatkan keluarganya dengan menyeru atau berkata; Wahai segenap saudaraku. bapakku berkata; Ibnu Abu 'Ady berkata tentang hadits ini, dari Qabishah bin Muhariq ataukah dari Wahab bin 'Amr, dan ternyata dia salah, karena yang benar adalah [Zuhair bin 'Amr], ketika dia salah menerangkan hal tersebut, saya tinggalkan Wahab bin 'Amr."},"726":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنِي عَوْفٌ قَالَ حَدَّثَنِي حَيَّانُ قَالَ حَدَّثَنِي قَطَنُ بْنُ قَبِيصَةَ عَنْ أَبِيهِ قَبِيصَةَ بْنِ مُخَارِقٍأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْعِيَافَةُ وَالطِّيَرَةُ وَالطَّرْقُ مِنْ الْجِبْتِ قَالَ الْعِيَافَةُ مِنْ الزَّجْرِ وَالطَّرْقُ مِنْ الْخَطِّ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] berkata; telah menceritakan kepadaku ['Auf] berkata; telah menceritakan kepadaku [Hayyan] berkata; telah menceritakan kepadaku [Qatn bin Qabishah] dari [Bapaknya, Qabishah bin Muhariq], ia mendengar Nabi Shallallahu'alaihiwasallam bersabda: \"Al Iyafah (menerbangkan atau mengusir burung lalu meramal arah terbang dan siulnya), tiyaroh (mengurungkan pekerjaan karena melihat hewan dengan alasan takut ada sesuatu yang buruk menimpa) dan At taraq (memukulkan tongkat ke tanah atau membuat garis di pasir untuk peramalan, yaitu suatu bentuk perdukunan) adalah termasuk sihir.\" (Qabishah bin Muhariq Radliyallahu'anhu) berkata; Al Iyafah adalah peramalan dengan cara menggertak burung atau hewan, sebaliknya At taraq adalah peramalan dengan menggunakan garis-garis."},"727":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ هَارُونَ بْنِ رِئَابٍ عَنْ كِنَانَةَ بْنِ نُعَيْمٍ عَنْ قَبِيصَةَ بْنِ الْمُخَارِقِ الْهِلَالِيِّتَحَمَّلْتُ بِحَمَالَةٍ فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْأَلُهُ فِيهَا فَقَالَ نُؤَدِّهَا عَنْكَ وَنُخْرِجُهَا مِنْ نَعَمْ الصَّدَقَةِ وَقَالَ مَرَّةً وَنُخْرِجُهَا إِذَا جَاءَتْنَا الصَّدَقَةُ أَوْ إِذَا جَاءَ نَعَمُ الصَّدَقَةِ وَقَالَ يَا قَبِيصَةُ إِنَّ الْمَسْأَلَةَ لَا تَصْلُحُ وَقَالَ مَرَّةً حُرِّمَتْ إِلَّا فِي ثَلَاثٍ رَجُلٍ تَحَمَّلَ بِحَمَالَةٍ حَلَّتْ لَهُ الْمَسْأَلَةُ حَتَّى يُؤَدِّيَهَا ثُمَّ يُمْسِكَ وَرَجُلٍ أَصَابَتْهُ حَاجَةٌ وَفَاقَةٌ حَتَّى يَشْهَدَ لَهُ ثَلَاثَةٌ مِنْ ذَوِي الْحِجَا مِنْ قَوْمِهِ وَقَالَ مَرَّةً رَجُلٍ أَصَابَتْهُ فَاقَةٌ أَوْ حَاجَةٌ حَتَّى يَشْهَدَ لَهُ أَوْ يَكَلَّمَ ثَلَاثَةٌ مِنْ ذَوِي الْحِجَا مِنْ قَوْمِهِ أَنَّهُ قَدْ أَصَابَتْهُ حَاجَةٌ أَوْ فَاقَةٌ إِلَّا قَدْ حَلَّتْ لَهُ الْمَسْأَلَةُ فَيَسْأَلُ حَتَّى يُصِيبَ قِوَامًا مِنْ عَيْشٍ أَوْ سِدَادًا مِنْ عَيْشٍ ثُمَّ يُمْسِكَ وَرَجُلٍ أَصَابَتْهُ جَائِحَةٌ اجْتَاحَتْ مَالَهُ حَلَّتْ لَهُ الْمَسْأَلَةُ فَيَسْأَلُ حَتَّى يُصِيبَ قِوَامًا مِنْ عَيْشٍ أَوْ سَدَادًا مِنْ عَيْشٍ ثُمَّ يُمْسِكَ وَمَا كَانَ سِوَى ذَلِكَ مِنْ الْمَسْأَلَةِ سُحْتٌ","id":"Telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Harun bin Ri'ab] dari [Kinanah bin Nuaim] dari [Qabishah bin Muhariq Al Hilali] saya mempunyai banyak tanggungan, lalu saya mendatangi Rasulullah Shallallahu'alahiwasallam dan meminta bantuan, Lalu beliau bersabda: \"Kami akan menyelesaikan tanggunganmu dan mengambilkan dari ternak-ternak sedekah\" Pada lain kesempatan, bersabda: \"Kami akan membantumu jika sedekah telah datang atau jika atau kita mendapatkan ternak-ternak sedekah\". Lalu beliau bersabda: \"Wahai Qabishah, meminta-minta itu tidak boleh, --dalam lain kesempatan dengan redaksi diharamkan-- kecuali dalam tiga kondisi, yaitu kondisi seseorang karena mempunyai tanggungan maka diperbolehkan untuk meminta-minta sampai dia mampu untuk menyelesaikan tanggungannya lantas berhenti. Seseorang yang sedang terdesak karena kebutuhan dan kefakiran hingga disaksikan oleh tiga orang dari kaumnya yang berakal, --dalam kesempatan lain dengan redaksi 'Seseorang yang sedang terdesak karena kefakiran dan kebutuhan hingga tiga orang berakal dari kaumnya bersaksi atau mengucapkan ucapan bahwa ia terdesak kebutuhan atau kefakiran, sehingga meminta dihalalkan baginya, lalu dia meminta hingga memperoleh penopang hidup atau kecukupan hidupnya lantas ia menahan diri, dan ketiga, seseorang yang tertimpa musibah (kebangkrutan) sehingga menghabiskan hartanya, maka meminta diperbolehkan baginya hingga memperoleh penopang atau kecukupan hidup lalu ia menahan diri, adapun selain dari tiga kondisi tersebut meminta-minta adalah haram."},"728":{"ar":"حَدَّثَنَا سُفْيَانُ عَنِ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ كُرْزِ بْنِ عَلْقَمَةَ الْخُزَاعِيِّ قَالَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ هَلْ لِلْإِسْلَامِ مِنْ مُنْتَهَى قَالَ أَيُّمَا أَهْلِ بَيْتٍ وَقَالَ فِي مَوْضِعٍ آخَرَ قَالَ نَعَمْ أَيُّمَا أَهْلِ بَيْتٍ مِنْ الْعَرَبِ أَوْ الْعُجْمِ أَرَادَ اللَّهُ بِهِمْ خَيْرًا أَدْخَلَ عَلَيْهِمْ الْإِسْلَامَ قَالَ ثُمَّ مَهْ قَالَ ثُمَّ تَقَعُ الْفِتَنُ كَأَنَّهَا الظُّلَلُ قَالَ كَلَّا وَاللَّهِ إِنْ شَاءَ اللَّهُ قَالَ بَلَى وَالَّذِي نَفْسِي بِيَدِهِ ثُمَّ تَعُودُونَ فِيهَا أَسَاوِدَ صُبًّا يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍوَقَرَأَ عَلَيَّ سُفْيَانُ قَالَ الزُّهْرِيُّ أَسَاوِدَ صُبًّا قَالَ سُفْيَانُ الْحَيَّةُ السَّوْدَاءُ تُنْصَبُ أَيْ تَرْتَفِعُ","id":"Telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari ['Urwah] dari [Kurz bin 'Alqamah Al Khuza'i] berkata; Ada seseorang yang berkata; \"Wahai Rasulullah, apakah Islam itu ada habisnya?\" Beliau bertanya, \"Dimanakah Ahli Bait\"? Pada tempat lain, beliau bersabda: \"Ya, mana saja Ahli Bait penduduk Arab ataupun bukan Arab, apabila Allah menghendaki kebaikan atas mereka, Allah memasukan mereka ke dalam Islam\". lalu ('Alqamah Radliyallahu'anhu) bertanya kembali, \"Lalu apa, Wahai Rasulullah\", beliau bersabda: lalu akan datang fitnah sebagaimana mendung. Dia berkata; \"Sekali-kali tidak, Demi Allah, jika Allah menghendaki\". Beliau bersabda: \"Ya. Demi yang jiwaku yang berada ditangan-Nya, akan datang kembali ulAr ular hitam (cobra) yang memangsa kalian semua, dan kalian akan saling membunuh\". Sufyan membaca kepadaku ('Alqomah), Az Zuhri berkata; ulAr ular hitam yang berdiri. Sufyan berkata; \"Ular hitam yang tegak berdiri\"."},"729":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ كُرْزِ بْنِ عَلْقَمَةَ الْخُزَاعِيِّ قَالَقَالَ أَعْرَابِيٌّ يَا رَسُولَ اللَّهِ هَلْ لِلْإِسْلَامِ مِنْ مُنْتَهَى قَالَ نَعَمْ أَيُّمَا أَهْلِ بَيْتٍ مِنْ الْعَرَبِ أَوْ الْعُجْمِ أَرَادَ اللَّهُ عَزَّ وَجَلَّ بِهِمْ خَيْرًا أَدْخَلَ عَلَيْهِمْ الْإِسْلَامَ قَالَ ثُمَّ مَاذَا يَا رَسُولَ اللَّهِ قَالَ ثُمَّ تَقَعُ فِتَنٌ كَأَنَّهَا الظُّلَلُ فَقَالَ الْأَعْرَابِيُّ كَلَّا يَا رَسُولَ اللَّهِ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَلَى وَالَّذِي نَفْسِي بِيَدِهِ لَتَعُودُنَّ فِيهَا أَسَاوِدَ صُبًّا يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍ","id":"Telah menceritakan kepada kami [Abdurrazzaq] berkata; telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Urwah bin Zubair] dari [Kurz bin 'Alqamah Al Khuza'i] berkata; ada seorang Badui berkata; Wahai Rasulullah, apakah Islam ada habisnya?. Beliau bersabda: \"Ya. Ahlu Bait mana saja baik dari Arab atau Non Arab jika Allah Azzawajalla menghendaki kebaikan pada mereka, maka (Allah Azzawajalla) memasukkan mereka ke agama Islam.\"(orang Badui) berkata; lalu apa lagi Wahai Rasulullah, Beliau bersabda: \"Lalu akan terjadi banyak fitnah, seperti mendung\". Orang Badui berkata; sekali-kali tidak Wahai Rasulullah, Nabi Shallallahu'alaihiwasallam bersabda: \"Ya Demi Dzat yang jiwaku berada di tangan-Nya, akan datang kembali ulAr ular hitam (cobra) yang memangsa kalian semua, dan sebagian kalian akan saling membunuh dengan menebas leher lainnya\"."},"730":{"ar":"حَدَّثَنَا أَبُو الْمُغِيرَةِ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ قَيْسٍ قَالَ حَدَّثَنَا عُرْوَةُ بْنُ الزُّبَيْرِ عَنْ كُرْزٍ الْخُزَاعِيِّ قَالَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْرَابِيٌّ فَقَالَ يَا رَسُولَ اللَّهِ هَلْ لِهَذَا الْأَمْرِ مِنْ مُنْتَهَى قَالَ نَعَمْ فَمَنْ أَرَادَ اللَّهُ بِهِ خَيْرًا مِنْ أَعْجَمٍ أَوْ عُرْبٍ أَدْخَلَهُ عَلَيْهِمْ ثُمَّ تَقَعُ فِتَنٌ كَالظُّلَلِ يَعُودُونَ فِيهَا أَسَاوِدَ صُبًّا يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍ وَأَفْضَلُ النَّاسِ يَوْمَئِذٍ مُؤْمِنٌ مُعْتَزِلٌ فِي شِعْبٍ مِنْ الشِّعَابِ يَتَّقِي رَبَّهُ تَبَارَكَ وَتَعَالَى وَيَدَعُ النَّاسَ مِنْ شَرِّهِقَالَ أَبِي و حَدَّثَنِي مُحَمَّدُ بْنُ مُصْعَبٍ الْقُرْقُسَانِيُّ مِثْلَ حَدِيثِ ابْنِ الْمُغِيرَةِ إِلَّا أَنَّهُ قَالَ كُرْزُ بْنُ حُبَيْشٍ الْخُزَاعِيُّ","id":"Telah menceritakan kepada kami [Abu Al Mughirah] berkata; telah menceritakan kepada kami [Al 'Auza'i] telah menceritakan kepada kami [Abdul Wahid bin Qais] berkata; telah menceritakan kepada kami ['Urwah bin Zubair] dari [Kurs Al Khuza'i] berkata; ada seorang Badui mendatangi Nabi Shallallahu'alaihiwasallam lalu berkata; Wahai Rasulullah, apakah urusan ini akan ada habisnya?. Beliau menjawab, ya. Barangsiapa siapa yang Allah kehendaki baik dari Arab maupun non Arab, Allah memasukkan mereka ke dalam (Islam), lalu akan terjadi banyak fitnah seperti awan atau gunung. Akan datang kembali ulAr ular hitam (cobra) yang memangsa kalian semua, dan sebagian kalian akan saling membunuh dengan menebas leher lainnya\". Bapakku berkata; dan telah menceritakan kepadaku [Muhammad bin Mush'ab Al Qurqusani] sebagaimana hadits Ibnu Al Mughirah kecuali dengan tambahan, [Kurz bin Hubaisy Al Khuza'i] berkata."},"731":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ قَالَ حَدَّثَنَا هِلَالُ بْنُ عَامِرٍ الْمُزَنِيُّ عَنْ أَبِيهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ النَّاسَ بِمِنًى عَلَى بَغْلَةٍ وَعَلَيْهِ بُرْدٌ أَحْمَرُ قَالَ وَرَجُلٌ مِنْ أَهْلِ بَدْرٍ بَيْنَ يَدَيْهِ يُعَبِّرُ عَنْهُ قَالَ فَجِئْتُ حَتَّى أَدْخَلْتُ يَدِي بَيْنَ قَدَمِهِ وَشِرَاكِهِ قَالَ فَجَعَلْتُ أَعْجَبُ مِنْ بَرَدِهَا","id":"Telah menceritakan kepada kami [Abu Mu'awiyah] berkata; telah menceritakan kepada kami [Hilal bin 'Amir Al Muzni] dari [Bapaknya] berkata; saya melihat Rasulullah Shallallahu'alahiwasallam sedang berkhotbah di atas keledainya di Mina dengan memakai selendang merah. ('Amir Al Muzni Radliyallahu'anhu) berkata; seorang laki-laki dari Ahli Badar di hadapan beliau menyampaikan dari beliau. Saya datang lalu kumasukkan tanganku di antara kaki dan tali sandalnya. Dan saya kagum dengan selendangnya."},"732":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ قَالَ حَدَّثَنَا شَيْخٌ مِنْ بَنِي فَزَارَةَ عَنْ هِلَالِ بْنِ عَامِرٍ الْمُزَنِيِّ عَنْ أَبِيهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ النَّاسَ عَلَى بَغْل��ةٍ شَهْبَاءَ وَعَلِيٌّ يُعَبِّرُ عَنْهُ","id":"Telah menceritakan kepada kami [Muhammad bin 'Ubaid] berkata; telah menceritakan kepada kami [seorang syaikh dari Bani Fazarah] dari [Hilal bin 'Amir Al Muzani] dari [Bapaknya] berkata; saya melihat Rasulullah Shallallahu'alahiwasallam berkhutbah kepada orang-orang di atas bighal yang diberi nama Syahba' dan 'Ali mengeraskannya."},"733":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ هِشَامٌ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عَبْدِ الْمَلِكِ عَنِ ابْنِ أَبِي الْمُعَلَّى عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطَبَ يَوْمًا فَقَالَ إِنَّ رَجُلًا خَيَّرَهُ رَبُّهُ عَزَّ وَجَلَّ بَيْنَ أَنْ يَعِيشَ فِي الدُّنْيَا مَا شَاءَ أَنْ يَعِيشَ فِيهَا يَأْكُلُ مِنْ الدُّنْيَا مَا شَاءَ أَنْ يَأْكُلَ مِنْهَا وَبَيْنَ لِقَاءِ رَبِّهِ عَزَّ وَجَلَّ فَاخْتَارَ لِقَاءَ رَبِّهِ قَالَ فَبَكَى أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ قَالَ فَقَالَ أَصْحَابُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا تَعْجَبُونَ مِنْ هَذَا الشَّيْخِ أَنْ ذَكَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا صَالِحًا خَيَّرَهُ رَبُّهُ تَبَارَكَ وَتَعَالَى بَيْنَ الدُّنْيَا وَبَيْنَ لِقَاءِ رَبِّهِ تَبَارَكَ وَتَعَالَى فَاخْتَارَ لِقَاءَ رَبِّهِ عَزَّ وَجَلَّ وَكَانَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ أَعْلَمَهُمْ بِمَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ بَلْ نَفْدِيكَ بِأَمْوَالِنَا وَأَبْنَائِنَا أَوْ بِآبَائِنَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ النَّاسِ أَحَدٌ أَمَنُّ عَلَيْنَا فِي صُحْبَتِهِ وَذَاتِ يَدِهِ مِنْ ابْنِ أَبِي قُحَافَةَ وَلَوْ كُنْتُ مُتَّخِذًا خَلِيلًا لَاتَّخَذْتُ ابْنَ أَبِي قُحَافَةَ وَلَكِنْ وُدٌّ وَإِخَاءُ إِيمَانٍ وَلَكِنْ وُدٌّ وَإِخَاءُ إِيمَانٍ مَرَّتَيْنِ وَإِنَّ صَاحِبَكُمْ خَلِيلُ اللَّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Abu Al Walid, Hisyam] berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Abdul Malik] dari [Ibnu Abu Al Mu'alla] dari [bapaknya] sesungguhnya Rasulullah Shallallahu'alahiwasallam berkhutbah pada suatu hari bersabda: \"Ada seorang laki-laki yang diberi pilihan oleh Allah Azzawajalla antara hidup di dunia sesuai yang dikehendakinya dan makan sesuka hatinya dengan bertemu dengan Rabbinya Azzawajalla. Dia memilih bertemu dengan Rabbinya\". (Abu Al Mu'alla Radliyallahu'anhu) berkata; lalu Abu Bakar Radliyallahu'anhu menangis. Para sahabat Rasulullah Shallallahu'alahiwasallam berkata; \"Apakah kalian tidak heran dengan orang yang tua ini (Para sahbaat saat itu belum tahu orang tua yang dimaksudkan), Rasulullah Shallallahu'alahiwasallam menyebutkan seorang lelaki shalih yang diberi pilihan oleh Rabbinya Tabaroka Wa Ta'ala, antara kenikmatan dunia dan bertemu Robnya Tabaraka Wa Ta'ala, lalu dia memilih untuk bertemu dengan Rabnya Tabaraka Wa Ta'ala, padahal Abu Bakar adalah orang yang paling mengetahui detail tentang perkataan Rasulullah Shallallahu'alahiwasallam\". Abu Bakar Radliyallahu'anhu berkata; \"Kami akan menebus anda dengan harta kami, anak kami dan bapak-bapak kami\"? Rasulullah Shallallahu'alahiwasallam bersabda: \"Tidak ada manusia yang lebih akrab persahabatannya denganku melebihi Ibnu Abu Quhafah, kalaulah saya boleh mengambil seorang kekasih pastilah saya mengambil Ibnu Abu Quhafah sebagai kekasih, tapi yang ada adalah cinta kasih, persaudaraan seiman, tapi yang ada adalah cinta kasih, persaudaraan seiman. Beliau mengucapkannya dua kali. Dan saudara kalian ini (Rasulullah Shallallahu'alahiwasallam) adalah kekasih Allah\""},"734":{"ar":"حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ دَاوُدَ بْنِ أَبِي هِنْدٍ عَنِ الشَّعْبِيِّ عَنْ عَلْقَمَةَ عَنْ سَلَمَةَ بْنِ يَزِيدَ الْجُعْفِيِّ قَالَانْطَلَقْتُ أَنَا وَأَخِي إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قُلْنَا يَا رَسُولَ اللَّهِ إِنَّ أُمَّنَا مُلَيْكَةَ كَانَتْ تَصِلُ الرَّحِمَ وَتَقْرِي الضَّيْفَ وَتَفْعَلُ وَتَفْعَلُ هَلَكَتْ فِي الْجَاهِلِيَّةِ فَهَلْ ذَلِكَ نَافِعُهَا شَيْئًا قَالَ لَا قَالَ قُلْنَا فَإِنَّهَا كَانَتْ وَأَدَتْ أُخْتًا لَنَا فِي الْجَاهِلِيَّةِ فَهَلْ ذَلِكَ نَافِعُهَا شَيْئًا قَالَ الْوَائِدَةُ وَالْمَوْءُودَةُ فِي النَّارِ إِلَّا أَنْ تُدْرِكَ الْوَائِدَةُ الْإِسْلَامَ فَيَعْفُوَ اللَّهُ عَنْهَا","id":"Telah menceritakan kepada kami [Ibnu Abu 'Adi] dari [Daud bin Abu Hind] dari [Asy-Sya'bi] dari ['Alqamah] dari [Salamah bin Yazid Al Ju'fi] berkata; Saya dan saudaraku pergi menemui Rasulullah Shallallahu'alahiwasallam lalu kami berkata; \"Wahai Rasulullah, Sesungguhnya ibu kami, Mulaikah, adalah orang yang menyambung silaturahmi dan memuliakan tamu, dan banyak berbuat kebaikan namun dia meninggal dalam keadaan Jahiliyah, lalu apakah hal itu bermanfaat baginya?\" (Rasulullah Shallallahu'alahiwasallam) bersabda: \" Tidak\". (Salamah bin Yazid Al Ju'fi Radliyallahu'anhu) berkata; lalu kami berkata; sesungguhnya ibu kami pada waktu jahiliyah menanam hidup-hidup saudara perempuan kami, apakah itu juga membawa pengaruh baginya? (Rasulullah Shallallahu'alahiwasallam) bersabda: \"Orang yang mengubur dan yang dikubur di neraka, kecuali orang yang mengubur tersebut masuk Islam, lalu Allah mengampuninya\"."},"735":{"ar":"حَدَّثَنَا أَبُو سَلَمَةَ الْخُزَاعِيُّ حَدَّثَنَا بَكْرُ بْنُ مُضَرَ قَالَ حَدَّثَنِي مُوسَى بْنُ جُبَيْرٍ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلِ بْنِ حُنَيْفٍ عَنْ عَاصِمِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَلَّقَ حَفْصَةَ بِنْتَ عُمَرَ بْنِ الْخَطَّابِ ثُمَّ رَاجَعَهَا","id":"Telah menceritakan kepada kami [Abu Salamah Al Khuza'i] telah menceritakan kepada kami [Bakr bin Mudlar] berkata; telah menceritakan kepadaku [Musa bin Jubair] dari [Abu Umamah bin Sahl bin Hunaif] dari ['Ashim bin 'Umar], Rasulullah Shallallahu'alahiwasallam pernah mentalak Hafshah binti 'Umar lalu merujuk kembali\""},"736":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ عِيسَى بْنِ الطَّبَّاعِ قَالَ حَدَّثَنَا جَرِيرٌ يَعْنِي ابْنَ حَازِمٍ عَنْ وَاصِلٍ الْأَحْدَبِ عَنْ أَبِي وَائِلٍ عَنْ شُرَيْحٍ قَالَ سَمِعْتُ رَجُلًا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُ تَعَالَى يَا ابْنَ آدَمَ قُمْ إِلَيَّ أَمْشِ إِلَيْكَ وَامْشِ إِلَيَّ أُهَرْوِلْ إِلَيْكَ","id":"Telah menceritakan kepada kami [Ishaq bin 'Isa bin Al Thaba'] berkata; telah menceritakan kepada kami [Jarir] yaitu Ibnu Hazim, dari [Wasil Al Ahdab] dari [Abu Wa'il] dari [Syuraih] berkata; saya telah mendengar [seorang sahabat] Nabi Shallallahu'alaihiwasallam berkata; Nabi Shallallahu'alaihiwasallam bersabda: Allah Ta'ala berfirman, \"Wahai anak Adam, berdirilah kepada-Ku, Aku akan menghampirimu dengan berjalan, berjalanlah untuk-Ku, Aku akan menghampirimu dengan berlari-lari\""},"737":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ أَبِي النَّضْرِ عَنْ زُرْعَةَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ جَرْهَدٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِهِ وَهُوَ كَاشِفٌ عَنْ فَخِذِهِ فَقَالَ أَمَا عَلِمْتَ أَنَّ الْفَخِذَ عَوْرَةٌ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Malik bin Anas] dari [Abu Nadlr] dari [Zur'ah bin Abdurrahman bin Jarhad] dari [bapaknya] dari [kakeknya] sesungguhnya Nabi Shallallahu'alaihiwasallam pernah melewatinya dan saat itu tersingkap pahanya, maka beliau bersabda: \"Tidaklah kau tahu, sesungguhnya paha adalah termasuk aurat\""},"738":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ أَبِي النَّضْرِ عَنْ زُرْعَةَ بْنِ مُسْلِمِ بْنِ جَرْهَدٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى جَرْهَدًا فِي الْمَسْجِدِ وَعَلَيْهِ بُرْدَةٌ قَدْ انْكَشَفَ فَخِذُهُ فَقَالَ الْفَخِذُ عَوْرَةٌ","id":"Telah menceritakan kepada kami [Sufyan] dari [Abu Nadlr] dari [Zur'ah Muslim bin Jarhad] sesungguhnya Nabi Shallallahu'alaihiwasallam melihat Jarhad dalam masjid dengan memakai selendang dan pahanya tersingkap. Beliau bersabda: \"Paha adalah aurat\"."},"739":{"ar":"حَدَّثَنَا سُفْيَانُ حَدَّثَنَا أَبُو الزِّنَادِ وَقَالَ أَخْبَرَنِي آلُ جَرْهَدٍ عَنْ جَرْهَدٍ قَالَالْفَخِذُ عَوْرَةٌ","id":"Telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Abu Az Zanad] dan berkata; telah mengabarkan kepadaku [keluarga Jarhad] dari [Jarhad] berkata; paha adalah aurat."},"740":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ أَبِي الزِّنَادِ عَنِ ابْنِ جَرْهَدٍ عَنْ أَبِيهِ قَالَمَرَّ بِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا كَاشِفٌ فَخِذِي فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَطِّهَا فَإِنَّهَا مِنْ الْعَوْرَةِ","id":"Telah menceritakan kepada kami [Abdurrazzaq] berkata; telah menceritakan kepada kami [Ma'mar] dari [Abu Ziyad] dari [Ibnu Jarhad] dari [Bapaknya] berkata; Rasulullah Shallallahu'alahiwasallam melewatiku dan saya dalam keadaan terbuka pahaku, lalu Nabi Shallallahu'alaihiwasallam bersabda: \"Tutuplah, sesungguhnya itu adalah bagian dari aurat\"."},"741":{"ar":"حَدَّثَنَا أَبُو عَامِرٍ قَالَ حَدَّثَنَا زُهَيْرٌ يَعْنِي ابْنَ مُحَمَّدٍ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ عَبْدِ اللَّهِ بْنِ جَرْهَدٍ الْأَسْلَمِيِّ أَنَّهُ سَمِعَ أَبَاهُ جَرْهَدًا يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فَخِذُ الْمَرْءِ الْمُسْلِمِ عَوْرَةٌ","id":"Telah menceritakan kepada kami [Abu 'Amir] berkata; telah menceritakan kepada kami [Zuhair] yaitu Ibnu Muhammad, dari [Abdullah bin Muhammad bin 'Aqil] dari [Abdullah bin Jarhad Al Aslami] sesungguhnya telah mendengar [Bapaknya] berkata; saya telah mendengar Rasulullah Shallallahu'alahiwasallam bersabda: \"Paha seseorang muslim adalah aurat\"."},"742":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ عِيسَى قَالَ أَخْبَرَنِي مَالِكٌ عَنْ أَبِي النَّضْرِ عَنْ زُرْعَةَ بْنِ جَرْهَدٍ الْأَسْلَمِيِّ عَنْ أَبِيهِ وَكَانَ مِنْ أَصْحَابِ الصُّفَّةِ قَالَجَلَسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَأَى فَخِذِي مُنْكَشِفَةً فَقَالَ خَمِّرْ عَلَيْكَ أَمَا عَلِمْتَ أَنَّ الْفَخِذَ عَوْرَةٌ","id":"Telah menceritakan kepada kami [Ishaq bin 'Isa] berkata; telah mengabarkan kepadaku [Malik] dari [Abu Nadlr] dari [Zur'ah bin Jarhad Al Aslami] dari [Bapaknya] dia adalah seorang ahli shuffah berkata; Rasulullah Shallallahu'alahiwasallam duduk lalu beliau melihat paha saya tersingkap. Lalu beliau bersabda: \"Tutuplah, tidakkah kau tahu, paha adalah aurat\"."},"743":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا ابْنُ أَبِي الزِّنَادِ عَنْ أَبِيهِ عَنْ زُرْعَةَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ جَرْهَدٍ عَنْ جَرْهَدٍ جَدِّهِ وَنَفَرٍ مِنْ أَسْلَمَ سِوَاهُ ذَوِي رِضًاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ عَلَى جَرْهَدٍ وَفَخِذُ جَرْهَدٍ مَكْشُوفَةٌ فِي الْمَسْجِدِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا جَرْهَدُ غَطِّ فَخِذَكَ فَإِنَّ يَا جَرْهَدُ الْفَخِذَ عَوْرَةٌ","id":"Telah menceritakan kepada kami [Husain bin Muhammad] berkata; telah menceritakan kepada kami [Ibnu Abu Az Zanad] dari [Bapaknya] dari [Zur'ah bin Abdurrahman bin Jarhad] dari [Jarhad] kakeknya dan beberapa orang Aslam selainnya yang bisa dipertanggungjawabkan, Rasulullah Shallallahu'alahiwasallam melewati Jarhad dan paha Jarhad tersingkap dalam masjid. Lalu Rasulullah Shallallahu'alahiwasallam bersabda kepadanya, \"Wahai Jarhad tutuplah pahamu. paha itu aurat.\""},"744":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سُفْيَانَ قَالَ حَدَّثَنِي أَبُو الزِّنَادِ عَنْ زُرْعَةَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ جَرْهَدٍ عَنْ جَدِّهِ جَرْهَدٍ قَالَمَرَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيَّ بُرْدَةٌ وَقَدْ انْكَشَفَتْ فَخِذِي قَالَ غَطِّ فَإِنَّ الْفَخْذَ عَوْرَةٌ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sufyan] berkata; telah menceritakan kepadaku [Abu Zinad] dari [Zur'ah bin Abdurrahman bin Jarhad] dari [kakeknya, Jarhad] berkata; Rasulullah Shallallahu'alahiwasallam melewati saya ketika saya memakai selendang yang tersingkap pahaku. Beliau bersabda: \"Tutuplah, karena paha itu aurat\"."},"745":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ مَوْلَى بَنِي هَاشِمٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عُلَاثَةَ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ قَالَ حَدَّثَنَا خَالِدُ بْنُ اللَّجْلَاجِ أَنَّ أَبَاهُ حَدَّثَهُ قَالَبَيْنَمَا نَحْنُ فِي السُّوقِ إِذْ مَرَّتْ امْرَأَةٌ تَحْمِلُ صَبِيًّا فَثَارَ النَّاسُ وَثُرْتُ مَعَهُمْ فَانْتَهَيْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَقُولُ لَهَا مَنْ أَبُو هَذَا فَسَكَتَتْ فَقَالَ مَنْ أَبُو هَذَا فَسَكَتَتْ فَقَالَ شَابٌّ بِحِذَائِهَا يَا رَسُولَ اللَّهِ إِنَّهَا حَدِيثَةُ السِّنِّ حَدِيثَةُ عَهْدٍ بِجِزْيَةٍ وَإِنَّهَا لَمْ تُخْبِرْكَ وَأَنَا أَبُوهُ يَا رَسُولَ اللَّهِ فَالْتَفَتَ إِلَى مَنْ عِنْدَهُ كَأَنَّهُ يَسْأَلُهُمْ عَنْهُ فَقَالُوا مَا عَلِمْنَا إِلَّا خَيْرًا أَوْ نَحْوَ ذَلِكَ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحْصَنْتَ قَالَ نَعَمْ فَأَمَرَ بِرَجْمِهِ فَذَهَبْنَا فَحَفَرْنَا لَهُ حَتَّى أَمْكَنَّا وَرَمَيْنَاهُ بِالْحِجَارَةِ حَتَّى هَدَأَ ثُمَّ رَجَعْنَا إِلَى مَجَالِسِنَا فَبَيْنَمَا نَحْنُ كَذَلِكَ إِذْ أَنَا بِشَيْخٍ يَسْأَلُ عَنْ الْفَتَى فَقُمْنَا إِلَيْهِ فَأَخَذْنَا بِتَلَابِيبِهِ فَجِئْنَا بِهِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْنَا يَا رَسُولَ اللَّهِ إِنَّ هَذَا جَاءَ يَسْأَلُ عَنْ الْخَبِيثِ فَقَالَ مَهْ لَهُوَ أَطْيَبُ عِنْدَ اللَّهِ رِيحًا مِنْ الْمِسْكِ قَالَ فَذَهَبْنَا فَأَعَنَّاهُ عَلَى غُسْلِهِ وَحَنُوطِهِ وَتَكْفِينِهِ وَحَفَرْنَا لَهُ وَلَا أَدْرِي أَذَكَرَ الصَّلَاةَ أَمْ لَا","id":"Telah menceritakan kepada kami [Abu Sa'id] budak Bani Hasyim, berkata; telah menceritakan kepada kami [Muhammad bin Abdullah bin 'Ulatsah] berkata; telah menceritakan kepada kami [Abdul Aziz bin 'Umar bin Abdul Aziz] berkata; telah menceritakan kepada kami [Khalid bin Hallaj] sesungguhnya [bapaknya] menceritakannya, berkata; ketika kami sedang berada di pasar, lewatlah seorang wanita yang membawa seorang bayi, lalu serentak orang-orang menyelidikinya, saya juga ikut dengan mereka. Saya laporkan perihal tersebut pada Rasulullah Shallallahu'alahiwasallam, lalu beliau bertanya kepada wanita tersebut, \"Siapakah bapak dari bayi ini\"? wanita tersebut terdiam. (Rasulullah Shallallahu'alahiwasallam) bertanya, siapakah bapak bayi ini? lalu wanita itu tetap terdiam. lalu ada seorang laki-laki yang berdiri di sampingnya, \"Wahai Rasulullah, sungguh perempuan ini masih belum cukup umur dan orang baru yang termasuk pembayar jizyah, dia belum bisa memberitahukan hal itu pada anda, Wahai Rasulullah. Saya bapak dari bayi tersebut\". Lalu (Rasulullah Shallallahu'alahiwasallam) menoleh ke samping orang itu seolah-olah dia bertanya kepada mereka tentangnya. Mereka berkata; sesungguhnya kami tidak mengenalnya kecuali dalam kebaikan, atau yang semisalnya. Maka Rasulullah Shallallahu'alahiwasallam bertanya kepada laki-laki tersebut, \"Apakah engkau sudah menikah?\" dia menjawab, Ya. Maka (Rasulullah Shallallahu'alahiwasallam) memerintahkan untuk merajamnya, lalu kami serentak pergi dan menggali lubang untuknya, sampai ketika kami telah memposisikan dia dalam lubang tersebut dan mulai melemparinya dengan batu. Ketika dia sudah tidak bergerak (bernyawa), kami pulang ke tempat kumpul kami. Ketika kami sedang berkumpul datanglah orang tua menanyakan tentang pemuda tersebut, maka kami berdiri dan mengambilkan untuknya bekas kain yang dipakai dalam prosesi rajam, dan kami membawa orang tua tersebut kepada Rasulullah Shallallahu'alahiwasallam, lalu kami berkata; \"Wahai Rasulullah, sesungguhnya orang tua ini datang untuk menanyakan pemuda yang berbuat buruk tadi\", Rasulullah Shallallahu'alahiwasallam bersabda: \"Tahan, Sungguh dia disisi Allah lebih wangi daripada minyak kasturi\". (Hallaj Radliyallahu'anhu) berkata; lalu kami pergi untuk mensucikan pemuda tersebut, memberi wewangian, mengafani dan menguburnya, tapi saya tidak ingat apakah dishalati atau tidak."},"746":{"ar":"حَدَّثَنَا الْوَلِيدُ بْنُ مَسْلِمٍ قَالَ سَمِعْتُ يَزِيدَ بْنَ أَبِي مَرْيَمَ قَالَ لَحِقَنِي عَبَايَةُ بْنُ رَافِعِ بْنِ خَدِيجٍ وَأَنَا رَائِحٌ إِلَى الْمَسْجِدِ إِلَى الْجُمُعَةِ مَاشِيًا وَهُوَ رَاكِبٌ قَالَ أَبْشِرْ فَإِنِّي سَمِعْتُ أَبَا عَبْسٍ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ اغْبَرَّتْ قَدَمَاهُ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ حَرَّمَهُمَا اللَّهُ عَزَّ وَجَلَّ عَلَى النَّارِ","id":"Telah menceritakan kepada kami [Al Walid bin Muslim] berkata saya telah mendengar [Yazid bin Abu Maryam] berkata; ['Abayah bin Rafi' bin Khadij] menyusulku, sedang saya sedang menuju ke masjid untuk (shalat) Jum'at dengan keadaan berjalan kaki, sedang dia berkendaraan. Dia berkata 'Bergembiralah, saya mendengar [Abu Abbas] berkata; Rasulullah Shallallahu'alahiwasallam bersabda: \"Barangsiapa yang kedua kakinya terkena debu di jalan Allah Azzawajalla, Allah Azzawajalla mengharamkan keduanya untuk neraka.\""},"747":{"ar":"حَدَّثَنَا أَبُو سَلَمَةَ الْخُزَاعِيُّ قَالَ أَخْبَرَنَا أَبُو هِلَالٍ عَنْ حُمَيْدِ بْنِ هِلَالٍ الْعَدَوِيِّ سَمِعَهُ مِنْهُ عَنْ أَبِي قَتَادَةَ عَنِ الْأَعْرَابِيِّالَّذِي سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ خَيْرَ دِينِكُمْ أَيْسَرُهُ إِنَّ خَيْرَ دِينِكُمْ أَيْسَرُهُ","id":"Telah menceritakan kepada kami [Abu Salamah Al Khuza'i] berkata; telah mengabarkan kepada kami [Abu Hilal] dari [Humaid bin Hilal Al 'Adawi] sesungguhnya dia mendengarnya, dari [Abu Qatadah] dari [seorang Badui], yang mendengar dari Rasulullah Shallallahu'alahiwasallam bersabda: \"Sebaik-baik perkara agama kalian adalah yang paling mudah urusannya, sungguh sebaik-baik perkara dien kalian adalah yang paling mudah urusannya\""},"748":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ قَالَ حَدَّثَنِي أَبُو النَّضْرِ عَنْ رَجُلٍ كَانَ قَدِيمًا مِنْ بَنِي تَمِيمٍ كَانَ فِي عَهْدِ عُثْمَانَ رَجُلٌ يُخْبِرُ عَنْ أَبِيهِأَنَّهُ لَقِيَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ اكْتُبْ لِي كِتَابًا أَنْ لَا أُؤَاخَذَ بِجَرِيرَةِ غَيْرِي فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ ذَلِكَ لَكَ وَلِكُلِّ مُسْلِمٍ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Musa bin 'Uqbah] berkata; telah menceritakan kepadaku [Abu Nadlr] dari [seorang laki-laki] dari Bani Tamim pada waktu kekhalifahan 'Utsman menghabari dari bapaknya, dia bertemu Rasulullah Shallallahu'alahiwasallam lalu berkata \"Wahai Rasulullah, tulislah sebagai catatan, bahwa saya tidak menanggung dosa yang diperbuat orang lain\" Lalu Rasulullah Shallallahu'alahiwasallam berkata kepadanya, \"Catatan itu adalah untukmu dan semua kaum muslimin\"."},"749":{"ar":"حَدَّثَنَا مَكِّيُّ بْنُ إِبْرَاهِيمَ قَالَ أَخْبَرَنَا عَبْدُ الْمَلِكِ بْنُ جُرَيْجٍ عَنْ عَمْرِو بْنِ دِينَارٍ أَنَّ هِشَامَ بْنَ يَحْيَى أَخْبَرَهُ أَنَّ عِكْرِمَةَ بْنَ سَلَمَةَ بْنِ رَبِيعَةَأَخْبَرَهُ أَنَّ أَخَوَيْنِ مِنْ بَنِي الْمُغِيرَةِ لَقِيَا مُجَمِّعَ بْنَ يَزِيدَ الْأَنْصَارِيَّ فَقَالَ إِنِّي أَشْهَدُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ أَنْ لَا يَمْنَعَ جَارٌ جَارَهُ أَنْ يَغْرِزَ خَشَبَةً فِي جِدَارِهِ فَقَالَ الْحَالِفُ أَيْ أَخِي قَدْ عَلِمْتُ أَنَّكَ مَقْضِيٌّ لَكَ وَقَدْ حَلَفْتُ فَاجْعَلْ أُسْطُوَانًا دُونَ جِدَارِي فَفَعَلَ الْآخَرُ فَغَرَزَ فِي الْأُسْطُوَانِ خَشَبَةًقَالَ ابْنُ جُرَيْجٍ قَالَ عَمْرٌو وَأَنَا نَظَرْتُ إِلَى ذَلِكَ","id":"Telah menceritakan kepada kami [Maki bin Ibrahim] berkata; telah mengabarkan kepada kami [Abdul Malik bin Juraij] dari ['Amr bin Dinar] Sesunguhnya [Hisyam bin Yahya] Mengabarinya sesungguhnya ['Ikrimah bin Salamah bin Rabi'ah] mengabarinya, sesungguhnya dua saudara dari Bani Mughirah bertemu dengan [Mujamma' bin Yazid Al Anshori] lalu berkata; \"Saya bersumpah, sesungguhnya Nabi Shallallahu'alaihiwasallam memerintahkan tetangga untuk tidak melarang para tetangganya yang lain menyandarkan kayu di dinding rumah\", Orang yang tadi bersumpah, yaitu saudaraku sendiri berkata; \"Aku tahu bahwa keputusan jatuh di tanganmu, dan saya telah bersumpah, maka buatlah sandaran pada selain dindingku\", Maka saudaranya itu pun berbuat yang sama untuk tidak menancapkan paku pada dinding tetangganya, dan ia sandarkan kayu pada sebuah tiang. Ibnu Juraij berkata; 'Amr berkata; saya melihat kejadian tersebut."},"750":{"ar":"حَدَّثَنَا حَجَّاجٌ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي عَمْرُو بْنُ دِينَارٍ عَنْ هِشَامِ بْنِ يَحْيَى أَخْبَرَهُ أَنَّ عِكْرِمَةَ بْنَ سَلَمَةَ بْنِ رَبِيعَةَأَخْبَرَهُ أَنَّ أَخَوَيْنِ مِنْ بَنِي الْمُغِيرَةِ أَعْتَقَ أَحَدُهُمَا أَنْ لَا يَغْرِزَ خَشَبًا فِي جِدَارِهِ فَلَقِيَا مُجَمِّعَ بْنَ يَزِيدَ الْأَنْصَارِيَّ وَرِجَالًا كَثِيرًا فَقَالُوا نَشْهَدُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَمْنَعْ جَارٌ جَارَهُ أَنْ يَغْرِزَ خَشَبًا فِي جِدَارِهِ فَقَالَ الْحَالِفُ أَيْ أَخِي قَدْ عَلِمْتُ أَنَّكَ مَقْضِيٌّ لَكَ عَلَيَّ وَقَدْ حَلَفْتُ فَاجْعَلْ أُسْطُوَانًا دُونَ جِدَارِي فَفَعَلَ الْآخَرُ فَغَرَزَ فِي الْأُسْطُوَانِ خَشَبَةًفَقَالَ لِي عَمْرٌو فَأَنَا نَظَرْتُ إِلَى ذَلِكَ","id":"Telah menceritakan kepada kami [Hajjaj] [Ibnu Juraij] berkata; telah mengabarkan kepadaku ['Amr bin Dinar] dari [Hisyam bin Yahya] menghabarinya, sesungguhnya ['Ikrimah bin Salamah bin Rabi'ah] menghabarinya, sesungguhnya dua saudara dari Bani Mughirah membebaskan salah satunya untuk tidak meletakkan kayu pada dindingnya, lalu bertemu dengan [Mujamma' bin Yazid Al Anshori] dan beberapa orang. Mereka berkata; kami menyaksikan Rasulullah Shallallahu'alahiwasallam bersabda: \"Tidak boleh seseorang melarang tetangganya menyandarkan kayu di dinding rumah\", Orang yang bersumpah, yaitu saudaraku berkata; \"Aku tahu bahwa keputusan jatuh di tanganmu, dan saya wajib (untuk taat), namun saya telah bersumpah, maka buatlah sandaran pada selain dindingku\", lalu saudaranya pun berbuat yang sama yaitu tidak menyandarkan kayu di dinding tetangganya, dan menyandarkannya pada sebuah tiang. Lalu 'Amr berkata kepadaku, saya melihat kejadian tersebut."},"751":{"ar":"حَدَّثَنَا هَارُونُ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يَزِيدُ بْنُ عِيَاضٍ عَنْ يَزِيدَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ رُقَيْشٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ بْنِ جَارِيَةَ عَنْ مُجَمِّعِ بْنِ يَزِيدَ بْنِ جَارِيَةَأَنَّهُ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي نَعْلَيْنِ","id":"Telah menceritakan kepada kami [Harun] berkata; telah menceritakan kepada kami [Ibnu Wahab] berkata; telah mengabarkan kepadaku [Yazid bin 'Iyadl] dari [Yazid bin Abdurrahman bin Ruqaisy] dari [Abdurrahman bin Yazid bin Jariyah] dari [Mujamma' bin Yazid bin Jariyah], pernah dia melihat Nabi Shallallahu'alaihiwasallam shalat dengan memakai kedua sandal."},"752":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ مَوْلَى بَنِي هَاشِمٍ قَالَ حَدَّثَنَا زَائِدَةُ قَالَ حَدَّثَنَا السَّائِبُ بْنُ حُبَيْشٍ عَنْ أَبِي الشَّمَّاخِ الْأَزْدِيِّ عَنِ ابْنِ عَمٍّ لَهُ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّهُ أَتَى مُعَاوِيَةَ فَدَخَلَ عَلَيْهِ وَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ وَلِيَ أَمْرَ النَّاسِ ثُمَّ أَغْلَقَ بَابَهُ دُونَ الْمِسْكِينِ أَوْ الْمَظْلُومِ أَوْ ذِي الْحَاجَةِ أَغْلَقَ اللَّهُ عَزَّ وَجَلَّ دُونَهُ أَبْوَابَ رَحْمَتِهِ عِنْدَ حَاجَتِهِ وَفَقْرِهِ أَفْقَرَ مَا يَكُونُ إِلَيْهَا","id":"Telah menceritakan kepada kami [Abu Sa'id] Budak Bani Hasyim, berkata; telah menceritakan kepada kami [Za'idah] berkata; telah menceritakan kepada kami [As-Sa'ib bin Hubaits] dari [Abu Asy-Syamah Al Azdi] dari [anak pamannya], yaitu termasuk sahabat Nabi Shallallahu'alaihiwasallam, dia menemui Mu'awiyah, dan berkata; saya mendengar Rasulullah Shallallahu'alahiwasallam bersabda: \"Barangsiapa yang mengurus urusan manusia lalu menutup pintu-pintunya untuk orang-orang miskin atau orang yang teraniaya atau orang sedang sangat butuh, niscaya Allah Azzawajalla menutup pintu-pintu rahmAt Nya ketika dia butuh dan terdesak, lebih dari pada yang dia sangat butuhkan.\""},"753":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا شَرِيكٌ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى قَالَنَادَى رَجُلٌ مِنْ أَهْلِ الشَّامِ يَوْمَ صِفِّينَ أَفِيكُمْ أُوَيْسٌ الْقَرَنِيُّ قَالُوا نَعَمْ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ خَيْرِ التَّابِعِينَ أُوَيْسًا الْقَرَنِيَّ","id":"Telah menceritakan kepada kami [Abu Nua'im] berkata; telah menceritakan kepada kami [Syarik] dari [Yazid bin Abu Ziyad] dari [Abdurrahman bin Abu Laila] berkata; ada [seorang laki-laki] dari penduduk Syam berseru pada Perang Shiffin, Apakah di antara kalian ada yang bernama Uwais Al Qarny?. mereka berkata; benar. (Abdurrahman bin Abu Laila Radliyallahu'anhu) berkata; saya mendengar Rasulullah Shallallahu'alahiwasallam, di antara para tabiin yang terbaik adalah Uwais Al Qarny."},"754":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ قَالَأُتِيَ عَبْدُ اللَّهِ فِي امْرَأَةٍ تَزَوَّجَهَا رَجُلٌ ثُمَّ مَاتَ عَنْهَا وَلَمْ يَفْرِضْ لَهَا صَدَاقًا وَلَمْ يَكُنْ دَخَلَ بِهَا قَالَ فَاخْتَلَفُوا إِلَيْهِ فَقَالَ أَرَى لَهَا مِثْلَ صَدَاقِ نِسَائِهَا وَلَهَا الْمِيرَاثُ وَعَلَيْهَا الْعِدَّةُ فَشَهِدَ مَعْقِلُ بْنُ سِنَانٍ الْأَشْجَعِيُّ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى فِي بِرْوَعَ ابْنَةِ وَاشِقٍ بِمِثْلِ مَا قَضَى","id":"Telah menceritakan kepada kami [Yazid bin Harun] berkata; telah mengabarkan kepada kami [Sufyan] dari [Manshur] dari [Ibrahim] dari ['AlQamah] berkata; [Abdullah] dibawa kepada seorang perempuan yang dinikahi seorang laki-laki, lantas si laki-laki meninggal, ternyata si laki-laki belum memberinya maskawin namun belum pula mencampurinya. (Ibrahim bin 'AlQamah Radliyallahu'anhu) berkata; orang-orang pun berselisih dan menyerahkan urusan kepadanya, lalu dia berkata; menurutku wanita itu berhak mendapatkan mahar seperti isteri-isteri yang lainnya. Dia juga termasuk dari ahli waris dan juga wajib ber'iddah. [Ma'qil bin Sinan Al Asyja'i] bersaksi, sesungguhnya Nabi Shallallahu'alaihiwasallam memberi keputusan kepada Birwa' binti Wasyiq sebagaimana keputusan yang diambil (Abdullah)."},"755":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ أَبِي شَيْبَةَ قَالَ عَبْد اللَّهِ وَسَمِعْتُهُ أَنَا مِنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ أَبِي شَيْبَةَ قَالَ حَدَّثَنَا ابْنُ فُضَيْلٍ عَنْ عَطَاءِ بْنِ السَّائِبِ قَالَ شَهِدَ عِنْدِي نَفَرٌ مِنْ أَهْلِ الْبَصْرَةِ مِنْهُمْ الْحَسَنُ بْنُ أَبِي الْحَسَنِ عَنْ مَعْقِلِ بْنِ سِنَانٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِهِ وَهُوَ يَحْتَجِمُ لِثَمَانِ عَشْرَةَ قَالَ أَفْطَرَ الْحَاجِمُ وَالْمَحْجُومُ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad bin Abu Syaibah] Abdullah berkata; dan saya mendengarnya dari [Abdullah bin Muhammad bin Abu Syaibah] berkata; telah menceritakan kepada kami [Ibnu Fudlail] dari ['Atho' bin As-Sa'ib] berkata; ada beberapa orang Bashrah yang menyaksikan, diantaranya adalah [Al Hasan bin Abu Al Hasan] dari [Ma'qil bin Sinan], Rasulullah Shallallahu'alahiwasallam melewatinya, dia sedang membekam pada tanggal delapan belas. (Rasulullah Shallallahu'alahiwasallam) kontan bersabda: \"Orang yang membekam dan yang dibekam telah batal puasanya.\""},"756":{"ar":"حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا كَهْمَسُ بْنُ الْحَسَنِ عَنْ سَيَّارِ بْنِ مَنْظُورٍ الْفَزَارِيِّ عَنْ أَبِيهِ عَنْ بُهَيْسَةَ عَنْ أَبِيهَا قَالَاسْتَأْذَنْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَخَلْتُ بَيْنَهُ وَبَيْنَ قَمِيصِهِ قَالَ فَقُلْتُ يَا رَسُولَ اللَّهِ مَا الشَّيْءُ الَّذِي لَا يَحِلُّ مَنْعُهُ قَالَ الْمَاءُ قُلْتُ يَا رَسُولَ اللَّهِ مَا الشَّيْءُ الَّذِي لَا يَحِلُّ مَنْعُهُ قَالَ الْمَاءُ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ مَا الشَّيْءُ الَّذِي لَا يَحِلُّ مَنْعُهُ قَالَ أَنْ تَفْعَلَ الْخَيْرَ خَيْرٌ لَكَحَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا كَهْمَسٌ قَالَ سَمِعْتُ سَيَّارَ بْنَ مَنْظُورٍ الْفَزَارِيَّ قَالَ حَدَّثَنِي أَبِي عَنْ بُهَيْسَةَ قَالَتِ اسْتَأْذَنَ أَبِي عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَخَلَ بَيْنَهُ وَبَيْنَ قَمِيصِهِ فَذَكَرَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Waki'] berkata; telah menceritakan kepada kami [Kahmas bin Al Hasan] dari [Sayyar bin Mandzur Al Fazari] dari [bapaknya] dari [Buhaisah] dari [bapaknya] berkata; saya meminta izin kepada Nabi Shallallahu'alaihiwasallam lalu saya masuk antara beliau dan bajunya. (bapaknya Buhaisah Radliyallahu'anhu) berkata; saya berkata \"Wahai Rasulullah, apakah yang tidak diperbolehkan untuk ditolak\"? (Rasulullah Shallallahu'alahiwasallam) menjawab, \"Air\". saya bertanya lagi \"Wahai Rasulullah, apakah yang tidak diperbolehkan untuk ditolak\"? (Rasulullah Shallallahu'alahiwasallam) menjawab, \"Air\". Saya bertanya \"Wahai Rasulullah, apakah yang tidak diperbolehkan untuk ditolak\"? beliau bersabda: \"Kamu berbuat kebaikan itu lebih baik bagimu\". Telah menceritakan kepada kami [Muhammad bin Ja'far] berkata; telah menceritakan kepada kami [Kahmas] berkata; saya telah mendengar [Sayyar bin Mandzur Al Fazari] berkata; telah menceritakan kepadaku [bapakku] dari [Buhaisah] berkata; bapakku meminta izin untuk menemui Nabi Shallallahu'alaihiwasallam, maka dia masuk antara beliau dan bajunya. Lalu menyebutkan secara maknanya."},"757":{"ar":"حَدَّثَنَا يَزِيدُ حَدَّثَنَا كَهْمَسٌ قَالَ حَدَّثَنِي سَيَّارُ بْنُ مَنْظُورٍ الْفَزَارِيُّ عَنْ أَبِيهِ عَنْ بُهَيْسَةَ قَالَتِاسْتَأْذَنَ أَبِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَعَلَ يَدْنُو مِنْهُ وَيَلْتَزِمُهُ ثُمَّ قَالَ يَا نَبِيَّ اللَّهِ مَا الشَّيْءُ الَّذِي لَا يَحِلُّ مَنْعُهُ قَالَ الْمَاءُ ثُمَّ قَالَ يَا نَبِيَّ اللَّهِ مَا الشَّيْءُ الَّذِي لَا يَحِلُّ مَنْعُهُ قَالَ الْمِلْحُ ثُمَّ قَالَ يَا نَبِيَّ اللَّهِ مَا الشَّيْءُ الَّذِي لَا يَحِلُّ مَنْعُهُ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ تَفْعَلْ الْخَيْرَ خَيْرٌ لَكَقَالَ فَانْتَهَى قَوْلُهُ إِلَى الْمَاءِ وَالْمِلْحِ قَالَ وَكَانَ ذَلِكَ الرَّجُلُ لَا يَمْنَعُ شَيْئًا وَإِنْ قَلَّ","id":"Telah menceritakan kepada kami [Yazid] telah menceritakan kepada kami [Kahmas] berkata; telah menceritakan kepadaku [Sayar bin Mandlur Al Fazari] dari [Bapaknya] dari [Buhaitsah], berkata; bapakku meminta ijin kepada Nabi Shallallahu'alaihiwasallam lalu dia mendekatinya dan menemaninya, lalu berkata; Wahai Nabiyullah apakah hal yang tidak boleh ditolak?. Beliau bersabda: \"Air\". Lalu dia bertanya lagi, Wahai Nabiyullah apa yang tidak boleh ditolak?. Beliau menjawab, \"Garam\". Lalu bertanya, Wahai Nabiyullah apa yang tidak boleh ditolak?. Beliau bersabda: \"Jika kamu melakukan kebaikan itu lebih baik bagimu.\" (Bapak Bukaitsah Radliyallahu'anhu) berkata; lalu perkataan sampai pada air dan garam. (Bapak Bukaitsah Radliyallahu'anhu) berkata; laki-laki tersebut tidak pernah menolak sesuatu apapun walaupun sedikit."},"758":{"ar":"قَالَ حَدَّثَنَا عَبْدُ اللَّهِ وَسَمِعْتُهُ أَنَا مِنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ شَيْبَةَ قَالَ حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ عَنْ يَحْيَى بْنِ الْحَارِثِ التَّيْمِيِّ عَنْ يَحْيَى بْنِ غَسَّانَ التَّيْمِيِّ عَنِ ابْنِ الرَّسِيمِ عَنْ أَبِيهِ أَنَّهُ قَالَوَفَدْنَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَهَانَا عَنْ الظُّرُوفِ قَالَ ثُمَّ قَدِمْنَا عَلَيْهِ فَقُلْنَا إِنَّ أَرْضَنَا أَرْضٌ وَخِمَةٌ قَالَ فَقَالَ اشْرَبُوا فِيمَا شِئْتُمْ مَنْ شَاءَ أَوْكَأَ سِقَاءَهُ عَلَى إِثْمٍ","id":"Telah menceritakan kepada kami Abdullah dan saya telah mendengarnya dari [Abdullah bin Muhammad bin Syaibah] berkata; telah menceritakan kepada kami [Abdurrahim bin Sulaiman] dari [Yahya bin Al Harits At Taimi] dari [Yahya bin Ghassan At Taimi] dari [Abu Ar Rasim] dari [bapakku] sesungguhnya dia berkata; kami mengutus utusan kepada Rasulullah Shallallahu'alahiwasallam, lalu beliau melarang kami menggunakan bejana yang terbuat dari kulit, lalu kami mendatangi beliau. (Abu Ar Rasim Radliyallahu'anhu) berkata; kami berkata; \"Sesungguhnya keadaan tanah kita tidak cocok dengan keadaan cuacanya\". maka beliau bersabda: \"Minumlah kalian menggunakan apa saja yang kalian sukai, siapa saja yang mau, silahkan mengikat tutup minumnya dengan menanggung dosa\"."},"759":{"ar":"حَدَّثَنَا حَسَنُ بْنُ مُوسَى قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُسْلِمٍ أَبُو زَيْدٍ عَنْ يَحْيَى بْنِ عَبْدِ اللَّهِ التَّيْمِيِّ عَنْ يَحْيَى بْنِ غَسَّانَ التَّيْمِيِّ عَنْ أَبِيهِ قَالَكَانَ أَبِي فِي الْوَفْدِ الَّذِينَ وَفَدُوا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ عَبْدِ قَيْسٍ فَنَهَاهُمْ عَنْ هَذِهِ الْأَوْعِيَةِ قَالَ فَأَتْخَمْنَا ثُمَّ أَتَيْنَاهُ الْعَامَ الْمُقْبِلَ قَالَ فَقُلْنَا يَا رَسُولَ اللَّهِ إِنَّكَ نَهَيْتَنَا عَنْ هَذِهِ الْأَوْعِيَةِ فَأَتْخَمْنَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْتَبِذُوا فِيمَا بَدَا لَكُمْ وَلَا تَشْرَبُوا مُسْكِرًا فَمَنْ شَاءَ أَوْكَأَ سِقَاءَهُ عَلَى إِثْمٍ","id":"Telah menceritakan kepada kami [Hasan bin Musa] berkata; telah menceritakan kepada kami [Abdul Aziz bin Muslim Abu Zaid] dari [Yahya bin Abdullah At Taimi] dari [Yahya bin Ghassan At Taimi] dari [Bapaknya] berkata; [bapakku] termasuk utusan yang diutus kepada Rasulullah Shallallahu'alahiwasallam dari Abdu Qais, beliau melarang mereka bejana-bejana ini. (Bapak Ghassan Radliyallahu'anhu) berkata; lalu kami merasa tidak enak makan, kami menemui beliau lagi satu tahun setelahnya. Lalu kami berkata; Wahai Rasulullah, sesungguhnya anda telah pernah melarang kami menggunakan bejana ini dan itu, lalu kami merasa tidak enak makan. Rasulullah Shallallahu'alahiwasallam bersabda: \"Oploslah minuman yang kelihatan layak bagi kalian, janganlah meminum yang memabukkan, sehingga mereka yang berkehendak mengikat tutup minumnya di atas dosa\"."},"760":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ مُحَمَّدٍ وَسَمِعْتُهُ أَنَا مِنْ عُثْمَانَ بْنِ مُحَمَّدِ بْنِ أَبِي شَيْبَةَ قَالَ حَدَّثَنَا سَعِيدُ بْنُ خُثَيْمٍ الْهِلَالِيُّ قَالَ سَمِعْتُ جَدَّتِي رَبِيعَةَ ابْنَةَ عِيَاضٍ قَالَتْ سَمِعْتُ جَدِّي عُبَيْدَةَ بْنَ عَمْرٍو الْكِلَابِيَّ يَقُولُرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ فَأَسْبَغَ الْوُضُوءَقَالَ وَكَانَتْ رِبْعِيَّةُ إِذَا تَوَضَّأَتْ أَسْبَغَتْ الْوُضُوءَ","id":"Telah menceritakan kepada kami ['Utsman bin Muhammad] dan saya telah mendengarnya dari ['Utsman bin Muhammad bin Abu Syaibah] berkata; telah menceritakan kepada kami [Sa'id bin Khutsaim Al Hilali] berkata; saya mendengar [kakek perempuanku, Rabi'ah binti Iyadl] berkata; saya mendengar [kakekku, 'Ubaidah bin 'Amr Al Killaby] berkata; saya melihat Rasulullah Shallallahu'alahiwasallam berwudlu dan menyempurnakanya. ('Ubaidah Radliyallahu'anhu) berkata; Rabi'ah jika berwudlu menyempurnakannya."},"761":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنَا لَيْثٌ عَنْ طَلْحَةَ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّهُ رَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْسَحُ رَأْسَهُ حَتَّى بَلَغَ الْقَذَالَ وَمَا يَلِيهِ مِنْ مُقَدَّمِ الْعُنُقِ مَرَّةًقَالَ الْقَذَالُ السَّالِفَةُ الْعُنُقِ","id":"Telah menceritakan kepada kami [Abdushamad bin Abdul Warits] berkata; telah menceritakan kepadaku [bapakku] berkata; telah menceritakan kepada kami [Laits] dari [Thalhah] dari [bapaknya] dari [kakeknya], dia pernah melihat Rasulullah Shallallahu'alahiwasallam mengusap kepalanya sampai bawah leher setelah itu adalah bagian atas leher sebanyak sekali. Dia berkata; bagian atas leher kemudian leher."},"762":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ قَالَ حَدَّثَنَا عَاصِمُ بْنُ أَبِي النَّجُودِ عَنِ الْحَارِثِ بْنِ حَسَّانَ الْبَكْرِيِّ قَالَقَدِمْنَا الْمَدِينَةَ فَإِذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمِنْبَرِ وَبِلَالٌ قَائِمٌ بَيْنَ يَدَيْهِ مُتَقَلِّدٌ السَّيْفَ بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَي��هِ وَسَلَّمَ وَإِذَا رَايَاتٌ سُودٌ وَسَأَلْتُ مَا هَذِهِ الرَّايَاتُ فَقَالُوا عَمْرُو بْنُ الْعَاصِ قَدِمَ مِنْ غَزَاةٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin 'Ayyasy] berkata; telah menceritakan kepada kami ['Ashim bin Abu An-Nujud] dari [Al Harits bin Hassan Al Bakri] berkata; kami datang ke Madinah, yang ketika itu Rasulullah Shallallahu'alahiwasallam sedang di atas Mimbar dan Bilal berdiri di depan beliau dengan membawa pedang. Lalu datanglah bendera hitam, saya bertanya, apakah bendera hitam ini? Maka mereka menjawab, \"Itu adalah 'Amar bin Al 'Ash yang datang dari perang\"."},"763":{"ar":"حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا سَلَّامٌ أَبُو الْمُنْذِرِ عَنْ عَاصِمِ بْنِ بَهْدَلَةَ عَنْ أَبِي وَائِلٍ عَنِ الْحَارِثِ بْنِ حَسَّانَ قَالَمَرَرْتُ بِعَجُوزٍ بِالرَّبَذَةِ مُنْقَطِعٌ بِهَا مِنْ بَنِي تَمِيمٍ قَالَ فَقَالَتْ أَيْنَ تُرِيدُونَ قَالَ فَقُلْتُ نُرِيدُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ فَاحْمِلُونِي مَعَكُمْ فَإِنَّ لِي إِلَيْهِ حَاجَةً قَالَ فَقُلْتُ فَدَخَلْتُ الْمَسْجِدَ فَإِذَا هُوَ غَاصٌّ بِالنَّاسِ وَإِذَا رَايَةٌ سَوْدَاءُ تَخْفِقُ فَقُلْتُ مَا شَأْنُ النَّاسِ الْيَوْمَ قَالُوا هَذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُرِيدُ أَنْ يَبْعَثَ عَمْرَو بْنَ الْعَاصِ وَجْهًا قَالَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنْ رَأَيْتَ أَنْ تَجْعَلَ الدَّهْنَاءَ حِجَازًا بَيْنَنَا وَبَيْنَ بَنِي تَمِيمٍ فَافْعَلْ فَإِنَّهَا كَانَتْ لَنَا مَرَّةً قَالَ فَاسْتَوْفَزَتْ الْعَجُوزُ وَأَخَذَتْهَا الْحَمِيَّةُ فَقَالَتْ يَا رَسُولَ اللَّهِ أَيْنَ تَضْطَرُّ مُضَرَكَ قُلْتُ يَا رَسُولَ اللَّهِ حَمَلْتُ هَذِهِ وَلَا أَشْعُرُ أَنَّهَا كَائِنَةٌ لِي خَصْمًا قَالَ قُلْتُ أَعُوذُ بِاللَّهِ أَنْ أَكُونَ كَمَا قَالَ الْأَوَّلُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَا قَالَ الْأَوَّلُ قَالَ عَلَى الْخَبِيرِ سَقَطْتَ يَقُولُ سَلَّامٌ هَذَا أَحْمَقُ يَقُولُ الرَّسُولُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْخَبِيرِ سَقَطْتَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هِيهْ يَسْتَطْعِمُهُ الْحَدِيثَ قَالَ إِنَّ عَادًا أَرْسَلُوا وَافِدَهُمْ قَيْلًا فَنَزَلَ عَلَى مُعَاوِيَةَ بْنِ بَكْرٍ شَهْرًا يَسْقِيهِ الْخَمْرَ وَتُغَنِّيهِ الْجَرَادَتَانِ فَانْطَلَقَ حَتَّى أَتَى عَلَى جِبَالِ مُهْرَةَ فَقَالَ اللَّهُمَّ إِنِّي لَمْ آتِ لِأَسِيرٍ أُفَادِيهِ وَلَا لِمَرِيضٍ فَأُدَاوِيَهُ فَاسْقِ عَبْدَكَ مَا كُنْتَ سَاقِيَهُ وَاسْقِ مُعَاوِيَةَ بْنَ بَكْرٍ شَهْرًا يَشْكُرْ لَهُ الْخَمْرَ الَّتِي شَرِبَهَا عِنْدَهُ قَالَ فَمَرَّتْ سَحَابَاتٌ سُودٌ فَنُودِيَ أَنْ خُذْهَا رَمَادًا رِمْدِدًا لَا تَذَرْ مِنْ عَادٍ أَحَدًاقَالَ أَبُو وَائِلٍ فَبَلَغَنِي أَنَّ مَا أُرْسِلَ عَلَيْهِمْ مِنْ الرِّيحِ كَقَدْرِ مَا يَجْرِي فِي الْخَاتَمِ","id":"Telah menceritakan kepada kami ['Affan] berkata; telah menceritakan kepada kami [Sallam Abu Al Mundzir] dari ['Ashim bin Bahdalah] dari [Abu Wa'il] dari [Al Harits bin Hassan] berkata; saya melewati seseorang yang sudah tua di Rabdzah berjalan sendirian dari Bani Tamim. (Al Harits bin Hassan Radliyallahu'anhu) berkata; dia bertanya: 'Kalian hendak kemana? ' (Al Harits bin Hassan Radliyallahu'anhu) berkata; saya menjawab, kami hendak menemui Rasulullah Shallallahu'alahiwasallam. Dia berkata; 'Ajaklah saya bersama kalian, saya memiliki keperluan kepada beliau.' (Al Harits bin Hassan Radliyallahu'anhu) berkata; saya masuk ke masjid, waktu itu beliau sedang dipenuhi orang-orang, dan di situ juga ada bendera hitam yang berkibar. Saya bertanya ada apa orang-orang pada hari ini? Mereka menjawab, Rasulullah Shallallahu'alahiwasallam hendak mengutus 'Amr bin Al 'Ash ke suatu peperangan. (Al Harits bin Hassan Radliyallahu'anhu) berkata; 'Wahai Rasulullah, bagaimana pendapat anda jika anda menjadikan Dahna' sebagai penghalang, antara kami dengan Bani Tamim?. Jika anda setuju, karena tempat itu menjadi tempat lewat kami.' (Al Harits bin Hassan Radliyallahu'anhu) berkata; orang tua tadi tidak tenang dalam duduknya dan mulai terlihat rasa fanatisme kesukuannya, lalu berkata; 'Wahai Rasulullah, di mana anda memaksa rasa masam anda. Saya berkata; Wahai Rasulullah, saya mengajak orang ini dan saya tidak merasa kalau dia mememusuhiku. (Al Harits bin Hassan Radliyallahu'anhu) berkata; saya berkata; saya berlindung kepada Allah jika saya menjadi sebagaimana yang dikatakan pertama kali. Rasulullah Shallallahu'alahiwasallam bertanya, apa yang dikatakan pertama. (Al Harits bin Hassan Radliyallahu'anhu) berkata; tepat kamu pada orang yang tahu, Sallam berkata; orang ini bodoh ini, Rasulullah Shallallahu'alahiwasallam bersabda: tepat kamu pada orang yang tahu. (Al Harits bin Hassan Radliyallahu'anhu) berkata; Rasulullah Shallallahu'alahiwasallam bersabda: \"Tambahkan kepadaku\", -beliau meminta tambahan perkataan cerita-. Dia berkata; sesungguhnya kaum 'Ad telah mengutus utusan mereka yaitu Qail, lalu singgah pada Mu'awiyah bin Bakr selama sebulan, dan memberinya minum dengan arak, ada dua budak yang bernyanyi untuknya, lalu dia pergi sampai di gunung Muhrah. Lalu berkata; Ya Allah, sesungguhnya saya tidak datang kepada tawanan yang akan saya tebus, juga bukan orang yang sakit lalu saya obati, berilah minum hamba-Mu dengan apa yang engkau kehendaki, berilah minum Mu'awiyah bin Bakr selama sebulan dengan arak yang dia minum. (Al Harits bin Hassan Radliyallahu'anhu) berkata; lalu lewatlah awan-awan yang hitam lalu diserukan agar mengambilnya untuk merusakkan serusak-rusaknya. Jangan tinggalkan kaum 'Ad satupun. Abu Wa'il berkata; sampai kepadaku, sesungguhnya yang dikirimkan kepada mereka berupa angin seukuran apa yang bisa melewati cincin."},"764":{"ar":"حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ قَالَ حَدَّثَنِي أَبُو الْمُنْذِرِ سَلَّامُ بْنُ سُلَيْمَانَ النَّحْوِيُّ قَالَ حَدَّثَنَا عَاصِمُ بْنُ أَبِي النَّجُودِ عَنْ أَبِي وَائِلٍ عَنِ الْحَارِثِ بْنِ يَزِيدَ الْبَكْرِيِّ قَالَخَرَجْتُ أَشْكُو الْعَلَاءَ بْنَ الْحَضْرَمِيِّ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَرَرْتُ بِالرَّبَذَةِ فَإِذَا عَجُوزٌ مِنْ بَنِي تَمِيمٍ مُنْقَطِعٌ بِهَا فَقَالَتْ لِي يَا عَبْدَ اللَّهِ إِنَّ لِي إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَاجَةً فَهَلْ أَنْتَ مُبَلِّغِي إِلَيْهِ قَالَ فَحَمَلْتُهَا فَأَتَيْتُ الْمَدِينَةَ فَإِذَا الْمَسْجِدُ غَاصٌّ بِأَهْلِهِ وَإِذَا رَايَةٌ سَوْدَاءُ تَخْفِقُ وَبِلَالٌ مُتَقَلِّدٌ السَّيْفَ بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ مَا شَأْنُ النَّاسِ قَالُوا يُرِيدُ أَنْ يَبْعَثَ عَمْرَو بْنَ الْعَاصِ وَجْهًا قَالَ فَجَلَسْتُ قَالَ فَدَخَلَ مَنْزِلَهُ أَوْ قَالَ رَحْلَهُ فَاسْتَأْذَنْتُ عَلَيْهِ فَأَذِنَ لِي فَدَخَلْتُ فَسَلَّمْتُ فَقَالَ هَلْ كَانَ بَيْنَكُمْ وَبَيْنَ بَنِي تَمِيمٍ شَيْءٌ قَالَ فَقُلْتُ نَعَمْ قَالَ وَكَانَتْ لَنَا الدَّبْرَةُ عَلَيْهِمْ وَمَرَرْتُ بِعَجُوزٍ مِنْ بَنِي تَمِيمٍ مُنْقَطِعٌ بِهَا فَسَأَلَتْنِي أَنْ أَحْمِلَهَا إِلَيْكَ وَهَا هِيَ بِالْبَابِ فَأَذِنَ لَهَا فَدَخَلَتْ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنْ رَأَيْتَ أَنْ تَجْعَلَ بَيْنَنَا وَبَيْنَ بَنِي تَمِيمٍ حَاجِزًا فَاجْعَلْ الدَّهْنَاءَ فَحَمِيَتْ الْعَجُوزُ وَاسْتَوْفَزَتْ قَالَتْ يَا رَسُولَ اللَّهِ فَإِلَى أَيْنَ تَضْطَرُّ مُضَرَكَ قَالَ قُلْتُ إِنَّمَا مَثَلِي مَا قَالَ الْأَوَّلُ مِعْزَاءُ حَمَلَتْ حَتْفَهَا حَمَلْتُ هَذِهِ وَلَا أَشْعُرُ أَنَّهَا كَانَتْ لِي خَصْمًا أَعُوذُ بِاللَّهِ وَرَسُولِهِ أَنْ أَكُونَ كَوَافِدِ عَادٍ قَالَ هِيهْ وَمَا وَافِدُ عَادٍ وَهُوَ أَعْلَمُ بِالْحَدِيثِ مِنْهُ وَلَكِنْ يَسْتَطْعِمُهُ قُلْتُ إِنَّ عَادًا قَحَطُوا فَبَعَثُوا وَافِدًا لَهُمْ يُقَالُ لَهُ قَيْلٌ فَمَرَّ بِمُعَاوِيَةَ بْنِ بَكْرٍ فَأَقَامَ عِنْدَهُ شَهْرًا يَسْقِيهِ الْخَمْرَ وَتُغَنِّيهِ جَارِيَتَانِ يُقَالُ لَهُمَا الْجَرَادَتَانِ فَلَمَّا مَضَى الشَّهْرُ خَرَجَ جِبَالَ تِهَامَةَ فَنَادَى اللَّهُمَّ إِنَّكَ تَعْلَمُ أَنِّي لَمْ أَجِئْ إِلَى مَرِيضٍ فَأُدَاوِيَهُ وَلَا إِلَى أَسِيرٍ فَأُفَادِيَهُ اللَّهُمَّ اسْقِ عَادًا مَا كُنْتَ تَسْقِيهِ فَمَرَّتْ بِهِ سَحَابَاتٌ سُودٌ فَنُودِيَ مِنْهَا اخْتَرْ فَأَوْمَأَ إِلَى سَحَابَةٍ مِنْهَا سَوْدَاءَ فَنُودِيَ مِنْهَا خُذْهَا رَمَادًا رِمْدِدًا لَا تُبْقِ مِنْ عَادٍ أَحَدًا قَالَ فَمَا بَلَغَنِي أَنَّهُ بُعِثَ عَلَيْهِمْ مِنْ الرِّيحِ إِلَّا قَدْرَ مَا يَجْرِي فِي خَاتِمِي هَذَا حَتَّى هَلَكُواقَالَ أَبُو وَائِلٍ وَصَدَقَ قَالَ فَكَانَتْ الْمَرْأَةُ وَالرَّجُلُ إِذَا بَعَثُوا وَافِدًا لَهُمْ قَالُوا لَا تَكُنْ كَوَافِدِ عَادٍ","id":"Telah menceritakan kepada kami [Zaib bin Al Habhab] berkata; telah menceritakan kepadaku [Abu Al Mundzir, Sallam bin Sulaiman Al Nahwi] berkata; telah menceritakan kepada kami ['Ashim bin Abu An-Nujud] dari [Abu Wa'il] dari [Al Harits bin Yazid Al Bakri] berkata; saya keluar hendak mengadukan Al 'Ala' bin Al Hadlrami kepada Rasulullah Shallallahu'alahiwasallam Lalu saya melewati Rabdzah, di sana ada nenek tua dari Bani Tamim berjalan sendirian. Lalu dia berkata kepadaku, Wahai Abdullah, saya hendak menuju Rasulullah Shallallahu'alahiwasallam karena suatu urusan, maukah kamu mengantarkan saya kepada beliau?. (Al Harits bin Yazid Al Bakri Radliyallahu'anhu) berkata; saya membawanya ke Madinah, ternyata masjid telah ramai dengan orang yang berada di dalamnya, di situ juga ada bendera hitam yang berkibar. Bilal sedang menenteng pedang di depan Rasulullah Shallallahu'alahiwasallam. Saya bertanya, ada apa dengan orang-orang? Mereka menjawab, (Rasulullah Shallallahu'alahiwasallam) hendak mengutus 'Amr bin Al 'Ash ke suatu lokasi. (Al Harits bin Yazid Al Bakri Radliyallahu'anhu) berkata; saya duduk, dan beliau masuk ke dalam rumah beliau, atau kendaraannya, saya meminta ijin kepada beliau, beliau mengijinkannya. Saya masuk dan mengucapkan salam kepada beliau. Beliau bertanya, apakah antara kalian dan Bani Tamim ada masalah yang harus dipecahkan?. (Al Harits bin Yazid Al Bakri Radliyallahu'anhu) berkata; saya menjawab, Ya. Kami menguasai mereka, saya melewati seseorang wanita tua dari Bani Tamim yang berjalan sendirian, dia memintaku untuk mengajaknya menemui anda dan ini orangnya ada di depan pintu. Beliau pun mengijinkannya dan dia masuk. Saya berkata; Wahai Rasulullah, jika anda berkenan, tolong buatlah benteng yang menghalangi antara antara kami dengan Bani Tamim, dan buatlah padang luas yang terbuka. Nenek tua tadi kontan terlihat rasa fanatisme sukunya dan duduk bergerak kesana-kesini pertanda nggak suka. Dia berkata; 'Wahai Rasulullah, di mana anda memaksa bani Mudharmu?. (Al Harits bin Yazid Al Bakri Radliyallahu'anhu) berkata; saya katakan, permisalanku sebagaimana yang dikatakan pertama kali, 'Padang tandus yang membawa bebatuannya' -maksudnya Harits bin Yazid membawa musuh bebuyutan- saya mengajak wanita tua ini, saya tidak merasa kalau dia ternyata musuh bagiku. Saya berlindung kepada Allah dan Rasul-Nya, jika saya seperti utusan kepada kaum 'Ad. Beliau bersabda: \"Apakah utusan 'Ad itu?\", padahal beliau lebih tahu dengan yang terjadi tentangnya namun beliau memintanya di jelaskan. Saya berkata; kaum 'Ad mengalami masa paceklik, lalu mengutus seseorang yang bernama Qail bin 'Athar, selanjutnya dia singgah di Mu'awiyah bin Bakr. Dia singgah di tempatnya selama sebulan. Qail menjamunya dengan minuman arak, sedang dua budak yang bernama Al Jaradatan mendendangkan lagu-lagu untuknya. Setelah habis sebulan, Qail pergi ke gunung Tihamah lalu berkata; 'Ya Allah, sungguh Kamu tahu bahwa saya tidak datang kepada orang yang sakit untuk saya obati, tidak pula kepada tawanan untuk saya tebus, berilah siraman hujan kepada kaum 'Ad, hanya kamu yang memberi mereka minuman, awan-awan hitam datang mengepul, lalu adau suara panggilan dari awan itu 'pilihlah'. Qail memberi isyarat ke arah awan yang berwarna hitam, kontan ada suara panggilan dari awan tersebut 'Ambillah sebagai awan yang menghancurkan sehancur-hancurnya.' Jangan kau tinggalkan kaum 'Ad seorang pun. (Al Harits bin Yazid Al Bakri Radliyallahu'anhu) berkata; berita yang sampai kepadaku angin yang dikirim kepada mereka kecuali hanya seukuran angin yang bisa melewati cincinku ini namun mereka musnah. Abu Wa'il berkata; dan benar. (Al Harits bin Yazid Al Bakri Radliyallahu'anhu) berkata; atas kejadian ini, jika ada seorang laki-laki maupun wanita mengutus utusan, mereka menyampaikan pesan, 'Namun kalian janganlah seperti utusan kaum 'Ad.'"},"765":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا سَعِيدٌ الْجُرَيْرِيُّ عَ��ْ أَبِي السَّلِيلِ عَنْ أَبِي تَمِيمَةَ الْهُجَيْمِيِّ قَالَ إِسْمَاعِيلُ مَرَّةً عَنْ أَبِي تَمِيمَةَ الْهُجَيْمِيِّ عَنْ رَجُلٍ مِنْ قَوْمِهِ قَالَلَقِيتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَعْضِ طُرُقِ الْمَدِينَةِ وَعَلَيْهِ إِزَارٌ مِنْ قُطْنٍ مُنْتَثِرُ الْحَاشِيَةِ فَقُلْتُ عَلَيْكَ السَّلَامُ يَا رَسُولَ اللَّهِ فَقَالَ إِنَّ عَلَيْكَ السَّلَامَ تَحِيَّةُ الْمَوْتَى إِنَّ عَلَيْكَ السَّلَامَ تَحِيَّةُ الْمَوْتَى إِنَّ عَلَيْكَ السَّلَامَ تَحِيَّةُ الْمَوْتَى سَلَامٌ عَلَيْكُمْ سَلَامٌ عَلَيْكُمْ مَرَّتَيْنِ أَوْ ثَلَاثًا هَكَذَا قَالَ سَأَلْتُ عَنْ الْإِزَارِ فَقُلْتُ أَيْنَ أَتَّزِرُ فَأَقْنَعَ ظَهْرَهُ بِعَظْمِ سَاقِهِ وَقَالَ هَاهُنَا اتَّزِرْ فَإِنْ أَبَيْتَ فَهَاهُنَا أَسْفَلَ مِنْ ذَلِكَ فَإِنْ أَبَيْتَ فَهَاهُنَا فَوْقَ الْكَعْبَيْنِ فَإِنْ أَبَيْتَ فَإِنَّ اللَّهَ عَزَّ وَجَلَّ لَا يُحِبُّ كُلَّ مُخْتَالٍ فَخُورٍ قَالَ وَسَأَلْتُهُ عَنْ الْمَعْرُوفِ فَقَالَ لَا تَحْقِرَنَّ مِنْ الْمَعْرُوفِ شَيْئًا وَلَوْ أَنْ تُعْطِيَ صِلَةَ الْحَبْلِ وَلَوْ أَنْ تُعْطِيَ شِسْعَ النَّعْلِ وَلَوْ أَنْ تَنْزِعَ مِنْ دَلْوِكَ فِي إِنَاءِ الْمُسْتَسْقِي وَلَوْ أَنْ تُنَحِّيَ الشَّيْءَ مِنْ طَرِيقِ النَّاسِ يُؤْذِيهِمْ ��َلَوْ أَنْ تَلْقَى أَخَاكَ وَوَجْهُكَ إِلَيْهِ مُنْطَلِقٌ وَلَوْ أَنْ تَلْقَى أَخَاكَ فَتُسَلِّمَ عَلَيْهِ وَلَوْ أَنْ تُؤْنِسَ الْوُحْشَانَ فِي الْأَرْضِ وَإِنْ سَبَّكَ رَجُلٌ بِشَيْءٍ يَعْلَمُهُ فِيكَ وَأَنْتَ تَعْلَمُ فِيهِ نَحْوَهُ فَلَا تَسُبَّهُ فَيَكُونَ أَجْرُهُ لَكَ وَوِزْرُهُ عَلَيْهِ وَمَا سَرَّ أُذُنَكَ أَنْ تَسْمَعَهُ فَاعْمَلْ بِهِ وَمَا سَاءَ أُذُنَكَ أَنْ تَسْمَعَهُ فَاجْتَنِبْهُ","id":"Telah menceritakan kepada kami [Isma'il bin Ibrahim] berkata; telah menceritakan kepada kami [Sa'id Al Jurairi] dari [Abu As-Salil] dari [Abu Tamimah Al Hujaimi]. [Isma'il] berkata pada kali lain, dari [Abu Tamimah Al Hujaimi] dari [seorang laki-laki kaumnya] berkata; saya bertemu Rasulullah Shallallahu'alahiwasallam di salah satu jalan di Madinah dan beliau memakai sarung yang terbuat dari kapas yang ujungnya terjuntai. Saya berkata; \"Semoga keselamatan atas anda, wahai Rasulullah\". Lalu (Rasulullah Shallallahu'alahiwasallam) bersabda: \"Sesungguhnya 'ALAIKASSALAM (semoga keselamatan atas kamu), adalah doa keselamatan untuk orang yang telah meninggal. Sesungguhnya 'ALAIKASSALAM, adalah doa keselamatan untuk orang yang telah meninggal. Sesungguhnya 'ALAIKASSALAM, adalah doa keselamatan untuk orang yang telah meninggal. Semoga keselamatan atas kalian, semoga keselamatan atas kalian, dua kali atau tiga kali. (seorang laki-laki kaum Abu Tamimah) berkata; saya bertanya tentang memakai sarung, dimana saya memakai sarung? Beliau lalu mengangkat ujung sarung sampai pertengahan betisnya lantas dia berkata; 'Disinilah tempatnya.' Jika kamu enggan maka turunkanlah sedikit dari itu, jika kamu masih enggan juga, maka tempatnya adalah di atas kedua tumit kaki, jika kamu masih enggan juga, sesungguhnya Allah Azzawajalla tidak menyukai orang yang sombong lagi memamerkan diri. Lalu saya bertanya tentang perkara kebaikan. Maka beliau bersabda: \"Janganlah menyepelekan perkara kebaikan sedikitpun, walau hanya dengan memberikan tali, walau hanya memberikan tali sandal, walau hanya mengisi dari embermu kepada orang yang butuh air, Walau menyingkirkan sesuatu dari jalan yang dapat mengganggu manusia, walaupun hanya bertemu dengan saudaramu dalam keadaan wajah yang berseri, walaupun jika kau bertemu saudaramu, lalu kamu mengucapkan salam untuknya, walaupun hanya lemah-lembut terhadap binatang liar yang di bumi. Jika ada seseorang yang mencelamu, karena dia tahu keburukanmu dan kamu juga tahu keburukannya, maka janganlah kamu mencelanya, maka pahalanya akan menjadi milikmu dan dosanya dilimpahkan kepadanya. Apa yang telingamu senang untuk mendengarnya, lakukanlah! Dan segala hal yang telingamu tidak suka mendengarnya, jauhilah."},"766":{"ar":"قَالَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ عَنِ الْجُرَيْرِيِّ عَنْ أَبِي الْعَلَاءِ بْنِ الشِّخِّيرِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ صُحَارٍ الْعَبْدِيِّ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُومُ السَّاعَةُ حَتَّى يُخْسَفَ بِقَبَائِلَ فَيُقَالُ مَنْ بَقِيَ مِنْ بَنِي فُلَانٍ قَالَ فَعَرَفْتُ حِينَ قَالَ قَبَائِلَ أَنَّهَا الْعَرَبُ لِأَنَّ الْعَجَمَ تُنْسَبُ إِلَى قُرَاهَا","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Isma'il bin Ibrahim] dari [Al Jurairi] dari [Abu Al 'Ala'i bin Asy-Syikhkhir] dari [Abdurrahman bin Shuhar Al 'Abdy] dari [bapaknya] berkata; Rasulullah Shallallahu'alahiwasallam bersabda: \"Tidak akan datang Hari Kiamat sampai ditenggelamkan kabilah-kabilah ke bumi\", lalu ditanyakan, siapakah yang tersisa dari Bani Fulan? lalu berkata; saya mengetahuinya maksud dari kata kabilah-kabilah, sesungguhnya itu adalah adalah Arab karena orang-orang selain Arab menisbatkan diri mereka kepada desa tempat tinggal mereka."},"767":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الطَّيَالِسِيُّ قَالَ وَحَدَّثَنَا الضَّحَّاكُ بْنُ يَسَارٍ قَالَ حَدَّثَنَا يَزِيدُ بْنُ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ صُحَارٍ الْعَبْدِيُّ عَنْ أَبِيهِ قَالَاسْتَأْذَنْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَأْذَنَ لِي فِي جَرَّةٍ أَنْتَبِذُ فِيهَا فَرَخَّصَ لِي فِيهَا أَوْ أَذِنَ لِي فِيهَا","id":"Telah menceritakan kepada kami [Sulaiman bin Daud Al Thayalisi] berkata; dan telah menceritakan kepada kami [Al Dlahak bin Yasar] berkata; telah menceritakan kepada kami [Yazid bin Abdullah bin Asy-Syikhir] berkata; telah menceritakan kepada kami [Abdurrahman bin Shuhar Al 'Abdi] dari [bapaknya] berkata; saya meminta izin Rasulullah Shallallahu'alahiwasallam untuk memakai bejana yang terbuat dari tanah liat untuk memeras anggur maka beliau memperbolehkan atau mengizinkan hal tersebut."},"768":{"ar":"حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ قَالَ حَدَّثَنَا أَبُو عَقِيلٍ يَعْنِي الثَّقَفِيَّ عَبْدَ اللَّهِ بْنَ عَقِيلٍ حَدَّثَنَا مُوسَى بْنُ الْمُسَيَّبِ أَخْبَرَنِي سَالِمُ بْنُ أَبِي الْجَعْدِ عَنْ سَبْرَةَ بْنِ أَبِي فَاكِهٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ الشَّيْطَانَ قَعَدَ لِابْنِ آدَمَ بِأَطْرُقِهِ فَقَعَدَ لَهُ بِطَرِيقِ الْإِسْلَامِ فَقَالَ لَهُ أَتُسْلِمُ وَتَذَرُ دِينَكَ وَدِينَ آبَائِكَ وَآبَاءِ أَبِيكَ قَالَ فَعَصَاهُ فَأَسْلَمَ ثُمَّ قَعَدَ لَهُ بِطَرِيقِ الْهِجْرَةِ فَقَالَ أَتُهَاجِرُ وَتَذَرُ أَرْضَكَ وَسَمَاءَكَ وَإِنَّمَا مَثَلُ الْمُهَاجِرِ كَمَثَلِ الْفَرَسِ فِي الطِّوَلِ قَالَ فَعَصَاهُ فَهَاجَرَ قَالَ ثُمَّ قَعَدَ لَهُ بِطَرِيقِ الْجِهَادِ فَقَالَ لَهُ هُوَ جَهْدُ النَّفْسِ وَالْمَالِ فَتُقَاتِلُ فَتُقْتَلُ فَتُنْكَحُ الْمَرْأَةُ وَيُقَسَّمُ الْمَالُ قَالَ فَعَصَاهُ فَجَاهَدَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَنْ فَعَلَ ذَلِكَ مِنْهُمْ فَمَاتَ كَانَ حَقًّا عَلَى اللَّهِ أَنْ يُدْخِلَهُ الْجَنَّةَ أَوْ قُتِلَ كَانَ حَقًّا عَلَى اللَّهِ عَزَّ وَجَلَّ أَنْ يُدْخِلَهُ الْجَنَّةَ وَإِنْ غَرِقَ كَانَ حَقًّا عَلَى اللَّهِ أَنْ يُدْخِلَهُ الْجَنَّةَ أَوْ وَقَصَتْهُ دَابَّتُهُ كَانَ حَقًّا عَلَى اللَّهِ أَنْ يُدْخِلَهُ الْجَنَّةَ","id":"Telah menceritakan kepada kami [Hasyim bin Al Qasim] berkata; telah menceritakan kepada kami [Abu 'Aqil] yaitu Ats-Staqafi, Abdullah bin 'Aqil, telah menceritakan kepada kami [Musa bin Al Musayyab] telah mengabarkan kepadaku [Salim bin Abu Al Jad] dari [Sabrah bin Abu Fakih] berkata; saya mendengar Rasulullah Shallallahu'alahiwasallam bersabda: \"Setan menghalangi anak Adam dari banyak jalan. Dia duduk di jalan Islam, dia berkata kepada manusia, 'Apakah engkau mau masuk Islam dan meninggalkan agamamu dan agama nenek moyangmu? ' (Rasulullah Shallallahu'alahiwasallam) bersabda: \"Lalu orang tersebut tidak menurutinya dan dia masuk Islam\" Lalu setan menghalanginya dari jalan hijrah, dengan berkata; apakah kamu akan berhijrah meninggalkan bumimu dan langitmu?. Permisalan orang yang berhijrah sebagaimana kuda yang ditambat. (Rasulullah Shallallahu'alahiwasallam) bersabda: lalu manusia tidak menurutinya dan dia tetap berhijrah. (Rasulullah Shallallahu'alahiwasallam) bersabda: lantas dia menghadangnya dari pintu jihad dan berkata; \"Jihad adalah mengorbankan harta dan nyawa, engkau mau membunuh dan terbunuh, dan istrimu akan dinikahi orang lain dan hartamu akan dibagi-bagikan?, (Rasulullah Shallallahu'alahiwasallam) bersabda: orang itu menolaknya dan tetap berjihad. Rasulullah Shallallahu'alahiwasallam bersabda: \"Barangsiapa yang berbuat seperti itu di antara mereka dan mati dalam keadaan tersebut, maka Allah memasukkannya ke surga\" ataupun dia terbunuh maka kewajiban Allah Azzawajalla untuk memasukkan ke surga. Jika dia tenggelam, maka kewajiban Allah untuk memasukkan dia ke surga ataupun juga di tewas karena kendaraannya, maka kewajiban Allah untuk memasukkannya ke surga\"."},"769":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ هِشَامِ بْنِ عُرْوَةَ قَالَ أَخْبَرَنِي أَبِي عَنْ عَبْدِ اللَّهِ بْنِ أَرْقَمَأَنَّهُ حَجَّ فَكَانَ يُصَلِّي بِأَصْحَابِهِ يُؤَذِّنُ وَيُقِيمُ فَأَقَامَ يَوْمًا الصَّلَاةَ وَقَالَ لِيُصَلِّ أَحَدُكُمْ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا أَرَادَ أَحَدُكُمْ أَنْ يَذْهَبَ إِلَى الْخَلَاءِ وَأُقِيمَتْ الصَّلَاةُ فَلْيَذْهَبْ إِلَى الْخَلَاءِ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Hisyam bin 'Urwah] berkata; telah mengabarkan kepadaku [bapakku] dari [Abdullah bin Arqam] sesungguhnya dia berhaji, dia shalat bersama para sahabatnya. Dia melantunkan adzan dan iqamah, lalu didirikan shalat pada suatu hari, lalu dia berkata; Shalatlah salah seorang dari kalian, saya mendengar Rasulullah Shallallahu'alahiwasallam bersabda: \"Apabila salah seorang di antara kalian hendak pergi ke WC, dan shalat sedang didirikan, pergilah ke WC dulu\"."},"770":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبِي حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَاقَ عَنْ أَبَانَ بْنِ صَالِحٍ عَنِ الْفَضْلِ بْنِ عَبْدِ اللَّهِ بْنِ مَعْقِلِ بْنِ سِنَانٍ عَنْ عَبْدِ اللَّهِ بْنِ نِيَارٍ الْأَسْلَمِيِّ عَنْ عَمْرِو بْنِ شَأْسٍ الْأَسْلَمِيِّ قَالَ وَكَانَ مِنْ أَصْحَابِ الْحُدَيْبِيَةِ قَالَخَرَجْتُ مَعَ عَلِيٍّ إِلَى الْيَمَنِ فَجَفَانِي فِي سَفَرِي ذَلِكَ حَتَّى وَجَدْتُ فِي نَفْسِي عَلَيْهِ فَلَمَّا قَدِمْتُ أَظْهَرْتُ شَكَايَتَهُ فِي الْمَسْجِدِ حَتَّى بَلَغَ ذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَخَلْتُ الْمَسْجِدَ ذَاتَ غُدْوَةٍ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نَاسٍ مِنْ أَصْحَابِهِ فَلَمَّا رَآنِي أَمَدَّنِي عَيْنَيْهِ يَقُولُ حَدَّدَ إِلَيَّ النَّظَرَ حَتَّى إِذَا جَلَسْتُ قَالَ يَا عَمْرُو وَاللَّهِ لَقَدْ آذَيْتَنِي قُلْتُ أَعُوذُ بِاللَّهِ أَنْ أُوذِيَكَ يَا رَسُولَ اللَّهِ قَالَ بَلَى مَنْ آذَى عَلِيًّا فَقَدْ آذَانِي","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Aban bin Shalih] dari [Al Fadl bin Abdullah bin Ma'qil bin Sinan] dari [Abdullah bin Niyar Al Aslami] dari ['Amr bin Sya'si Al Aslamy] berkata; dia termasuk dari ahli Hudaibiyah berkata; saya bepergian bersama 'Ali ke Yaman, 'Ali berbuat kasar terhadapku dalam perjalanan itu sehingga saya marah terhadapnya. Ketika sampai di tujuan, saya mengadukan kejadian tersebut di masjid, hingga hal tersebut sampai pada Rasulullah Shallallahu'alahiwasallam, saya masuk ke masjid pada suatu pagi dan Rasulullah Shallallahu'alahiwasallam berada dalam kerumunan para sahabatnya. Ketika beliau melihatku, beliau menajamkan pandangannya seolah-olah mengancamku dengan pandangan beliau. Tatkala saya sudah duduk beliau bersabda: \"Wahai 'Amr, Demi Allah, sungguh kamu telah menyakitiku\" Saya menjawab, \"Saya berlindung kepada Allah jika saya menyakiti anda, wahai Rasulullah\". Lalu beliau bersabda: \"Ya, barangsiapa yang menyakiti 'Ali, dia telah menyakitiku\"."},"771":{"ar":"حَدَّثَنَا أَبُو النَّضْرِ قَالَ حَدَّثَنَا الْمُرَجَّى بْنُ رَجَاءٍ الْيَشْكُرِيُّ قَالَ حَدَّثَنِي سَلْمُ بْنُ عَبْدِ الرَّحْمَنِ قَالَ سَمِعْتُ سَوَادَةَ بْنَ الرَّبِيعِ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلْتُهُ فَأَمَرَ لِي بِذَوْدٍ ثُمَّ قَالَ لِي إِذَا رَجَعْتَ إِلَى بَيْتِكَ فَمُرْهُمْ فَلْيُحْسِنُوا غِذَاءَ رِبَاعِهِمْ وَمُرْهُمْ فَلْيُقَلِّمُوا أَظْفَارَهُمْ وَلَا يَعْبِطُوا بِهَا ضُرُوعَ مَوَاشِيهِمْ إِذَا حَلَبُوا","id":"Telah menceritakan kepada kami [Abu Nadlr] berkata; telah menceritakan kepada kami [Al Murajja bin Raja' Al Yasykuri] berkata; telah menceritakan kepadaku [Salm bin Abdurrahman] berkata; saya mendengar [Sawadah bin Ar Rabi'] berkata; saya mendatangi Nabi Shallallahu'alaihiwasallam lalu saya bertanya, beliau menyuruhku dengan sekumpulan unta (antara3-10) lalu bersabda: \"Jikalau kamu pulang ke rumahmu maka suruhlah mereka untuk tidak menyapih anak unta dari induk-induknya, dan perintahlah mereka untuk memotong kuku mereka. Janganlah serampangan dalam bersikap terhadap unta ternaknya ketika memeras susunya\""},"772":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ أَبِي بَكْرِ بْنِ مُحَمَّدٍ عَنْ حَبِيبِ بْنِ هِنْدِ بْنِ أَسْمَاءَ الْأَسْلَمِيِّ عَنْ هِنْدِ بْنِ أَسْمَاءَ قَالَبَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى قَوْمِي مِنْ أَسْلَمَ فَقَالَ مُرْ قَوْمَكَ فَلْيَصُومُوا هَذَا الْيَوْمَ يَوْمَ عَاشُورَاءَ فَمَنْ وَجَدْتَهُ مِنْهُمْ قَدْ أَكَلَ فِي أَوَّلِ يَوْمِهِ فَلْيَصُمْ آخِرَهُ","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim] berkata; telah menceritakan kepada kami [bapakku] dari [Ibnu Ishaq] berkata; telah menceritakan kepada kami [Abdurrahman bin Abu Bakar bin Muhammad] dari [Habib bin Hind bin Asma' Al Aslami] dari [Hind bin Asma'] berkata; Rasulullah Shallallahu'alahiwasallam mengutusku menuju kaumku dari Aslam dan bersabda: \"Suruhlah kaum-mu untuk berpuasa hari ini yaitu hari 'Asyura', siapa saja yang kamu temukan telah makan dari mereka pada hari ini, hendaklah mereka berpuasa pada penghujung harinya (maksudnya meneruskan puasanya) \"."},"773":{"ar":"قَالَ حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ حَرْمَلَةَ عَنْ يَحْيَى بْنِ هِنْدِ بْنِ حَارِثَةَ وَكَانَ هِنْدٌ مِنْ أَصْحَابِ الْحُدَيْبِيَةِ وَأَخُوهُ الَّذِي بَعَثَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُ قَوْمَهُ بِصِيَامِ عَاشُورَاءَ وَهُوَ أَسْمَاءُ بْنُ حَارِثَةَ فَحَدَّثَنِي يَحْيَى بْنُ هِنْدٍ عَنْ أَسْمَاءَ بْنِ حَارِثَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَهُ فَقَالَ مُرْ قَوْمَكَ بِصِيَامِ هَذَا الْيَوْمِ قَالَ أَرَأَيْتَ إِنْ وَجَدْتُهُمْ قَدْ طَعِمُوا قَالَ فَلْيُتِمُّوا آخِرَ يَوْمِهِمْ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami ['Affan] berkata; telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Abdurrahman bin Harmalah] dari Yahya bin Haritsah, Hind adalah salah seorang pengikut dalam Peristiwa Hudaibiyyah, dan saudaranya yang mengutusnya. Dia berkata; suruhlah kaummu dengan berpuasa 'Asyura'. Dia adalah Asma' bin Haristsah lalu dia menceritakan kepadaku [Yahya bin Hind] dari [Asma' bin Haristsah], Rasulullah Shallallahu'alahiwasallam mengutusnya, lalu bersabda: \"Suruhlah kaummu untuk berpuasa pada hari ini\" dia bertanya, bagaimana pendapat anda jika saya mendapati mereka telah makan? Beliau bersabda: \"Sempurnakanlah sampai akhir hari\"."},"774":{"ar":"قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ هِشَامٍ يَعْنِي ابْنَ عُرْوَةَ قَالَ أَخْبَرَنِي أَبِي عَنِ الْأَحْنَفِ بْنِ قَيْسٍ عَنْ عَمٍّ لَهُ يُقَالُ لَهُ جَارِيَةُ بْنُ قُدَامَةَأَنَّ رَجُلًا قَالَ لَهُ يَا رَسُولَ اللَّهِ قُلْ لِي قَوْلًا وَأَقْلِلْ عَلَيَّ لَعَلِّي أَعْقِلُهُ قَالَ لَا تَغْضَبْ فَأَعَادَ عَلَيْهِ مِرَارًا كُلُّ ذَلِكَ يَقُولُ لَا تَغْضَبْقَالَ يَحْيَى كَذَا قَالَ هِشَامٌ قُلْتُ يَا رَسُولَ اللَّهِ وَهُمْ يَقُولُونَ لَمْ يُدْرِكْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Hisyam] yaitu Ibnu 'Urwah, berkata; telah mengabarkan kepadaku [bapakku] dari [Al Ahnaf bin Qais] dari [salah seorang pamannya] yang bernama Jariyah bin Qudamah, Ada seorang laki-laki berkata kepadanya, Wahai Rasulullah, katakanlah kepadaku satu perkataan dan ringankanlah itu supaya saya dapat memahaminya?. lalu beliau bersabda: \"Janganlah kamu marah\", beliau mengulanginya berkali-kali, semuanya berbunyi, \"Janganlah kamu marah\". Yazid berkata; begini. Hisyam berkata; Wahai Rasulullah. Mereka berkata dia tidak mengetahui Nabi Shallallahu'alaihiwasallam."},"775":{"ar":"حَدَّثَنَا عِصَامُ بْنُ خَالِدٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ بْنِ أَبِي إِسْحَاقَ الْهَمْدَانِيُّ عَنْ أَبِيهِ عَنْ جَدِّهِ عَنْ ذِي الْجَوْشَنِ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ أَنْ فَرَغَ مِنْ أَهْلِ بَدْرٍ بِابْنِ فَرَسٍ لِي فَقُلْتُ يَا مُحَمَّدُ إِنِّي قَدْ جِئْتُكَ بِابْنِ الْعَرْجَاءِ لِتَتَّخِذَهُ قَالَ لَا حَاجَةَ لِي فِيهِ وَلَكِنْ إِنْ شِئْتَ أَنْ أَقِيضَكَ بِهِ الْمُخْتَارَةَ مِنْ دُرُوعِ بَدْرٍ فَقُلْتُ مَا كُنْتُ لِأَقِيضَكَ الْيَوْمَ بِعُدَّةٍ قَالَ فَلَا حَاجَةَ لِي فِيهِ ثُمَّ قَالَ يَا ذَا الْجَوْشَنِ أَلَا تُسْلِمُ فَتَكُونَ مِنْ أَوَّلِ هَذَا الْأَمْرِ قُلْتُ لَا قَالَ لِمَ قُلْتُ إِنِّي رَأَيْتُ قَوْمَكَ قَدْ وَلِعُوا بِكَ قَالَ فَكَيْفَ بَلَغَكَ عَنْ مَصَارِعِهِمْ بِبَدْرٍ قَالَ قُلْتُ بَلَغَنِي قَالَ قُلْتُ إِنْ تَغْلِبْ عَلَى مَكَّةَ وَتَقْطُنْهَا قَالَ لَعَلَّكَ إِنْ عِشْتَ أَنْ تَرَى ذَلِكَ قَالَ ثُمَّ قَالَ يَا بِلَالُ خُذْ حَقِيبَةَ الرَّجُلِ فَزَوِّدْهُ مِنْ الْعَجْوَةِ فَلَمَّا أَنْ أَدْبَرْتُ قَالَ أَمَا إِنَّهُ مِنْ خَيْرِ بَنِي عَامِرٍ قَالَ فَوَاللَّهِ إِنِّي لَبِأَهْلِي بِالْغَوْرِ إِذْ أَقْبَلَ رَاكِبٌ فَقُلْتُ مِنْ أَيْنَ قَالَ مِنْ مَكَّةَ فَقُلْتُ مَا فَعَلَ النَّاسُ قَالَ قَدْ غَلَبَ عَلَيْهَا مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قُلْتُ هَبِلَتْنِي أُمِّي فَوَاللَّهِ لَوْ أُسْلِمُ يَوْمَئِذٍ ثُمَّ أَسْأَلُهُ الْحِيرَةَ لَأَقْطَعَنِيهَاحَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَالْحَكَمُ بْنُ مُوسَى قَالَا حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ أَبِيهِ عَنْ جَدِّهِ عَنْ ذِي الْجَوْشَنِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عَبَّادٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَاقَ عَنْ ذِي الْجَوْشَنِ أَبِي شِمْرٍ الضِّبَابِيِّ نَحْوَ هَذَا الْحَدِيثِ قَالَ سُفْيَانُ فَكَانَ ابْنُ ذِي الْجَوْشَنِ جَارًا لِأَبِي إِسْحَاقَ لَا أُرَاهُ إِلَّا سَمِعَهُ مِنْهُ","id":"Telah menceritakan kepada kami ['Isham bin Khalid] telah menceritakan kepada kami ['Isa bin Yunus bin Abu Ishaq Al Hamdani] dari [Bapaknya] dari [kakeknya] dari [Dzil Jausyan] berkata; saya menemui Nabi Shallallahu'alaihiwasallam setelah beliau menemui Ahli Badar dengan anak kuda milikku. Saya berkata; Wahai Muhammad! Saya datang kepada anda, saya membawa Ibnu Al Arja', agar anda mengambilnya. Beliau bersabda: \"Saya tidak berminat dengannya, namun jika kau mau, saya akan menggantikan dengan anak kuda itu untukmu dengan baju besi dari Badar yang mahal. Saya berkata; saya tidak akan menukarkannya hari ini dengan barang lain. (Rasulullah Shallallahu'alahiwasallam) bersabda: \"Saya tidak ada keperluan dengan barang itu\" lalu bersabda: \"Wahai Dzal Jausyan!, tidakkah kau masuk Islam, lalu kamu menjadi menjadi orang yang pertama pada urusan ini\". Saya berkata; tidak. (Rasulullah Shallallahu'alahiwasallam) bersabda: \"Kenapa?\" Saya menjawab, saya melihat kaum anda telah terkena fitnah dengan anda. Beliau bersabda: \"Bagaimana kabar yang sampai padamu tentang tempat meninggalnya mereka di Badar?.\" (Dzil Jausyan Radliyallahu'anhu) berkata; ya, telah sampai kepadaku. Bisakah anda mengalahkan Makkah dan anda tinggal di dalamnya?. Beliau bersabda: \"Semoga jika kau masih hidup, kamu bisa menyaksikan hal itu\". (Dzil Jausyan Radliyallahu'anhu) berkata; beliau bersabda: \"Wahai Bilal, ambilah tas orang ini dan isilah dengan kurma 'Ajuwa. Tatkala saya hendak berangkat, beliau bersabda: \"Dia adalah orang paling baik di Bani 'Amir\". (Dzil Jausyan Radliyallahu'anhu) berkata; demi Allah, ketika saya bersama dengan keluarga pada suatu tempat yang rendah, datanglah orang yang berkendaraan. Saya bertanya, dari mana? Dia menjawab, dari Makkah. Saya (Dzil Jausyan Radliyallahu'anhu) berkata; apa yang terjadi di sana? Dia menjawab, Muhammad Shallallahu'alaihiwasallam telah mengalahkannya. (Dzil Jausyan Radliyallahu'anhu) berkata; 'ibuku telah kehilanganku' demi Allah, seandainya saya masuk Islam saat itu, lalu saya meminta Al Hirah (nama tempat) agar saya dapat memotongnya. Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Al Hakam bin Musa] berkata; telah menceritakan kepada kami ['Isa bin Yunus] dari [Bapaknya] dari [kakeknya] dari [Dzil Jausyan] dari Nabi Shallallahu'alaihiwasallam semisalnya. (Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Muhammad bin 'Abbad] berkata; telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari [Dzil Jausyan, Abu Syimr Al Dlababi] seperti ini."},"776":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا أَبَانُ الْعَطَّارُ حَدَّثَنَا قَتَادَةُ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَبِي عُبَيْدٍ أَنَّهُطَبَخَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِدْرًا فِيهِ لَحْمٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَاوِلْنِي ذِرَاعَهَا فَنَاوَلْتُهُ فَقَالَ نَاوِلْنِي ذِرَاعَهَا فَنَاوَلْتُهُ فَقَالَ نَاوِلْنِي ذِرَاعَهَا فَقَالَ يَا نَبِيَّ اللَّهِ كَمْ لِلشَّاةِ مِنْ ذِرَاعٍ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ لَوْ سَكَتَّ لَأَعْطَتْكَ ذِرَاعًا مَا دَعَوْتَ بِهِ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Aban Al 'Athar] telah menceritakan kepada kami [Qatadah] dari [Syahr bin Hausab] dari [Abu 'Ubaid], dia memasak untuk Rasulullah Shallallahu'alahiwasallam dalam suatu periuk yang berisi daging, lalu Rasulullah Shallallahu'alahiwasallam bersabda: \"Berikan lengannya untukku\", maka saya serahkan untuknya, lalu beliau bersabda: \"Ambillkan untukku lengannya\", maka saya ambilkan untuknya, bersabda: \"Berikan untukku lengannya\", maka saya serahkan untuknya, (Abu 'Ubaid Radliyallahu'anhu) berkata; \"Wahai Nabiyullah, berapa lengan yang ada pada kambing\"? beliau bersabda: \"Demi Dzat yang jiwaku berada di tangan-Nya, jikalah kamu diam, niscaya kamu akan diberi lengan kambing sebanyak yang kamu inginkan\"."},"777":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عِكْرِمَةَ بْنِ عَمَّارٍ قَالَ حَدَّثَنِي الْهِرْمَاسُ بْنُ زِيَادٍ الْبَاهِلِيُّ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ عَلَى رَاحِلَتِهِ يَوْمَ النَّحْرِ بِمِنًي","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Ikrimah bin 'Ammar] berkata; telah menceritakan kepadaku [Al Hirmas bin Ziyad Al Bahily] berkata; Aku melihat Rasulullah Shallallahu'alaihiwasallam berpidato di atas untanya pada hari nahar ketika di Mina. "},"778":{"ar":"حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ وَهُوَ الْعِجْلِيُّ حَدَّثَنَا الْهِرْمَاسُ بْنُ زِيَادٍ الْبَاهِلِيُّ قَالَكُنْتُ رِدْفَ أَبِي يَوْمَ الْأَضْحَى وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ عَلَى نَاقَتِهِ بِمِنًى","id":"Telah menceritakan kepada kami [Hasyim bin Al Qasim] telah menceritakan kepada kami ['Ikrimah bin 'Ammar] yaitu Al 'Ijli, telah menceritakan kepada kami [Al Hirmas bin Ziyad Al Bahily] berkata; saya membonceng bapakku pada Idul Adha dan Rasulullah Shallallahu'alaihiwasallam berkhutbah di atas untanya di Mina."},"779":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَاقِدٍ قَالَ أَخْبَرَنِي عِكْرِمَةُ بْنُ عَمَّارٍ عَنِ الْهِرْمَاسِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي عَلَى بَعِيرٍ نَحْوَ الشَّامِ","id":"Telah menceritakan kepada kami [Abdullah bin Waqid] berkata; telah mengabarkan kepadaku ['Ikrimah bin 'Ammar] dari [Al Hirmas] berkata; saya melihat Rasulullah Shallallahu'alaihiwasallam shalat di atas unta menghadap Syam."},"780":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عِمْرَانَ بْنِ أَبِي عَلِيٍّ أَبُو مُحَمَّدٍ مِنْ أَهْلِ الرَّيِّ وَكَانَ أَصْلُهُ أَصْبَهَانِيًّا قَالَ حَدَّثَنَا يَحْيَى بْنُ الضُّرَيْسِ قَالَ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ عَنْ هِرْمَاسٍ قَالَكُنْتُ رِدْفَ أَبِي فَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى بَعِيرٍ وَهُوَ يَقُولُ لَبَّيْكَ بِحَجَّةٍ وَعُمْرَةٍ مَعًا","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Abdullah bin 'Imran bin Abu 'Ali, Abu Muhammad] dari Ray, yang aslinya adalah dari Asbahan, berkata; telah menceritakan kepada kami [Yahya bin Adl-Dlurais] berkata; telah menceritakan kepada kami ['Ikrimah bin 'Ammar] dari [Hirmas] berkata; saya membonceng bapakku, lalu saya melihat Rasulullah Shallallahu'alaihiwasallam di atas unta dengan membaca 'Kami berniat haji dan umrah bersama-sama.'"},"781":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا يَحْيَى بْنُ زُرَارَةَ السَّهْمِيُّ قَالَ حَدَّثَنِي أَبِي عَنْ جَدِّي الْحَارِثِ بْنِ عَمْرٍوأَنَّهُ لَقِيَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ فَقُلْتُ بِأَبِي أَنْتَ يَا رَسُولَ اللَّهِ اسْتَغْفِرْ لِي قَالَ غَفَرَ اللَّهُ لَكُمْ قَالَ وَهُوَ عَلَى نَاقَتِهِ الْعَضْبَاءِ قَالَ فَاسْتَدَرْتُ لَهُ مِنْ الشِّقِّ الْآخَرِ أَرْجُو أَنْ يَخُصَّنِي دُونَ الْقَوْمِ فَقُلْتُ اسْتَغْفِرْ لِي قَالَ غَفَرَ اللَّهُ لَكُمْ قَالَ رَجُلٌ يَا رَسُولَ اللَّهِ الْفَرَائِعُ وَالْعَتَائ��رُ قَالَ مَنْ شَاءَ فَرَّعَ وَمَنْ شَاءَ لَمْ يُفَرِّعْ وَمَنْ شَاءَ عَتَرَ وَمَنْ شَاءَ لَمْ يَعْتِرْ فِي الْغَنَمِ أُضْحِيَّةٌ ثُمَّ قَالَ أَلَا إِنَّ دِمَاءَكُمْ وَأَمْوَالَكُمْ عَلَيْكُمْ حَرَامٌ كَحُرْمَةِ يَوْمِكُمْ هَذَا فِي بَلَدِكُمْ هَذَا وَقَالَ عَفَّانُ مَرَّةً حَدَّثَنِي يَحْيَى بْنُ زُرَارَةَ السَّهْمِيُّ قَالَ حَدَّثَنِي أَبِي عَنْ جَدِّهِ الْحَارِثِ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Yahya bin Zurarah As-Sahmi] berkata; telah menceritakan kepadaku [bapakku] dari [kakekku, Al Harits bin 'Amr], dia bertemu Rasulullah Shallallahu'alaihiwasallam pada waktu Haji Wada', maka aku berkata; Demi ayahku dan ibuku, wahai Rasulullah, mintakanlah ampun untukku. (Rasulullah Shallallahu'alaihiwasallam) bersabda di atas untanya yang bernama Al'Adlba', \"Semoga Allah mengampuni kalian\". Lalu saya berputar ke sisi yang lain berharap untuk mendapatkan perhatian beliau, dan saya berkata 'Tolong mintakan ampun untukku, wahai Rasulullah.' (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Semoga Allah mengampuni kalian\". Ada seseorang yang berkata 'Wahai Rasulullah, Al fara'i' dan al'Ata'ir apa boleh dilakukan?. Beliau bersabda: \"Barangsiapa yang berkenan lakukanlah, dan barangsiapa yang berkenan jangan lakukan. Barangsiapa yang mau menyembelih lakukanlah, siapa yang tidak mau maka tinggalkanlah kambing, sebagai hewan kurban\". Lalu beliau bersabda: \"Ketahuilah bahwa darah dan harta kalian adalah haram sebagaimana keharaman hari ini di negeri kalian ini'. Dan 'Affan berkata suatu kali, telah menceritakan kepadaku Yahya bin Zurarah As-Sahmi berkata; telah menceritakan kepadaku bapakku dari kakekku, Al Harits. "},"782":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ قَالَ أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْحَاقَ قَالَ حَدَّثَنِي سَعِيدُ بْنُ عُبَيْدِ بْنِ السَّبَّاقِ عَنْ أَبِيهِ عَنْ سَهْلِ بْنِ حُنَيْفٍ قَالَكُنْتُ أَلْقَى مِنْ الْمَذْيِ شِدَّةً فَكُنْتُ أُكْثِرُ الِاغْتِسَالَ مِنْهُ فَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَقَالَ إِنَّمَا يُجْزِئُكَ مِنْهُ الْوُضُوءُ فَقُلْتُ كَيْفَ بِمَا يُصِيبُ ثَوْبِي فَقَالَ يَكْفِيكَ أَنْ تَأْخُذَ كَفًّا مِنْ مَاءٍ فَتَمْسَحَ بِهَا مِنْ ثَوْبِكَ حَيْثُ تَرَى أَنَّهُ أَصَابَ","id":"Telah menceritakan kepada kami [Isma'il bin Ibrohim] berkata; telah mengabarkan kepada kami [Muhammad bin Ishaq] berkata; telah menceritakan kepadaku [Sa'id bin 'Ubaid Bin As-Sabaq] dari [Bapaknya] dari [Sahal bin Hunaif] berkata; Saya mengeluarkan madzi karena tingginya hasratku, hingga menyebabkan banyak mandi. Saya bertanya Rasulullah Shallallahu'alaihiwasallam tentang hal itu. Beliau bersabda: \"Cukup bagimu berwudlu\". Saya bertanya, Bagaimana dengan pakaianku yang terkena itu? beliau bersabda: \"Cukuplah engkau ambil segenggam air lalu engkau usap pakaianmu di bagian yang kau lihat terkena\""},"783":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي وَائِلٍ قَالَ قَالَ سَهْلُ بْنُ حُنَيْفٍاتَّهِمُوا رَأْيَكُمْ فَلَقَدْ رَأَيْتُنَا يَوْمَ أَبِي جَنْدَلٍ وَلَوْ نَسْتَطِيعُ أَنْ نَرُدَّ أَمْرَهُ لَرَدَدْنَاهُ وَاللَّهِ مَا وَضَعْنَا سُيُوفَنَا عَنْ عَوَاتِقِنَا مُنْذُ أَسْلَمْنَا لِأَمْرٍ يُفْظِعُنَا إِلَّا أَسْهَلَ بِنَا إِلَى أَمْرٍ نَعْرِفُهُ إِلَّا هَذَا الْأَمْرَ مَا سَدَدْنَا خَصْمًا إِلَّا انْفَتَحَ لَنَا خَصْمٌ آخَرُ","id":"Telah menceritakan kepada kami [Sufyan bin 'Uyainah] berkata; telah menceritakan kepada kami [Al 'Amasy] dari [Abu Wa'il] berkata; [Sahal bin Hunaif] berkata; perhitungkanlah pendapat kalian, kami mengalami hari-hari siksaan Abu Jandal, sekiranya kami dapat mengembalikan urusannya niscaya kami akan mengembalikannya. Demi Allah, tidaklah kami meletakkan pedang dari pundak kami sejak kami masuk Islam karena suatu urusan yang sangat mengerikan, kecuali memudahkan kami kepada urusan yang kami ketahui, kecuali urusan ini (maksudnya saat-saat tumbuhnya sekte khawarij). Kami tidak menutup permusuhan kecuali terbuka lagi bagi kami permusuhan yang lain."},"784":{"ar":"حَدَّثَنَا يَعْلَى بْنُ عُبَيْدٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ سِيَاهٍ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ قَالَأَتَيْتُ أَبَا وَائِلٍ فِي مَسْجِدِ أَهْلِهِ أَسْأَلُهُ عَنْ هَؤُلَاءِ الْقَوْمِ الَّذِينَ قَتَلَهُمْ عَلِيٌّ بِالنَّهْرَوَانِ فَفِيمَا اسْتَجَابُوا لَهُ وَفِيمَا فَارَقُوهُ وَفِيمَا اسْتَحَلَّ قِتَالَهُمْ قَالَ كُنَّا بِصِفِّينَ فَلَمَّا اسْتَحَرَّ الْقَتْلُ بِأَهْلِ الشَّامِ اعْتَصَمُوا بِتَلٍّ فَقَالَ عَمْرُو بْنُ الْعَاصِ لِمُعَاوِيَةَ أَرْسِلْ إِلَى عَلِيٍّ بِمُصْحَفٍ وَادْعُهُ إِلَى كِتَابِ اللَّهِ فَإِنَّهُ لَنْ يَأْبَى عَلَيْكَ فَجَاءَ بِهِ رَجُلٌ فَقَالَ بَيْنَنَا وَبَيْنَكُمْ كِتَابُ اللَّهِ{ أَلَمْ تَرَ إِلَى الَّذِينَ أُوتُوا نَصِيبًا مِنْ الْكِتَابِ يُدْعَوْنَ إِلَى كِتَابِ اللَّهِ لِيَحْكُمَ بَيْنَهُمْ ثُمَّ يَتَوَلَّى فَرِيقٌ مِنْهُمْ وَهُمْ مُعْرِضُونَ }فَقَالَ عَلِيٌّ نَعَمْ أَنَا أَوْلَى بِذَلِكَ بَيْنَنَا وَبَيْنَكُمْ كِتَابُ اللَّهِ قَالَ فَجَاءَتْهُ الْخَوَارِجُ وَنَحْنُ نَدْعُوهُمْ يَوْمَئِذٍ الْقُرَّاءَ وَسُيُوفُهُمْ عَلَى عَوَاتِقِهِمْ فَقَالُوا يَا أَمِيرَ الْمُؤْمِنِينَ مَا نَنْتَظِرُ بِهَؤُلَاءِ الْقَوْمِ الَّذِينَ عَلَى التَّلِّ أَلَا نَمْشِي إِلَيْهِمْ بِسُيُوفِنَا حَتَّى يَحْكُمَ اللَّهُ بَيْنَنَا وَبَيْنَهُمْ فَتَكَلَّمَ سَهْلُ بْنُ حُنَيْفٍ فَقَالَ يَا أَيُّهَا النَّاسُ اتَّهِمُوا أَنْفُسَكُمْ فَلَقَدْ رَأَيْتُنَا يَوْمَ الْحُدَيْبِيَةِ يَعْنِي الصُّلْحَ الَّذِي كَانَ بَيْنَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبَيْنَ الْمُشْرِكِينَ وَلَوْ نَرَى قِتَالًا لَقَاتَلْنَا فَجَاءَ عُمَرُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَلَسْنَا عَلَى الْحَقِّ وَهُمْ عَلَى بَاطِلٍ أَلَيْسَ قَتْلَانَا فِي الْجَنَّةِ وَقَتْلَاهُمْ فِي النَّارِ قَالَ بَلَى قَالَ فَفِيمَ نُعْطِي الدَّنِيَّةَ فِي دِينِنَا وَنَرْجِعُ وَلَمَّا يَحْكُمِ اللَّهُ بَيْنَنَا وَبَيْنَهُمْ فَقَالَ يَا ابْنَ الْخَطَّابِ إِنِّي رَسُولُ اللَّهِ وَلَنْ يُضَيِّعَنِي أَبَدًا قَالَ فَرَجَعَ وَهُوَ مُتَغَيِّظٌ فَلَمْ يَصْبِرْ حَتَّى أَتَى أَبَا بَكْرٍ فَقَالَ يَا أَبَا بَكْرٍ أَلَسْنَا عَلَى حَقٍّ وَهُمْ عَلَى بَاطِلٍ أَلَيْسَ قَتْلَانَا فِي الْجَنَّةِ وَقَتْلَاهُمْ فِي النَّارِ قَالَ بَلَى قَالَ فَفِيمَ نُعْطِي الدَّنِيَّةَ فِي دِينِنَا وَنَرْجِعُ وَلَمَّا يَحْكُمِ اللَّهُ بَيْنَنَا وَبَيْنَهُمْ فَقَالَ يَا ابْنَ الْخَطَّابِ إِنَّهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَنْ يُضَيِّعَهُ اللَّهُ أَبَدًا قَالَ فَنَزَلَتْ سُورَةُ الْفَتْحِ قَالَ فَأَرْسَلَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى عُمَرَ فَأَقْرَأَهَا إِيَّاهُ قَالَ يَا رَسُولَ اللَّهِ وَفَتْحٌ هُوَ قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Ya'la bin 'Ubaid] dari [Abdul Aziz bin Siyah] dari [Habib bin Abu Tsabit] berkata; saya mendatangi [Abu Wa'il] di masjid keluarganya, saya bertanya kepadanya tentang kaum yang diperangi 'Ali di Nahrawan, hal-hal apa saja yang mereka terima, hal-hal apa saja yang mereka tak cocok, dan hal-hal apa saja sehingga 'Ali menganggap halal mereka diperangi. (Abu Wa'il radliyallahu'anhu) berkata; kami saat itu sedang di Shiffin, tatkala berkecamuk perang dengan penduduk Syam, mereka berpegang teguh untuk tetap di tempat yang tinggi. Lalu 'Amr bin Al 'Ash berkata kepada Mu'awiyah 'Utuslah seseorang kepada 'Ali dengan mushaf dan ajaklah dia kepada kitab Allah, dia tidak bakalan menolaknya.' Sang utusan pun datang menemui 'Ali dan berujar 'Antara kita dan kalian ada kitab Allah, 'Tidakkah kamu memperhatikan orang-orang yang telah diberi bahagian yaitu Al Kitab (Taurat), mereka diseru kepada Kitab Allah supaya Kitab itu menetapkan hukum diantara mereka; Kemudian sebahagian dari mereka berpaling, dan mereka selalu membelakangi (kebenaran) ' 'Ali berkata; ya saya lebih layak untuk melakukan hal itu, antara kami dan kalian ada kitab Allah. Lalu datanglah Al Khawarij, pada saat itu kami memanggil mereka dengan istilah Al Qurra', pedang mereka diletakkan pada pundak-pundak mereka. Mereka berkata; Wahai Amirul Mukminin, kenapa kita menunggu mereka, kaum yang berada di atas dataran tinggi itu, tidak sebaiknyakah kita berjalan kepada mereka dengan membawa pedang kita, sampai Allah memutuskan antara kita dengan mereka?. Lalu [Sahl bin Hunaif] berkata; Wahai manusia, koreksilah diri kalian sendiri, kami telah mengadakan perdamaian pada saat Hudaibiyah antara Rasulullah Shallallahu'alaihiwasallam dan kaum musrikin. Jika kami hendak berperang niscaya itu akan terjadi. Lalu datanglah 'Umar kepada Rasulullah Shallallahu'alaihiwasallam, berkata; \"Wahai Rasulullah, bukankah kita berada di atas kebenaran dan mereka berada di atas kebatilan, bukankah jika ada yang terbunuh diantara kita berada di surga dan jika ada yang terbunuh dari mereka akan berada di neraka?.\" Beliau menjawab, ya. ('Umar radliyallahu'anhu) berkata; kenapa kita memberi kehinaan kepada agama kita ini dan kita kembali, bukankah Allah telah memutuskan antara kita dan mereka?. beliau bersabda: \"Wahai Ibnu Khattab, saya adalah Rasulullah Shallallahu'alaihiwasallam dan (Allah Azzawajalla) tidak akan menelantarkanku selamanya.\" (Abu Wa'il radliyallahu'anhu) berkata; lalu Umar pulang dalam keadaan marah dan tidak sabar sehingga mendatangi Abu Bakar, seraya bertanya-tanya, Wahai Abu Bakar, bukankah kita berada di atas kebenaran dan mereka di atas kebatilan, bukankah korban dari kita berada di syurga dan korban dari mereka di neraka?.\" (Abu Bakar) menjawab, ya. ('Umar radliyallahu'anhu) berkata; kenapa kita memberi kekurangan pada agama kita ini dan kita kembali, bukankah Allah telah memutuskan antara kita dan mereka?. Abu Bakar terus mengatakan, \"Wahai Ibnu Al Khattab, dia adalah Rasulullah Shallallahu'alaihiwasallam dan Allah Azzawajalla tidak bakalan menelantarkannya selama-lamanya.\" (Abu Wa'il radliyallahu'anhu) berkata; lalu turunlah Surat Al Fath. Lantas Rasulullah Shallallahu'alaihiwasallam mengutusku kepada 'Umar, dan saya membacakan kepadanya. Dia berkata; Wahai Rasulullah, apakah itu berarti kemenangan?. Beliau menjawab, Ya."},"785":{"ar":"حَدَّثَنَا أَبُو النَّضْرِ قَالَ حَدَّثَنَا حِزَامُ بْنُ إِسْمَاعِيلَ الْعَامِرِيُّ عَنْ أَبِي إِسْحَاقَ الشَّيْبَانِيِّ عَنْ يُسَيْرِ بْنِ عَمْرٍو قَالَدَخَلْتُ عَلَى سَهْلِ بْنِ حُنَيْفٍ فَقُلْتُ حَدِّثْنِي مَا سَمِعْتَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي الْحَرُورِيَّةِ قَالَ أُحَدِّثُكَ مَا سَمِعْتُ لَا أَزِيدُكَ عَلَيْهِ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَذْكُرُ قَوْمًا يَخْرُجُونَ مِنْ هَاهُنَا وَأَشَارَ بِيَدِهِ نَحْوَ الْعِرَاقِ ي��قْرَءُونَ الْقُرْآنَ لَا يُجَاوِزُ حَنَاجِرَهُمْ يَمْرُقُونَ مِنْ الدِّينِ كَمَا يَمْرُقُ السَّهْمُ مِنْ الرَّمِيَّةِقُلْتُ هَلْ ذَكَرَ لَهُمْ عَلَامَةً قَالَ هَذَا مَا سَمِعْتُ لَا أَزِيدُكَ عَلَيْهِ","id":"Telah menceritakan kepada kami [Abu Nadlr] berkata; telah menceritakan kepada kami [Hizam bin Isma'il Al 'Amiri] dari [Abu Ishaq As-Syaibani] dari [Yusair bin 'Amr] berkata; saya menemui [Sahal bin Hunaif], lalu saya berkata; ceritakan kepadaku apa yang kau dengar dari Rasulullah Shallallahu'alaihiwasallam tentang Al Haruriyyah?. Dia berkata; akan saya sampaikan kepadamu apa yang saya dengar, saya tidak menambah-nambahi. Saya mendengar Rasulullah Shallallahu'alaihiwasallam menyebutkan suatu kaum, yang akan keluar dari tempat itu, dia menunjukkan dengan tangannya ke arah Iraq, mereka membaca alqur'an namun tidak sampai tenggorokan mereka, mereka meninggalkan agama sebagaimana anak panah meninggalkan busurnya. Saya berkata; apa beliau menyebutkan kepada mereka tanda-tandanya?. Dia menjawab, ini yang saya dengar, saya tidak menambahi sedikitpun. "},"786":{"ar":"قَالَ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ وَعَفَّانُ قَالَا حَدَّثَنَا عَبْدُ الْوَاحِدِ يَعْنِي ابْنَ زِيَادٍ قَالَ حَدَّثَنَا عُثْمَانُ بْنُ حَكِيمٍ قَالَ حَدَّثَتْنِي جَدَّتِي الرَّبَابُ وَقَالَ يُونُسُ فِي حَدِيثِهِ قَالَتْ سَمِعْتُ سَهْلَ بْنَ حُنَيْفٍ يَقُولُمَرَرْنَا بِسَيْلٍ فَدَخَلْتُ فَاغْتَسَلْتُ مِنْهُ فَخَرَجْتُ مَحْمُومًا فَنُمِيَ ذَلِكَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مُرُوا أَبَا ثَابِتٍ يَتَعَوَّذُ قُلْتُ يَا سَيِّدِي وَالرُّقَى صَالِحَةٌ قَالَ لَا رُقْيَةَ إِلَّا فِي نَفْسٍ أَوْ حُمَةٍ أَوْ لَدْغَةٍ قَالَ عَفَّانُ النَّظْرَةُ وَاللَّدْغَةُ وَالْحُمَةُ","id":"Telah menceritakan kepada kami [Yunus bin Muhammad] dan ['Affan] berkata; telah menceritakan kepada kami [Abdul Wahid] yaitu Ibnu Ziyad, berkata; telah menceritakan kepada kami ['Utsman bin Hakim] berkata; telah menceritakan kepadaku [nenekku, Ar-Rabab] dan [Yunus] berkata; dalam hadisnya, (Ar-Rabab Radliyallahu'anha) berkata; saya mendengar [Sahal bin Hunaif] berkata; \"Kami melewati aliran air, lalu saya menceburkan diri, mandi. Ketika saya keluar dari air, aku merasakan demam. Kejadian tersebut dilaporkan kepada Rasulullah Shallallahu'alaihiwasallam. Beliau bersabda: \"Suruhlah Abu Tsabit untuk berlindung diri dengan doa\", Lalu saya berkata; \"Wahai baginda, apakah dengan membaca doa (ruqyah) boleh? Beliau bersabda: \"Tidak ada Ruqyah, kecuali karena pandangan mata jahat, badan yang terkena racun ataupun sengatan\". 'Affan mengatakan; karena pandangan mata jahat, sengatan, atau racun."},"787":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا أَبُو أُوَيْسٍ حَدَّثَنَا الزُّهْرِيُّ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلِ بْنِ حُنَيْفٍ أَنَّ أَبَاهُ حَدَّثَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ وَسَارُوا مَعَهُ نَحْوَ مَكَّةَ حَتَّى إِذَا كَانُوا بِشِعْبِ الْخَزَّارِ مِنْ الْجُحْفَةِ اغْتَسَلَ سَهْلُ بْنُ حُنَيْفٍ وَكَانَ رَجُلًا أَبْيَضَ حَسَنَ الْجِسْمِ وَالْجِلْدِ فَنَظَرَ إِلَيْهِ عَامِرُ بْنُ رَبِيعَةَ أَخُو بَنِي عَدِيِّ بْنِ كَعْبٍ وَهُوَ يَغْتَسِلُ فَقَالَ مَا رَأَيْتُ كَالْيَوْمِ وَلَا جِلْدَ مُخَبَّأَةٍ فَلُبِطَ سَهْلٌ فَأُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقِيلَ لَهُ يَا رَسُولَ اللَّهِ هَلْ لَكَ فِي سَهْلٍ وَاللَّهِ مَا يَرْفَعُ رَأْسَهُ وَمَا يُفِيقُ قَالَ هَلْ تَتَّهِمُونَ فِيهِ مِنْ أَحَدٍ قَالُوا نَظَرَ إِلَيْهِ عَامِرُ بْنُ رَبِيعَةَ فَدَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامِرًا فَتَغَيَّظَ عَلَيْهِ وَقَالَ عَلَامَ يَقْتُلُ أَحَدُكُمْ أَخَاهُ هَلَّا إِذَا رَأَيْتَ مَا يُعْجِبُكَ بَرَّكْتَ ثُمَّ قَالَ لَهُ اغْتَسِلْ لَهُ فَغَسَلَ وَجْهَهُ وَيَدَيْهِ وَمِرْفَقَيْهِ وَرُكْبَتَيْهِ وَأَطْرَافَ رِجْلَيْهِ وَدَاخِلَةَ إِزَارِهِ فِي قَدَحٍ ثُمَّ صُبَّ ذَلِكَ الْمَاءُ عَلَيْهِ يَصُبُّهُ رَجُلٌ عَلَى رَأْسِهِ وَظَهْرِهِ مِنْ خَلْفِهِ يُكْفِئُ الْقَدَحَ وَرَاءَهُ فَفَعَلَ بِهِ ذَلِكَ فَرَاحَ سَهْلٌ مَعَ النَّاسِ لَيْسَ بِهِ بَأْسٌ","id":"Telah menceritakan kepada kami [Husain bin Muhammad] berkata; telah menceritakan kepada kami [Abu Uwais] telah menceritakan kepada kami [Az Zuhri] dari [Abu Umamah bin Sahal bin Hunaif], [bapaknya] menceritakan kepadanya, Rasulullah Shallallahu'alaihiwasallam keluar melakukan perjalanan bersama para sahabat menuju Makkah. Ketika mereka sampai pada suatu daerah pegunungan di daerah Juhfah, Sahal bin Hunaif mandi, dia adalah seorang yang berperawakan putih wajah dan kulitnya. Lalu 'Amir bin Rabi'ah-saudara bani Ady bin Kaab- melihatnya, dia juga dalam sedang mandi. 'Amir bin Rabi'ah berkata; \"Belum pernah aku melihat seperti hari ini, dan juga tidak kulit yang begitu putih\". Seketika itu juga, terjatuhlah Sahal, Sahal kontan digotong kepada Rasulullah Shallallahu'alaihiwasallam dan dikatakan kepada beliau, \"Wahai Rasulullah, apakah engkau mengetahui apa yang terjadi dengan Sahal?\", demi Allah, Sahal tidak dapat mengangkat kepalanya dan tidak sadar. (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Mungkin kalian bisa menebak seseorang dalam kasus ini\". Mereka berkata; 'Amir bin Rabi'ah tertegun melihat Sahal. Rasulullah Shallallahu'alaihiwasallam kontan memanggil 'Amir dengan agak marah, lalu bersabda: \"Atas dasar apa di antara kalian membunuh saudaranya, jika di antara kalian melihat sesuatu yang membuat terkagum, mintalah Allah agar memberkahinya\". Lalu bersabda: \"Mandikanlah\", lalu 'Amir bin Rabi'ah membasuh wajahnya, kedua tangannya, kedua sikutnya, pergelangan kaki dan ujung kakinya serta menyiram apa yang ada pada sarungnya dengan gayung, lalu memercikinya dengan air itu. Ada seorang laki-laki memercikan air ke kepala dan punggungnya dari belakang, sehingga habislah air dalam bejana, setelah itu Sahal istirahat bersama yang lain dan tidak terjadi apa-apa dengannya."},"788":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ عِيسَى حَدَّثَنِي مُجَمِّعُ بْنُ يَعْقُوبَ الْأَنْصَارِيُّ بِقُبَاءٍ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ الْكَرْمَانِيِّ قَالَ سَمِعْتُ أَبَا أُمَامَةَ بْنَ سَهْلِ بْنِ حُنَيْفٍ يَقُولُ قَالَ أَبِيقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ خَرَجَ حَتَّى يَأْتِيَ هَذَا الْمَسْجِدَ يَعْنِي مَسْجِدَ قُبَاءٍ فَيُصَلِّيَ فِيهِ كَانَ كَعَدْلِ عُمْرَةٍحَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا مُجَمِّعُ بْنُ يَعْقُوبَ الْأَنْصَارِيُّ عَنْ مُحَمَّدِ بْنِ سُلَيْمَانَ الْكَرْمَانِيِّ قَالَ سَمِعْتُ أَبَا أُمَامَةَ بْنَ سَهْلِ بْنِ حُنَيْفٍ فَذَكَرَ مِثْلَهُ قَالَ حَدَّثَنَا عَلِيُّ بْنُ بَحْرٍ قَالَ حَدَّثَنَا حَاتِمٌ حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ الْكَرْمَانِيُّ فَذَكَرَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Ishaq bin 'Isa] telah menceritakan kepadaku [Mujami' bin Ya'qub Al Anshari] di Quba', berkata; telah menceritakan kepadaku [Muhammad bin Al Karmany] berkata; saya mendengar [Abu Umamah bin Sahal bin Hunaif] berkata; [bapakku] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa keluar dan datang ke masjid ini (yaitu masjid Quba') lalu shalat di dalamnya, maka menyamai pahala umrah\". Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata; telah menceritakan kepada kami [Mujammi' bin Ya'qub Al Anshory] dari [Muhammad bin Sulaiman Al Karmany] berkata; saya mendengar [Abu Umamah bin Sahal bin Hunaif], lalu menyebutkan sebagaimana dalam hadis. (Ahmad bin Hanbal) berkata; telah menceritakan kepada kami ['Ali bin Bahr] berkata; telah menceritakan kepada kami [Hatim] telah menceritakan kepada kami [Muhammad bin Sulaiman Al Karmany] lalu menyebutkan secara makna."},"789":{"ar":"قَالَ حَدَّثَنَا رَوْحٌ وَعَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ حَدَّثَنِي عَبْدُ الْكَرِيمِ بْنُ أَبِي الْمُخَارِقِ أَنَّ الْوَلِيدَ بْنَ مَالِكِ بْنِ عَبْدِ الْقَيْسِ أَخْبَرَهُ وَقَالَ عَبْدُ الرَّزَّاقِ مِنْ عَبْدِ الْقَيْسِ أَنَّ مُحَمَّدَ بْنَ قَيْسٍ أَخْبَرَهُ أَنَّ سَهْلًا أَخْبَرَهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَهُ قَالَ أَنْتَ رَسُولِي إِلَى أَهْلِ مَكَّةَ قُلْ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْسَلَنِي يَقْرَأُ عَلَيْكُمْ السَّلَامَ وَيَأْمُرُكُمْ بِثَلَاثٍ لَا تَحْلِفُوا بِغَيْرِ اللَّهِ وَإِذَا تَخَلَّيْتُمْ فَلَا تَسْتَقْبِلُوا الْقِبْلَةَ وَلَا تَسْتَدْبِرُوهَا وَلَا تَسْتَنْجُوا بِعَظْمٍ وَلَا بِبَعْرَةٍ","id":"Telah menceritakan kepada kami [Rouh] dan [Abdurrozaq] berkata; telah mengabarkan kepada kami [Muhammad bin Qais] telah mengabarkan kepada kami [Ibnu Juraij] berkata; telah menceritakan kepadaku [Abdul Karim bin Abu Al Muhariq] [Al Walid bin Malik bin Abdul Qais] mengabarinya. Dan [Abdurrazzaq] berkata; dari Abdul Qais [Muhammad bin Qais] mengabarinya [Sahal] mengabarinya, Nabi Shallallahu'alaihiwasallam mengutusnya dan bersabda: \"Engkau adalah utusanku kepada penduduk Makkah, katakan, Rasulullah Shallallahu'alaihiwasallam telah mengutusku untuk menyampaikan salam dan menyuruh kalian tiga hal yaitu: Janganlah kalian bersumpah dengan selain Allah. Jika kalian menunaikan hajatnya, janganlah menghadap atau membelakangi kiblat. Janganlah bercebok menggunakan tulang ataupun bekas kotoran unta\"."},"790":{"ar":"قَالَ حَدَّثَنَا زَكَرِيَّا بْنُ عَدِيٍّ قَالَ أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ عَمْرٍو عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ عَبْدِ اللَّهِ بْنِ سَهْلِ بْنِ حُنَيْفٍ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَعَانَ مُجَاهِدًا فِي سَبِيلِ اللَّهِ أَوْ غَارِمًا فِي عُسْرَتِهِ أَوْ مُكَاتَبًا فِي رَقَبَتِهِ أَظَلَّهُ اللَّهُ فِي ظِلِّهِ يَوْمَ لَا ظِلَّ إِلَّا ظِلُّهُ","id":"Telah menceritakan kepada kami [Zakariya bin 'Adi] berkata; telah mengabarkan kepada kami ['Ubaidullah bin 'Amr] dari [Abdullah bin Muhammad bin 'Aqil] dari [Abdullah bin Suhail bin Hunaif] dari [bapaknya] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa menolong seorang mujahid di jalan Allah atau orang yang terlilit hutang dalam kesulitan yang dia hadapi atau budak (yang telah dijanjikan merdeka oleh tuannya) dalam tanggungannya, Allah menaunginya dalam naungAn Nya pada hari ketika tidak ada naungan selain naungAn Nya\""},"791":{"ar":"قَالَ حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ قَالَ حَدَّثَنَا زُهَيْرُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ عَبْدِ اللَّهِ بْنِ سَهْلِ بْنِ حُنَيْفٍ أَنَّ سَهْلًا حَدَّثَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَعَانَ مُجَاهِدًا فِي سَبِيلِ اللَّهِ أَوْ غَارِمًا فِي عُسْرَتِهِ أَوْ مُكَاتَبًا فِي رَقَبَتِهِ أَظَلَّهُ اللَّهُ فِي ظِلِّهِ يَوْمَ لَا ظِلَّ إِلَّا ظِلُّهُ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] berkata; telah menceritakan kepada kami [Zuhair bin Muhammad] berkata; telah menceritakan kepada kami [Abdullah bin Muhammad bin 'Aqil] dari [Abdullah bin Sahl bin Hunaif] bahwa [Sahl] menceritakannya, Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa menolong seorang mujahid di jalan Allah atau orang yang terlilit hutang dalam kesulitan yang dia hadapi atau budak (yang dijanjikan merdeka oleh tuannya) dalam tanggungannya, Allah menaunginya dalam naungAn Nya pada hari ketika tidak ada naungan selain naungAn Nya\""},"792":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ قَالَ حَدَّثَنِي أَبِي حَدَّثَنَا دَاوُدُ يَعْنِي ابْنَ أَبِي هِنْدٍ عَنْ أَبِي حَرْبٍ أَنَّ طَلْحَةَ حَدَّثَهُ وَكَانَ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَأَتَيْتُ الْمَدِينَةَ وَلَيْسَ لِي بِهَا مَعْرِفَةٌ فَنَزَلْتُ فِي الصُّفَّةِ مَعَ رَجُلٍ فَكَانَ بَيْنِي وَبَيْنَهُ كُلَّ يَوْمٍ مُدٌّ مِنْ تَمْرٍ فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ يَوْمٍ فَلَمَّا انْصَرَفَ قَالَ رَجُلٌ مِنْ أَصْحَابِ الصُّفَّةِ يَا رَسُولَ اللَّهِ أَحْرَقَ بُطُونَنَا التَّمْرُ وَتَخَرَّقَتْ عَنَّا الْخُنُفُ فَصَعِدَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَطَبَ ثُمَّ قَالَ وَاللَّهِ لَوْ وَجَدْتُ خُبْزًا أَوْ لَحْمًا لَأَطْعَمْتُكُمُوهُ ��َمَا إِنَّكُمْ تُوشِكُونَ أَنْ تُدْرِكُوا وَمَنْ أَدْرَكَ ذَلِكَ مِنْكُمْ أَنْ يُرَاحَ عَلَيْكُمْ بِالْجِفَانِ وَتَلْبَسُونَ مِثْلَ أَسْتَارِ الْكَعْبَةِ قَالَ فَمَكَثْتُ أَنَا وَصَاحِبِي ثَمَانِيَةَ عَشَرَ يَوْمًا وَلَيْلَةً مَا لَنَا طَعَامٌ إِلَّا الْبَرِيرَ حَتَّى جِئْنَا إِلَى إِخْوَانِنَا مِنْ الْأَنْصَارِ فَوَاسَوْنَا وَكَانَ خَيْرَ مَا أَصَبْنَا هَذَا التَّمْرُ","id":"(Ahmad bin Hanbal radliyallhu'anhu) berkata; telah menceritakan kepada kami [Abdusshamad bin Al Abdul Warits] berkata; telah bercerita kepadsaya [bapakku] telah menceritakan kepada kami [Daud] yaitu Ibnu Abu Hind, dari [Abu Harb] [Thalhah] menceritakannya, dia termasuk dari kalangan sahabat, berkata; saya datang ke Madinah dalam keadaan buta tentang seluk beluk kota itu, maka saya singgah di Suffah bersama seorang laki-laki, saya dan dia saban hari mendapat jatah satu mud kurma. Suatu hari Rasulullah Shallallahu'alaihiwasallam melaksanakan shalat, ketika sudah selesai, ada seorang laki-laki Ahli Shuffah berkata; \"Wahai Rasulullah, kurma telah membakar perut kami, dan pakaian jelek ini telah sedemikian compang camping\". Rasulullah Shallallahu'alaihiwasallam naik ke mimbar lalu berkhutbah, lalu bersabda: \"Demi Allah, kalaulah saya mendapatkan roti atau daging, pastilah saya berikan untuk kalian. Tak lama lagi kalian mendapatkannya. Siapa di antara kalian menjumpainya, niscaya ada yang diberi piring besar, atau kalian memakai pakaian seperti penutup Ka'bah.\" (Thalhah radliyallhu'anhu) berkata; lalu saya dan saudaraku tinggal selama delapan belas hari, kami tidak mendapatkan makanan kecuali barir (buah arak yang telah hitam dan rusak) sampai saya datang kepada saudara kami dari Anshar, dan dia membantu kami, kurma itulah makanan paling baik yang kami dapati. "},"793":{"ar":"قَالَ حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ الرَّازِيُّ قَالَ حَدَّثَنَا سَلَمَةُ بْنُ الْفَضْلِ الْأَنْصَارِيُّ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَاقَ قَالَ حَدَّثَنِي سَعْدُ بْنُ طَارِقٍ الْأَشْجَعِيُّ وَهُوَ أَبُو مَالِكٍ عَنْ سَلَمَةَ بْنِ نُعَيْمِ بْنِ مَسْعُودٍ الْأَشْجَعِيِّ عَنْ أَبِيهِ نُعَيْمٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ حِينَ قَرَأَ كِتَابَ مُسَيْلِمَةَ الْكَذَّابِ قَالَ لِلرَّسُولَيْنِ فَمَا تَقُولَانِ أَنْتُمَا قَالَا نَقُولُ كَمَا قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاللَّهِ لَوْلَا أَنَّ الرُّسُلَ لَا تُقْتَلُ لَضَرَبْتُ أَعْنَاقَكُمَا","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim Ar-Razi] berkata; telah menceritakan kepada kami [Salamah bin Al Fadl Al Anshari] berkata; telah menceritakan kepada kami [Muhammad bin Ishaq] berkata; telah menceritakan kepadaku [Sa'ad bin Thariq Al Asyja'i] yaitu Abu Malik, dari [Salamah bin Nu'aim bin Mas'ud Al Asyja'i] dari [Bapaknya, Nu'aim] berkata; saya mendengar Rasulullah Shallallahu'alaihiwasallam ketika membaca surat Musailamah Al Kadzab, beliau bertanya dua orang utusannya, \"Apa yang kalian komentari tentang suratnya?\" (mereka berdua) berkata; Kami sependapat dengan dia (Musailamah). Rasulullah Shallallahu'alaihiwasallam bersabda: \"Demi Allah, kalaulah bukan karena pertimbangan seorang utusan tidak boleh dibunuh, pasti saya potong leher kalian berdua\"."},"794":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ يَحْيَى بْنِ سَعِيدٍ الْأَنْصَارِيِّ قَالَ حَدَّثَنِي بُشَيْرُ بْنُ يَسَارٍ عَنْ سُوَيْدِ بْنِ النُّعْمَانِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَزَلَ بِالصَّهْبَاءِ عَامَ خَيْبَرَ فَلَمَّا صَلَّى الْعَصْرَ دَعَا بِالْأَطْعِمَةِ فَلَمْ يُؤْتَ إِلَّا بِسَوِيقٍ قَالَ فَلُكْنَا يَعْنِي أَكَلْنَا مِنْهُ فَلَمَّا كَانَتْ الْمَغْرِبُ تَمَضْمَضَ وَتَمَضْمَضْنَا مَعَهُ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Yahya bin Sa'id Al Anshori] berkata; telah menceritakan kepadaku [Busyair bin Yasar] dari [Suwaid bin An Nu'man] Rasulullah Shallallahu'alaihiwasallam singgah di Shahba' pada tahun terjadinya Perang Khaibar. Selesai beliau shalat asar, beliau meminta makanan, namun tidak di suguhkan kecuali hanya sawiq (makanan yang terbuat dari tepung gandum). (Suwaid bin An Nu'man) berkata; Lalu kami memakannya, pada saat maghrib, beliau berkumur-kumur saja dan juga kami."},"795":{"ar":"قَالَ حَدَّثَنَا عَفَّانُ حَدَّثَنَا وُهَيْبٌ قَالَ حَدَّثَنِي مُوسَى بْنُ عُقْبَةَ قَالَ حَدَّثَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ عَنِ الْأَقْرَعِ بْنِ حَابِسٍأَنَّهُ نَادَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ وَرَاءِ الْحُجُرَاتِ فَقَالَ يَا رَسُولَ اللَّهِ فَلَمْ يُجِبْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَلَا إِنَّ حَمْدِي زَيْنٌ وَإِنَّ ذَمِّي شَيْنٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَمَا حَدَّثَ أَبُو سَلَمَةَ ذَاكَ اللَّهُ عَزَّ وَجَلَّ","id":"(Ahmad bin Hanbal radliyallhu'anhu) berkata; telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Wuhaib] berkata; telah menceritakan kepadaku [Musa bin 'Utbah] berkata; telah menceritakan kepadaku [Abu Salamah bin Abdurrahman] dari [Al Aqro' bin Habis] dia memanggil Rasulullah Shallallahu'alaihiwasallam dari belakang kamar, \"Wahai Rasulullah\", Rasulullah Shallallahu'alaihiwasallam tidak menjawabnya. Lalu dia mengulangi kembali, \"Wahai Rasulullah, bukankah pujianku adalah perhiasan dan keburukan amalku adalah aib\". Rasulullah Shallallahu'alaihiwasallam bersabda: sebagaimana Abu Salamah menceritakan, \"Itu adalah Allah Azzawajalla\"."},"796":{"ar":"قَالَ حَدَّثَنَا أَبُو عَامِرٍ عَبْدُ الْمَلِكِ بْنُ عَمْرٍو قَالَ حَدَّثَنَا الْمُغِيرَةُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي الزِّنَادِ قَالَ حَدَّثَنِي الْمُرَقِّعُ بْنُ صَيْفِيٍّ عَنْ جَدِّهِ رَبَاحِ بْنِ الرَّبِيعِ أَخِي حَنْظَلَةَ الْكَاتِبِ أَنَّهُ أَخْبَرَهُأَنَّهُ خَرَجَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةٍ غَزَاهَا وَعَلَى مُقَدِّمَتِهِ خَالِدُ بْنُ الْوَلِيدِ فَمَرَّ رَبَاحٌ وَأَصْحَابُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى امْرَأَةٍ مَقْتُولَةٍ مِمَّا أَصَابَتْ الْمُقَدِّمَةُ فَوَقَفُوا يَنْظُرُونَ إِلَيْهَا وَيَتَعَجَّبُونَ مِنْ خَلْقِهَا حَتَّى لَحِقَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى رَاحِلَتِهِ فَانْفَرَجُوا عَنْهَا فَوَقَفَ عَلَيْهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا كَانَتْ هَذِهِ لِتُقَاتِلَ فَقَالَ لِأَحَدِهِمْ الْحَقْ خَالِدًا فَقُلْ لَهُ لَا تَقْتُلُونَ ذُرِّيَّةً وَلَا عَسِيفًاقَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ أَبِي الْعَبَّاسِ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي الزِّنَادِ عَنْ أَبِي الزِّنَادِ قَالَ أَخْبَرَنِي الْمُرَقِّعُ بْنُ صَيْفِيِّ بْنِ رَبَاحٍ أَنَّ رَبَاحًا جَدَّهُ ابْنَ الرَّبِيعِ أَخْبَرَهُ أَنَّهُ كَانَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ الْحَدِيثَ حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا ابْنُ أَبِي الزِّنَادِ عَنْ أَبِيهِ عَنِ الْمُرَقِّعِ بْنِ صَيْفِيِّ بْنِ رَبَاحٍ أَخِي حَنْظَلَةَ الْكَاتِبِ قَالَ أَخْبَرَنِي جَدِّي أَنَّهُ خَرَجَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ الْحَدِيثَ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أُخْبِرْتُ عَنْ أَبِي الزِّنَادِ قَالَ أَخْبَرَنِي مُرَقِّعُ بْنُ صَيْفِيٍّ التَّمِيمِيُّ شَهِدَ عَلَى جَدِّهِ رَبَاحِ بْنِ رَبِيعٍ الْحَنْظَلِيِّ الْكَاتِبِ أَنَّهُ أَخْبَرَهُ أَنَّهُ خَرَجَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةٍ فَذَكَرَ مِثْلَ حَدِيثِ ابْنِ أَبِي الزِّنَادِ","id":"(Ahmad bin Hanbal radliyallhu'anhu) berkata; telah menceritakan kepada kami [Abu 'Amir Abdul Malik bin 'Amr] berkata; telah menceritakan kepada kami [Al Mughirah bin Abdurrohman] dari [Abu Zinad] berkata; telah menceritakan kepadaku [Al Muraqq' bin Shaifi] dari [kakeknya, Rabah bin Ar-Rabi'], saudara Handzalah seorang penulis dia mengabarinya, dia keluar bersama Rasulullah Shallallahu'alaihiwasallam dalam suatu peperangan. Di bagian depan terdapat Khalid bin Al Walid, lalu Rabah dan beberapa sahabat Rasulullah melewati seorang wanita yang terbunuh oleh pasukan yang berada di depan, maka mereka berhenti dan mengamat-amatinya serta terherAn heran. Sampai Rasulullah Shallallahu'alaihiwasallam menghampiri mereka dari atas untanya, para sahabat serentak memberi kelapangan jalan kepada beliau, dan Rasulullah Shallallahu'alaihiwasallam berdiri di atas mayat wanita itu. Lalu beliau bersabda: Kenapa wanita ini diperangi?!\" lalu beliau bersabda kepada salah seorang, susullah Khalid dan katakan padanya, jangan membunuh anak-anak dan para wanita\". (Ahmad bin Hanbal radliyallhu'anhu) berkata; telah menceritakan kepada kami [Ibrahim bin Abu Al 'Abbas] berkata; telah menceritakan kepada kami [Abdurrahman bin Abu Az Zinnad] dari [Abu Zinad] berkata; telah mengabarkan kepadaku [Al Muraqqi' bin Shaify bin Rabah] [Rabah, kakek Ibnu Ar-Rabi] mengabarinya, dia bersama Rasulullah Shallallahu'alaihiwasallam, lalu menyebutkan hadis secara lengkap. Telah menceritakan kepada kami [Husain bin Muhammad] berkata; telah menceritakan kepada kami [Ibnu Abu Zinnad] dari [bapaknya] dari [Al Muraqqi' bin Shaifi bin Rabah, saudara Handzalah seorang penulis] berkata; telah mengabarkan kepadaku [kakekku] dia keluar bersama Rasulullah Shallallahu'alaihiwasallam, lalu menyebutkan hadis secara sempurna. Telah menceritakan kepada kami [Abdurrazaq] berkata; telah mengabarkan kepada kami [Ibnu Juraij] berkata; saya [telah dikabari] dari [Abu Zinad] berkata; telah menceritakan kepadaku [Muraqqi' bin Ash-Shaifi At-Taimi] menyaksikan [kakeknya, Rabah bin Rabi' Al Handzaly, seorang penulis] dia mengabarinya, dia keluar bersama Rasulullah Shallallahu'alaihiwasallam dalam suatu peperangan, lalu menyebutkan seperti hadis Ibnu Abu Zinnad."},"797":{"ar":"قَالَ حَدَّثَنَا أَبُو النَّضْرِ حَدَّثَنَا الْحَكَمُ بْنُ فُضَيْلٍ حَدَّثَنَا يَعْلَى بْنُ عَطَاءٍ عَنْ عُبَيْدِ بْنِ جُبَيْرٍ عَنْ أَبِي مُوَيْهِبَةَ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَأُمِرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُصَلِّيَ عَلَى أَهْلِ الْبَقِيعِ فَصَلَّى عَلَيْهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةً ثَلَاثَ مَرَّاتٍ فَلَمَّا كَانَتْ لَيْلَةُ الثَّانِيَةِ قَالَ يَا أَبَا مُوَيْهِبَةَ أَسْرِجْ لِي دَابَّتِي قَالَ فَرَكِبَ فَمَشَيْتُ حَتَّى انْتَهَى إِلَيْهِمْ فَنَزَلَ عَنْ دَابَّتِهِ وَأَمْسَكَتْ الدَّابَّةُ وَوَقَفَ عَلَيْهِمْ أَوْ قَالَ قَامَ عَلَيْهِمْ فَقَالَ لِيَهْنِيكُمْ مَا أَنْتُمْ فِيهِ مِمَّا فِيهِ النَّاسُ أَتَتْ الْفِتَنُ كَقِطَعِ اللَّيْلِ يَرْكَبُ بَعْضُهَا بَعْضًا الْآخِرَةُ أَشَدُّ مِنْ الْأُولَى فَلْيَهْنِيكُمْ مَا أَنْتُمْ فِيهِ ثُمَّ رَجَعَ فَقَالَ يَا أَبَا مُوَيْهِبَةَ إِنِّي أُعْطِيتُ أَوْ قَالَ خُيِّرْتُ مَفَاتِيحَ مَا يُفْتَحُ عَلَى أُمَّتِي مِنْ بَعْدِي وَالْجَنَّةَ أَوْ لِقَاءَ رَبِّي فَقُلْتُ بِأَبِي وَأُمِّي يَا رَسُولَ اللَّهِ فَأَخْبِرْنِي قَالَ لَأَنْ تُرَدَّ عَلَى عَقِبِهَا مَا شَاءَ اللَّهُ فَاخْتَرْتُ لِقَاءَ رَبِّي عَزَّ وَجَلَّ فَمَا لَبِثَ بَعْدَ ذَلِكَ إِلَّا سَبْعًا أَوْ ثَمَانِيًا حَتَّى قُبِضَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ أَبُو النَّضْرِ مَرَّةً تُرَدُّ عَلَى عَقِبَيْهَا","id":"Telah menceritakan kepada kami [Abu Nadlr] telah menceritakan kepada kami [Al Hakam bin Fudlail] telah menceritakan kepada kami [Ya'la bin 'Atha'] dari ['Ubaid bin Jubair] dari [Abu Muwaihibah] budak Rasulullah Shallallahu'alaihiwasallam mengatakan; Rasulullah Shallallahu'alaihiwasallam diminta untuk mendoakan penghuni pekuburan Baqi', lalu Rasulullah Shallallahu'alaihiwasallam mendoakan mereka pada waktu malam sebanyak tiga kali. Pada malam kedua, beliau bersabda: \"Wahai Abu Muwaihibah, berilah pelana pada kendaraanku.\" Lalu beliau naik dan saya berjalan sehingga kami sampai ke mereka. Beliau turun dari tunggangannya setelah tunggangannya berhenti. Beliau berdiri di tengah-tengah mereka dan bersabda: \"Hendaklah kalian merasa nyaman, daripada keadaan yang dialami manusia sekarang ini. Telah datang fitnah seperti segelapAn kegelapan malam, kegelapan itu bertumpuk-tumpukan. Fitnah yang terakhir jauh lebih dahsyat daripada fitnah yang pertama, maka hendaklah kalian merasa nyaman dengan keadaanmu sekarang\", lalu beliau kembali dan bersabda: \"Wahai Abu Muwaihibah. Sesungguhnya saya telah diberi, \" atau bersabda dengan redaksi, \" Aku diberi pilihan kunci-kunci perbendaharaan duniawi yang akan dibuka untuk umatku setelahku dan surga, atau pertemuan Rabku\" Lalu saya berkata; demi bapakku dan ibuku, Wahai Rasulullah, beritahukanlah aku!. Beliau bersabda: \"Umatku akan kembali kepada kekufuran sebagaimana Allah kehendaki, sehingga saya memilih bertemu dengan Rabku\". Tidak lama setelah kejadian itu kecuali tujuh atau delapan hari, sehingga (Rasulullah) Shallallahu'alaihiwasallam wafat.\" Dan Abu Nadlr berkata; dan umatnya telah kembali kepada kekufuran."},"798":{"ar":"قَالَ حَدَّثَنِي يَعْقُوبُ قَالَ حَدَّثَنِي أَبِي قَالَ عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عُمَرَ الْعَبْلِيُّ قَالَ حَدَّثَنِي عُبَيْدُ بْنُ جُبَيْرٍ مَوْلَى الْحَكَمِ بْنِ أَبِي الْعَاصِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو عَنْ أَبِي مُوَيْهِبَةَ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَبَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ جَوْفِ اللَّيْلِ فَقَالَ يَا أَبَا مُوَيْهِبَةَ إِنِّي قَدْ أُمِرْتُ أَنْ أَسْتَغْفِرَ لِأَهْلِ الْبَقِيعِ فَانْطَلِقْ مَعِي فَانْطَلَقْتُ مَعَهُ فَلَمَّا وَقَفَ بَيْنَ أَظْهُرِهِمْ قَالَ السَّلَامُ عَلَيْكُمْ يَا أَهْلَ الْمَقَابِرِ لِيَهْنِ لَكُمْ مَا أَصْبَحْتُمْ فِيهِ مِمَّا أَصْبَحَ فِيهِ النَّاسُ لَوْ تَعْلَمُونَ مَا نَجَّاكُمْ اللَّهُ مِنْهُ أَقْبَلَتْ الْفِتَنُ كَقِطَعِ اللَّيْلِ الْمُظْلِمِ يَتْبَعُ أَوَّلُهَا آخِرَهَا الْآخِرَةُ شَرٌّ مِنْ الْأُولَى قَالَ ثُمَّ أَقْبَلَ عَلَيَّ فَقَالَ يَا أَبَا مُوَيْهِبَةَ إِنِّي قَدْ أُوتِيتُ مَفَاتِيحَ خَزَائِنِ الدُّنْيَا وَالْخُلْدَ فِيهَا ثُمَّ الْجَنَّةَ وَخُيِّرْتُ بَيْنَ ذَلِكَ وَبَيْنَ لِقَاءِ رَبِّي عَزَّ وَجَلَّ وَالْجَنَّةِ قَالَ قُلْتُ بِأَبِي وَأُمِّي فَخُذْ مَفَاتِيحَ الدُّنْيَا وَالْخُلْدَ فِيهَا ثُمَّ الْجَنَّةَ قَالَ لَا وَاللَّهِ يَا أَبَا مُوَيْهِبَةَ لَقَدْ اخْتَرْتُ لِقَاءَ رَبِّي عَزَّ وَجَلَّ وَالْجَنَّةَ ثُمَّ اسْتَغْفَرَ لِأَهْلِ الْبَقِيعِ ثُمَّ انْصَرَفَ فَبُدِئَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي وَجَعِهِ الَّذِي قَضَاهُ اللَّهُ عَزَّ وَجَلَّ فِيهِ حِينَ أَصْبَحَ","id":"Telah menceritakan kepada kami [Ya'qub] berkata; telah menceritakan kepadaku [bapakku] berkata; dari [Muhammad bin Ishaq] berkata; telah menceritakan kepadaku [Abdullah bin 'Umar Al 'Abla] berkata; telah menceritakan kepadaku ['Ubaid bin Jubair] budak Al Hakam bin Abu Al 'Ash, dari [Abdullah bin 'Amr] dari [Abu Muwaihibah], budak Rasulullah Shallallahu'alaihiwasallam, berkata; Rasulullah Shallallahu'alaihiwasallam mengutusku pada suatu malam yang sangat gelap, lalu beliau bersabda: \"Wahai Abu Muwaihibah? Saya diperintah untuk memintakan ampun untuk penghuni pekuburan Baqi', berangkatlah bersamaku\". Saya pun berangkat bersamanya, tatkala sudah sampai di sana, beliau bersabda: \"Semoga kesejahteraan kepada kalian wahai penghuni kubur, hendaklah kalian merasa nyaman dengan keadaanmu sekarang daripada keadaan yang dialami manusia sekarang ini. Duhai sekiranya kalian mengetahui bagaimana Allah menyelamatkan kalian. Telah datang fitnah sebagaimana bagiAn bagian malam yang sangat gelap, yang fitnah itu datang susul menyusul, dan fitnah yang terakhir jauh lebih jelek daripada yang pertama.\" (Abu Muwaihibah) berkata; lalu beliau menemui saya dan bersabda: \"Wahai Abu Muwaihibah, saya telah diberi kunci-kunci simpanAn simpanan dunia dan kekekalannya, kemudian surga. Saya di suruh memilih antara hal itu atau bertemu dengan Rabku Azzawajalla dan surga\". Lalu beliau bersabda: \"Tidak, demi Allah, Wahai Abu Muwaihibah, saya memilih bertemu dengan Rabku AzzaWaJalla dan surga', lalu beliau meminta ampunan untuk penghuni pekuburan Baqi'. Lalu beliau pergi dan mulailah sakit Rasulullah Shallallahu'alaihiwasallam yang Allah Azzawajalla tetapkan pada pagi harinya\"."},"799":{"ar":"قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ قَالَ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ مُسْلِمِ بْنِ يَسَارٍ عَنْ أَبِي الْأَشْعَثِ الصَّنْعَانِيِّ عَنْ رَاشِدِ بْنِ حُبَيْشٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَى عُبَادَةَ بْنِ الصَّامِتِ يَعُودُهُ فِي مَرَضِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَعْلَمُونَ مَنْ الشَّهِيدُ مِنْ أُمَّتِي فَأَرَمَّ الْقَوْمُ فَقَالَ عُبَادَةُ سَانِدُونِي فَأَسْنَدُوهُ فَقَالَ يَا رَسُولَ اللَّهِ الصَّابِرُ الْمُحْتَسِبُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ شُهَدَاءَ أُمَّتِي إِذًا لَقَلِيلٌ الْقَتْلُ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ شَهَادَةٌ وَالطَّاعُونُ شَهَادَةٌ وَالْغَرَقُ شَهَادَةٌ وَالْبَطْنُ شَهَادَةٌ وَالنُّفَسَاءُ يَجُرُّهَا وَلَدُهَا بِسُرَرِهِ إِلَى الْجَنَّةِقَالَ وَزَادَ فِيهَا أَبُو الْعَوَّامِ سَادِنُ بَيْتِ الْمَقْدِسِ وَالْحَرْقُ وَالسَّيْلُ حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ صَاحِبٍ لَهُ عَنْ رَاشِدِ بْنِ حُبَيْشٍ عَنْ عُبَادَةَ بْنِ الصَّامِتِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَاهُ يَعُودُهُ فِي مَرَضِهِ فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Muhammad bin Bakr] berkata; telah menceritakan kepada kami [Sa'id bin Abu 'Arubah] dari [Qatadah] dari [Muslim bin Yasar] dari [Abu Al Asy'ats, Ash-Shan'ani] dari [Rasyid bin Hubais], Rasulullah Shallallahu'alaihiwasallam menemui 'Ubadah bin Shamit untuk menjenguknya ketika dia sakit. Rasulullah Shallallahu'alaihiwasallam bersabda: \"Apakah kalian tahu, siapa yang diistilahkan syahid di antara umatku?\" Semua terdiam. 'Ubadah berkata; \"Sandarkanlah saya\", mereka pun menyandarkannya. Lalu Ubadah berkata; \"Wahai Rasulullah, yang dinamakan syahid adalah orang sabar yang mengharapkan balasan dari Allah\". Rasulullah Shallallahu'alaihiwasallam bersabda: \"Kalau begitu orang yang syahid dari ummatku sangat sedikit, padahal orang yang terbunuh di jalan Allah Azzawajalla adalah syahid, orang yang mati terkena Thaun adalah syahid, orang mati tenggelam adalah syahid, orang yang mati karena sakit perut adalah syahid, wanita yang meninggal karena melahirkan anaknya, anaknya menariknya dengan tali pusar untuk masuk ke surga\". [Abu Al 'Awwam], pengurus Baitul Maqdis menambahnya, \"Orang yang mati karena terbakar, dan yang mati karena terseret sungai\" Telah menceritakan kepada kami [Abdusshamad] telah menceritakan kepada kami [Hammad] dari [Qatadah] dari [temannya] dari [Rasyid bin Hubais] dari ['Ubadah bin Shamit] Rasulullah Shallallahu'alaihiwasallam menjenguknya waktu sakitnya, lalu menyebut hadis."},"800":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ مَوْلَى بَنِي هَاشِمٍ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ عَمَّارِ بْنِ أَبِي عَمَّارٍ عَنْ أَبِي حَبَّةَ الْبَدْرِيِّ قَالَلَمَّا نَزَلَتْ لَمْ يَكُنْ قَالَ جِبْرِيلُ عَلَيْهِ السَّلَام يَا مُحَمَّدُ إِنَّ رَبَّكَ يَأْمُرُكَ أَنْ تُقْرِئَ هَذِهِ السُّورَةَ أُبَيَّ بْنَ كَعْبٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أُبَيُّ إِنَّ رَبِّي عَزَّ وَجَلَّ أَمَرَنِي أَنْ أُقْرِئَكَ هَذِهِ السُّورَةَ فَبَكَى وَقَالَ ذُكِرْتُ ثَمَّةَ قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Abu Sa'id] budak Bani Hasyim, berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari ['Ali bin Zaid] dari ['Amar bin Abu Amar] dari [Abu Habbah Al Badry] berkata; Ketika turun ayat, LAM YAKUN (Al Bayyinah), Jibril Alaihissalam berkata; \"Wahai Muhammad, Rab-mu menyuruhmu untuk membacakan surat ini kepada Ubay bin Ka'ab\". Nabi Shallallahu'alaihiwasallam kontan bersabda: \"Wahai Ubay Rabbi-ku AzzaWaJalla menyuruhku untuk membacakan surat ini kepadamu\", maka (Ubbay) menangis dan berkata; Apakah namaku disebut-sebut di sana\"? (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Ya\"."},"801":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا عَلِيُّ بْنُ زَيْدٍ عَنْ عَمَّارِ بْنِ أَبِي عَمَّارٍ قَالَ سَمِعْتُ أَبَا حَبَّةَ الْبَدْرِيَّ قَالَلَمَّا نَزَلَتْ لَمْ يَكُنْ الَّذِينَ كَفَرُوا مِنْ أَهْلِ الْكِتَابِ إِلَى آخِرِهَا قَالَ جِبْرِيلُ عَلَيْهِ السَّلَام يَا رَسُولَ اللَّهِ إِنَّ رَبَّكَ يَأْمُرُكَ أَنْ تُقْرِئَهَا أُبَيًّا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأُبَيٍّ إِنَّ جِبْرِيلَ عَلَيْهِ السَّلَام أَمَرَنِي أَنْ أُقْرِئَكَ هَذِهِ السُّورَةَ قَالَ أُبَيٌّ وَقَدْ ذُكِرْتُ ثَمَّ يَا رَسُولَ اللَّهِ قَالَ نَعَمْ قَالَ فَبَكَى أُبَيٌّ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Salamah] telah mengabarkan kepada kami ['Ali bin Zaid] dari ['Amar bin Abu Amar] berkata; saya mendengar [Abu Habbah Al Badry] berkata; Ketika turun ayat LAMYAKUNIL LADZINA KAFARU MIN AHLIL KITABI, sampai akhir, Jibril 'alaihissalam berkata; \"Wahai Rasulullah, Rab-mu menyuruhmu untuk membacakannya kepada Ubbay\". Lalu Nabi Shallallahu'alaihiwasallam bersabda kepada Ubay 'Jibril 'alaihissalam menyuruhku untuk membacakan surat ini kepadamu\", maka Ubay berkata; Apakah namaku disebut-sebut di sana Wahai Rasulullah?. (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Ya\". Lalu Ubay menangis."},"802":{"ar":"حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا مَعْرُوفٌ يَعْنِي ابْنَ وَاصِلٍ قَالَ حَدَّثَتْنِي حَفْصَةُ ابْنَةُ طَلْقٍ امْرَأَةٌ مِنْ الْحَيِّ سَنَةَ تِسْعِينَ عَنْ أَبِي عُمَيْرَةَ قَالَكُنَّا جُلُوسًا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا فَجَاءَ رَجُلٌ بِطَبَقٍ عَلَيْهِ تَمْرٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا هَذَا أَصَدَقَةٌ أَمْ هَدِيَّةٌ قَالَ صَدَقَةٌ قَالَ فَقَدِّمْهُ إِلَى الْقَوْمِ وَحَسَنٌ صَلَوَاتُ اللَّهِ وَسَلَامُهُ عَلَيْهِ يَتَعَفَّرُ بَيْنَ يَدَيْهِ فَأَخَذَ الصَّبِيُّ تَمْرَةً فَجَعَلَهَا فِي فِيهِ فَأَدْخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُصْبُعَهُ فِي فِي الصَّبِيِّ فَنَزَعَ التَّمْرَةَ فَقَذَفَ بِهَا ثُمَّ قَالَ إِنَّا آلَ مُحَمَّدٍ لَا تَحِلُّ لَنَا الصَّدَقَةُفَقُلْتُ لِمَعْرُوفٍ أَبُو عُمَيْرٍ جَدُّكَ قَالَ جَدُّ أَبِي قَالَ حَدَّثَنَا حَسَنُ بْنُ مُوسَى قَالَ حَدَّثَنَا مَعْرُوفٌ عَنْ حَفْصَةَ بِنْتِ طَلْقٍ عَنْ أَبِي عَمِيرَةَ أُسَيْدِ بْنِ مَالِكٍ جَدِّ مَعْرُوفٍ قَالَ كُنَّا جُلُوسًا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Yahya bin Adam] telah menceritakan kepada kami [Ma'ruf] yaitu Ibnu Wasil, berkata; telah menceritakan kepadaku [Hafshah], anak Thalq, seorang wanita dari suatu desa tahun sembilan puluh, dari [Abu 'Umairah] berkata; kami sedang duduk di samping Rasulullah Shallallahu'alaihiwasallam pada suatu hari, selanjutnya seorang laki-laki membawa periuk berisi kurma. Rasulullah Shallallahu'alaihiwasallam bersabda: \"Apakah ini sedekah ataukah hadiah?\" laki-laki tersebut menjawab, \"Itu adalah sedekah\". beliau bersabda: \"Berikanlah untuk orang-orang\". Lantas Hasan memasukkan jarinya, mengambil kurma lalu meletakkanya di mulutnya. Kontan Nabi Shallallahu'alaihiwasallam memasukkan jarinya pada mulut bayi dan mengeluarkan kurma dan membuangnya. Beliau bersabda: \"Sesungguhnya keluarga Muhammad, tidak halal sedekah bagi kita\". Saya berkata kepada Ma'ruf bahwa Abu 'Umair adalah kakekmu, maka (Ma'ruf) berkata; dia adalah kakek bapakku. (Ahmad bin Hanbal radliyallhu'anhu) berkata; telah menceritakan kepada kami [Hasan bin Musa] berkata; telah menceritakan kepada kami [Ma'ruf] dari [Hafshah binti Thalq] dari [Abu 'Amirah, Usaid bin Malik, kakek Ma'ruf] berkata; kami sedang duduk bersama Rasulullah Shallallahu'alaihiwasallam, lalu menyebutkan hadisnya secara lengkap"},"803":{"ar":"قَالَ حَدَّثَنَا هَيْثَمُ بْنُ خَارِجَةَ قَالَ أَخْبَرَنَا أَبُو عَبْدِ الْمَلِكِ الْحَسَنُ بْنُ يَحْيَى الْخُشَنِيُّ عَنْ بِشْرِ بْنِ حَيَّانَ قَالَجَاءَ وَاثِلَةُ بْنُ الْأَسْقَعِ وَنَحْنُ نَبْنِي مَسْجِدَنَا قَالَ فَوَقَفَ عَلَيْنَا فَسَلَّمَ ثُمَّ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَ��ُولُ مَنْ بَنَى مَسْجِدًا يُصَلَّى فِيهِ بَنَى اللَّهُ عَزَّ وَجَلَّ لَهُ فِي الْجَنَّةِ أَفْضَلَ مِنْهُقَالَ أَبُو عَبْد الرَّحْمَنِ وَقَدْ سَمِعْتُهُ مِنْ هَيْثَمِ بْنِ خَارِجَةَ","id":"(Ahmad bin Hanbal radliyallhu'anhu) berkata; telah menceritakan kepada kami [Hutsaim bin Kharijah] berkata; telah mengabarkan kepada kami [Abu Abdul Malik Al Hasan bin Yahya Al Khusyni] dari [Bisyr bin Hayyan] berkata; [Watsilah bin Al Asyqa'] datang ketika kami membangun masjid kami. Dia berdiri dan mengucapkan salam kepada kami, dan berkata; saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa membangun masjid dan digunakan untuk shalat, Allah Azzawajalla membangunkan sesuatu yang jauh lebih baik baginya di surga\". Abu Abdurrahman berkata demikian dan saya juga mendengarnya dari Haitsam bin Kharijah."},"804":{"ar":"قَالَ حَدَّثَنَا عَتَّابٌ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ قَالَ أَخْبَرَنَا ابْنُ لَهِيعَةَ قَالَ حَدَّثَنِي يَزِيدُ يَعْنِي ابْنَ أَبِي حَبِيبٍ أَنَّ رَبِيعَةَ بْنَ يَزِيدَ الدِّمَشْقِيَّ أَخْبَرَهُ عَنْ وَاثِلَةَ يَعْنِي ابْنَ الْأَسْقَعِ قَالَكُنْتُ مِنْ أَهْلِ الصُّفَّةِ فَدَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا بِقُرْصٍ فَكَسَرَهُ فِي الْقَصْعَةِ وَصَنَعَ فِيهَا مَاءً سُخْنًا ثُمَّ صَنَعَ فِيهَا وَدَكًا ثُمَّ سَفْسَفَهَا ثُمَّ لَبَّقَهَا ثُمَّ صَعْنَبَهَا ثُمَّ قَالَ اذْهَبْ فَأْتِنِي بِعَشَرَةٍ أَنْتَ عَاشِرُهُمْ فَجِئْتُ بِهِمْ فَقَالَ كُلُوا وَكُلُوا مِنْ أَسْفَلِهَا وَلَا تَأْكُلُوا مِنْ أَعْلَاهَا فَإِنَّ الْبَرَكَةَ تَنْزِلُ مِنْ أَعْلَاهَا فَأَكَلُوا مِنْهَا حَتَّى شَبِعُوا","id":"(Ahmad bin Hanbal radliyallhu'anhu) berkata; telah menceritakan kepada kami ['Attab] berkata; telah menceritakan kepada kami [Abdullah bin Al Mubarak] berkata; telah mengabarkan kepada kami [Ibnu Lahi'ah] berkata; telah menceritakan kepadaku [Yazid] yaitu Ibnu Abu Habib, [Rabi'ah bin Yazid Ad-Dimasyki] mengabarinya, dari [Watsilah] yaitu Ibnu Al Asyqa', saya termasuk dari Ahli Shuffah, pada suatu hari Rasulullah Shallallahu'alaihiwasallam memanggil-manggil dengan membawa roti yang berbentuk bulat pipih, lantas beliau memecahnya dalam bejana yang berisi air hangat. Beliau buat bubur roti dalam bejana tersebut, beliau saring dengan saringan, dan beliau campur sedemikian rupa, kemudian beliau bersabda: \"Undanglah sepuluh orang, sekaligus kamu\". Saya membawa mereka, lalu beliau bersabda: \"Makanlah, makanlah kalian dari bawahnya dan jangan kalian makan dari atasnya, sebab keberkahan itu turun dari atas\" lalu mereka memakannya sampai kenyang."},"805":{"ar":"قَالَ حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنَا لَيْثٌ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مَلِيحِ بْنِ أُسَامَةَ عَنْ وَاثِلَةَ بْنِ الْأَسْقَعِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمِرْتُ بِالسِّوَاكِ حَتَّى خَشِيتُ أَنْ يُكْتَبَ عَلَيَّ","id":"(Ahmad bin Hanbal radliyallhu'anhu) berkata; telah menceritakan kepada kami [Isma'il] berkata; telah menceritakan kepada kami [Laits] dari [Abu Burdah] dari [Abu Mulaih bin Usamah] dari [Watsilah bin Al Ayqa'] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Saya diperintah untuk bersiwak hingga saya khawatir jangAn jangan hal itu diwajibkan atasku\""},"806":{"ar":"قَالَ حَدَّثَنَا هَاشِمٌ قَالَ حَدَّثَنَا أَبُو فَضَالَةَ الْفَرَجُ قَالَ حَدَّثَنَا أَبُو سَعْدٍ قَالَرَأَيْتُ وَاثِلَةَ بْنَ الْأَسْقَعِ يُصَلِّي فِي مَسْجِدِ دِمَشْقَ فَبَزَقَ تَحْتَ رِجْلِهِ الْيُسْرَى ثُمَّ عَرَكَهَا بِرِجْلِهِ فَلَمَّا انْصَرَفَ قُلْتُ أَنْتَ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَبْزُقُ فِي الْمَسْجِدِ قَالَ هَكَذَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْعَلُ","id":"(Ahmad bin Hanbal radliyallhu'anhu) berkata; telah menceritakan kepada kami [Hasyim] berkata; telah menceritakan kepada kami [Abu Fadlalah bin Al Faraj] berkata; telah menceritakan kepada kami [Abu Sa'd] berkata; Saya melihat [Watsilah bin Asyqa'] shalat di masjid Damaskus, lalu dia meludah di bawah kaki kirinya kemudian mengubur bekas ludahnya dengan kakinya. Selesai shalat, saya bertanya, \"Apa kamu termasuk sahabat Rasulullah Shallallahu'alaihiwasallam, berludah di masjid?\", maka dia berkata; \"Begitulah saya melihat Rasulullah Shallallahu'alaihiwasallam berbuat\"."},"807":{"ar":"قَالَ حَدَّثَنَا أَبُو النَّضْرِ هَاشِمٌ قَالَ أَخْبَرَنَا ابْنُ عُلَاثَةَ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ أَبِي عَبْلَةَ عَنْ وَاثِلَةَ بْنِ الْأَسْقَعِ قَالَجَاءَ نَفَرٌ مِنْ بَنِي سُلَيْمٍ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا يَا رَسُولَ اللَّهِ إِنَّ صَاحِبًا لَنَا قَدْ أَوْجَبَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيَعْتِقْ رَقَبَةً مُسْلِمَةً يَفُكَّ اللَّهُ عَزَّ وَجَلَّ بِكُلِّ عُضْوٍ مِنْهَا عُضْوًا مِنْهُ مِنْ النَّارِ","id":"(Ahmad bin Hanbal radliyallhu'anhu) berkata; telah menceritakan kepada kami [Abu Nadlr, Hasyim] berkata; telah mengabarkan kepada kami [Ibnu 'Ulatsah] berkata; telah menceritakan kepada kami [Ibrahim bin Abu 'Ablah] dari [Watsilah bin Al Asyqa'] berkata; telah datang beberapa laki-laki dari Bani Sulaim kepada Rasulullah Shallallahu'alaihiwasallam lalu mereka berkata; \"Wahai Rasulullah, ada salah seorang teman kami yang melakukan dosa besar\", Rasulullah Shallallahu'alaihiwasallam bersabda: \"Hendaklah dia membebaskan seorang budak muslim, niscaya Allah Azzawajalla akan membebaskan anggota tubuhnya dari api neraka dengan perantaraan masing-masing anggota tubuh budak yang dimerdekakannya\""},"808":{"ar":"حَدَّثَنَا أَبُو النَّضْرِ قَالَ حَدَّثَنَا بَقِيَّةُ بْنُ الْوَلِيدِ الْحِمْصِيُّ عَنْ أَبِي سَلَمَةَ الْحِمْصِيِّ قَالَ حَدَّثَنَا عُمَرُ بْنُ رُؤْبَةَ التَّغْلِبِيُّ قَالَ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ عَبْدِ اللَّهِ النَّصْرِيُّ عَنْ وَاثِلَةَ بْنِ الْأَسْقَعِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَرْأَةُ تَحُوزُ ثَلَاثَ مَوَارِيثَ عَتِيقَهَا وَلَقِيطَهَا وَوَلَدَهَا الَّذِي تُلَاعِنُ عَلَيْهِ","id":"Telah menceritakan kepada kami [Abu Nadlr] berkata; telah menceritakan kepada kami [Baqiyah bin Al Walid Al Himshi] dari [Abu Salamah Al Himshi] berkata; telah menceritakan kepada kami ['Umar bin Ru`bah At-Taghlibi] berkata; telah menceritakan kepada kami [Abdul Wahid bin Abdullah An Nashri] dari [Watsilah bin Al Asyqa'] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Wanita itu berhak mendapatkan tiga warisan, warisan orang yang dia bebaskan (yaitu dengan wala' jika dia tidak ada ahli warisnya). Warisan dari orang yang dia temukan dan warisan anaknya yang dia di li'an karena anak tersebut\"."},"809":{"ar":"حَدَّثَنَا أَبُو النَّضْرِ قَالَ حَدَّثَنَا أَبُو جَعْفَرٍ يَعْنِي الرَّازِيَّ عَنْ يَزِيْدَ بْنِ أَبِي مَالِكٍ قَالَ حَدَّثَنَا أَبُو سِبَاعٍ قَالَاشْتَرَيْتُ نَاقَةً مِنْ دَارِ وَاثِلَةَ بْنِ الْأَسْقَعِ فَلَمَّا خَرَجْتُ بِهَا أَدْرَكَنَا وَاثِلَةُ وَهُوَ يَجُرُّ رِدَاءَهُ فَقَالَ يَا عَبَد اللَّهِ اشْتَرَيْتَ قُلْتُ نَعَمْ قَالَ هَلْ بَيَّنَ لَكَ مَا فِيهَا قُلْتُ وَمَا فِيهَا قَالَ إِنَّهَا لَسَمِينَةٌ ظَاهِرَةُ الصِّحَّةِ قَالَ فَقَالَ أَرَدْتَ بِهَا سَفَرًا أَمْ أَرَدْتَ بِهَا لَحْمًا قُلْتُ بَلْ أَرَدْتُ عَلَيْهَا الْحَجَّ قَالَ فَإِنَّ بِخُفِّهَا نَقْبًا قَالَ فَقَالَ صَاحِبُهَا أَصْلَحَكَ اللَّهُ أَيْ هَذَا تُفْسِدُ عَلَيَّ قَالَ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَحِلُّ لِأَحَدٍ يَبِيعُ شَيْئًا إِلَّا يُبَيِّنُ مَا فِيهِ وَلَا يَحِلُّ لِمَنْ يَعْلَمُ ذَلِكَ إِلَّا يُبَيِّنُهُ","id":"Telah menceritakan kepada kami [Abu Nadlr] berkata; telah menceritakan kepada kami [Abu Ja'far] yaitu Ar-Razi dari [Yazid bin Abu Malik] berkata; telah menceritakan kepada kami [Abu Siba'] berkata; saya membeli unta dari perkampungan [Watsilah bin Al Asyqa'], ketika kami keluar dari perkampungan itu, kami mengetahui Watsilah sedang membentangkan selendangnya, lalu dia berkata; \"Wahai hamba Allah, engkau membeli unta itu?\" Abu Siba' menjawab, \"Ya\". Watsilah bertanya, \"Apakah pemilik unta menjelaskan kepadamu segala hal ihwal unta itu?\" saya bertanya, \"Memangnya kenapa\"? Pemilik unta menjawab, \"Unta tersebut gemuk dan kelihatan sehat\". Watsilah bertanya kepadaku, \"Unta tersebut memangnya hendak kau pergunakan untuk apa, digunakan untuk perjalanan atau diambil dagingnya\"? Saya (Abu Siba') menjawab, \"Bukan, tapi saya gunakan untuk keperluan haji\" Watsilah berkata; \"Maaf ya, kaki unta itu berlubang, \" pemilik unta tersebut berkata; \"Kiranya Allah membereskanmu -Maksud pemilik unta, ucapan Watsilah menjadikan jual belinya gagAl -\", (Watsilah bin Al Asyqa') berkata; Maaf saja, saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidak halal bagi seseorang untuk menjual sesuatu kecuali dia menjelaskan segala hal ihwal (cacat) barangnya, dan tidak halal bagi seseorang yang mengetahui hal tersebut kecuali harus menjelaskannya.\""},"810":{"ar":"قَالَ حَدَّثَنَا أَبُو النَّضْرِ قَالَ حَدَّثَنَا شَيْبَانُ عَنْ لَيْثٍ عَنْ أَبِي بُرْدَةَ بْنِ أَبِي مُوسَى عَنْ أَبِي مَلِيحِ بْنِ أُسَامَةَ عَنْ وَاثِلَةَ بْنِ الْأَسْقَعِ قَالَشَهِدْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ يَوْمٍ وَأَتَاهُ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي أَصَبْتُ حَدًّا مِنْ حُدُودِ اللَّهِ عَزَّ وَجَلَّ فَأَقِمْ فِيَّ حَدَّ اللَّهِ فَأَعْرَضَ ثُمَّ أَتَاهُ الثَّانِيَةَ فَأَعْرَضَ عَنْهُ ثُمَّ قَالَهَا الثَّالِثَةَ فَأَعْرَضَ عَنْهُ ثُمَّ أُقِيمَتْ الصَّلَاةُ فَلَمَّا قَضَى الصَّلَاةَ أَتَاهُ الرَّابِعَةَ فَقَالَ إِنِّي أَصَبْتُ حَدًّا مِنْ حُدُودِ اللَّهِ عَزَّ وَجَلَّ فَأَقِمْ فِيَّ حَدَّ اللَّهِ عَزَّ وَجَلَّ قَالَ فَدَعَاهُ فَقَالَ أَلَمْ تُحْسِنْ الطُّهُورَ أَوْ الْوُضُوءَ ثُمَّ شَهِدْتَ الصَّلَاةَ مَعَنَا آنِفًا قَالَ بَلَى قَالَ اذْهَبْ فَهِيَ كَفَّارَتُكَ","id":"(Ahmad bin Hanbal radliyallhu'anhu) berkata; telah menceritakan kepada kami [Abu Nadlr] berkata; telah menceritakan kepada kami [Syaiban] dari [Laits] dari [Abu Burdah bin Abu Musa] dari [Abu Malih bin Usamah] dari [Watsilah bin Al Asyqa'] berkata; Suatu hari aku menyaksikan Rasulullah Shallallahu'alaihiwasallam didatangi seorang laki-laki berkata; \"Wahai Rasulullah Shallallahu'alaihiwasallam, saya telah melanggar salah satu hukum Allah Azzawajalla, maka tegakkanlah kepadaku hukuman atas hal tersebut\". (Rasulullah Shallallahu'alaihiwasallam) berpaling, lalu (pemuda itu) datang untuk kedua kalinya, beliau berpaling darinya, lalu mengatakan yang ketiga kalinya namun beliau tetap menolaknya kembali. Kemudian didirikanlah shalat, setelah shalat ditunaikan, pemuda tersebut kembali datang keempat kalinya, dia berkata; saya telah melanggar hukum Allah Azzawajalla, maka lakukanlah hukuman terhadap diriku\". Beliau memanggilnya dan bersabda: \"Bukankah kamu telah menyempurnakan wudlu, dan kamu ikut shalat bersama kami?\" (pemuda tersebut) berkata; \"Ya\". (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Pergilah, apa yang telah kamu kerjakan tadi menjadi penebus dari kesalahanmu\"."},"811":{"ar":"قَالَ حَدَّثَنَا الْوَلِيدُ بْنِ مُسْلِمٍ قَالَ حَدَّثَنِي الْوَلِيدُ بْنُ سُلَيْمَانَ يَعْنِي ابْنَ أَبِي السَّائِبِ قَالَ حَدَّثَنِي حَيَّانُ أَبُو النَّضْرِ قَالَدَخَلْتُ مَعَ وَاثِلَةَ بْنِ الْأَسْقَعِ عَلَى أَبِي الْأَسْوَدِ الْجُرَشِيِّ فِي مَرَضِهِ الَّذِي مَاتَ فِيهِ فَسَلَّمَ عَلَيْهِ وَجَلَسَ قَالَ فَأَخَذَ أَبُو الْأَسْوَدِ يَمِينَ وَاثِلَةَ فَمَسَحَ بِهَا عَلَى عَيْنَيْهِ وَوَجْهِهِ لِبَيْعَتِهِ بِهَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ وَاثِلَةُ وَاحِدَةٌ أَسْأَلُكَ عَنْهَا قَالَ وَمَا هِيَ قَالَ كَيْفَ ظَنُّكَ بِرَبِّكَ قَالَ فَقَالَ أَبُو الْأَسْوَدِ وَأَشَارَ بِرَأْسِهِ أَيْ حَسَنٌ قَالَ وَاثِلَةُ أَبْشِرْ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ قَالَ اللَّهُ عَزَّ وَجَلَّ أَنَا عِنْدَ ظَنِّ عَبْدِي بِي فَلْيَظُنَّ بِي مَا شَاءَ قَالَحَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ قَالَ حَدَّثَنِي سَعِيدُ بْنُ عَبْدِ الْعَزِيزِ وَهِشَامُ بْنُ الْغَازِ أَنَّهُمَا سَمِعَاهُ مِنْ حَيَّانَ أَبِي النَّضْرِ ي��حَدِّثُ بِهِ وَلَا يَأْتِيَانِ عَلَى حِفْظِ الْوَلِيدِ بْنِ سُلَيْمَانَ","id":"(Ahmad bin Hanbal radliyallhu'anhu) berkata; telah menceritakan kepada kami [Al Walid bin Muslim] berkata; telah menceritakan kepadaku [Al Walid bin Sulaiman] yaitu Ibnu Abu Sa`ib, berkata; telah menceritakan kepadaku [Hayyan Abu Nadlar] berkata; saya bersama [Watsilah bin Al Asyqa'] mengunjungi Abu Aswad Al Jurasy ketika sakit yang menyebabkan kematiannya, (Watsilah bin Al Asyqa') memberi salam untuknya dan duduk. Abul Aswad menggandeng tangan kanan Watsilah dan mengusapkanya pada kedua mata dan wajahnya untuk berbaiat Rasulullah Shallallahu'alaihiwasallam. Watsilah berkata padanya, \"Ada satu hal yang ingin saya tanyakan\" Dia berkata; \"Apakah itu?\" (Watsilah bin Al Asyqa') berkata; \"Apa prasangkamu terhadap Rab-mu\"? Maka Abu Al Aswad memberi isyarat dengan kepalanya yang artinya prasangkanya baik, Watsilah berkata; bergembiralah, saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Allah berfirman: 'Aku pada prasangka hamba-Ku terhadap-Ku, maka terserah dia untuk berprasangka terhadap-Ku'\". (Ahmad bin Hanbal radliyallhu'anhu) berkata; telah menceritakan kepada kami [Al Walid bin Muslim] berkata; telah menceritakan kepada kami [Said bin Abdul Aziz] dan [Hisyam bin Ghaz] mereka berdua mendengar dari [Hayyan, Abu Nadzar] menceritakannya, dan mereka berdua tidak mendatangi hafalan Al Walid bin Sulaiman"},"812":{"ar":"قَالَ حَدَّثَنَا عَلِيُّ بْنُ بَحْرٍ قَالَ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ قَالَ حَدَّثَنَا مَرْوَانُ بْنُ جَنَاحٍ عَنْ يُونُسَ بْنِ مَيْسَرَةَ بْنِ حَلْبَسٍ عَنْ وَاثِلَةَ بْنِ الْأَسْقَعِ أَنَّهُسَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَلَا إِنَّ فُلَانَ بْنَ فُلَانٍ فِي ذِمَّتِكَ وَحَبْلِ جِوَارِكَ فَقِهِ فِتْنَةَ الْقَبْرِ وَعَذَابَ النَّارِ أَنْتَ أَهْلُ الْوَفَاءِ وَالْحَقِّ اللَّهُمَّ فَاغْفِرْ لَهُ وَارْحَمْهُ فَإِنَّكَ أَنْتَ الْغَفُورُ الرَّحِيمُ","id":"(Ahmad bin Hanbal radliyallhu'anhu) berkata; telah menceritakan kepada kami ['Ali bin Bahr] berkata; telah menceritakan kepada kami [Al Walid bin Muslim] berkata; telah menceritakan kepada kami [Marwan bin Jannah] dari [Yunus bin Maisarah bin Halbas] dari [Watsilah bin Al Asyqa'] mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Bukankah fulan bin fulan berada dalam tanggunganmu dan berada dalam tali kekerabatanmu. Jagalah dia dari fitnah kubur dan siksa neraka. Kamu adalah orang yang selalu menepati janji dan kebenaran. Ya Allah, ampunilah dosanya dan kasihanilah ia Engkau adalah Maha pengampun dan Maha Penyayang\"."},"813":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا مُصْعَبُ بْنُ عَبْدِ اللَّهِ الزُّبَيْرِيُّ قَالَ حَدَّثَنِي عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدِ بْنِ أَبِي عُبَيْدٍ عَنِ ابْنِ أَبِي ذِئْبٍ عَنْ سَعِيدِ بْنِ خَالِدٍ الْقَارِظِيِّ عَنْ رَبِيعَةَ بْنِ عَبَّادٍ الدِّيلِيِّ أَنَّهُ قَالَرَأَيْتُ أَبَا لَهَبٍ بِعُكَاظٍ وَهُوَ يَتْبَعُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَقُولُ يَا أَيُّهَا النَّاسُ إِنَّ هَذَا قَدْ غَوَى فَلَا يُغْوِيَنَّكُمْ عَنْ آلِهَةِ آبَائِكُمْ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفِرُّ مِنْهُ وَهُوَ عَلَى أَثَرِهِ وَنَحْنُ نَتْبَعُهُ وَنَحْنُ غِلْمَانُ كَأَنِّي أَنْظُرُ إِلَيْهِ أَحْوَلَ ذَا غَدِيرَتَيْنِ أَبْيَضَ النَّاسِ وَأَجْمَلَهُمْ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Mush'ab bin Abdullah Az Zubairi] berkata; telah menceritakan kepadaku [Abdul Aziz bin Muhammad bin Abu 'Ubaid] dari [Ibnu Abu dzi`b] dari [Sa'id bin Khalid Al Qarizhi] dari [Rabi'ah bin 'Abbad Ad-Dili] dia melihat Abu Lahab di pasar 'Ukazh mengikuti Rasulullah Shallallahu'alaihiwasallam dengan berseru, \"Wahai manusia, orang ini telah sesat. Janganlah kalian tersesat olehnya sehingga meninggalkan tuhAn tuhan bapak kalian\" Rasulullah Shallallahu'alaihiwasallam pun menjauh darinya, namun Abu Lahab tetap mengikutinya. Kami pada waktu itu masih anak-anak membuntuti (Abu lahab) yang aku melihatnya seakAn akan aku melihat orang yang juling, yang rambutnya di kepang dua, kulitnya sangat putih dan sangat tampan di antara mereka\"."},"814":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ بُنْدَارٌ قَالَ حَدَّثَنَا عَبْدُ الْوَهَّابِ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ رَبِيعَةَ بْنِ عَبَّادٍ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِذِي الْمَجَازِ يَدْعُو النَّاسَ وَخَلْفَهُ رَجُلٌ أَحْوَلُ يَقُولُ لَا يَصُدَّنَّكُمْ هَذَا عَنْ دِينِ آلِهَتِكُمْ قُلْتُ مَنْ هَذَا قَالُوا هَذَا عَمُّهُ أَبُو لَهَبٍ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Muhammad bin Basyar, bundar] berkata; telah menceritakan kepada kami [Abdul Wahab] berkata; telah menceritakan kepada kami [Muhammad bin 'Amr] dari [Muhammad Al Munkadir] dari [Rabi'ah bin 'Abbad] berkata; saya melihat Nabi Shallallahu'alaihiwasallam di Dzil Majaz, menyeru orang-orang masuk Islam dan di belakangnya seorang laki-laki juling dan berkata; jangan sesekali laki-laki ini menghalangi kalian dari agama nenek moyang kalian\". Saya (Rabi'ah bin 'Abbad) bertanya, siapakah ini?, mereka menjawab, pamannya Abu Lahab."},"815":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي سُرَيْجُ بْنُ يُونُسَ قَالَ حَدَّثَنَا عَبَّادُ بْنُ عَبَّادٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ رَبِيعَةَ بْنِ عَبَّادٍ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَدْعُو النَّاسَ إِلَى الْإِسْلَامِ بِذِي الْمَجَازِ وَخَلْفَهُ رَجُلٌ أَحْوَلُ يَقُولُ لَا يَغْلِبَنَّكُمْ هَذَا عَنْ دِينِكُمْ وَدِينِ آبَائِكُمْ قُلْتُ لِأَبِي وَأَنَا غُلَامٌ مَنْ هَذَا الْأَحْوَلُ الَّذِي يَمْشِي خَلْفَهُ قَالَ هَذَا عَمُّهُ أَبُو لَهَبٍقَالَ عَبَّادٌ أَظُنُّ بَيْنَ مُحَمَّدِ بْنِ عَمْرٍو وَبَيْنَ رَبِيعَةَ مُحَمَّدَ بْنَ الْمُنْكَدِرِ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku [Suraij bin Yunus] berkata; telah menceritakan kepada kami ['Abbad bin 'Abbad] dari [Muhammad bin 'Amr] dari [Rabi'ah bin 'Abbad] berkata; saya melihat Rasulullah Shallallahu'alaihiwasallam menyeru manusia kepada Islam di Dzil Majaz dan di belakangnya ada seorang yang juling yang berkata 'Jangan sesekali orang ini mengalahkan kalian dari agama kalian dan agama nenek moyang kalian.' Saya bertanya kepada bapakku, waktu itu saya ada seorang pemuda, siapakah orang juling yang mengikuti di belakangnya?. Dia menjawab, orang itu adalah pamannya, Abu Lahab. 'Abbad berkata; sepengetahuanku antara Muhammad bin 'Amr dan Rabi'ah bin 'Abbad ada [Muhammad bin Munkadir]."},"816":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي أَبُو سُلَيْمَانَ الضَّبِّيُّ دَاوُدُ بْنُ عَمْرِو بْنِ زُهَيْرٍ الْمُسَيِّبِيُّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي الزِّنَادِ عَنْ أَبِيهِ عَنْ رَبِيعَةَ بْنِ عَبَّادٍ الدِّيلِيِّ وَكَانَ جَاهِلِيًّا أَسْلَمَ فَقَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَصَرَ عَيْنِي بِسُوقِ ذِي الْمَجَازِ يَقُولُ يَا أَيُّهَا النَّاسُ قُولُوا لَا إِلَهَ إِلَّا اللَّهُ تُفْلِحُوا وَيَدْخُلُ فِي فِجَاجِهَا وَالنَّاسُ مُتَقَصِّفُونَ عَلَيْهِ فَمَا رَأَيْتُ أَحَدًا يَقُولُ شَيْئًا وَهُوَ لَا يَسْكُتُ يَقُولُ أَيُّهَا النَّاسُ قُولُوا لَا إِلَهَ إِلَّا اللَّهُ تُفْلِحُوا إِلَّا أَنَّ وَرَاءَهُ رَجُلًا أَحْوَلَ وَضِيءَ الْوَجْهِ ذَا غَدِيرَتَيْنِ يَقُولُ إِنَّهُ صَابِئٌ كَاذِبٌ فَقُلْتُ مَنْ هَذَا قَالُوا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ وَهُوَ يَذْكُرُ النُّبُوَّةَ قُلْتُ مَنْ هَذَا الَّذِي يُكَذِّبُهُ قَالُوا عَمُّهُ أَبُو لَهَبٍقُلْتُ إِنَّكَ كُنْتَ يَوْمَئِذٍ صَغِيرًا قَالَ لَا وَاللَّهِ إِنِّي يَوْمَئِذٍ لَأَعْقِلُ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku [Abu Sulaiman Adl-Dlabbi, Daud bin 'Amr bin Zuhair Al Musayyibi], berkata; telah menceritakan kepada kami [Abdurrahman bin Abu Az Zinad] dari [Bapaknya] dari [Rabi'ah bin 'Abbad Ad-Dili] dia awalnya jahiliyyah, lantas masuk Islam. Dia berkata; saya melihat Rasulullah Shallallahu'alaihiwasallam dengan mataku sendiri, di pasar Dzil Majaz berseru 'Wahai manusia. katakanlah \"Tidak ada tuhan selain Allah, niscaya kalian akan beruntung\" beliau memasuki lorong-lorong pasar itu. Orang-orang berhiruk pikuk kepadanya dan saya tidak melihat seorangpun yang berbicara. Sedang beliau tidak diam. Beliau menyerukan 'Katakanlah \"Tidak ada tuhan selain Allah\", niscaya kalian akan beruntung.' Sedang di belakangnya ada seorang yang juling, wajahnya berseri-seri, memiliki dua kepang rambut yang dipintal seraya berkata 'Ini adalah orang murtad dan pendusta.' Saya bertanya siapakah orang itu? Mereka menjawab, itu adalah pamannya, Abu Lahab. Saya berkata; kamu waktu itu adalah masih kecil. Dia berkata; tidak demi Allah, saya waktu itu sudah berakal."},"817":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا سَعِيدُ بْنُ أَبِي الرَّبِيعِ السَّمَّانُ قَالَ حَدَّثَنِي سَعِيدُ بْنُ سَلَمَةَ يَعْنِي ابْنَ أَبِي الْحُسَامِ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ الْمُنْكَدِرِ أَنَّهُ سَمِعَ رَبِيعَةَ بْنَ عَبَّادٍ الدِّيلِيَّ يَقُولُرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَطُوفُ عَلَى النَّاسِ بمِنًى فِي مَنَازِلِهِمْ قَبْلَ أَنْ يُهَاجِرَ إِلَى الْمَدِينَةِ يَقُولُ يَا أَيُّهَا النَّاسُ إِنَّ اللَّهَ عَزَّ وَجَلَّ يَأْمُرُكُمْ أَنْ تَعْبُدُوهُ وَلَا تُشْرِكُوا بِهِ شَيْئًا قَالَ وَوَرَاءَهُ رَجُلٌ يَقُولُ هَذَا يَأْمُرُكُمْ أَنْ تَدَعُوا دِينَ آبَائِكُمْ فَسَأَلْتُ مَنْ هَذَا الرَّجُلُ فَقِيلَ هَذَا أَبُو لَهَبٍ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Sa'id bin Abu Ar-Rabi' As-Saman] berkata; telah menceritakan kepadaku [Sa'id bin Salamah] yaitu Ibnu Abu Al Husam, berkata; telah menceritakan kepada kami [Muhammad bin Munkadir] mendengar [Rabi'ah bin 'Abbad Ad-Dili] berkata; saya melihat Rasulullah Shallallahu'alaihiwasallam berkeliling kepada manusia di Mina di tempat tinggal mereka sebelum hijrah ke Madinah. Beliau menyerukan, 'Wahai manusia, Allah Azzawajalla memerintahkan kalian agar kalian menyembah-Nya dan janganlah kalian menyekutukAn Nya dengan sesuatupun. Sedang di belakangnya seorang laki-laki yang berkata 'Orang ini memerintahkan kalian untuk meninggalkan agama bapak-bapak kalian', saya bertanya 'Siapakah orang ini?. Ada yang menjawab, ini adalah Abu Lahab."},"818":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا مَسْرُوقُ بْنُ الْمَرْزُبَانِ الْكُوفِيُّ حَدَّثَنَا ابْنُ أَبِي زَائِدَةَ قَالَ قَالَ ابْنُ إِسْحَاقَ فَحَدَّثَنِي حُسَيْنُ بْنُ عَبْدِ اللَّهِ بْنِ عُبَيْدِ اللَّهِ بْنِ الْعَبَّاسِ قَالَ سَمِعْتُ رَبِيعَةَ بْنَ عَبَّادٍ الدِّيلِيَّ قَالَإِنِّي لَمَعَ أَبِي رَجُلٌ شَابٌّ أَنْظُرُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتْبَعُ الْقَبَائِلَ وَوَرَاءَهُ رَجُلٌ أَحْوَلُ وَضِيءٌ ذُو جُمَّةٍ يَقِفُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْقَبِيلَةِ وَيَقُولُ يَا بَنِي فُلَانٍ إِنِّي رَسُولُ اللَّهِ إِلَيْكُمْ آمُرُكُمْ أَنْ تَعْبُدُوا اللَّهَ وَلَا تُشْرِكُوا بِهِ شَيْئًا وَأَنْ تُصَدِّقُونِي حَتَّى أُنْفِذَ عَنْ اللَّهِ مَا بَعَثَنِي بِهِ فَإِذَا فَرَغَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ مَقَالَتِهِ قَالَ الْآخَرُ مِنْ خَلْفِهِ يَا بَنِي فُلَانٍ إِنَّ هَذَا يُرِيدُ مِنْكُمْ أَنْ تَسْلُخُوا اللَّاتَ وَالْعُزَّى وَحُلَفَاءَكُمْ مِنْ الْحَيِّ بَنِي مَالِكِ بْنِ أُقَيْشٍ إِلَى مَا جَاءَ بِهِ مِنْ الْبِدْعَةِ وَالضَّلَالَةِ فَلَا تَسْمَعُوا لَهُ وَلَا تَتَّبِعُوهُ فَقُلْتُ لِأَبِي مَنْ هَذَا قَالَ عَمُّهُ أَبُو لَهَبٍ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Masruq bin Al Marzuban Al Kufi] telah menceritakan kepada kami [Ibnu Abu Za`idah], berkata; [Ibnu Ishaq] berkata; lalu menceritakan kepadaku [Husain bin Abdullah bin 'Ubaidullah bin Al Abbas] berkata; saya mendengar [Rabi'ah bin 'Abbad Ad-Dili] berkata; aku yang ketika itu masih muda belia, saya melihat Rasulullah Shallallahu'alaihiwasallam membuntuti kabilah- kabilah sedang di belakangnya ada seorang juling, wajahnya cerah dan terjuntai rambutnya, Rasulullah Shallallahu'alaihiwasallam berdiri pada setiap kabilah dan menyerukan 'Wahai Bani Fulan, saya Rasulullah, saya perintahkan kalian agar kalian menyembah Allah dan janganlah menyekutukAn nya dengan sesuatupun dan agar kalian membenarkanku sampai saya bisa melaksanakan apa yag telah Allah bebankan kepadaku.' Jika Rasulullah Shallallahu'alaihiwasallam selesai melafadzkan perkataan itu, orang yang di belakangnya berkata 'Wahai Bani Fulan, orang ini menghendaki kalian meninggalkan Latta dan Uzza dan sekutu-sekutu kalian dari perkampungan Bani Malik bin Uqais untuk mengikuti ajaran yang dibawanya berupa hal yang baru dan kesesatan. Janganlah kalian mendengarnya, janganlah kalian mengikutinya. Saya berkata kepada bapakku siapakah orang ini?. Dia menjawab, itu justru pamannya sendiri, Abu lahab."},"819":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي مُحَمَّدُ بْنُ بَكَّارٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ ذَكْوَانَ عَنْ أَبِيهِ أَبِي الزِّنَادِ قَالَرَأَيْتُ رَجُلًا يُقَالُ لَهُ رَبِيعَةُ بْنُ عَبَّادٍ الدِّيلِيُّ قَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَمُرُّ فِي فِجَاجِ ذِي الْمَجَازِ إِلَّا أَنَّهُمْ يَتْبَعُونَهُ وَقَالُوا هَذَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الْمُطَّلِبِ قَالَ وَرَجُلٌ أَحْوَلُ وَضِيءُ الْوَجْهِ ذُو غَدِيرَتَيْنِ يَتْبَعُهُ فِي فِجَاجِ ذِي الْمَجَازِ وَيَقُولُ إِنَّهُ صَابِئٌ كَاذِبٌ فَقُلْتُ مَنْ هَذَا قَالُوا هَذَا عَمُّهُ أَبُو لَهَبٍ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku [Muhammad bin Bakr] berkata; telah menceritakan kepada kami [Abdurrahman bin Abdullah bin Dzakwan] dari [Bapaknya, Abu Az Zinad] berkata; saya melihat seorang laki-laki yang bernama [Rabi'ah bin 'Abbad Ad-Dili] berkata; saya melihat Rasulullah Shallallahu'alaihiwasallam melewati lorong-lorong pasar Dzul Majaz, mereka mengikutinya dan berkata; ini adalah Muhammad bin Abdullah bin Abdul Muthalib. (Rabi'ah bin 'Abbad) berkata; dan ada laki-laki juling yang wajahnya cerah memiliki dua kepang rambut membuntutinya di lorong-lorong Dzil Majaz dan berkata 'Dia adalah orang murtad lagi pendusta.' Saya bertanya 'Siapakah orang itu?. Mereka menjawab, itu adalah pamannya, Abu Lahab."},"820":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ يَحْيَى بْنِ سَعِيدٍ الْقُرَشِيُّ قَالَ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ قَالَ حَدَّثَنِي حُسَيْنُ بْنُ عَبْدِ اللَّهِ عَنْ رَبِيعَةَ بْنِ عَبَّادٍ الدُؤَلِيِّ وَعَمَّنْ حَدَّثَهُ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ رَبِيعَةَ بْنِ عَبَّادٍ قَالَوَاللَّهِ إِنِّي لَأَذْكُرُهُ يَطُوفُ عَلَى الْمَنَازِلِ بِمِنًى وَأَنَا مَعَ أَبِي غُلَامٌ شَابٌّ وَوَرَاءَهُ رَجُلٌ حَسَنُ الْوَجْهِ أَحْوَلُ ذُو غَدِيرَتَيْنِ فَلَمَّا وَقَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى قَوْمٍ قَالَ أَنَا رَسُولُ اللَّهِ يَأْمُرُكُمْ أَنْ تَعْبُدُوهُ وَلَا تُشْرِكُوا بِهِ شَيْئًا وَيَقُولُ الَّذِي خَلْفَهُ إِنَّ هَذَا يَدْعُوكُمْ إِلَى أَنْ تُفَارِقُوا دِينَ آبَائِكُمْ وَأَنْ تَسْلُخُوا اللَّاتَ وَالْعُزَّى وَحُلَفَاءَكُمْ مِنْ بَنِي مَالِكِ بْنِ أُقَيْشٍ إِلَى مَا جَاءَ بِهِ مِنْ الْبِدْعَةِ وَالضَّلَالِ قَالَ فَقُلْتُ لِأَبِي مَنْ هَذَا قَالَ هَذَا عَمُّهُ أَبُو لَهَبٍ عَبْدُ الْعُزَّى بْنُ عَبْدِ الْمُطَّلِبِ","id":"Telah menceritakan kepada kami [Sa'id bin Yahya bin Sa'id Al Qurasyi] berkata; telah menceritakan kepada kami [bapakku] dari [Ibnu Ishaq] berkata; telah menceritakan kepadaku [Husain bin Abdullah] dari [Rabi'ah bin 'Abbad Ad-Dili] dari [orang yang telah menceritakannya] dari [Zaid bin Aslam] dari [Rabi'ah bin 'Abbad] berkata; demi Allah saya akan menceritakannya, dia (Muhammad) berkeliling ke rumah-rumah di Mina, ketika itu saya masih muda bersama bapakku, sedang di belakangnya ada seorang yang wajahnya cerah, juling, memiliki dua kepang. Tatkala Rasulullah Shallallahu'alaihiwasallam berhenti pada suatu kaum, beliau bersabda: \"Saya adalah utusan Allah, saya perintahkan kalian untuk menyembah-Nya dan jangan kalian menyekutukAn Nya dengan sesuatupun. Anehnya, orang yang di belakangnya berkata; orang ini menyeru kalian agar meninggalkan agama bapak kalian dan kalian meninggalkan Lata dan 'Uzza dan para pemimpin kalian dari perkampungan Bani Malik bin Uqais kepada ajaran yang dibawanya berupa hal baru dan kesesatan. Saya berkata kepada bapakku, siapakah orang ini?. Dia menjawab, pamannya Abu lahab, Abdul Al 'Uzza bin Abdul Muthallib."},"821":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا الْحَجَّاجُ بْنُ أَرْطَاةَ عَنْ مُحَمَّدِ بْنِ سُلَيْمَانَ بْنِ أَبِي حَثْمَةَ عَنْ سَهْلِ بْنِ أَبِي حَثْمَةَ قَالَرَأَيْتُ مُحَمَّدَ بْنَ مَسْلَمَةَ يُطَارِدُ امْرَأَةً بِبَصَرِهِ فَقُلْتُ تَنْظُرُ إِلَيْهَا وَأَنْتَ مِنْ أَصْحَابِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا أَلْقَى اللَّهُ عَزَّ وَجَلَّ فِي قَلْبِ امْرِئٍ خِطْبَةً لِامْرَأَةٍ فَلَا بَأْسَ أَنْ يَنْظُرَ إِلَيْهَا","id":"Telah menceritakan kepada kami [Yazid bin Harun] berkata; telah mengabarkan kepada kami [Al Hajjaj bin Arthah] dari [Muhammad bin Sulaiman bin Abu Hatsmah] dari [Sahal bin Abu Hatsmah] berkata; saya melihat [Muhammad bin Maslamah] mengintip seorang wanita dengan matanya. Saya bertanya, kamu mengintipnya padahal kamu adalah seorang sahabat Muhammad Shallallahu'alaihiwasallam? lalu dia berkata; 'Saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jika Allah Azzawajalla menjadikan hati seseorang tertarik untuk melamar seorang wanita, tidak masalah ia melihatnya.\""},"822":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ أَبِي بُرْدَةَ قَالَمَرَرْتُ بِالرَّبَذَةِ فَإِذَا فُسْطَاطٌ فَقُلْتُ لِمَنْ هَذَا فَقِيلَ لِمُحَمَّدِ بْنِ مَسْلَمَةَ فَاسْتَأْذَنْتُ عَلَيْهِ فَدَخَلْتُ عَلَيْهِ فَقُلْتُ رَحِمَكَ اللَّهُ إِنَّكَ مِنْ هَذَا الْأَمْرِ بِمَكَانٍ فَلَوْ خَرَجْتَ إِلَى النَّاسِ فَأَمَرْتَ وَنَهَيْتَ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّهُ سَتَكُونُ فِتْنَةٌ وَفُرْقَةٌ وَاخْتِلَافٌ فَإِذَا كَانَ ذَلِكَ فَأْتِ بِسَيْفِكَ أُحُدًا فَاضْرِبْ بِهِ عُرْضَهُ وَاكْسِرْ نَبْلَكَ وَاقْطَعْ وَتَرَكَ وَاجْلِسْ فِي بَيْتِكَ فَقَدْ كَانَ ذَلِكَ وَقَالَ يَزِيدُ مَرَّةً فَاضْرِبْ بِهِ حَتَّى تَقْطَعَهُ ثُمَّ اجْلِسْ فِي بَيْتِكَ حَتَّى تَأْتِيَكَ يَدٌ خَاطِئَةٌ أَوْ يُعَافِيَكَ اللَّهُ عَزَّ وَجَلَّ فَقَدْ كَانَ مَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفَعَلْتُ مَا أَمَرَنِي بِهِ ثُمَّ اسْتَنْزَلَ سَيْفًا كَانَ مُعَلَّقًا بِعَمُودِ الْفُسْطَاطِ فَاخْتَرَطَهُ فَإِذَا سَيْفٌ مِنْ خَشَبٍ فَقَالَ قَدْ فَعَلْتُ مَا أَمَرَنِي بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاتَّخَذْتُ هَذَا أُرْهِبُ بِهِ النَّاسَ قَالَحَدَّثَنَا مُؤَمَّلٌ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ أَبِي بُرْدَةَ قَالَ مَرَرْنَا بِالرَّبَذَةِ فَإِذَا فُسْطَاطٌ مَضْرُوبٌ فَذَكَرَهُ قَالَ إِنَّهُ سَتَكُونُ فِتْنَةٌ وَفُرْقَةٌ فَاضْرِبْ بِسَيْفِكَ عُرْضَ أُحُدٍ قَالَ حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا عَلِيُّ بْنُ زَيْدٍ عَنْ أَبِي بُرْدَةَ بْنِ أَبِي مُوسَى قَالَ مَرَرْنَا بِالرَّبَذَةِ فَإِذَا فُسْطَاطٌ فَقُلْتُ لِمَنْ هَذَا فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Yazid bin Harun] berkata; telah mengabarkan kepada kami [Hammad bin Salamah] dari ['Ali bin Zaid] dari [Abu Burdah] berkata; saya melewati Rabadzah, di sana ada kemah, saya bertanya, Kemah ini milik siapa\"? Ada yang berkata; milik [Muhammad bin Maslamah], maka saya pun meminta izin dan masuk kemah itu. Saya berkata; \"Semoga Allah merahmatimu, engkau mempunyai kedudukan dalam permasalahan ini yang apabila engkau keluar bersama manusia, engkau dapat memberi perintah dan melarang sesuatu\". Lalu Muhammad bin Maslamah berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: Sungguh akan terjadi suatu fitnah, perpecahan dan perbedaan, jika hal itu terjadi, datanglah membawa pedangmu ke gunung Uhud dan pukullah gunung itu dengan pedangmu, pecahkanlah panahmu serta potonglah, tinggalkan dan kemudian duduklah kamu di rumah, sampai datanglah tangan yang berdosa atau Allah mengampuni dosamu. Lalu lakukan apa yang beliau perintahkan. Kemudian saya meminta diturunkanya pedang yang tergantung di tiang kemah dan mengeluarkanya dari sarungnya, pedang itu terbuat dari kayu, maka dia berkata: \"Aku telah melaksanakan apa yang Rasulullah Shallallahu'alaihiwasallam perintahkan, maka aku ambil pedang itu untuk menakuti manusia, ternyata itu adalah pedang dari kayu.\" (Ahmad bin Hanbal radliyallhu'anhu) berkata; telah menceritakan kepada kami [Mu'amal] berkata; telah bercerita kepada kami [Hammad] dari ['Ali bin Zaid] dari [Abu Burdah'] dia berkata; Aku melewati Rabadzah, ketika itu ada sebuah kemah besar, maka dia berkata; lalu menyebutkannya, berkata; \"Sungguh akan terjadi fitnah dan perpecahan, maka pukullah gunung Uhud dengan pedangmu\". (Ahmad bin Hanbal radliyallhu'anhu) berkata; telah menceritakan kepada kami ['Affan] berkata; telah menceritakan kepada kami [Hammad bin Salamah] telah mengabarkan kepada kami ['Ali bin Zaid] dari [Abu Burdah bin Musa] dia berkata; Aku melewati tempat Rabazhah, ternyata ada sebuah kemah besar\", maka aku berkata; \"Sebagaimana telah disebutkan dalam hadis\""},"823":{"ar":"حَدَّثَنَا الْقَاسِمُ بْنُ مَالِكٍ الْمُزَنِيُّ أَبُو جَعْفَرٍ قَالَ أَخْبَرَنِي جَمِيلُ بْنُ زَيْدٍ قَالَ صَحِبْتُ شَيْخًا مِنْ الْأَنْصَارِ ذَكَرَ أَنَّهُ كَانَتْ لَهُ صُحْبَةٌ يُقَالُ لَهُ كَعْبُ بْنُ زَيْدٍ أَوْ زَيْدُ بْنُ كَعْبٍ فَحَدَّثَنِيأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَزَوَّجَ امْرَأَةً مِنْ بَنِي غِفَارٍ فَلَمَّا دَخَلَ عَلَيْهَا وَضَعَ ثَوْبَهُ وَقَعَدَ عَلَى الْفِرَاشِ أَبْصَرَ بِكَشْحِهَا بَيَاضًا فَانْحَازَ عَنْ الْفِرَاشِ ثُمَّ قَالَ خُذِي عَلَيْكِ ثِيَابَكِ وَلَمْ يَأْخُذْ مِمَّا أَتَاهَا شَيْئًا","id":"Telah menceritakan kepada kami [Al Qasim bin Malik Al Muzani, Abu Ja'far] berkata; telah mengabarkan kepadaku [Jamil bin Zaid] berkata; saya menemani seorang guru dari Anshar, yang disebutkan bahwa dia adalah salah seorang sahabat yang bernama [Ka'ab bin Zaid] atau Zaid bin Ka'ab, dia menceritakan kepadaku bahwa Rasulullah Shallallahu'alaihiwasallam menikahi seorang perempuan Bani Ghiffar, ketika beliau menemuinya dan meletakkan bajunya serta duduk di atas tempat tidur, beliau melihat bagian badan perempuan tersebut di sekitar pinggul berwarna putih, maka beliau bangkit dari tempat tidur dan berkata; \"Ambillah bajumu\" dan beliau tidak mengambil apapun dari yang telah beliau berikan kepadanya\"."},"824":{"ar":"قَالَ حَدَّثَنَا يَزِيدُ قَالَ أَخْبَرَنَا جَرِيرُ بْنُ حَازِمٍ عَنْ مُحَمَّدِ بْنِ أَبِي يَعْقُوبَ عَنْ عَبْدِ اللَّهِ بْنِ شَدَّادٍ عَنْ أَبِيهِ قَالَخَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي إِحْدَى صَلَاتَيْ الْعَشِيِّ الظُّهْرِ أَوْ الْعَصْرِ وَهُوَ حَامِلٌ الْحَسَنَ أَوْ الْحُسَيْنَ فَتَقَدَّمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَضَعَهُ ثُمَّ كَبَّرَ لِلصَّلَاةِ فَصَلَّى فَسَجَدَ بَيْنَ ظَهْرَانَيْ صَلَاتِهِ سَجْدَةً أَطَالَهَا فَقَالَ إِنِّي رَفَعْتُ رَأْسِي فَإِذَا الصَّبِيُّ عَلَى ظَهْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ سَاجِدٌ فَرَجَعْتُ فِي سُجُودِي فَلَمَّا قَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّلَاةَ قَالَ النَّاسُ يَا رَسُولَ اللَّهِ إِنَّكَ سَجَدْتَ بَيْنَ ظَهْرَانَيْ صَلَاتِكَ هَذِهِ سَجْدَةً قَدْ أَطَلْتَهَا فَظَنَنَّا أَنَّهُ قَدْ حَدَثَ أَمْرٌ أَوْ أَنَّهُ قَدْ يُوحَى إِلَيْكَ قَالَ فَكُلُّ ذَلِكَ لَمْ يَكُنْ وَلَكِنَّ ابْنِي ارْتَحَلَنِي فَكَرِهْتُ أَنْ أُعَجِّلَهُ حَتَّى يَقْضِيَ حَاجَتَهُ","id":"(Ahmad bin Hanbal radliyallhu'anhu) berkata; telah menceritakan kepada kami [Yazid] berkata; telah mengabarkan kepada kami [Jarir bin Hazim] dari [Muhammad bin Abu Ya'qub] dari [Abdulllah bin Syadad] dari [bapaknya] berkata; Rasulullah Shallallahu'alaihiwasallam keluar menemui kami dengan menggendong Hasan atau Husain antara dua waktu shalat, zhuhur dan ashar. Nabi Shallallahu'alaihiwasallam maju ke depan dan meletakkan (Hasan dan Hasan) lalu mulai bertakbir untuk shalat, dan beliau bersujud ketika dalam shalatnya dengan sujud yang begitu lama.(Syadad) berkata; \"Saya mengangkat kepalaku, terlihat anak kecil itu sedang berada di punggung Rasulullah Shallallahu'alaihiwasallam, maka saya kembali lagi untuk bersujud, ketika Rasulullah Shallallahu'alaihiwasallam selesai dari shalatnya, orang-orang berkata; 'Wahai Rasulullah, anda tadi sujud waktu dalam shalat dengan begitu lama, sehingga kami mengira jangAn jangan terjadi suatu hal atau telah diturunkan wahyu kepadamu\". Beliau bersabda: \"Bukan karena itu, tapi ketika aku sujud, anakku (maksudnya cucuku) sedang menaikku, saya tidak mau menyegerakannya sampai cucuku turun dariku\"."},"825":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا الْمُغِيرَةُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي الزِّنَادِ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ حَمْزَةَ الْأَسْلَمِيُّ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّرَهُ عَلَى سَرِيَّةٍ فَخَرَجْتُ فِيهَا فَقَالَ إِنْ أَخَذْتُمْ فُلَانًا فَأَحْرِقُوهُ بِالنَّارِ فَلَمَّا وَلَّيْتُ نَادَانِي فَقَالَ إِنْ أَخَذْتُمُوهُ فَاقْتُلُوهُ فَإِنَّهُ لَا يُعَذِّبُ بِالنَّارِ إِلَّا رَبُّ النَّارِ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur] telah menceritakan kepada kami [Al Mughirah bin Abdurrahman] dari [Abu Zinad] berkata; telah menceritakan kepadaku [Muhammad bin Hamzah Al Aslamy] dari [bapaknya] Rasulullah Shallallahu'alaihiwasallam menjadikannya panglima suatu pasukan. Lalu saya berangkat, maka beliau bersabda: \"Jika kalian menemukan fulan, maka bakarlah dia dengan api\". Ketika saya berangkat, beliau memanggilku lagi seraya bersabda: \"Kalau kalian menemukannya, maka bunuhlah, karena tidak boleh menyiksa dengan api kecuali pencipta api\"."},"826":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي زِيَادٌ يَعْنِي ابْنَ سَعْدٍ أَنَّ أَبَا الزِّنَادِ قَالَ أَخْبَرَنِي حَنْظَلَةُ بْنُ عَلِيٍّ عَنْ حَمْزَةَ بْنِ عَمْرٍو الْأَسْلَمِيِّ صَاحِبِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَهُ وَرَهْطًا مَعَهُ إِلَى رَجُلٍ مِنْ عُذْرَةَ فَقَالَ إِنْ قَدَرْتُمْ عَلَى فُلَانٍ فَأَحْرِقُوهُ بِالنَّارِ فَانْطَلَقُوا حَتَّى إِذَا تَوَارَوْا مِنْهُ نَادَاهُمْ أَوْ أَرْسَلَ فِي أَثَرِهِمْ فَرَدُّوهُمْ ثُمَّ قَالَ إِنْ أَنْتُمْ قَدَرْتُمْ عَلَيْهِ فَاقْتُلُوهُ وَلَا تُحْرِقُوهُ بِالنَّارِ فَإِنَّمَا يُعَذِّبُ بِالنَّارِ رَبُّ النَّارِ قَالَحَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنَا زِيَادٌ أَنَّ أَبَا الزِّنَادِ أَخْبَرَهُ قَالَ أَخْبَرَنِي حَنْظَلَةُ بْنُ عَلَيٍّ الْأَسْلَمِيُّ أَنَّ حَمْزَةَ بْنَ عَمْرٍو الْأَسْلَمِيَّ صَاحِبَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَهُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَهُ وَرَهْطًا مَعَهُ سَرِيَّةً إِلَى رَجُلٍ فَذَكَرَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Muhammad bin Bakr] telah mengabarkan kepada kami [Ibnu Juraij] berkata; telah mengabarkan kepada kami [Ziyad] yaitu Ibnu Saad, [Abu Zinad] berkata; telah menceritakan kepadaku [Hanzhalah bin 'Ali] dari [Hamzah bin 'Amr Al Aslami] seorang sahabat Nabi Shallallahu'alaihiwasallam menceritakannya bahwa Rasulullah Shallallahu'alaihiwasallam mengutusnya bersama beberapa orang seorang laki-laki dari 'Udzrah, lalu beliau bersabda: \"Jika mampu maka bakarlah, bakarlah dia dengan api\". Lalu mereka berangkat, setelah mereka meninggalkan beliau, beliau memanggil mereka lagi, atau mengutus kepada mereka, dan meminta mereka untuk kembali dan bersabda: \"Jika kalian bisa, maka bunuhlah, tapi jangan kalian bakar dengan api. Karena yang berhak menyiksa dengan api adalah pencipta api\" (Ahmad bin Hanbal radliyallhu'anhu) berkata; telah menceritakan kepada kami [Abdurrazzaq] berkata; telah mengabarkan kepada kami [Ibnu Juraij] berkata; telah mengabarkan kepada kami [Ziyad] [Abu Zinad] mengabarinya, berkata; telah mengabarkan kepadaku [Hanzhalah bin 'Ali Al Aslami] [Hamzah bin 'Amr Al Aslami] salah seorang sahabat Nabi Shallallahu'alaihiwasallam menceritakannya bahwa Rasulullah Shallallahu'alaihiwasallam mengutusnya bersama beberapa orang dalam sebuah ekspedisi untuk menangkap seseorang, lalu menyebutkan secara makna."},"827":{"ar":"قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ حَمْزَةَ بْنِ عَمْرٍو الْأَسْلَمِيِّ أَنَّهُسَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الصَّوْمِ فِي السَّفَرِ فَقَالَ إِنْ شِئْتَ صُمْتَ وَإِنْ شِئْتَ أَفْطَرْتَ","id":"(Ahmad bin Hanbal radliyallhu'anhu) berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Sulaiman bin Yasar] dari [Hamzah bin 'Amr Al Aslami] dia bertanya Rasulullah Shallallahu'alaihiwasallam tentang berpuasa pada saat perjalanan, maka (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Terserah kamu untuk berpuasa atau tidak\"."},"828":{"ar":"قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ حَمْزَةَ بْنِ عَمْرٍو الْأَسْلَمِيِّأَنَّهُ رَأَى رَجُلًا عَلَى جَمَلٍ يَتْبَعُ رِحَالَ النَّاسِ بِمِنًى وَنَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَاهِدٌ وَالرَّجُلُ يَقُولُ لَا تَصُومُوا هَذِهِ الْأَيَّامَ فَإِنَّهَا أَيَّامُ أَكْلٍ وَشُرْبٍ قَالَ قَتَادَةُ فَذَكَرَ لَنَا أَنَّ ذَلِكَ الْمُنَادِي كَانَ بِلَالًا","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] berkata; telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Sulaiman bin Yasar] dari [Hamzah bin 'Amr Al Aslami] dia melihat seorang laki-laki di atas unta mengikuti orang yang berjalan sewaktu di Mina dan Nabiyullah Shallallahu'alaihiwasallam menyaksikan, laki-laki tersebut berseru, \"Janganlah kalian berpuasa pada hari-hari ini (Tasyriq) karena hari tersebut adalah hari makan dan minum\". Qatadah berkata; \"(Hamzah bin 'Amr Al Aslami) menyebutkan bahwa laki-laki yang menyerukan tersebut adalah Bilal\"."},"829":{"ar":"قَالَ حَدَّثَنَا عَتَّابٌ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ وَعَلِيُّ بْنُ إِسْحَاقَ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ يَعْنِي ابْنَ الْمُبَارَكِ قَالَ أَخْبَرَنَا أُسَامَةُ بْنُ زَيْدٍ قَالَ أَخْبَرَنِي مُحَمَّدُ بْنُ حَمْزَةَ أَنَّهُ سَمِعَ أَبَاهُ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ عَلَى ظَهْرِ كُلِّ بَعِيرٍ شَيْطَانٌ فَإِذَا رَكِبْتُمُوهَا فَسَمُّوا اللَّهَ عَزَّ وَجَلَّ ثُمَّ لَا تُقَصِّرُوا عَنْ حَاجَاتِكُمْ","id":"Telah menceritakan kepada kami ['Attab] berkata; telah menceritakan kepada kami [Abdullah] dan ['Ali bin Ishaq] berkata; telah mengabarkan kepada kami [Abdullah] yaitu Ibnu Mubarak berkata; telah mengabarkan kepada kami [Usamah bin Zaid] berkata; telah mengabarkan kepadaku [Muhammad bin Hamzah] bahwa dia mendengar [bapaknya] berkata; saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Di atas pundak setiap unta terdapat setan, apabila kalian menaikinya, sebutlah nama Allah Azzawajalla, kemudian janganlah kalian menyepelekan kebutuhan kalian\""},"830":{"ar":"قَالَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ حَدَّثَنَا شَرِيكُ بْنُ عَبْدِ اللَّهِ عَنْ عُثْمَانَ بْنِ عُمَيْرٍ عَنْ زَاذَانَ أَبِي عُمَرَ عَنْ عُلَيْمٍ قَالَكُنَّا جُلُوسًا عَلَى سَطْحٍ مَعَنَا رَجُلٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَزِيدُ لَا أَعْلَمُهُ إِلَّا عَبْسًا الْغِفَارِيَّ وَالنَّاسُ يَخُوضُونَ فِي الطَّاعُونِ فَقَالَ عَبَسٌ يَا طَاعُونُ خُذْنِي ثَلَاثًا يَقُولُهَا فَقَالَ لَهُ عُلَيْمٌ لِمَ تَقُولُ هَذَا أَلَمْ يَقُلْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَتَمَنَّى أَحَدُكُمْ الْمَوْتَ فَإِنَّهُ عِنْدَ انْقِطَاعِ عَمَلِهِ لَا يُرَدُّ فَيُسْتَعْتَبَ فَقَالَ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ بَادِرُوا بِالْمَوْتِ سِتًّا إِمْرَةَ السُّفَهَاءِ وَكَثْرَةَ الشَّرْطِ وَبَيْعَ الْحُكْمِ وَاسْتِخْفَافًا بِالدَّمِ وَقَطِيعَةَ الرَّحِمِ وَنَشْئًا يَتَّخِذُونَ الْقُرْآنَ مَزَامِيرَ يُقَدِّمُونَهُ يُغَنِّيهِمْ وَإِنْ كَانَ أَقَلَّ مِنْهُمْ فِقْهًا","id":"(Ahmad bin Hanbal radliyallhu'anhu) berkata; telah menceritakan kepada kami [Yazid bin Harun] berkata; telah menceritakan kepada kami [Syarik bin Abdullah] dari ['Utsman bin 'Umair] dari [Zadzan Abu 'Umar] dari ['Ulaim] berkata; kami duduk di atas atap beserta seorang laki-laki dari sahabat Nabi Shallallahu'alaihiwasallam. [Yazid] berkata; saya tidak mengetahuinya kecuali ['Abbas] Al Giffary, manusia pada saat itu sedang terkena wabah penyakit thaun. 'Abbas berkata; \"Wahai Penyakit Thaun, ambillah aku\", dia mengulangnya sampai tiga kali. Lalu 'Ulaim berkata kepadanya, \"Mengapa engkau ucapkan perkataan semacam itu! Bukankah Rasulullah Shallallahu'alaihiwasallam bersabda: 'Jangan kalian berangAn angan untuk mati karena ketika itu amal diputus dan tidak dapat dikembalikan', sehingga dia binasa.\" lalu dia berkata; saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Bersegeralah melakukan enam hal sebelum datang kematian: dari pemimpin bodoh, banyaknya ajudan, hokum diperjualbelikan, darah tertumpah dengan mudah, saling memotong tali silaturrahmi, dan keturunan yang menjadikan Al Qur'an bagaikan seruling, mereka dahulukan siapa saja yang bisa menyanyikannya walaupun dia adalah orang yang tidak mengerti persoalan agama\""},"831":{"ar":"حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ قَالَ حَدَّثَنَا مُسْلِمُ بْنُ خَالِدٍ عَنْ عَمْرِو بْنِ يَحْيَى الْمَازِنِيِّ عَنْ أَبِيهِ عَنْ شُقْرَانَ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَرَأَيْتُهُ يَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتَوَجِّهًا إِلَى خَيْبَرَ عَلَى حِمَارٍ يُصَلِّي عَلَيْهِ يُومِئُ إِيمَاءً","id":"Telah menceritakan kepada kami [Asad bin 'Amir] berkata; telah menceritakan kepada kami [Muslim bin Khalid] dari ['Amr bin Yahya Al Muzani] dari [Bapaknya] dari [Syuqran] budak Rasulullah Shallallahu'alaihiwasallam berkata; saya melihat Rasulullah Shallallahu'alaihiwasallam shalat dengan memberi isyarat di atas untanya menuju ke Khaibar\"."},"832":{"ar":"قَالَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا هَمَّامُ بْنُ يَحْيَى عَنِ الْقَاسِمِ بْنِ عَبْدِ الْوَاحِدِ الْمَكِّيِّ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُبَلَغَنِي حَدِيثٌ عَنْ رَجُلٍ سَمِعَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاشْتَرَيْتُ بَعِيرًا ثُمَّ شَدَدْتُ عَلَيْهِ رَحْلِي فَسِرْتُ إِلَيْهِ شَهْرًا حَتَّى قَدِمْتُ عَلَيْهِ الشَّامَ فَإِذَا عَبْدُ اللَّهِ بْنُ أُنَيْسٍ فَقُلْتُ لِلْبَوَّابِ قُلْ لَهُ جَابِرٌ عَلَى الْبَابِ فَقَالَ ابْنُ عَبْدِ اللَّهِ قُلْتُ نَعَمْ فَخَرَجَ يَطَأُ ثَوْبَهُ فَاعْتَنَقَنِي وَاعْتَنَقْتُهُ فَقُلْتُ حَدِيثًا بَلَغَنِي عَنْكَ أَنَّكَ سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْقِصَاصِ فَخَشِيتُ أَنْ تَمُوتَ أَوْ أَمُوتَ قَبْلَ أَنْ أَسْمَعَهُ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يُحْشَرُ النَّاسُ يَوْمَ الْقِيَامَةِ أَوْ قَالَ الْعِبَادُ عُرَاةً غُرْلًا بُهْمًا قَالَ قُلْنَا وَمَا بُهْمًا قَالَ لَيْسَ مَعَهُمْ شَيْءٌ ثُمَّ يُنَادِيهِمْ بِصَوْتٍ يَسْمَعُهُ مِنْ قُرْبٍ أَنَا الْمَلِكُ أَنَا الدَّيَّانُ وَلَا يَنْبَغِي لِأَحَدٍ مِنْ أَهْلِ النَّارِ أَنْ يَدْخُلَ النَّارَ وَلَهُ عِنْدَ أَحَدٍ مِنْ أَهْلِ الْجَنَّةِ حَقٌّ حَتَّى أَقُصَّهُ مِنْهُ وَلَا يَنْبَغِي لِأَحَدٍ مِنْ أَهْلِ الْجَنَّةِ أَنْ يَدْخُلَ الْجَنَّةَ وَلِأَحَدٍ مِنْ أَهْلِ النَّارِ عِنْدَهُ حَقٌّ حَتَّى أَقُصَّهُ مِنْهُ حَتَّى اللَّطْمَةُ قَالَ قُلْنَا كَيْفَ وَإِنَّا إِنَّمَا نَأْتِي اللَّهَ عَزَّ وَجَلَّ عُرَاةً غُرْلًا بُهْمًا قَالَ بِالْحَسَنَاتِ وَالسَّيِّئَاتِ","id":"(Ahmad bin Hanbal radliyallhu'anhu) berkata; telah menceritakan kepada kami [Yazid bin Harun] berkata; telah mengabarkan kepada kami [Hammad bin Yahya] dari [Al Qasim bin Abdul Wahid Al Maki] dari [Abdullah bin Muhammad bin 'Aqil] mendengar [Jabir bin Abdullah] berkata; telah sampai hadis kepadaku dari seorang laki-laki yang mendengar dari Rasulullah Shallallahu'alaihiwasallam, kontan saya membeli unta, kuikat kencang perbekalanku dan kuarahkan perjalananku untuk menemuinya selama satu bulan. Selanjutnya aku menemuinya tepatnya di Syam, tak tahunya orang itu adalah [Abdullah bin Unais]. Saya berkata kepada penjaga pintu, \"Katakan padanya, Jabir sedang menunggunya di di depan pintu\". Lalu dia bertanya, kamu adalah Ibnu Abdullah, saya menjawab, Ya. Lalu dia keluar dengan menginjak pakaiannya, dia memelukku dan sebaliknya aku juga memeluknya, saya berkata; telah sampai kepadaku suatu hadis darimu, kamu mendengar Rasulullah Shallallahu'alaihiwasallam tentang perkara qishas, saya khawatir apabila engkau meninggal ataupun saya meninggal sebelum saya dapat mendengarnya. (Abdullah bin Unais) berkata; saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Manusia akan dikumpulkan pada Hari Kiamat\", --atau bersabda dengan redaksi para hamba--, dalam keadaan telanjang, tidak berkhitan dan dalam keadaan buhman\", lalu kami bertanya, \"Apakah buhman itu?\" Beliau bersabda: \"Tidak memakai pakaian sehelai benangpun\", lalu ada suara yang memanggil mereka dari dekat, 'Aku adalah raja dan Aku Dayyan (pemberi pembalasan) tidaklah patut bagi seorang penduduk neraka untuk masuk neraka sedangkan dia mempunyai hak atas seseorang dari penduduk surga sampai Aku memberikan haknya. Juga tidaklah patut seseorang dari penduduk surga untuk masuk syurga sedangkan seseorang dari penduduk nereka mempunyai hak atas dirinya sampai Aku memberikan haknya. Sampai satu tamparan sekalipun. (Jabir bin Abdullah) berkata; kami bertanya, Bagaimana ini? Kami mendatangi Allah Azzawajalla dalam keadaan telanjang dan tidak berkhitan, dan tidak memakai sehelai benangpun? maka beliau bersabda: \"Kalian datang dengan kebaikan dan keburukan\"."},"833":{"ar":"قَالَ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا لَيْثٌ عَنْ هِشَامِ بْنِ سَعْدٍ عَنْ مُحَمَّدِ بْنِ زَيْدِ بْنِ الْمُهَاجِرِ بْنِ قُنْفُذٍ التَّيْمِيِّ عَنْ أَبِي أُمَامَةَ الْأَنْصَارِيِّ عَنْ عَبْدِ اللَّهِ بْنِ أُنَيْسٍ الْجُهَنِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ أَكْبَرِ الْكَبَائِرِ الشِّرْكَ بِاللَّهِ وَعُقُوقَ الْوَالِدَيْنِ وَالْيَمِينَ الْغَمُوسَ وَمَا حَلَفَ حَالِفٌ بِاللَّهِ يَمِينًا صَبْرًا فَأَدْخَلَ فِيهَا مِثْلَ جَنَاحِ بَعُوضَةٍ إِلَّا جَعَلَهُ اللَّهُ نُكْتَةً فِي قَلْبِهِ إِلَى يَوْمِ الْقِيَامَةِ","id":"(Ahmad bin Hanbal radliyallhu'anhu) berkata; telah menceritakan kepada kami [Yunus bin Muhammad] berkata; telah menceritakan kepada kami [Laits] dari [Hisyam bin Sa'ad] dari [Muhammad bin Zaid bin Al Muhajir bin Qunfudz At-Taimi] dari [Abu Umamah Al Anshari] dari [Abdullah bin Unais Al Juhani] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Yang termasuk dosa-dosa paling besar adalah: Menyekutukan Allah, durhaka kepada orang tua, dan sumpah bohong. Tidaklah bersumpah seseorang dengan nama Allah di hadapan seorang hakim walau hanya untuk perkara sepele yang hanya senilai sayap nyamuk kecuali Allah akan membuat coretan hitam dalam hatinya sampai Hari Kiamat nanti\"."},"834":{"ar":"حَدَّثَنَا أَبُو سَلَمَةَ الْخُزَاعِيُّ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ يَعْنِي الْمَخْرَمِيَّ عَنْ يَزِيدَ بْنِ الْهَادِ عَنْ أَبِي بَكْرِ بْنِ حَزْمٍ عَنْ عَبْدِ اللَّهِ بْنِ أُنَيْسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُمْ وَسَأَلُوهُ عَنْ لَيْلَةٍ يَتَرَاءَوْنَهَا فِي رَمَضَانَ قَالَ لَيْلَةُ ثَلَاثٍ وَعِشْرِينَ","id":"Telah menceritakan kepada kami [Abu Salamah Al Khuza'i] berkata; telah menceritakan kepada kami [Abdullah bin Ja'far] yaitu Al Makhrami, dari [Yazid bin Al Had] dari [Abu Bakar bin Hazm] dari [Abdullah bin Unais] Nabi Shallallahu'alaihiwasallam bersabda kepada mereka. Mereka bertanya kepada beliau tentang malam yang mereka saling melihatnya (malam lailatul qodar, pent) waktu Bulan Ramadlan. Beliau bersabda: \"Malam ke dua puluh tiga\"."},"835":{"ar":"قَالَ حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ أَبُو ضَمْرَةَ قَالَ حَدَّثَنِي الضَّحَّاكُ بْنُ عُثْمَانَ عَنْ أَبِي النَّضْرِ مَوْلَى عُمَرَ بْنِ عُبَيْدِ اللَّهِ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ عَبْدِ اللَّهِ بْنِ أُنَيْسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رَأَيْتُ لَيْلَةَ الْقَدْرِ ثُمَّ أُنْسِيتُهَا وَأُرَانِي صَبِيحَتَهَا أَسْجُدُ فِي مَاءٍ وَطِينٍ فَمُطِرْنَا لَيْلَةَ ثَلَاثٍ وَعِشْرِينَ فَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَانْصَرَفَ وَإِنَّ أَثَرَ الْمَاءِ وَالطِّينِ عَلَى جَبْهَتِهِ وَأَنْفِهِ","id":"(Ahmad bin Hanbal radliyallhu'anhu) berkata; telah menceritakan kepada kami [Anas bin 'Iyadl, Abu Dlamrah] berkata; telah menceritakan kepadaku [Al Dlahaq bin 'Utsman] dari [Abu Nadlr] budak 'Umar bin 'Ubaidullah dari [Busr bin Sa'id] dari [Abdullah bin Unais] Rasulullah Shallallahu'alaihiwasallam bersabda: \"Saya bermimpi malam Lailaitul Qadr lalu saya lupa, saya mengingatnya pada pagi harinya. Saya bersujud pada air dan tanah\". Lalu kami mendapatkan hujan pada malam ke dua puluh tiga. Lalu Rasulullah Shallallahu'alaihiwasallam shalat bersama kami. Dan beliau pergi. Bekas air dan tanah terlihat pada keningnya dan hidungnya."},"836":{"ar":"قَالَ حَدَّثَنَا يَعْقُوبُ قَالَ حَدَّثَنِي أَبِي عَنِ ابْنِ إِسْحَاقَ قَالَ حَدَّثَنِي مُعَاذُ بْنُ عَبْدِ اللَّهِ بْنِ خُبَيْبٍ الْجُهَنِيُّ عَنْ أَخِيهِ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ خُبَيْبٍ قَالَكَانَ رَجُلٌ فِي زَمَانِ عُمَرَ بْنِ الْخَطَّابِ قَدْ سَأَلَهُ فَأَعْطَاهُ قَالَ جَلَسَ مَعَنَا عَبْدُ اللَّهُ بْنُ أُنَيْسٍ صَاحِبُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَجْلِسِهِ فِي مَجْلِسِ جُهَيْنَةَ قَالَ فِي رَمَضَانَ قَالَ فَقُلْنَا لَهُ يَا أَبَا يَحْيَى سَمِعْتَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذِهِ اللَّيْلَةِ الْمُبَارَكَةِ مِنْ شَيْءٍ فَقَالَ نَعَمْ جَلَسْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي آخِرِ هَذَا الشَّهْرِ فَقُلْنَا لَهُ يَا رَسُولَ اللَّهِ مَتَى نَلْتَمِسُ هَذِهِ اللَّيْلَةَ الْمُبَارَكَةَ قَالَ الْتَمِسُوهَا هَذِهِ اللَّيْلَةَ وَقَالَ وَذَلِكَ مَسَاءَ لَيْلَةِ ثَلَاثٍ وَعِشْرِينَ فَقَالَ لَهُ رَجُلٌ مِنْ الْقَوْمِ وَهِيَ إِذًا يَا رَسُولَ اللَّهِ أَوَّلُ ثَمَانٍ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهَا لَيْسَتْ بِأَوَّلِ ثَمَانٍ وَلَكِنَّهَا أَوَّلُ السَّبْعِ إِنَّ الشَّهْرَ لَا يَتِمُّ","id":"(Ahmad bin Hanbal radliyallhu'anhu) berkata; telah menceritakan kepada kami [Ya'qub] berkata; telah menceritakan kepadaku [bapakku] dari [Ibnu Ishaq] berkata; telah menceritakan kepadaku [Mu'adz bin Abdullah bin Hubaib Al Juhani] dari [saudaranya, Abdullah bin Abdullah Khubaib] berkata; ada seorang laki-laki pada jaman 'Umar bin Al Khattab meminta-minta kepada beliau, lalu beliau memberinya. (Abdullah bin Abdullah Khubaib) berkata; [Abdullah bin Unais] yaitu salah seorang sahabat Rasulullah Shallallahu'alaihiwasallam duduk bersama kami di majlis Juhainah. Dia berkata; pada bulan Ramadlan. Kami pun bertanya ' Hai Abu Yahya, adakah kamu mendengar suatu hal dari Rasulullah Shallallahu'alaihiwasallam di malam yang penuh barakah ini? 'Ya' jawabnya. Pernah kami duduk-duduk bersama Rasulullah Shallallahu'alaihiwasallam di akhir bulan seperti ini. Kami pun bertanya kepada beliau 'Hai Rasulullah, kapan kami bisa mendapatkan malam yang penuh barakah (lailatul qadar)? Beliau menjawab 'Carilah seperti malam ini'. Ia katakan, itu terjadi sore hari di malam dua puluh tiga. Lantas seseorang bertanya 'kalau begitu maksudnya di malam ke delapan begitu? Lantas Rasulullah Shallallahu'alaihiwasallam bersabda 'Bukan awal malam ke delapan namun malam ketujuh, sebab sebulan itu tidak genap.'"},"837":{"ar":"قَالَ حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي قَالَ عَنِ ابْنِ إِسْحَاقَ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ جَعْفَرِ بْنِ الزُّبَيْرِ عَنِ ابْنِ عَبْدِ اللَّهِ بْنِ أُنَيْسٍ عَنِ أَبِيهِ قَالَدَعَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّهُ قَدْ بَلَغَنِي أَنَّ خَالِدَ بْنَ سُفْيَانَ بْنِ نُبَيْحٍ يَجْمَعُ لِي النَّاسَ لِيَغْزُوَنِي وَهُوَ بِعُرَنَةَ فَأْتِهِ فَاقْتُلْهُ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ انْعَتْهُ لِي حَتَّى أَعْرِفَهُ قَالَ إِذَا رَأَيْتَهُ وَجَدْتَ لَهُ أُقْشَعْرِيَرَةً قَالَ فَخَرَجْتُ مُتَوَشِّحًا بِسَيْفِي حَتَّى وَقَعْتُ عَلَيْهِ وَهُوَ بِعُرَنَةَ مَعَ ظُعُنٍ يَرْتَادُ لَهُنَّ مَنْزِلًا وَحِينَ كَانَ وَقْتُ الْعَصْرِ فَلَمَّا رَأَيْتُهُ وَجَدْتُ مَا وَصَفَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْأُقْشَعْرِيرَةِ فَأَقْبَلْتُ نَحْوَهُ وَخَشِيتُ أَنْ يَكُونَ بَيْنِي وَبَيْنَهُ مُحَاوَلَةٌ تَشْغَلُنِي عَنْ الصَّلَاةِ فَصَلَّيْتُ وَأَنَا أَمْشِي نَحْوَهُ أُومِئُ بِرَأْسِي الرُّكُوعَ وَالسُّجُودَ فَلَمَّا انْتَهَيْتُ إِلَيْهِ قَالَ مَنْ الرَّجُلُ قُلْتُ رَجُلٌ مِنْ الْعَرَبِ سَمِعَ بِكَ وَبِجَمْعِكَ لِهَذَا الرَّجُلِ فَجَاءَكَ لِهَذَا قَالَ أَجَلْ أَنَا فِي ذَلِكَ قَالَ فَمَشَيْتُ مَعَهُ شَيْئًا حَتَّى إِذَا أَمْكَنَنِي حَمَلْتُ عَلَيْهِ السَّيْفَ حَتَّى قَتَلْتُهُ ثُمَّ خَرَجْتُ وَتَرَكْتُ ظَعَائِنَهُ مُكِبَّاتٍ عَلَيْهِ فَلَمَّا قَدِمْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَآنِي فَقَالَ أَفْلَحَ الْوَجْهُ قَالَ قُلْتُ قَتَلْتُهُ يَا رَسُولَ اللَّهِ قَالَ صَدَقْتَ قَالَ ثُمَّ قَامَ مَعِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَخَلَ فِي بَيْتِهِ فَأَعْطَانِي عَصًا فَقَالَ أَمْسِكْ هَذِهِ عِنْدَكَ يَا عَبْدَ اللَّهِ بْنَ أُنَيْسٍ قَالَ فَخَرَجْتُ بِهَا عَلَى النَّاسِ فَقَالُوا مَا هَذِهِ الْعَصَا قَالَ قُلْتُ أَعْطَانِيهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَمَرَنِي أَنْ أَمْسِكَهَا قَالُوا أَوَلَا تَرْجِعُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَسْأَلَهُ عَنْ ذَلِكَ قَالَ فَرَجَعْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ لِمَ أَعْطَيْتَنِي هَذِهِ الْعَصَا قَالَ آيَةٌ بَيْنِي وَبَيْنَكَ يَوْمَ الْقِيَامَةِ إِنَّ أَقَلَّ النَّاسِ الْمُتَخَصِّرُونَ يَوْمَئِذٍ يَوْمَ الْقِيَامَةِفَقَرَنَهَا عَبْدُ اللَّهِ بِسَيْفِهِ فَلَمْ تَزَلْ مَعَهُ حَتَّى إِذَا مَاتَ أَمَرَ بِهَا فَصُبَّتْ مَعَهُ فِي كَفَنِهِ ثُمَّ دُفِنَا جَمِيعًا قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا ابْنُ إِدْرِيسَ عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ عَنْ مُحَمَّدِ بْنِ جَعْفَرِ بْنِ الزُّبَيْرِ عَنْ بَعْضِ وَلَدِ عَبْدِ اللَّهِ بْنِ أُنَيْسٍ عَنْ أَبِي عَبْدِ اللَّهِ بْنِ أُنَيْسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَهُ إِلَى خَالِدِ بْنِ سُفْيَانَ بْنِ نُبَيْحٍ الْهُذَلِيِّ لِيَقْتُلَهُ وَكَانَ يُجَمِّعُ لِقِتَالِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَأَتَيْتُهُ بِعُرَنَةَ وَهُوَ فِي ظَهْرٍ لَهُ وَقَدْ دَخَلَ وَقْتُ الْعَصْرِ فَخِفْتُ أَنْ يَكُونَ بَيْنِي وَبَيْنَهُ مُحَاوَلَةٌ تَشْغَلُنِي عَنْ الصَّلَاةِ قَالَ فَصَلَّيْتُ وَأَنَا أَمْشِي أُومِئُ إِيمَاءً فَلَمَّا انْتَهَيْتُ إِلَيْهِ قُلْتُ كَذَا وَكَذَا حَتَّى ذَكَرَ الْحَدِيثَ ثُمَّ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَهُ بِقَتْلِهِ إِيَّاهُ وَذَكَرَ الْحَدِيثَ","id":"(Ahmad bin Hanbal radliyallhu'anhu) berkata; telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [bapakku] berkata; dari [Ibnu Ishaq] berkata; telah menceritakan kepadaku [Muhammad bin Ja'far bin Al Zubair] dari [Ibnu Abdullah bin Unais] dari [bapaknya] berkata; Rasulullah Shallallahu'alaihiwasallam memanggilku dan bersabda: \"Telah sampai berita kepadaku bahwa Khalid bin Sufyan bin Nubaih mengumpulkan khalayak manusia untuk memerangiku, dia berada di 'Uranah (nama tempat, pent) bunuhlah dia. Berkata (Abdullah bin Unais), \"Wahai Rasulullah, jelaskan sifat-sifatnya kepadaku hingga aku dapat mengenalnya\". Beliau bersabda: \"Apabila kamu mendapatkanya, dia dalam kedaaan tubuh yang merinding dan bergetar\". (Abdullah bin Unais) berkata; saya keluar dan menutupi tubuhku dengan pedang hingga aku bertemu langsung denganya di 'Uranah pada waktu ashar dengan isterinya dan memilimilih sebuah persinggahanuntuk istrinya. Aku melihat sifat sebagaimana yang disebutkan Rasulullah Shallallahu'alaihiwasallam dari tubuh yang merinding dan bergetar. Aku berusaha menemuinya, dan aku sempat khawatir jangAn jangan ada perlawanan darinya sehingga menyibukkanku dari shalat. Aku pun berjalan di depannya dan shalat dengan isyarat kepala dan ruku serta sujud, ketika aku telah menyelesaikan keperluanku, Dia bertanya, \"Siapakah laki-laki itu?\" (maksudnya menanyakan Abdullah bin Unais, pent) (Abdullah bin Unais) menjawabnya, \"Seorang laki-laki Arab yang telah mendengarmu dan tujuanmu mengumpulkan orang untuk membunuh Muhammad, maka dia (maksudnya dirinya) datang untuk membantumu perihal urusanmu itu\", dia berkata; \"Tepat sekali, aku memang sedang mengurusi hal itu (ingin membunuh Muhammad, pent) \" lalu (Abdullah bin Unais) berkata; lalu saya berjalan sebentar bersamanya, begitu ketika aku mendapatkan kesempatan untuk membunuhnya, aku bawakan pedang dan aku bunuh dia. Kemudian aku keluar dan meninggalkan para isterinya yang meratapinya. Ketika saya menemui Rasulullah Shallallahu'alaihiwasallam dan beliau melihatku, beliau bersabda: \"Telah beruntung wajahmu\" (ungkapan kegembiraan, pent) (Abdullah bin Unais) berkata; \"Wahai Rasulullah, saya telah membunuhnya\", Beliau bersabda: \"Engkau benar\" kemudian beliau berdiri bersamaku, dan beliau masuk ke rumah dan memberiku tongkat seraya bersabda: \"Peganglah tongkat ini wahai Abdullah bin Unais! (Abdullah bin Unais) berkata; lalu saya pulang dengan membawa tongkat tersebut sehingga orang-orang bertanya, \"Untuk apa tongkatmu itu wahai Abdullah bin Unais?\", maka aku berkata; \"Tongkat ini adalah pemberian Rasulullah Shallallahu'alaihiwasallam dan beliau memerintahkanku untuk memegangnya\". Mereka berkata; \"Apakah tidak lebih baik apabila engkau kembali kepada Rasulullah Shallallahu'alaihiwasallam dan menanyakan perihal tongkat itu? (Abdullah bin Unais) berkata; lalu saya kembali kepada Rasulullah Shallallahu'alaihiwasallam dan bertanya beliau, \"Wahai Rasulullah Shallallahu'alaihiwasallam mengapa engkau memberiku tongkat ini?\" Beliau menjawab, \"Ini adalah tanda antara aku dan dirimu pada waktu Hari Kiamat nanti, hari ketika sedikit manusia yang berjalan dengan berpegang tongkat, maka tongkat itu selalu menyertai Abdullah beserta dengan pedangnya dan selalu bersamanya sampai dia meninggal. Ketika dia meninggal, dia memerintahkan agar tongkat itu ditancapkan bersamanya dengan kain kafannya, yang kemudian dia dimakamkan bersama dengan tongkatnya. Telah menceritakan kepada kami [Yahya bin Adam] berkata; telah menceritakan kepada kami [Ibnu Abu Idris] dari [Muhammad bin Ishaq] dari [Muhammad bin Ja'far bin Az Zubair] dari [beberapa anak Abdullah bin Unais] dari [Abu Abdullah bin Unais] Rasulullah Shallallahu'alaihiwasallam menyuruhnya untuk membunuh Khalid bin Sufyan bin Nubaih Al Hudzailly yang dia mengumpulkan orang untuk membunuh Rasulullah Shallallahu'alaihiwasallam, maka aku menemuinya di 'Uranah ketika dia diatas tungganganya ketika waktu ashar. Aku khawatir jangAn jangan ada perlawanan atau duel antara aku dan dia sehingga melalaikanku dari shalat. Maka saya shalat dengan berjalan dan hanya memberi isyarat, ketika aku bertemu dengannya kuceritakan demikiAn demikian, hingga ia sebutkan dalam hadis kemudian datang pada Nabi Shallallahu'alaihiwasallam dan memberitahukannya tentang terbunuhnya dia, lalu dia menyebutkan hadis secara lengkap."},"838":{"ar":"حَدَّثَنَا حَجَّاجٌ قَالَ حَدَّثَنِي شُعْبَةُ قَالَ سَمِعْتُ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ أَبِي أُسَيْدٍ السَّاعِدِيِّ قَالَ أَبِي و قَالَ ابْنُ جَعْفَرٍ عَنْ أَبِي أُسَيْدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُ دُورِ الْأَنْصَارِ بَنُو النَّجَّارِ ثُمَّ بَنُو عَبْدِ الْأَشْهَلِ ثُمَّ بَنُو الْحَارِثِ بْنِ الْخَزْرَجِ ثُمَّ بَنُو سَاعِدَةَ وَفِي كُلِّ دُورِ الْأَنْصَارِ خَيْرٌفَقَالَ سَعْدُ بْنُ عُبَادَةَ مَا أَرَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا قَدْ فَضَّلَ عَلَيْنَا فَقِيلَ قَدْ فَضَّلَكُمْ عَلَى كَثِيرٍ","id":"Telah menceritakan kepada kami [Hajjaj] berkata; telah menceritakan kepadaku [Syu'bah] berkata; saya mendengar [Qatadah] dari [Anas bin Malik] dari [Abu Usaid As-Saidi] berkata; [bapakku] dan [Ibnu Ja'far] berkata; dari Abu Usaid berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Sebaik-baik rumah kaum Anshor adalah Bani Najjar, kemudian Bani Abdul Asyhal, kemudian Bani Al Harits bin Khajraj kemudian Bani Sa'idah dan setiap derajat kaum Anshar adalah baik\". Sa'ad bin 'Ubadah berkata; \"Aku tidak pernah melihat Rasulullah Shallallahu'alaihiwasallam kecuali memberi keutamaan kita atau telah memberi banyak keutamaan di antara yang lainnya\""},"839":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ أَبِي الزِّنَادِ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي أُسَيْدٍ السَّاعِدِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُ الْأَنْصَارِ بَنُو النَّجَّارِ ثُمَّ بَنُو عَبْدِ الْأَشْهَلِ ثُمَّ بَنُو الْحَارِثِ بْنِ الْخَزْرَجِ ثُمَّ بَنُو سَاعِدَةَ ثُمَّ قَالَ وَفِي كُلِّ دُورِ الْأَنْصَارِ خَيْرٌ","id":"(Ahmad bin Hanbal radliyallhu'anhu) berkata; telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Sufyan] dari [Abu Az Zinad] dari [Abu Salamah] dari [Abu Usaid As-Sa'idi] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Sebaik-baik rumah orang Anshar adalah Bani Najjar, kemudian Bani Abdul Asyhal, kemudian Bani Al Harits bin Khazraj, kemudian Bani Sa'idah\" kemudian berkata; \"Setiap derajat kaum Anshar adalah baik\"."},"840":{"ar":"قَالَ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ ذَكْوَانَ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي أُسَيْدٍ السَّاعِدِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُ دُورِ الْأَنْصَارِ بَنُو النَّجَّارِ ثُمَّ بَنُو عَبْدِ الْأَشْهَلِ ثُمَّ بَنُو الْحَارِثِ بْنِ الْخَزْرَجِ ثُمَّ بَنُو سَاعِدَةَ ثُمَّ قَالَ وَفِي كُلِّ دُورِ الْأَنْصَارِ خَيْرٌفَقَالَ سَعْدُ بْنُ عُبَادَةَ جَعَلَنَا رَابِعَ أَرْبَعَةٍ أَسْرِجُوا لِي حِمَارِي فَقَالَ ابْنُ أَخِيهِ أَتُرِيدُ أَنْ تَرُدَّ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَسْبُكَ أَنْ تَكُونَ رَابِعَ أَرْبَعَةٍ","id":"(Ahmad bin Hanbal radliyallhu'anhu) berkata; telah mengabarkan kepada kami [Abdurrazzaq] berkata; telah menceritakan kepada kami [Sufyan] dari [Abdullah bin Dzakwan] dari [Abu Salamah] dari [Abu Usaid As-Sa'idi] dari Nabi Shallallahu'alaihiwasallam, \"Sebaik-baik rumah Anshar adalah Bani Najjar, kemudian Bani Abdul Asyhal, kemudian Bani Al Harits bin Khazraj, kemudian Bani Sa'idah\" kemudian berkata; \"Setiap rumah kaum Anshar adalah baik\". Sa'ad bin 'Ubadah berkata; kami menjadikan urutan yang keempat adalah berilah pelana pada keledaiku. Anak saudaraku berkata; apakah kamu mau dikembalikan kepada Rasulullah Shallallahu'alaihiwasallam, cukuplah bagimu untuk urutan yang ke empat."},"841":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى قَالَ حَدَّثَنِي عَطَاءٌ رَجُلٌ كَانَ يَكُونُ بِالسَّاحِلِ عَنْ أَبِي أُسَيْدٍ أَوْ أَبِي أَسِيدِ بْنِ ثَابِتٍ شَكَّ سُفْيَانُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلُوا الزَّيْتَ وَادَّهِنُوا بِالزَّيْتِ فَإِنَّهُ مِنْ شَجَرَةٍ مُبَارَكَةٍ","id":"(Ahmad bin Hanbal radliyallhu'anhu) berkata; telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Sufyan] dari [Abdullah bin 'Isa] berkata; telah menceritakan kepadaku ['Atha`] orang yang berada di tepi pantai, dari [Abu Usaid] atau Abu Asid bin Tsabit, Sufyan ragu, Nabi Shallallahu'alaihiwasallam bersabda: \"Makanlah buah zaitun dan dan pakailah minyak rambut dari buah zaitun, karena buah itu dari pohon yang berbarakah\""},"842":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ عَطَاءٍ الشَّامِيِّ عَنْ أَبِي أَسِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُوا الزَّيْتَ وَادَّهِنُوا بِهِ فَإِنَّهُ مِنْ شَجَرَةٍ مُبَارَكَةٍ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sufyan] dari [Abdullah bin 'Isa] dari ['Atho`Asy-Syami] dari [Abu Asid] dengan Rasulullah Shallallahu'alaihiwasallam bersabda: \"Makanlah buah zaitun dan dan pakailah minyak rambut dari buah zaitun, karena buah itu dari pohon yang berbarakah\""},"843":{"ar":"قَالَ حَدَّثَنَا أَبُو عَامِرٍ قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ عَنْ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ الْمَلِكِ بْنِ سَعِيدِ بْنِ سُوَيْدٍ الْأَنْصَارِيِّ قَالَ سَمِعْتُ أَبَا حُمَيْدٍ وَأَبَا أُسَيْدٍ يَقُولَانِقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَخَلَ أَحَدُكُمْ الْمَسْجِدَ فَلْيَقُلْ اللَّهُمَّ افْتَحْ لَنَا أَبْوَابَ رَحْمَتِكَ وَإِذَا خَرَجَ فَلْيَقُلْ اللَّهُمَّ إِنِّي أَسْأَلُكَ مِنْ فَضْلِكَ","id":"(Ahmad bin Hanbal radliyallhu'anhu) berkata; telah menceritakan kepada kami [Abu 'Amir] berkata; telah menceritakan kepada kami [Sulaiman bin Bilal] dari [Rabi'ah bin Abu Abdurrohman] dari [Abdul Malik bin Sa'id bin Suwaid Al Anshari], berkata; saya mendengar [Abu Humaid] dan [Abu Usaid] keduanya berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Apabila salah seorang dari kalian masuk masjid hendaklah membaca, 'ALLAHUMMAFTAH LI ABWABA RAHMATIKA' (Ya Allah bukakanlah untukku pintu-pintu rahmat-Mu) dan apabila keluar hendaklah dia berdoa, 'ALLAHUMMA INNI ASA`LUKA MIN FADZLIK' (Ya Allah, aku memohon dari keutamaAn Mu) \"."},"844":{"ar":"قَالَ حَدَّثَنَا أَبُو عَامِرٍ قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ عَنْ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ الْمَلِكِ بْنِ سَعِيدِ بْنِ سُوَيْدٍ عَنْ أَبِي حُمَيْدٍ وَعَنْ أَبِي أُسَيْدٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا سَمِعْتُمْ الْحَدِيثَ عَنِّي تَعْرِفُهُ قُلُوبُكُمْ وَتَلِينُ لَهُ أَشْعَارُكُمْ وَأَبْشَارُكُمْ وَتَرَوْنَ أَنَّهُ مِنْكُمْ قَرِيبٌ فَأَنَا أَوْلَاكُمْ بِهِ وَإِذَا سَمِعْتُمْ الْحَدِيثَ عَنِّي تُنْكِرُهُ قُلُوبُكُمْ وَتَنْفِرُ أَشْعَارُكُمْ وَأَبْشَارُكُمْ وَتَرَوْنَ أَنَّهُ مِنْكُمْ بَعِيدٌ فَأَنَا أَبْعَدُكُمْ مِنْهُ","id":"(Ahmad bin Hanbal radliyallhu'anhu) berkata; telah menceritakan kepada kami [Abu 'Amir] berkata; telah menceritakan kepada kami [Sulaiman bin Bilal] dari [Rabi'ah bin Abu Abdurrahman] dari [Abdul Malik bin Sa'id bin Suwaid] dari [Abu Humaid] dan dari [Abu Usaid] Nabi Shallallahu'alaihiwasallam, bersabda: \"Jika kalian mendengar sebuah hadis dariku, hati kalian membenarkan dan perasaan kalian menjadi halus serta kalian memandang hadis tersebut dekat dengan kalian maka aku menjadi dekat dengan kalian. Tapi jika kalian mendengar hadis dariku dan hati kalian mengingkarinya, perasaan kalian menjadi keras karenanya dan kalian memandang hadis sebagai sesuatu yang jauh dari kalian, maka aku akan jauh dari kalian\"."},"845":{"ar":"قَالَ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ الْغَسِيلِ قَالَ حَدَّثَنِي أَسِيدُ بْنُ عَلِيٍّ عَنْ أَبِيهِ عَلِيِّ بْنِ عُبَيْدٍ عَنْ أَبِي أُسَيْدٍ صَاحِبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ بَدْرِيًّا وَكَانَ مَوْلَاهُمْ قَالَ قَالَ أَبُو أُسَيْدٍبَيْنَمَا أَنَا جَالِسٌ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ جَاءَهُ رَجُلٌ مِنْ الْأَنْصَارِ فَقَالَ يَا رَسُولَ اللَّهِ هَلْ بَقِيَ عَلَيَّ مِنْ بِرِّ أَبَوَيَّ شَيْءٌ بَعْدَ مَوْتِهِمَا أَبَرُّهُمَا بِهِ قَالَ نَعَمْ خِصَالٌ أَرْبَعَةٌ الصَّلَاةُ عَلَيْهِمَا وَالِاسْتِغْفَارُ لَهُمَا وَإِنْفَاذُ عَهْدِهِمَا وَإِكْرَامُ صَدِيقِهِمَا وَصِلَةُ الرَّحِمِ الَّتِي لَا رَحِمَ لَكَ إِلَّا مِنْ قِبَلِهِمَا فَهُوَ الَّذِي بَقِيَ عَلَيْكَ مِنْ بِرِّهِمَا بَعْدَ مَوْتِهِمَا","id":"(Ahmad bin Hanbal radliyallhu'anhu) berkata; telah menceritakan kepada kami [Yunus bin Muhammad] berkata; telah menceritakan kepada kami [Abdurrohman bin Al Ghasil] berkata; telah menceritakan kepadaku [Asid bin 'Ali] dari [bapaknya, 'Ali bin 'Ubaid] dari [Abu Usaid], sahabat Rasulullah Shallallahu'alaihiwasallam, Ahli Badar, dan dia termasuk maula mereka, berkata; Abu Usaid berkata; Ketika aku duduk di samping Rasulullah Shallallahu'alaihiwasallam, tiba-tiba seorang laki-laki Anshar datang dan berkata; Wahai Rasulullah Shallallahu'alaihiwasallam apakah masih tersisa kewajiban atasku untuk berbuat baik kepada orang tuaku setelah kematian mereka berdua?. Beliau menjawab 'Ya', masih tersisa empat perkara yaitu: mendoakan untuk mereka berdua, meminta ampunan mereka, memenuhi janji mereka yang belum terselesaikan dan memuliakan temAn teman mereka serta silaturrahim yang sebenarnya tidak berhubungan dengan kamu kecuali dari jalur mereka. Itulah semua yang tersisa dari kewajibanmu untuk berbuat kebaikan kepada orang tuamu setelah mereka meninggal \""},"846":{"ar":"قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الزُّبَيْرِيُّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ الْغَسِيلِ عَنْ حَمْزَةَ بْنِ أَبِي أُسَيْدٍ عَنْ أَبِيهِ وَعَبَّاسِ بْنِ سَهْلٍ عَنْ أَبِيهِ قَالَامَرَّ بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابٌ لَهُ فَخَرَجْنَا مَعَهُ حَتَّى انْطَلَقْنَا إِلَى حَائِطٍ يُقَالُ لَهُ الشَّوْطُ حَتَّى انْتَهَيْنَا إِلَى حَائِطَيْنِ مِنْهُمَا فَجَلَسْنَا بَ��ْنَهُمَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اجْلِسُوا وَدَخَلَ هُوَ وَقَدْ أُوتِيَ بِالْجَوْنِيَّةِ فِي بَيْتِ أُمَيْمَةَ بِنْتِ النُّعْمَانِ بْنِ شَرَاحِيلَ وَمَعَهَا دَايَةٌ لَهَا فَلَمَّا دَخَلَ عَلَيْهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ هَبِي لِي نَفْسَكِ قَالَتْ وَهَلْ تَهَبُ الْمَلِكَةُ نَفْسَهَا لِلسُّوقَةِ قَالَتْ إِنِّي أَعُوذُ بِاللَّهِ مِنْكَ قَالَ لَقَدْ عُذْتِ بِمُعَاذٍ ثُمَّ خَرَجَ عَلَيْنَا فَقَالَ يَا أَبَا أُسَيْدٍ اكْسُهَا رَازِقِيَّتَيْنِ وَأَلْحِقْهَا بِأَهْلِهَاقَالَ وَقَالَ غَيْرُ أَبِي أَحْمَدَ امْرَأَةٌ مِنْ بَنِي الْجَوْنِ يُقَالُ لَهَا أَمِينَةُ","id":"(Ahmad bin Hanbal radliyallhu'anhu) berkata; telah menceritakan kepada kami [Muhammad bin Abdullah Az Zubairi] berkata; telah menceritakan kepada kami [Abdurrahman Al Ghasil] dari [Hamzah bin Abu Usaid] dari [bapaknya] dan ['Abbas bin Sahal] dari [bapaknya] mereka berdua berkata; Rasulullah Shallallahu'alaihiwasallam dan para sahabatnya melewati mereka, lalu kami ikut keluar bersama mereka hingga berhenti di sebuah kebun yang disebut Syauth dan kami berhenti dan duduk di antara dua kebun tersebut. Rasulullah Shallallahu'alaihiwasallam bersabda: \"Duduklah kalian!\" Dan beliau diserahi seorang perempuan (untuk dinikahi) dari Kabilah Jaun di rumah Umaimah binti An Nu'man bin Syarahbil, dan perempuan bidan. Ketika Rasulullah Shallallahu'alaihiwasallam menemuinya, beliau bersabda: \"Serahkanlah dirimu untukku\" perempuan itu menjawab, \"Apakah seorang ratu perempuan menyerahkan dirinya untuk laki-laki jelata?\" dan berkata; \"Aku berlindung kepada Allah dari dirimu\". (Rasulullah Shallallahu'alaihiwasallam) menjawab, \"Sesungguhnya engkau telah berlindung kepada Sang Pelindung\", kemudian (Rasulullah Shallallahu'alaihiwasallam) menemui kami dan berkata; \"Wahai Abu Usaid pakaikanlah untuknya dua lapis pakaian yang berwarna putih dan pulangkanlah dia kepada keluarganya\". ('Abbas bin Sahal) berkata; selain Abu Ahmad berkata; seorang wanita dari Bani Al Jaun yang bernama Aminah."},"847":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا يَعْقُوبُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي حَازِمٍ قَالَ سَمِعْتُ سَهْلًا يَقُولُأَتَى أَبُو أُسَيْدٍ السَّاعِدِيُّ فَدَعَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي عُرْسِهِ فَكَانَتْ امْرَأَتُهُ خَادِمَهُمْ يَوْمَئِذٍ وَهِيَ الْعَرُوسُ قَالَ تَدْرُونَ مَا سَقَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْقَعَتْ تَمَرَاتٍ مِنْ اللَّيْلَةِ فِي تَوْرٍ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Ya'qub bin Abdurrahman] dari [Abu Hazm] berkata; saya mendengar [Sahal] berkata; Abu Usaid As-Sai'di datang dan memanggil Rasulullah Shallallahu'alaihiwasallam di tempat pelaminannya, adapun istri Abu Usaid membantu mereka pada hari ketika dia menjadi pengantin. (Sahal) berkata 'Apakah kalian mengetahui apa yang perempuan itu tuangkan kepada Rasulullah Shallallahu'alaihiwasallam? sesungguhnya dia memasukkan kurma dalam sebuah kuali untuk direndam\""},"848":{"ar":"حَدَّثَنَا هَارُونُ بْنُ مَعْرُوفٍ قَالَ عَبْد اللَّهِ وَسَمِعْتُهُ أَنَا مِنْ هَارُونَ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ حَدَّثَنَا عَمْرُو بْنُ الْحَارِثِ أَنَّ مُوسَى بْنَ جُبَيْرٍ حَدَّثَهُ أَنَّ عَبْدَ اللَّهِ بْنَ عَبْدِ الرَّحْمَنِ بْنِ الْحُبَابِ الْأَنْصَارِيَّ حَدَّثَهُ أَنَّ عَبْدَ اللَّهِ بْنَ أُنَيْسٍ حَدَّثَهُأَنَّهُمْ تَذَاكَرُوا هُوَ وَعُمَرُ بْنُ الْخَطَّابِ يَوْمًا الصَّدَقَةَ فَقَالَ عُمَرُ أَلَمْ تَسْمَعْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ ذَكَرَ غُلُولَ الصَّدَقَةِ إِنَّهُ مَنْ غَلَّ مِنْهَا بَعِيرًا أَوْ شَاةً أُتِيَ بِهِ يَحْمِلُهُ يَوْمَ الْقِيَامَةِ قَالَ عَبْدُ اللَّهِ بْنُ أُنَيْسٍ بَلَى","id":"Telah menceritakan kepada kami [Harun bin Makruf] Abdullah berkata; dan saya mendengarnya dari [Harun] berkata; telah menceritakan kepada kami [Ibnu Wahb] berkata; telah menceritakan kepada kami ['Amr bin Al Harits] [Musa bin Jubair] menceritakannya [Abdullah bin Abdurrahman bin Al Habab Al Anshary] menceritakannya, [Abdullah bin Unais] menceritakan kepadanya bahwa pada suatu hari dia dan 'Umar bin Khattab teringat perkara zakat. ['Umar] berkata; tidakkah engkau mendengar Rasulullah Shallallahu'alaihiwasallam ketika beliau mengingatkan pencurian zakat?, \"Sesungguhnya orang yang berkhianat dengan mengambil unta dan kambing zakat, maka Allah akan mendatangkannya pada Hari Kiamat dalam keadaan memikul barang-barang yang diambilnya\". [Abdullah bin Unais] berkata; Ya."},"849":{"ar":"قَالَ حَدَّثَنَا أَبُو سَعِيدٍ مَوْلَى بَنِي هَاشِمٍ قَالَ حَدَّثَنَا زَائِدَةُ قَالَ حَدَّثَنَا شَبِيبُ بْنُ غَرْقَدَةَ عَنْ سُلَيْمَانَ بْنِ عَمْرِو بْنِ الْأَحْوَصِ قَالَ حَدَّثَنِي أَبِي أَنَّهُشَهِدَ حَجَّةَ الْوَدَاعِ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَجْنِي جَانٍ إِلَّا عَلَى نَفْسِهِ لَا يَجْنِي وَالِدٌ عَلَى وَلَدِهِ وَلَا مَوْلُودٌ عَلَى وَالِدِهِ","id":"Telah menceritakan kepada kami [Abu Sa'id] budak Bani Hasyim. Berkata; telah menceritakan kepada kami [Za`idah] berkata; telah menceritakan kepada kami [Syabib bin Ghurqadah] dari [Sulaiman bin 'Amr bin Al Ahwash] berkata; telah menceritakan kepadaku [bapakku] dia menyaksikan Haji Wada'bersama Rasulullah Shallallahu'alaihiwasallam. Lalu Rasulullah Shallallahu'alaihiwasallam bersabda: \" Tidaklah seseorang melakukan pelanggaran kecuali kepada dirinya sendiri, dan tidaklah orang tua melakukan pelanggaran sedang dosanya ditanggung anaknya, dan tidak pula seorang anak melakukan pelanggaran dan dosanya ditanggung kedua orang tuanya.\""},"850":{"ar":"حَدَّثَنَا هَيْثَمُ بْنُ خَارِجَةَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ أَيُّوبَ بْنِ مَيْسَرَةَ بْنِ حَلْبَسٍ قَالَ سَمِعْتُ أَبِي سَمِعَ خُرَيْمَ بْنَ فَاتِكٍ الْأَسَدِيَّ يَقُولُأَهْلُ الشَّامِ سَوْطُ اللَّهِ فِي الْأَرْضِ يَنْتَقِمُ بِهِمْ مِمَّنْ يَشَاءُ كَيْفَ يَشَاءُ وَحَرَامٌ عَلَى مُنَافِقِيهِمْ أَنْ يَظْهَرُوا عَلَى مُؤْمِنِيهِمْ وَلَنْ يَمُوتُوا إِلَّا هَمًّا أَوْ غَيْظًا أَوْ حُزْنًا","id":"Telah menceritakan kepada kami [Husyaim bin Kharijah] berkata; telah menceritakan kepada kami [Muhammad bin Ayyub bin Maisarah bin Halbas] berkata; saya mendengar [bapakku] juga mendengar dari [Huraim bin Fatik Al Asadi] berkata; \"Penduduk Syam adalah cemeti Allah di muka bumi, (Allah Azzawajalla) menyiksa sebuah kaum dengan perantaraan mereka terhadap siapa saja yang Dikehendaki-Nya. Dan diharamkan bagi kaum munafiqnya mengalahkan kaum mukminnya, dan mereka (orang munafiqnya) sekali-kali tidak akan mati kecuali dalam keadaan cemas, marah ataupun sedih.\""},"851":{"ar":"حَدَّثَنَا هَيْثَمُ بْنُ خَارِجَةَ قَالَ حَدَّثَنَا طَيَّافٌ الْإِسْكَنْدَرَانِيُّ عَنِ ابْنِ شَرَاحِيلَ بْنِ بُكَيْلٍ عَنِ أَبِيهِ شُرَاحْبِيلَ قَالَقُلْتُ لِابْنِ عُمَرَ إِنَّ لِي أَرْحَامًا بِمِصْرَ يَتَّخِذُونَ مِنْ هَذِهِ الْأَعْنَابِ قَالَ وَفَعَلَ ذَلِكَ أَحَدٌ مِنْ الْمُسْلِمِينَ قُلْتُ نَعَمْ قَالَ لَا تَكُونُوا بِمَنْزِلَةِ الْيَهُودِ حُرِّمَتْ عَلَيْهِمْ الشُّحُومُ فَبَاعُوهَا وَأَكَلُوا أَثْمَانَهَا قَالَ قُلْتُ مَا تَقُولُ فِي رَجُلٍ أَخَذَ عُنْقُودًا فَعَصَرَهُ فَشَرِبَهُ قَالَ لَا بَأْسَ فَلَمَّا نَزَلْتُ قَالَ مَا حَلَّ شُرْبُهُ حَلَّ بَيْعُهُ","id":"Telah menceritakan kepada kami [Husyaim bin Kharijah] berkata; telah menceritakan kepada kami [Thayyaf Al Iskandari] dari [Ibnu Syarahil bin Bukail] dari [bapaknya, Syurahil] berkata; saya berkata kepada [Ibnu 'Umar], saya mempunyai kerabat yang berada di Mesir yang menjadikan anggur menjadi sejenis Nabid (setelah melalui proses fregmentasi, pent). (Syurahbil) berkata; yang melakukan hal tersebut dari kaum muslimin? aku berkata; Ya. (Ibnu Umar) berkata; \"Janganlah kalian seperti orang yang Yahudi, diharamkan bagi mereka lemak, lalu mereka menjualnya dan memakan hasilnya\" Saya berkata; \"Bagaimana pendapat kamu mengenai seorang laki-laki yang mengambil pohon 'Unqud lalu memerasnya dan meminumnya? lalu dia berkata; \"Tidak apa-apa\" maka ketika aku turun, dia kembali berkata; \"Apa yang boleh untuk diminum, maka boleh untuk dijual.\""},"852":{"ar":"قَالَ حَدَّثَنَا هَيْثَمٌ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَيْمُونٍ الْأَشْعَرِيُّ عَنِ الْعَلَاءِ بْنِ الْحَارِثِ عَنْ مَكْحُولٍرَفَعَهُ قَالَ أَيُّمَا شَجَرَةٍ أَظَلَّتْ عَلَى قَوْمٍ فَصَاحِبُهُ بِالْخِيَارِ مِنْ قَطْعِ مَا أَظَلَّ أَوْ أَكْلِ ثَمَرِهَا","id":"(Ahmad bin Hanbal radliyallhu'anhu) berkata; telah menceritakan kepada kami [Hutsaim] berkata; telah menceritakan kepada kami [Abdullah bin Maimun Al Asy'ari] dari [Al 'Ala` bin Al Harits] dari [Makhul] dia memarfukkannya, (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Pohon mana saja yang menaungi suatu kaum, maka yang terkena naungan itu berhak memilih antara memotong bagian pohon yang menaungi atau menyantap buahnya.\""},"853":{"ar":"قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ إِسْحَاقَ قَالَ حَدَّثَنِي الْمُنْكَدِرُ بْنُ مُحَمَّدٍ يَعْنِي ابْنَ الْمُنْكَدِرِ عَنْ أَبِيهِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عُثْمَانَ التَّيْمِيِّ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَائِمًا فِي السُّوقِ يَوْمَ الْعِيدِ يَنْظُرُ وَالنَّاسُ يَمُرُّونَ","id":"(Ahmad bin Hanbal radliyallhu'anhu) berkata; telah menceritakan kepada kami [Ibrahim bin Ishaq] berkata; telah menceritakan kepadaku [Al Munkadir bin Muhammad] yaitu Ibnu Al Munkadir, dari [Bapaknya] dari [Abdurrahman bin 'Utsman At-Taimi] berkata; Aku melihat Rasulullah Shallallahu'alaihiwasallam berdiri melihat-lihat di pasar pada hari raya, dan manusia berlalu lalang.\""},"854":{"ar":"قَالَ حَدَّثَنَا هَاشِمٌ عَنِ ابْنِ أَبِي ذِئْبٍ وَيَزِيدُ قَالَ أَخْبَرَنَا ابْنُ أَبِي ذِئْبٍ عَنْ سَعِيدِ بْنِ خَالَدٍ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عُثْمَانَ قَالَذَكَرَ طَبِيبٌ الدَّوَاءَ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَذَكَرَ الضُّفْدَعَ تَكُونُ فِي الدَّوَاءِ فَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ قَتْلِهَا","id":"(Ahmad bin Hanbal radliyallhu'anhu) berkata; Telah menceritakan kepada kami [Hasyim] dari [Ibnu Abu Dzi`b], dan [Yazid] berkata; telah mengabarkan kepada kami [Ibnu Abu Dz`ib] dari [Sa'id bin Khalid] dari [Sa'id bin Musayyab] dari [Abdurrahman bin 'Utsman] berkata; ada seorang dokter yang menyebutkan obat di sisi Rasulullah Shallallahu'alaihiwasallam berupa katak, lalu Rasulullah Shallallahu'alaihiwasallam melarang membunuhnya."},"855":{"ar":"قَالَ حَدَّثَنَا سُرَيْجٌ وَهَارُونُ قَالَا حَدَّثَنَا ابْنُ وَهْبٍ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ بُكَيْرِ بْنِ الْأَشَجِّ عَنْ يَحْيَى بْنِ عَبْدِ الرَّحْمَنِ بْنِ حَاطِبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عُثْمَانَ التَّيْمِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ لُقَطَةِ الْحَاجِّ وَقَالَ هَارُونُ فِي حَدِيثِهِ عَمْرُو بْنُ الْحَارِثِقَالَ عَبْد اللَّهِ وَسَمِعْتُهُ أَنَا مِنْ هَارُونَ","id":"(Ahmad bin Hanbal radliyallhu'anhu) berkata; telah menceritakan kepada kami [Suraij] dan [Harun] berkata; telah menceritakan kepada kami [Ibnu Wahb] dari ['Amr bin Al Harits] dari [Bukair bin Al Asysyaj] dari [Yahya bin Abdurrahman bin Hatib] dari [Abdurahman bin 'Utsman At-Taimi] Rasulullah Shallallahu'alaihiwasallam mencegah dari mengambil barang temuan jamaah haji. Harun berkata dalam hadisnya, 'Amr bin Al Harits berkata; Abdullah berkata; dan saya mendengarnya dari Harun."},"856":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ ثَابِتٍ قَالَ حَدَّثَنِي عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ الْأَنْصَارِيُّ عَن�� أَبِيهِ عَنْ عِلْبَاءَ السُّلَمِيِّ قَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَقُومُ السَّاعَةُ إِلَّا عَلَى حُثَالَةِ النَّاسِ","id":"Telah menceritakan kepada kami ['Ali bin Tsabit] berkata; telah menceritakan kepadaku [Abdul Hamid bin Ja'far Al Anshari] dari [Bapaknya] dari ['Ilba' As-Sulamy] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Hari Kiamat tidak terjadi kecuali menimpa manusia-manusia yang buruk\"."},"857":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ ثَابِتٍ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ النُّعْمَانِ بْنِ مَعْبَدِ بْنِ هَوْذَةَ الْأَنْصَارِيُّ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِالْإِثْمِدِ الْمُرَوَّحِ عِنْدَ النَّوْمِ","id":"Telah menceritakan kepada kami ['Ali bin Tsabit] berkata; telah menceritakan kepadaku [Abdurrahman bin An Nu'man bin Ma'bad bin Haudzah Al Anshari] dari [bapaknya] dari [kakeknya] Rasulullah Shallallahu'alaihiwasallam menyuruh untuk memakai celak yang bercampur dengan wangi-wangian ketika tidur."},"858":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ قَالَ عَبْد اللَّهِ حَدَّثَنَاه أَبِي عَنْهُ وَهُوَ حَيٌّ قَالَ حَدَّثَنَا حُجْرُ بْنُ الْحَارِثِ الْغَسَّانِيُّ مِنْ أَهْلِ الرَّمْلَةِ عَنْ عَبْدِ اللَّهِ بْنِ عَوْنٍ الْكِنَانِيِّ وَكَانَ عَامِلًا لِعُمَرَ بْنِ عَبْدِ الْعَزِيزِ عَلَى الرَّمْلَةِ أَنَّهُشَهِدَ عَبْدَ الْمَلِكِ بْنَ مَرْوَانَ قَالَ لِبَشِيرِ بْنِ عَقْرَبَةَ الْجُهَنِيِّ يَوْمَ قُتِلَ عَمْرُو بْنُ سَعِيدِ بْنِ الْعَاصِ يَا أَبَا الْيَمَانِ إِنِّي قَدْ احْتَجْتُ الْيَوْمَ إِلَى كَلَامِكَ فَقُمْ فَتَكَلَّمْ قَالَ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ قَامَ يَخْطُبُ لَا يَلْتَمِسُ بِهَا إِلَّا رِيَاءً وَسُمْعَةً أَوْقَفَهُ اللَّهُ عَزَّ وَجَلَّ يَوْمَ الْقِيَامَةِ مَوْقِفَ رِيَاءٍ وَسُمْعَةٍ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur] Abdullah berkata; bapakku menceritakannya dari (Sa'id bin Manshur) ketika masih hidup berkata; telah menceritakan kepada kami [Hujr bin Al Harits, Al Ghassani] dari penduduk Ramlah, dari [Abdullah bin 'Aun Al Kinany] yang dia adalah gubernur untuk 'Umar Bin Abdul Aziz di Ramlah, bahwa dia menyaksikan Abdul Malik bin Marwan berkata kepada [Basyir bin 'Aqrabah] pada hari terbunuhnya Sa'id bin Al 'Ash 'Wahai Abu Al Yaman, pada hari aku membutuhkan perkataanmu, bangunlah dan bicaralah.' Lalu dia berkata; Aku mendengar Rasulullah Shallallahu'alaihiwasallam bersabda \"Barangsiapa yang berbicara dengan tujuan untuk riya dan sum'ah (diperdengarkan kepada orang lain-pent) niscaya Allah Azzawajalla akan menempatkan dia di tempat orang-orang yang riya dan sum'ah (neraka, pent)."},"859":{"ar":"حَدَّثَنَا أَبُو النَّضْرِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ قَالَ سَمِعْتُ عَمْرَو بْنَ مَيْمُونٍ يُحَدِّثُ عَنْ عَبْدِ اللَّهِ بْنِ رَبِيعَةَ السُّلَمِيِّ عَنْ عُبَيْدِ بْنِ خَالِدٍ السُّلَمِيِّ وَكَانَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَآخَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ رَجُلَيْنِ قُتِلَ أَحَدُهُمَا عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ مَاتَ الْآخَرُ فَصَلَّوْا عَلَيْهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا قُلْتُمْ قَالَ قُلْنَا اللَّهُمَّ اغْفِرْ لَهُ اللَّهُمَّ ارْحَمْهُ اللَّهُمَّ أَلْحِقْهُ بِصَاحِبِهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَيْنَ صَلَاتُهُ بَعْدَ صَلَاتِهِ وَأَيْنَ صِيَامُهُ أَوْ عَمَلُهُ بَعْدَ عَمَلِهِ مَا بَيْنَهُمَا أَبْعَدُ مَا بَيْنَ السَّمَاءِ وَالْأَرْضِ","id":"Telah menceritakan kepada kami [Abu Nadlr] berkata; telah menceritakan kepada kami [Syu'bah] dari ['Amr bin Murrah] berkata; saya mendengar ['Amr bin Maimun] menceritakan dari [Abdullah bin Rabi'ah As-Sulami] dari [Ubaid bin Khalid As-Sulamy] yang termasuk dari sahabat Nabi Shallallahu'alaihiwasallam berkata; Nabi Shallallahu'alaihiwasallam mempersaudarakan dua orang laki-laki yang salah satunya terbunuh (pada waktu peperangan) pada zaman Nabi Shallallahu'alaihiwasallam. Kemudian yang satu lagi meninggal, maka para sahabat menshalatkannya. Rasulullah Shallallahu'alaihiwasallam bersabda: \"Apa yang kalian ucapkan dalam shalat?\" Kami menjawab, ALLAHUMMAGFIR LAHU WARHAMHU, ALLAHUMMA ALHIQHU BISHAHIBIHI (Ya Allah ampunilah dosanya dan berilah kasih sayang dan pertemukanlah dia dengan saudaranya). Nabi Shallallahu'alaihiwasallam bersabda: \"Lalu dimanakah letak amal shalatnya setelah amal shalat (yang terbunuh) dan amalAn amalanya setelah amalan dari sahabat yang terbunuh, yang antara amalan keduanya terdapat perbedaan bagaikan langit dan bumi (artinya: sahabat yang pertama lebih utama dari sahabat yang mati terakhir dengan amalan yang disertai dengan rasa khusu' dan ikhlas dan waktu beramal yang lebih banyak-pent).\""},"860":{"ar":"قَالَ حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنِ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ كَعْبِ بْنِ مَالِكٍ الْأَنْصَارِيُّ وَهُوَ أَحَدُ الثَّلَاثَةِ الَّذِينَ تِيبَ عَلَيْهِمْ أَنَّهُ أَخْبَرَهُ بَعْضُ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ يَوْمًا عَاصِبًا رَأْسَهُ فَقَالَ فِي خُطْبَتِهِ أَمَّا بَعْدُ يَا مَعْشَرَ الْمُهَاجِرِينَ فَإِنَّكُمْ قَدْ أَصْبَحْتُمْ تَزِيدُونَ وَأَصْبَحَتْ الْأَنْصَارُ لَا تَزِيدُ عَلَى هَيْئَتِهَا الَّتِي هِيَ عَلَيْهَا الْيَوْمَ وَإِنَّ الْأَنْصَارَ عَيْبَتِي الَّتِي أَوَيْتُ إِلَيْهَا فَأَكْرِمُوا كَرِيمَهُمْ وَتَجَاوَزُوا عَنْ مُسِيئِهِمْ","id":"(Ahmad bin Hanbal radliyallhu'anhu) berkata; telah menceritakan kepada kami [Abu Al Yaman] berkata; telah mengabarkan kepada kami [Syua'ib] dari [Az Zuhri] berkata; telah mengabarkan kepadaku [Abdullah bin Ka'ab bin Malik Al Anshary] dia termasuk salah seorang dari tiga orang yang diterima taubatnya (pada peristiwa Perang Tabuk, pent) bahwa [sebagian sahabat Nabi Shallallahu'alaihiwasallam] mengabari kepadanya bahwa Nabi Shallallahu'alaihiwasallam suatu hari bepergian dengan kepala yang terikat dan berkata dalam khutbahnya, \"Amma Ba'du, Wahai sekalian Kaum Muhajirin, kalian telah bertambah banyak, Kaum Anshar tidaklah bertambah kecuali sebagaimana keadaan mereka pada hari ini, dan kaum Anshar adalah pembelaku dan tempat menjaga rahasiaku yang aku berlindung kepadanya, maka muliakanlah yang baik-baik di antara mereka dan maafkanlah mereka yang berbuat jelek."},"861":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا خَالِدٌ يَعْنِي الْوَاسِطِيَّ قَالَ حَدَّثَنَا عَمْرُو بْنُ يَحْيَى الْأَنْصَارِيُّ عَنْ زِيَادِ بْنِ أَبِي زِيَادٍ مَوْلَى بَنِي مَخْزُومٍ عَنْ خَادِمٍ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٍ أَوْ امْرَأَةٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِمَّا يَقُولُ لِلْخَادِمِ أَلَكَ حَاجَةٌ قَالَ حَتَّى كَانَ ذَاتَ يَوْمٍ فَقَالَ يَا رَسُولَ اللَّهِ حَاجَتِي قَالَ وَمَا حَاجَتُكَ قَالَ حَاجَتِي أَنْ تَشْفَعَ لِي يَوْمَ الْقِيَامَةِ قَالَ وَمَنْ دَلَّكَ عَلَى هَذَا قَالَ رَبِّي قَالَ إِمَّا لَا فَأَعِنِّي بِكَثْرَةِ السُّجُودِ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Khalid] yaitu Al Washiti, berkata; telah menceritakan kepada kami ['Amr bin Yahya Al Anshary] dari [Ziyad bin Abu Ziyad] budak Bani Makhzum dari [pembantu Nabi] Shallallahu'alaihiwasallam, laki-laki atau perempuan, berkata; Nabi Shallallahu'alaihiwasallam pernah berkata kepada pelayannya, \"Mungkin engkau mempunyai keperluan?\" (Ziyad bin Abu Ziyad) berkata; hingga pada suatu hari dia berkata; \"Wahai Rasulullah, aku punya keperluan ya Rasulullah\" Rasulullah Shallallahu'alaihiwasallam bertanya, \"Apa keperluanmu\"? pembantu tersebut berkata; \"Berilah syafaat kepadaku pada Hari Kiamat\" (Rasulullah Shallallahu'alaihiwasallam) bertanya kembali, \"Siapakah yang menunjukkan kepadamu perkara ini?\" dia menjawab, \"Rabbku\" (Rasulullah Shallallahu'alaihiwasallam) bersabda padanya, \"Bantulah diriku agar bisa memberi syafaat kepadamu dengan memperbanyak sujud.\""},"862":{"ar":"حَدَّثَنَا حُجَيْنُ بْنُ الْمُثَنَّى أَبُو عُمَرَ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ يَعْنِي ابْنَ عَبْدِ اللَّهِ بْنِ أَبِي سَلَمَةَ عَنْ عَبْدِ اللَّهِ بْنِ الْفَضْلِ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ جَعْفَرِ بْنِ عَمْرٍو الضَّمْرِيِّ قَالَخَرَجْتُ مَعَ عُبَيْدِ اللَّهِ بْنِ عَدِيِّ بْنِ الْخِيَارِ إِلَى الشَّامِ فَلَمَّا قَدِمْنَا حِمْصَ قَالَ لِي عُبَيْدُ اللَّهِ هَلْ لَكَ فِي وَحْشِيٍّ نَسْأَلُهُ عَنْ قَتْلِ حَمْزَةَ قُلْتُ نَعَمْ وَكَانَ وَحْشِيٌّ يَسْكُنُ حِمْصَ قَالَ فَسَأَلْنَا عَنْهُ فَقِيلَ لَنَا هُوَ ذَاكَ فِي ظِلِّ قَصْرِهِ كَأَنَّهُ حَمِيتٌ قَالَ فَجِئْنَا حَتَّى وَقَفْنَا عَلَيْهِ فَسَلَّمْنَا فَرَدَّ عَلَيْنَا السَّلَامَ قَالَ وَعُبَيْدُ اللَّهِ مُعْتَجِرٌ بِعِمَامَتِهِ مَا يَرَى وَحْشِيٌّ إِلَّا عَيْنَيْهِ وَرِجْلَيْهِ فَقَالَ عُبَيْدُ اللَّهِ يَا وَحْشِيُّ أَتَعْرِفُنِي قَالَ فَنَظَرَ إِلَيْهِ ثُمَّ قَالَ لَا وَاللَّهِ إِلَّا أَنِّي أَعْلَمُ أَنَّ عَدِيَّ بْنَ الْخِيَارِ تَزَوَّجَ امْرَأَةً يُقَالُ لَهَا أُمُّ قِتَالٍ ابْنَةُ أَبِي الْعِيصِ فَوَلَدَتْ لَهُ غُلَامًا بِمَكَّةَ فَاسْتَرْضَعَهُ فَحَمَلْتُ ذَلِكَ الْغُلَامَ مَعَ أُمِّهِ فَنَاوَلْتُهَا إِيَّاهُ فَلَكَأَنِّي نَظَرْتُ إِلَى قَدَمَيْكَ قَالَ فَكَشَفَ عُبَيْدُ اللَّهِ وَجْهَهُ ثُمَّ قَالَ أَلَا تُخْبِرُنَا بِقَتْلِ حَمْزَةَ قَالَ نَعَمْ إِنَّ حَمْزَةَ قَتَلَ طُعَيْمَةَ بْنَ عَدِيٍّ بِبَدْرٍ فَقَالَ لِي مَوْلَايَ جُبَيْرُ بْنُ مُطْعِمٍ إِنْ قَتَلْتَ حَمْزَةَ بِعَمِّي فَأَنْتَ حُرٌّ فَلَمَّا خَرَجَ النَّاسُ يَوْمَ عِينِينَ قَالَ وَعِينِينُ جُبَيْلٌ تَحْتَ أُحُدٍ وَبَيْنَهُ وَادٍ خَرَجْتُ مَعَ النَّاسِ إِلَى الْقِتَالِ فَلَمَّا أَنْ اصْطَفُّوا لِلْقِتَالِ قَالَ خَرَجَ سِبَاعٌ مَنْ مُبَارِزٌ قَالَ فَخَرَجَ إِلَيْهِ حَمْزَةُ بْنُ عَبْدِ الْمُطَّلِبِ فَقَالَ سِبَاعُ بْنُ أُمِّ أَنْمَارٍ يَا ابْنَ مُقَطِّعَةِ الْبُظُورِ أَتُحَادُّ اللَّهَ وَرَسُولَهُ ثُمَّ شَدَّ عَلَيْهِ فَكَانَ كَأَمْسِ الذَّاهِبِ وَأَكْمَنْتُ لِحَمْزَةَ تَحْتَ صَخْرَةٍ حَتَّى إِذَا مَرَّ عَلَيَّ فَلَمَّا أَنْ دَنَا مِنِّي رَمَيْتُهُ بِحَرْبَتِي فَأَضَعُهَا فِي ثُنَّتِهِ حَتَّى خَرَجَتْ مِنْ بَيْنِ وَرِكَيْهِ قَالَ فَكَانَ ذَلِكَ الْعَهْدُ بِهِ قَالَ فَلَمَّا رَجَعَ النَّاسُ رَجَعْتُ مَعَهُمْ قَالَ فَأَقَمْتُ بِمَكَّةَ حَتَّى فَشَا فِيهَا الْإِسْلَامُ قَالَ ثُمَّ خَرَجْتُ إِلَى الطَّائِفِ قَالَ فَأَرْسَلَ إِلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَقِيلَ لَهُ إِنَّهُ لَا يَهِيجُ لِلرُّسُلِ قَالَ فَخَرَجْتُ مَعَهُمْ حَتَّى قَدِمْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَلَمَّا رَآنِي قَالَ أَنْتَ وَحْشِيٌّ قَالَ قُلْتُ نَعَمْ قَالَ أَنْتَ قَتَلْتَ حَمْزَةَ قَالَ قُلْتُ قَدْ كَانَ مِنْ الْأَمْرِ مَا بَلَغَكَ يَا رَسُولَ اللَّهِ إِذْ قَالَ مَا تَسْتَطِيعُ أَنْ تُغَيِّبَ عَنِّي وَجْهَكَ قَالَ فَرَجَعْتُ فَلَمَّا تُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَخَرَجَ مُسَيْلِمَةُ الْكَذَّابُ قَالَ قُلْتُ لَأَخْرُجَنَّ إِلَى مُسَيْلِمَةَ لَعَلِّي أَقْتُلُهُ فَأُكَافِئَ بِهِ حَمْزَةَ قَالَ فَخَرَجْتُ مَعَ النَّاسِ فَكَانَ مِنْ أَمْرِهِمْ مَا كَانَ قَالَ فَإِذَا رَجُلٌ قَائِمٌ فِي ثَلْمَةِ جِدَارٍ كَأَنَّهُ جَمَلٌ أَوْرَقُ ثَائِرٌ رَأْسُ��ُ قَالَ فَأَرْمِيهِ بِحَرْبَتِي فَأَضَعُهَا بَيْنَ ثَدْيَيْهِ حَتَّى خَرَجَتْ مِنْ بَيْنِ كَتِفَيْهِ قَالَ وَوَثَبَ إِلَيْهِ رَجُلٌ مِنْ الْأَنْصَارِ قَالَ فَضَرَبَهُ بِالسَّيْفِ عَلَى هَامَتِهِقَالَ عَبْدُ اللَّهِ بْنُ الْفَضْلِ فَأَخْبَرَنِي سُلَيْمَانُ بْنُ يَسَارٍ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ بْنَ عُمَرَ فَقَالَتْ جَارِيَةٌ عَلَى ظَهْرِ بَيْتٍ وَأَمِيرُ الْمُؤْمِنِينَ قَتَلَهُ الْعَبْدُ الْأَسْوَدُ","id":"Telah menceritakan kepada kami [Hujain bin Al Mustanna, Abu 'Umar] berkata; telah menceritakan kepada kami [Abdul Aziz] yaitu Ibnu Abdullah bin Abu Salamah dari [Abdullah bin Al Fadl] dari [Sulaiman bin Yasar] dari [Ja'far bin 'Amr Ad-Dlamry] berkata; saya keluar bersama 'Ubaidullah bin 'Ady bin Hiyar ke Syam. Ketika kami sampai ke Himsh, 'Ubaidullah berkata kepadaku, \"Bagaimana kalau kita ke Wahsy dan bertanya tentang pembunuhan Hamzah\", saya menjawab, \"Baiklah\". [Wahsy] ketika itu bertempat tinggal di Himsh. (Ja'far bin 'Amr Ad-Dlamry) berkata; kami bertanya tentang dia, maka ditunjukkan kepada kami bahwa Wahsy saat itu berada di bawah istana seakAn akan dia geriba (kantong air dari kulit) yang berisi minyak samin. (Ja'far bin 'Amr Ad-Dlamry) berkata; kami mendatanginya sampai kami di hadapannya, kami mengucapkan salam, lalu dia membalasnya. 'Ubaidullah melipat penutup kepalanya, sehingga Wahsy tidak dapat melihatnya kecuali kedua mata Ubaidullah dan kedua kakinya. 'Ubaidullah bertanya, \"Wahai Wahsy, apa engkau mengenaliku\"?, maka Wahsy memperhatikannya, lalu berkata; \"Demi Allah, tidak. Aku tidak mengenalimu, kecuali aku tahu bahwa 'Ady bin Khiyar menikah dengan seorang perempuan yang disebut dengan Ummu Qital putri Abu Al 'Ish. Lalu lahirlah seorang anak di Makkah, maka dia dimintakan untuk disusukan kepada orang lain lalu aku membawa anak kecil itu sama ibunya, lalu aku serahkan kepadanya, maka seakAn akan aku melihatnya sama jika melihat ke kedua kakimu\" (Ja'far bin 'Amr Ad-Dlamry) berkata; lalu 'Ubaidullah menyingkapkan wajahnya, lalu berkata; \"Maukah engkau menceritakan kepada kami tentang terbunuhnya Hamzah\"? dia menjawab, \"Ya, Hamzah membunuh Tu'aimah bin 'Ady pada Perang Badar, lalu tuanku, Zubair bin Muth'im berkata kepadaku, jika kamu dapat membunuh Hamzah sebagai balas dendam kematian pamanku, kamu menjadi bebas. Ketika orang-orang serentak keluar ke 'Innin, yaitu sebuah gunung kecil di bawah Uhud yang terpisah dengan bukit, saya keluar bersama mereka untuk ikut serta perang. Ketika pasukan telah berbaris untuk berperang, maka keluarlah para pendekar untuk maju ke depan, ketika itu keluarlah Hamzah bin Abdul Al Munthalib, lalu Siba' bin Ummi Anmar berkata; \"Wahai anak potongan bagian dari kemaluan perempuan, apakah kamu akan memerangi Allah dan Rasul-Nya \" kemudian Hamzah menghabisinya, kemudian aku secara diam-diam mengincar Hamzah di bawah bebatuan, sampai ketika dia melewatiku. Tatkala dia sangat dekat denganku, saya lemparkan tombakku dan mengenai daerah bawah perutnya sehingga keluarlah apa yang di dalam daerah yang terkena lemparan tombak tersebut. (Wahsy) berkata; dan itulah apa yang akan menjadi janjiku. Ketika orang-orang balik pulang, sayapun bersama mereka. (Wahsy) berkata; saya tinggal di Makkah sampai Islam tersebar di sana. Saya keluar ke Thaif. lalu Rasulllah Shallallahu'alaihiwasallam mengirimkan suatu utusan kepadaku, dan mengajakku bicara, sang utusan mengatakan bahwa beliau tidak marah terhadapnya. Aku pun pergi bersama mereka sampai aku temui Rasulullah Shallallahu'alaihiwasallam. Ketika beliau melihatku, beliau bertanya, \"Apakah engkau wahsy?\" saya menjawab, \"Benar\". Beliau bersabda: \"Kamu yang telah membunuh Hamzah?\" (Wahsy) berkata; urusan tentang pembunuhan itu telah sampai kepada anda, Wahai Rasulullah\", dan beliau bersabda: \"Dapatkah kamu menjauhkan wajahmu dariku?\" (Wahsy) berkata; lalu saya kembali pulang, ketika Rasulullah Shallallahu'alaihiwasallam meninggal dan muncul nabi palsu Musailamah Al Kadzab, saya bertekad, \"Sayan akan menjumpai Musailamah, semoga saya dapat membunuhnya dan menebus kesalahan karena membunuh Hamzah\", lalu saya keluar bersama orang-orang yang akan memerangi Musailamah. Saya melihat seorang laki-laki berdiri di salah satu dinding rumah seakAn akan unta yang berambut ikal kepalanya. Ketika itu saya lemparkan tombakku dan mengenai tepat di tengah dadanya, sehingga keluar dari antara kedua pundaknya. (Wahsy) berkata; lalu ada seorang laki-laki Anshar yang melompat kepadanya dan menghunuskan pedang ke kepalanya\". [Abdullah bin Al Fadl] berkata; telah mengabarkan kepadaku, [Sulaiman bin Yasar] mendengar [Abdullah bin 'Umar] lalu ada seorang wanita yang berada di dalam rumahnya berkata; dan yang membunuh Amirul Mukminin, Al 'Abd Al Aswad."},"863":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ عَبْدِ رَبِّهِ قَالَ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ وَحْشِيِّ بْنِ حَرْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَجُلًا قَالَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّا نَأْكُلُ وَمَا نَشْبَعُ قَالَ فَلَعَلَّكُمْ تَأْكُلُونَ مُفْتَرِقِينَ اجْتَمِعُوا عَلَى طَعَامِكُمْ وَاذْكُرُوا اسْمَ اللَّهِ تَعَالَى عَلَيْهِ يُبَارَكْ لَكُمْ فِيهِ","id":"Telah menceritakan kepada kami [Yazid bin Abdurobbih] berkata; telah menceritakan kepada kami [Al Walid bin Muslim] dari [Wahsy bin Harb] dari [bapaknya] dari [kakeknya] ada seorang laki-laki berkata kepada Nabi Shallallahu'alaihiwasallam, kami makan, tapi tidak merasakan kenyang. (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Mungkin kalian makan dengan berpencar-pencar, maka berkumpullah ketika makan, dan sebutlah nama Allah Ta'ala, semoga kalian akan diberi berkah di dalamnya\""},"864":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا مَعْمَرٌ عَنْ عُثْمَانَ بْنِ زُفَرَ عَنْ بَعْضِ بَنِي رَافِعِ بْنِ مَكِيثٍ عَنْ رَافِعِ بْنِ مَكِيثٍ وَكَانَ مِمَّنْ شَهِدَ الْحُدَيْبِيَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ حُسْنُ الْخُلُقِ نَمَاءٌ وَسُوءُ الْخُلُقِ شُؤْمٌ وَالْبِرُّ زِيَادَةٌ فِي الْعُمُرِ وَالصَّدَقَةُ تَمْنَعُ مِيتَةَ السَّوْءِ","id":"Telah menceritakan kepada kami [Abdurrozzaq] berkata; telah mengabarkan kepada kami [Ma'mar] dari ['Utsman bin Zufar] dari [sebagian Bani Rafi' bin Makits] dari [Rafi' bin Makits] dia salah satu yang ikut dalam Peristiwa Hudaibiyah, Nabi Shallallahu'alaihiwasallam bersabda: \"Akhlaq yang baik akan berkembang, dan akhlaq yang buruk adalah tercela, kebaikan adalah menambah umur dan sedekah mencegah dari bangkai keburukan\""},"865":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا ابْنُ جُرَيْجٍ حَدَّثَنِي ابْنُ شِهَابٍ أَنَّ الْحُسَيْنَ بْنَ السَّائِبِ بْنِ أَبِي لُبَابَةَ أَخْبَرَهُأَنَّ أَبَا لُبَابَةَ عَبْدَ الْمُنْذِرِ لَمَّا تَابَ اللَّهُ عَلَيْهِ قَالَ يَا رَسُولَ اللَّهِ إِنَّ مِنْ تَوْبَتِي إِلَى اللَّهِ عَزَّ وَجَلَّ أَنْ أَهْجُرَ دَارَ قَوْمِي وَأُسَاكِنَكَ وَأَنْ أَنْخَلِعَ مِنْ مَالِي صَدَقَةً لِلَّهِ عَزَّ وَجَلَّ وَلِرَسُولِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُجْزِئُ عَنْكَ الثُّلُثُ","id":"Telah menceritakan kepada kami [Rouh] telah menceritakan kepada kami [Ibnu Juraij] telah menceritakan kepadaku [Ibnu Syihab] [Al Husain bin As-Sa`Ib bin Abu Lubabah] mengabarinya, [Abu lubabah, Abdul Mundzir], ketika Allah menerima taubahnya, dia berkata; \"Wahai Rasulullah, bagian dari taubatku kepada Allah Azzawajalla: saya berhijrah dari rumah kaumku dan bertempat dekat denganmu, melepaskan dari hartaku sebagai sedekah kepada Allah Azzawajalla dan Rasul-Nya\". Lalu Rasulullah Shallallahu'alaihiwasallam bersabda: \"Cukup bagimu dengan sepertiga hartamu saja\"."},"866":{"ar":"قَالَ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا الْعَطَّافُ قَالَ حَدَّثَنِي مُجَمِّعُ بْنُ يَعْقُوبَ عَنْ غُلَامٍ مِنْ أَهْلِ قُباءٍ أَنَّهُ أَدْرَكَهُ شَيْخًا أَنَّهُ قَالَجَاءَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقُبَاءٍ فَجَلَسَ فِي فَيْءِ الْأَحْمَرِ وَاجْتَمَعَ إِلَيْهِ نَاسٌ فَاسْتَسْقَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسُقِيَ فَشَرِبَ وَأَنَا عَنْ يَمِينِهِ وَأَنَا أَحْدَثُ الْقَوْمِ فَنَاوَلَنِي فَشَرِبْتُ وَحَفِظْتُ أَنَّهُ صَلَّى بِنَا يَوْمَئِذٍ الصَّلَاةَ وَعَلَيْهِ نَعْلَاهُ لَمْ يَنْزِعْهُمَا","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Yunus bin Muhammad] berkata; telah menceritakan kepada kami [Al 'Atthaf] berkata; telah menceritakan kepadaku [Mujamma' bin Yaqub] dari [seorang pemuda dari penduduk Quba`] yang telah tua, dia berkata; Rasulullah Shallallahu'alaihiwasallam datang ke Quba', beliau duduk di bawah bayangan merah setelah matahari tergelincir, orang-orang pun duduk mengelilingi beliau. Lantas Rasulullah Shallallahu'alaihiwasallam meminta air minum, beliau pun diberi dan minum. Saya pada saat itu masih sangat muda, berada di posisi kanan beliau. Lantas beliau memberikan kepadaku dan aku meminumnya. Aku ingat betul bahwa waktu itu (Rasulullah Shallallahu'alaihiwasallam) menjadi imam bagi kita dan beliau memakai sandal dan tidak melepasnya.\""},"867":{"ar":"قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ عَنْ أَبِي وَائِلٍ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ زَيْنَبَ امْرَأَةِ عَبْدِ اللَّهِ أَنَّهَا قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلنِّسَاءِ تَصَدَّقْنَ وَلَوْ مِنْ حُلِيِّكُنَّ قَالَتْ فَكَانَ عَبْدُ اللَّهِ خَفِيفَ ذَاتِ الْيَدِ فَقَالَتْ لَهُ أَيَسَعُنِي أَنْ أَضَعَ صَدَقَتِي فِيكَ وَفِي بَنِي أَخِي أَوْ بَنِي أَخٍ لِي يَتَامَى فَقَالَ عَبْدُ اللَّهِ سَلِي عَنْ ذَلِكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِذَا عَلَى بَابِهِ امْرَأَةٌ مِنْ الْأَنْصَارِ يُقَالُ لَهَا زَيْنَبُ تَسْأَلُ عَمَّا أَسْأَلُ عَنْهُ فَخَرَجَ إِلَيْنَا بِلَالٌ فَقُلْنَا انْطَلِقْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَلْهُ عَنْ ذَلِكَ وَلَا تُخْبِرْ مَنْ نَحْنُ فَانْطَلَقَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَنْ هُمَا فَقَالَ زَيْنَبُ فَقَالَ أَيُّ الزَّيَانِبِ فَقَالَ زَيْنَبُ امْرَأَةُ عَبْدِ اللَّهِ وَزَيْنَبُ الْأَنْصَارِيَّةُ فَقَالَ نَعَمْ لَهُمَا أَجْرَانِ أَجْرُ الْقَرَابَةِ وَأَجْرُ الصَّدَقَةِقَالَ حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا الْأَعْمَشُ عَنْ مَنْصُورٍ عَنْ عَمْرِو بْنِ الْحَارِثِ بْنِ الْمُصْطَلِقِ عَنْ زَيْنَبَ امْرَأَةِ عَبْدِ اللَّهِ قَالَتْ أَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالصَّدَقَةِ فَقَالَ تَصَدَّقْنَ يَا مَعْشَرَ النِّسَاءِ فَذَكَرَ الْحَدِيثَ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا سُفْيَانُ عَنِ الْأَعْمَشِ عَنْ شَقِيقٍ عَنْ عَمْرِو بْنِ الْحَارِثِ بْنِ الْمُصْطَلِقِ عَنْ زَيْنَبَ قَالَتْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَصَدَّقْنَ يَا مَعْشَرَ النِّسَاءِ فَذَكَرَهُ","id":"(Ahmad bin hanbal) berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] berkata; telah menceritakan kepada kami [Syu'bah] dari [Sulaiman] dari [Abu Wa`il] dari ['Amr bin Al Harits] dari [Zainab, istri Abdullah] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda kepada para wanita, \"Bersedekahlah kalian, walaupun dengan perhiasan kalian!\" (Zainab) berkata; \"Abdullah adalah orang yang ringan tangannya (suka membantu) \", aku pun berkata kepadanya, \"Bolehkan aku bersedekah untukmu atau kepada kaum saudaraku ataupun anak saudaraku yang yatim?.\" Abdullah menjawab, \"Coba tanyakan saja hal itu kepada Nabi Shallallahu'alaihiwasallam\". (Zainab) berkata; kontan saya temui Nabi Shallallahu'alaihiwasallam, ketika saya sampai di pintu rumahnya, aku mendapati ada seorang perempuan yang bernama Zainab, kebetulan ia hendak bertanya beliau sebagaimana yang hendak aku tanyakan, lalu Bilal keluar menemui kami. Kami berkata; \"Temuilah Rasulullah Shallallahu'alaihiwasallam dan tanyakanlah hal itu kepada beliau, tapi janganlah engkau beritahukan siapa kami sebenarnya.\" Lalu (Bilal) menemui Rasulullah Shallallahu'alaihiwasallam, dan beliau bertanya, \"Siapa dua orang perempuan tadi?\", Bilal berkata; Zainab. (Rasulullah Shallallahu'alaihiwasallam) bertanya, Zainab yang mana? Dia menjawab, Zainab istri Abdullah dan Zainab wanita Anshar. Beliau menjawab, \"Ya, mereka mendapatkan dua pahala, yaitu pahala sedekah dan pahala kekerabatan.\" (Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [Al A'masy] dari [Manshur] dari ['Amr bin Al Harits bin Al Musthaliq] dari [Zainab istri Abdullah] berkata; Rasulullah Shallallahu'alaihiwasallam menyuruh kami untuk bersedekah. Beliau bersabda: \"Wahai kaum wanita, bersedekahlah kalian\", lalu menyebutkan seperti dalam hadis di atas. (Ahmad bin hanbal) berkata; telah menceritakan kepada kami [Abdurrazaq] berkata; telah mengabarkan kepada kami [Sufyan] dari [Al A'masy] dari [Syaqiq] dari ['Amr bin Al Harits bin Al Musthaliq] dari [Zainab] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Bersedekahlah kalian, wahai kaum wanita\", lalu menyebutkannya."},"868":{"ar":"قَالَ قَالَ حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ حَدَّثَنَا ابْنُ أَ��ِي الزِّنَادِ وَسُلَيْمَانُ بْنُ دَاوُدَ قَالَا حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ عُرْوَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَعَنْ رَائِطَةَ امْرَأَةِ عَبْدِ اللَّهِ وَكَانَتْ امْرَأَةً صَنَاعًا وَكَانَتْ تَبِيعُ وَتَصَدَّقُ فَقَالَتْ لِعَبْدِ اللَّهِ يَوْمًا لَقَدْ شَغَلْتَنِي أَنْتَ وَوَلَدُكَ فَمَا أَسْتَطِيعُ أَنْ أَتَصَدَّقَ مَعَكُمْ فَقَالَ مَا أُحِبُّ إِنْ لَمْ يَكُنْ فِي ذَلِكَ أَجْرٌ أَنْ تَفْعَلِي فَسَأَلَا عَنْ ذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَكِ أَجْرُ مَا أَنْفَقْتِ عَلَيْهِمْ","id":"(Abdullah bin Ahmad bin Hanbal) berkata; (Ahmad bin hanbal) berkata; telah menceritakan kepada kami [Husain bin Muhammad] telah menceritakan kepada kami [Ibnu Abu Az Zinad] dan [Sulaiman bin Daud] berkata; telah menceritakan kepada kami [Abdurrahman] dari [Bapaknya] dari ['Urwah] dari ['Ubaidullah bin Abdullah bin 'Utbah] dari [Ra`ithah, isteri Abdullah] dia adalah wanita yang rajin membuat kerajinan, dia berjualan dan bersedekah. Suatu hari dia berkata kepada Abdullah, \"Engkau dan anakmu telah menyibukkanku sehingga aku tidak dapat bersedekah\". Abdullah berkata; \"Kalaulah hal tersebut tidak mendapatkan pahala, maka aku tidak menyukainya untuk kamu kerjakan\". Lalu mereka berdua bertanya mengenai hal itu kepada Rasulullah Shallallahu'alaihiwasallam, dan beliau bersabda kepada istri Abdullah, \"Engkau mendapatkan pahala dari yang kamu belanjakan untuk mereka.\""},"869":{"ar":"قَالَ حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ قَالَ حَدَّثَنِي هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَعَنْ رَائِطَةَ امْرَأَةِ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ وَأُمِّ وَلَدِهِ وَكَانَتْ امْرَأَةً صَنَاعَ الْيَدِ قَالَ وَكَانَتْ تُنْفِقُ عَلَيْهِ وَعَلَى وَلَدِهِ مِنْ صَنْعَتِهَا قَالَتْ فَقُلْتُ لِعَبْدِ اللَّهِ بْنِ مَسْعُودٍ لَقَدْ شَغَلْتَنِي أَنْتَ وَوَلَدُكَ عَنْ الصَّدَقَةِ فَمَا أَسْتَطِيعُ أَنْ أَتَصَدَّقَ مَعَكُمْ بِشَيْءٍ فَقَالَ لَهَا عَبْدُ اللَّهِ وَاللَّهِ مَا أُحِبُّ إِنْ لَمْ يَكُنْ فِي ذَلِكَ أَجْرٌ أَنْ تَفْعَلِي فَأَتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي امْرَأَةٌ ذَاتُ صَنْعَةٍ أَبِيعُ مِنْهَا وَلَيْسَ لِي وَلَا لِوَلَدِي وَلَا لِزَوْجِي نَفَقَةٌ غَيْرَهَا وَقَدْ شَغَلُونِي عَنْ الصَّدَقَةِ فَمَا أَسْتَطِيعُ أَنْ أَتَصَدَّقَ بِشَيْءٍ فَهَلْ لِي مِنْ أَجْرٍ فِيمَا أَنْفَقْتُ قَالَ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْفِقِي عَلَيْهِمْ فَإِنَّ لَكِ فِي ذَلِكَ أَجْرَ مَا أَنْفَقْتِ عَلَيْهِمْ","id":"(Ahmad bin hanbal) berkata; telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [bapakku] dari [Ibnu Ishaq] berkata; telah menceritakan kepadaku [Hisyam bin 'Urwah] dari [Bapaknya] dari ['Ubaidullah bin Abdullah bin 'Utbah] dari [Ra`ithah], istri Abdullah bin Mas'ud, dan ibu dari anaknya, dia adalah seorang yang biasa membuat kerajinan. ('Urwah) berkata; dia berinfak kepada (Abdullah) dan anaknya dari hasil kerjanya. Dia berkata; saya berkata kepada Abdullah bin Mas'ud, kamu dan anakmu telah menyibukkanku dari bersedekah, sehingga saya tidak bisa bersedekah bersama kalian. Abdullah berkata kepadanya 'Demi Allah, saya tidak suka kamu melakukannya jika kamu tidak mendapatkan pahala dari hal itu.' Raitah kontan mendatangi Rasulullah Shallallahu'alaihiwasallam dan berkata; 'Wahai Rasulullah, saya seorang wanita yang punya ketrampilan, yang hasilnya bisa saya jual, namun anak dan suamiku tidak ada nafkahnya selainnya, namun selanjutnya mereka menyibukkanku sehingga aku tidak bisa bersedekah, apakah saya mendapatkan pahala dari apa yang saya belanjakan?. Rasulullah Shallallahu'alaihiwasallam bersabda: \"Berinfaklah kepada mereka, karena hal itu menjadi pahala bagimu.\""},"870":{"ar":"قَالَ حَدَّثَنَا ابْنُ فُضَيْلٍ عَنْ يَزِيدَ عَنْ سُلَيْمَانَ بْنِ عَمْرِو بْنِ الْأَحْوَصِ عَنْ أُمِّهِ قَالَتْرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْمِي جَمْرَةَ الْعَقَبَةِ مِنْ بَطْنِ الْوَادِي يَوْمَ النَّحْرِ وَهُوَ يَقُولُ يَا أَيُّهَا النَّاسُ لَا يَقْتُلُ بَعْضُكُمْ وَلَا يُصِيبُ بَعْضُكُمْ وَإِذَا رَمَيْتُمْ الْجَمْرَةَ فَارْمُوهَا بِمِثْلِ حَصَى الْخَذْفِ فَرَمَى بِسَبْعٍ وَلَمْ يَقِفْ وَخَلْفَهُ رَجُلٌ يَسْتُرُهُ قُلْتُ مَنْ هَذَا قَالُوا الْفَضْلُ بْنُ الْعَبَّاسِ","id":"(Ahmad bin hanbal) berkata; telah menceritakan kepada kami [Ibnu Fudlail] dari [Yazid] dari [Sulaiman bin 'Amr bin Al Ahwash] dari [ibunya] berkata; Aku melihat Rasulullah Shallallahu'alaihiwasallam sedang melempar jumrah Aqabah di tengah bukit pada Hari Nahr, sambil bersabda: \"Wahai manusia, janganlah kalian membunuh sebagian kalian, melempari sebagian lainnya. Jika kalian melempar Jumrah, lakukan dengan kerikil\". Lalu beliau melemparkan tujuh kali, dan tidak berdiri. Di belakangnya ada seorang laki-laki yang menutupinya. Saya bertanya, \"Ini siapa\"? mereka menjawab, \"Al Fadl bin Al 'Abbas.\""},"871":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ سُلَيْمَانَ بْنِ عَمْرِو بْنِ الْأَحْوَصِ عَنْ أُمِّهِ وَكَانَتْ بَايَعَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْسَمِعْتُ رَسُولَ اللَّهِ يَقُولُ وَهُوَ يَرْمِي الْجَمْرَةَ مِنْ بَطْنِ الْوَادِي وَهُوَ يَقُولُ يَا أَيُّهَا النَّاسُ لَا يَقْتُلْ بَعْضُكُمْ بَعْضًا وَإِذَا رَأَيْتُمْ الْجَمْرَةَ فَارْمُوهَا بِمِثْلِ حَصَى الْخَذْفِ","id":"(Ahmad bin hanbal) berkata; telah menceritakan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Ma'mar] dari [Yazid bin Abu Ziyad] dari [Sulaiman bin 'Amr bin Al Ahwash] dari [ibunya] dia adalah termasuk orang yang berbaiat kepada Nabi Shallallahu'alaihiwasallam, dia berkata; saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda sambil melempar jumrah Aqabah di tengah bukit \"Wahai manusia, janganlah kalian membunuh sebagian kalian, Jika kalian melakukan Jumrah, lakukan saja dengan kerikil.\""},"872":{"ar":"قَالَ حَدَّثَنَا رَوْحٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ سُلَيْمَانَ بْنِ عَمْرِو بْنِ الْأَحْوَصِ الْأَزْدِيِّ عَنْ أُمِّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهَا سَمِعَتْهُ يَقُولُ عِنْدَ جَمْرَةِ الْعَقَبَةِ يَا أَيُّهَا النَّاسُ لَا تَقْتُلُوا أَنْفُسَكُمْ وَارْمُوا الْجَمْرَةَ أَوْ الْجَمَرَاتِ بِمِثْلِ حَصَى الْخَذْفِهَذَا آخِرُ مُسْنَدِ الْمَكِّيِّينَ","id":"(Ahmad bin hanbal) berkata; telah menceritakan kepada kami [Rouh] berkata; telah menceritakan kepada kami [Syu'bah] dari [Yazid bin Abu Ziyad] dari [Sulaiman bin 'Amr bin Al Ahwash Al Azdi] dari [ibunya] dari Nabi Shallallahu'alaihiwasallam, dia mendengar (Rasulullah Shallallahu'alaihiwasallam) bersabda ketika di jumrah Aqabah \"Wahai manusia, janganlah kalian membunuh diri kalian, lemparlah Jumrah dengan kerikil.\""},"873":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ صَفْوَانَ بْنِ سُلَيْمٍ عَنْ نَافِعِ بْنِ جُبَيْرٍ عَنْ سَهْلِ بْنِ أَبِي حَثْمَةَيَبْلُغُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَقَالَ سُفْيَانُ مَرَّةً إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا صَلَّى أَحَدُكُمْ إِلَى سُتْرَةٍ فَلْيَدْنُ مِنْهَا مَا لَا يَقْطَعُ الشَّيْطَانُ عَلَيْهِ صَلَاتَهُ","id":"Telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Shafwan bin Sulaim] dari [Nafi' bin Jubair] dari [Sahl bin Abu Hatsmah] sampai kepadanya bahwa Nabi Shallallahu'alaihiwasallam, --di lain waktu Sufyan berkata dengan redaksi Rasulullah (bukan nabi) Shallallahu'alaihiwasallam-- bersabda: \"Jika salah seorang di antara kalian shalat dengan pembatas, mendekatlah kepada pembatas tersebut, sehingga setan tidak dapat memotong shalatnya.\""},"874":{"ar":"قَالَ أَخْبَرَنَا سُفْيَانُ عَنْ يَحْيَى بْنِ سَعِيدٍ سَمِعَ بُشَيْرَ بْنَ يَسَارٍ مَوْلَى بَنِي حَارِثَةَ قَالَ سُفْيَانُ هَذَا حَدِيثُ ابْنِ حَثْمَةَ يُخْبِرُ عَنْ سَهْلِ بْنِ أَبِي حَثْمَةَوَوُجِدَ عَبْدُ اللَّهِ بْنُ سَهْلٍ مِنْ الْأَنْصَارِ قَتِيلًا فِي قَلِيبٍ مِنْ قُلُبِ خَيْبَرَ فَجَاءَ عَمَّاهُ وَأَخُوهُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخُوهُ عَبْدُ الرَّحْمَنِ بْنُ سَهْلٍ وَعَمَّاهُ حُوَيِّصَةُ وَمُحَيِّصَةُ فَذَهَبَ عَبْدُ الرَّحْمَنِ يَتَكَلَّمُ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ الْكِبَرَ الْكِبَرَ فَتَكَلَّمَ أَحَدُ عَمَّيْهِ إِمَّا حُوَيِّصَةُ وَإِمَّا مُحَيِّصَةُ قَالَ سُفْيَانُ نَسِيتُ أَيُّهُمَا الْكَبِيرُ مِنْهُمَا فَقَالَ يَا رَسُولَ اللَّهِ إِنَّا وَجَدْنَا عَبْدَ اللَّهِ قَتِيلًا فِي قَلِيبٍ مِنْ قُلُبِ خَيْبَرَ ثُمَّ ذَكَرَ يَهُودَ وَشَرَّهُمْ وَعَدَاوَتَهُمْ قَالَ لِيُقْسِمْ مِنْكُمْ خَمْسُونَ أَنَّ يَهُودَ قَتَلَتْهُ قَالُوا كَيْفَ نُقْسِمُ عَلَى مَا لَمْ نَرَ قَالَ فَتُبْرِئُكُمْ يَهُودُ بِخَمْسِينَ يَحْلِفُونَ أَنَّهُمْ لَمْ يَقْتُلُوهُ قَالُوا كَيْفَ نَرْضَى بِأَيْمَانِهِمْ وَهُمْ مُشْرِكُونَ قَالَ فَوَدَاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ عِنْدِهِ فَرَكَضَتْنِي بَكْرَةٌ مِنْهُقِيلَ لِسُفْيَانَ فِي الْحَدِيثِ وَتَسْتَحِقُّونَ دَمَ صَاحِبِكُمْ قَالَ هُوَ ذَا","id":"(Ahmad bin hanbal) berkata; telah mengabarkan kepada kami [Sufyan] dari [Yahya bin Sa'id] telah mendengar [Busyair bin Yasar] budak Bani Haritsah, Sufyan berkata; ini adalah hadis Ibnu Hatsmah, yang mengabari dari [Sahl bin Abu Hatsmah], Abdullah bin Sahl seseorang dari Anshar diketemukan terbunuh di salah satu sumur tua di Khaibar. Dua pamannya dan saudara laki-lakinya mengadukan perkaranya kepada Rasulullah Shallallahu'alaihiwasallam. saudaranya yaitu Abdurrahman bin Sahl dan dua pamannya yaitu Huwaishah dan Muhaishah. Abdurrahman berangkat dan menceritakan kasusnya di sisi Rasulullah Shallallahu'alaihiwasallam. Hanya nabi shallallahu 'alaihi wasallam bersabda 'Tolong yang menyampaikan yang tua, tolong yang menyampaikan yang tua.' Selanjutnya salah seorang pamannya, entah Huwaishah, entah Muhaishah menyampaikan uneg-unegnya. [Sufyan] berkata; saya lupa mana yang lebih tua di antara keduanya. Dia berkata; Wahai Rasulullah, kami mendapatkan Abdullah terbunuh di salah satu sumur tua di Khaibar, lalu dia ceritakan orang Yahudi dan kejelekannya dan permusuhannya. Beliau bersabda: \"Hendaklah di antara kalian lima puluh orang yang bersumpah bahwa orang yahudi itu yang membunuhnya\". Mereka berkata; bagaimana kami bersumpah terhadap sebuah kasus yang tidak kami lihat!. Beliau bersabda: \"Suruhlah orang Yahudi terbebaskan dari kalian dengan cara lima puluh dari mereka bersumpah bahwa mereka tidak membunuhnya!\" Mereka berkata; bagaimana kami rela dengan sumpah mereka, sedangkan mereka adalah orang musyrik?. Lalu Rasulullah Shallallahu'alaihiwasallam membayarkan diyatnya dari hartanya sendiri, dan untanya menendangku. Dikatakan kepada Sufyan dalam hadis, dan kalian berhak atas darah saudara kalian. Dia menjawab, ya. Seperti itu."},"875":{"ar":"قَالَ حَدَّثَنَا سُفْيَانُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ بُشَيْرِ بْنِ يَسَارٍ عَنْ سَهْلِ بْنِ أَبِي حَثْمَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ التَّمْرِ بِالتَّمْرِ وَرَخَّصَ فِي الْعَرَايَا أَنْ تُشْتَرَى بِخَرْصِهَا يَأْكُلُهَا أَهْلُهَا رُطَبًاقَالَ سُفْيَانُ قَالَ لِي يَحْيَى بْنُ سَعِيدٍ وَمَا عِلْمُ أَهْلِ مَكَّةَ بِالْعَرَايَا قُلْتُ أَخْبَرَهُمْ عَطَاءٌ سَمِعَهُ مِنْ جَابِرٍ","id":"(Ahmad bin hanbal) berkata; telah menceritakan kepada kami [Sufyan] dari [Yahya bin Sa'id] dari [Busyair bin Yasar] dari [Sahl bin Abu Hatsmah] berkata; Rasulullah melarang jual beli kurma dengan kurma tetapi beliau memberi pengecualian pada Al Araya yaitu pembelian kurma yang masih dalam batang pohonnya, sedang pemiliknya biasanya makan kurma yang masih mentah-mentah masak. Sufyan berkata; Yahya bin Sa'id berkata kepadaku, penduduk Makkah tidak mengetahui tentang Al Araya, lalu aku berkata; \"'Atho` telah mengabarkan kepada mereka, yang dia mendengarnya dari Jabir.\""},"876":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَ��َّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا خُبَيْبُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ مَسْعُودِ بْنِ نِيَارٍ عَنْ سَهْلِ بْنِ أَبِي حَثْمَةَ قَالَأَتَانَا وَنَحْنُ فِي مَسْجِدِنَا قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا خَرَصْتُمْ فَخُذُوا وَدَعُوا دَعُوا الثُّلُثَ فَإِنْ لَمْ تَدَعُوا أَوْ تَجُدُّوا شُعْبَةُ الشَّاكُّ الثُّلُثَ فَالرُّبُعَ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] berkata; telah menceritakan kepada kami [Syu'bah] berkata; telah menceritakan kepada kami [Khubaib bin Abdurrahman] dari [Abdurrahman bin Mas'ud bin Niyar] dari [Sahl bin Abu Hatsmah] berkata; telah kepada kami dan kami waktu itu di masjid kami, (Sahl bin Abu Hatsmah) berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jika kalian menaksir (kurma dalam pohon) maka ambillah dan tinggalkanlah sepertiganya, jika kalian tidak meninggalkannya atau kalian memanennya, --Syu'bah ragu kepastian redaksinya-- maka sepertiga atau seperempat."},"877":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي خُبَيْبُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ مَسْعُودِ بْنِ نِيَارٍ قَالَأَتَانَا سَهْلُ بْنُ أَبِي حَثْمَةَ فِي مَسْجِدِنَا فَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا خَرَصْتُمْ فَخُذُوا وَدَعُوا دَعُوا الثُّلُثَ فَإِنْ لَمْ تَجُدُّوا أَوْ تَدَعُوا فَالرُّبُعَ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Syu'bah] berkata; telah mengabarkan kepadaku [Khubaib bin Abdurrahman] dari [Abdurrahman bin Mas'ud bin Niyar] berkata; [Sahl bin Abu Hatsmah] menemui kami di masjid kami, lalu (Sahl bin Abu Hatsmah) berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jika kalian menaksir (kurma dalam pohon) maka ambillah dan tinggalkanlah sepertiganya, jika kalian tidak meninggalkannya atau memanennya maka seperempatnya."},"878":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الْقُدُّوسِ بْنُ بَكْرِ بْنِ خُنَيْسٍ قَالَ أَخْبَرَنَا حَجَّاجٌ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو وَالْحَجَّاجِ عَنْ مُحَمَّدِ بْنِ سُلَيْمَانَ بْنِ أَبِي حَثْمَةَ عَنْ عَمِّهِ سَهْلِ بْنِ أَبِي حَثْمَةَ قَالَكَانَتْ حَبِيبَةُ ابْنَةُ سَهْلٍ تَحْتَ ثَابِتِ بْنِ قَيْسِ بْنِ شَمَّاسٍ الْأَنْصَارِيِّ فَكَرِهَتْهُ وَكَانَ رَجُلًا دَمِيمًا فَجَاءَتْ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي لَأَرَاهُ فَلَوْلَا مَخَافَةُ اللَّهِ عَزَّ وَجَلَّ لَبَزَقْتُ فِي وَجْهِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَرُدِّينَ عَلَيْهِ حَدِيقَتَهُ الَّتِي أَصْدَقَكِ قَالَتْ نَعَمْ فَأَرْسَلَ إِلَيْهِ فَرَدَّتْ عَلَيْهِ حَدِيقَتَهُ وَفَرَّقَ بَيْنَهُمَا قَالَ فَكَانَ ذَلِكَ أَوَّلَ خُلْعٍ كَانَ فِي الْإِسْلَامِ","id":"(Ahmad bin hanbal) berkata; telah menceritakan kepada kami [Abdul Qudus bin Bakr bin Khunais] berkata; telah mengabarkan kepada kami [Hajjaj] dari ['Amr bin Syua'ib] dari [Bapaknya] dari [Abdullah bin 'Amr] dan [Al Hajjaj] dari [Muhammad bin Sulaiman bin Abu Khatsmah] dari [pamannya, Sahal bin Abu Khatsmah] berkata; \"Habibah anak perempuan Sahal diperistri oleh Tsabit bin Qais bin Syamas Al Anshory, dia seorang laki-laki yang buruk mukanya, dan perempuan tersebut membencinya. Lalu datang kepada Nabi Shallallahu'alaihiwasallam, berkata; \"Wahai Rasulullah, kalaulah bukan karena saya takut pada Allah, pastilah aku meludahi wajahnya\", lalu Rasulullah bersabda: \"Apakah engkau mau mengembalikan kebun yang telah dia berikan kepadamu?\" maka perempuan itu menjawab, \"Ya\". Selanjutnya dikirimlah (utusan) kepada Tsabit bin Qais dan dikembalikan kebunnya, keduanya kemudian bercerai. (Sahal bin Abu Khatsmah) berkata; itulah Khulu' (permintaan cerai dari pihak perempuan, pent) yang pertama dalam Islam."},"879":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ حَدَّثَنِي بُشَيْرُ بْنُ يَسَارٍ عَنْ سَهْلِ بْنِ أَبِي حَثْمَةَ قَالَخَرَجَ عَبْدُ اللَّهِ بْنُ سَهْلٍ أَخُو بَنِي حَارِثَةَ يَعْنِي فِي نَفَرٍ مِنْ بَنِي حَارِثَةَ إِلَى خَيْبَرَ يَمْتَارُونَ مِنْهَا تَمْرًا قَالَ فَعُدِيَ عَلَى عَبْدِ اللَّهِ بْنِ سَهْلٍ فَكُسِرَتْ عُنُقُهُ ثُمَّ طُرِحَ فِي مَنْهَرٍ مِنْ مَنَاهِرِ عُيُونِ خَيْبَرَ وَفَقَدَهُ أَصْحَابُهُ فَالْتَمَسُوهُ حَتَّى وَجَدُوهُ فَغَيَّبُوهُ قَالَ ثُمَّ قَدِمُوا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَقْبَلَ أَخُوهُ عَبْدُ الرَّحْمَنِ بْنُ سَهْلٍ وَابْنَا عَمِّهِ حُوَيِّصَةُ وَمُحَيِّصَةُ وَهُمَا كَانَا أَسَنَّ مِنْ عَبْدِ الرَّحْمَنِ وَكَانَ عَبْدُ الرَّحْمَنِ إِذًا أَقْدَمَ الْقَوْمِ وَصَاحِبَ الدَّمِ فَتَقَدَّمَ لِذَلِكَ فَكَلَّمَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبْلَ ابْنَيْ عَمِّهِ حُوَيِّصَةَ وَمُحَيِّصَةَ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْكِبَرَ الْكِبَرَ فَاسْتَأْخَرَ عَبْدُ الرَّحْمَنِ وَتَكَلَّمَ حُوَيِّصَةُ ثُمَّ تَكَلَّمَ مُحَيِّصَةُ ثُمَّ تَكَلَّمَ عَبْدُ الرَّحْمَنِ فَقَالُوا يَا رَسُولَ اللَّهِ عُدِيَ عَلَى صَاحِبِنَا فَقُتِلَ وَلَيْسَ بِخَيْبَرَ عَدُوٌّ إِلَّا يَهُودَ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تُسَمُّونَ قَاتِلَكُمْ ثُمَّ تَحْلِفُونَ عَلَيْهِ خَمْسِينَ يَمِينًا ثُمَّ تُسْلِمُهُ قَالَ فَقَالُوا يَا رَسُولَ اللَّهِ مَا كُنَّا لِنَحْلِفَ عَلَى مَا لَمْ نَشْهَدْ قَالَ فَيَحْلِفُونَ لَكُمْ خَمْسِينَ يَمِينًا وَيَبْرَءُونَ مِنْ دَمِ صَاحِبِكُمْ قَالُوا يَا رَسُولَ اللَّهِ مَا كُنَّا لِنَقْبَلَ أَيْمَانَ يَهُودَ مَا هُمْ فِيهِ مِنْ الْكُفْرِ أَعْظَمُ مِنْ أَنْ يَحْلِفُوا عَلَى إِثْمٍ قَالَ فَوَدَاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ عِنْدِهِ مِائَةَ نَاقَةٍقَالَ يَقُولُ سَهْلٌ فَوَاللَّهِ مَا أَنْسَى بَكْرَةً مِنْهَا حَمْرَاءَ رَكَضَتْنِي وَأَنَا أَحُوزُهَا","id":"Telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [bapakku] dari [Ibnu Ishaq] telah menceritakan kepadaku [Busyair bin Yasar] dari [Sahl bin Abu Hatsmah] berkata; Abdullah bin Sahl dari Bani Haritsah keluar bersama beberapa orang dari sukunya menuju Khaibar, hendak mengambil kurma. (Sahl bin Abu Hatsmah) berkata; Lalu Abdullah bin Sahl diculik, lehernya dipotong, dan dicampakkan di salah satu mata air Khaibar. Para sahabatnya merasa kehilangan dirinya, lalu mereka mencarinya sampai mereka mendapatkannya setelah lama hilang. Mereka datangi Rasulullah Shallallahu'alaihiwasallam. Selanjutnya saudaranya, Abdurrahman bin Sahl dan dua anak pamannya, yaitu Huwaishah dan Muhaishah datang, mereka berdua lebih tua daripada Abdurrahman. Abdurrahman adalah orang yang paling pemberani dan yang berhak menuntut darahnya. Karenanya dialah yang maju sebagai pembicara dan berkata kepada Rasulullah Shallallahu'alaihiwasallam sebelum kedua anak pamannya yaitu Huwaishah dan Muhaishah. Hanya Rasulullah Shallallahu'alaihiwasallam menegur, \"Maaf, yang bicara silahkan yang tua, yang bicara silahkan yang lebih tua\". Lalu Abdurrahman mundur dan Huwaishah berkata; dan diikuti Muhaishah. Lalu Abdurrahman juga berbicara, mereka berkata; Wahai Rasulullah, telah di culik saudara kami dan dibunuh dan kami tidak mempunyai musuh di Khaibar kecuali orang Yahudi. (Sahl bin Abu Hatsmah) berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tolong kalian sebutkan nama pembunuhnya lalu kalian bersumpah dengan cara menghadirkan lima orang diantara kalian yang kesemua bersumpah bahwa orang itu yang membunuhnya, setelah itu kaum yahudi harus menyerahkannya\". (Sahl bin Abu Hatsmah) berkata; kami bertiga berkata; \"Wahai Rasulullah, kami tidak akan bersumpah atas suatu kasus yang kami tidak menyaksikannya sendiri\". Beliau bersabda: \" Kalau begitu, suruhlah kaum yahudi untuk mendatangkan lima puluh orang dan kesemuanya bersumpah bahwa bukan dari merekalah yang membunuhnya dan mereka akan terlepas dari tuntutan darah sahabat kalian\". Mereka berkata; Wahai Rasulullah, kami tidak bakalan menerima sumpah orang Yahudi karena kekufuran yang mereka pegang teguh jauh lebih besar daripada sekedar melakukan sumpah dosa. (Sahl bin Abu Hatsmah) berkata; lalu Rasulullah Shallallahu'alaihiwasallam sendiri yang membayar diyatnya dengan seratus unta. (Busyair bin Yasar) berkata; Sahl berkata; demi Allah, saya tidak melupakan unta di antaranya yang berwarna merah yang menendangku ketika aku melewatinya."},"880":{"ar":"قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ إِدْرِيسَ الشَّافِعِيُّ قَالَ حَدَّثَنَا مَالِكٌ عَنِ أَبِي لَيْلَى بْنِ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ سَهْلِ بْنِ أَبِي حَثْمَةَ أَنَّ سَهْلَ بْنَ أَبِي حَثْمَةَ أَخْبَرَهُ وَرِجَالٌ مِنْ كُبَرَاءِ قَوْمِهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِحُوَيِّصَةَ وَمُحَيِّصَةَ وَعَبْدِ الرَّحْمَنِ أَتَحْلِفُونَ وَتَسْتَحِقُّونَ دَمَ صَاحِبِكُمْ قَالُوا لَا قَالَ فَتَحْلِفُ يَهُودُ قَالُوا لَيْسُوا بِمُسْلِمِينَ فَوَدَاهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ عِنْدِهِ","id":"(Ahmad bin hanbal) berkata; telah menceritakan kepada kami [Muhammad bin Idris Asy-Syafi'i] berkata; telah menceritakan kepada kami [Malik] dari [Abu Laila bin Abdullah bin Abdurrahman bin Sahl bin Abu Hatsmah], [Sahl bin Abu Hatsmah] mengabarinya dari [beberapa orang dari pembesar kaumnya], Rasulullah Shallallahu'alaihiwasallam bersabda kepada Huwaishah, Muhaishah dan Abdurrahman, Apakah kalian mau bersumpah dan berhak mendapatkan tuntutan darah sahabat kalian? Mereka berkata; 'Tidak.' Beliau bersabda: 'Kalau kalian tidak mau bersumpah, biarlah kaum yahudi yang bersumpah.' Mereka berkata 'Jangan, mereka bukan orang muslim' lalu Nabi Shallallahu'alaihiwasallam menebus diyatnya dari hartanya sendiri."},"881":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا سَعِيدُ بْنُ يَزِيدَ يَعْنِي أَبَا مَسْلَمَةَ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَسِيدٍ قَالَسَمِعْتُ رَجُلًا قَالَ لِابْنِ الزُّبَيْرِ أَفْتِنَا فِي نَبِيذِ الْجَرِّ فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى عَنْهُ","id":"Telah menceritakan kepada kami [Isma'il bin Ibrahim] telah menceritakan kepada kami [Sa'id bin Yazid] yaitu Abu Maslamah berkata; telah menceritakan kepada kami ['Abdul Aziz bin Usaid] berkata; Aku mendengar seorang laki-laki berkata kepada [Ibnu Zubair], \"Berilah kami fatwa tentang perasan kurma yang direndam dalam suatu bejana tanah liat\" (Abdul Aziz bin Usaid) berkata; aku mendengar Rasulullah melarang hal tersebut. "},"882":{"ar":"حَدَّثَنَا عَبْدُ الْقُدُّوسِ بْنُ بَكْرِ بْنِ خُنَيْسٍ قَالَ أَخْبَرَنَا حَجَّاجٌ عَنْ عَامِرِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ أَبِيهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ افْتَتَحَ الصَّلَاةَ فَرَفَعَ يَدَيْهِ حَتَّى جَاوَزَ بِهِمَا أُذُنَيْهِقَالَ قُرِئَ عَلَى سُفْيَانَ وَأَنَا شَاهِدٌ سَمِعْتُ ابْنَ عَجْلَانَ وَزِيَادَ بْنَ سَعْدٍ عَنْ عَامِرِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ أَبِيهِ قَالَ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْعُو هَكَذَا وَعَقَدَ ابْنُ الزُّبَيْرِ","id":"Telah menceritakan kepada kami [Abdulquddus bin Bakr bin Khunais] berkata; telah mengabarkan kepada kami [Hajjaj] dari ['Amir bin Abdullah Az Zubair] dari [Bapaknya] berkata; Aku melihat Rasulullah memulai shalat dan mengangkat kedua tangannya sampai melewati kedua daun telinganya. (Ahmad bin hanbal) berkata; dibacakan hadis ini di hadapan [Sufyan] dan aku menyaksikan, aku mendengar [Ibnu 'Ajlan] dan [Ziyad bin Sad] dari ['Amir bin Abdullah bin Zubair] dari [bapaknya] berkata; saya melihat Nabi Shallallahu'alaihiwasallam berdoa seperti ini dan Abu Zubair melipat tangannya."},"883":{"ar":"قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ أَبِي الْبَخْتَرِيِّ عَنْ عَبِيدَةَ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ رَجُلًا حَلَفَ بِاللَّهِ الَّذِي لَا إِلَهَ إِلَّا هُوَ كَاذِبًا فَغَفَرَ اللَّهُ لَهُقَالَ شُعْبَةُ مِنْ قَبْلِ التَّوْحِيدِ","id":"(Ahmad bin hanbal) berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] berkata; telah menceritakan kepada kami [Syu'bah] dari ['Atho` bin As-Sa`Ib] dari [Abu Al Bukhtari] dari ['Abidah] dari [Abdullah bin Az Zubair] dari Nabi Shallallahu'alaihiwasallam, ada seorang laki-laki bersumpah dengan nama Allah yang tidak ada ilah selain-Nya namun ia bohong dalam sumpahnya, maka Allah akan mengampuni dosanya, Syu'bah berkata; \"Itulah bagian dari tauhid\"."},"884":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ يُوسُفَ عَنِ ابْنِ الزُّبَيْرِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِرَجُلٍ أَنْتَ أَكْبَرُ وَلَدِ أَبِيكَ فَاحْجُجْ عَنْهُ","id":"Telah menceritakan kepada kami [Abdurrahman] dari [Sufyan] dari [Manshur] dari [Mujahid] dari [Yusuf] dari [Ibnu Zubair] Nabi Shallallahu'alaihiwasallam bersabda kepada seorang laki-laki, \"Kamu adalah yang paling tua dari anak bapakmu, maka hajikanlah bapakmu.\""},"885":{"ar":"قَالَ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنِي أَبِي عَنِ ابْنِ إِسْحَاقَ قَالَ حَدَّثَنِي أَبِي إِسْحَاقُ بْنُ يَسَارٍ قَالَإِنَّا لَبِمَكَّةَ إِذْ خَرَجَ عَلَيْنَا عَبْدُ اللَّهِ بْنُ الزُّبَيْرِ فَنَهَى عَنْ التَّمَتُّعِ بِالْعُمْرَةِ إِلَى الْحَجِّ وَأَنْكَرَ أَنْ يَكُونَ النَّاسُ صَنَعُوا ذَلِكَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَلَغَ ذَلِكَ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ فَقَالَ وَمَا عِلْمُ ابْنِ الزُّبَيْرِ بِهَذَا فَلْيَرْجِعْ إِلَى أُمِّهِ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ فَلْيَسْأَلْهَا فَإِنْ لَمْ يَكُنْ الزُّبَيْرُ قَدْ رَجَعَ إِلَيْهَا حَلَالًا وَحَلَّتْ فَبَلَغَ ذَلِكَ أَسْمَاءَ فَقَالَتْ يَغْفِرُ اللَّهُ لِابْنِ عَبَّاسٍ وَاللَّهِ لَقَدْ أَفْحَشَ قَدْ وَاللَّهِ صَدَقَ ابْنُ عَبَّاسٍ لَقَدْ حَلُّوا وَأَحْلَلْنَا وَأَصَابُوا النِّسَاءَ","id":"(Ahmad bin hanbal) berkata; telah menceritakan kepada kami [Ya'qub bin Ibrahim] berkata; telah menceritakan kepadaku [bapakku] dari [Ibnu Ishaq] berkata; telah menceritakan kepadaku [Abu Ishaq bin Yasar] berkata; \"Ketika kami sedang berada di Makkah, tiba-tiba Abdullah Bin Zubair menemui kami, beliau melarang Haji dengan cara tamattu' (melaksanakan umrah lantas diikuti haji) dan beliau mengingkari bahwa para sahabat pernah melakukan yang demikian bersama Rasulullah Shallallahu'alaihiwasallam. Hal tersebut sampai kepada [Abdullah bin 'Abbas], lalu dia berkata; apa yang diketahui oleh Ibnu Az Zubair tentang hal itu, hendaklah dia merujuk kepada ibunya [Asma` binti Abu Bakar], dan menanyakan kepadanya. Jika dia tidak mau merujuk kepadanya, maka berarti dia telah bertahalul dan juga ibunya. Hal itu sampai pada Asma`, lalu dia berkata; semoga Allah mengampuni Ibnu Abbas, demi Allah, dia telah berbuat kekejian. Demi Allah, Ibnu Abbas benar, mereka telah bertahallul dan juga kami dan mereka mendatangi para isteri-isterinya."},"886":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ قَالَ حَدَّثَنَا هِشَامٌ يَعْنِي ابْنَ عُرْوَةَ عَنْ أَبِي الزُّبَيْرِ قَالَكَانَ عَبْدُ اللَّهِ بْنُ الزُّبَيْرِ يَقُولُ فِي دُبُرِ كُلِّ صَلَاةٍ حِينَ يُسَلِّمُ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ لَا إِلَهَ إِلَّا اللَّهُ وَلَا نَعْبُدُ إِلَّا إِيَّاهُ وَلَهُ النِّعْمَةُ وَلَهُ الْفَضْلُ وَلَهُ الثَّنَاءُ الْحَسَنُ لَا إِلَهَ إِلَّا اللَّهُ مُخْلِصِينَ لَهُ الدِّينَ وَلَوْ كَرِهَ الْكَافِرُونَ قَالَ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُهَلِّلُ بِهِنَّ دُبُرَ كُلِّ صَلَاةٍ","id":"Telah menceritakan kepada kami [Abdullah bin Numair] berkata; telah menceritakan kepada kami [Hisyam] yaitu Ibnu 'Urwah dari [Abu Az Zubair] berkata; [Abdullah bin Az Zubair] memanjatkan doa-doa setelah melaksanakan shalat ketika salam, \"LA ILAHA ILLA ALLAH WAHDAHU LA SYARIKA LAHU, LAHUL MULKU WA LAHUL HAMDU WA HUWA ALA KULLI SYAIIN QODIIR. LA HAULA WALA QUWWATA ILLA BILLAH LA ILAHA ILLALLAHU WA LA NA'BUDU ILLA IYYAHU WA LAHU NI'MAH WA LAHUL FADLU WALAHU TSANAU AL HASAN LA ILLA HA ILLALLAH MUKHLISIINA LAHUDDINA WALAU KARIHAL KAFIRUN\" (Tidak ada tuhan selain Allah, dan tidak ada sekutu bagi-Nya dan Dia Maha Kuasa atas segala sesuatu. Tidak ada kekuatan selain kekuatan Allah bagi-Nya segala kenikmatan dan keutamaan yang baik, tidak ada tuhan selain Allah orang-orang yang ihlas baginya agama walaupun kaum kafir membencinya). (Abdullah bin Az Zubair) berkata; Rasulullah Shallallahu'alaihiwasallam membaca kalimat tahlil dengan kalimat tersebut setiap selesai shalat."},"887":{"ar":"حَدَّثَنَا مُوسَى بْنُ دَاوُدَ حَدَّثَنَا نَافِعٌ يَعْنِي ابْنَ عُمَرَ عَنِ ابْنِ أَبِي مُلَيْكَةَ فَقَالَ ابْنُ الزُّبَيْرِفَمَا كَانَ عُمَرُ يَسْمَعُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ هَذِهِ الْآيَةِ حَتَّى يَسْتَفْهِمَهُ يَعْنِي قَوْلَهُ تَعَالَى{ لَا تَرْفَعُوا أَصْوَاتَكُمْ فَوْقَ صَوْتِ النَّبِيِّ }","id":"Telah menceritakan kepada kami [Musa bin Daud] berkata; telah menceritakan kepada kami [Nafi'] yaitu Ibnu 'Umar dari [Ibnu Abu Mulaikah], [Ibnu Az Zubair] berkata; 'Umar tidak mau mendengar Nabi Shallallahu'alaihiwasallam setelah ayat ini, sampai dia meminta kefahaman yaitu firman (Allah) Ta'ala, 'Janganlah kalian mengangkat suara kalian di atas suara Nabi'.\""},"888":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ قَالَ فَحَدَّثَنِي وَهْبُ بْنُ كَيْسَانَ مَوْلَى ابْنِ الزُّبَيْرِ قَالَسَمِعْتُ عَبْدَ اللَّهِ بْنَ الزُّبَيْرِ فِي يَوْمِ الْعِيدِ يَقُولُ حِينَ صَلَّى قَبْلَ الْخُطْبَةِ ثُمَّ قَامَ يَخْطُبُ النَّاسَ يَا أَيُّهَا النَّاسُ كَذَا سُنَّةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim] berkata; telah menceritakan kepada kami [bapakku] dari [Ibnu Ishaq] berkata; telah menceritakan kepada kami [Wahab bin Kaisan] budak Ibnu Zubair, berkata; aku mendengar [Abdullah bin Zubair] pada Hari Raya ia melakukan shalat sebelum khutbah, kemudian berdiri dan berkhutbah di hadapan manusia, \"Wahai segenap manusia, beginilah sunnah Rasulullah Shallallahu'alaihiwasallam.\""},"889":{"ar":"قَالَ حَدَّثَنَا أَبُو سَلَمَةَ الْخُزَاعِيُّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي الْمَوَالِي قَالَ أَخْبَرَنِي نَافِعُ بْنُ ثَابِتٍ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى الْعِشَاءَ رَكَعَ أَرْبَعَ رَكَعَاتٍ وَأَوْتَرَ بِسَجْدَةٍ ثُمَّ نَامَ حَتَّى يُصَلِّيَ بَعْدَ صَلَاتِهِ بِاللَّيْلِ","id":"(Ahmad bin hanbal) berkata; telah menceritakan kepada kami [Abu Salamah Al Khuza'i] telah menceritakan kepada kami [Abdurrahman bin Abu Al Mawali] berkata; telah mengabarkan kepadaku [Nafi' bin Tsabit] dari [Abdullah bin Zubair] berkata; Rasulullah Shallallahu'alaihiwasallam apabila shalat isya', beliau lakukan dengan empat rakaat, kemudian beliau melakukan witir dengan satu sujud, kemudian tidur hingga beliau lakukan shalat di malam itu."},"890":{"ar":"قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ هِشَامٍ قَالَ أَخْبَرَنِي أَبِي عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُحَرِّمُ مِنْ الرَّضَاعِ الْمَصَّةُ وَالْمَصَّتَانِ","id":"(Ahmad bin hanbal) berkata; Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Hisyam] berkata; telah mengabarkan kepadaku [bapakku] dari [Abdullah bin Zubair] Nabi Shallallahu'alaihiwasallam bersabda: \"Tidaklah menjadi mahram dari sepersusuan jika hanya karena satu atau dua kali sedotan.\""},"891":{"ar":"قَالَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ جَامِعِ بْنِ أَبِي رَاشِدٍ وَعَاصِمٍ عَنْ أَبِي وَائِلٍ عَنْ قَيْسِ بْنِ أَبِي غَرَزَةَ قَالَكُنَّا نُسَمَّى السَّمَاسِرَةَ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَانَا بِالْبَقِيعِ فَقَالَ يَا مَعْشَرَ التُّجَّارِ فَسَمَّانَا بِاسْمٍ أَحْسَنَ مِنْ اسْمِنَا إِنَّ الْبَيْعَ يَحْضُرُهُ الْحَلِفُ وَالْكَذِبُ فَشُوبُوهُ بِالصَّدَقَةِ","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Jami' bin Abu Rasyid] dan ['Ashim] dari [Abu Wa'il] dari [Qais bin Abu Gharzah] berkata; kami menamakan diri kami dengan nama samasirah (Makelar) pada masa Rasulullah Shallallahu'alaihiwasallam. Lalu (Rasulullah Shallallahu'alaihiwasallam) mendatangi kami waktu di Baqi' dan bersabda: \"Wahai para pedagang\", beliau menamakan kami dengan nama yang lebih baik dari nama kita sendiri (makelar, pent), \"Sesunguhnya jual beli itu terdapat sumpah dan kebohongan, maka campurkanlah dengan sedekah.\""},"892":{"ar":"قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي وَائِلٍ عَنْ قَيْسِ بْنِ أَبِي غَرَزَةَ قَالَكُنَّا نَبْتَاعُ الْأَوْسَاقَ بِالْمَدِينَةِ وَكُنَّا نُسَمَّى السَّمَاسِرَةَ قَالَ فَأَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَمَّانَا بِاسْمٍ هُوَ أَحْسَنُ مِمَّا كُنَّا نُسَمِّي بِهِ أَنْفُسَنَا فَقَالَ يَا مَعْشَرَ التُّجَّارِ إِنَّ هَذَا الْبَيْعَ يَحْضُرُهُ اللَّغْوُ وَالْحَلِفُ فَشُوبُوهُ بِالصَّدَقَةِ","id":"(Ahmad bin hanbal) berkata; telah menceritakan kepada kami [Waki'] berkata; telah menceritakan kepada kami [Al A'Masy] dari [Abu Wa'il] dari [Qais bin Abu Gharzah] berkata; kami menjual watsaq (ukuran takaran kurma setara dengan enam puluh sho`) di Madinah, kami menamai diri kami dengan samasirah. (Qais bin Abu Gharzah) berkata; lalu Rasulullah Shallallahu'alaihiwasallam mendatangi kami dan memberi nama kepada kami dengan nama yang terbaik daripada nama kami sebelumnya, beliau bersabda: \"Wahai para pedagang, jual beli ini ada unsur hal yang sia-sia dan sumpah maka campurkanlah dengan sedekah.\""},"893":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مُغِيرَةَ عَنْ أَبِي وَائِلٍ عَنْ قَيْسِ بْنِ أَبِي غَرَزَةَ قَالَأَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ فِي السُّوقِ فَقَالَ إِنَّ هَذِهِ السُّوقَ يُخَالِطُهَا اللَّغْوُ وَحَلِفٌ فَشُوبُوهَا بِصَدَقَةٍ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] berkata; telah menceritakan kepada kami [Syu'bah] dari [Mughirah] dari [Abu Wa`il] dari [Qais bin Abu Gharzah] berkata; Rasulullah Shallallahu'alaihiwasallam mendatangi kami dan kami sedang berada di pasar, lalu beliau bersabda: \"Sesungguhnya di dalam pasar ini, ada campurannya berupa hAl hal yang sia-sia dan sumpah maka campurlah dengan sedekah.\""},"894":{"ar":"قَالَ حَدَّثَنَا بَهْزٌ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَبِيبُ بْنُ أَبِي ثَابِتٍ أَخْبَرَنِي قَالَ سَمِعْتُ أَبَا وَائِلٍ يُحَدِّثُ عَنْ قَيْسِ بْنِ أَبِي غَرَزَةَ قَالَخَرَجَ إِلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ نَبِيعُ الرَّقِيقَ نُسَمَّى السَّمَاسِرَةَ فَقَالَ يَا مَعْشَرَ التُّجَّارِ إِنَّ بَيْعَكُمْ هَذَا يُخَالِطُهُ لَغْوٌ وَحَلِفٌ فَشُوبُوهُ بِصَدَقَةٍ أَوْ بِشَيْءٍ مِنْ صَدَقَةٍ","id":"(Ahmad bin hanbal) berkata; telah menceritakan kepada kami [Bahz] berkata; telah menceritakan kepada kami [Syu'bah] berkata; [Habib bin Abu Tsabit] telah mengabarkan kepadaku berkata; saya telah mendengar [Abu Wa`il] menceritakan dari [Qais bin Abu Gharzah] berkata; Rasulullah Shallallahu'alaihiwasallam menemui kami ketika kami sedang menjual budak kami dinamakan dengan samamir (makelar) lalu beliau bersabda: \"Wahai para pedagang, jual beli kalian ini telah tercampur dengan hAl hal yang sia-sia dan sumpah maka campurlah dengan sedekah atau dengan sesuatu yang ada nilai sedekah\"."},"895":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ أَبِي وَائِلٍ عَنْ قَيْسِ بْنِ أَبِي غَرَزَةَ قَالَكُنَّا نَبِيعُ الرَّقِيقَ فِي السُّوقِ وَكُنَّا نُسَمَّى السَّمَاسِرَةَ فَسَمَّانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَحْسَنَ مِمَّا سَمَّيْنَا بِهِ أَنْفُسَنَا فَقَالَ يَا مَعْشَرَ التُّجَّارِ إِنَّ هَذَا الْبَيْعَ يَحْضُرُهُ اللَّغْوُ وَالْأَيْمَانُ فَشُوبُوهُ بِالصَّدَقَةِ","id":"(Ahmad bin hanbal) berkata; telah menceritakan kepada kami [Abdurrohman bin Mahdi] dari [Sufyan] dari [Habib bin Abu Tsabit] dari [Abu Wa`il] dari [Qais bin Abu Gharzah] berkata; kami sedang menjual budak di pasar sehingga kami dinamakan dengan samamir (makelar) lalu Rasulullah Shallallahu'alaihiwasallam memberi nama dengan nama yang baik buat kami dari nama yang kami pakai sendiri, bersabda: \"Wahai para pedagang, jual beli ini telah tercampur dengan hAl hal yang sia-sia dan sumpah maka campurlah dengan sedekah.\""},"896":{"ar":"قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ عَنْ قَيْسِ بْنِ أَبِي غَرَزَةَ قَالَكُنَّا نُسَمَّى عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ السَّمَاسِرَةَ فَمَرَّ بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَمَّانَا بِاسْمٍ هُوَ أَحْسَنُ مِنْهُ فَقَالَ يَا مَعْشَرَ التُّجَّارِ إِنَّ هَذَا الْبَيْعَ يَحْضُرُهُ اللَّغْوُ وَالْحَلِفُ فَشُوبُوهُ بِالصَّدَقَةِقَالَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا الْعَوَّامُ بْنُ حَوْشَبٍ قَالَ حَدَّثَنِي إِبْرَاهِيمُ مَوْلَى صُخَيْرٍ عَنْ بَعْضِ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَرَادَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَنْهَى عَنْ بَيْعٍ فَقَالُوا يَا رَسُولَ اللَّهِ إِنَّهَا مَعَايِشُنَا قَالَ فَقَالَ لَا خِلَابَ إِذًا وَكُنَّا نُسَمَّى السَّمَاسِرَةَ فَذَكَرَ الْحَدِيثَ","id":"(Ahmad bin hanbal) berkata; telah menceritakan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami [Al A'masy] dari [Syaqiq] dari [Qais bin Abu Gharzah] berkata; kami diberi nama pada masa Rasulullah Shallallahu'alaihiwasallam dengan samamir (makelar) lalu Rasulullah Shallallahu'alaihiwasallam melewati kami lalu memberi nama pada kami dengan nama yang lebih dari nama sebelumnya.beliau bersabda: \"Wahai para pedagang, jual beli ini telah tercampur dengan hAl hal yang sia-sia dan sumpah maka campurlah dengan sedekah\". (Ahmad bin hanbal) berkata; telah menceritakan kepada kami [Yazid bin Harun] berkata; telah mengabarkan kepada kami [Al Awwam bin Hausyab] berkata; telah menceritakan kepadaku [Ibrahim] budak Shukhair, dari [beberapa sahabat Nabi Shallallahu'alaihiwasallam], berkata; Rasulullah Shallallahu'alaihiwasallam hendak melarang jual beli. lalu mereka berkata; itu adalah mata pencaharian kami. (beberapa sahabat ASC) berkata; yang tidak ada hilab (penghianatan dalam agama), kami menamainya dengan Samasirah (makelar), lalu menyebutkan hadis secara lengkap."},"897":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ فُرَاتٍ عَنْ أَبِي الطُّفَيْلِ عَنْ حُذَيْفَةَ بْنِ أَسِيدٍاطَّلَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْنَا وَنَحْنُ نَتَذَاكَرُ السَّاعَةَ فَقَالَ مَا تَذْكُرُونَ قَالُوا نَذْكُرُ السَّاعَةَ فَقَالَ إِنَّهَا لَنْ تَقُومَ حَتَّى تَرَوْنَ عَشْرَ آيَاتٍ الدُّخَانُ وَالدَّجَّالُ وَالدَّابَّةُ وَطُلُوعُ الشَّمْسِ مِنْ مَغْرِبِهَا وَنُزُولُ عِيسَى ابْنِ مَرْيَمَ وَيَأْجُوجُ وَمَأْجُوجُ وَثَلَاثُ خُسُوفٍ خَسْفٌ بِالْمَشْرِقِ وَخَسْفٌ بِالْمَغْرِبِ وَخَسْفٌ بِجَزِيرَةِ الْعَرَبِ وَآخِرُ ذَلِكَ نَارٌ تَخْرُجُ مِنْ قِبَلِ تَطْرُدُ النَّاسَ إِلَى مَحْشَرِهِمْقَالَ أَبُو عَبْد الرَّحْمَنِ سَقَطَ كَلِمَةٌ","id":"Telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Furat] dari [Abu Thufail] dari [Hudaifah bin Asid] Rasulullah Shallallahu'alaihiwasallam menemui kita dan kita sedang membicarakan tentang Hari Kiamat, lalu Rasulullah Shallallahu'alaihiwasallam bersabda: \"Apa yang kalian bincangkan\" Kami menjawab, kami sedang membincangkan Hari Kiamat. (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Kalian tidak akan menemui Hari Kiamat sampai kalian melihat sepuluh tandanya: keluarnya asap, Dajjal, binatang melata, keluarnya matahari dari sebelah barat, turunnya 'Isa bin Maryam, keluarnya bangsa Yajuj dan ma'juj, dan berkobarnya api di tiga tempat, yaitu di sebelah timur, barat dan di Jazirah Arab dan pemungkasnya adalah api yang menggiring mereka menuju ke tempat berkumpul\"Abu Abdurrohman berkata; kalimatnya ada yang hilang."},"898":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ أَبِي الطُّفَيْلِ عَنْ حُذَيْفَةَ بْنِ أَسِيدٍ الْغِفَارِيِّ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْخُلُ الْمَلَكُ عَلَى النُّطْفَةِ بَعْدَمَا تَسْتَقِرُّ فِي الرَّحِمِ بِأَرْبَعِينَ لَيْلَةً وَقَالَ سُفْيَانُ مَرَّةً أَوْ خَمْسِينَ وَأَرْبَعِينَ لَيْلَةً فَيَقُولُ يَا رَبِّ مَاذَا أَشَقِيٌّ أَمْ سَعِيدٌ أَذَكَرٌ أَمْ أُنْثَى فَيَقُولُ اللَّهُ تَبَارَكَ وَتَعَالَى فَيَكْتُبَانِ فَيَقُولَانِ مَاذَا أَذَكَرٌ أَمْ أُنْثَى فَيَقُولُ اللَّهُ عَزَّ وَجَلَّ فَيَكْتُبَانِ فَيُكْتَبُ عَمَلُهُ وَأَثَرُهُ وَمُصِيبَتُهُ وَرِزْقُهُ ثُمَّ تُطْوَى الصَّحِيفَةُ فَلَا يُزَادُ عَلَى مَا فِيهَا وَلَا يُنْقَصُ","id":"Telah menceritakan kepada kami [Sufyan] dari ['Amr] dari [Abu Thufail] dari [Hudzaifah bin Asid Al Ghiffary] berkata; Aku mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Malaikat masuk untuk meniupkan ruh pada janin setelah berumur 40 hari\" Sufyan berkata; \"Lima puluh atau empat hari, lalu Malaikat berkata; 'Wahai Rab, apakah dia termasuk yang bahagia ataukah celaka, apakah laki-laki ataukah perempuan, maka Allah 'azza wajalla Tabaroka Wa Ta'ala berfirman lalu kedua Malaikat mencatatnya dan berkata; \"Laki-laki ataukah perempuan?\" lalu Allah 'azza wajalla berfirman lalu keduanya mencatat, mencatat segala amalnya, bagian, musibah dan rizqinya, kemudian dilipatlah catatan amalnya dengan tidak dikurangi dan ditambah"},"899":{"ar":"قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ فُرَاتٍ عَنْ أَبِي الطُّفَيْلِ عَنْ أَبِي سَرِيحَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غُرْفَةٍ وَنَحْنُ تَحْتَهَا نَتَحَدَّثُ قَالَ فَأَشْرَفَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا تَذْكُرُونَ قَالُوا السَّاعَةَ قَالَ إِنَّ السَّاعَةَ لَنْ تَقُومَ حَتَّى تَرَوْنَ عَشْرَ آيَاتٍ خَسْفٌ بِالْمَشْرِقِ وَخَسْفٌ بِالْمَغْرِبِ وَخَسْفٌ فِي جَزِيرَةِ الْعَرَبِ وَالدُّخَانُ وَالدَّجَّالُ وَالدَّابَّةُ وَطُلُوعُ الشَّمْسِ مِنْ مَغْرِبِهَا وَيَأْجُوجُ وَمَأْجُوجُ وَنَارٌ تَخْرُجُ مِنْ قَعْرِ عَدَنٍ تُرَحِّلُ النَّاسَ فَقَالَ شُعْبَةُ سَمِعْتُهُ وَأَحْسِبُهُ قَالَ تَنْزِلُ مَعَهُمْ حَيْثُ نَزَلُوا وَتَقِيلُ مَعَهُمْ حَيْثُ قَالُواقَالَ شُعْبَةُ وَحَدَّثَنِي بِهَذَا الْحَدِيثِ رَجُلٌ عَنْ أَبِي الطُّفَيْلِ عَنْ أَبِي سَرِيحَةَ لَمْ يَرْفَعْهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَحَدُ هَذَيْنِ الرَّجُلَيْنِ نُزُولُ عِيسَى ابْنِ مَرْيَمَ وَقَالَ الْآخَرُ رِيحٌ تُلْقِيهِمْ فِي الْبَحْرِ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] berkata; telah menceritakan kepada kami [Syu'bah] dari [Furat] dari [Abu Thufail] dari [Abu Sarihah] berkata; Rasulullah shallallahu 'alaihi wasallam sedang berada di kamar dan kami berada di tengahnya kami berbincang-bincang. Lalu Rasulullah shallallahu 'alaihi wasallam mendekati kami dan bertanya, \"Apakah yang kalian sebutkan tadi?\" Mereka menjawab, Hari Kiamat. Beliau bersabda: \"Sesungguhnya Hari Kiamat tidak akan terjadi sampai ada sepuluh tanda. Terjadinya kerusakan di timur, kerusakan di barat, kerusakan di negeri Arab, asap, Dajjal, dabbah (munculnya hewan melata), terbitnya matahari dari arah barat, Ya'juj dan Ma'juj dan api yang keluar dari ujung tanah Adan yang mengiring manusia. Lalu Syu'bah berkata; saya telah mendengarnya dan saya menyangka dia berkata; akan turun bersama mereka sebagaimana mereka turun dan akan beristirahat bersama mereka sebagaimana mereka berkata. Syu'bah berkata; dan telah menceritakan kepadaku dengan hadis ini seorang laki-laki dari Abu Ath-Thufail dari Abu Sarihah dengan tidak memarfukkan kepada Nabi Shallallahu'alaihiwasallam, maka salah seorang dari keduanya berkata; turunnya Isa bin Maryam dan yang satunya berkata; angin yang melemparkan mereka ke laut."},"900":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ فُرَاتٍ عَنْ أَبِي الطُّفَيْلِ عَنْ حُذَيْفَةَ بْنِ أَسِيدٍ الْغِفَارِيِّ قَالَأَشْرَفَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ غُرْفَةٍ وَنَحْنُ نَتَذَاكَرُ السَّاعَةَ فَقَالَ لَا تَقُومُ السَّاعَةُ حَتَّى تَرَوْنَ عَشْرَ آيَاتٍ طُلُوعُ الشَّمْسِ مِنْ مَغْرِبِهَا وَالدُّخَانُ وَالدَّابَّةُ وَخُرُوجُ يَأْجُوجَ وَمَأْجُوجَ وَخُرُوجُ عِيسَى ابْنِ مَرْيَمَ وَالدَّجَّالِ وَثَلَاثُ خُسُوفٍ خَسْفٌ بِالْمَغْرِبِ وَخَسْفٌ بِالْمَشْرِقِ وَخَسْفٌ بِجَزِيرَةِ الْعَرَبِ وَنَارٌ تَخْرُجُ مِنْ قَعْرِ عَدَنٍ تَسُوقُ أَوْ تَحْشُرُ النَّاسَ تَبِيتُ مَعَهُمْ حَيْثُ بَاتُوا وَتَقِيلُ مَعَهُمْ حَيْثُ قَالُوا","id":"(Ahmad bin hanbal) berkata; telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Sufyan] dari [Furat] dari [Abu Ath-Thufail] dari [Hudzaifah bin Asid Al Ghifari] berkata; Rasulullah Shallallahu'alaihiwasallam mendekati kami dari kamar dan kami sedang memperbincangkan Hari Kiamat. Lalu beliau bersabda: \"Tidak akan terjadi hari kiamat sehingga kalian melihat sepuluh tanda: Terbitnya matahari dari arah barat, munculnya asap, dabbah (munculnya hewan melata),, Ya'juj dan Ma'juj, keluarnya 'Isa bin Maryam, Dajjal, terjadinya kerusakan di tiga tempat: di barat, di timur dan di negeri Arab, dan api yang keluar dari ujung tanah Adan yang mengiring manusia, dan api tersebut turun bersama mereka dimana mereka turun dan akan beristirahat bersama mereka sebagaimana mereka berkata."},"901":{"ar":"قَالَ حَدَّثَنَا رَوْحٌ قَالَ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ وَعَبْدُ الْوَهَّابِ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ أَبِي الطُّفَيْلِ عَنْ حُذَيْفَةَ بْنِ أَسِيدٍ الْغِفَارِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَ بِمَوْتِ النَّجَاشِيِّ قَالَ فَقَالَ صَلُّوا عَلَى أَخٍ لَكُمْ بِغَيْرِ بِلَادِكُمْ","id":"(Ahmad bin hanbal) berkata; telah menceritakan kepada kami [Rouh] berkata; telah menceritakan kepada kami [Sa'id bin Abu 'Arubah] dan [Abdul Wahab] dari [Sa'id] dari [Qatadah] dari [Abu Thufail] dari [Hudzaifah bin Usaid Al Ghiffary] Rasulullah Shallallahu'alaihiwasallam memberitahukan kematian Najasy, lalu beliau berkata; \"Shalatlah kalian atas saudara kalian yang meninggal bukan di negara kalian.\""},"902":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الصَّمَدِ وَأَزْهَرُ بْنُ الْقَاسِمِ قَالَا حَدَّثَنَا الْمُثَنَّى حَدَّثَنَا قَتَادَةُ عَنْ أَبِي الطُّفَيْلِ عَنْ حُذَيْفَةَ بْنِ أَسِيدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ عَلَيْهِمْ يَوْمًا فَقَالَ صَلُّوا عَلَى صَاحِبِكُمْ مَاتَ بِغَيْرِ بِلَادِكُمْ قَالُوا مَنْ هُوَ يَا رَسُولَ اللَّهِ قَالَ صُحْمَةُ النَّجَاشِيُّ وَقَالَ أَزْهَرُ صَحْمَةُ وَقَالَ أَزْهَرُ أَبِي الطُّفَيْلِ اللَّيْثِيِّ عَنْ حُذَيْفَةَ بْنِ أَسِيدٍ الْغِفَارِيِّ","id":"(Ahmad bin hanbal) berkata; telah menceritakan kepada kami [Abdusshomad] dan [Azhar bin Al Qasim] berkata; telah menceritakan kepada kami [Al Mutsanna] telah menceritakan kepada kami [Qatadah] dari [Abu Thufail] dari [Hudzaifah bin Asid] Rasulullah Shallallahu'alaihiwasallam menemui mereka pada suatu hari lalu bersabda: \"Shalatlah kalian atas sahabat kalian yang mati di negerinya\", mereka bertanya siapakah dia Wahai Rasulullah. Beliau menjawab, Shuhmah dari Najasyi. Azhar berkata; Shahmah, Abu Thufail Al Laitsi berkata; dari Hudzaifah bin Asid Al Ghifari."},"903":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ مَوْلَى بَنِي هَاشِمٍ قَالَ حَدَّثَنَا الْمُثَنَّى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا قَتَادَةُ عَنْ أَبِي الطُّفَيْلِ عَنْ حُذَيْفَةَ بْنِ أَسِيدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءَ ذَاتَ يَوْمٍ فَقَالَ صَلُّوا عَلَى أَخٍ لَكُمْ مَاتَ بِغَيْرِ أَرْضِكُمْ قَالُوا مَنْ هُوَ يَا رَسُولَ اللَّهِ قَالَ صُحْمَةُ النَّجَاشِيُّ فَقَامُوا فَصَلَّوْا عَلَيْهِ","id":"Telah menceritakan kepada kami [Ibnu Asid] budak Bani Hasyim, berkata; telah menceritakan kepada kami [Al Mutsanna bin Sa'id] berkata; telah menceritakan kepada kami [Qatadah] dari [Abu Thufail] dari [Hudzaifah bin Asid] Rasulullah Shallallahu'alaihiwasallam datang pada suatu hari lalu bersabda: \"Shalatlah kalian atas sahabat kalian yang mati di negerinya\", mereka bertanya siapakah dia Wahai Rasulullah. Beliau menjawab, Shuhmah dari Najasyi. Lalu mereka berdiri dan shalat atasnya."},"904":{"ar":"قَالَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ قَالَ أَخْبَرَنَا أَيُّوبُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي مُلَيْكَةَ قَالَ حَدَّثَنِي عُبَيْدُ بْنُ أَبِي مَرْيَمَ عَنْ عُقْبَةَ بْنِ الْحَارِثِ قَالَ وَقَدْ سَمِعْتُهُ مِنْ عُقْبَةَ وَلَكِنِّي لِحَدِيثِ عُبَيْدٍ أَحْفَظُ قَالَتَزَوَّجْتُ فَجَاءَتْنَا امْرَأَةٌ سَوْدَاءُ فَقَالَتْ إِنِّي قَدْ أَرْضَعْتُكُمَا فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ إِنِّي تَزَوَّجْتُ امْرَأَةً فُلَانَةَ ابْنَةَ فُلَانٍ فَجَاءَتْنَا امْرَأَةٌ سَوْدَاءُ فَقَالَتْ إِنِّي أَرْضَعْتُكُمَا وَهِيَ كَافِرَةٌ فَأَعْرَضَ عَنِّي فَأَتَيْتُهُ مِنْ قِبَلِ وَجْهِهِ فَقُلْتُ إِنَّهَا كَاذِبَةٌ فَقَالَ لِي كَيْفَ بِهَا وَقَدْ زَعَمَتْ أَنَّهَا أَرْضَعَتْكُمَا دَعْهَا عَنْكَ","id":"(Ahmad bin hanbal) berkata; telah menceritakan kepada kami [Isma'il bin Ibrahim] berkata; telah mengabarkan kepada kami [Ayyub] dari [Abdullah bin Abu Mulaikah] berkata; telah menceritakan kepadaku ['Ubaid bin Abu Maryam] dari ['Uqbah bin Al Harits] berkata; dan saya telah mendengarnya dari 'Uqbah, tapi untuk hadis 'Ubaid, saya lebih menjaga. Dia berkata; saya baru saja menikah, lalu datanglah seorang wanita yang berkulit hitam dan berkata; saya telah menyusui kalian berdua. Lalu saya menemui Nabi Shallallahu'alaihiwasallam dan saya katakan 'Saya baru saja menikahi seorang wanita sebut saja si fulanah binti fulan lalu datang seorang wanita hitam dan berkata; saya pernah menyusui kalian berdua.' Wanita tersebut masih kafir, lalu beliau berpaling dariku, lalu saya memergokirnya dari arah depannya, lalu saya berkata; 'Wanita itu hanyalah pembohong.' Lalu beliau bersabda kepadaku 'Bagaimana dengan dia, padahal dia telah yakin bahwa dia telah menyusui kalian berdua, tinggalkanlah isterimu.\""},"905":{"ar":"قَالَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ إِسْمَاعِيلَ يَعْنِي ابْنَ أُمَيَّةَ عَنِ ابْنِ أَبِي مُلَيْكَةَ عَنْ عُقْبَةَ بْنِ الْحَارِثِتَزَوَّجْتُ ابْنَةَ أَبِي إِيهَابٍ فَجَاءَتْ امْرَأَةٌ سَوْدَاءُ يَعْنِي فَذَكَرَتْ أَنَّهَا أَرْضَعَتْكُمَا فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُمْتُ بَيْنَ يَدَيْهِ فَكَلَّمْتُهُ فَأَعْرَضَ عَنِّي فَقُمْتُ عَنْ يَمِينِهِ فَأَعْرَضَ عَنِّي فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّمَا هِيَ سَوْدَاءُ قَالَ فَكَيْفَ وَقَدْ قِيلَ","id":"(Ahmad bin hanbal) berkata; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Isma'il] yaitu Ibnu Umayyah, dari [Ibnu Abu Mulaikah] dari ['Uqbah bin Al Harits], saya menikah dengan anak perempuan Abu Ihab (Jangan dibaca Abu Lahab), lalu datanglah seorang wanita yang berwarna hitam, dia mengutarakan bahwa dia telah menyusui kalian berdua. Lalu saya datangi Nabi Shallallahu'alaihiwasallam, lalu saya duduk di hadapannya, dan saya berbicara dengan mereka. Namun beliau berpaling dariku, lalu saya berpindah ke arah sebelah kanan, namun beliau tetap berpaling dariku. Lalu saya berkata; Wahai Rasulullah, dia hanyalah orang yang hitam. Beliau bersabda: \"Lha bagaimana, padahal telah dikatakan seperti itu.\""},"906":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الصَّمَدِ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا أَيُّوبُ عَنِ ابْنِ أَبِي مُلَيْكَةَ قَالَ حَدَّثَنِي عُقْبَةُ بْنُ الْحَارِثِ قَالَأُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالنُّعَيْمَانِ قَدْ شَرِبَ الْخَمْرَ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ فِي الْبَيْتِ فَضَرَبُوهُ بِالْأَيْدِي وَالْجَرِيدِ وَالنِّعَالِقَالَ فَكُنْتُ مِمَّنْ ضَرَبَهُ","id":"(Ahmad bin hanbal) berkata; telah menceritakan kepada kami [Abdusshamad] berkata; telah menceritakan kepada kami [bapakku] berkata; telah menceritakan kepada kami [Ayyub] dari [Ibnu Abu Mulaikah] berkata; telah menceritakan kepadaku ['Uqbah bin Al Harits] berkata; dihadapkan kepada Rasulullah Shallallahu'alaihiwasallam seorang laki-laki yang bernama Nu'man yang meminum arak. Rasulullah Shallallahu'alaihiwasallam menyuruh orang yang sedang berada di rumah untuk memukulinya dengan tangan, pelepah dan sandal. 'Uqbah bin Al Harits) berkata; saya termasuk orang yang memukulinya."},"907":{"ar":"قَالَ حَدَّثَنَا رَوْحٌ قَالَ حَدَّثَنَا عُمَرُ بْنُ سَعِيدِ بْنِ أَبِي حُسَيْنٍ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ أَبِي مُلَيْكَةَ عَنْ عُقْبَةَ بْنِ الْحَارِثِ قَالَصَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَصْرَ فَلَمَّا سَلَّمَ قَامَ سَرِيعًا فَدَخَلَ عَلَى بَعْضِ نِسَائِهِ ثُمَّ خَرَجَ وَرَأَى مَا فِي وُجُوهِ الْقَوْمِ مِنْ تَعَاجُبِهِمْ وَلُبِسَ عَلَيْهِ قَالَ ذَكَرْتُ وَأَنَا فِي الصَّلَاةِ تِبْرًا عِنْدَنَا فَكَرِهْتُ أَنْ يُمْسِيَ أَوْ يَبِيتَ عِنْدَنَا فَأَمَرْتُ بِقِسْمَتِهِقَالَ حَدَّثَنَا أَبُو أَحْمَدَ الزُّبَيْرِيُّ قَالَ حَدَّثَنَا عُمَرُ بْنُ سَعِيدٍ عَنِ ابْنِ أَبِي مُلَيْكَةَ عَنْ عُقْبَةَ بْنِ الْحَارِثِ قَالَ انْصَرَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ صَلَّى الْعَصْرَ فَذَكَرَ مَعْنَاهُ","id":"(Ahmad bin hanbal) berkata; telah menceritakan kepada kami [Rouh] berkata; telah menceritakan kepada kami ['Umar bin Sa'id bin Abu Husain] berkata; telah menceritakan kepadaku [Abdullah bin Ibnu Mulaikah] dari ['Uqbah bin Al Harits] berkata; saya shalat ashar bersama Rasulullah Shallallahu'alaihiwasallam. Setelah mengucapkan salam, beliau bangkit dengan segera, beliau temui sebagian istrinya, lalu beliau muncul, beliau lihat wajah para sahabatnya yang merasa terherAn heran. Hati beliau merasa kacau dengan emas itu. Beliau bersabda: \"Ketika sedang shalat saya teringat sebiji emas atau perak yang kami punyai dan saya tidak suka jika itu berlangsung sampai sore atau sampai malam di rumah kami. Lalu saya memerintahkan agar di bagikan. Ahmad bin hanbal berkata; telah menceritakan kepada kami [Abu Ahmad Az Zubairy] berkata; telah menceritakan kepada kami ['Umar bin Sa'id] dari [Ibnu Abu Mulaikah] dari ['Uqbah bin Al Harits] berkata; Rasulullah Shallallahu'alaihiwasallam pulang ketika shalat asar, lalu menyebutkan secara makna."},"908":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنِ ابْنِ جُرَيْجٍ عَنِ ابْنِ أَبِي مُلَيْكَةَ قَالَ حَدَّثَنِي عُقْبَةُ بْنُ الْحَارِثِ أَوْ سَمِعْتُهُ مِنْهُأَنَّهُ تَزَوَّجَ أُمَّ يَحْيَى ابْنَةَ أَبِي إِيهَابٍ فَجَاءَتْ امْرَأَةٌ سَوْدَاءُ فَقَالَتْ قَدْ أَرْضَعْتُكُمَا فَذَكَرْتُ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَعْرَضَ عَنِّي فَتَنَحَّيْتُ فَذَكَرْتُهُ لَهُ فَقَالَ فَكَيْفَ وَقَدْ زَعَمَتْ أَنْ قَدْ أَرْضَعَتْكُمَا فَنَهَاهُ عَنْهَا","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ibnu Juraij] dari [Ibnu Abu Mulaikah] berkata; telah menceritakan kepadaku ['Uqbah bin Al Harits] atau saya mendengarnya darinya, dia menikah dengan Umu Yahya, anak perempuan Abu Ihab, lalu datanglah seorang wanita berkulit hitam. Si wanita itu berkata; sungguh saya telah menyusui kalian berdua. Segera saja saya menyebutkan kasus ini kepada Rasulullah Shallallahu'alaihiwasallam, lalu beliau berpaling dariku, saya mencoba memergoki beliau dari arah lainnya dan saya sampaikan lagi, lalu beliau bersabda: \"Bagaimana, dia telah mengatakan bahwa dia telah menyusui kalian berdua\". Lalu beliau melarang laki-laki tadi berumahtangga dengan wanita itu."},"909":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنَا عَبْدُ اللَّهُ بْنُ عُبَيْدِ اللَّهِ بْنِ أَبِي مُلَيْكَةَ أَنَّ عُقْبَةَ بْنَ الْحَارِثِ بْنِ عَامِرٍ أَخْبَرَهُ أَوْ سَمِعَهُ مِنْهُ إِنْ لَمْ يَكُنْ خَصَّهُ بِهِأَنَّهُ نَكَحَ ابْنَةَ أَبِي إِيهَابٍ فَقَالَتْ أَمَةٌ سَوْدَاءُ قَدْ أَرْضَعْتُكُمَا فَجِئْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ ذَلِكَ لَهُ فَأَعْرَضَ عَنِّي فَجِئْتُ فَذَكَرْتُ لَهُ فَقَالَ فَكَيْفَ وَقَدْ زَعَمَتْ أَنْ قَدْ أَرْضَعَتْكُمَا فَنَهَاهُ عَنْهَا","id":"Telah menceritakan kepada kami [Abdurrazzaq] berkata; telah menceritakan kepada kami [Ibnu Juraij] berkata; telah mengabarkan kepada kami [Abdullah bin 'Ubaidullah bin Abu Mulaikah] ['Uqbah bin Al Harits bin 'Amir], dia mengabarinya atau mendengarnya --dia tidak mengkhususkan dengan salah satu redaksi mengabari atau mendengar-- dia menikahi anak perempuan Abu Ihab, lalu ada seorang budak wanita yang berwarna hitam berkata 'Sungguh saya telah menyusui kalian berdua.' Kontan saya datangi Nabi Shallallahu'alaihiwasallam, saya utarakan kasus ini kepada beliau, lalu berpaling dariku, lalu saya datang lagi dan saya utarakan lagi kasusnya kepada beliau, lantas beliau bersabda: \"Lha bagaimana, dia telah mengatakan bahwa dia telah menyusui kalian berdua\". Lalu beliau melarang dia berumah tangga dengan wanita itu."},"910":{"ar":"قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ وَعَفَّانُ قَالَا حَدَّثَنَا وُهَيْبُ بْنُ خَالِدٍ قَالَ عَفَّانُ فِي حَدِيثِهِ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي مُلَيْكَةَ عَنْ عُقْبَةَ بْنِ الْحَارِثِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِالنُّعَيْمَانِ أَوْ ابْنِ النُّعَيْمَانِ وَهُوَ سَكْرَانُ قَالَ فَاشْتَدَّ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَمَرَ مَنْ فِي الْبَيْتِ أَنْ يَضْرِبُوهُ فَضَرَبُوهُ قَالَ عَفَّانُ فِي حَدِيثِهِ فَشَقَّ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَشَقَّةً شَدِيدَةًقَالَ عُقْبَةُ فَكُنْتُ فِيمَنْ ضَرَبَهُ","id":"(Ahmad bin hanbal) berkata; telah menceritakan kepada kami [Sulaiman bin Harb] dan ['Affan] berkata; telah menceritakan kepada kami [Wuhaib bin Khalid] ['Affan] berkata; dalam hadisnya, berkata; telah menceritakan kepada kami [Ayyub] dari [Abdullah bin Abu Mulaikah] dari ['Uqbah bin Al Harits], dihadapkan kepada Nabi Shallallahu'alaihiwasallam An Nu'aiman atau Ibnu An Nua'iman dalam keadaan mabuk. ('Uqbah bin Al Harits) berkata; hal itu membuat Rasulullah Shallallahu'alaihiwasallam marah, lalu menyuruh orang yang berada di rumah untuk memukulinya, dan mereka lakukan. 'Affan berkata dalam hadisnya, lalu hal itu sangat memberatkan Rasulullah Shallallahu'alaihiwasallam. 'Uqbah berkata; saya termasuk orang yang memukulinya."},"911":{"ar":"حَدَّثَنَا هُشَيْمٌ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ أَبِيهِ عَنْ أَوْسِ بْنِ أَوْسٍ الثَّقَفِيِّ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَى كِظَامَةَ قَوْمٍ فَتَوَضَّأَ","id":"Telah menceritakan kepada kami [Husyaim] dari [Ya'la bin 'Atha`] dari [Bapaknya] dari [Aus bin Aus Al Atsaqafi] berkata; Aku pernah melihat Rasulullah Shallallahu'alaihiwasallam mendatangi tempat penampungan air, kemudian beliau berwudlu.\""},"912":{"ar":"قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ عَنِ النُّعْمَانِ بْنِ سَالِمٍ عَنِ ابْنِ أَبِي أَوْسٍ عَنْ جَدِّهِ أَنَّهُكَانَ يُؤْتَى بِنَعْلَيْهِ وَهُوَ يُصَلِّي فَيَلْبَسُهُمَا وَيَقُولُ إِنِّي رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي نَعْلَيْهِ","id":"(Ahmad bin hanbal) berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Syu'bah] dari [An Nu'man bin Salim] dengan [Ibnu Abu Aus] dari [kakeknya], Sepasang sandal didatangkan baginya ketika ia shalat, lalu dia mengenakannya waktu shalat dan berkata; \"Saya pernah melihat Rasulullah shalat dengan memakai kedua sandalnya.\""},"913":{"ar":"قَالَ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ قَالَ حَدَّثَنَا يَعْلَى بْنُ عَطَاءٍ عَنْ أَبِيهِ عَنْ أَوْسِ بْنِ أَبِي أَوْسٍ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ وَمَسَحَ عَلَى نَعْلَيْهِ ثُمَّ قَامَ إِلَى الصَّلَاةِ","id":"(Ahmad bin hanbal) berkata; telah menceritakan kepada kami [Yahya] dari [Syu'bah] berkata; telah menceritakan kepada kami [Ya'la bin 'Atha`] dari [Bapaknya] dari [Aus bin Abi Aus] berkata; saya melihat Rasulullah Shallallahu'alaihiwasallam berwudlu dan mengusap kedua sandalnya, kemudian berdiri dan mendirikan shalat.\""},"914":{"ar":"قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنِ النُّعْمَانِ قَالَ سَمِعْتُ أَوْسًا يَقُولُأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي وَفْدِ ثَقِيفٍ فَكُنَّا فِي قُبَّةٍ فَقَامَ مَنْ كَانَ فِيهَا غَيْرِي وَغَيْرَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ رَجُلٌ فَسَارَّهُ فَقَالَ اذْهَبْ فَاقْتُلْهُ ثُمَّ قَالَ أَلَيْسَ يَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ قَالَ بَلَى وَلَكِنَّهُ يَقُولُهَا تَعَوُّذًا فَقَالَ رُدَّهُ ثُمَّ قَالَ أُمِرْتُ أَنْ أُقَاتِلَ النَّاسَ حَتَّى يَقُولُوا لَا إِلَهَ إِلَّا اللَّهُ فَإِذَا قَالُوهَا حُرِّمَتْ عَلَيَّ دِمَاؤُهُمْ وَأَمْوَالُهُمْ إِلَّا بِحَقِّهَا فَقُلْتُ لِشُعْبَةَ أَلَيْسَ فِي الْحَدِيثِ ثُمَّ قَالَ أَلَيْسَ يَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنِّي رَسُولُ اللَّهِ قَالَ شُعْبَةُ أَظُنُّهَا مَعَهَا وَمَا أَدْرِي","id":"(Ahmad bin hanbal) berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] berkata; telah menceritakan kepada kami [Syu'bah] dari [An Numan] berkata; aku mendengar [Aus] berkata; Aku pernah mendatangi Rasulullah Shallallahu'alaihiwasallam yang tengah berkumpul bersama utusAn utusan Bani Tsaqif, ketika itu kami berada di suatu bangunan. Lalu orang-orang penghuni bangunan itu berdiri kecuali saya dan Rasulullah Shallallahu'alaihiwasallam. Tiba-tiba datanglah seorang laki-laki yang memancing kemarahan nabi shallallahu 'alaihi wasallam, lalu nabi berkata; \"Pergilah dan bunuhlah dia\". Tapi beberapa saat kemudian nabi shallallahu 'alaihi wasallam bersabda: \"Namun bukankah dia mengucapkan kalimah syahadah?\" Aus menjawab, Ya, tapi dia mengucapkannya hanya sebagai alat untuk menghindarkan diri dari pembunuhan? (Rasulullah Shallallahu'alaihiwasallam) kontan bersabda: \"Lepaskanlah dia\" lalu beliau bersabda: \"Saya diperintahkan untuk memerangi manusia sampai mereka mengucapkan, \"Tidak ada tuhan selain Allah', jika mereka telah mengucapkannya, maka haram bagiku darah dan harta mereka kecuali karena alasan yang dibenarkan.\" Saya bertanya kepada Syu'bah, 'Apakah dalam hadis terdapat redaksi kemudian ia berkata; bukankah dia bersaksi bahwa 'tidak ada tuhan selain Allah dan saya adalah Rasul Allah? '. Syu'bah berkata; saya pikir begitu, namun saya tidak tahu."},"915":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا ابْنُ جُرَيْجٍ عَنْ عُمَرَ بْنِ مُحَمَّدٍ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ عَنْ مُحَمَّدِ بْنِ سَعِيدٍ عَنْ أَوْسِ بْنِ أَوْسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا كَانَ يَوْمُ الْجُمُعَةِ فَغَسَلَ أَحَدُكُمْ رَأْسَهُ وَاغْتَسَلَ ثُمَّ غَدَا أَوْ ابْتَكَرَ ثُمَّ دَنَا فَاسْتَمَعَ وَأَنْصَتَ كَانَ لَهُ بِكُلِّ خُطْوَةٍ خَطَاهَا كَصِيَامِ سَنَةٍ وَقِيَامِ سَنَةٍ","id":"(Ahmad bin hanbal) berkata; telah menceritakan kepada kami [Abdurrozzaq] berkata; telah mengabarkan kepada kami [Ibnu Juraij] dari ['Umar bin Muhammad] dari [Sa'id bin Abu Hilal] dari [Muhammad bin Sa'id] dari [Aus bin Aus] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Apabila hari Jum'at tiba, lantas salah seorang diantara kalian membasuh kepalanya, mandi, berangkat sedini mungkin, mendekat imam, mendengar khutbah dengan baik, dan diam,, maka setiap langkah yang dilakukannya bagaikan puasa dan shalat selama setahun.\""},"916":{"ar":"قَ��لَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بَكْرٍ السَّهْمِيُّ قَالَ حَدَّثَنَا حَاتِمُ بْنُ أَبِي صَغِيرَةَ عَنِ النُّعْمَانِ بْنِ سَالِمٍ أَنَّ عَمْرَو بْنَ أَوْسٍ أَخْبَرَهُ أَنَّ أَبَاهُ أَوْسًا أَخْبَرَهُ قَالَإِنَّا لَقُعُودٌ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الصُّفَّةِ وَهُوَ يَقُصُّ عَلَيْنَا وَيُذَكِّرُنَا إِذْ جَاءَ رَجُلٌ فَسَارَّهُ فَقَالَ اذْهَبُوا فَاقْتُلُوهُ قَالَ فَلَمَّا وَلَّى الرَّجُلُ دَعَاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ قَالَ الرَّجُلُ نَعَمْ نَعَمْ يَا رَسُولَ اللَّهِ فَقَالَ اذْهَبُوا فَخَلُّوا سَبِيلَهُ فَإِنَّمَا أُمِرْتُ أَنْ أُقَاتِلَ النَّاسَ حَتَّى يَشْهَدُوا أَنْ لَا إِلَهَ إِلَّا اللَّهُ فَإِذَا فَعَلُوا ذَلِكَ حُرِّمَتْ عَلَيَّ دِمَاؤُهُمْ وَأَمْوَالُهُمْ إِلَّا بِحَقِّهَاقَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْأَنْصَارِيُّ قَالَ حَدَّثَنَا أَبُو يُونُسَ حَاتِمُ بْنُ أَبِي صَغِيرَةَ قَالَ حَدَّثَنِي النُّعْمَانُ بْنُ سَالِمٍ أَنَّ عَمْرَو بْنَ أَوْسٍ أَخْبَرَهُ عَنْ أَبِيهِ أَوْسٍ قَالَ إِنَّا لَقُعُودٌ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحَدِّثُنَا وَيُوصِينَا إِذْ أَتَاهُ رَجُلٌ فَذَكَرَ مِثْلَهُ","id":"(Ahmad bin hanbal) berkata; telah menceritakan kepada kami [Abdullah bin Bakr As-Sahmi] berkata; telah menceritakan kepada kami [Hatim bin Abu Saghirah] dari [An Nu'man bin Salim] ['Amr bin Aus] mengabarinya, [Bapaknya, Aus] mengabarinya berkata; kami sedang duduk di samping Rasulullah Shallallahu'alaihiwasallam di suatu bangunan, beliau berbagi cerita kepada kami dan mengingatkan kami. Tiba-tiba datanglah seorang yang marah-marah kepada beliau. Lalu beliau bersabda: \"Pergilah dan bunuhlah dia\". (Aus) berkata; tatkala laki-laki itu telah berpaling, Rasulullah Shallallahu'alaihiwasallam memanggilnya dan bersabda: \"Apakah dia mengucapkan \"Tidak ada tuhan selain Allah? '\". Orang itu berkata; ya, ya Wahai Rasulullah, Lalu beliau bersabda: \"Pergilah dan biarkanlah, saya hanya diperintah untuk memerangi manusia sampai mereka bersaksi bahwa tidak ada sesembahan yang hak selain Allah. Jika mereka melakukan hal itu, maka diharamkan bagiku darah mereka dan harta mereka kecuali ada alasan yang dibenarkan.\" (Ahmad bin hanbal) berkata; telah menceritakan kepada kami [Muhammad bin Abdullah Al Anshari] berkata; telah menceritakan kepada kami [Abu Yunus, Hatim bin Abu Saghirah] berkata; telah menceritakan kepadaku [Nu'man bin Salim] ['Amr bin Aus] mengabarinya dari [Bapaknya, Aus] berkata; kami sedang duduk di sisi Rasulullah Shallallahu'alaihiwasallam, beliau menceritakan kepada kami dan memberi nasehat kepada kami. Tiba-tiba datang seorang laki-laki, lalu menyebutkan hadis secara lengkap."},"917":{"ar":"قَالَ حَدَّثَنَا بَهْزُ بْنُ أَسَدٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا يَعْلَى بْنُ عَطَاءٍ عَنْ أَوْسِ بْنِ أَبِي أَوْسٍ قَالَرَأَيْتُ أَبِي يَوْمًا تَوَضَّأَ فَمَسَحَ النَّعْلَيْنِ فَقُلْتُ لَهُ أَتَمْسَحُ عَلَيْهِمَا فَقَالَ هَكَذَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْعَلُ","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Bahz bin Asad] telah menceritakan kepada kami [Hammad bin Salamah] telah menceritakan kepada kami [Ya'la bin 'Atha`] dari [Aus bin Abu Aus] berkata; saya telah melihat [bapakku] pada suatu hari berwudlu dan mengusap kedua sandalnya, lalu saya bertanya kepadanya, apakah bapak mengusap keduanya?. Dia menjawab, beginilah saya melihat Rasulullah Shallallahu'alaihiwasallam melakukan."},"918":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ الطَّائِفِيُّ عَنْ عُثْمَانَ بْنِ عَبْدِ اللَّهِ بْنِ أَوْسٍ الثَّقَفِيِّ عَنْ جَدِّهِ أَوْسِ بْنِ حُذَيْفَةَ قَالَكُنْتُ فِي الْوَفْدِ الَّذِينَ أَتَوْا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْلَمُوا مِنْ ثَقِيفٍ مِنْ بَنِي مَالِكٍ أَنْزَلَنَا فِي قُبَّةٍ لَهُ فَكَانَ يَخْتَلِفُ إِلَيْنَا بَيْنَ بُيُوتِهِ وَبَيْنَ الْمَسْجِدِ فَإِذَا صَلَّى الْعِشَاءَ الْآخِرَةَ انْصَرَفَ إِلَيْنَا وَلَا نَبْرَحُ حَتَّى يُحَدِّثَنَا وَيَشْتَكِي قُرَيْشًا وَيَشْتَكِي أَهْلَ مَكَّةَ ثُمَّ يَقُولُ لَا سَوَاءَ كُنَّا بِمَكَّةَ مُسْتَذَلِّينَ وَمُسْتَضْعَفِينَ فَلَمَّا خَرَجْنَا إِلَى الْمَدِينَةِ كَانَتْ سِجَالُ الْحَرْبِ عَلَيْنَا وَلَنَا فَمَكَثَ عَنَّا لَيْلَةً لَمْ يَأْتِنَا حَتَّى طَالَ ذَلِكَ عَلَيْنَا بَعْدَ الْعِشَاءِ قَالَ قُلْنَا مَا أَمْكَثَكَ عَنَّا يَا رَسُولَ اللَّهِ قَالَ طَرَأَ عَلَيَّ حِزْبٌ مِنْ الْقُرْآنِ فَأَرَدْتُ أَنْ لَا أَخْرُجَ حَتَّى أَقْضِيَهُ قَالَ فَسَأَلْنَا أَصْحَابَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ أَصْبَحْنَا قَالَ قُلْنَا كَيْفَ تُحَزِّبُونَ الْقُرْآنَ قَالُوا نُحَزِّبُهُ ثَلَاثَ سُوَرٍ وَخَمْسَ سُوَرٍ وَسَبْعَ سُوَرٍ وَتِسْعَ سُوَرٍ وَإِحْدَى عَشْرَةَ سُورَةً وَثَلَاثَ عَشْرَةَ سُورَةً وَحِزْبَ الْمُفَصَّلِ مِنْ قَافْ حَتَّى يُخْتَمَ","id":"(Ahmad bin hanbal) berkata; telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Abdullah bin Abdurrahman Ath-Tha'ifi] dari ['Utsman bin Abdullah bin Aus Ats-Tsaqafi] dari [kakeknya, Aus bin Hudzaifah] berkata; saya berada dalam rombongan utusan yang mendatangi Nabi Shallallahu'alaihiwasallam. Mereka telah masuk Islam, dari kabilah tsaqif Tsaqif, dari Bani Malik. Kami mendatangi kemah besar beliau, yang kemah tersebut berada antara rumahnya dan masjid. Jika beliau telah melaksanakan shalat isya' pada akhir malam, beliau mengunjungi kami, dan kami tidak meninggalkan tempat itu sampai beliau menceritakan kepada kami dan mengadukan penderitaannya dari orang Quraisy dan penduduk Makkah. Selanjutnya beliau bersabda: \"Tidak sama, kami di Makkah dalam keadaan selalu dihinakan dan dilemahkan. Tatkala kami keluar ke Madinah, terjadilah peperangan, Kemenangan dan kekalahan terjadi silih berganti, terkadang kami menerima kekalahan, namun terkadang memperoleh kemenangan\". Suatu malam beliau tidak mendatangi kami, hal itu berlalu sekian lama sesudah waktu isya'. (Aus bin Hudzaifah) berkata; apa yang menyebabkan anda meninggalkan kami Wahai Rasulullah? Beliau bersabda: \"Telah turun kepadaku sekian kumpulan alqur'an, sehingga memaksa saya tidak keluar sampai hal itu selesai. (Aus bin Hudzaifah) berkata; kami bertanya kepada para sahabat Rasulullah Shallallahu'alaihiwasallam pada pagi harinya. Bagaimana kalian membagi pengelompokan Al qur'an?, mereka menjawab, kami membaginya menjadi tiga surat, lima surat, tujuh surat, sembilan surat, sebelas surat, tiga belas surat, dan hizb Al mufashshal yaitu dari surat QAF sampai akhir."},"919":{"ar":"قَالَ حَدَّثَنَا وَكِيعٌ عَنْ شَرِيكٍ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ أَوْسِ بْنِ أَبِي أَوْسٍ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ وَمَسَحَ عَلَى نَعْلَيْهِ","id":"(Ahmad bin hanbal) berkata; telah menceritakan kepada kami [Waki'] dari [Syarik] dari [Ya'la bin 'Atha`] dari [Aus bin Abu Aus] dari [Bapaknya] Nabi Shallallahu'alaihiwasallam berwudlu dengan mengusap kedua sandalnya."},"920":{"ar":"قَالَ حَدَّثَنَا بَهْزٌ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا النُّعْمَانُ بْنُ سَالِمٍ عَنْ رَجُلٍ جَدُّهُ أَوْسُ بْنُ أَبِي أَوْسٍكَانَ يُصَلِّي وَيُومِئُ إِلَى نَعْلَيْهِ وَهُوَ فِي الصَّلَاةِ فَيَأْخُذُهُمَا فَيَنْتَعِلُهُمَا وَيُصَلِّي فِيهِمَا وَيَقُولُ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي نَعْلَيْهِ","id":"(Ahmad bin hanbal) berkata; telah menceritakan kepada kami [Bahz] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [An Nu'man bin Salim] dari [seorang laki-laki], yaitu kakeknya, [Aus bin Abu Aus] dia shalat dan memberi isyarat kepada sepasang sandalnya padahal dalam keadaan shalat, lalu dia mengambil keduanya dan memakainya dan dipergunakannya untuk shalat. Lalu dia berkata; Rasulullah Shallallahu'alaihiwasallam shalat dengan memakai kedua sandalnya."},"921":{"ar":"حَدَّثَنَا بَهْزٌ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ وَكِيعِ بْنِ عُدُسٍ عَنْ عَمِّهِ أَبِي رَزِينٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الرُّؤْيَا مُعَلَّقَةٌ بِرِجْلِ طَائِرٍ مَا لَمْ يُحَدِّثْ بِهَا صَاحِبُهَا فَإِذَا حَدَّثَ بِهَا وَقَعَتْ وَلَا تُحَدِّثُوا بِهَا إِلَّا عَالِمًا أَوْ نَاصِحًا أَوْ لَبِيبًا وَالرُّؤْيَا الصَّالِحَةُ جُزْءٌ مِنْ أَرْبَعِينَ جُزْءًا مِنْ النُّبُوَّةِ","id":"Telah menceritakan kepada kami [Bahz] berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Ya'la bin 'Atha`] dari [Waki' bin 'Udus] dari [pamannya, Abu Razin] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Setiap mimpi adalah sebuah misteri selama orang yang bermimpi belum menceritakannya. Jika dia telah menceritakannya, maka akan terjadi. Janganlah kalian menceritakannya kecuali kepada orang alim, atau orang yang bisa memberi nasehat atau orang yang berakal, mimpi yang baik adalah bagian dari empat puluh bagian kenabian\""},"922":{"ar":"حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنِ النُّعْمَانِ بْنِ سَالِمٍ عَنْ عَمْرِو بْنِ أَوْسٍ عَنْ أَبِي رَزِينٍ الْعُقَيْلِيِّ أَنَّهُأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ أَبِي شَيْخٌ كَبِيرٌ لَا يَسْتَطِيعُ الْحَجَّ وَلَا الْعُمْرَةَ وَلَا الظَّعْنَ قَالَ حُجَّ عَنْ أَبِيكَ وَاعْتَمِرْ","id":"Telah menceritakan kepada kami [Waki'] berkata; telah menceritakan kepada kami [Syu'bah] dari [An Nu'man bin Salim] dari ['Amr bin Aus] dari [Abu Razin Al 'Uqaily] dia mendatangi Nabi Shallallahu'alaihiwasallam dan berkata; bapakku sudah tua dan tidak mampu lagi untuk berhaji, umrah dan juga berkendaraan. Rasulullah Shallallahu'alaihiwasallam bersabda: \"Berhajilah dan berumrahlah untuk menggantikan bapakmu.\""},"923":{"ar":"قَالَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ وَكِيعِ بْنِ عُدُسٍ عَنْ عَمِّهِ أَبِي رَزِينٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَكُلُّنَا يَرَى اللَّهَ عَزَّ وَجَلَّ يَوْمَ الْقِيَامَةِ وَمَا آيَةُ ذَلِكَ فِي خَلْقِهِ قَالَ يَا أَبَا رَزِينٍ أَلَيْسَ كُلُّكُمْ يَرَى الْقَمَرَ مُخْلِيًا بِهِ قَالَ قُلْتُ بَلَى يَا رَسُولَ اللَّهِ قَالَ فَاللَّهُ أَعْظَمُ","id":"(Ahmad bin hanbal) berkata; telah menceritakan kepada kami [Yazid bin Harun] berkata; telah mengabarkan kepada kami [Hammad bin Salamah] dari [Ya'la bin 'Atho`] dari [Waki' bin 'Udus] dari [pamannya, Abu Razin] berkata; saya berkata; Wahai Rasulullah, apakah semua dari kita bisa melihat Allah AzzaWaJalla pada Hari Kiamat, tolong jelaskan tandanya dari ciptaAn Nya!. Beliau bersabda: \"Wahai Abu Razin, tidakkah kalian semua bisa melihat bulan dengan mata telanjang?\". (Abu Razin) berkata; saya menjawab, ya Wahai Rasulullah? Beliau bersabda: \"Allah lebih Agung.\""},"924":{"ar":"قَالَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ وَكِيعِ بْنِ عُدُسٍ عَنْ عَمِّهِ أَبِي رَزِينٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَحِكَ رَبُّنَا مِنْ قُنُوطِ عَبْدِهِ وَقُرْبِ غَيْرِهِ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ أَوَيَضْحَكُ الرَّبُّ عَزَّ وَجَلَّ قَالَ نَعَمْ قَالَ لَنْ نَعْدَمَ مِنْ رَبٍّ يَضْحَكُ خَيْرًا","id":"(Ahmad bin hanbal) berkata; telah menceritakan kepada kami [Yazid bin Harun] berkata; telah mengabarkan kepada kami [Hammad bin Salamah] dari [Ya'la bin 'Atha`] dari [Waki' bin 'Udus] dari [pamannya, Abu Razin] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Rabb kita tertawa terhadap hamba-Nya yang berputus asa karena sadar dirinya lemah dan membutuhkan pertolongan\". (Abu Razin) berkata; saya bertanya, \"Wahai Rasulullah, Apakah Rabb AzzaWaJalla tertawa?\" Rasulullah bersabda: \"Ya\". (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Selama Rab kita tertawa, kita tidak kehilangan kebaikan.\""},"925":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ وَكِيعِ بْنِ عُدُسٍ عَنْ عَمِّهِ أَبِي رَزِينٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَيْنَ كَانَ رَبُّنَا عَزَّ وَجَلَّ قَبْلَ أَنْ يَخْلُقَ خَلْقَهُ قَالَ كَانَ فِي عَمَاءٍ مَا تَحْتَهُ هَوَاءٌ وَمَا فَوْقَهُ هَوَاءٌ ثُمَّ خَلَقَ عَرْشَهُ عَلَى الْمَاءِ","id":"Telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Hammad bin Salamah] dari [Ya'la bin 'Atho`] dari [Waki' bin 'Udus] dari [pamannya, Abu Razin] berkata; saya berkata; \"Wahai Rasulullah, di mana Rab kita AzzaWaJalla sebelum mencipta makhluq-Nya?\", beliau berkata; \"Dia berada di awan yang bagian bawah dan atasnya adalah ruang udara kemudian Dia menciptakan Arsy-Nya di atas air\""},"926":{"ar":"قَالَ حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي النُّعْمَانُ بْنُ سَالِمٍ قَالَ سَمِعْتُ عَمْرَو بْنَ أَوْسٍ يُحَدِّثُ عَنْ أَبِي رَزِينٍ أَنَّهُ قَالَيَا رَسُولَ اللَّهِ إِنَّ أَبِي شَيْخٌ كَبِيرٌ لَا يَسْتَطِيعُ الْحَجَّ وَالْعُمْرَةَ وَلَا الظَّعْنَ قَالَ حُجَّ عَنْ أَبِيكَ وَاعْتَمِرْ","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami ['Affan] berkata; telah menceritakan kepada kami [Syu'bah] berkata; telah menghabarkan kepadaku [An Nu'man bin Salim] berkata; saya mendengar ['Amr bin Aus] menceritakan dari [Abu Razin] dia berkata; Wahai Rasulullah, bapakku orang yang sudah tua, tidak mampu untuk berhaji dan umrah atau naik kendaraan. (Rasulullah shallallahu'alaihiwasallam) bersabda: \"Berhajilah dan umrahlah untuk menggantikan bapakmu.\""},"927":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا سُفْيَانُ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ أَبِي رَزِينٍ لَقِيطٍ عَنْ عَمِّهِ رَفَعَهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رُؤْيَا الْمُؤْمِنِ جُزْءٌ مِنْ أَرْبَعِينَ جُزْءًا مِنْ النُّبُوَّةِ أَشُكُّ أَنَّهُ قَالَ رُؤْيَا الْمُؤْمِنِ عَلَى رِجْلِ طَائِرٍ مَا لَمْ يُخْبِرْ بِهَا فَإِذَا أَخْبَرَ بِهَا وَقَعَتْ","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Abdurrazzaq] berkata; telah menghabarkan kepada kami [Sufyan] dari [Ya'la bin 'Atha`] dari [Abu Razin, Laqith] dari [Pamannya] dengan memarfukkannya, berkata; Nabi bersabda: \"Mimpi seorang mukmin adalah bagian dari empat puluh bagian kenabian\", saya ragu dia berkata; mimpi seorang mukmin adalah sebuah misteri selama belum dikabarkannya. Jika dikabarkan maka akan terjadi."},"928":{"ar":"قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ وَكِيعِ بْنِ حُدُسٍ عَنْ أَبِي رَزِينٍ عَمِّهِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ كَيْفَ يُحْيِي اللَّهُ الْمَوْتَى فَقَالَ أَمَا مَرَرْتَ بِالْوَادِي مُمْحِلًا ثُمَّ تَمُرُّ بِهِ خَضِرًا قَالَ شُعْبَةُ قَالَهُ أَكْثَرَ مِنْ مَرَّتَيْنِ كَذَلِكَ يُحْيِي اللَّهُ الْمَوْتَى","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] berkata; telah menceritakan kepada kami [Syu'bah] dari [Ya'la bin 'Atha`] dari [Waki' bin Hudus] dari [Abu Razin, pamannya] berkata; saya berkata; Wahai Rasulullah, bagaimana Allah menghidupkan makhluq yang sudah mati?. Lalu (Rasulullah shallallahu'alaihiwasallam) bersabda: \"Bagaimana jika kalian melewati suatu bukit yang sangat tandus lalu kalian melewatinya dalam keadaan yang sangat subur?.\" Syu'bah berkata; beliau mengatakannya lebih dari dua kali, demikianlah Allah menghidupkan makhluq yang mati."},"929":{"ar":"قَالَ حَدَّثَنَا عَلِيُّ بْنُ إِسْحَاقَ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ يَعْنِي ابْنَ الْمُبَارَكِ قَالَ أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ يَزِيدَ بْنِ جَابِرٍ عَنْ سُلَيْمَانَ بْنِ مُوسَى عَنْ أَبِي رَزِينٍ الْعُقَيْلِيِّ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ كَيْفَ يُحْيِي اللَّهُ الْمَوْتَى قَالَ أَمَا مَرَرْتَ بِأَرْضٍ مِنْ أَرْضِكَ مُجْدِبَةٍ ثُمَّ مَرَرْتَ بِهَا مُخْصَبَةً قَالَ نَعَمْ قَالَ كَذَلِكَ النُّشُورُ قَالَ يَا رَسُولَ اللَّهِ وَمَا الْإِيمَانُ قَالَ أَنْ تَشْهَدَ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ وَأَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ وَأَنْ يَكُونَ اللَّهُ وَرَسُولُهُ أَحَبَّ إِلَيْكَ مِمَّا سِوَاهُمَا وَأَنْ تُحْرَقَ بِالنَّارِ أَحَبُّ إِلَيْكَ مِنْ أَنْ تُشْرِكَ بِاللَّهِ وَأَنْ تُحِبَّ غَيْرَ ذِي نَسَبٍ لَا تُحِبُّهُ إِلَّا لِلَّهِ عَزَّ وَجَلَّ فَإِذَا كُنْتَ كَذَلِكَ فَقَدْ دَخَلَ حُبُّ الْإِيمَانِ فِي قَلْبِكَ كَمَا دَخَلَ حُبُّ الْمَاءِ لِلظَّمْآنِ فِي الْيَوْمِ الْقَائِظِ قُلْتُ يَا رَسُولَ اللَّهِ كَيْفَ لِي بِأَنْ أَعْلَمَ أَنِّي مُؤْمِنٌ قَالَ مَا مِنْ أُمَّتِي أَوْ هَذِهِ الْأُمَّةِ عَبْدٌ يَعْمَلُ حَسَنَةً فَيَعْلَمُ أَنَّهَا حَسَنَةٌ وَأَنَّ اللَّهَ عَزَّ وَجَلَّ جَازِيهِ بِهَا خَيْرًا وَلَا يَعْمَلُ سَيِّئَةً فَيَعْلَمُ أَنَّهَا سَيِّئَةٌ وَاسْتَغْفَرَ اللَّهَ عَزَّ وَجَلَّ مِنْهَا وَيَعْلَمُ أَنَّهُ لَا يَغْفِرُ إِلَّا هُوَ إِلَّا وَهُوَ مُؤْمِنٌ","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami ['Ali bin Ishaq] berkata; telah menghabarkan kepada kami [Abdullah] yaitu Ibnu Al Mubarak, berkata; telah menghabarkan kepada kami [Abdurrahman bin Yazid bin Jabir] dari [Sulaiman bin Musa] dari [Abu Razin Al 'Uqaili] berkata; saya menemui Rasulullah shallallahu'alaihiwasallam lalu saya berkata; Wahai Rasulullah, bagaimana Allah menghidupkan orang yang mati, apa bukti tersebut bagi makhluq-Nya? (Rasulullah shallallahu'alaihiwasallam) menjawab, \"Apa kalian pernah melewati suatu tanah yang tandus lalu kalian melewatinya dalam keadaan subur?\" (Abu Razin) berkata; \"Ya.\" Lalu (Rasulullah shallallahu'alaihiwasallam) bersabda: \"Begitulah fenomena kebangkitan.\" (Abu Razin) berkata; Wahai Rasulullah, apakah iman itu? Beliau bersabda: \"Kamu bersaksi bahwa tidak ada sesembahan yang hak selain Allah, Yang Maha Esa, tidak ada sekutu bagi-Nya, Muhammad adalah hamba-Nya dan Rasul-Nya. Allah dan Rasul-Nya lebih kamu sukai daripada selainnya. Ia dibakar dengan neraka lebih dia sukai daripada menyekutukan Allah. Kamu mencintai orang yang tidak punya kekerabatan denganmu, kamu tidak mencintainya kecuali hanya karena Allah AzzaWaJalla. Jika kamu seperti itu, kecintaan kepada iman telah masuk dalam hatimu, sebagaimana masuknya air kepada orang yang haus pada hari yang sangat panas. Saya bertanya, Wahai Rasulullah, bagaimana saya mengetahui bahwa saya adalah seorang mukmin?. Beliau bersabda: \"Tidaklah dari umatku, atau dari umat ini seorang hamba yang mengerjakan kebaikan, lalu dia mengetahui bahwa hal itu adalah kebaikan, ia sadar bahwa Allah AzzaWaJalla akan membalasnya dengan kebaikan, dia tidak melakukan kejelekan dan dia mengetahui bahwa itu adalah kejelekan, lalu dia meminta ampunan kepada Allah AzzaWaJalla, dan dia sadar bahwa tidak ada yang mengampuni selain Dia kecuali orang yang mukmin.\""},"930":{"ar":"قَالَ حَدَّثَنَا بَهْزٌ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي يَعْلَى بْنُ عَطَاءٍ قَالَ سَمِعْتُ وَكِيعَ بْنَ حُدُسٍ يُحَدِّثُ عَنْ عَمِّهِ أَبِي رَزِينٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ رُؤْيَا الْمُسْلِمِ جُزْءٌ مِنْ أَرْبَعِينَ جُزْءًا مِنْ النُّبُوَّةِ وَهِيَ عَلَى رِجْلِ طَائِرٍ مَا لَمْ يُحَدِّثْ بِهَا فَإِذَا حَدَّثَ بِهَا وَقَعَتْ قَالَ أَظُنُّهُ قَالَ لَا يُحَدِّثُ بِهَا إِلَّا حَبِيبًا أَوْ لَبِيبًا","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Bahz] berkata; telah menceritakan kepada kami [Syu'bah] berkata; telah menghabarkan kepadaku [Ya'la bin 'Atha`] berkata; saya mendengar [Waki' bin Hudus] dari [Pamannya, Abu Razin] Rasulullah shallallahu'alaihiwasallam bersabda: \"Mimpi seorang muslim adalah bagian dari empat puluh kenabian, dan hal itu merupakan sebuah misteri selama belum diceritakannya. Jika dia menceritakannya maka akan terjadi.\" (Abu Razin) berkata; setahu saya beliau mengatakan 'Janganlah kamu menceritakannya kecuali kepada orang yang dia sukai atau kepada orang yang berakal.'"},"931":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي إِبْرَاهِيمُ بْنُ الْحَجَّاجِ النَّاجِيُّ قَالَ حَدَّثَنَا عَبْدُ الْقَاهِرِ بْنُ السَّرِيِّ قَالَ حَدَّثَنِي ابْنٌ لِكِنَانَةَ بْنِ عَبَّاسِ بْنِ مِرْدَاسٍ عَنْ أَبِيهِ أَنَّ أَبَاهُ الْعَبَّاسَ بْنَ مِرْدَاسٍ حَدَّثَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعَا عَشِيَّةَ عَرَفَةَ لِأُمَّتِهِ بِالْمَغْفِرَةِ وَالرَّحْمَةِ فَأَكْثَرَ الدُّعَاءَ فَأَجَابَهُ اللَّهُ عَزَّ وَجَلَّ أَنْ قَدْ فَعَلْتُ وَغَفَرْتُ لِأُمَّتِكَ إِلَّا مَنْ ظَلَمَ بَعْضُهُمْ بَعْضًا فَقَالَ يَا رَبِّ إِنَّكَ قَادِرٌ أَنْ تَغْفِرَ لِلظَّالِمِ وَتُثِيبَ الْمَظْلُومَ خَيْرًا مِنْ مَظْلَمَتِهِ فَلَمْ يَكُنْ فِي تِلْكَ الْعَشِيَّةِ إِلَّا ذَا فَلَمَّا كَانَ مِنْ الْغَدِ دَعَا غَدَاةَ الْمُزْدَلِفَةِ فَعَادَ يَدْعُو لِأُمَّتِهِ فَلَمْ يَلْبَثْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تَبَسَّمَ فَقَالَ بَعْضُ أَصْحَابِهِ يَا رَسُولَ اللَّهِ بِأَبِي أَنْتَ وَأُمِّي ضَحِكْتَ فِي سَاعَةٍ لَمْ تَكُنْ تَضْحَكُ فِيهَا فَمَا أَضْحَكَكَ أَضْحَكَ اللَّهُ سِنَّكَ قَالَ تَبَسَّمْتُ مِنْ عَدُوِّ اللَّهِ إِبْلِيسَ حِينَ عَلِمَ أَنَّ اللَّهَ عَزَّ وَجَلَّ قَدْ اسْتَجَابَ لِي فِي أُمَّتِي وَغَفَرَ لِلظَّالِمِ أَهْوَى يَدْعُو بِالثُّبُورِ وَالْوَيْلِ وَيَحْثُو التُّرَابَ عَلَى رَأْسِهِ فَتَبَسَّمْتُ مِمَّا يَصْنَعُ جَزَعُهُ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku [Ibrahim bin Alhajjaj] berkata; telah menceritakan kepada kami [Abdul Qahir bin As-Sari] berkata; telah menceritakan kepadaku [salah seorang anak Kinanah bin 'Abbas bin Mirdas] dari [bapaknya] bapaknya, [Al 'Abbas bin Mirdas], menceritakannya, Rasulullah shallallahu'alaihiwasallam, berdoa untuk ummatnya di Arafah pada waktu sore dengan pengampunan dan rahmat. Beliau memperbanyak doa, lalu Allah AzzaWaJalla menjawabnya, telah Aku kerjakan dan telah Aku ampuni dosa ummatmu kecuali yang berlaku zhalim di antara kalian. (Rasulullah shallallahu'alaihiwasallam) bersabda: \"Wahai Rabku Engkau mampu untuk mengampuni yang berbuat zhalim dan memberikan pahala bagi yang teraniaya atas kezhalimannya.\" Tidaklah beliau berdoa sore itu kecuali seperti itu, sampai kemudian pada esok harinya di Muzdalifah berdoa seperti sebelumnya, sampai kemudian terlihat senyum beliau. Sebagian sahabat berkata; \"Wahai Rasulullah, demi bapak dan ibumu, sungguh engkau tertawa pada waktu yang engkau tidak pernah tertawa saat itu, apakah gerangan yang membuatmu tertawa, apakah Allah yang yang menjadikan anda tertawa. (Rasulullah shallallahu'alaihiwasallam) bersabda: \"Aku tertawa dari musuh Allah iblis, ketika dia mengetahui bahwa Allah AzzaWaJalla mengabulkan permintaan doaku dengan mengampuni ummatku dan yang berbuat zhalim, kemudian mengampuni orang yang berbuat aniaya, Iblis mengambil pasir lalu manaburkannya di atas kepalanya, maka aku tersenyum karenanya.\""},"932":{"ar":"قَالَ حَدَّثَنَا هُشَيْمٌ عَنِ ابْنِ أَبِي خَالِدٍ وَزَكَرِيَّا عَنِ الشَّعْبِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ مُضَرِّسٍ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ بِجَمْعٍ فَقُلْتُ يَا رَسُولَ اللَّهِ جِئْتُكَ مِنْ جَبَلَيْ طَيِّءٍ أَتْعَبْتُ نَفْسِي وَأَنْصَبْتُ رَاحِلَتِي وَاللَّهِ مَا تَرَكْتُ مِنْ جَبَلٍ إِلَّا وَقَفْتُ عَلَيْهِ فَهَلْ لِي مِنْ حَجٍّ فَقَالَ مَنْ شَهِدَ مَعَنَا هَذِهِ الصَّلَاةَ يَعْنِي صَلَاةَ الْفَجْرِ بِجَمْعٍ وَوَقَفَ مَعَنَا حَتَّى نُفِيضَ مِنْهُ وَقَدْ أَفَاضَ قَبْلَ ذَلِكَ مِنْ عَرَفَاتٍ لَيْلًا أَوْ نَهَارًا فَقَدْ تَمَّ حَجُّهُ وَقَضَى تَفَثَهُ","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Husyaim] dari [Ibnu Abu Khalid] dan [Zakariya] dari [Asy-Sya'bi] berkata; telah mengabarkan kepadaku ['Urwah bin Mudlarris] berkata; saya mendatangi Nabi Shallallahu'alaihiwasallam dan beliau sedang di Jam', saya berkata kepada beliau 'Wahai Rasulullah, aku datang kepada engkau dari daerah gunung Thayyi' sehingga aku keletihan dan tungganganku kelelahan, Demi Allah, tidaklah aku tinggalkan gunung kecuali agar dapat berdiri di sana. Apakah dengan ini, saya mendapatkan haji (tidak batalkah hajiku)?, maka (Rasulullah shallallahu'alaihiwasallam) bersabda: \"Barangsiapa shalat subuh bersama kami di Muzdalifah, dan melakukan wuquf bersama kita lalu bertolak darinya, atau sudah bertolak sebelumnya dari Arafah baik malam atau siang maka haji telah sah\" "},"933":{"ar":"قَالَ حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا زَكَرِيَّا عَنِ الشَّعْبِيِّ قَالَ حَدَّثَنِي عُرْوَةُ بْنُ مُضَرِّسِ بْنِ أَوْسِ بْنِ حَارِثَةَ بْنِ لَامٍأَنَّهُ حَجَّ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يُدْرِكْ النَّاسَ إِلَّا لَيْلًا وَهُوَ بِجَمْعٍ فَانْطَلَقَ إِلَى عَرَفَاتٍ فَأَفَاضَ مِنْهَا ثُمَّ رَجَعَ فَأَتَى جَمْعًا فَقَالَ يَا رَسُولَ اللَّهِ أَتْعَبْتُ نَفْسِي وَأَنْصَبْتُ رَاحِلَتِي فَهَلْ لِي مِنْ حَجٍّ فَقَالَ مَنْ صَلَّى مَعَنَا صَلَاةَ الْغَدَاةِ بِجَمْعٍ وَوَقَفَ مَعَنَا حَتَّى نُفِيضَ وَقَدْ أَفَاضَ قَبْلَ ذَلِكَ مِنْ عَرَفَاتٍ لَيْلًا أَوْ نَهَارًا فَقَدْ تَمَّ حَجُّهُ وَقَضَى تَفَثَهُ","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Abu Nua'im] berkata; telah menceritakan kepada kami [Zakariya] dari [Asy-Sya'bi] berkata; telah menceritakan kepada kami ['Urwah bin Mudlarris bin Aus bin Haritsah bin Lam] dia melakukan haji pada masa Rasulullah shallallahu'alaihiwasallam, dia tidak menjumpai orang-orang kecuali pada malam hari ketika di Muzdalifah, lalu dia berangkat ke Arafah dan bertolak daripadanya dengan cepat, ia pulang dan datang lagi ke Jama' (Muzdalifah). Lalu dia berkata; Wahai Rasulullah, saya telah kecapekan dan tungganganku telah kelelahan, apakah saya telah mendapatkan haji?. (Rasulullah shallallahu'alaihiwasallam) bersabda: \"Barangsiapa yang shalat subuh bersama kami di di Jam' (Muzdalifah) dan melakukan wuquf bersama kami hingga kita bertolak (dari Arafah) padahal sebelumnya ia telah bertolak dari Arafah pada. malam atau siangnya, berarti telah terlaksana hajinya dan menuntaskan manasiknya"},"934":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ قَالَ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أُخْبِرْتُ أَنَّ أَبَا سَعِيدٍ الْخُدْرِيَّ و عَنْ سُلَيْمَانَ بْنِ مُوسَى عَنْ فُلَانٍ و عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ وَلَمْ يَبْلُغْ أَبُو الزُّبَيْرِ هَذِهِ الْقِصَّةَ كُلَّهَاأَنَّ أَبَا قَتَادَةَ أَتَى أَهْلَهُ فَوَجَدَ قَصْعَةَ ثَرِيدٍ مِنْ قَدِيدِ الْأَضْحَى فَأَبَى أَنْ يَأْكُلَهُ فَأَتَى قَتَادَةَ بْنَ النُّعْمَانِ فَأَخْبَرَهُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ فِي حَجٍّ فَقَالَ إِنِّي كُنْتُ أَمَرْتُكُمْ أَنْ لَا تَأْكُلُوا الْأَضَاحِيَّ فَوْقَ ثَلَاثَةِ أَيَّامٍ لِتَسَعَكُمْ وَإِنِّي أُحِلُّهُ لَكُمْ فَكُلُوا مِنْهُ مَا شِئْتُمْ قَالَ وَلَا تَبِيعُوا لُحُومَ الْهَدْيِ وَالْأَضَاحِيِّ فَكُلُوا وَتَصَدَّقُوا وَاسْتَمْتِعُوا بِجُلُودِهَا وَإِنْ أُطْعِمْتُمْ مِنْ لُحُومِهَا شَيْئًا فَكُلُوهُ إِنْ شِئْتُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Bakr] berkata; telah menghabarkan kepada kami [Ibnu Juraij] berkata; saya telah diberi kabar, [Abu Sa'id Al Khudri], dan dari [Sulaiman bin Musa] dari [Fulan] dan [Abu Zubair] dari [Jabir bin Abdullah] dan belum tersampaikan kisah ini kepada Abu Zubair secara keseluruhan, Abu Qatadah mendatangi keluarganya lalu mendapati periuk (yang bisa memuat sepuluh orang) yang berisi tsarid (makanan yang terbuat dari daging dan roti) dari bahan dendeng hewan kurban, lalu dia menolak untuk memakannnya. [Qatadah bin Nu'man] datang, mengabarkan kepadanya, Nabi Shallallahu'alaihiwasallam berdiri pada Hari Haji dan bersabda: \"Aku dahulu memperintahkan kalian untuk tidak memakan sembelihan kurban di atas tiga hari untuk mencukupkan kalian. Sekarang aku memperbolehkan kalian darinya sekehendak hati kalian.\" Dan beliau bersabda: \"Janganlah kalian menjual daging Hadyu (daging yang disembelih Jamaah Haji waktu pelaksanaan ibadah), tapi makanlah, bersedekahlah dan nikmatilah dengan kulitnya. Jika kalian diberi makan dengan daging tersebut maka makanlah sekehendak hati kalian.\""},"935":{"ar":"قَالَ حَدَّثَنَا حَجَّاجٌ قَالَ حَدَّثَنِي ابْنُ جُرَيْجٍ قَالَ قَالَ سُلَيْمَانُ بْنُ مُوسَى أَخْبَرَنِي زُبَيْدٌأَنَّ أَبَا سَعِيدٍ الْخُدْرِيَّ أَتَى أَهْلَهُ فَوَجَدَ قَصْعَةً مِنْ قَدِيدِ الْأَضْحَى فَأَبَى أَنْ يَأْكُلَهُ فَأَتَى قَتَادَةَ بْنَ النُّعْمَانِ فَأَخْبَرَهُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ فَقَالَ إِنِّي كُنْتُ أَمَرْتُكُمْ أَنْ لَا تَأْكُلُوا الْأَضَاحِيَّ فَوْقَ ثَلَاثَةِ أَيَّامٍ لِتَسَعَكُمْ وَإِنِّي أُحِلُّهُ لَكُمْ فَكُلُوا مِنْهُ مَا شِئْتُمْ وَلَا تَبِيعُوا لُحُومَ الْهَدْيِ وَالْأَضَاحِيِّ فَكُلُوا وَتَصَدَّقُوا وَاسْتَمْتِعُوا بِجُلُودِهَا وَلَا تَبِيعُوهَا وَإِنْ أُطْعِمْتُمْ مِنْ لَحْمِهَا فَكُلُوا إِنْ شِئْتُمْو قَالَ فِي هَذَا الْحَدِيثِ عَنْ أَبِي سَعِيدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَالْآنَ فَكُلُوا وَاتَّجِرُوا وَادَّخِرُوا قَالَ حَدَّثَنَا حَجَّاجٌ عَنِ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي أَبُو الزُّبَيْرِ عَنْ جَابِرٍ نَحْوَ حَدِيثِ زُبَيْدٍ هَذَا عَنْ أَبِي سَعِيدٍ لَمْ يَبْلُغْهُ كُلُّ ذَلِكَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Hajjaj] berkata; telah menceritakan kepadaku [Ibnu Juraij] berkata; [Sulaiman bin Musa] berkata; telah mengabarkan kepadaku [Zubaid], [Abu Sa'id Al Khudri] menemui keluarganya lalu mendapati periuk (yang bisa memuat sepuluh orang) yang berisi daging hewan kurban, dan dia menolak memakannya. Selanjutnya dia menemui [Qatadah bin Nu'man], lalu dia mengabarkan kepada (Abu Sa'id Al Khudri), Nabi Shallallahu'alaihiwasallam berdiri pada Hari Haji dan bersabda: \"Aku dahulu memerintahkan kalian untuk tidak memakan sembelihan kurban di atas tiga hari untuk mencukupkan kalian. Sekarang saya halalkan untuk kalian, makanlah kalian terserah kalian. Janganlah kalian menjual daging Hadyu (daging yang disembelih Jamaah Haji waktu pelaksanaan ibadah), tapi makanlah, bersedekahlah dan nikmatilah dengan kulitnya dan jangan kalian menjualnya. Jika kalian diberi makan dengan daging tersebut maka makanlah sekehendak hati kalian.\" (Zubaid) berkata dalam hadits ini, dari [Abu Sa'id] dari Nabi Shallallahu'alaihiwasallam, Namun sekarang makanlah, juallah dan simpanlah kalian. (Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] berkata; telah mengabarkan kepadaku [Abu Az-Zubair] dari [Jabir] sebagaimana hadis Zubaid ini, dari Abu Sa'id tidak sampai kepadanya, semuanya hal itu dari Nabi Shallallahu'alaihiwasallam."},"936":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عَمْرٍو قَالَ حَدَّثَنَا زُهَيْرٌ يَعْنِي ابْنَ مُحَمَّدٍ عَنْ شَرِيكٍ يَعْنِي ابْنَ عَبْدِ اللَّهِ بْنِ أَبِي نَمِرٍ تَمِيمٍ عَنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ أَبِيهِ وَعَمِّهِ قَتَادَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلُوا لُحُومَ الْأَضَاحِيِّ وَادَّخِرُوا","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Abdul Malik bin 'Amr] berkata; telah menceritakan kepada kami [Zuhair] yaitu Ibnu Muhammad dari [Syarik] yaitu Ibnu Abdullah bin Abu Namr Tamim, dari [Abdurrahman bin Abu Sa'id Al Khudri] dari [Bapaknya] dan [pamannya, Qatadah] Rasulullah shallallahu'alaihiwasallam bersabda: \"Makanlah daging kurban dan simpanlah.\""},"937":{"ar":"قَالَ حَدَّثَنَا يَعْقُوبُ قَالَ حَدَّثَنَا أَبِي عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ عَلِيِّ بْنِ حُسَيْنِ بْنِ جَعْفَرٍ وَأَبِي إِسْحَاقُ بْنُ يَسَارٍ عَنْ عَبْدِ اللَّهِ بْنِ خَبَّابٍ مَوْلَى بَنِي عَدِيِّ بْنِ النَّجَّارِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ نَهَانَا عَنْ أَنْ نَأْكُلَ لُحُومَ نُسُكِنَا فَوْقَ ثَلَاثٍ قَالَ فَخَرَجْتُ فِي سَفَرٍ ثُمَّ قَدِمْتُ عَلَى أَهْلِي وَذَلِكَ بَعْدَ الْأَضْحَى بِأَيَّامٍ قَالَ فَأَتَتْنِي صَاحِبَتِي بِسَاقٍ قَدْ جَعَلَتْ فِيهِ قَدِيدًا فَقُلْتُ لَهَا أَنَّى لَكِ هَذَا الْقَدِيدُ فَقَالَتْ مِنْ ضَحَايَانَا قَالَ فَقُلْتُ لَهَا أَوَلَمْ يَنْهَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَنْ نَأْكُلَهَا فَوْقَ ثَلَاثٍ قَالَ فَقَالَتْ إِنَّهُ قَدْ رَخَّصَ لِلنَّاسِ بَعْدَ ذَلِكَ قَالَ فَلَمْ أُصَدِّقْهَا حَتَّى بَعَثْتُ إِلَى أَخِي قَتَادَةَ بْنِ النُّعْمَانِ وَكَانَ بَدْرِيًّا أَسْأَلُهُ عَنْ ذَلِكَ قَالَ فَبَعَثَ إِلَيَّ أَنْ كُلْ طَعَامَكَ فَقَدْ صَدَقَتْ قَدْ أَرْخَصَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْمُسْلِمِينَ فِي ذَلِكَ","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Ya'qub] berkata; telah menceritakan kepada kami [bapakku] dari [Muhammad bin Ishaq] berkata; telah menceritakan kepadaku [Muhammad bin 'Ali bin Husain bin Ja'far] dan [bapakku, Ishaq bin Yasar] dari [Abdullah bin Khabbab] budak bani 'Adi bin An Najar, dari [Abu Sa'id Al Khudri] berkata; Rasulullah shallallahu'alaihiwasallam melarang kami memakan daging kurban lebih dari tiga hari. (Abu Sa'id Al Khudri) berkata; lalu saya keluar untuk suatu perjalanan dan saya datangi keluargaku dan itu terjadi beberapa hari setelah hari kurban. Lalu [salah satu sahabat perempuanku] datang dengan membawa satu tempat yang berisi daging yang diawetkan, saya bertanya kepadanya 'Dari mana daging ini? ' Dia menjawab 'Dari daging kurban kami.' Saya bertanya, bukankan Rasulullah shallallahu'alaihiwasallam melarang untuk memakannya lebih dari tiga hari?. Dia menjawan 'Sungguh (Rasulullah shallallahu'alaihiwasallam) telah memberi keringanan kepada orang-orang setelah itu. Saya tidak langsung mempercayai sampai saya mengirim seorang utusan kepada saudaraku, [Qatadah bin An Nu'man], dia adalah seorang veteran perang Badar, saya bertanya kepadanya mengenai hal itu. Lalu dia mengirim utusan kepadaku agar saya memakan makanan itu, dan (wanita tersebut) adalah benar, Rasulullah shallallahu'alaihiwasallam telah memberi keringanan bagi kaum muslimin mengenai hal itu."},"938":{"ar":"قَالَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا هِشَامٌ الدَّسْتُوَائِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ هِلَالِ بْنِ أَبِي مَيْمُونَةَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ رِفَاعَةَ الْجُهَنِيِّ قَالَأَقْبَلْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى إِذَا كُنَّا بِالْكَدِيدِ أَوْ قَالَ بِقُدَيْدٍ فَجَعَلَ رِجَالٌ مِنَّا يَسْتَأْذِنُونَ إِلَى أَهْلِيهِمْ فَيَأْذَنُ لَهُمْ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ مَا بَالُ رِجَالٍ يَكُونُ شِقُّ الشَّجَرَةِ الَّتِي تَلِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبْغَضَ إِلَيْهِمْ مِنْ الشِّقِّ الْآخَرِ فَلَمْ نَرَ عِنْدَ ذَلِكَ مِنْ الْقَوْمِ إِلَّا بَاكِيًا فَقَالَ رَجُلٌ إِنَّ الَّذِي يَسْتَأْذِنُكَ بَعْدَ هَذَا لَسَفِيهٌ فَحَمِدَ اللَّهَ وَقَالَ حِينَئِذٍ أَشْهَدُ عِنْدَ اللَّهِ لَا يَمُوتُ عَبْدٌ يَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنِّي رَسُولُ اللَّهِ صِدْقًا مِنْ قَلْبِهِ ثُمَّ يُسَدِّدُ إِلَّا سُلِكَ فِي الْجَنَّةِ قَالَ وَقَدْ وَعَدَنِي رَبِّي عَزَّ وَجَلَّ أَنْ يُدْخِلَ مِنْ أُمَّتِي سَبْعِينَ أَلْفًا لَا حِسَابَ عَلَيْهِمْ وَلَا عَذَابَ وَإِنِّي لَأَرْجُو أَنْ لَا يَدْخُلُوهَا حَتَّى تَبَوَّءُوا أَنْتُمْ وَمَنْ صَلَحَ مِنْ آبَائِكُمْ وَأَزْوَاجِكُمْ وَذُرِّيَّاتِكُمْ مَسَاكِنَ فِي الْجَنَّةِ وَقَالَ إِذَا مَضَى نِصْفُ اللَّيْلِ أَوْ قَالَ ثُلُثَا اللَّيْلِ يَنْزِلُ اللَّهُ عَزَّ وَجَلَّ إِلَى السَّمَاءِ الدُّنْيَا فَيَقُولُ لَا أَسْأَلُ عَنْ عِبَادِي أَحَدًا غَيْرِي مَنْ ذَا يَسْتَغْفِرُنِي فَأَغْفِرَ لَهُ مَنْ الَّذِي يَدْعُونِي أَسْتَجِيبُ لَهُ مَنْ ذَا الَّذِي يَسْأَلُنِي أُعْطِيهِ حَتَّى يَنْفَجِرَ الصُّبْحُقَالَ حَدَّثَنَا أَبُو الْمُغِيرَةِ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ هِلَالِ بْنِ أَبِي مَيْمُونَةَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ رِفَاعَةَ بْنِ عَرَابَةَ الْجُهَنِيِّ قَالَ صَدَرْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ مَكَّةَ فَجَعَلَ النَّاسُ يَسْتَأْذِنُونَهُ فَذَكَرَ الْحَدِيثَ قَالَ وَقَالَ أَبُو بَكْرٍ إِنَّ الَّذِي يَسْتَأْذِنُكَ بَعْدَ هَذِهِ لَسَفِيهٌ فِي نَفْسِي ثُمَّ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَمِدَ اللَّهَ وَقَالَ خَيْرًا ثُمَّ قَالَ أَشْهَدُ عِنْدَ اللَّهِ وَكَانَ إِذَا حَلَفَ قَالَ وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ مَا مِنْ عَبْدٍ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ ثُمَّ يُسَدِّدُ إِلَّا سُلِكَ فِي الْجَنَّةِ فَذَكَرَ الْحَدِيثَ حَدَّثَنَا حَسَنُ بْنُ مُوسَى قَالَ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى يَعْنِي ابْنَ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي هِلَالُ بْنُ أَبِي مَيْمُونَةَ رَجُلٌ مِنْ أَهْلِ الْمَدِينَةِ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ رِفَاعَةَ بْنِ عَرَابَةَ الْجُهَنِيِّ قَالَ أَقْبَلْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى إِذَا كُنَّا بِالْكَدِيدِ أَوْ قَالَ بِعَرَفَةَ فَذَكَرَ الْحَدِيثَ","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Isma'il bin Ibrahim] berkata; telah menceritakan kepada kami [Hisyam Ad-Dastuwani] dari [Yahya bin Abu Katsir] dari [Hilal bin Abu Maimunah] dari ['Atha' bin Yasar] dari [Rifa'ah Al Juhanny] berkata; kami bersama Rasulullah shallallahu'alaihiwasallam sampai di Kadid -dengan huruf kaf diawAl atau di Qadid -dengan huruf qaf diawAl, lalu sebagian orang di antara kami meninggalkan Rasulullah dengan meminta ijin untuk menemui keluarganya. (Rasulullah shallallahu'alaihiwasallam) pun mengijinkannya. Rasulullah shallallahu'alaihiwasallam bangkit, memuji Allah lalu bersabda: \"Bagaimana keadaan suatu kaum yang bagian sisi pohonnya yang dekat Rasulullah shallallahu'alaihiwasallam lebih mereka benci daripada sisi yang lain?\", lalu kami tidak kami melihat keadaan orang-orang selain dalam keadaan menangis. Lalu ada seorang laki-laki yang berkata 'Orang yang meminta ijin kepada anda setelah ini betul-betul orang yang tolol, dia memuji Allah, lalu (Rasulullah shallallahu'alaihiwasallam) saat itu juga bersabda: \"Saya bersaksi di sisi Allah, tidaklah seorang hamba pun yang meninggal, yang bersaksi bahwa tidak ada tuhan selain Allah dan saya adalah utusan Allah, dengan tulus dari hatinya, kemudian dia berbuat benar kecuali dia pasti masuk surga.\" (Rasulullah shallallahu'alaihiwasallam) bersabda kembali, \"Sungguh Rabbku AzzaWaJalla menjanjikan kepadaku untuk memasukkan dari kalangan umatku sebanyak tujuh puluh ribu orang yang masuk surga tanpa hisab dan siksa. Namun saya berharap agar mereka tidak memasukinya sampai kalian menempati tempat-tempat di surga, juga bapak-bapak kalian yang shalih, istri-istri kalian dan keluarga kalian.\" Lalu beliau bersabda: \"Jika telah lewat pertengahan malam\", atau, \"Dua pertiga malam, Allah AzzaWaJalla turun ke langit dunia, lalu berfirman, 'Aku tidak mungkin meminta kepada seorang pun dari hamba-Ku selain diri-Ku sendiri, dan siapakah yang meminta ampun kepada-Ku lantas Aku ampuni? siapakah yang mau berdo'a kepada-Ku lantas Aku kabulkan?, siapakah yang meminta kepada-Ku lantas Aku beri?\", Dan hal ini terus berlaku sampai pagi hari. (Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Abu Al Mughirah] berkata; telah menceritakan kepada kami [Al Auza'i] berkata; telah menceritakan kepada kami [Yahya bin Abu Katsir] dari [Hilal bin Abu Maimunah] dari ['Atha' bin Yasar] dari [Rifa'ah bin 'Arabah Al Juhanny] berkata; kami tiba bersama Rasulullah shallallahu'alaihiwasallam dari Makkah, lalu banyak orang yang meminta ijin kepada beliau, lalu ia sebutkan hadis secara lengkap. (Rifa'ah bin 'Arabah Al Juhanny) berkata; Abu Bakar berkata; orang yang meminta ijin kepada anda setelah itu adalah orang yang sangat tolol menurutku, lalu Nabi Shallallahu'alaihiwasallam memuji Allah dan berkata tentang kebaikan, lalu bersabda: \"Saya bersaksi di sisi Allah\" dan beliau jika bersumpah, biasa dengan lafadz, \"Demi yang jiwa Muhammad berada di tangAn Nya, tidaklah seorang hamba beriman kepada Allah dan hari Kiamat lalu berbuat baik, kecuali dia sedang menuju ke surga, lalu ia sebutkan hadis secara lengkap. Telah menceritakan kepada kami [Hasan bin Musa] berkata; telah menceritakan kepada kami [Syaiban] dari [Yahya] yaitu Ibnu Abu Katsir, berkata; telah menceritakan kepadaku [Hilal bin Abu Maimunah] seorang laki-laki dari Madinah, dari ['Atha' bin Yasar] dari [Rifa'ah bin 'Arabah Al Juhanny] berkata; kami berangkat bersama Rasulullah shallallahu'alaihiwasallam, lalu ketika kami sampai di daerah Kadid atau berkata; di Arafah, lalu ia sebutkan hadis secara lengkap."},"939":{"ar":"قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا هِشَامٌ يَعْنِي الدَّسْتُوَائِيَّ قَالَ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ هِلَالِ بْنِ أَبِي مَيْمُونَةَ قَالَ حَدَّثَنَا عَطَاءُ بْنُ يَسَارٍ أَنَّ رِفَاعَةَ الْجُهَنِيَّ حَدَّثَهُ قَالَأَقْبَلْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى إِذَا كُنَّا بِالْكَدِيدِ أَوْ قَالَ بِقُدَيْدٍ جَعَلَ رِجَالٌ يَسْتَأْذِنُونَ إِلَى أَهْلِيهِمْ فَيُؤْذَنُ لَهُمْ قَالَ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ وَقَالَ خَيْرًا وَقَالَ أَشْهَدُ عِنْدَ اللَّهِ لَا يَمُوتُ عَبْدٌ شَهِدَ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ صَادِقًا مِنْ قَلْبِهِ ثُمَّ يُسَدِّدُ إِلَّا سُلِكَ فِي الْجَنَّةِ ثُمَّ قَالَ وَعَدَنِي رَبِّي أَنْ يُدْخِلَ مِنْ أُمَّتِي سَبْعِينَ أَلْفًا بِغَيْرِ حِسَابٍ وَإِنِّي لَأَرْجُو أَنْ لَا يَدْخُلُوهَا حَتَّى تَبَوَّءُوا أَنْتُمْ وَمَنْ صَلَحَ مِنْ أَزْوَاجِكُمْ وَذَرَارِيِّكُمْ مَسَاكِنَ فِي الْجَنَّةِ وَقَالَ إِذَا مَضَى نِصْفُ اللَّيْلِ أَوْ ثُلُثُ اللَّيْلِ يَنْزِلُ اللَّهُ عَزَّ وَجَلَّ إِلَى السَّمَاءِ الدُّنْيَا فَيَقُولُ لَا أَسْأَلُ عَنْ عِبَادِي أَحَدًا غَيْرِي مَنْ ذَا الَّذِي يَسْتَغْفِرُنِي أَغْفِرُ لَهُ مَنْ ذَا الَّذِي يَدْعُونِي فَأَسْتَجِيبَ لَهُ مَنْ ذَا الَّذِي يَسْأَلُنِي فَأُعْطِيَهُ حَتَّى يَنْفَجِرَ الصُّبْحُ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] berkata; telah menceritakan kepada kami [Hisyam] yaitu ad-dastuwa'i, berkata; telah menceritakan kepada kami [Yahya bin Abu Katsir] dari [Hilal bin Abu Maimunah] berkata; telah menceritakan kepada kami ['Atha' bin Yasar] [Rifa'ah Al Juhanny] menceritakannya berkata; kami berjalan bersama Rasulullah shallallahu'alaihiwasallam sampai di Kadid, atau Qadid. Orang-orang banyak yang meminta ijin untuk menemui keluarga mereka, dan beliau pun mengijinkan mereka. (Rifa'ah Al Juhanny) berkata; lalu (Rasulullah shallallahu'alaihiwasallam) memuji Allah dan melontarkan ucapAn ucapan kebaikan dan bersabda: \"Saya bersaksi di sisi Allah, tidaklah seorang hamba meninggal dengan bersaksi bahwa tidak ada sesembahan yang hak selain Allah dan Muhammad adalah utusan Allah secara tulus dari hatinya, kemudian ia berusaha menepati ucapannya kecuali dia dibimbing menuju surga\", lalu bersabda: \"Dan Rabbiku telah menjanjikan kepadaku untuk memasukkan dari kalangan umatku sebanyak tujuh puluh ribu orang tanpa hisab dan siksa. Saya berharap agar mereka tidak memasukinya sampai kalian menyinggahi tempat-tempat kalian di surga, dan juga istri-istri kalian dan keluarga kalian.\" Lalu beliau bersabda: \"Jika telah lewat pertengahan malam\", atau, \"dua pertiga malam, Allah AzzaWaJalla turun ke langit dunia, lalu berfirman, 'Aku tidak bakalan meminta seorangpun dari hamba-Ku selain diri-Ku sendiri, siapa yang mau meminta ampun kepada-Ku sehingga kuampuni?, siapa yang mau berdo'a kepada-Ku sehingga Aku kabulkan?, siapa yang meminta kepada-Ku sehingga aku beri?\", Dan itu berlaku sampai pagi hari."},"940":{"ar":"حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا وُهَيْبٌ قَالَ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ قَالَ حَدَّثَنِي أَبُو سَلَمَةَعَنْ الرَّجُلِ الَّذِي مَرَّ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُنَاجِي جِبْرِيلَ عَلَيْهِ السَّلَام فَزَعَمَ أَبُو سَلَمَةَ أَنَّهُ تَجَنَّبَ أَنْ يَدْنُوَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَخَوُّفًا أَنْ يَسْمَعَ حَدِيثَهُ فَلَمَّا أَصْبَحَ قَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مَنَعَكَ أَنْ تُسَلِّمَ إِذْ مَرَرْتَ بِي الْبَارِحَةَ قَالَ رَأَيْتُكَ تُنَاجِي رَجُلًا فَخَشِيتُ أَنْ تَكْرَهَ أَنْ أَدْنُوَ مِنْكُمَا قَالَ وَهَلْ تَدْرِي مَنْ الرَّجُلُ قَالَ لَا قَالَ فَذَلِكَ جِبْرِيلُ عَلَيْهِ السَّلَام وَلَوْ سَلَّمْتَ لَرَدَّ السَّلَامَوَقَدْ سَمِعْتُ مِنْ غَيْرِ أَبِي سَلَمَةَ أَنَّهُ حَارِثَةَ بْنَ النُّعْمَانِ","id":"Telah menceritakan kepada kami ['Affan] berkata; telah menceritakan kepada kami [Wuhaib] berkata; telah menceritakan kepada kami [Musa Bin 'Uqbah] berkata; telah menceritakan kepadaku [Abu Salamah] dari [seorang laki-laki yang melewati Rasulullah shallallahu'alaihiwasallam] yang ketika itu beliau sedang bercakap-cakap dengan Jibril Alaihissalam. Abu Salamah beranggapan orang itu menjauh dari mendekati Rasulullah shallallahu'alaihiwasallam karena khawatir jangAn jangan mendengar percakapan nabi. Ketika pagi tiba, Rasulullah shallallahu'alaihiwasallam bertanya, \"Apa yang yang membuat kamu tidak mengucapkan salam ketika kamu melewatiku tadi malam? (Sahabat tadi) menjawab 'Saya melihat anda sedang bercakap-cakap dengan seorang laki-laki, sehingga saya khawatir jangAn jangan anda keberatan jika saya mendekati anda berdua. (Rasulullah shallallahu'alaihiwasallam) bersabda: \"Apakah engkau mengetahui siapa laki-laki tersebut?\" (Sahabat tadi) menjawab, \"Tidak\" (Rasulullah shallallahu'alaihiwasallam) bersabda: \"Dialah Jibril 'Alaihissalam, kalau saja engkau mengucapkan salam, pastilah dia menjawabnya.\" (Musa bin 'Uqbah) berkata 'Saya mendengarnya selain dari Abi Salamah yaitu dari [Haritsah bin An Nu'man].'"},"941":{"ar":"قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ أَبَا مَالِكٍ الْأَشْجَعِيَّ يُحَدِّثُ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ قَالَ أَخْبَرَنِي مَنْرَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي ثَوْبٍ قَدْ خَالَفَ بَيْنَ طَرَفَيْهِ","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] berkata; telah menceritakan kepada kami [Syu'bah] berkata; saya mendengar [Abu Malik Al Asyja'i] menceritakan dari [Abu Salamah bin Abdurrahman] berkata; telah mengabarkan kepadaku [orang yang telah melihat Nabi Shallallahu'alaihiwasallam] shalat dengan memakai satu kain dengan mengikatkan ke dua ujungnya."},"942":{"ar":"قَالَ حَدَّثَنَا وَكِيعٌ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ زَمْعَةَ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَذْكُرُ النِّسَاءَ فَوَعَظَ فِيهِنَّ وَقَالَ عَلَامَ يَضْرِبُ أَحَدُكُمْ امْرَأَتَهُ وَلَعَلَّهُ أَنْ يُضَاجِعَهَا مِنْ آخِرِ النَّهَارِ أَوْ آخِرِ اللَّيْلِ","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Waki'] dari [Hisyam] dari [Bapaknya] dari [Abdullah bin Zam'ah] berkata Aku mendengar Nabi Shallallahu'alaihiwasallam menyebut-nyebut kaum perempuan dan menasehati sahabatnya tentang para isteri seraya bersabda: \"Atas dasar apa salah seorang di antara kalian memukul isterinya padahal siapa tahu dia menidurinya di waktu sorenya atau di akhir malamnya bukan?\""},"943":{"ar":"قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ قَالَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ زَمْعَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ إِذْ انْبَعَثَ أَشْقَاهَا }انْبَعَثَ لَهَا رَجُلٌ عَارِمٌ عَزِيزٌ مَنِيعٌ فِي رَهْطِهِ مِثْلُ أَبِي زَمْعَةَ ثُمَّ وَعَظَهُمْ فِي الضَّحِكِ مِنْ الضَّرْطَةِ فَقَالَ إِلَى مَا يَضْحَكُ أَحَدُكُمْ مِمَّا يَفْعَلُ قَالَ ثُمَّ قَالَ إِلَى مَا يَجْلِدُ أَحَدُكُمْ امْرَأَتَهُ جَلْدَ الْعَبْدِ ثُمَّ لَعَلَّهُ أَنْ يُضَاجِعَهَا مِنْ آخِرِ يَوْمِهِ","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Abu Mu'awiyah] berkata; telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [Bapaknya] dari [Abdullah bin Zam'ah] berkata; Rasulullah shallallahu'alaihiwasallam bersabda mengomentari ayat 'Ketika bangkit orang yang paling celaka di antara mereka' maka bangkitlah seorang laki-laki yang kasar, bangsawan, dan pelit di kalangan kaumnya seperti Abu Zam'ah, lalu nabi menasehati mereka perihal tertawa karena kentut. Lalu beliau bersabda: \"Atas dasar apa salah seorang diantara kalian tertawa karena kentut?\" (Abdullah bin Zam'ah) berkata; lalu beliau bersabda: \"Atas dasar apa salah seorang di antara kalian mencambuk istrinya sebagaimana mencambuk budak, yang bisa jadi pada sore harinya dia menggaulinya?.\""},"944":{"ar":"قَالَ حَدَّثَنَا ابْنُ نُمَيْرٍ قَالَ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ زَمْعَةَ قَالَخَطَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ النَّاقَةَ وَذَكَرَ الَّذِي عَقَرَهَا فَقَالَ{ إِذْ انْبَعَثَ أَشْقَاهَا }انْبَعَثَ لَهَا رَجُلٌ عَارِمٌ عَزِيزٌ مَنِيعٌ فِي رَهْطِهِ مِثْلُ أَبِي زَمْعَةَ ثُمَّ ذَكَرَ النِّسَاءَ فَوَعَظَهُمْ فِيهِنَّ فَقَالَ عَلَامَ يَجْلِدُ أَحَدُكُمْ امْرَأَتَهُ جَلْدَ الْعَبْدِ وَلَعَلَّهُ يُضَاجِعُهَا مِنْ آخِرِ يَوْمِهِ ثُمَّ وَعَظَهُمْ فِي ضَحِكِهِمْ مِنْ الضَّرْطَةِ فَقَالَ عَلَامَ يَضْحَكُ أَحَدُكُمْ عَلَى مَا يَفْعَلُ","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Ibnu Numair] berkata; telah menceritakan kepada kami [Hisyam] dari [Bapaknya] dari [Abdullah bin Zam'ah] berkata; Rasulullah shallallahu'alaihiwasallam berkhutbah lalu menyebut-nyebut 'Unta' dan menyebut-nyebut unta yang kaum Tsamud sembelih. Beliau bersabda mengomentari ayat 'Ketika bangkit orang yang paling celaka di antara mereka', Maka bangkitlah seorang yang kasar dan jelek, bangsawan, orang yang pelit di kalangan kaumnya seperti Abu Zam'ah, kemudian beliau menyebut-nyebut wanita dan menasehati (kaum laki-laki) tentang kaum wanita. Lalu beliau bersabda: \"Atas dasar apa salah seorang di antara kalian mencambuk istrinya sebagaimana mencambuk budak bisa jadi padahal bisa jadi pada sore harinya dia menggaulinya?.\" Lalu beliau menasehati mereka tentang tertawa mereka karena kentut, beliau bersabda: \"Atas dasar apa kalian mentertawakannya?.\""},"945":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ زَمْعَةَوَعَظَهُمْ فِي النِّسَاءِ وَقَالَ عَلَامَ يَضْرِبُ أَحَدُكُمْ امْرَأَتَهُ ضَرْبَ الْعَبْدِ ثُمَّ يُضَاجِعُهَا مِنْ آخِرِ اللَّيْلِ","id":"Telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Hisyam] dari [Bapaknya] dari [Abdullah bin Zam'ah] dia menasehati mereka dalam masalah wanita dan berkata; atas dasar apa salah seorang diantara kalian memukul istrinya sebagaimana memukul budak lalu menggaulinya pada akhir malam?."},"946":{"ar":"قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا هِشَامٌ عَنْ حَفْصَةَ عَنِ الرَّبَابِ الضَّبِّيَّةِ عَنْ سَلْمَانَ بْنِ عَامِرٍ الضَّبِّيِّ أَنَّهُ قَالَإِذَا أَفْطَرَ أَحَدُكُمْ فَلْيُفْطِرْ عَلَى تَمْرٍ فَإِنْ لَمْ يَجِدْ فَلْيُفْطِرْ عَلَى الْمَاءِ فَإِنَّ الْمَاءَ طَهُورٌقَالَ هِشَامٌ وَحَدَّثَنِي عَاصِمٌ الْأَحْوَلُ أَنَّ حَفْصَةَ رَفَعَتْهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] Berkata; telah menceritakan kepada kami [Hisyam] dari [Hafshah] dari [Ar-Rabab Adl-Dlabbiyah] dari [Salman bin 'Amir Adz-Dlabby] dia berkata; Jika di antara kalian berbuka, berbukalah dengan kurma, kalaulah tidak ada, maka berbukalah dengan air, karena air itu suci. [Hisyam] berkata; dan telah menceritakan kepadaku ['Ashim Al Ahwal] [Hafshah] memarfukkannya kepada Nabi Shallallahu'alaihiwasallam."},"947":{"ar":"قَالَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَاصِمٍ عَنْ حَفْصَةَ عَنِ الرَّبَابِ عَنْ عَمِّهَا سَلْمَانَ بْنِ عَامِرٍ الضَّبِّيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَلْيُفْطِرْ عَلَى تَمْرٍ فَإِنْ لَمْ يَجِدْ فَلْيُفْطِرْ عَلَى مَاءٍ فَإِنَّهُ طَهُورٌ","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari ['Ashim] dari [Hafshah] dari [Ar-Rabab] dari [pamannya, Salman bin 'Amir Adz-Dlabby] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Hendaklah berbuka dengan kurma, jika dia tidak mendapatkannya, maka berbukalah dengan air karena air itu suci.\""},"948":{"ar":"وَمَعَ الْغُلَامِ عَقِيقَتُهُ فَأَمِيطُوا عَنْهُ الْأَذَى وَأَرِيقُوا عَنْهُ دَمًا وَالصَّدَقَةُ عَلَى ذِي الْقَرَابَةِ ثِنْتَانِ صَدَقَةٌ وَصِلَةٌ","id":"MaAsih melalui jalur periwayatan yang sama seperti hadits sebelumnya dari [Salman bin Amir]; Dan, \"Kelahiran seorang anak itu harus disertai aqiqah, Hilangkan gangguannya (maksudnya cukurlah rambutnya) dan alirkanlah darah (sembelihlah hewan). Dan bersedekah kepada kerabat dekat mendapatkan dua pahala sekaligus, pahala sedekah dan pahala silaturrahim.\""},"949":{"ar":"قَالَ قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَاصِمٍ الْأَحْوَلِ عَنْ حَفْصَةَ عَنِ الرَّبَابِ أُمِّ الرَّائِحِ ابْنَةِ صُلَيْعٍ عَنْ سَلْمَانَ بْنِ عَامِرٍ الضَّبِّيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَفْطَرَ أَحَدُكُمْ فَلْيُفْطِرْ عَلَى تَمْرٍ فَإِنْ لَمْ يَجِدْ فَلْيُفْطِرْ عَلَى مَاءٍ فَإِنَّهُ طَهُورٌ","id":"(Abdullah bin Ahmad) berkata; (Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Waki'] berkata; telah menceritakan kepada kami [Sufyan] dari ['Ashim Al Ahwal] dari [Hafshah] dari [Ar-Rabab], Ummu Ar-Ra`ihah binti Shulaih dari [Salman bin 'Amir Adz-Dlabby] berkata; Rasulullah shallallahu'alaihiwasallam bersabda: \"Jika salah seorang dari kalian berbuka hendaklah dengan kurma, jika dia tidak mendapatkannya maka berbukalah dengan air karena air itu suci.\""},"950":{"ar":"قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ وَابْنُ نُمَيْرٍ قَالَا حَدَّثَنَا هِشَامٌ وَيَزِيدُ قَالَ أَخْبَرَنَا هِشَامٌ عَنْ حَفْصَةَ ابْنَةِ سِيرِينَ عَنْ سَلْمَانَ بْنِ عَامِرٍ الضَّبِّيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ابْنُ نُمَيْرٍ أَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ يَزِيدُ بْنُ هَارُونَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَعَ الْغُلَامِ عَقِيقَتُهُ فَأَهْرِيقُوا عَنْهُ دَمًا وَأَمِيطُوا عَنْهُ الْأَذَى","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] dan [Ibnu Numair] berkata; telah menceritakan kepada kami [Hisyam] dan [Yazid] berkata; telah menghabarkan kepada kami [Hisyam] dari [Hafshah binti Sirin] dari [Salman bin 'Amir Adz-Dlabby] Nabi Shallallahu'alaihiwasallam bersabda: Adapun Ibnu Numair dia telah mendengar Rasulullah shallallahu'alaihiwasallam. Yazid bin Harun berkata; saya mendengar Rasulullah shallallahu'alaihiwasallam bersabda: \"Anak yang lahir harus disertai aqiqahnya\", beliau bersabda: \"Alirkanlah darah (sembelihlah kambing) dan hilangkanlah gangguannya?\""},"951":{"ar":"قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ قَالَ حَدَّثَنَا عَاصِمٌ عَنْ حَفْصَةَ عَنِ الرَّبَابِ عَنْ سَلْمَانَ بْنِ عَامِرٍ الضَّبِّيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَفْطَرَ أَحَدُكُمْ فَلْيُفْطِرْ عَلَى تَمْرٍ فَإِنْ لَمْ يَجِدْ فَلْيُفْطِرْ عَلَى مَاءٍ فَإِنَّهُ طَهُورٌ","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Abu Mu'awiyah] berkata; telah menceritakan kepada kami ['Ashim] dari [Hafshah] dari [Ar-Rabab] dari [Salman bin 'Amir Adz-Dlabby] berkata; Rasulullah shallallahu'alaihiwasallam bersabda: \"Jika salah seorang dari kalian berbuka hendaklah dengan kurma, jika dia tidak mendapatkannya maka berbukalah dengan air karena air itu suci.\""},"952":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا هِشَامٌ عَنْ حَفْصَةَ ابْنَةِ سِيرِينَ عَنِ الرَّبَابِ عَنْ سَلْمَانَ بْنِ عَامِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَفْطَرَ أَحَدُكُمْ فَلْيُفْطِرْ عَلَى تَمْرٍ فَإِنْ لَمْ يَجِدْ فَلْيُفْطِرْ بِمَاءٍ فَإِنَّ الْمَاءَ طَهُورٌ","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Abdurrazzaq] berkata; telah menghabarkan kepada kami [Hisyam] dari [Hafshah binti Sirin] dari [Ar-Rabab] dari [Salman bin 'Amir Adz-Dlabby] berkata; Rasulullah shallallahu'alaihiwasallam bersabda: \"Jika salah seorang dari kalian berbuka hendaklah dengan kurma, jika dia tidak mendapatkannya maka berbukalah dengan air. Sesungguhnya air itu suci.\""},"953":{"ar":"وَقَالَمَعَ الْغُلَامِ عَقِيقَتُهُ فَأَهْرِيقُوا عَنْهُ دَمًا وَأَمِيطُوا عَنْهُ الْأَذَى","id":"Masih melalui jalur periwayatan yang sama seperti hadits sebelumnya, dari [Salman bin Amir]; dan beliau bersabda: \"Anak yang baru lahir harus disertai aqiqahnya, Alirkanlah darah (lakukan penyembelihan) dan hilangkanlah gangguannya.\""},"954":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا هِشَامٌ عَنْ حَفْصَةَ عَنْ سَلْمَانَ بْنِ عَامِرٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الصَّدَقَةُ عَلَى الْمِسْكِينِ صَدَقَةٌ وَالصَّدَقَةُ عَلَى ذِي الرَّحِمِ اثْنَتَانِ صَدَقَةٌ وَصِلَةٌ","id":"Telah menceritakan kepada kami [Yazid bin Harun] berkata; telah menghabarkan kepada kami [Hisyam] dari [Hafshah] dari [Salman bin 'Amir Adz-Dlabby] berkata; saya mendengar Rasulullah shallallahu'alaihiwasallam bersabda: \"Sedekah bagi kaum miskin mendapat pahala sedekah, adapun sedekah untuk kerabat dekat mendatangkan dua pahala, pahala sedekah dan pahala menyambung tali kerabat.\""},"955":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ هِشَامٍ قَالَ حَدَّثَتْنِي حَفْصَةُ عَنْ سَلْمَانَ بْنِ عَامِرٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَعَ الْغُلَامِ عَقِيقَتُهُ فَأَهْرِيقُوا عَنْهُ دَمًا وَأَمِيطُوا عَنْهُ الْأَذَى","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Hisyam] berkata; telah menceritakan kepadaku [Hafshah] dari [Salman bin 'Amir] berkata; saya mendengar Rasulullah shallallahu'alaihiwasallam bersabda: \"Anak yang baru lahir harus disertai aqiqahnya, alirkanlah darahnya dan singkirkanlah gangguannya.\""},"956":{"ar":"قَالَ حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ قَالَ حَدَّثَنَا أَبُو خَيْثَمَةَ عَنْ عُرْوَةَ بْنِ عَبْدِ اللَّهِ بْنِ قُشَيْرٍ الْجُعْفِيِّ قَالَ حَدَّثَنِي مُعَاوِيَةُ بْنُ قُرَّةَ عَنْ أَبِيهِ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي رَهْطٍ مِنْ مُزَيْنَةَ فَبَايَعْنَا وَإِنَّ قَمِيصَهُ لَمُطْلَقٌ فَبَايَعْتُهُ فَأَدْخَلْتُ يَدِي مِنْ جَيْبِ الْقَمِيصِ فَمَسِسْتُ الْخَاتَمَقَالَ عُرْوَةُ فَمَا رَأَيْتُ مُعَاوِيَةَ وَلَا أَبَاهُ شِتَاءً وَلَا حَرًّا إِلَّا مُطْلِقَيْ أَزْرَارِهِمَا لَا يَزُرَّانِ أَبَدًا","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Hasyim bin Al Qasim] berkata; telah menceritakan kepada kami [Abu Khatsmah] dari ['Urwah bin Abdullah bin Qusyair Al ju'fy] telah menceritakan kepadaku [Mu'awiyah bin Qurrah] dari [bapaknya] berkata; Aku menemui Rasulullah shallallahu'alaihiwasallam dalam rombongan dari Muzainah, lalu kami berbaiat kepadanya dan gamisnya diselempangkan begitu saja (tidak dikancing), lantas aku berbaiat kepadanya, lalu kumasukkan tanganku ke dalam kantong gamis, dan kusentuh cincinnya\" 'Urwah berkata; \"Di hari-hari selanjutnya aku tidak pernah melihat Mu'awiyah dan juga ayahnya, baik di musim dingin maupun musim panas selain melepas kancing bajunya dan tidak mengancingkannya.\""},"957":{"ar":"قَالَ حَدَّثَنَا سُلَيْمَانُ حَدَّثَنَا رَوْحٌ قَالَ حَدَّثَنَا بِسْطَامُ بْنُ مُسْلِمٍ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ قَالَ قَالَ أَبِيلَقَدْ عَمَّرْنَا مَعَ نَبِيِّنَا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَا لَنَا طَعَامٌ إِلَّا الْأَسْوَدَانِثُمَّ قَالَ هَلْ تَدْرِي مَا الْأَسْوَدَانِ قُلْتُ لَا قَالَ التَّمْرُ وَالْمَاءُ","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Sulaiman] telah menceritakan kepada kami [Rouh] berkata; telah menceritakan kepada kami [Bistham bin Muslim] dari [Muawiyah bin Qurrah] berkata [bapakku] berkata; kami pernah berumrah bersama Nabi kita Shallallahu'alaihiwasallam dan tidak tersisa makanan bagi kami kecuali hanyalah Al Aswadan (dua benda hitam) kemudian (Rasulullah shallallahu'alaihiwasallam) bertanya, Apakah kalian tahu maksud dua benda hitam? Saya menjawab, Tidak. beliau berkata; \"Kurma dan air.\""},"958":{"ar":"قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ أَبِيهِ أَنَّهُأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ كَانَ حَلَبَ وَصَرَّقَالَ حَدَّثَنَا سُلَيْمَانُ عَنْ شُعْبَةَ عَنْ مُعَاوِيَةَ قَالَ كَانَ أَبِي حَدَّثَنَا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَا أَدْرِي أَسَمِعَهُ مِنْهُ أَوْ حُدِّثَ عَنْهُ","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Sulaiman bin Daud] berkata; telah menceritakan kepada kami [Syu'bah] dari [Muawiyah bin Qurrah] dari [Bapaknya] dia menemui Nabi Shallallahu'alaihiwasallam ternyata beliau baru saja memeras dan mengikat. (Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Sulaiman] dari [Syu'bah] dari [Mu'awiyah] berkata; [bapakku] telah menceritakan kepada kami dari Nabi Shallallahu'alaihiwasallam, saya tidak tahu apakah dia mendengarnya dari beliau atau diceritakan dari beliau."},"959":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عَمْرٍو قَالَ حَدَّثَنَا خَالِدُ بْنُ مَيْسَرَةَ حَدَّثَنَا مُعَاوِيَةُ بْنُ قُرَّةَ عَنْ أَبِيهِ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ هَاتَيْنِ الشَّجَرَتَيْنِ الْخَبِيثَتَيْنِ وَقَالَ مَنْ أَكَلَهُمَا فَلَا يَقْرَبَنَّ مَسْجِدَنَا وَقَالَ إِنْ كُنْتُمْ لَا بُدَّ آكِلِيهِمَا فَأَمِيتُمُوهُمَا طَبْخًا قَالَ يَعْنِي الْبَصَلَ وَالثُّومَ","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Abdul Malik bin 'Amr] berkata; telah menceritakan kepada kami [Khalid bin Maisarah] telah menceritakan kepada kami [Muawiyah bin Qurrah] dari [Bapaknya] berkata; Rasulullah shallallahu'alaihiwasallam melarang dua pohon yang buruk, dengan bersabda: \"Barangsiapa yang memakan keduanya, maka janganlah mendekati masjid kami, jika kalian terpaksa untuk memakannya, hilangkanlah baunya dengan memasaknya\" dua pohon itu adalah, \"Bawang merah dan bawang putih.\""},"960":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مُعَاوِيَةَ أَبِي إِيَاسٍ قَالَ سَمِعْتُ أَبِي وَقَدْ كَانَ أَدْرَكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَفَمَسَحَ رَأْسَهُ وَاسْتَغْفَرَ لَهُ","id":"Telah menceritakan kepada kami [Husain bin Muhammad] berkata; telah menceritakan kepada kami [Syu'bah] dari [Muawiyah, Abu 'Iyash] berkata; saya mendengar [bapakku], dia pernah menjumpai Nabi Shallallahu'alaihiwasallam, dan nabi membasuh kepalanya dan memintakan ampun baginya."},"961":{"ar":"حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي صِيَامِ ثَلَاثَةِ أَيَّامٍ مِنْ الشَّهْرِ صَوْمُ الدَّهْرِ وَإِفْطَارُهُ","id":"Telah menceritakan kepada kami ['Affan] berkata; telah menceritakan kepada kami [Syu'bah] dari [Muawiyah bin Qurrah] dari [Bapaknya] dari Nabi Shallallahu'alaihiwasallam, beliau bersabda bahwa puasa tiga hari dalam sebulan bagaikan puasa sepanjang masa dan berbukanya."},"962":{"ar":"حَدَّثَنَا حَجَّاجٌ قَالَ حَدَّثَنِي شُعْبَةُ عَنْ أَبِي إِيَاسٍ قَالَجَاءَ أَبِي إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ غُلَامٌ صَغِيرٌ فَمَسَحَ رَأْسَهُ وَاسْتَغْفَرَ لَهُقَالَ شُعْبَةُ قُلْنَا لَهُ صُحْبَةٌ قَالَ لَا وَلَكِنَّهُ كَانَ عَلَى عَهْدِهِ قَدْ حَلَبَ وَصَرَّ","id":"Telah menceritakan kepada kami [Hajjaj] berkata; telah menceritakan kepadaku [Syu'bah] dari [Abu 'Iyas] berkata; bapakku menemui Nabi Shallallahu'alaihiwasallam pada saat masih muda, lalu beliau mengusap kepalanya dan memintakan ampun baginya. Syu'bah berkata; apakah dia bisa di katakan sahabat? (Abu 'Iyas) berkata; tidak tapi pada masa beliau dia telah bisa memeras susu dan mengikat-ikat kayu."},"963":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ سُلَيْمَانَ بْنِ الْمُغِيرَةِ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ هِشَامِ بْنِ عَامِرٍ الْأَنْصَارِيِّ قَالَلَمَّا كَانَ يَوْمُ أُحُدٍ أَصَابَ النَّاسَ قَرْحٌ وَجَهْدٌ شَدِيدٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْفِرُوا وَأَوْسِعُوا وَادْفِنُوا الِاثْنَيْنِ وَالثَّلَاثَةَ فِي الْقَبْرِ قَالُوا يَا رَسُولَ اللَّهِ مَنْ نُقَدِّمُ قَالَ أَكْثَرَهُمْ جَمْعًا وَأَخْذًا لِلْقُرْآنِ","id":"Telah menceritakan kepada kami [Waki'] dari [Sulaiman bin Al Mughirah] dari [Humaid bin Hilal] dari [Hisyam bin 'Amir Al Anshari] berkata; Pada waktu Perang Uhud, manusia terkena luka-luka dan kepayahan yang sangat, Lalu Rasulullah shallallahu'alaihiwasallam bersabda: \"Galilah lubang dan perluaslah, serta kuburkanlah dua atau tiga orang dalam satu pekuburan\" mereka berkata 'Wahai Rasulullah, siapa yang kita dahulukan? beliau bersabda: \"Yang paling banyak mengumpulkan dan menghafalkan Al qur'an.\""},"964":{"ar":"قَالَ حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ قَالَكَانَ النَّاسُ يَشْتَرُونَ الذَّهَبَ بِالْوَرِقِ نَسِيئَةً إِلَى الْعَطَاءِ فَأَتَى عَلَيْهِمْ هِشَامُ بْنُ عَامِرٍ فَنَهَاهُمْ وَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَانَا أَنْ نَبِيعَ الذَّهَبَ بِالْوَرِقِ نَسِيئَةً وَأَنْبَأَنَا أَوْ قَالَ وَأَخْبَرَنَا أَنَّ ذَلِكَ هُوَ الرِّبَا","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Isma'il] berkata; telah menceritakan kepada kami [Ayyub] dari [Abu Qilabah] berkata; orang-orang membeli emas dengan mata uang secara kredit dengan syarat ada penambahan, kemudian hari [Hisyam bin 'Amir] datang kepada mereka, lalu melarang transaksi semacam itu dan berkata; Rasulullah shallallahu'alaihiwasallam melarang kita untuk menjual emas dengan mata uang secara kredit dan bersyarat penambahan, ia beritakan itu adalah riba.\""},"965":{"ar":"قَالَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَيُّوبَ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ هِشَامِ بْنِ عَامِرٍ قَالَإِنَّكُمْ لَتَخُطُّونَ إِلَى أَقْوَامٍ مَا هُمْ بِأَعْلَمَ بِحَدِيثِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنَّا قُتِلَ أَبِي يَوْمَ أُحُدٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْفِرُوا وَأَوْسِعُوا وَادْفِنُوا الِاثْنَيْنِ وَالثَّلَاثَةَ فِي الْقَبْرِ وَقَدِّمُوا أَكْثَرَهُمْ قُرْآنًاوَكَانَ أَبِي أَكْثَرَهُمْ قُرْآنًا فَقُدِّمَ","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Ayyub] dari [Humaid bin Hilal] dari [Hisyam bin 'Amir] berkata; kalian mendatangi suatu kaum yang mereka tidak lebih tahu terhadap hadis Rasulullah shallallahu'alaihiwasallam daripada kita. Bapakku tewas dalam Perang Uhud, lalu Rasulullah shallallahu'alaihiwasallam bersabda: \"Galilah, perluaslah dan dan kuburkanlah dua atau tiga orang dalam satu liang. Dahulukanlah orang yang paling banyak hapalan Al qur'annya\" bapakku adalah termasuk yang paling banyak hapalannya, maka lebih didahulukan."},"966":{"ar":"قَالَوَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ وَاللَّهِ مَا بَيْنَ خَلْقِ آدَمَ إِلَى قِيَامِ السَّاعَةِ أَمْرٌ أَعْظَمُ مِنْ الدَّجَّالِ","id":"[Hisyam bin 'Amir] berkata; saya mendengar Rasulullah shallallahu'alaihiwasallam bersabda: \"Sejak Adam dicipta sampai terjadi Hari Kiamat, tidak ada perkara yang lebih besar daripada Dajjal.\""},"967":{"ar":"��َدَّثَنَا رَوْحُ بْنُ عُبَادَةَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ يَزِيدَ الرِّشْكِ قَالَ شُعْبَةُ قَرَأْتُهُ عَلَيْهِ قَالَ سَمِعْتُ مُعَاذَةَ الْعَدَوِيَّةَ قَالَتْ سَمِعْتُ هِشَامَ بْنَ عَامِرٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَحِلُّ لِمُسْلِمٍ أَنْ يَهْجُرَ مُسْلِمًا فَوْقَ ثَلَاثِ لَيَالٍ فَإِنْ كَانَ تَصَارَمَا فَوْقَ ثَلَاثٍ فَإِنَّهُمَا نَاكِبَانِ عَنْ الْحَقِّ مَا دَامَا عَلَى صُرَامِهِمَا وَأَوَّلُهُمَا فَيْئًا فَسَبْقُهُ بِالْفَيْءِ كَفَّارَتُهُ فَإِنْ سَلَّمَ عَلَيْهِ فَلَمْ يَرُدَّ عَلَيْهِ وَرَدَّ عَلَيْهِ سَلَامَهُ رَدَّتْ عَلَيْهِ الْمَلَائِكَةُ وَرَدَّ عَلَى الْآخَرِ الشَّيْطَانُ فَإِنْ مَاتَا عَلَى صُرَامِهِمَا لَمْ يَجْتَمِعَا فِي الْجَنَّةِ أَبَدًا","id":"Telah menceritakan kepada kami [Rauh bin 'Ubadah] berkata; telah menceritakan kepada kami [Syu'bah] dari [Yazid Ar-Risyk]. Syu'bah berkata; saya membacakan di hadapannya, berkata saya mendengar [Mu'adzah Al 'Adawiyah] berkata; saya mendengar [Hisyam bin 'Amir] berkata; saya mendengar Rasulullah shallallahu'alaihiwasallam bersabda: \"Tidak halal bagi seorang muslim untuk mendiamkan saudaranya semuslim lebih dari tiga malam, jika mereka berdua saling mendiamkan lebih dari tiga malam tersebut, keduanya jauh dari kebenaran selama mereka berdua masih mendiamkan. Jika salah satu di antaranya kembali sadar dari rasa marah, maka sadarnya tersebut sebagai penebus dosanya. Jika si 'A' memberi salam terhadap temannya si 'B' namun tidak diterima, padahal si 'A' masih mau menjawab salamnya, maka si 'A' akan dijawab oleh Malaikat, dan si 'B' yang mendiamkan akan dijawab oleh setan. Jika mereka berdua meninggal dalam keadaan saling mendiamkan, maka mereka berdua tidak akan berkumpul di surga selama-lamanya.\""},"968":{"ar":"قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ يَزِيدَ الرِّشْكِ عَنْ مُعَاذَةَ عَنْ هِشَامِ بْنِ عَامِرٍ أَنَّهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَحِلُّ لِمُسْلِمٍ أَنْ يَهْجُرَ مُسْلِمًا فَوْقَ ثَلَاثِ لَيَالٍ فَإِنَّهُمَا نَاكِبَانِ عَنْ الْحَقِّ مَا دَامَا عَلَى صُرَامِهِمَا وَأَوَّلُهُمَا فَيْئًا يَكُونُ سَبْقُهُ بِالْفَيْءِ كَفَّارَةً لَهُ وَإِنْ سَلَّمَ فَلَمْ يَقْبَلْ وَرَدَّ عَلَيْهِ سَلَامَهُ رَدَّتْ عَلَيْهِ الْمَلَائِكَةُ وَرَدَّ عَلَى الْآخَرِ الشَّيْطَانُ وَإِنْ مَاتَا عَلَى صُرَامِهِمَا لَمْ يَدْخُلَا الْجَنَّةَ جَمِيعًا أَبَدًا","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] berkata; telah menceritakan kepada kami [Syu'bah] dari [Yazid Ar-Risyk] dari [Mu'adzah] dari [Hisyam bin 'Amir] dia berkata; Rasulullah shallallahu'alaihiwasallam bersabda: \"Tidak halal bagi seorang muslim untuk mendiamkan muslim yang lain lebih dari tiga malam. Sesungguhnya kedua-duanya jauh dari kebenaran selama mereka berdua masih saling mendiamkan. Yang pertama-tama insyaf di antara keduanya, maka kesegeraannya berinsyaf menjadi penebus dosanya. Jika si 'A' mengucapkan salam terhadap temannya si 'B', namun si 'B' tidak menerimanya padahal si'A'masih mau menjawab salamnya, maka salamnya akan dijawab oleh Malaikat, dan yang lain salamnya akan dijawab oleh setan. Jika mereka berdua meninggal dalam keadaan saling mendiamkan, niscaya mereka berdua tidak akan masuk surga selamanya.\""},"969":{"ar":"حَدَّثَنَا بَهْزٌ قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ الْمُغِيرَةِ قَالَ حَدَّثَنَا حُمَيْدُ بْنُ هِلَالٍ قَالَ قَالَ هِشَامُ بْنُ عَامِرٍجَاءَتْ الْأَنْصَارُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ أُحُدٍ فَقَالُوا يَا رَسُولَ اللَّهِ أَصَابَنَا قَرْحٌ وَجَهْدٌ فَكَيْفَ تَأْمُرُنَا قَالَ احْفِرُوا وَأَوْسِعُوا وَاجْعَلُوا الرَّجُلَيْنِ وَالثَّلَاثَةَ فِي الْقَبْرِ قَالُوا فَأَيُّهُمْ نُقَدِّمُ قَالَ أَكْثَرَهُمْ قُرْآنًاقَالَ فَقُدِّمَ أَبِي عَامِرٌ بَيْنَ يَدَيْ رَجُلٍ أَوْ اثْنَيْنِ","id":"Telah menceritakan kepada kami [Bahz] berkata; telah menceritakan kepada kami [Sulaiman bin Al Mughirah] berkata; telah menceritakan kepada kami [Humaid bin Al Hilal] berkata; [Hisyam bin 'Amir] berkata; orang Anshar datang menemui Rasulullah shallallahu'alaihiwasallam Pada waktu Perang Uhud, lalu mereka berkata 'Wahai Rasulullah, kami terkena luka-luka dan kepayahan yang sangat, apa yang anda perintahkan kepada kami!, (Rasulullah shallallahu'alaihiwasallam) bersabda: \"Galilah lubang untuk kalian dan perluaslah serta kuburkanlah dua orang atau tiga orang dalam satu liang\" mereka bertanya, Wahai Rasulullah, siapa yang kami dahulukan? beliau bersabda: \"Yang paling banyak hafal Al qur'an.\" (Hisyam bin 'Amir) berkata; lalu kami mendahulukan Abu 'Amir sebelum seorangpun atau yang lainnya.\""},"970":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ أَيُّوبَ عَنْ حُمَيْدِ بْنِ هِلَالٍ قَالَ أَخْبَرَنَا هِشَامُ بْنُ عَامِرٍ قَالَقُتِلَ أَبِي يَوْمَ أُحُدٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْفِرُوا وَوَسِّعُوا وَأَحْسِنُوا وَادْفِنُوا الِاثْنَيْنِ وَالثَّلَاثَةَ فِي الْقَبْرِ وَقَدِّمُوا أَكْثَرَهُمْ قُرْآنًافَكَانَ أَبِي ثَالِثَ ثَلَاثَةٍ وَكَانَ أَكْثَرَهُمْ قُرْآنًا فَقُدِّمَ","id":"(Ahmad bin Hanbal) berkata; telah menghabarkan kepada kami [Abdurrazzaq] berkata; telah menceritakan kepada kami [Ma'mar] dari [Ayyub] dari [Humaid bin Al Hilal] berkata; telah menghabarkan kepada kami [Hisyam bin 'Amir] berkata; Bapakku tewas dalam Perang Uhud, lalu Nabi Shallallahu'alaihiwasallam bersabda: \"Galilah, perluaslah, perbaguslah, kuburkanlah dua atau tiga orang dalam satu liang. Dahulukanlah orang yang paling banyak hapalan Al qur'annya\" bapakku adalah jenazah ketiga yang datang terakhir kali, hanya dia orang yang paling banyak hapalannya maka didahulukan."},"971":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الصَّمَدِ قَالَ حَدَّثَنَا أَبِي حَدَّثَنَا أَيُّوبُ عَنْ حُمَيْدٍ عَنْ أَبِي الدَّهْمَاءِ عَنْ هِشَامِ بْنِ عَامِرٍ قَالَشَكَوْا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا بِهِمْ مِنْ الْقَرْحِ فَقَالَ احْفِرُوا وَأَحْسِنُوا وَأَوْسِعُوا وَادْفِنُوا الِاثْنَيْنِ وَالثَّلَاثَةَ فِي الْقَبْرِ وَقَدِّمُوا أَكْثَرَهُمْ قُرْآنًافَمَاتَ أَبِي فَقُدِّمَ بَيْنَ يَدَيْ رَجُلَيْنِ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ قَالَ حَدَّثَنَا أَبِي قَالَ سَمِعْتُ حُمَيْدَ بْنَ هِلَالٍ يُحَدِّثُ عَنْ سَعْدِ بْنِ هِشَامٍ عَنْ أَبِيهِ هِشَامِ بْنِ عَامِرٍ قَالَ لَمَّا كَانَ يَوْمُ أُحُدٍ فَذَكَرَ الْحَدِيثَ قَالَ حَدَّثَنَا عَفَّانُ قَالَ سَمِعْتُ جَرِيرَ بْنَ حَازِمٍ يُحَدِّثُ هَذَا الْحَدِيثَ عَنْ حُمَيْدِ بْنِ هِلَالٍ وَزَادَ فِيهِ عَنْ سَعْدِ بْنِ هِشَامٍ وَزَادَ فِيهِ وَأَعْمِقُوا","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Abdusshomad] berkata; telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Ayyub] dari [Humaid] dari [Abu Ad-Dahma'] dari [Hisyam bin 'Amir] berkata; mereka mengadu kepada Nabi Shallallahu'alaihiwasallam kesusahan yang menimpa mereka. Lalu (Rasulullah shallallahu'alaihiwasallam) bersabda: \"Galilah, perbaguslah, perluaslah dan kuburkanlah dua atau tiga orang dalam setiap lubang. Dahulukanlah orang yang paling banyak hapalan Al qur'annya\" lalu bapakku termasuk yang meninggal lalu di dahulukan daripada yang lainnya. Telah menceritakan kepada kami [Wahab bin Jarir] berkata; telah menceritakan kepada kami [bapakku] berkata; saya mendengar [Humaid bin Hilal] menceritakan dari [Sa'ad bin Hisyam] dari [Bapaknya, Hisyam bin 'Amir] berkata; pada saat Perang Uhud, lalu menyebutkan haditsnya, secara lengkap. (Ahmad bin Hanbal) berkata; telah menceritakan kepada kami ['Affan] berkata; saya mendengar [Jarir bin Hazim] menceritakan hadits ini, dari [Humaid bin Hilal] dan menambahkan di dalamnya dari [Sa'ad bin Hisyam] dengan tambahan, dan perdalamlah."},"972":{"ar":"قَالَ حَدَّثَنَا حَسَنُ بْنُ مُوسَى قَالَ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ قَالَقَدِمَ هِشَامُ بْنُ عَامِرٍ الْبَصْرَةَ فَوَجَدَهُمْ يَتَبَايَعُونَ الذَّهَبَ فِي أُعْطِيَاتِهِمْ فَقَامَ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ الذَّهَبِ بِالْوَرِقِ نَسِيئَةً وَأَخْبَرَنَا أَوْ قَالَ إِنَّ ذَلِكَ هُوَ الرِّبَا","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Hasan bin Musa] berkata; telah menceritakan kepada kami [Hammad] yaitu Ibnu Zaid, dari [Ayyub] dari [Abu Qilabah] berkata; [Hisyam bin 'Amir] datang ke Basrah, lalu mendapati mereka saling berjual beli emas dalam tempat pertukaran mereka, lalu dia berdiri dan berkata; Rasulullah shallallahu'alaihiwasallam melarang juAl beli emas dengan uang secara kredit, dan telah mengabarkan kepada kami atau berkata; itu adalah riba."},"973":{"ar":"قَالَ حَدَّثَنَا رَوْحٌ قَالَ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ يَزِيدَ بْنِ خُصَيْفَةَ أَنَّ عَمْرَو بْنَ عَبْدِ اللَّهِ بْنِ كَعْبٍ السُّلَمِيَّ أَخْبَرَهُ أَنَّ نَافِعَ بْنَ جُبَيْرٍ أَخْبَرَهُأَنَّ عُثْمَانَ بْنَ أَبِي الْعَاصِ أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عُثْمَانُ وَبِي وَجَعٌ قَدْ كَادَ يُهْلِكُنِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمْسِكْ بِيَمِينِكَ سَبْعَ مَرَّاتٍ وَقُلْ أَعُوذُ بِعِزَّةِ اللَّهِ وَقُدْرَتِهِ مِنْ شَرِّ مَا أَجِدُقَالَ فَفَعَلْتُ ذَلِكَ فَأَذْهَبَ اللَّهُ مَا كَانَ بِي فَلَمْ أَزَلْ آمُرُ بِهِ أَهْلِي وَغَيْرَهُمْ","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Rouh] berkata; telah menceritakan kepada kami [Malik bin Anas] dari [Yazid bin Khushaifah] ['Amr bin Abdullah bin Ka'ab As-Sulami] menghabarinya [Nafi' bin Jubair] menghabarinya, ['Utsman bin Abu Al 'Ash] mendatangi Rasulullah shallallahu'alaihiwasallam. 'Utsman berkata; Aku merasakan sakit yang sangat sehingga aku hampir meninggal olehnya, lalu Rasulullah shallallahu'alaihiwasallam bersabda: \"Peganglah daerah yang sakit itu dengan tangan kananmu sebanyak tujuh kali dengan berdoa, 'AUDZU BI IZZATILLAH WA QUDRATIHI MIN SYARRI MA AJIDU (Aku berlindung dari kemuliaan Allah dan Segala kemampuAn Nya, dari segala keburukan yang menimpaku) lalu saya melakukan hal itu sehingga Allah menghilangkan rasa sakit yang aku derita, sehingga aku menyuruh keluargaku dan orang lain untuk mempraktekkan doa tersebut"},"974":{"ar":"قَالَ حَدَّثَنَا رَوْحٌ وَعَبْدُ الصَّمَدِ قَالَا حَدَّثَنَا حَمَّادٌ قَالَ رَوْحٌ قَالَ أَخْبَرَنَا الْجُرَيْرِيُّ عَنْ أَبِي الْعَلَاءِ عَنْ عُثْمَانَ بْنِ أَبِي الْعَاصِ وَامْرَأَةٍ مِنْ قَيْسٍ أَنَّهُمَاسَمِعَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَحَدُهُمَا سَمِعْتُهُ يَقُولُ اللَّهُمَّ اغْفِرْ لِي ذَنْبِي وَخَطَئِي وَعَمْدِيو قَالَ الْآخَرُ سَمِعْتُهُ يَقُولُ اللَّهُمَّ أَسْتَهْدِيكَ لِأَرْشَدِ أَمْرِي وَأَعُوذُ بِكَ مِنْ شَرِّ نَفْسِي","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Rouh] dan [Abdusshomad] berkata; telah menceritakan kepada kami [Hammad] berkata; [Rouh] berkata; telah menghabarkan kepada kami [Al Jurairi] dari [Abu Al Ala'i] dari ['Utsman bin Abu Al Ash] dan [seorang wanita] dari Qais, mereka berdua mendengar Nabi Shallallahu'alaihiwasallam, bersabda: salah satu dari keduanya, saya mendengarnya berkata; \"ALLAHUMMA IGFIRLI DZANBI WA KHATAI WA 'AMDY (Ya Allah ampunilah dosaku dan kesalahan yang tidak sengaja maupun disengaja).\" Adapun salah satunya berkata; Aku mendengarnya (Rasulullah shallallahu'alaihiwasallam) berdoa, \"ASTAHDIIKA LI ARSYADI AMRY WA `A'UDZU BIKA MIN SYARRI NAFSI\" (aku meminta petunjuk kepada-Mu agar urusanku di puncak kebenaran, dan aku berlindung dari kejelekan diriku) \""},"975":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الصَّمَدِ قَالَ حَدَّثَنَا حَمَّادٌ عَنِ الْجُرَيْرِيِّ عَنْ أَبِي الْعَلَاءِ عَنْ عُثْمَانَ بْنِ أَبِي الْعَاصِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ اجْعَلْنِي إِمَامَ قَوْمِي فَقَالَ أَنْتَ إِمَامُهُمْ وَاقْتَدِ بِأَضْعَفِهِمْ وَاتَّخِذْ مُؤَذِّنًا لَا يَأْخُذُ عَلَى أَذَانِهِ أَجْرًا","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Abdushshomad] berkata; telah menceritakan kepada kami [Hammad] dari [Al Jurairi] dari [Abu Al Ala'i] dari ['Utsman bin Abu Al Ash] berkata; Wahai Rasulullah shallallahu'alaihiwasallam jadikanlah aku imam kaumku!. Lalu (Rasulullah shallallahu'alaihiwasallam) berkata 'Engkau imam mereka dan teladanilah orang terlemah di antara mereka, dan ambillah seorang muadzin yang tidak mengambil upah atas adzannya.\""},"976":{"ar":"حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ قَالَ أَخْبَرَنَا سَعِيدٌ الْجُرَيْرِيُّ عَنْ أَبِي الْعَلَاءِ عَنْ مُطَرِّفٍ عَنْ عُثْمَانَ بْنِ أَبِي الْعَاصِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ اجْعَلْنِي إِمَامَ قَوْمِي قَالَ أَنْتَ إِمَامُهُمْ فَاقْتَدِ بِأَضْعَفِهِمْ وَاتَّخِذْ مُؤَذِّنًا لَا يَأْخُذُ عَلَى أَذَانِهِ أَجْرًا","id":"Telah menceritakan kepada kami ['Affan] berkata; telah menceritakan kepada kami [Hammad bin Salamah] berkata; telah menghabarkan kepada kami [Sa'id Al Jurairi] dari [Abu Al Ala'i] dari [Mutharrif] dari ['Utsman bin Abu Al Ash] berkata saya berkata; Wahai Rasulullah, jadikanlah saya imam bagi kaum saya. Beliau bersabda: \"Kamu adalah imam mereka, dan teladanilah orang yang paling lemah di antara kalian. Angkatlah seorang muadzin yang tidak mengambil upah.\""},"977":{"ar":"حَدَّثَنَا يُونُسُ قَالَ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ زَيْدٍ عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ عَنْ سَعِيدِ بْنِ أَبِي هِنْدٍ عَنْ مُطَرِّفٍ قَالَدَخَلْتُ عَلَى عُثْمَانَ بْنِ أَبِي الْعَاصِ فَقَالَ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الصِّيَامُ جُنَّةٌ كَجُنَّةِ أَحَدِكُمْ مِنْ الْقِتَالِ وَكَانَ آخِرُ مَا عَهِدَ إِلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ بَعَثَنِي إِلَى الطَّائِفِ قَالَ يَا عُثْمَانُ تَجَوَّزْ فِي الصَّلَاةِ فَإِنَّ فِي الْقَوْمِ الْكَبِيرَ وَذَا الْحَاجَةِ","id":"Telah menceritakan kepada kami [Yunus] berkata; telah menceritakan kepada kami [Hammad] yaitu Ibnu Zaid, dari [Muhammad bin Ishaq] dari [Sa'id bin Abu Hind] dari [Mutharrif] Berkata; Aku menemui ['Utsman bin Abu Al Ash], lalu dia berkata; Aku mendengar Rasulullah shallallahu'alaihiwasallam bersabda: \"Puasa adalah perisai, seperti perisai di antara kalian waktu berperang, dan wasiat terakhir Rasulullah shallallahu'alaihiwasallam kepadaku ketika beliau mengutusku ke Thaif beliau bersabda: \"Wahai Usman peringanlah dalam shalat, karena yang menjadi makmum terdapat orang tua dan orang yang mempunyai keperluan.\""},"978":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ عِيسَى قَالَ حَدَّثَنَا مَالِكٌ عَنْ يَزِيدَ بْنِ خُصَيْفَةَ أَنَّ عَمْرَو بْنَ عَبْدِ اللَّهِ بْنِ كَعْبٍ أَخْبَرَهُ عَنْ نَافِعِ بْنِ جُبَيْرٍ عَنْ عُثْمَانَ بْنِ أَبِي الْعَاصِ قَالَأَتَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبِي وَجَعٌ قَدْ كَادَ يُهْلِكُنِي فَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ امْسَحْهُ بِيَمِينِكَ سَبْعَ مَرَّاتٍ وَقُلْ أَعُوذُ بِعِزَّةِ اللَّهِ وَقُدْرَتِهِ مِنْ شَرِّ مَا أَجِدُقَالَ فَفَعَلْتُ ذَلِكَ فَأَذْهَبَ اللَّهُ مَا كَانَ بِي فَلَمْ أَزَلْ آمُرُ بِهِ أَهْلِي وَغَيْرَهُمْ","id":"Telah menceritakan kepada kami [Ishaq bin 'Isa] berkata; telah menceritakan kepada kami [Malik] dari [Yazid bin Khushaifah] ['Amr bin Abdullah bin Kaab] menghabarinya, dari [Nafi' bin Jubair] dari ['Utsman bin Abu Al Ash] berkata; Rasulullah shallallahu'alaihiwasallam menemuiku ketika saya sedang sakit yang hampir saja menjadikanku meninggal karenanya. lalu Rasulullah shallallahu'alaihiwasallam bersabda kepadaku, \"Usaplah daerah yang sakit itu dengan tangan kananmu sebanyak tujuh kali dengan berdoa, 'AUDZU BI IZZATILLAH WA QUDRATIHI MIN SYARRI MA AJIDU (Aku berlindung dengan kemuliaan Allah dan Segala kemampuAn Nya, dari segala keburukan yang menimpaku), saya lakukan hal itu sehingga Allah menghilangkan rasa sakit yang aku derita, sehingga aku menyuruh keluargaku dan orang lain untuk mempraktekkan doa tersebut."},"979":{"ar":"قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنِ النُّعْمَانِ بْنِ سَالِمٍ قَالَ سَمِعْتُ أَشْيَاخَنَا مِنْ ثَقِيفٍ قَالُوا أَخْبَرَنَا عُثْمَانُ بْنُ أَبِي الْعَاصِ أَنَّهُ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمَّ قَوْمَكَ وَإِذَا أَمَمْتَ قَوْمَكَ فَأَخِفَّ بِهِمْ الصَّلَاةَ فَإِنَّهُ يَقُومُ فِيهَا الصَّغِيرُ وَالْكَبِيرُ وَالضَّعِيفُ وَالْمَرِيضُ وَذُو الْحَاجَةِ","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [An Nu'man bin Salim] berkata; saya mendengar para [Syaikh] dari Tsaqif, telah menghabarkan kepada kami ['Utsman bin Abu Al Ash] dia berkata; Rasulullah shallallahu'alaihiwasallam bersabda kepadaku 'Imamilah kaummu. Ketika kamu menjadi imam kaummu, peringkaslah shalat, karena yang ikut ada anak kecil, orang yang sudah tua, orang yang lemah, orang yang sakit dan orang yang memiliki keperluan.\""},"980":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ قَالَ سَمِعْتُ سَعِيدَ بْنَ الْمُسَيِّبِ قَالَ حَدَّثَ عُثْمَانُ بْنُ أَبِي الْعَاصِ قَالَآخِرُ مَا عَهِدَ إِلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَمَمْتَ قَوْمًا فَأَخِفَّ بِهِمْ الصَّلَاةَ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari ['Amr bin Murrah] berkata; saya mendengar [Sa'id bin Musayyab] berkata; ['Utsman bin Abu Al Ash] menceritakan, berkata; pesan terakhir yang diwasiatkan Rasulullah shallallahu'alaihiwasallam kepadaku adalah 'Jika kamu menjadi imam suatu kaum, ringankanlah shalat.'"},"981":{"ar":"قَالَ حَدَّثَنَا حَجَّاجٌ قَالَ حَدَّثَنَا لَيْثُ بْنُ سَعْدٍ قَالَ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ سَعِيدِ بْنِ أَبِي هِنْدٍ أَنَّ مُطَرِّفًا مِنْ بَنِي عَامِرِ بْنِ صَعْصَعَةَ حَدَّثَهُأَنَّ عُثْمَانَ بْنَ أَبِي الْعَاصِ الثَّقَفِيَّ دَعَا لَهُ بِلَبَنٍ لِيَسْقِيَهُ فَقَالَ مُطَرِّفٌ إِنِّي صَائِمٌ فَقَالَ عُثْمَانُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الصِّيَامُ جُنَّةٌ مِنْ النَّارِ كَجُنَّةِ أَحَدِكُمْ مِنْ الْقِتَالِ وَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ صِيَامٌ حَسَنٌ صِيَامُ ثَلَاثَةِ أَيَّامٍ مِنْ الشَّهْرِ","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Hajjaj] berkata; telah menceritakan kepada kami [Laits bin Sa'ad] berkata; telah menceritakan kepadaku [Yazid bin Abu Habib] dari [Sa'id bin Abu Hind] [Mutharrif] dari Bani 'Amir bin Sha'sha'ah, menceritakannya ['Utsman bin Abu Al Ash Ats-Tsaqafi] meminta susu untuk diminum, lalu Mutharrif berkata; saya sedang berpuasa. 'Usman berkata; saya mendengar Rasulullah shallallahu'alaihiwasallam bersabda: \"Puasa adalah perisai dari neraka seperti perisai di antara kalian waktu berperang\", dan saya mendengar Rasulullah shallallahu'alaihiwasallam bersabda: \"Puasa yang baik adalah puasa tiga hari setiap bulan.\""},"982":{"ar":"قَالَ حَدَّثَنَا يَزِيدُ قَالَ أَخْبَرَنَا حَمَّادُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا عَلِيُّ بْنُ زَيْدٍ عَنِ الْحَسَنِ قَالَمَرَّ عُثْمَانُ بْنُ أَبِي الْعَاصِ عَلَى كِلَابِ بْنِ أُمَيَّةَ وَهُوَ جَالِسٌ عَلَى مَجْلِسِ الْعَاشِرِ بِالْبَصْرَةِ فَقَالَ مَا يُجْلِسُكَ هَاهُنَا قَالَ اسْتَعْمَلَنِي هَذَا عَلَى هَذَا الْمَكَانِ يَعْنِي زِيَادًا فَقَالَ لَهُ عُثْمَانُ أَلَا أُحَدِّثُكَ حَدِيثًا سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَلَى فَقَالَ عُثْمَانُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ كَانَ لِدَاوُدَ نَبِيِّ اللَّهِ عَلَيْهِ السَّلَام مِنْ اللَّيْلِ سَاعَةٌ يُوقِظُ فِيهَا أَهْلَهُ فَيَقُولُ يَا آلَ دَاوُدَ قُومُوا فَصَلُّوا فَإِنَّ هَذِهِ سَاعَةٌ يَسْتَجِيبُ اللَّهُ فِيهَا الدُّعَاءَ إِلَّا لِسَاحِرٍ أَوْ عَشَّارٍ فَرَكِبَ كِلاَبُ بْنُ أُمَيَّةَ سَفِينَتَهُ فَأَتَى زَيِادًا فَاسْتَعْفَاهُ فَأَعْفَاهُحَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ الْقَوَارِيرِيُّ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنِ الْحَسَنِ قَالَ مَرَّ عُثْمَانُ بْنُ أَبِي الْعَاصِ عَلَى كِلَابِ بْنِ أُمَيَّةَ فَذَكَرَ نَحْوَهُ","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Yazid] berkata; telah mengabarkan kepada kami [Hammad bin Salamah] berkata; telah menceritakan kepada kami ['Ali bin Zaid] dari [Al Hasan] 'Utsman bin Abu Al Ash melewati Kilab Bin Umayyah yang sedang duduk di tempat perpajakan di Bashrah, maka 'Utsman bin Abu Al Ash bertanya, \" Apa yang membuatmu duduk disini\"? (Kilab bin Umayyah) menjawab 'Ziyad yang menyuruhku untuk duduk.' 'Utsman berkata, maukah saya ceritakan sesuatu hadits?.\"Maukah aku tunjukkan kepadamu suatu hadits yang saya dengar langsung dari Rasulullah shallallahu'alaihiwasallam?.\" Dia berkata; Ya. Lalu ['Utsman] berkata; saya mendengar Rasulullah shallallahu'alaihiwasallam bersabda: \"Dawud, Nabi Allah Alaihissalam, suatu malam membangunkan keluarganya dan berseru, 'Wahai keluarga Dawud, bangunlah kalian dan shalatlah! sungguh ini adalah waktu yang dikabulkan doa oleh Allah, kecuali untuk tukang sihir atau para pekerja pajak. Lalu Kilab bin Umayyah menaiki kapalnya untuk mendatangi Ziyad, untuk meminta maaf, dan (Kilab) pun memaafkannya. Telah menceritakan kepada kami ['Ubaidullah bin 'Umar Al Qawaryry] berkata; telah menceritakan kepada kami [Hammad bin Zaid] dari ['Ali bin Zaid] dari [Al Hasan] berkata; ['Utsman bin Abu Al Ash] melewati Kilab bin Umayyah, maka (Hasan) menyebutkan hadis sebagaimana di atas."},"983":{"ar":"قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ عَنْ عَبْدِ اللَّهِ بْنِ زَيْدٍ أَوْ بَدْرٍ أَنَا أَشُكُّ عَنْ طَلْقِ بْنِ عَلِيٍّ الْحَنَفِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَنْظُرُ اللَّهُ عَزَّ وَجَلَّ إِلَى صَلَاةِ عَبْدٍ لَا يُقِيمُ فِيهَا صُلْبَهُ بَيْنَ رُكُوعِهَا وَسُجُودِهَا","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Waki'] berkata; telah menceritakan kepada kami ['Ikrimah bin 'Ammar] dari [Abdullah bin Zaid] atau Badr saya ragu, dari [Thalq bin 'Ali Al Hanafi], berkata; Rasulullah shallallahu'alaihiwasallam bersabda: \"Allah AzzaWaJalla tidak melihat shalat seorang hamba yang tidak menegakkan tulang punggungnya pada saat ruku' dan sujudnya.\""},"984":{"ar":"قَالَ حَدَّثَنَا أَبُو النَّضْرِ قَالَ حَدَّثَنَا أَيُّوبُ بْنُ عُتْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بَدْرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَلِيِّ بْنِ شَيْبَانَ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَنْظُرُ اللَّهُ عَزَّ وَجَلَّ إِلَى رَجُلٍ لَا يُقِيمُ صُلْبَهُ بَيْنَ رُكُوعِهِ وَسُجُودِهِ","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Abu Nadlr] berkata; telah menceritakan kepada kami [Ayyub bin 'Utbah] telah menceritakan kepada kami [Abdullah bin Badr] dari [Abdurrahman bin 'Ali bin Syaiban] dari [bapaknya], Rasulullah shallallahu'alaihiwasallam bersabda: \"Allah AzzaWaJalla tidak melihat seorang laki-laki yang tidak menegakkan tulang punggungnya antara ruku'nya dan sujudnya.\""},"985":{"ar":"قَالَ قَالَ حَدَّثَنَا حَمَّادُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا أَيُّوبُ بْنُ عُتْبَةَ عَنْ قَيْسِ بْنِ طَلْقٍ عَنْ أَبِيهِ قَالَسَأَلَ رَجُلٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيَتَوَضَّأُ أَحَدُنَا إِذَا مَسَّ ذَكَرَهُ قَالَ إِنَّمَا هُوَ بَضْعَةٌ مِنْكَ أَوْ جَسَدِكَ","id":"(Abdullah bin Ahmad) berkata; (Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Hammad bin Khalid] berkata; telah menceritakan kepada kami [Ayyub bin 'Utbah] dari [Qais bin Thalq] dari [bapaknya] berkata; Seorang laki-laki bertanya Rasulullah shallallahu'alaihiwasallam, Apabila salah di antara kita memegang kemaluannya haruskah dia berwudlu? beliau bersabda: \"Sesungguhnya itu (kemaluan, pent) adalah bagian darimu atau tubuhmu.\""},"986":{"ar":"قَالَ حَدَّثَنَا يُونُسُ حَدَّثَنَا أَبَانُ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عِيسَى بْنِ خُثَيْمٍ عَنْ قَيْسِ بْنِ طَلْقٍ أَنَّ أَبَاهُشَهِدَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَأَلَهُ رَجُلٌ عَنْ الصَّلَاةِ فِي الثَّوْبِ الْوَاحِدِ فَلَمْ يَقُلْ لَهُ شَيْئًا فَلَمَّا أُقِيمَتْ الصَّلَاةُ طَارَقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ ثَوْبَيْهِ فَصَلَّى فِيهِمَا","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Yunus] telah menceritakan kepada kami [Aban] dari [Yahya bin Abu Katsir] dari ['Isa bin Khutsaim] dari [Qais bin Thalq] [bapaknya] dia pernah menjumpai Rasulullah shallallahu'alaihiwasallam, ketika ada seorang yang bertanya telah shalat dengan satu pakaian, beliau tidak mengucapkan sepatah katapun. Tatkala shalat didirikan, Rasulullah shallallahu'alaihiwasallam melipat antara kedua ujung kainnya dan beliau pergunakan untuk shalat."},"987":{"ar":"قَالَ حَدَّثَنَا مُوسَى بْنُ دَاوُدَ حَدَّثَنَا مُحَمَّدُ بْنُ جَابِرٍ عَنْ عَبْدِ اللَّهِ بْنِ بَدْرٍ عَنْ عَلِيِّ بْنِ طَلْقٍ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَكُونُ وِتْرَانِ فِي لَيْلَةٍ","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Musa bin Daud] telah menceritakan kepada kami [Muhammad bin Jabir] dari [Abdullah bin Badr] ['Ali bin Thalq] dari [bapaknya] berkata; Rasulullah shallallahu'alaihiwasallam bersabda: \"Tidak ada witir dalam satu malam.\""},"988":{"ar":"قَالَوَسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الرَّجُلِ يُصَلِّي فِي ثَوْبٍ وَاحِدٍ قَالَ وَكُلُّكُمْ يَجِدُ ثَوْبَيْنِ","id":"[Thalq] berkata; Nabi Shallallahu'alaihiwasallam ditanya tentang seorang laki-laki yang shalat dengan memakai satu pakaian. Beliau bersabda: \"Tapi bukankah kalian mendapatkan dua kain?.\""},"989":{"ar":"حَدَّثَنَا مُوسَى قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَابِرٍ عَنْ قَيْسِ بْنِ طَلْقٍ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَأَيْتُمْ الْهِلَالَ فَصُومُوا وَإِذَا رَأَيْتُمُوهُ فَأَفْطِرُوا فَإِنْ أُغْمِيَ عَلَيْكُمْ فَأَتِمُّوا الْعِدَّةَ","id":"Telah menceritakan kepada kami [Musa] berkata; telah menceritakan kepada kami [Muhammad bin Jabir] dari [Qais bin Thalq] dari [bapaknya] berkata; Rasulullah shallallahu'alaihiwasallam bersabda: \"Jika kalian melihat Hilal, maka berpuasalah. Jika kalian melihatnya lagi maka berbukalah. Jika ada mendung pada kalian maka sempurnakanlah hitungan.\""},"990":{"ar":"قَالَ حَدَّثَنَا مُوسَى بْنُ دَاوُدَ حَدَّثَنَا مُحَمَّدُ بْنُ جَابِرٍ عَنْ قَيْسِ بْنِ طَلْقٍ عَنْ أَبِيهِ قَالَكُنْتُ جَالِسًا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ رَجُلٌ فَقَالَ مَسِسْتُ ذَكَرِي أَوْ الرَّجُلُ يَمَسُّ ذَكَرَهُ فِي الصَّلَاةِ عَلَيْهِ الْوُضُوءُ قَالَ لَا إِنَّمَا هُوَ مِنْكَ","id":"(Ahmad bin Hanbal) berkata; telah menceritakan kepada kami [Musa bin Daud] telah menceritakan kepada kami [Muhammad bin Jabir] dari [Qais bin Thalq] dari [bapaknya] berkata; Aku sedang duduk bersama Nabi Shallallahu'alaihiwasallam, lalu ada seorang laki-laki bertanya beliau dengan berkata; \"Aku telah memegang kemaluanku\" ataupun ada seorang laki-laki yang memegang kemaluannya dalam shalat, apakah wajib baginya untuk berwudlu? Beliau bersabda: \"Tidak, karena itu (kemaluan, pent) adalah bagian dari anggota tubuhmu.\""},"991":{"ar":"قَالَ حَدَّثَنَا مُوسَى بْنُ دَاوُدَ حَدَّثَنَا مُحَمَّدُ بْنُ جَابِرٍ عَنْ عَبْدِ اللَّهِ بْنِ بَدْرٍ عَنْ طَلْقِ بْنِ عَلِيٍّ قَالَوَفَدْنَا عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا وَدَّعَنَا أَمَرَنِي فَأَتَيْتُهُ بِإِدَاوَةٍ مِنْ مَاءٍ فَحَثَا مِنْهَا ثُمَّ مَجَّ فِيهَا ثَلَاثًا ثُمَّ أَوْكَأَهَا ثُمَّ قَالَ اذْهَبْ بِهَا فَانْضَحْ مَسْجِدَ قَوْمِكَ وَأْمُرْهُمْ يَرْفَعُوا بِرُءُوسِهِمْ أَنْ رَفَعَهَا اللَّهُ قُلْتُ إِنَّ الْأَرْضَ بَيْنَنَا وَبَيْنَكَ بَعِيدَةٌ وَإِنَّهَا تَيْبَسُ قَالَ فَإِذَا يَبِسَتْ فَمُدَّهَا","id":"(Ahmad bin Hanbal) berkata, telah menceritakan kepada kami [Musa bin Daud] telah menceritakan kepada kami [Muhammad bin Jabir] dari [Abdullah bin Badr] dari [Thalq bin 'Ali] berkata, kami menjadi utusan untuk menemui Nabi Shallallahu'alaihiwasallam. Tatkala beliau hendak meninggalkan kami, beliau menyuruhku suatu urusan. Lalu saya membawa bejana yang berisi air, beliau mengambil dengan kedua telapak tangannya, lalu mengeluarkan dari mulutnya tiga kali, mengikatnya kembali lalu bersabda: \"Bawalah ini dan basahilah masjid kaummu dan perintahkan mereka untuk mengangkat kepala mereka, niscaya Allah akan mengangkatnya. Saya berkata, bumi antara tempat anda dengan kami sangat jauh dan tanah itu sangat kering. (Rasulullah) bersabda: \"Jika telah kering maka panjangkanlah!\""},"992":{"ar":"حَدَّثَنَا قُرَّانُ بْنُ تَمَّامٍ عَنْ مُحَمَّدِ بْنِ جَابِرٍ عَنْ قَيْسِ بْنِ طَلْقٍ عَنْ أَبِيهِ قَالَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ أَيَتَوَضَّأُ أَحَدُنَا إِذَا مَسَّ ذَكَرَهُ فِي الصَّلَاةِ قَالَ هَلْ هُوَ إِلَّا مِنْكَ أَوْ بَضْعَةٌ مِنْكَ","id":"Telah menceritakan kepada kami [Qurrab bin Tamam] dari [Muhammad bin Jabir] dari [Qais bin Thalq] dari [bapaknya] berkata, ada seorang laki-laki yang berkata, Wahai Rasulullah, jika salah seorang dari kita memegang kemaluannya ketika shalat, apa harus berwudhu?. (Rasulullahi Shallallahu'alaihiwasallam) bersabda: \"Itu hanya potongan dari tubuhmu atau secuil daging darimu.\""},"993":{"ar":"قَالَ حَدَّثَنَا عَبْدُ الصَّمَدِ وَسُرَيْجٌ قَالَا حَدَّثَنَا مُلَازِمُ بْنُ عَمْرٍو حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بَدْرٍ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ عَلِيٍّ حَدَّثَهُ أَنَّ أَبَاهُ عَلِيَّ بْنَ شَيْبَانَ حَدَّثَهُأَنَّهُ خَرَجَ وَافِدًا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَصَلَّيْنَا خَلْفَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَحَ بِمُؤْخِرِ عَيْنَيْهِ إِلَى رَجُلٍ لَا يُقِيمُ صُلْبَهُ فِي الرُّكُوعِ وَالسُّجُودِ فَلَمَّا انْصَرَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَا مَعْشَرَ الْمُسْلِمِينَ إِنَّهُ لَا صَلَاةَ لِمَنْ لَا يُقِيمُ صُلْبَهُ فِي الرُّكُوعِ وَالسُّجُودِ قَالَ وَرَأَى رَجُلًا يُصَلِّي خَلْفَ الصَّفِّ فَوَقَفَ حَتَّى انْصَرَفَ الرَّجُلُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَقْبِلْ صَلَاتَكَ فَلَا صَلَاةَ لِرَجُلٍ فَرْدٍ خَلْفَ الصَّفِّ قَالَ عَبْدُ الصَّمَدِ فَرْدًا خَلْفَ الصَّفِّحَدَّثَنَا عَبْدُ الصَّمَدِ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنَا أَبُو عَبْدِ اللَّهِ الشَّقَرِيُّ قَالَ حَدَّثَنِي عَمْرُو بْنُ جَابِرٍ عَنْ عَبْدِ اللَّهِ بْنِ بَدْرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَلِيِّ بْنِ شَيْبَانَ عَنْ أَبِيهِ فَذَكَرَهُ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا أَيُّوبُ بْنُ عُتْبَةَ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بَدْرٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَلِيِّ بْنِ شَيْبَانَ السُّحَيْمِيُّ قَالَ حَدَّثَنِي أَبِي فَذَكَرَهُ","id":"(Ahmad bin Hanbal) berkata, telah menceritakan kepada kami [Abdushshamad] dan [Suraij] berkata, telah menceritakan kepada kami [Mulazim bin 'Amr] telah menceritakan kepada kami [Abdullah bin Badr] [Abdurrahman bin 'Ali] menceritakannya, [bapaknya, 'Ali bin Syaiban] menceritakannya, dia berangkat sebagai utusan untuk menemui Rasulullahi Shallallahu'alaihiwasallam. Dia berkata, Kami shalat di belakang Nabi Shallallahu'alaihiwasallam, dengan kedua matanya secara selintas beliau melihat seorang laki-laki yang tidak menyempurnakan tulang punggungnya waktu ruku' dan sujud. Ketika Rasulullahi Shallallahu'alaihiwasallam selesai shalat, bersabda: \"Wahai kaum muslimin, tidak sah shalat bagi seseorang yang tidak menyempurnakan tulang punggungnya waktu ruku' dan sujud\", lalu ('Ali bin Syaiban) berkata, (Rasulullahi Shallallahu'alaihiwasallam) melihat seorang laki-laki shalat di belakang shaf dan berdiri sendiri sampai shalat selesai, maka Rasulullah Shallallahu'alaihiwasallam bersabda: \"Ulangilah shalatmu, karena tidak sah shalat seseorang yang berdiri di belakang shaf sendirian.\" Abdushshamad berkata dengan redaksi 'Secara sendirian di belakang shaf.' Telah menceritakan kepada kami [Abdushamad] berkata, telah menceritakan kepadaku [bapakku] berkata, telah mengabarkan kepada kami [Abu Abdullah Asy-Syaqary] berkata, telah menceritakan kepadaku ['Amr bin Jabir bin Abdullah bin Badr] dari [Abdurrahman] dari ['Ali bin Syaiban] dari bapaknya yang dia menyebutkan haditsnya. Telah menceritakan kepada kami [Yazid bin Harun] berkata, telah mengabarkan kepada kami [Ayyub bin 'Utbah] berkata, telah menceritakan kepada kami [Abdullah bin Badr] berkata, telah menceritakan kepada kami [Abdurrahman bin 'Ali bin Syaiban Asy-Suhaimi] berkata, telah menceritakan kepadaku [bapakku] lalu dia menyebutkan hadits secara lengkap."},"994":{"ar":"قَالَ حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي مُلَازِمُ بْنُ عَمْرٍو قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ بَدْرٍ عَنْ قَيْسِ بْنِ طَلْقٍ عَنْ أَبِيهِ طَلْقِ بْنِ عَلِيٍّ قَالَ قَالَلَدَغَتْنِي عَقْرَبٌ عِنْدَ نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَقَانِي وَمَسَحَهَا","id":"(Ahmad bin Hanbal) berkata, telah menceritakan kepada kami ['Ali bin Abdullah] berkata, telah menceritakan kepadaku [Mulazim bin 'Amr] berkata, telah menceritakan kepadaku [Abdullah bin Badr] dari [Qais bin Thalq] dari [bapaknya, Talq bin 'Ali] berkata, saya disengat kalajengking di sisi Nabiyullah Shallallahu'alaihiwasallam, lalu beliau membacakanku dengan dengan doa dan mengusapnya.\""},"995":{"ar":"قَالَ حَدَّثَنَا رَوْحٌ قَالَ حَدَّثَنَا سَعِيدٌ وَعَبْدُ الْوَهَّابِ قَالَ أَخْبَرَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنِ الْحَسَنِ عَنِ الْأَسْوَدِ بْنِ سَرِيعٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ سَرِيَّةً يَوْمَ حُنَيْنٍ قَالَ رَوْحٌ فَأَتَوْا حَيًّا مِنْ أَحْيَاءِ الْعَرَبِ فَذَكَرَ الْحَدِيثَ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ مَا مِنْ نَسَمَةٍ تُولَدُ إِلَّا عَلَى الْفِطْرَةِ حَتَّى يُعْرِبَ عَنْهَا لِسَانُهَا","id":"(Ahmad bin Hanbal) berkata, telah menceritakan kepada kami [Rauh] berkata, telah menceritakan kepada kami [Sa'id] dan [Abdul Wahab] berkata, telah mengabarkan kepada kami [Sa'id] dari [Qatadah] dari [Al Hasan] dari [Al Aswad bin Sari'] Rasulullahi Shallallahu'alaihiwasallam mengutus satuan kelompok perang pada Peristiwa Hunain. [Rauh] berkata, lalu mereka mendatangi salah satu desa yang ada di pedalaman Arab, lalu menyebutkan hadis secara lengkap. Beliau bersabda: \"Demi yang jiwa Muhammad berada di tangan-Nya, tidaklah ada jiwa yang dilahirkan kecuali pasti dalam keadaan fitrah sehingga lidahnya yang akan mengikrarkannya.\""},"996":{"ar":"قَالَ حَدَّثَنَا حَسَنُ بْنُ مُوسَى حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ عَنِ الْأَسْوَدِ بْنِ سَرِيعٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي قَدْ مَدَحْتُ اللَّهَ بِمَدْحَةٍ وَمَدَحْتُكَ بِأُخْرَى فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَاتِ وَابْدَأْ بِمَدْحَةِ اللَّهِ عَزَّ وَجَلَّ","id":"(Ahmad bin Hanbal) berkata, telah menceritakan kepada kami [Hasan bin Musa] telah menceritakan kepada kami [Hammad bin Zaid] dari ['Ali bin Zaid] dari [Abdurrahman bin Abu Bakrah] dari [Aswad bin Sari'] berkata, saya berkata, Wahai Rasulullah, saya telah memuji Allah dengan suatu pujian dan memuji anda dengan pujian yang lain. Lalu Nabi Shallallahu'alaihiwasallam bersabda: \"Lakukanlah dan mulailah dengan memuji Allah AzzaWaJalla.\""},"997":{"ar":"قَالَ حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنِ الْأَحْنَفِ بْنِ قَيْسٍ عَنِ الْأَسْوَدِ بْنِ سَرِيعٍأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَرْبَعَةٌ يَوْمَ الْقِيَامَةِ رَجُلٌ أَصَمُّ لَا يَسْمَعُ شَيْئًا وَرَجُلٌ أَحْمَقُ وَرَجُلٌ هَرَمٌ وَرَجُلٌ مَاتَ فِي فَتْرَةٍ فَأَمَّا الْأَصَمُّ فَيَقُولُ رَبِّ لَقَدْ جَاءَ الْإِسْلَامُ وَمَا أَسْمَعُ شَيْئًا وَأَمَّا الْأَحْمَقُ فَيَقُولُ رَبِّ لَقَدْ جَاءَ الْإِسْلَامُ وَالصِّبْيَانُ يَحْذِفُونِي بِالْبَعْرِ وَأَمَّا الْهَرَمُ فَيَقُولُ رَبِّي لَقَدْ جَاءَ الْإِسْلَامُ وَمَا أَعْقِلُ شَيْئًا وَأَمَّا الَّذِي مَاتَ فِي الْفَتْرَةِ فَيَقُولُ رَبِّ مَا أَتَانِي لَكَ رَسُولٌ فَيَأْخُذُ مَوَاثِيقَهُمْ لَيُطِيعُنَّهُ فَيُرْسِلُ إِلَيْهِمْ أَنْ ادْخُلُوا النَّارَ قَالَ فَوَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ لَوْ دَخَلُوهَا لَكَانَتْ عَلَيْهِمْ بَرْدًا وَسَلَامًاقَالَ حَدَّثَنَا عَلِيٌّ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنِ الْحَسَنِ عَنْ أَبِي رَافِعٍ عَنْ أَبِي هُرَيْرَةَ مِثْلَ هَذَا غَيْرَ أَنَّهُ قَالَ فِي آخِرِهِ فَمَنْ دَخَلَهَا كَانَتْ عَلَيْهِ بَرْدًا وَسَلَامًا وَمَنْ لَمْ يَدْخُلْهَا يُسْحَبُ إِلَيْهَا","id":"(Ahmad bin Hanbal) berkata, telah menceritakan kepada kami ['Ali bin Abdullah] telah menceritakan kepada kami [Mu'adz bin Hisyam] berkata, telah menceritakan kepadaku [bapakku] dari [Qatadah] dari [Ahnaf bin Qais] dari [Aswad bin Sari'] Sesungguhnya Nabiyullah Shallallahu'alaihiwasallam bersabda: \"Ada empat jenis orang di hari kiamat nanti: Seorang laki-laki tuli yang tidak mendengar apapun, seorang laki-laki bodoh, seorang laki-laki yang pikun, dan seorang laki-laki yang mati dalam masa-masa kevakuman (ajaran agama atau risalah kenabian tidak sempat menjumpai dirinya). Orang tuli tersebut menyampaikan alasannya, 'Wahai Rabku, telah datang Islam hanya aku tidak mendengar apapun tentang hal itu'. Adapun orang yang bodoh beralasan, 'Wahai Rabku, Islam telah datang, hanya anak-anak melempariku dengan kotoran unta'. Adapun yang pikun berkata, 'Wahai Rabku, telah datang Islam hanya aku tidak bisa berfikir sama sekali'. Adapun orang yang mati dalam masa-masa kevakuman berkata, 'Wahai Rabku, para utusan-Mu tidak mendatangiku dan mengambil janji orang-orang untuk taat kepadanya. Lantas Allah mengutus para malaikatnya untuk mengatakan 'Masuklah kalian ke dalam neraka'. Demi Dzat yang jiwa Muhammad berada di tangan-Nya, kalaulah mereka memasuki api tersebut, api itu akan menjadi dingin dan menyelamatkan mereka\". (Ahmad bin Hanbal) berkata, telah menceritakan kepada kami ['Ali] telah menceritakan kepada kami [Mu'adz bin Hisyam] berkata, telah menceritakan kepadaku [bapakku] dari [Al Hasan] dari [Abu Rafi'] dari [Abu Hurairah] sepereti di atas, kecuali dalam perkataan yang terakhirnya, 'Barangsiapa memasuki api tersebut, api tersebut akan menjadi dingin dan menyelamatkan, dan barangsiapa tidak memasukinya, ia justru diseret untuk memasukinya.\""},"998":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا السَّرِيُّ بْنُ يَحْيَى حَدَّثَنَا الْحَسَنُ عَنْ الْأَسْوَدِ بْنِ سَرِيعٍ وَكَانَ رَجُلًا مِنْ بَنِي سَعْدٍ قَالَ وَكَانَ أَوَّلَ مَنْ قَصَّ فِي هَذَا الْمَسْجِدِ يَعْنِي الْمَسْجِدَ الْجَامِعَ قَالَغَزَوْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْبَعَ غَزَوَاتٍ قَالَ فَتَنَاوَلَ قَوْمٌ الذُّرِّيَّةَ بَعْدَمَا قَتَلُوا الْمُقَاتِلَةَ فَبَلَغَ ذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَلَا مَا بَالُ أَقْوَامٍ قَتَلُوا الْمُقَاتِلَةَ حَتَّى تَنَاوَلُوا الذُّرِّيَّةَ قَالَ فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ أَوَلَيْسَ أَبْنَاءُ الْمُشْرِكِينَ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ خِيَارَكُمْ أَبْنَاءُ الْمُشْرِكِينَ إِنَّهَا لَيْسَتْ نَسَمَةٌ تُولَدُ إِلَّا وُلِدَتْ عَلَى الْفِطْرَةِ فَمَا تَزَالُ عَلَيْهَا حَتَّى يُبِينَ عَنْهَا لِسَانُهَا فَأَبَوَاهَا يُهَوِّدَانِهَا أَوْ يُنَصِّرَانِهَاقَالَ وَأَخْفَاهَا الْحَسَنُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [As Sari bin Yahya] telah menceritakan kepada kami [Al Hasan] dari [Al Aswad bin Sari'] dia adalah seorang laki-laki dari Bani Saad berkata, dan dia adalah orang yang pertama kali menceritakan Masjid Jami' ini, ia berkata, saya berperang bersama Rasulullahi Shallallahu'alaihiwasallam sebanyak empat kali peperangan. (Al Aswad bin Sari') berkata, lalu orang-orang menyerang anak-anak dan para wanita (rakyat sipil) setelah membunuh prajurit musuh. Kasus ini sampai kepada Rasulullahi Shallallahu'alaihiwasallam, lalu beliau bersabda: \"Atas dasar apa suatu kaum membunuh para prajurit hingga juga mereka bunuh rakyat sipil (anak-anak dan para wanita)?\" (Al Aswad bin Sari') berkata, lalu ada seorang laki-laki yang berkata, Wahai Rasulullah, bukankan mereka adalah anak-anak orang musyrik? (Al Aswad bin Sari') berkata, lalu Rasulullahi Shallallahu'alaihiwasallam bersabda: \"Apa alasan kalian hanya karena mereka adalah anak orang musyrik, tidak ada jiwa yang lahir yang dilahirkan kecuali dalam keadaan fitrah, dan akan tetap seperti itu sampai lidahnya mengikrarkannya. Lalu kedua orang tuanyalah yang akan menjadikan dia Yahudi atau menjadikan Nasrani\" (Al Aswad bin Sari') berkata, Al Hasan menyembunyikannya."},"999":{"ar":"حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ وَبَهْزٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ مُطَرِّفٍ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ شُعْبَةُ قَالَ قَتَادَةُ أَخْبَرَنِي قَالَ سَمِعْتُ مُطَرِّفًا عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي صَوْمِ الدَّهْرِ قَالَ مَا صَامَ وَمَا أَفْطَرَ أَوْ لَا صَامَ وَلَا أَفْطَرَ وَقَالَ بَهْزٌ فِي حَدِيثِهِ لَا صَامَ وَلَا أَفْطَرَ","id":"Telah menceritakan kepada kami [Yahya] dari [Syu'bah] dan [Bahz] Nabi Shallallahu'alaihiwasallam telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Mutharrif] dari [bapaknya] dari Nabi Shallallahu'alaihiwasallam. Syu'bah berkata, Qatadah berkata, telah mengabarkan kepadaku, berkata, saya telah mendengar Mutharrif dari Bapaknya dari Nabi Shallallahu alaihi wa sallam tentang puasa dahr (puasa sepanjang masa, pent). (Rasulullahi Shallallahu'alaihiwasallam) bersabda: \"Orang itu dianggap tidak berpuasa juga tidak berbuka.\" Bahz berkata dalam hadisnya dengan redaksi 'Tidak berpuasa juga tidak berbuka.'"},"1000":{"ar":"قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ مُطَرِّفِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِأَنَّ رَجُلًا انْتَهَى إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَقُولُ وَقَالَ وَكِيعٌ مَرَّةً انْتَهَى إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَقْرَأُ{ أَلْهَاكُمْ التَّكَاثُرُ حَتَّى زُرْتُمْ الْمَقَابِرَ }قَالَ يَقُولُ ابْنُ آدَمَ مَالِي مَالِي وَهَلْ لَكَ مِنْ مَالِكَ إِلَّا مَا تَصَدَّقْتَ فَأَمْضَيْتَ أَوْ لَبِسْتَ فَأَبْلَيْتَ أَوْ أَكَلْتَ فَأَفْنَيْتَ","id":"(Ahmad bin Hanbal) berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Mutharrif bin Abdullah] dari [bapaknya], ada seorang laki-laki yang menemui Rasulullahi Shallallahu'alaihiwasallam lalu berkata. --Sedang Waki' berkata dengan redaksi menemui Nabi Shallallahu'alaihiwasallam bukan Rasulullah--, dan beliau membaca, ALHAAKUMUT TAKAATSUR HATTAA ZURTUMUL MAQAABIR, 'Bermegah-megahan Telah melalaikan kamu, Sampai kamu masuk ke dalam kubur' Lalu beliau bersabda: \"Anak Adam berkata, 'aduhai hartaku, aduhai hartaku', padahal tidak ada harta yang menjadi milikmu melainkan yang kau makan lantas menjadi musnah, atau apa yang kamu pakai lalu menjadi kusut atau yang kamu sedekahkan lalu harta tersebut habis.\""}};
